/**
 * Marco Extension — Auto-Attach Evaluator
 *
 * Implements the AND-gated auto-attach policy defined in
 * mem://features/auto-attach-policy.md.
 *
 * A library script is auto-attached to a project ONLY when ALL of C1..C8
 * hold. URL match alone is NEVER sufficient. Every skip MUST return a
 * structured reason — never a silent early return.
 *
 * See also:
 * - mem://standards/no-silent-failures.md
 * - src/background/condition-evaluator.ts (reused for C3 at inject-time)
 */

import type { StoredProject, ScriptEntry } from "../shared/project-types";
import { isUrlMatch } from "./url-matcher";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

/** Minimal shape of a library script's compiled instruction needed here. */
export interface LibraryScriptForAttach {
    /** Stable identifier — used both as scriptId and ScriptEntry.path. */
    id: string;
    name: string;
    instruction: {
        UrlMatches?: string[];
        AutoAttach?: boolean;
        RunAt?: ScriptEntry["runAt"];
        World?: "MAIN" | "ISOLATED";
        RequiredCookies?: string[];
        Dependencies?: string[];
        InjectionConditions?: {
            requireElement?: string | null;
            requireCookie?: string | null;
            minDelayMs?: number;
            requireOnline?: boolean;
        };
    };
}

export type SkipReason =
    | "AUTOATTACH_SKIPPED_AUTOSTART_OFF"            // C1
    | "AUTOATTACH_SKIPPED_OPT_OUT"                  // C4
    | "AUTOATTACH_SKIPPED_URL_NO_MATCH"             // C2
    | "AUTOATTACH_ALREADY_ATTACHED"                 // C8
    | "AUTOATTACH_SKIPPED_INCOMPATIBLE_RUN_CONTEXT" // C5
    | "AUTOATTACH_SKIPPED_COOKIE_BINDING_MISSING"   // C6
    | "AUTOATTACH_SKIPPED_DEP_MISSING"              // C7
    | "AUTOATTACH_SKIPPED_CONDITION_FAIL";          // C3

export interface AttachDecision {
    ok: boolean;
    reason: SkipReason | "OK";
    detail: string;
}

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Evaluates whether `script` should be auto-attached to `project`.
 * Cheap → expensive ordering; short-circuits on first failure.
 *
 * Note: C3 (runtime InjectionConditions) is checked structurally here.
 * Live element/cookie/online evaluation happens at inject-time via
 * condition-evaluator.ts; at attach-time we only reject if the declared
 * conditions are obviously unresolvable (e.g. requireCookie names a cookie
 * the project has no binding for).
 */
export function evaluateAutoAttach(
    project: StoredProject,
    script: LibraryScriptForAttach,
    libraryIds: ReadonlySet<string>,
): AttachDecision {
    // C1 — autoStart gate
    const isAutoStartOn = project.settings?.autoStart === true;
    if (!isAutoStartOn) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_AUTOSTART_OFF",
            detail: `Project "${project.name}" has autoStart=false`,
        };
    }

    // C4 — script opt-out
    const isOptedOut = script.instruction.AutoAttach === false;
    if (isOptedOut) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_OPT_OUT",
            detail: `Script "${script.name}" declared AutoAttach=false`,
        };
    }

    // C2 — URL match
    const urlMatches = script.instruction.UrlMatches ?? [];
    const projectPatterns = project.targetUrls.map((r) => r.pattern);
    const hasUrlOverlap = urlMatches.some((scriptPattern) =>
        projectPatterns.some((projectPattern) =>
            isUrlMatch(projectPattern, {
                pattern: scriptPattern,
                matchType: "glob",
            }),
        ),
    );
    if (!hasUrlOverlap) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_URL_NO_MATCH",
            detail: `Script UrlMatches [${urlMatches.join(", ")}] do not overlap project URLs [${projectPatterns.join(", ")}]`,
        };
    }

    // C8 — idempotent
    const isAlreadyAttached = project.scripts.some(
        (s) => s.path === script.id || s.path === script.name,
    );
    if (isAlreadyAttached) {
        return {
            ok: false,
            reason: "AUTOATTACH_ALREADY_ATTACHED",
            detail: `Script "${script.name}" already in project.scripts`,
        };
    }

    // C5 — run context compatibility (current pipeline only injects MAIN world)
    const declaredWorld = script.instruction.World;
    const isIncompatibleWorld =
        declaredWorld !== undefined && declaredWorld !== "MAIN";
    if (isIncompatibleWorld) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_INCOMPATIBLE_RUN_CONTEXT",
            detail: `Script declares World="${declaredWorld}"; pipeline requires MAIN`,
        };
    }

    // C6 — cookie bindings present on project
    const requiredCookies = script.instruction.RequiredCookies ?? [];
    const projectCookieNames = new Set(
        (project.cookies ?? []).map((c) => c.cookieName),
    );
    const missingCookie = requiredCookies.find(
        (name) => !projectCookieNames.has(name),
    );
    if (missingCookie !== undefined) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_COOKIE_BINDING_MISSING",
            detail: `Project has no cookie binding for "${missingCookie}"`,
        };
    }

    // C7 — dependencies present in library
    const declaredDeps = script.instruction.Dependencies ?? [];
    const missingDep = declaredDeps.find((depId) => !libraryIds.has(depId));
    if (missingDep !== undefined) {
        return {
            ok: false,
            reason: "AUTOATTACH_SKIPPED_DEP_MISSING",
            detail: `Dependency "${missingDep}" is not in the library`,
        };
    }

    // C3 — structural feasibility of InjectionConditions at attach-time
    const cond = script.instruction.InjectionConditions;
    const hasCookieRequirement =
        cond !== undefined && cond.requireCookie != null;
    if (hasCookieRequirement) {
        const cookieName = cond!.requireCookie as string;
        const isCookieBindable = projectCookieNames.has(cookieName);
        if (!isCookieBindable) {
            return {
                ok: false,
                reason: "AUTOATTACH_SKIPPED_CONDITION_FAIL",
                detail: `InjectionConditions.requireCookie="${cookieName}" has no project binding`,
            };
        }
    }

    return {
        ok: true,
        reason: "OK",
        detail: `All C1..C8 satisfied for "${script.name}"`,
    };
}

/**
 * Builds a ScriptEntry from a library script for insertion into project.scripts.
 * Caller is responsible for persisting the project and logging the attach.
 */
export function buildAttachedScriptEntry(
    script: LibraryScriptForAttach,
    order: number,
): ScriptEntry {
    return {
        path: script.id,
        order,
        runAt: script.instruction.RunAt ?? "document_idle",
    };
}

/**
 * Marco Extension — First-Attach Toast
 *
 * When auto-attach matches an origin for the *first time* in this
 * profile, we inject a lightweight in-page toast asking the user
 * whether they want Marco to keep attaching here. The toast has
 * three actions:
 *
 *   • Yes, keep attaching      → just mark origin as seen
 *   • Not now                  → tab-scoped dismiss (this tab only)
 *   • Don't ask for this site  → persistent dismiss + seen
 *
 * The toast posts a `window.postMessage` upward; a tiny script
 * shim listens and forwards via `chrome.runtime.sendMessage` to
 * the background bridge registered here.
 *
 * Restricted URLs (chrome://, chrome-extension:// of other
 * extensions, etc.) are skipped — `chrome.scripting.executeScript`
 * would throw and we'd just log + bail.
 *
 * No retry/backoff. Single attempt, fail-fast.
 *
 * See:
 *   - mem://features/auto-attach-policy (C9, first-attach intent)
 *   - .lovable/audits/ link-click "opens the extension" investigation
 */

import { logCaughtError, BgLogTag } from "./bg-logger";
import { isOriginSeen, markOriginSeen } from "./seen-origins";
import {
    isOriginDismissedForTab,
    dismissOriginForTab,
    persistDismissOrigin,
} from "./dismissed-origins";

const MSG_TYPE = "MARCO_FIRST_ATTACH_ACTION";

type ToastAction = "accept" | "dismiss-tab" | "dismiss-persist";

interface ToastActionMessage {
    type: typeof MSG_TYPE;
    action: ToastAction;
    url: string;
}

function isToastActionMessage(m: unknown): m is ToastActionMessage {
    if (m === null || typeof m !== "object") return false;
    const o = m as Record<string, unknown>;
    return o.type === MSG_TYPE
        && (o.action === "accept" || o.action === "dismiss-tab" || o.action === "dismiss-persist")
        && typeof o.url === "string";
}

/**
 * Renders a Marco-branded toast inside the page. Runs in the page's
 * MAIN world via `chrome.scripting.executeScript`.
 *
 * Self-contained: zero deps, inline styles, dark theme matching the
 * extension. Removes itself after any button click or 30s timeout.
 */
function toastPagePayload(origin: string): void {
    const ID = "marco-first-attach-toast";
    if (document.getElementById(ID)) return;

    const root = document.createElement("div");
    root.id = ID;
    root.setAttribute("role", "dialog");
    root.setAttribute("aria-label", "Marco auto-attach prompt");
    root.style.cssText = [
        "position:fixed",
        "bottom:20px",
        "right:20px",
        "z-index:2147483647",
        "max-width:340px",
        "padding:14px 16px",
        "background:#1a1a2e",
        "color:#e8edf3",
        "border:1px solid #2d2d4a",
        "border-radius:10px",
        "box-shadow:0 10px 30px rgba(0,0,0,0.45)",
        "font:13px/1.45 -apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif",
    ].join(";");

    const title = document.createElement("div");
    title.textContent = "Marco attached to this site";
    title.style.cssText = "font-weight:600;margin-bottom:4px;color:#fff";

    const body = document.createElement("div");
    body.textContent = `Keep auto-attaching on ${origin}?`;
    body.style.cssText = "color:#b8c0d0;margin-bottom:10px";

    const row = document.createElement("div");
    row.style.cssText = "display:flex;gap:6px;flex-wrap:wrap";

    function btn(label: string, action: string, primary: boolean): HTMLButtonElement {
        const b = document.createElement("button");
        b.textContent = label;
        b.dataset.action = action;
        b.style.cssText = [
            "padding:6px 10px",
            "border-radius:6px",
            "border:1px solid " + (primary ? "#4f46e5" : "#3a3a5a"),
            "background:" + (primary ? "#4f46e5" : "transparent"),
            "color:" + (primary ? "#fff" : "#e8edf3"),
            "font-size:12px",
            "cursor:pointer",
        ].join(";");
        return b;
    }

    const yes = btn("Yes, keep", "accept", true);
    const notNow = btn("Not now", "dismiss-tab", false);
    const never = btn("Don't ask for this site", "dismiss-persist", false);

    row.append(yes, notNow, never);
    root.append(title, body, row);
    document.documentElement.appendChild(root);

    let timeoutId: ReturnType<typeof window.setTimeout> | null = null;

    function cleanup(): void {
        if (timeoutId !== null) {
            window.clearTimeout(timeoutId);
            timeoutId = null;
        }
        root.removeEventListener("click", onClick);
        window.removeEventListener("pagehide", cleanup);
        if (root.isConnected) root.remove();
    }

    function send(action: string): void {
        window.postMessage(
            { type: "MARCO_FIRST_ATTACH_ACTION", action, url: window.location.href },
            window.location.origin,
        );
        cleanup();
    }

    function onClick(e: Event): void {
        const t = e.target as HTMLElement;
        const a = t?.dataset?.action;
        if (typeof a === "string" && a.length > 0) send(a);
    }

    root.addEventListener("click", onClick);
    window.addEventListener("pagehide", cleanup, { once: true });

    timeoutId = window.setTimeout(cleanup, 30_000);
}

/**
 * Tiny shim that runs alongside the toast: listens for the
 * window.postMessage from the toast and forwards it as a
 * chrome.runtime.sendMessage so the background bridge can react.
 */
function bridgePagePayload(): void {
    if ((window as unknown as { __marcoToastBridge?: boolean }).__marcoToastBridge) return;
    (window as unknown as { __marcoToastBridge?: boolean }).__marcoToastBridge = true;

    const cleanup = (): void => {
        window.removeEventListener("message", onMessage);
        window.removeEventListener("pagehide", cleanup);
        (window as unknown as { __marcoToastBridge?: boolean }).__marcoToastBridge = false;
    };

    const onMessage = (e: MessageEvent): void => {
        if (e.source !== window) return;
        const d = e.data;
        if (d === null || typeof d !== "object") return;
        const o = d as Record<string, unknown>;
        if (o.type !== "MARCO_FIRST_ATTACH_ACTION") return;
        try {
            chrome.runtime.sendMessage(o);
        } catch { // allow-swallow: SW asleep / port closed — single-attempt fail-fast per no-retry policy; user can retry from the toast
            /* intentionally empty */
        }
    };

    window.addEventListener("message", onMessage);
    window.addEventListener("pagehide", cleanup, { once: true });
}

/**
 * Inject the toast + bridge into the tab. Skips if origin already
 * seen, dismissed (tab or persistent), or if scripting fails.
 */
export async function maybeShowFirstAttachToast(
    tabId: number,
    url: string,
): Promise<void> {
    if (isOriginDismissedForTab(tabId, url)) return;
    if (isOriginSeen(url)) return;

    let origin = "";
    try { origin = new URL(url).origin; } catch { return; }
    if (origin === "") return;

    try {
        await chrome.scripting.executeScript({
            target: { tabId },
            world: "MAIN",
            func: toastPagePayload,
            args: [origin],
        });
        await chrome.scripting.executeScript({
            target: { tabId },
            world: "ISOLATED",
            func: bridgePagePayload,
        });
        // Optimistically mark seen so we don't double-fire on bursts;
        // user can still explicitly dismiss via the toast buttons.
        void markOriginSeen(url);
    } catch (err) {
        // Restricted URLs / closed tabs — log once, no retry.
        logCaughtError(
            BgLogTag.MARCO,
            `[first-attach-toast] inject skipped tab=${tabId} url=${url}`,
            err as Error,
        );
    }
}

/**
 * Register the runtime message bridge that handles toast actions.
 * Call once from boot.
 */
export function registerFirstAttachToastBridge(): void {
    chrome.runtime.onMessage.addListener((message, sender) => {
        if (!isToastActionMessage(message)) return false;
        const tabId = sender.tab?.id;
        const url = message.url;
        if (typeof tabId !== "number") return false;

        if (message.action === "accept") {
            void markOriginSeen(url);
        } else if (message.action === "dismiss-tab") {
            dismissOriginForTab(tabId, url);
        } else if (message.action === "dismiss-persist") {
            void persistDismissOrigin(url);
            void markOriginSeen(url);
        }
        console.log(
            `[first-attach-toast] action=${message.action} tab=${tabId} url=${url}`,
        );
        return false;
    });
}

/**
 * Marco Extension — Injection Request Resolver
 *
 * Normalizes popup injection requests into executable scripts.
 * Returns both resolved scripts and skipped entries with reasons.
 *
 * @see spec/05-chrome-extension/12-project-model-and-url-rules.md — Project model & URL matching
 * @see .lovable/memory/architecture/script-injection-pipeline-stages.md — Pipeline stages
 */

import type { InjectableScript, SkipReason } from "../../shared/injection-types";
import type { ScriptEntry } from "../../shared/project-types";
import type { ScriptBindingResolved } from "../../shared/types";
import { resolveScriptBindings, type SkippedScript } from "../script-resolver";
import { ensureBuiltinScriptsExist } from "../builtin-script-guard";
import { persistInjectionWarn } from "../injection-diagnostics";
import { readAllProjects } from "./project-helpers";
import { logBgWarnError, BgLogTag } from "../bg-logger";

/** Executable script plus its resolved config and theme JSON payloads. */
export interface PreparedInjectionScript {
    injectable: InjectableScript;
    configJson: string | null;
    themeJson: string | null;
    /** Where the script code came from — for injection diagnostics. */
    codeSource: string | null;
}

/** Full resolution result from the request resolver. */
export interface InjectionResolveResult {
    prepared: PreparedInjectionScript[];
    skipped: SkippedScript[];
}

/** Raw entry shape coming from popup / messaging surface (any of three flavors). */
type RawEntry = ScriptEntry | InjectableScript | Record<string, string | number | boolean | null | undefined>;

/** Classification of a single raw input entry. */
type Classified =
    | { kind: "project-entry"; value: ScriptEntry }
    | { kind: "injectable"; value: InjectableScript }
    | { kind: "empty-code"; id: string; name: string }
    | { kind: "malformed"; id: string; name: string; missing: string };

/** Resolves popup-provided scripts into executable injection inputs. */
// eslint-disable-next-line max-lines-per-function -- resolver with diagnostics logging
export async function resolveInjectionRequestScripts(
    scripts: RawEntry[],
): Promise<InjectionResolveResult> {
    const classified = scripts.map((entry, index) => classifyEntry(entry, index));
    const skipped: SkippedScript[] = [];

    const projectEntries: ScriptEntry[] = [];
    const injectables: InjectableScript[] = [];

    for (const item of classified) {
        if (item.kind === "project-entry") {
            projectEntries.push(item.value);
        } else if (item.kind === "injectable") {
            injectables.push(item.value);
        } else if (item.kind === "empty-code") {
            logBgWarnError(
                BgLogTag.INJECTION_RESOLVE,
                `Script '${item.name}' (id=${item.id}) has empty code — skipping (empty_code).`,
            );
            void persistInjectionWarn(
                "REQUEST_RESOLVER_EMPTY_CODE",
                `[injection:resolve] Inline script '${item.name}' (id=${item.id}) had empty code and was skipped`,
            );
            skipped.push({
                scriptId: item.id,
                scriptName: item.name,
                reason: "empty_code" as SkipReason,
            });
        } else {
            logBgWarnError(
                BgLogTag.INJECTION_RESOLVE,
                `Malformed script entry id=${item.id} name=${item.name} — missing required field(s): ${item.missing}. Skipping (resolver_mismatch).`,
            );
            void persistInjectionWarn(
                "REQUEST_RESOLVER_MISMATCH",
                `[injection:resolve] Malformed entry '${item.name}' (id=${item.id}) missing ${item.missing}, skipped`,
            );
            skipped.push({
                scriptId: item.id,
                scriptName: item.name,
                reason: "resolver_mismatch" as SkipReason,
            });
        }
    }

    const hasOnlyProjectEntries = projectEntries.length > 0 && injectables.length === 0;

    console.log(
        "[injection:resolve] Input: %d scripts → %d project-entries, %d injectables, %d skipped (mode=%s)",
        scripts.length,
        projectEntries.length,
        injectables.length,
        skipped.length,
        hasOnlyProjectEntries ? "project-store" : "passthrough",
    );

    if (hasOnlyProjectEntries) {
        const result = await resolveProjectEntryScripts(projectEntries);
        return {
            prepared: result.prepared,
            skipped: [...skipped, ...result.skipped],
        };
    }

    return {
        prepared: sortPreparedScripts(
            injectables.map((injectable) => ({
                injectable,
                configJson: null,
                themeJson: null,
                codeSource: null,
            })),
        ),
        skipped,
    };
}

/** Resolves stored project script entries through the script store. */
async function resolveProjectEntryScripts(
    entries: ScriptEntry[],
): Promise<InjectionResolveResult> {
    // ✅ Self-heal: reseed missing built-in scripts before resolving
    // Without this, the popup "Run Scripts" path skips the guard that
    // the auto-injector applies, causing "script not found in store".
    // See: spec/22-app-issues/check-button/11-popup-injection-missing-guard.md
    const projects = await readAllProjects();
    await ensureBuiltinScriptsExist(projects);

    const bindings = buildScriptBindings(entries);
    const { resolved, skipped } = await resolveScriptBindings(bindings);

    return {
        prepared: sortPreparedScripts(
            resolved.map(({ injectable, configJson, themeJson, codeSource }) => ({
                injectable,
                configJson,
                themeJson,
                codeSource: codeSource ?? null,
            })),
        ),
        skipped,
    };
}

/** Converts project script entries into background script bindings. */
function buildScriptBindings(entries: ScriptEntry[]): ScriptBindingResolved[] {
    return entries.map((script) => ({
        scriptId: script.path,
        configId: script.configBinding ?? null,
        order: script.order,
        world: "MAIN",
        runAt: script.runAt ?? "document_idle",
    }));
}

/** Classifies a raw entry into one of four buckets — never throws. */
function classifyEntry(entry: RawEntry, index: number): Classified {
    if (typeof entry !== "object" || entry === null) {
        return {
            kind: "malformed",
            id: `unknown-${index}`,
            name: `script-${index}`,
            missing: "entry is not an object",
        };
    }

    const candidate = entry as Record<string, unknown>;
    const rawId = typeof candidate.id === "string" ? candidate.id : null;
    const rawPath = typeof candidate.path === "string" ? candidate.path : null;
    const rawName = typeof candidate.name === "string" ? candidate.name : null;
    const rawCode = typeof candidate.code === "string" ? candidate.code : null;
    const rawOrder = typeof candidate.order === "number" ? candidate.order : null;

    const displayId = rawId ?? rawPath ?? `unknown-${index}`;
    const displayName = rawName ?? rawPath ?? displayId;

    // Project store entry shape: has `path` + `order`, no inline `code`.
    if (rawPath !== null && rawOrder !== null && !("code" in candidate)) {
        return { kind: "project-entry", value: entry as ScriptEntry };
    }

    // Inline injectable shape: needs id + code + order.
    const missing: string[] = [];
    if (rawId === null) missing.push("id");
    if (!("code" in candidate)) missing.push("code");
    if (rawOrder === null) missing.push("order");

    if (missing.length > 0) {
        return {
            kind: "malformed",
            id: displayId,
            name: displayName,
            missing: missing.join(", "),
        };
    }

    // id, code key, and order are all present — but code might be empty/non-string.
    if (rawCode === null) {
        return {
            kind: "malformed",
            id: displayId,
            name: displayName,
            missing: "code (must be a string)",
        };
    }
    if (rawCode.trim().length === 0) {
        return { kind: "empty-code", id: displayId, name: displayName };
    }

    return { kind: "injectable", value: entry as InjectableScript };
}

/** Sorts prepared scripts by execution order. */
function sortPreparedScripts(
    scripts: PreparedInjectionScript[],
): PreparedInjectionScript[] {
    return [...scripts].sort(
        (a, b) => a.injectable.order - b.injectable.order,
    );
}

/**
 * Unit test for logging-handler.normalizeRow.
 *
 * Verifies the PascalCase → camelCase column normalization contract used to
 * bridge SQLite rows (PascalCase) to the UI (camelCase) without dropping the
 * original keys for callers that already expect PascalCase.
 */

import { describe, it, expect } from "vitest";
import { normalizeRow } from "./logging-handler";
import type { SqlRow } from "./handler-types";

describe("normalizeRow", () => {
    it("returns a Record<string, SqlValue> with camelCased keys", () => {
        const row: SqlRow = {
            Timestamp: "2026-04-27T00:00:00.000Z",
            Level: "INFO",
            Source: "background",
            StackTrace: null,
        };

        const result = normalizeRow(row);

        expect(result).toEqual({
            Timestamp: "2026-04-27T00:00:00.000Z",
            timestamp: "2026-04-27T00:00:00.000Z",
            Level: "INFO",
            level: "INFO",
            Source: "background",
            source: "background",
            StackTrace: null,
            stackTrace: null,
        });
    });

    it("only lowercases the first character (preserves rest of key)", () => {
        const row: SqlRow = { ScriptId: "abc", ProjectId: "p1", ConfigId: "c1" };
        const result = normalizeRow(row);

        expect(result.scriptId).toBe("abc");
        expect(result.projectId).toBe("p1");
        expect(result.configId).toBe("c1");
        // Originals retained
        expect(result.ScriptId).toBe("abc");
        expect(result.ProjectId).toBe("p1");
        expect(result.ConfigId).toBe("c1");
    });

    it("does not duplicate keys that are already camelCase", () => {
        const row: SqlRow = { foo: "bar" };
        const result = normalizeRow(row);

        expect(result).toEqual({ foo: "bar" });
        expect(Object.keys(result)).toHaveLength(1);
    });

    it("preserves SqlValue types (number, null, Uint8Array)", () => {
        const blob = new Uint8Array([1, 2, 3]);
        const row: SqlRow = { SessionId: 42, Detail: null, Blob: blob };
        const result = normalizeRow(row);

        expect(result.sessionId).toBe(42);
        expect(result.detail).toBeNull();
        expect(result.blob).toBe(blob);
    });

    it("returns an empty object for an empty row", () => {
        expect(normalizeRow({})).toEqual({});
    });
});

/**
 * Marco Extension — Data-Source Drop-Zone Overlay
 *
 * Phase 07 — Macro Recorder.
 *
 * Renders a fixed full-viewport drop target inside a closed Shadow Root that
 * activates when the user drags a file over the page. Accepts CSV / JSON
 * files, parses them via {@link parseCsv} / {@link parseJson}, and forwards
 * the parsed result to the caller through {@link DropZoneOptions.OnFileDropped}.
 *
 * The overlay is *passive* — it never persists. The caller is expected to
 * forward the payload to `RECORDER_DATA_SOURCE_ADD` or equivalent.
 *
 * @see ./data-source-parsers.ts — Pure CSV/JSON parsers used here.
 * @see spec/31-macro-recorder/07-data-source-drop-zone.md
 */

import { DataSourceKindId } from "../recorder-db-schema";
import { parseCsv, parseJson, type ParsedDataSource } from "./data-source-parsers";

export const DROPZONE_HOST_ID = "marco-recorder-dropzone-host";

export interface DroppedDataSource {
    readonly FileName: string;
    readonly MimeKind: "csv" | "json";
    readonly RawText: string;
    readonly Parsed: ParsedDataSource;
}

export interface DropZoneOptions {
    readonly OnFileDropped: (file: DroppedDataSource) => void;
    /** Optional error sink — defaults to console.warn. */
    readonly OnError?: (err: Error, fileName: string) => void;
}

export interface DropZoneHandle {
    readonly Host: HTMLElement;
    readonly Root: ShadowRoot;
    /** True while a drag operation is hovering over the page. */
    IsActive(): boolean;
    Destroy(): void;
}

const STYLE = `
:host { all: initial; }
.overlay {
    position: fixed; inset: 0; z-index: 2147483646;
    display: none; align-items: center; justify-content: center;
    background: rgba(17, 17, 17, .55);
    pointer-events: none;
    font: 600 16px/1.4 system-ui, -apple-system, sans-serif;
    color: #fff;
}
.overlay[data-active="true"] { display: flex; pointer-events: auto; }
.panel {
    border: 2px dashed #fff; border-radius: 12px;
    padding: 28px 36px; background: rgba(0,0,0,.45);
    text-align: center;
}
.panel small { display: block; font-weight: 400; opacity: .75; margin-top: 6px; }
`;

export function mountDropZoneOverlay(
    options: DropZoneOptions,
    container: ParentNode = document.body,
): DropZoneHandle {
    if (container === null || container === undefined) {
        throw new Error("mountDropZoneOverlay: no container available");
    }

    const host = document.createElement("div");
    host.id = DROPZONE_HOST_ID;
    const root = host.attachShadow({ mode: "closed" });

    const style = document.createElement("style");
    style.textContent = STYLE;
    root.appendChild(style);

    const overlay = document.createElement("div");
    overlay.className = "overlay";
    overlay.dataset.active = "false";
    overlay.innerHTML =
        '<div class="panel">Drop CSV or JSON to attach<small>.csv · .json — first row used as header for CSV</small></div>';
    root.appendChild(overlay);
    container.appendChild(host);

    let dragDepth = 0;
    let active = false;

    function setActive(on: boolean): void {
        active = on;
        overlay.dataset.active = on ? "true" : "false";
    }

    function onDragEnter(e: DragEvent): void {
        if (!hasFiles(e.dataTransfer)) { return; }
        e.preventDefault();
        dragDepth += 1;
        if (dragDepth === 1) { setActive(true); }
    }
    function onDragOver(e: DragEvent): void {
        if (!hasFiles(e.dataTransfer)) { return; }
        e.preventDefault();
        if (e.dataTransfer !== null) { e.dataTransfer.dropEffect = "copy"; }
    }
    function onDragLeave(): void {
        dragDepth = Math.max(0, dragDepth - 1);
        if (dragDepth === 0) { setActive(false); }
    }
    function onDrop(e: DragEvent): void {
        e.preventDefault();
        dragDepth = 0;
        setActive(false);
        const files = e.dataTransfer?.files;
        if (files === undefined || files.length === 0) { return; }
        for (const f of Array.from(files)) {
            void handleFile(f, options);
        }
    }

    window.addEventListener("dragenter", onDragEnter);
    window.addEventListener("dragover",  onDragOver);
    window.addEventListener("dragleave", onDragLeave);
    window.addEventListener("drop",      onDrop);

    let destroyed = false;
    return {
        Host: host,
        Root: root,
        IsActive: () => active,
        Destroy: () => {
            if (destroyed) { return; }
            destroyed = true;
            window.removeEventListener("dragenter", onDragEnter);
            window.removeEventListener("dragover",  onDragOver);
            window.removeEventListener("dragleave", onDragLeave);
            window.removeEventListener("drop",      onDrop);
            host.remove();
        },
    };
}

function hasFiles(dt: DataTransfer | null): boolean {
    if (dt === null) { return false; }
    return Array.from(dt.types).includes("Files");
}

async function handleFile(file: File, options: DropZoneOptions): Promise<void> {
    const onError = options.OnError ?? ((err, name) => console.warn(`[DropZone] ${name}: ${err.message}`));
    try {
        const mimeKind = detectMimeKind(file);
        if (mimeKind === null) {
            throw new Error(`Unsupported file type — accepts .csv / .json (got '${file.name}')`);
        }
        const rawText = await file.text();
        const parsed = mimeKind === "csv" ? parseCsv(rawText) : parseJson(rawText);
        options.OnFileDropped({ FileName: file.name, MimeKind: mimeKind, RawText: rawText, Parsed: parsed });
    } catch (err) {
        onError(err instanceof Error ? err : new Error(String(err)), file.name);
    }
}

function detectMimeKind(file: File): "csv" | "json" | null {
    const lower = file.name.toLowerCase();
    if (lower.endsWith(".csv"))  { return "csv";  }
    if (lower.endsWith(".json")) { return "json"; }
    if (file.type === "text/csv")          { return "csv";  }
    if (file.type === "application/json")  { return "json"; }
    return null;
}

export { DataSourceKindId };

/**
 * Marco Extension — Recorder Failure Logger
 *
 * Single shared formatter for any failure raised during the macro
 * recorder's two pipelines: **Record** (capturing + persisting Steps) and
 * **Replay** (executing persisted Steps against the live DOM).
 *
 * The output is a structured `FailureReport` JSON document optimised for
 * AI debugging — the user can copy it from a toast or DevTools and paste
 * it directly into ChatGPT/Claude. Every report carries:
 *
 *   - `Phase`            — `"Record" | "Replay"`, the pipeline that failed.
 *   - `Message`          — short human-readable summary.
 *   - `StackTrace`       — `Error.stack` when available.
 *   - `Selectors`        — every selector kind/expression the executor tried.
 *   - `DomContext`       — tag/id/class/aria-label/text snippet of the
 *                          target element (replay) or capture element
 *                          (record), so the AI can spot selector drift.
 *   - `DataRow`          — active `{{Column}}` row at failure time, optional.
 *   - `StepId`/`Index`   — locate the step in the project's Step list.
 *   - `Timestamp`        — ISO string, deterministic via injected `Now`.
 *
 * Pure: no DOM mutation, no chrome.*, no async. The DOM read for
 * `DomContext` is a single `getBoundingClientRect`-free pass that tolerates
 * `null`/detached nodes.
 *
 * Conformance:
 *   - Every error site stamps an exact source location and tried-selector
 *     list per `spec/03-error-manage` rules ("HARD ERROR logs must include
 *     exact path, what was missing, and reasoning — optimized for AI
 *     consumption" — mem://standards/error-logging-requirements).
 *
 * @see spec/03-error-manage/01-error-resolution/06-error-documentation-guideline.md
 * @see ./live-dom-replay.ts          — Replay-phase caller.
 * @see ./capture-to-step-bridge.ts   — Record-phase data shape.
 */

import type { PersistedSelector } from "./step-persistence";
import type { FieldRow, VariableContext } from "./field-reference-resolver";
import type {
    EvaluatedAttempt,
    AttemptFailureReason,
} from "./selector-attempt-evaluator";
import { xpathOfElement } from "./xpath-of-element";
import {
    captureFormSnapshot,
    type FormSnapshot,
} from "./form-snapshot";

export type { VariableContext } from "./field-reference-resolver";
export type { FormSnapshot } from "./form-snapshot";

export type FailurePhase = "Record" | "Replay";

/**
 * Top-level short-code classifying the failure for AI grouping.
 * Stable string values — UI / exporters key off these.
 */
export type FailureReasonCode =
    // ---- Variable / data-row failures (highest priority — explain WHY the
    //      step had bad inputs before any selector was even tried). --------
    | "VariableMissing"        // {{Token}} references a column not in the row.
    | "VariableNull"           // Column exists but value is null.
    | "VariableUndefined"      // Column exists but value is undefined.
    | "VariableEmpty"          // Column exists but value is "".
    | "VariableTypeMismatch"   // Column present but wrong type for this step.
    // ---- Selector failures ------------------------------------------------
    | "ZeroMatches"            // No selector (primary or fallback) matched anything.
    | "PrimaryMissedFallbackOk" // Primary missed but a fallback matched — drift.
    | "XPathSyntaxError"       // At least one XPath threw during evaluation.
    | "CssSyntaxError"         // At least one CSS selector threw.
    | "UnresolvedAnchor"       // XPathRelative anchor chain broken / cyclic.
    | "EmptyExpression"        // A stored expression was "".
    | "NoSelectors"            // Step had zero selectors persisted.
    // ---- Other ------------------------------------------------------------
    | "Timeout"                // Wait/Retry exceeded budget (set by callers).
    | "ConditionTimeout"       // Gate condition not met within TimeoutMs (per spec 19 §2).
    | "JsThrew"                // JsInline step threw inside the sandbox.
    | "Unknown";               // Caller did not classify — last resort.

export interface SelectorAttempt {
    readonly SelectorId: number | null;
    readonly Strategy: string;             // "XPathFull" | "XPathRelative" | "Css" | "Aria" | …
    readonly Expression: string;           // Stored expression (may be relative).
    readonly ResolvedExpression: string;   // Anchor-joined expression actually evaluated.
    readonly IsPrimary: boolean;
    readonly Matched: boolean;
    readonly MatchCount: number;
    readonly FailureReason: AttemptFailureReason | "NotEvaluated";
    readonly FailureDetail: string | null;
}

export interface DomContext {
    readonly TagName: string;
    readonly Id: string | null;
    readonly ClassName: string | null;
    readonly AriaLabel: string | null;
    readonly Name: string | null;
    readonly Type: string | null;
    readonly TextSnippet: string;       // Always truncated to 120 chars (legacy contract).
    readonly OuterHtmlSnippet: string;  // Always truncated to 240 chars (legacy contract).
    /**
     * Absolute XPath of the captured element. Populated by `readDomContext`
     * when a target Element is supplied. Optional so external producers
     * (selector-comparison, selector-tester, fixtures) can omit it without
     * a forced migration; the verbose-logging spec requires it whenever a
     * fresh DOM read happens via `readDomContext`.
     */
    readonly XPath?: string;
    /**
     * Full untruncated outerHTML of the captured element. Populated ONLY
     * when the failure report is built with `Verbose: true`. Omitted on
     * non-verbose runs to keep the SQLite/OPFS payload small.
     */
    readonly OuterHtml?: string;
    /**
     * Full untruncated textContent. Populated ONLY when `Verbose: true`.
     */
    readonly Text?: string;
}

export interface FailureReport {
    readonly Phase: FailurePhase;
    readonly Message: string;
    readonly Reason: FailureReasonCode;
    readonly ReasonDetail: string;
    readonly StackTrace: string | null;
    readonly StepId: number | null;
    readonly Index: number | null;
    readonly StepKind: string | null;
    readonly Selectors: ReadonlyArray<SelectorAttempt>;
    readonly Variables: ReadonlyArray<VariableContext>;
    readonly DomContext: DomContext | null;
    readonly DataRow: FieldRow | null;
    readonly ResolvedXPath: string | null;
    readonly Timestamp: string;
    readonly SourceFile: string;
    /**
     * Was this report built with the verbose toggle ON? Persisted alongside
     * the report so future readers can tell whether `CapturedHtml` /
     * `DomContext.OuterHtml` / `DomContext.Text` are full or omitted.
     */
    readonly Verbose: boolean;
    /**
     * Full outerHTML of the matched/expected element. Populated ONLY when
     * `Verbose === true`. Always identical to `DomContext.OuterHtml` when
     * both are present — surfaced at top level for easier export tooling.
     */
    readonly CapturedHtml: string | null;
    /**
     * Snapshot of the form/inputs surrounding the failing step, captured
     * by `captureFormSnapshot`. Field metadata (names, types, required) is
     * ALWAYS populated when a form is reachable from the target — this
     * lets a debugger see "did the user even fill in 'email'?". Raw
     * values are present only when `Verbose === true`. Null when the
     * step has no nearby form or the caller passed `FormSnapshot: false`.
     *
     * See mem://features/form-snapshot-capture and
     * mem://standards/verbose-logging-and-failure-diagnostics.
     */
    readonly FormSnapshot: FormSnapshot | null;
}

export interface BuildFailureReportInput {
    readonly Phase: FailurePhase;
    readonly Error: unknown;
    readonly StepId?: number;
    readonly Index?: number;
    readonly StepKind?: string;
    /**
     * Persisted selectors as stored in the per-project DB. Used as a
     * fallback when `EvaluatedAttempts` is not supplied (e.g. Record
     * phase, where no live DOM evaluation happened).
     */
    readonly Selectors?: ReadonlyArray<PersistedSelector>;
    /**
     * Live-DOM evaluation outcomes, one per selector. When present this
     * supersedes `Selectors` because it carries Matched/MatchCount/Reason
     * per attempt — exactly what AI debuggers need.
     */
    readonly EvaluatedAttempts?: ReadonlyArray<EvaluatedAttempt>;
    readonly Target?: Element | null;
    readonly DataRow?: FieldRow;
    /**
     * Per-variable diagnostics for any `{{Token}}` referenced by the step's
     * Value template. Caller produces this with
     * `resolveFieldReferencesDetailed`. Drives the top-level Reason when
     * any variable failed (variable failures outrank selector failures
     * because they explain WHY the step had bad inputs to begin with).
     */
    readonly Variables?: ReadonlyArray<VariableContext>;
    readonly ResolvedXPath?: string;
    readonly SourceFile: string;        // e.g. "src/background/recorder/live-dom-replay.ts"
    /** Caller-supplied classification. Auto-derived from attempts/variables when omitted. */
    readonly Reason?: FailureReasonCode;
    readonly ReasonDetail?: string;
    /**
     * Verbose-logging toggle (per
     * mem://standards/verbose-logging-and-failure-diagnostics). When
     * `true`, the produced report includes the full untruncated outerHTML
     * + textContent of the captured `Target` and a top-level
     * `CapturedHtml` field. Default `false` keeps the legacy 120/240-char
     * truncation behavior. Callers MUST resolve this from
     * `resolveVerboseLogging(projectId)` — never hard-code `true`.
     */
    readonly Verbose?: boolean;
    /**
     * Pre-captured form snapshot from the recorder (preferred when the
     * step already carries one). When absent and a `Target` is supplied,
     * the failure logger captures one inline using `captureFormSnapshot`
     * with the same `Verbose` flag. Pass `null` explicitly to suppress.
     */
    readonly FormSnapshot?: FormSnapshot | null;
    readonly Now?: () => Date;
}

const SELECTOR_KIND_NAMES: Readonly<Record<number, string>> = {
    1: "XPathFull",
    2: "XPathRelative",
    3: "Css",
    4: "Aria",
};

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

export function buildFailureReport(input: BuildFailureReportInput): FailureReport {
    const now = input.Now ?? defaultNow;
    const message = extractMessage(input.Error);
    const stack = extractStack(input.Error);

    const attempts: ReadonlyArray<SelectorAttempt> =
        input.EvaluatedAttempts !== undefined
            ? input.EvaluatedAttempts.map(toAttemptFromEvaluated)
            : (input.Selectors ?? []).map(toAttemptFromPersisted);

    const variables: ReadonlyArray<VariableContext> = input.Variables ?? [];
    const { Reason, ReasonDetail } = classifyReason(input, attempts, variables, message);

    const verbose = input.Verbose === true;
    const domContext = input.Target ? readDomContext(input.Target, verbose) : null;
    const capturedHtml = verbose && domContext !== null
        ? (domContext.OuterHtml ?? null)
        : null;

    // Form snapshot precedence:
    //   1. Caller-supplied (recorder already attached one to the step) — use as-is.
    //   2. Caller passed `null` — explicit suppression.
    //   3. Otherwise capture fresh from the live Target using the same verbose flag.
    let formSnapshot: FormSnapshot | null = null;
    if (input.FormSnapshot !== undefined) {
        formSnapshot = input.FormSnapshot;
    } else if (input.Target) {
        formSnapshot = captureFormSnapshot(input.Target, { Verbose: verbose, Now: now });
    }

    return {
        Phase: input.Phase,
        Message: message,
        Reason,
        ReasonDetail,
        StackTrace: stack,
        StepId: input.StepId ?? null,
        Index: input.Index ?? null,
        StepKind: input.StepKind ?? null,
        Selectors: attempts,
        Variables: input.Variables ?? [],
        DomContext: domContext,
        DataRow: input.DataRow ?? null,
        ResolvedXPath: input.ResolvedXPath ?? null,
        Timestamp: now().toISOString(),
        SourceFile: input.SourceFile,
        Verbose: verbose,
        CapturedHtml: capturedHtml,
        FormSnapshot: formSnapshot,
    };
}

/**
 * Auto-classify the failure when the caller did not supply a Reason.
 *
 * Precedence (highest first):
 *   - Caller-supplied Reason       → wins
 *   - Variable failures (any)      → "VariableMissing" / "VariableNull" /
 *                                    "VariableUndefined" / "VariableEmpty" /
 *                                    "VariableTypeMismatch"
 *   - No selectors                 → "NoSelectors"
 *   - Any attempt threw XPath      → "XPathSyntaxError"
 *   - Any attempt threw CSS        → "CssSyntaxError"
 *   - Any anchor unresolved        → "UnresolvedAnchor"
 *   - Any expression empty         → "EmptyExpression"
 *   - Primary missed, fallback OK  → "PrimaryMissedFallbackOk"
 *   - All attempts returned 0      → "ZeroMatches"
 *   - Otherwise                    → "Unknown"
 */
function classifyReason(
    input: BuildFailureReportInput,
    attempts: ReadonlyArray<SelectorAttempt>,
    variables: ReadonlyArray<VariableContext>,
    message: string,
): { Reason: FailureReasonCode; ReasonDetail: string } {
    if (input.Reason !== undefined) {
        return {
            Reason: input.Reason,
            ReasonDetail: input.ReasonDetail ?? message,
        };
    }
    // Variable failures explain WHY the step's inputs were wrong before we
    // even tried the DOM — surface them first.
    const failedVar = variables.find((v) => v.FailureReason !== "Resolved");
    if (failedVar !== undefined) {
        const code = variableReasonToCode(failedVar.FailureReason);
        const detail = failedVar.FailureDetail ?? `Variable {{${failedVar.Name}}} failed.`;
        return { Reason: code, ReasonDetail: detail };
    }
    if (attempts.length === 0) {
        return { Reason: "NoSelectors", ReasonDetail: "Step has no persisted selectors to try." };
    }
    const reasons = new Set(attempts.map((a) => a.FailureReason));
    if (reasons.has("XPathSyntaxError")) {
        return { Reason: "XPathSyntaxError", ReasonDetail: firstDetail(attempts, "XPathSyntaxError") };
    }
    if (reasons.has("CssSyntaxError")) {
        return { Reason: "CssSyntaxError", ReasonDetail: firstDetail(attempts, "CssSyntaxError") };
    }
    if (reasons.has("UnresolvedAnchor")) {
        return { Reason: "UnresolvedAnchor", ReasonDetail: firstDetail(attempts, "UnresolvedAnchor") };
    }
    if (reasons.has("EmptyExpression")) {
        return { Reason: "EmptyExpression", ReasonDetail: firstDetail(attempts, "EmptyExpression") };
    }
    const primary = attempts.find((a) => a.IsPrimary) ?? null;
    const anyFallbackMatched = attempts.some((a) => !a.IsPrimary && a.Matched);
    if (primary !== null && !primary.Matched && anyFallbackMatched) {
        return {
            Reason: "PrimaryMissedFallbackOk",
            ReasonDetail:
                `Primary selector '${primary.ResolvedExpression}' missed; ` +
                `${attempts.filter((a) => !a.IsPrimary && a.Matched).length} fallback(s) matched.`,
        };
    }
    // Only claim ZeroMatches when at least one attempt was actually
    // evaluated against the live DOM — pure persisted selectors have
    // FailureReason === "NotEvaluated" and must not be misreported.
    const anyEvaluated = attempts.some((a) => a.FailureReason !== "NotEvaluated");
    if (anyEvaluated && attempts.every((a) => !a.Matched && a.MatchCount === 0)) {
        return {
            Reason: "ZeroMatches",
            ReasonDetail:
                `All ${attempts.length} selector(s) returned 0 nodes. ` +
                `Tried: ${attempts.map((a) => a.ResolvedExpression).join(" | ")}`,
        };
    }
    return { Reason: "Unknown", ReasonDetail: message };
}

function firstDetail(attempts: ReadonlyArray<SelectorAttempt>, code: AttemptFailureReason | "NotEvaluated"): string {
    const hit = attempts.find((a) => a.FailureReason === code);
    return hit?.FailureDetail ?? `Attempt failed with ${code}.`;
}

function variableReasonToCode(reason: VariableContext["FailureReason"]): FailureReasonCode {
    if (reason === "MissingColumn")   { return "VariableMissing"; }
    if (reason === "NullValue")       { return "VariableNull"; }
    if (reason === "UndefinedValue")  { return "VariableUndefined"; }
    if (reason === "EmptyString")     { return "VariableEmpty"; }
    if (reason === "TypeMismatch")    { return "VariableTypeMismatch"; }
    return "Unknown";
}

/**
 * Serializes a report to a multi-line block suitable for `console.error` or
 * a clipboard paste into AI chat. Format:
 *
 * ```
 * [MarcoReplay] Element not found for selector '#go'
 *   Reason: PrimaryMissedFallbackOk — Primary missed; 1 fallback matched.
 *   at src/background/recorder/live-dom-replay.ts StepId=42 Index=3
 *   Selectors:
 *     ✗ ✓ XPathFull   //button[@id='go'] → 0 matches (ZeroMatches: …)
 *     ✓ · Css         #go                → 1 matches
 *   DomContext: <button id="go" class="primary"> "Go"
 *   DataRow: { "Email": "alice@example.com" }
 *   Stack:
 *     <stack lines>
 * ```
 */
export function formatFailureReport(report: FailureReport): string {
    const tag = `[Marco${report.Phase}]`;
    const lines: string[] = [];
    lines.push(`${tag} ${report.Message}`);
    lines.push(`  Reason: ${report.Reason} — ${report.ReasonDetail}`);

    const where: string[] = [`at ${report.SourceFile}`];
    if (report.StepId !== null) where.push(`StepId=${report.StepId}`);
    if (report.Index !== null)  where.push(`Index=${report.Index}`);
    if (report.StepKind !== null) where.push(`Kind=${report.StepKind}`);
    lines.push(`  ${where.join(" ")}`);

    if (report.Selectors.length > 0) {
        lines.push("  Selectors:");
        for (const s of report.Selectors) {
            const matchMark = s.Matched ? "✓" : "✗";
            const primaryMark = s.IsPrimary ? "✓" : "·";
            const expr = s.ResolvedExpression.length > 0 ? s.ResolvedExpression : s.Expression;
            const detailSuffix = s.FailureDetail !== null ? `: ${s.FailureDetail}` : "";
            const tail = s.Matched
                ? `→ ${s.MatchCount} match${s.MatchCount === 1 ? "" : "es"}`
                : `→ ${s.MatchCount} matches (${s.FailureReason}${detailSuffix})`;
            lines.push(`    ${matchMark} ${primaryMark} ${s.Strategy.padEnd(13)} ${expr} ${tail}`);
        }

    }

    if (report.Variables.length > 0) {
        lines.push("  Variables:");
        for (const v of report.Variables) {
            const ok = v.FailureReason === "Resolved";
            const mark = ok ? "✓" : "✗";
            const valueLabel = v.ResolvedValue === null ? "<null>" : JSON.stringify(v.ResolvedValue);
            const detailSuffix = v.FailureDetail !== null ? `: ${v.FailureDetail}` : "";
            const tail = ok
                ? `${valueLabel} [${v.ValueType}] from ${v.Source}`
                : `${valueLabel} [${v.ValueType}] from ${v.Source} — ${v.FailureReason}${detailSuffix}`;
            lines.push(`    ${mark} {{${v.Name}}} = ${tail}`);

        }
    }

    if (report.ResolvedXPath !== null) {
        lines.push(`  ResolvedXPath: ${report.ResolvedXPath}`);
    }

    if (report.DomContext !== null) {
        const ctx = report.DomContext;
        const attrs: string[] = [];
        if (ctx.Id !== null)        attrs.push(`id="${ctx.Id}"`);
        if (ctx.ClassName !== null) attrs.push(`class="${ctx.ClassName}"`);
        if (ctx.Name !== null)      attrs.push(`name="${ctx.Name}"`);
        if (ctx.Type !== null)      attrs.push(`type="${ctx.Type}"`);
        if (ctx.AriaLabel !== null) attrs.push(`aria-label="${ctx.AriaLabel}"`);
        const attrStr = attrs.length > 0 ? ` ${attrs.join(" ")}` : "";
        const text = ctx.TextSnippet.length > 0 ? ` "${ctx.TextSnippet}"` : "";
        lines.push(`  DomContext: <${ctx.TagName}${attrStr}>${text}`);
        if (ctx.XPath !== undefined && ctx.XPath.length > 0) {
            lines.push(`    XPath: ${ctx.XPath}`);
        }
    }

    if (report.Verbose && report.CapturedHtml !== null) {
        lines.push(`  CapturedHtml (verbose):`);
        lines.push(`    ${report.CapturedHtml}`);
    }

    if (report.DataRow !== null) {
        lines.push(`  DataRow: ${JSON.stringify(report.DataRow)}`);
    }

    if (report.StackTrace !== null) {
        lines.push("  Stack:");
        for (const line of report.StackTrace.split("\n")) {
            lines.push(`    ${line.trim()}`);
        }
    }

    return lines.join("\n");
}

/**
 * Single entry point used by both pipelines. Writes the structured report
 * to `console.error` with the phase prefix and returns the report so the
 * caller can persist `JSON.stringify(report)` into the project DB and/or
 * surface a copy-to-clipboard toast.
 */
export function logFailure(input: BuildFailureReportInput): FailureReport {
    const report = buildFailureReport(input);
    console.error(formatFailureReport(report));
    return report;
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function extractMessage(err: unknown): string {
    if (err instanceof Error) return err.message;
    if (typeof err === "string") return err;
    try { return JSON.stringify(err); } catch { return String(err); }
}

function extractStack(err: unknown): string | null {
    if (err instanceof Error && typeof err.stack === "string") return err.stack;
    return null;
}

function toAttemptFromPersisted(s: PersistedSelector): SelectorAttempt {
    // Record-phase fallback: no live evaluation happened, so Matched /
    // MatchCount / FailureReason are reported as "NotEvaluated" so the
    // consumer can tell apart "we tried and it missed" vs "we never tried".
    return {
        SelectorId: s.SelectorId,
        Strategy: SELECTOR_KIND_NAMES[s.SelectorKindId] ?? `Kind${s.SelectorKindId}`,
        Expression: s.Expression,
        ResolvedExpression: s.Expression,
        IsPrimary: s.IsPrimary === 1,
        Matched: false,
        MatchCount: 0,
        FailureReason: "NotEvaluated",
        FailureDetail: null,
    };
}

function toAttemptFromEvaluated(a: EvaluatedAttempt): SelectorAttempt {
    return {
        SelectorId: a.SelectorId,
        Strategy: a.Strategy,
        Expression: a.Expression,
        ResolvedExpression: a.ResolvedExpression,
        IsPrimary: a.IsPrimary,
        Matched: a.Matched,
        MatchCount: a.MatchCount,
        FailureReason: a.FailureReason,
        FailureDetail: a.FailureDetail,
    };
}

function readDomContext(el: Element, verbose: boolean): DomContext {
    const id = el.getAttribute("id");
    const cls = el.getAttribute("class");
    const aria = el.getAttribute("aria-label");
    const name = el.getAttribute("name");
    const type = el.getAttribute("type");
    const fullText = (el.textContent ?? "").trim();
    const fullOuter = el.outerHTML ?? "";
    const text = fullText.slice(0, 120);
    const outer = fullOuter.slice(0, 240);
    const xpath = xpathOfElement(el);
    const base: DomContext = {
        TagName: el.tagName.toLowerCase(),
        Id: id !== null && id.length > 0 ? id : null,
        ClassName: cls !== null && cls.length > 0 ? cls : null,
        AriaLabel: aria !== null && aria.length > 0 ? aria : null,
        Name: name !== null && name.length > 0 ? name : null,
        Type: type !== null && type.length > 0 ? type : null,
        TextSnippet: text,
        OuterHtmlSnippet: outer,
        XPath: xpath,
    };
    if (verbose) {
        return { ...base, OuterHtml: fullOuter, Text: fullText };
    }
    return base;
}

function defaultNow(): Date {
    return new Date();
}

/**
 * Marco Extension — Hover Field-Binding Overlay
 *
 * Phase 08 — Macro Recorder.
 *
 * In-page UI mounted in a closed Shadow Root that follows the cursor as the
 * user hovers over input-like elements (`input`, `textarea`,
 * `[contenteditable]`). Shows a column picker — clicking a column emits a
 * binding payload that the caller persists via `RECORDER_FIELD_BINDING_UPSERT`.
 *
 * The overlay does *not* mutate the host page (no `{{Column}}` is written
 * into the input). It also previews the resolved value via
 * {@link resolveFieldReferences} when a sample row is supplied.
 *
 * ### Multi-column composer (Phase 08.1)
 * When the popover is pinned (user clicked the target), the overlay enters
 * composer mode: an editable template input + live preview let the user
 * combine multiple `{{Column}}` placeholders before committing. Clicking a
 * column appends `{{Column}}` to the template at the caret. The preview
 * resolves every placeholder against `SampleRow` on every keystroke.
 * Pressing "Bind" emits a single payload describing the full template.
 *
 * @see ./field-reference-resolver.ts — `{{Column}}` substitution
 * @see spec/31-macro-recorder/08-field-reference-wrapper.md
 */

import {
    extractReferencedColumns,
    resolveFieldReferences,
    type FieldRow,
} from "./field-reference-resolver";

export const FIELD_BINDING_HOST_ID = "marco-recorder-field-binding-host";

export interface FieldBindingOptions {
    /** Column names available in the active data source. */
    readonly Columns: ReadonlyArray<string>;
    /** Optional sample row used to preview the resolved value of a column. */
    readonly SampleRow?: FieldRow;
    /** Invoked when the user clicks a column for the currently-hovered field. */
    readonly OnBind: (binding: FieldBindingPayload) => void;
}

export interface FieldBindingPayload {
    readonly Target: HTMLElement;
    /**
     * The first column referenced by `Template`, or the single column the
     * user clicked. Kept for backwards compatibility with single-column
     * callers; multi-column templates expose every name via `Columns`.
     */
    readonly ColumnName: string;
    /** Every distinct column referenced in `Template`, in first-occurrence order. */
    readonly Columns: ReadonlyArray<string>;
    /** Final template, e.g. `"{{First}} {{Last}}"` or `"{{Email}}"`. */
    readonly Template: string;
    /** Resolved preview against `SampleRow`, or `null` when unavailable. */
    readonly PreviewValue: string | null;
}

export interface FieldBindingHandle {
    readonly Host: HTMLElement;
    readonly Root: ShadowRoot;
    /** Currently-hovered bindable element, if any. */
    GetHoveredTarget(): HTMLElement | null;
    /** Current composer template string. Empty when not in composer mode. */
    GetTemplate(): string;
    Destroy(): void;
}

