const BINDABLE_SELECTOR = "input, textarea, [contenteditable=''], [contenteditable='true']";

export function mountFieldBindingOverlay(
    options: FieldBindingOptions,
    container: ParentNode = document.body,
): FieldBindingHandle {
    if (container === null || container === undefined) {
        throw new Error("mountFieldBindingOverlay: no container available");
    }

    const host = document.createElement("div");
    host.id = FIELD_BINDING_HOST_ID;
    const root = host.attachShadow({ mode: "closed" });

    const style = document.createElement("style");
    style.textContent = STYLE;
    root.appendChild(style);

    const outline = document.createElement("div");
    outline.className = "outline";
    outline.dataset.open = "false";
    root.appendChild(outline);

    const popover = document.createElement("div");
    popover.className = "popover";
    popover.dataset.open = "false";
    popover.setAttribute("role", "menu");
    popover.setAttribute("aria-label", "Field bindings");
    root.appendChild(popover);

    container.appendChild(host);

    let hovered: HTMLElement | null = null;
    let pinned = false;
    let template = "";
    let templateInput: HTMLInputElement | null = null;
    let preview: HTMLDivElement | null = null;
    let tagsRow: HTMLDivElement | null = null;
    let bindBtn: HTMLButtonElement | null = null;
    let composer: HTMLDivElement | null = null;

    renderColumns();

    function renderColumns(): void {
        popover.innerHTML = "";
        const title = document.createElement("div");
        title.className = "title";
        title.textContent = "Bind to column";
        popover.appendChild(title);

        for (const col of options.Columns) {
            const btn = document.createElement("button");
            btn.type = "button";
            btn.className = "col";
            btn.dataset.column = col;
            btn.setAttribute("role", "menuitem");

            const name = document.createElement("span");
            name.className = "col-name";
            name.textContent = col;
            btn.appendChild(name);

            const colPreview = document.createElement("span");
            colPreview.className = "col-preview";
            colPreview.textContent = options.SampleRow?.[col] ?? "";
            btn.appendChild(colPreview);

            btn.addEventListener("mousedown", (e) => { e.preventDefault(); }); // don't blur target
            btn.addEventListener("click", () => { handleColumnClick(col); });
            popover.appendChild(btn);
        }

        composer = document.createElement("div");
        composer.className = "composer";
        composer.dataset.open = "false";

        const composerLabel = document.createElement("div");
        composerLabel.className = "title";
        composerLabel.textContent = "Template";
        composer.appendChild(composerLabel);

        templateInput = document.createElement("input");
        templateInput.type = "text";
        templateInput.className = "template-input";
        templateInput.placeholder = "{{First}} {{Last}}";
        templateInput.spellcheck = false;
        templateInput.addEventListener("input", () => {
            template = templateInput!.value;
            refreshPreview();
        });
        templateInput.addEventListener("mousedown", (e) => { e.stopPropagation(); });
        templateInput.addEventListener("click", (e) => { e.stopPropagation(); });
        composer.appendChild(templateInput);

        const previewLabel = document.createElement("div");
        previewLabel.className = "preview-label";
        previewLabel.textContent = "Preview";
        composer.appendChild(previewLabel);

        preview = document.createElement("div");
        preview.className = "preview";
        composer.appendChild(preview);

        tagsRow = document.createElement("div");
        tagsRow.className = "tags";
        composer.appendChild(tagsRow);

        const actions = document.createElement("div");
        actions.className = "actions";

        bindBtn = document.createElement("button");
        bindBtn.type = "button";
        bindBtn.className = "btn btn-primary";
        bindBtn.textContent = "Bind";
        bindBtn.addEventListener("mousedown", (e) => { e.preventDefault(); e.stopPropagation(); });
        bindBtn.addEventListener("click", (e) => { e.stopPropagation(); commitTemplate(); });
        actions.appendChild(bindBtn);

        const clearBtn = document.createElement("button");
        clearBtn.type = "button";
        clearBtn.className = "btn btn-secondary";
        clearBtn.textContent = "Clear";
        clearBtn.addEventListener("mousedown", (e) => { e.preventDefault(); e.stopPropagation(); });
        clearBtn.addEventListener("click", (e) => {
            e.stopPropagation();
            template = "";
            if (templateInput !== null) { templateInput.value = ""; }
            refreshPreview();
            templateInput?.focus();
        });
        actions.appendChild(clearBtn);

        composer.appendChild(actions);
        popover.appendChild(composer);
    }

    function handleColumnClick(col: string): void {
        if (hovered === null) { return; }
        const token = `{{${col}}}`;
        if (pinned) {
            // Composer mode: append (or insert at caret) and keep popover open.
            insertTokenIntoTemplate(token);
            refreshPreview();
            templateInput?.focus();
            return;
        }
        // Single-click flow: emit immediately for backwards compatibility.
        emitBinding(token);
        hide();
    }

    function insertTokenIntoTemplate(token: string): void {
        if (templateInput === null) {
            template = `${template}${token}`;
            return;
        }
        const start = templateInput.selectionStart ?? template.length;
        const end = templateInput.selectionEnd ?? template.length;
        const next = `${template.slice(0, start)}${token}${template.slice(end)}`;
        template = next;
        templateInput.value = next;
        const caret = start + token.length;
        templateInput.setSelectionRange(caret, caret);
    }

    function refreshPreview(): void {
        if (preview === null || tagsRow === null) { return; }
        tagsRow.innerHTML = "";
        const cols = extractReferencedColumns(template);
        for (const c of cols) {
            const tag = document.createElement("span");
            tag.className = "tag";
            tag.textContent = c;
            tagsRow.appendChild(tag);
        }

        if (template === "") {
            preview.textContent = "";
            preview.dataset.error = "false";
            if (bindBtn !== null) { bindBtn.disabled = true; }
            return;
        }

        if (options.SampleRow === undefined) {
            preview.textContent = template;
            preview.dataset.error = "false";
        } else {
            try {
                preview.textContent = resolveFieldReferences(template, options.SampleRow);
                preview.dataset.error = "false";
            } catch (err) {
                preview.textContent = err instanceof Error ? err.message : String(err);
                preview.dataset.error = "true";
            }
        }
        if (bindBtn !== null) { bindBtn.disabled = false; }
    }

    function commitTemplate(): void {
        if (hovered === null || template === "") { return; }
        emitBinding(template);
        pinned = false;
        template = "";
        if (templateInput !== null) { templateInput.value = ""; }
        refreshPreview();
        hide();
    }

    function emitBinding(tpl: string): void {
        if (hovered === null) { return; }
        const cols = extractReferencedColumns(tpl);
        const primary = cols[0] ?? "";
        let previewValue: string | null = null;
        if (options.SampleRow !== undefined) {
            try { previewValue = resolveFieldReferences(tpl, options.SampleRow); }
            catch { previewValue = null; }
        }
        options.OnBind({
            Target: hovered,
            ColumnName: primary,
            Columns: cols,
            Template: tpl,
            PreviewValue: previewValue,
        });
    }

    function show(target: HTMLElement): void {
        hovered = target;
        const rect = target.getBoundingClientRect();
        outline.style.left   = `${rect.left}px`;
        outline.style.top    = `${rect.top}px`;
        outline.style.width  = `${rect.width}px`;
        outline.style.height = `${rect.height}px`;
        outline.dataset.open = "true";

        popover.style.left = `${rect.left}px`;
        popover.style.top  = `${rect.bottom + 6}px`;
        popover.dataset.open = "true";

        if (composer !== null) {
            composer.dataset.open = pinned ? "true" : "false";
        }
        if (pinned) {
            refreshPreview();
        }
    }
    function hide(): void {
        if (pinned) { return; }
        hovered = null;
        outline.dataset.open = "false";
        popover.dataset.open = "false";
        if (composer !== null) { composer.dataset.open = "false"; }
    }

    function isOurNode(node: EventTarget | null): boolean {
        return node === host || (node instanceof Node && host.contains(node));
    }

    function onMove(e: MouseEvent): void {
        if (pinned) { return; }
        const t = e.target;
        if (isOurNode(t)) { return; }
        if (!(t instanceof HTMLElement)) { hide(); return; }
        const candidate = t.closest(BINDABLE_SELECTOR);
        if (candidate instanceof HTMLElement) {
            show(candidate);
        } else {
            hide();
        }
    }

    function onClick(e: MouseEvent): void {
        const t = e.target;
        if (isOurNode(t)) { return; }
        if (!(t instanceof HTMLElement)) { return; }
        const candidate = t.closest(BINDABLE_SELECTOR);
        if (candidate instanceof HTMLElement) {
            e.preventDefault();
            pinned = true;
            show(candidate);
            refreshPreview();
        } else {
            pinned = false;
            template = "";
            if (templateInput !== null) { templateInput.value = ""; }
            hide();
        }
    }

    document.addEventListener("mousemove", onMove, true);
    document.addEventListener("click",     onClick, true);

    let destroyed = false;
    return {
        Host: host,
        Root: root,
        GetHoveredTarget: () => hovered,
        GetTemplate: () => template,
        Destroy: () => {
            if (destroyed) { return; }
            destroyed = true;
            document.removeEventListener("mousemove", onMove, true);
            document.removeEventListener("click",     onClick, true);
            host.remove();
        },
    };
}

/**
 * Marco Extension — Field Reference Resolver
 *
 * Phase 08 — Macro Recorder.
 *
 * Replaces `{{ColumnName}}` tokens in a template string with values from the
 * current data-source row. Used by the replay engine (Phase 09) and by the
 * preview tooltip in the field-binding UI (Phase 09).
 *
 * Rules:
 *   - Token syntax: `{{ColumnName}}` — PascalCase, no spaces, no expressions.
 *   - Whitespace inside the braces is tolerated: `{{ Email }}` works.
 *   - Unknown columns raise — silent fallbacks would corrupt replay data.
 *   - Escaped braces (`\{{Foo}}`) are emitted literally as `{{Foo}}`.
 *
 * Pure: no DOM, no chrome, no async — fully unit-testable.
 */

import type { JsonValue } from "../handlers/handler-types";
import { isSensitiveDiagnosticName, maskDiagnosticValue } from "./sensitive-diagnostics";

const TOKEN_PATTERN = /\\?\{\{\s*([A-Za-z_][A-Za-z0-9_]*)\s*\}\}/g;

export type FieldRow = Readonly<Record<string, string>>;

/**
 * Loose row shape used by the diagnostics path. Real-world rows can carry
 * `null` (SQLite NULL), numbers, booleans, or arbitrary objects from JS
 * step output. We accept all of them so the variable-failure log can
 * report the *actual* type that arrived rather than crashing the resolver.
 */
export type LooseFieldRow = Readonly<Record<string, JsonValue | undefined>>;

/**
 * Per-variable diagnostic record attached to failure logs. One entry per
 * `{{Token}}` referenced by the template — including ones that resolved
 * successfully, so AI debuggers can see the entire input surface.
 *
 * Conformance: mem://standards/verbose-logging-and-failure-diagnostics
 *   "Every failure MUST log full VariableContext[] with name + source +
 *    resolvedValue + valueType + reason; never omit silently."
 */
export type VariableValueType =
    | "string" | "number" | "boolean" | "null" | "undefined" | "object" | "array";

export type VariableFailureReason =
    | "Resolved"           // Not a failure — kept so the union covers OK rows.
    | "MissingColumn"      // The token references a column that is not in the row at all.
    | "NullValue"          // Column exists but value is null.
    | "UndefinedValue"     // Column exists but value is undefined.
    | "EmptyString"        // Column exists, value is "" — usually fatal for required inputs.
    | "TypeMismatch";      // Value present but not the type the step expected.

export interface VariableContext {
    readonly Name: string;                 // e.g. "Email"
    readonly Source: string;               // e.g. "DataSource:CustomersV2", "Row", "ProjectVar"
    readonly RowIndex: number | null;
    readonly Column: string | null;
    readonly ResolvedValue: JsonValue | null; // JSON-compatible value; null when MissingColumn/NullValue/UndefinedValue
    readonly ValueType: VariableValueType;
    readonly FailureReason: VariableFailureReason;
    readonly FailureDetail: string | null; // human sentence; null when Resolved
}

export interface ResolveDetailedResult {
    readonly Resolved: string;             // partial resolution — failed tokens emit "" so the caller can still preview
    readonly Variables: ReadonlyArray<VariableContext>;
    readonly FirstFailure: VariableContext | null;
}

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Resolve every `{{Column}}` token in `template` against `row`.
 * Throws when a referenced column is not present in `row`.
 */
export function resolveFieldReferences(
    template: string,
    row: FieldRow,
): string {
    return template.replace(TOKEN_PATTERN, (match, name: string) => {
        const isEscaped = match.charAt(0) === "\\";
        if (isEscaped) return match.slice(1);

        const hasColumn = Object.prototype.hasOwnProperty.call(row, name);
        if (hasColumn === false) {
            throw new Error(`Field reference {{${name}}} — column missing in row`);
        }

        return row[name] ?? "";
    });
}

/**
 * Diagnostic resolver. Never throws — always returns a `ResolveDetailedResult`
 * so the caller can decide whether to abort the step or pass the partial
 * substitution downstream while still attaching the full `Variables` array
 * to a failure report.
 *
 * Failure-reason precedence (per token):
 *   1. MissingColumn  — column not in row at all
 *   2. NullValue      — present, but `null`
 *   3. UndefinedValue — present, but `undefined`
 *   4. EmptyString    — present, but ""
 *   5. TypeMismatch   — present, but not string/number/boolean (object/array)
 *
 * @param expectedType — caller's contract for what the resolved value
 *                       should be. Defaults to "string" (Type/Select steps).
 * @param source       — free-text origin label, e.g. "DataSource:Customers".
 * @param rowIndex     — index in the source data set, when known.
 */
export function resolveFieldReferencesDetailed(
    template: string,
    row: LooseFieldRow,
    options: {
        readonly Source?: string;
        readonly RowIndex?: number;
        readonly ExpectedType?: VariableValueType;
    } = {},
): ResolveDetailedResult {
    const source = options.Source ?? "Row";
    const rowIndex = options.RowIndex ?? null;
    const expected = options.ExpectedType ?? "string";

    const seen = new Map<string, VariableContext>();
    let firstFailure: VariableContext | null = null;

    const resolved = template.replace(TOKEN_PATTERN, (match, name: string) => {
        const isEscaped = match.charAt(0) === "\\";
        if (isEscaped) { return match.slice(1); }

        // Deduplicate per-name so repeated tokens produce one diagnostic.
        const cached = seen.get(name);
        if (cached !== undefined) {
            return valueToReplacement(cached.ResolvedValue);
        }

        const ctx = classifyVariable(name, row, source, rowIndex, expected);
        seen.set(name, ctx);
        if (ctx.FailureReason !== "Resolved" && firstFailure === null) {
            firstFailure = ctx;
        }
        return valueToReplacement(ctx.ResolvedValue);
    });

    return {
        Resolved: resolved,
        Variables: Array.from(seen.values()),
        FirstFailure: firstFailure,
    };
}

/* ------------------------------------------------------------------ */
/*  Static analysis                                                    */
/* ------------------------------------------------------------------ */

/** Lists every distinct column name referenced in a template. */
export function extractReferencedColumns(template: string): ReadonlyArray<string> {
    const found = new Set<string>();
    const pattern = new RegExp(TOKEN_PATTERN.source, "g");
    let match: RegExpExecArray | null;

    while ((match = pattern.exec(template)) !== null) {
        const isEscaped = match[0].charAt(0) === "\\";
        if (isEscaped === false) {
            found.add(match[1]!);
        }
    }

    return Array.from(found);
}

/* ------------------------------------------------------------------ */
/*  Internals                                                          */
/* ------------------------------------------------------------------ */

function classifyVariable(
    name: string,
    row: LooseFieldRow,
    source: string,
    rowIndex: number | null,
    expected: VariableValueType,
): VariableContext {
    const hasColumn = Object.prototype.hasOwnProperty.call(row, name);
    if (!hasColumn) {
        return {
            Name: name, Source: source, RowIndex: rowIndex, Column: name,
            ResolvedValue: null, ValueType: "undefined",
            FailureReason: "MissingColumn",
            FailureDetail: (() => {
                const rowSuffix = rowIndex !== null ? `, rowIndex=${rowIndex}` : "";
                const columnList = Object.keys(row).join(", ") || "<empty>";
                return `Variable {{${name}}} is not a column in the active row `
                    + `(source=${source}${rowSuffix}). `
                    + `Available columns: [${columnList}].`;
            })(),
        };

    }

    const raw = row[name];
    const valueType = classifyType(raw);

    if (raw === null) {
        return baseFailure(name, source, rowIndex, null, "null", "NullValue",
            `Variable {{${name}}} resolved to null (source=${source}, column=${name}).`);
    }
    if (raw === undefined) {
        return baseFailure(name, source, rowIndex, null, "undefined", "UndefinedValue",
            `Variable {{${name}}} resolved to undefined (source=${source}, column=${name}).`);
    }
    if (typeof raw === "string" && raw.length === 0) {
        return baseFailure(name, source, rowIndex, "", "string", "EmptyString",
            `Variable {{${name}}} resolved to an empty string (source=${source}, column=${name}). ` +
            `If empty is valid for this step, ignore.`);
    }

    // Type-mismatch only fires when caller expected a primitive but got object/array.
    const isPrimitive = valueType === "string" || valueType === "number" || valueType === "boolean";
    if (!isPrimitive && expected !== "object" && expected !== "array") {
        const redacted = sanitizeDiagnosticValue(name, raw);
        const display = safeStringify(redacted);
        return baseFailure(name, source, rowIndex, redacted, valueType, "TypeMismatch",
            `Variable {{${name}}} expected ${expected} but got ${valueType} ` +
            `(source=${source}, column=${name}, value=${display}).`);
    }

    const resolved = sanitizeDiagnosticValue(name, raw);
    return {
        Name: name, Source: source, RowIndex: rowIndex, Column: name,
        ResolvedValue: resolved,
        ValueType: valueType,
        FailureReason: "Resolved",
        FailureDetail: null,
    };
}

function baseFailure(
    name: string,
    source: string,
    rowIndex: number | null,
    resolved: JsonValue | null,
    valueType: VariableValueType,
    reason: VariableFailureReason,
    detail: string,
): VariableContext {
    return {
        Name: name, Source: source, RowIndex: rowIndex, Column: name,
        ResolvedValue: resolved, ValueType: valueType,
        FailureReason: reason, FailureDetail: detail,
    };
}

function classifyType(v: JsonValue | undefined): VariableValueType {
    if (v === null) { return "null"; }
    if (v === undefined) { return "undefined"; }
    if (Array.isArray(v)) { return "array"; }
    const t = typeof v;
    if (t === "string" || t === "number" || t === "boolean" || t === "object") { return t; }
    return "object";
}

function sanitizeDiagnosticValue(name: string, value: JsonValue): JsonValue {
    if (isSensitiveDiagnosticName(name)) {
        return maskDiagnosticValue(value);
    }
    return value;
}

function safeStringify(v: JsonValue): string {
    try { return JSON.stringify(v) ?? "undefined"; } catch { return String(v); }
}

function valueToReplacement(value: JsonValue | null): string {
    if (value === null) { return ""; }
    if (typeof value === "string") { return value; }
    return safeStringify(value);
}

/**
 * Marco Extension — Hover Highlighter
 *
 * Phase 17 — Macro Recorder.
 *
 * Renders two nested overlays — a primary outline of the element under the
 * cursor and a dashed outline of its smart group container — into a single
 * shadow-root host with `pointer-events: none`. No DOM mutation of the
 * inspected element. Active in three modes:
 *
 *   - "recording" — auto-on while a recorder session runs.
 *   - "replay"   — auto-on while the replay runner ticks (listens for
 *                  `replay:step:start` / `replay:step:end` CustomEvents).
 *   - "inspector" — on-demand toggle from the recorder toolbar.
 *
 * Alt-key cycling: while Alt is held, mouse-wheel up/down moves the primary
 * outline up/down the ancestor chain; releasing Alt resets the offset on the
 * next mousemove.
 *
 * @see spec/31-macro-recorder/17-hover-highlighter-and-data-controllers.md
 */

export type HighlighterMode = "off" | "recording" | "replay" | "inspector";

export interface HoverHighlighterHandle {
    readonly Host: HTMLElement;
    SetMode(mode: HighlighterMode): void;
    GetMode(): HighlighterMode;
    /** Manually outline an element (used by replay listeners). */
    Outline(target: Element | null): void;
    Destroy(): void;
}

export const HOVER_HIGHLIGHTER_HOST_ID = "marco-hover-highlighter";

const SMART_GROUP_ROLE_SELECTOR =
    '[role="group"], [role="region"], [role="listitem"], [role="row"]';

/* ------------------------------------------------------------------ */
/*  Smart group detection (spec §1.3)                                  */
/* ------------------------------------------------------------------ */

export function findSmartGroup(el: Element): Element | null {
    const form = el.closest("form");
    if (form !== null) return form;

    const fieldset = el.closest("fieldset");
    if (fieldset !== null) return fieldset;

    const tr = el.closest("tr");
    if (tr !== null) return tr;

    const role = el.closest(SMART_GROUP_ROLE_SELECTOR);
    if (role !== null) return role;

    const cardLike = closestByClassToken(el, ["card", "panel", "field-row", "form-group"]);
    if (cardLike !== null) return cardLike;

    const flexGrid = closestFlexOrGrid(el);
    if (flexGrid !== null) return flexGrid;

    return el.parentElement;
}

function closestByClassToken(el: Element, tokens: ReadonlyArray<string>): Element | null {
    let current: Element | null = el;
    while (current !== null) {
        const cls = current.className;
        const isString = typeof cls === "string";
        if (isString) {
            const lower = cls.toLowerCase();
            const hasToken = tokens.some((t) => lower.includes(t));
            if (hasToken) return current;
        }
        current = current.parentElement;
    }
    return null;
}

function closestFlexOrGrid(el: Element): Element | null {
    let current: Element | null = el.parentElement;
    while (current !== null) {
        const styles = current.ownerDocument?.defaultView?.getComputedStyle(current);
        const display = styles?.display ?? "";
        const isFlexOrGrid = display === "flex" || display === "grid";
        const hasMultipleChildren = current.childElementCount >= 2;
        if (isFlexOrGrid && hasMultipleChildren) return current;
        current = current.parentElement;
    }
    return null;
}

/* ------------------------------------------------------------------ */
/*  Ancestor offset                                                    */
/* ------------------------------------------------------------------ */

export function nthAncestor(el: Element, depth: number): Element {
    let current: Element = el;
    let remaining = depth;
    while (remaining > 0 && current.parentElement !== null) {
        current = current.parentElement;
        remaining--;
    }
    return current;
}

/* ------------------------------------------------------------------ */
/*  Mount                                                              */
/* ------------------------------------------------------------------ */

interface InternalState {
    Mode: HighlighterMode;
    HoverTarget: Element | null;
    AncestorOffset: number;
    AltHeld: boolean;
    RafToken: number | null;
}

const STYLE = `
:host { all: initial; }
.outline-primary, .outline-group, .chip {
    position: fixed;
    pointer-events: none;
    box-sizing: border-box;
    z-index: 2147483647;
    transition: transform 80ms linear, width 80ms linear, height 80ms linear;
}
.outline-primary {
    border: 2px solid hsl(217 91% 60%);
    background: hsla(217, 91%, 60%, 0.08);
    border-radius: 2px;
}
.outline-group {
    border: 1px dashed hsl(280 80% 65%);
    border-radius: 4px;
}
.chip {
    font: 11px/1.4 ui-monospace, monospace;
    background: hsl(222 47% 11% / 0.92);
    color: hsl(0 0% 100%);
    padding: 2px 6px;
    border-radius: 3px;
    white-space: nowrap;
    max-width: 360px;
    overflow: hidden;
    text-overflow: ellipsis;
}
.hidden { display: none; }
`;

export function mountHoverHighlighter(
    doc: Document = document,
): HoverHighlighterHandle {
    const existing = doc.getElementById(HOVER_HIGHLIGHTER_HOST_ID);
    if (existing !== null) existing.remove();

    const host = doc.createElement("div");
    host.id = HOVER_HIGHLIGHTER_HOST_ID;
    host.style.cssText = "position:fixed;inset:0;pointer-events:none;z-index:2147483647;";
    doc.body.appendChild(host);

    const root = host.attachShadow({ mode: "closed" });
    const style = doc.createElement("style");
    style.textContent = STYLE;
    root.appendChild(style);

    const groupEl = doc.createElement("div");
    groupEl.className = "outline-group hidden";
    const primaryEl = doc.createElement("div");
    primaryEl.className = "outline-primary hidden";
    const chipEl = doc.createElement("div");
    chipEl.className = "chip hidden";
    root.append(groupEl, primaryEl, chipEl);

    const state: InternalState = {
        Mode: "off",
        HoverTarget: null,
        AncestorOffset: 0,
        AltHeld: false,
        RafToken: null,
    };

    function paint(): void {
        state.RafToken = null;
        const target = state.HoverTarget;
        if (target === null || state.Mode === "off") {
            primaryEl.classList.add("hidden");
            groupEl.classList.add("hidden");
            chipEl.classList.add("hidden");
            return;
        }

        const resolved = nthAncestor(target, state.AncestorOffset);
        const group = findSmartGroup(resolved);

        applyRect(primaryEl, resolved.getBoundingClientRect());
        primaryEl.classList.remove("hidden");

        if (group !== null && group !== resolved) {
            applyRect(groupEl, group.getBoundingClientRect());
            groupEl.classList.remove("hidden");
        } else {
            groupEl.classList.add("hidden");
        }

        const r = resolved.getBoundingClientRect();
        chipEl.textContent = describeElement(resolved, state.AncestorOffset);
        chipEl.style.transform = `translate(${Math.round(r.left)}px, ${Math.round(Math.max(r.top - 18, 0))}px)`;
        chipEl.classList.remove("hidden");
    }

    function schedulePaint(): void {
        if (state.RafToken !== null) return;
        const win = doc.defaultView;
        if (win === null) return;
        state.RafToken = win.requestAnimationFrame(paint);
    }

    function onMouseMove(ev: MouseEvent): void {
        if (state.Mode === "off") return;
        const t = ev.target;
        const isElement = t instanceof Element;
        if (isElement === false) return;
        const el = t as Element;
        if (host.contains(el)) return;
        if (state.HoverTarget !== el) {
            state.HoverTarget = el;
            if (state.AltHeld === false) state.AncestorOffset = 0;
        }
        schedulePaint();
    }

    function onKeyDown(ev: KeyboardEvent): void {
        if (ev.key === "Alt") {
            state.AltHeld = true;
            if (state.AncestorOffset === 0) state.AncestorOffset = 1;
            schedulePaint();
        }
    }

    function onKeyUp(ev: KeyboardEvent): void {
        if (ev.key === "Alt") state.AltHeld = false;
    }

    function onWheel(ev: WheelEvent): void {
        if (state.AltHeld === false) return;
        const direction = ev.deltaY < 0 ? 1 : -1;
        state.AncestorOffset = Math.max(0, state.AncestorOffset + direction);
        schedulePaint();
    }

    function onReplayStart(ev: Event): void {
        if (state.Mode !== "replay") return;
        const detail = (ev as CustomEvent<{ Element?: Element }>).detail;
        const el = detail?.Element ?? null;
        if (el !== null) {
            state.HoverTarget = el;
            state.AncestorOffset = 0;
            schedulePaint();
        }
    }

    function onReplayEnd(): void {
        if (state.Mode !== "replay") return;
        state.HoverTarget = null;
        schedulePaint();
    }

    doc.addEventListener("mousemove", onMouseMove, { passive: true });
    doc.addEventListener("keydown", onKeyDown, { passive: true });
    doc.addEventListener("keyup", onKeyUp, { passive: true });
    doc.addEventListener("wheel", onWheel, { passive: true });
    doc.addEventListener("replay:step:start", onReplayStart);
    doc.addEventListener("replay:step:end", onReplayEnd);

    return {
        Host: host,
        SetMode(mode) {
            state.Mode = mode;
            if (mode === "off") {
                state.HoverTarget = null;
                state.AncestorOffset = 0;
            }
            schedulePaint();
        },
        GetMode() { return state.Mode; },
        Outline(target) {
            state.HoverTarget = target;
            state.AncestorOffset = 0;
            schedulePaint();
        },
        Destroy() {
            doc.removeEventListener("mousemove", onMouseMove);
            doc.removeEventListener("keydown", onKeyDown);
            doc.removeEventListener("keyup", onKeyUp);
            doc.removeEventListener("wheel", onWheel);
            doc.removeEventListener("replay:step:start", onReplayStart);
            doc.removeEventListener("replay:step:end", onReplayEnd);
            host.remove();
        },
    };
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function applyRect(el: HTMLElement, r: DOMRect): void {
    el.style.transform = `translate(${Math.round(r.left)}px, ${Math.round(r.top)}px)`;
    el.style.width = `${Math.round(r.width)}px`;
    el.style.height = `${Math.round(r.height)}px`;
}

export function describeElement(el: Element, depthOffset: number): string {
    const tag = el.tagName.toLowerCase();
    const id = el.id !== "" ? `#${el.id}` : "";
    const cls = typeof el.className === "string" && el.className !== ""
        ? "." + el.className.trim().split(/\s+/).slice(0, 3).join(".")
        : "";
    const depth = depthOffset > 0 ? `  · depth +${depthOffset}` : "";
    return `${tag}${id}${cls}${depth}`;
}

/**
 * Marco Extension — HttpRequest Step (Spec 17 §3)
 *
 * A new replay step kind that performs an HTTP call, optionally interpolating
 * `{{Column}}` placeholders against the active data row. Intended for sending
 * collected form values back to a backend, or pulling fresh data mid-run.
 *
 * Pure module — no chrome.* / DOM dependencies. Failures are returned as a
 * structured object (not thrown) so the recorder failure pipeline can attach
 * verbose-log tail / row vars / selectors per the project standard.
 *
 * @see spec/31-macro-recorder/17-hover-highlighter-and-data-controllers.md §3
 * @see mem://standards/verbose-logging-and-failure-diagnostics
 */

export interface HttpRequestParams {
    readonly Url: string;
    readonly Method: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
    readonly HeadersJson?: string;
    readonly BodyJson?: string;
    readonly CaptureAs?: string;
    readonly TimeoutMs?: number;
}

export type HttpStepReason =
    | "Ok"
    | "EndpointHttpError"
    | "EndpointTimeout"
    | "EndpointParseError"
    | "BadParams";

export interface HttpStepResult {
    readonly Reason: HttpStepReason;
    readonly Status?: number;
    readonly ResponseSnippet?: string;
    readonly CapturedValue?: unknown;
    readonly ResolvedUrl: string;
    readonly ResolvedMethod: string;
    readonly ResolvedHeaders: Record<string, string>;
    readonly ResolvedBody?: string;
    readonly DurationMs: number;
}

export interface ExecuteHttpStepInit {
    readonly Params: HttpRequestParams;
    readonly Row: Record<string, string>;
    readonly FetchImpl?: typeof fetch;
    readonly NowMs?: () => number;
}

const DEFAULT_TIMEOUT_MS = 15_000;
const SNIPPET_LIMIT = 2048;

/* ------------------------------------------------------------------ */
/*  Template interpolation                                             */
/* ------------------------------------------------------------------ */

const TEMPLATE_PATTERN = /\{\{\s*([\w.-]+)\s*\}\}/g;

export function interpolateTemplate(
    template: string,
    row: Record<string, string>,
): string {
    return template.replace(TEMPLATE_PATTERN, (_match, key: string) => {
        const value = row[key];
        return value === undefined ? "" : value;
    });
}

function interpolateHeaders(
    raw: string | undefined,
    row: Record<string, string>,
): Record<string, string> {
    if (raw === undefined || raw === "") return {};
    const interpolated = interpolateTemplate(raw, row);
    let parsed: unknown;
    try {
        parsed = JSON.parse(interpolated);
    } catch {
        throw new Error("BadParams: HeadersJson is not valid JSON after interpolation");
    }
    if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) {
        throw new Error("BadParams: HeadersJson must be a JSON object");
    }
    const out: Record<string, string> = {};
    for (const [k, v] of Object.entries(parsed as Record<string, unknown>)) {
        out[k] = String(v);
    }
    return out;
}

/* ------------------------------------------------------------------ */
/*  Execute                                                            */
/* ------------------------------------------------------------------ */

export async function executeHttpStep(
    init: ExecuteHttpStepInit,
): Promise<HttpStepResult> {
    const fetchImpl = init.FetchImpl ?? fetch;
    const now = init.NowMs ?? (() => Date.now());
    const startedAt = now();

    const url = interpolateTemplate(init.Params.Url, init.Row);
    const method = init.Params.Method;
    const timeoutMs = init.Params.TimeoutMs ?? DEFAULT_TIMEOUT_MS;

    let headers: Record<string, string>;
    try {
        headers = interpolateHeaders(init.Params.HeadersJson, init.Row);
    } catch (err) {
        return {
            Reason: "BadParams",
            ResolvedUrl: url,
            ResolvedMethod: method,
            ResolvedHeaders: {},
            DurationMs: now() - startedAt,
            ResponseSnippet: err instanceof Error ? err.message : String(err),
        };
    }

    const body =
        init.Params.BodyJson !== undefined && init.Params.BodyJson !== ""
            ? interpolateTemplate(init.Params.BodyJson, init.Row)
            : undefined;

    if (body !== undefined && headers["Content-Type"] === undefined) {
        headers["Content-Type"] = "application/json";
    }

    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    let response: Response;
    try {
        response = await fetchImpl(url, {
            method,
            headers,
            body,
            signal: controller.signal,
        });
    } catch (err) {
        clearTimeout(timer);
        const isAbort = controller.signal.aborted;
        return {
            Reason: isAbort ? "EndpointTimeout" : "EndpointHttpError",
            ResolvedUrl: url,
            ResolvedMethod: method,
            ResolvedHeaders: headers,
            ResolvedBody: body,
            DurationMs: now() - startedAt,
            ResponseSnippet: err instanceof Error ? err.message : String(err),
        };
    }
    clearTimeout(timer);

    const snippet = await safeReadSnippet(response);

    if (response.ok === false) {
        return {
            Reason: "EndpointHttpError",
            Status: response.status,
            ResolvedUrl: url,
            ResolvedMethod: method,
            ResolvedHeaders: headers,
            ResolvedBody: body,
            ResponseSnippet: snippet,
            DurationMs: now() - startedAt,
        };
    }

    let captured: unknown;
    if (init.Params.CaptureAs !== undefined && init.Params.CaptureAs !== "") {
        try {
            captured = JSON.parse(snippet);
        } catch (err) {
            return {
                Reason: "EndpointParseError",
                Status: response.status,
                ResolvedUrl: url,
                ResolvedMethod: method,
                ResolvedHeaders: headers,
                ResolvedBody: body,
                ResponseSnippet: err instanceof Error ? err.message : String(err),
                DurationMs: now() - startedAt,
            };
        }
    }

    return {
        Reason: "Ok",
        Status: response.status,
        ResolvedUrl: url,
        ResolvedMethod: method,
        ResolvedHeaders: headers,
        ResolvedBody: body,
        ResponseSnippet: snippet,
        CapturedValue: captured,
        DurationMs: now() - startedAt,
    };
}

async function safeReadSnippet(response: Response): Promise<string> {
    try {
        const text = await response.text();
        return text.slice(0, SNIPPET_LIMIT);
    } catch {
        return "";
    }
}

/**
 * Marco Extension — Live-DOM Replay Executor
 *
 * Phase 09 — Macro Recorder.
 *
 * Consumes a list of persisted Steps + their selectors, locates each target
 * in the live DOM via {@link resolveStepSelector}, and dispatches a real
 * browser event (`click`, `input`, `change`, …) on it. This is the missing
 * caller side — the resolver is pure, and this module is the imperative
 * actuator.
 *
 * Pure event dispatch only — no chrome.* or messaging. Caller supplies the
 * Document and the binding/value lookup so the same code is unit-testable
 * under jsdom and shippable in the content script.
 *
 * @see ./replay-resolver.ts          — Pure selector resolution.
 * @see ./field-reference-resolver.ts — `{{Column}}` substitution for Type values.
 * @see spec/31-macro-recorder/12-record-replay-e2e-contract.md
 */

import { resolveStepSelector, type ResolvedSelector } from "./replay-resolver";
import {
    resolveFieldReferences,
    resolveFieldReferencesDetailed,
    type FieldRow,
    type VariableContext,
} from "./field-reference-resolver";
import type { PersistedSelector } from "./step-persistence";
import {
    saveReplayRun,
    type PersistedReplayRun,
    type ReplayStepResultDraft,
} from "./replay-run-persistence";
import {
    logFailure,
    type FailureReasonCode,
    type FailureReport,
} from "./failure-logger";
import { evaluateAllSelectors } from "./selector-attempt-evaluator";
import { resolveVerboseLogging } from "./verbose-logging";
import { waitForElement, type WaitForSpec } from "./wait-for-element";
import { readStepWait, type WaitConfig } from "./step-library/step-wait";
import {
    waitForCondition,
    type Condition,
    type ConditionWaitOutcome,
} from "./condition-evaluator";

const SOURCE_FILE = "src/background/recorder/live-dom-replay.ts";

export interface ReplayStepInput {
    readonly StepId: number;
    readonly Index: number;
    readonly Kind: "Click" | "Type" | "Select" | "Wait";
    readonly Selectors: ReadonlyArray<PersistedSelector>;
    /** For Type/Select — the literal value or a `{{Column}}` template. */
    readonly Value?: string;
    /** For Wait — milliseconds. */
    readonly WaitMs?: number;
    /**
     * Optional backend-controlled gate: after the action dispatches the
     * executor polls the live DOM until this selector resolves to an
     * `HTMLElement`, or fails the step on timeout. Applies to Click /
     * Type / Select only — Wait steps ignore it. See
     * {@link WaitForSpec} for the selector grammar.
     */
    readonly WaitFor?: WaitForSpec;
    /**
     * Spec-19 canonical pre-condition gate. When present, the executor
     * polls `Condition` against the live DOM **before** actuating the
     * step. On timeout:
     *   - `OnTimeout = "Fail"` → step fails with `ConditionTimeout`.
     *   - `OnTimeout = "Skip"` → step is skipped (no actuation, not a
     *     failure).
     */
    readonly Gate?: StepGate;
}

export interface StepGate {
    readonly Condition: Condition;
    readonly TimeoutMs: number;
    readonly PollMs?: number;
    readonly OnTimeout: "Fail" | "Skip";
}

export interface ReplayPersistOptions {
    /** Project slug whose per-project DB receives the run row. */
    readonly ProjectSlug: string;
    /** Optional free-text notes attached to the persisted ReplayRun. */
    readonly Notes?: string;
}

export interface ReplayOptions {
    readonly Doc: Document;
    /** Active data-source row used to resolve `{{Column}}` templates in Value. */
    readonly Row?: FieldRow;
    /** Sleep implementation — injected so tests can fast-forward. */
    readonly Sleep?: (ms: number) => Promise<void>;
    /** Wall-clock provider — injected so tests get deterministic timestamps. */
    readonly Now?: () => Date;
    /**
     * When provided, the run + per-step results are persisted to the project
     * DB after `executeReplay` finishes. Tests omit this to stay pure.
     */
    readonly Persist?: ReplayPersistOptions;
    /**
     * Verbose-logging override. When `undefined` (default), the replay
     * resolves the toggle via
     * `resolveVerboseLogging(Persist?.ProjectSlug)`. When set explicitly,
     * the value wins — used by tests and by callers who already know the
     * effective flag (e.g. settings preview). Per
     * `mem://standards/verbose-logging-and-failure-diagnostics`, default
     * remains OFF; callers must opt in.
     */
    readonly Verbose?: boolean;
}

export interface ReplayStepResult {
    readonly StepId: number;
    readonly Index: number;
    readonly Ok: boolean;
    readonly Error?: string;
    readonly ResolvedXPath?: string;
    readonly StartedAt: string;
    readonly FinishedAt: string;
    readonly DurationMs: number;
    /** Structured failure report — populated only when `Ok === false`. */
    readonly FailureReport?: FailureReport;
    /**
     * When `true`, the step was intentionally skipped because its
     * pre-condition gate timed out with `OnTimeout = "Skip"`. Not a
     * failure — `Ok` is also `true`.
     */
    readonly Skipped?: true;
}

export interface ReplayRunOutcome {
    readonly Results: ReadonlyArray<ReplayStepResult>;
    readonly StartedAt: string;
    readonly FinishedAt: string;
    /** Populated only when `options.Persist` was supplied and the save succeeded. */
    readonly PersistedRun: PersistedReplayRun | null;
}

export async function executeReplay(
    steps: ReadonlyArray<ReplayStepInput>,
    options: ReplayOptions,
): Promise<ReplayRunOutcome> {
    const sleep = options.Sleep ?? defaultSleep;
    const now = options.Now ?? defaultNow;
    const runStarted = now();

    const results: ReplayStepResult[] = [];
    for (const step of steps) {
        results.push(await executeStep(step, options, sleep, now));
    }

    const runFinished = now();
    const startedAt = toIso(runStarted);
    const finishedAt = toIso(runFinished);

    let persistedRun: PersistedReplayRun | null = null;
    if (options.Persist !== undefined) {
        persistedRun = await saveReplayRun(options.Persist.ProjectSlug, {
            StartedAt: startedAt,
            FinishedAt: finishedAt,
            Notes: options.Persist.Notes ?? "",
            StepResults: results.map(toStepResultDraft),
        });
    }

    return {
        Results: results,
        StartedAt: startedAt,
        FinishedAt: finishedAt,
        PersistedRun: persistedRun,
    };
}

async function executeStep(
    step: ReplayStepInput,
    options: ReplayOptions,
    sleep: (ms: number) => Promise<void>,
    now: () => Date,
): Promise<ReplayStepResult> {
    const startedAt = now();
    let target: HTMLElement | null = null;
    let resolvedXPath: string | undefined;
    let variables: ReadonlyArray<VariableContext> = [];
    try {
        if (step.Kind === "Wait") {
            await sleep(step.WaitMs ?? 0);
            return finalize(step, options, startedAt, now(), { Ok: true });
        }

        // Spec 19 §2 — pre-condition gate (checked before actuation).
        if (step.Gate !== undefined) {
            const gateOutcome = await waitForCondition(step.Gate.Condition, {
                Doc: options.Doc,
                TimeoutMs: step.Gate.TimeoutMs,
                PollMs: step.Gate.PollMs,
                Sleep: sleep,
                Now: () => now().getTime(),
            });
            if (!gateOutcome.Ok) {
                if (step.Gate.OnTimeout === "Skip") {
                    return finalize(step, options, startedAt, now(), {
                        Ok: true,
                        Skipped: true,
                        Error: new Error(
                            "Skipped: gate condition not met within " + step.Gate.TimeoutMs + "ms " +
                            "(polls=" + gateOutcome.Polls + ", elapsed=" + gateOutcome.DurationMs + "ms)",
                        ),
                    });
                }
                return finalize(step, options, startedAt, now(), {
                    Ok: false,
                    Reason: "ConditionTimeout",
                    ReasonDetail:
                        "Gate condition not met within " + step.Gate.TimeoutMs + "ms " +
                        "(polls=" + gateOutcome.Polls + ", elapsed=" + gateOutcome.DurationMs + "ms). " +
                        "Last evaluation: " + JSON.stringify(gateOutcome.LastEvaluation),
                    Error: new Error("Gate condition not met within " + step.Gate.TimeoutMs + "ms"),
                });
            }
        }

        // Resolve {{Token}} variables FIRST (per
        // mem://standards/verbose-logging-and-failure-diagnostics): the
        // detailed resolver returns one VariableContext per token with
        // Name + ResolvedValue + ValueType + FailureReason so we can fail
        // fast with a precise reason BEFORE the DOM lookup ever runs.
        if ((step.Kind === "Type" || step.Kind === "Select") && step.Value !== undefined && step.Value !== "") {
            const detailed = resolveFieldReferencesDetailed(step.Value, options.Row ?? {}, {
                Source: options.Row !== undefined ? "Row" : "NoActiveRow",
                ExpectedType: "string",
            });
            variables = detailed.Variables;
            if (detailed.FirstFailure !== null) {
                return finalize(step, options, startedAt, now(), {
                    Ok: false,
                    Variables: variables,
                    Error: new Error(detailed.FirstFailure.FailureDetail ?? `Variable {{${detailed.FirstFailure.Name}}} failed`),
                });
            }
        }

        const resolved = resolveStepSelector(step.Selectors);
        resolvedXPath = resolved.Expression;
        target = locateElement(resolved, options.Doc);
        if (target === null) {
            return finalize(step, options, startedAt, now(), {
                Ok: false,
                ResolvedXPath: resolved.Expression,
                Variables: variables,
                Error: new Error(`Element not found for selector '${resolved.Expression}'`),
            });
        }

        if (step.Kind === "Click")  { dispatchClick(target); }
        if (step.Kind === "Type")   { dispatchType(target,   resolveValue(step.Value, options.Row)); }
        if (step.Kind === "Select") { dispatchSelect(target, resolveValue(step.Value, options.Row)); }

        // Resolve the wait gate. Inline `step.WaitFor` (set programmatically
        // by tests / advanced callers) wins; otherwise fall back to the
        // per-step config persisted via the StepWaitDialog UI. Both feed
        // the same `waitForElement` helper.
        const effectiveWait: WaitForSpec | null =
            step.WaitFor !== undefined
                ? step.WaitFor
                : persistedWaitToSpec(readStepWait(step.StepId));
        if (effectiveWait !== null) {
            const waitOutcome = await waitForElement(effectiveWait, {
                Doc: options.Doc,
                Sleep: sleep,
                Now: () => now().getTime(),
            });
            if (!waitOutcome.Ok) {
                // Build a structured failure so the FailureDetailsPanel /
                // failure-toast UI surfaces the selector, kind, configured
                // timeout, and the actual elapsed time. The classification
                // is "Timeout" for the polling-budget exhaustion case and
                // "XPathSyntaxError" / "CssSyntaxError" for compile errors
                // — chosen so the existing ReasonBanner colours apply.
                const declaredKind = effectiveWait.Kind ?? "Auto";
                const resolvedKind: "XPath" | "Css" =
                    declaredKind === "XPath" ? "XPath"
                        : declaredKind === "Css" ? "Css"
                            : effectiveWait.Expression.trim().startsWith("/")
                                ? "XPath" : "Css";
                const reasonCode =
                    waitOutcome.Reason === "InvalidSelector"
                        ? (resolvedKind === "XPath" ? "XPathSyntaxError" : "CssSyntaxError")
                        : "Timeout";
                const reasonDetail =
                    waitOutcome.Reason === "Timeout"
                        ? `WaitFor selector '${effectiveWait.Expression}' (Kind=${resolvedKind}) ` +
                          `did not appear within ${effectiveWait.TimeoutMs} ms ` +
                          `(elapsed ${waitOutcome.DurationMs} ms).`
                        : `WaitFor selector '${effectiveWait.Expression}' (Kind=${resolvedKind}) ` +
                          `is invalid: ${waitOutcome.Detail}`;
                return finalize(step, options, startedAt, now(), {
                    Ok: false,
                    ResolvedXPath: resolved.Expression,
                    Variables: variables,
                    Target: target,
                    Reason: reasonCode,
                    ReasonDetail: reasonDetail,
                    Error: new Error(reasonDetail),
                });
            }
        }

        return finalize(step, options, startedAt, now(), { Ok: true, ResolvedXPath: resolved.Expression });
    } catch (err) {
        return finalize(step, options, startedAt, now(), {
            Ok: false,
            ResolvedXPath: resolvedXPath,
            Variables: variables,
            Error: err,
            Target: target,
        });
    }
}

function finalize(
    step: ReplayStepInput,
    options: ReplayOptions,
    started: Date,
    finished: Date,
    outcome: {
        Ok: boolean;
        Error?: unknown;
        ResolvedXPath?: string;
        Target?: HTMLElement | null;
        Variables?: ReadonlyArray<VariableContext>;
        /** Caller-supplied classification — overrides auto-derivation in `logFailure`. */
        Reason?: FailureReasonCode;
        ReasonDetail?: string;
        Skipped?: boolean;
    },
): ReplayStepResult {
    if (outcome.Ok) {
        return {
            StepId: step.StepId,
            Index: step.Index,
            Ok: true,
            Skipped: outcome.Skipped === true ? true : undefined,
            ResolvedXPath: outcome.ResolvedXPath,
            StartedAt: toIso(started),
            FinishedAt: toIso(finished),
            DurationMs: Math.max(0, finished.getTime() - started.getTime()),
        };
    }

    // Evaluate every persisted selector against the live DOM so the
    // failure log carries the full XPath/CSS expression that was tried,
    // its Matched outcome, MatchCount, and per-attempt FailureReason
    // (per mem://standards/verbose-logging-and-failure-diagnostics).
    // Wait steps have no selectors — skip evaluation.
    const evaluatedAttempts = step.Kind === "Wait"
        ? undefined
        : evaluateAllSelectors(step.Selectors, options.Doc);

    const verbose = options.Verbose !== undefined
        ? options.Verbose
        : resolveVerboseLogging(options.Persist?.ProjectSlug);

    const report = logFailure({
        Phase: "Replay",
        Error: outcome.Error,
        StepId: step.StepId,
        Index: step.Index,
        StepKind: step.Kind,
        Selectors: step.Selectors,
        EvaluatedAttempts: evaluatedAttempts,
        Target: outcome.Target ?? null,
        DataRow: options.Row,
        Variables: outcome.Variables,
        ResolvedXPath: outcome.ResolvedXPath,
        SourceFile: SOURCE_FILE,
        Reason: outcome.Reason,
        ReasonDetail: outcome.ReasonDetail,
        Verbose: verbose,
        Now: options.Now,
    });

    return {
        StepId: step.StepId,
        Index: step.Index,
        Ok: false,
        Error: report.Message,
        ResolvedXPath: outcome.ResolvedXPath,
        StartedAt: toIso(started),
        FinishedAt: toIso(finished),
        DurationMs: Math.max(0, finished.getTime() - started.getTime()),
        FailureReport: report,
    };
}

function toStepResultDraft(r: ReplayStepResult): ReplayStepResultDraft {
    // When a structured FailureReport exists, persist it as JSON so the
    // user can later copy the full diagnostic blob from the project DB.
    const errorMessage = r.FailureReport !== undefined
        ? JSON.stringify(r.FailureReport)
        : (r.Skipped === true ? (r.Error ?? "Skipped: gate condition not met") : (r.Error ?? null));
    return {
        StepId: r.StepId,
        OrderIndex: r.Index,
        IsOk: r.Ok || r.Skipped === true,
        ErrorMessage: errorMessage,
        ResolvedXPath: r.ResolvedXPath ?? null,
        StartedAt: r.StartedAt,
        FinishedAt: r.FinishedAt,
        DurationMs: r.DurationMs,
    };
}

function toIso(d: Date): string {
    // SQLite stores `datetime('now')` in 'YYYY-MM-DD HH:MM:SS'; ISO is fine here
    // because the column is TEXT and we read it back verbatim.
    return d.toISOString();
}

function defaultNow(): Date {
    return new Date();
}

function resolveValue(raw: string | undefined, row: FieldRow | undefined): string {
    if (raw === undefined || raw === "") { return ""; }
    if (row === undefined)               { return raw; }
    return resolveFieldReferences(raw, row);
}

/* ------------------------------------------------------------------ */
/*  DOM lookup                                                         */
/* ------------------------------------------------------------------ */

function locateElement(resolved: ResolvedSelector, doc: Document): HTMLElement | null {
    if (resolved.Kind === "XPath") {
        const r = doc.evaluate(resolved.Expression, doc, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null);
        const node = r.singleNodeValue;
        return node instanceof HTMLElement ? node : null;
    }
    if (resolved.Kind === "Css") {
        const element = doc.querySelector(resolved.Expression);
        return element instanceof HTMLElement ? element : null;
    }
    // Aria — minimal support: `[aria-label="…"]`-style expressions are passed straight to querySelector
    const element = doc.querySelector(resolved.Expression);
    return element instanceof HTMLElement ? element : null;
}

/* ------------------------------------------------------------------ */
/*  Event dispatch                                                     */
/* ------------------------------------------------------------------ */

function dispatchClick(element: HTMLElement): void {
    element.focus({ preventScroll: true });
    element.dispatchEvent(new MouseEvent("mousedown", { bubbles: true, cancelable: true }));
    element.dispatchEvent(new MouseEvent("mouseup",   { bubbles: true, cancelable: true }));
    element.dispatchEvent(new MouseEvent("click",     { bubbles: true, cancelable: true }));
}

function dispatchType(element: HTMLElement, value: string): void {
    element.focus({ preventScroll: true });
    if (element instanceof HTMLInputElement || element instanceof HTMLTextAreaElement) {
        const proto = element instanceof HTMLInputElement
            ? HTMLInputElement.prototype
            : HTMLTextAreaElement.prototype;
        const setter = Object.getOwnPropertyDescriptor(proto, "value")?.set;
        if (setter !== undefined) {
            setter.call(element, value);
        } else {
            element.value = value;
        }
    } else if (element.isContentEditable) {
        element.textContent = value;
    } else {
        return; // not typeable
    }
    element.dispatchEvent(new Event("input",  { bubbles: true }));
    element.dispatchEvent(new Event("change", { bubbles: true }));
}

function dispatchSelect(element: HTMLElement, value: string): void {
    if (!(element instanceof HTMLSelectElement)) { return; }
    element.value = value;
    element.dispatchEvent(new Event("input",  { bubbles: true }));
    element.dispatchEvent(new Event("change", { bubbles: true }));
}

function defaultSleep(ms: number): Promise<void> {
    return new Promise((resolve) => {
        let timeoutId: ReturnType<typeof setTimeout> | null = null;
        timeoutId = setTimeout(() => {
            if (timeoutId !== null) {
                clearTimeout(timeoutId);
                timeoutId = null;
            }
            resolve();
        }, ms);
    });
}

/**
 * Bridge `WaitConfig` (persisted via the StepWaitDialog UI) into the
 * inline `WaitForSpec` shape that `waitForElement` expects.
 *
 * `wait-for-element.ts` currently implements only the **Appears**
 * predicate (returns when the element is found in the DOM). The
 * `Disappears` and `Visible` modes from the dialog are accepted by the
 * storage layer but cannot be honoured here yet — for those, we still
 * resolve to `Appears` so the user gets *some* gating instead of silent
 * no-op, and we leave a console warning so the discrepancy is traceable.
 *
 * Returns `null` when there's no persisted config so the caller can
 * skip the wait branch entirely.
 */
function persistedWaitToSpec(config: WaitConfig | null): WaitForSpec | null {
    if (config === null) return null;
    if (config.Condition !== "Appears") {
        console.warn(
            `live-dom-replay: persisted wait condition '${config.Condition}' is ` +
            `not yet supported by waitForElement; falling back to 'Appears'.`,
        );
    }
    return {
        Expression: config.Selector,
        Kind: config.Kind === "XPath" ? "XPath" : "Css",
        TimeoutMs: config.TimeoutMs,
    };
}

/**
 * Marco Extension — Shadow-Root Recorder Toolbar
 *
 * Self-contained floating toolbar mounted into a closed Shadow DOM so that
 * host-page CSS cannot leak in. Wraps the pure {@link recorderReducer} and
 * exposes three controls — Start, Pause/Resume, Stop — that drive the
 * RecordingPhase state machine.
 *
 * No chrome.* APIs, no React — pure DOM so it can be injected by the content
 * script during macro recording. State changes are emitted via the
 * {@link RecorderToolbarOptions.onPhaseChange} callback so the caller can
 * persist sessions, broadcast messages, or wire shortcuts on top.
 *
 * @see ./recorder-store.ts          — Pure reducer this toolbar drives.
 * @see ./recorder-session-types.ts  — RecordingPhase / RecordingSession types.
 * @see spec/26-chrome-extension-generic/06-ui-and-design-system/10-toolbar-recording-ux.md
 */

import {
    IDLE_SESSION,
    type RecorderAction,
    recorderReducer,
} from "./recorder-store";
import type { RecordingPhase, RecordingSession } from "./recorder-session-types";

/* ------------------------------------------------------------------ */
/*  Public contract                                                    */
/* ------------------------------------------------------------------ */

export const RECORDER_TOOLBAR_HOST_ID = "marco-recorder-toolbar-host";

export interface RecorderToolbarOptions {
    readonly ProjectSlug: string;
    /** Factory for SessionId — injected so tests are deterministic. */
    readonly NewSessionId: () => string;
    /** Wall-clock provider — injected so tests are deterministic. */
    readonly Now: () => string;
    /** Notified after each successful phase transition. */
    readonly OnPhaseChange?: (phase: RecordingPhase, session: RecordingSession) => void;
}

export interface RecorderToolbarHandle {
    /** The DOM host element appended to <body>. */
    readonly Host: HTMLElement;
    /** The closed Shadow Root containing the toolbar UI. */
    readonly Root: ShadowRoot;
    /** Current immutable session snapshot. */
    GetSession(): RecordingSession;
    /** Programmatic equivalents of the three buttons. */
    Start(): void;
    Pause(): void;
    Resume(): void;
    Stop(): void;
    /** Removes the toolbar from the DOM. Idempotent. */
    Destroy(): void;
}

/* ------------------------------------------------------------------ */
/*  Styling — scoped inside the shadow root                            */
/* ------------------------------------------------------------------ */

const TOOLBAR_CSS = `
