/* ------------------------------------------------------------------ */
/*  Mount                                                              */
/* ------------------------------------------------------------------ */

export function mountRecorderToolbar(
    options: RecorderToolbarOptions,
    container: ParentNode = (typeof document !== "undefined" ? document.body : (null as unknown as ParentNode)),
): RecorderToolbarHandle {
    if (container === null || container === undefined) {
        throw new Error("mountRecorderToolbar: no container available (document.body missing)");
    }

    let session: RecordingSession = IDLE_SESSION;

    const host = document.createElement("div");
    host.id = RECORDER_TOOLBAR_HOST_ID;
    const root = host.attachShadow({ mode: "closed" });

    const style = document.createElement("style");
    style.textContent = TOOLBAR_CSS;
    root.appendChild(style);

    const bar = document.createElement("div");
    bar.className = "toolbar";
    bar.setAttribute("role", "toolbar");
    bar.setAttribute("aria-label", "Marco Recorder");

    const phaseLabel = document.createElement("span");
    phaseLabel.className = "phase";

    const projectChip = document.createElement("span");
    projectChip.className = "project";
    projectChip.setAttribute("aria-label", "Active recording project");
    projectChip.title = `Steps will be saved to project: ${options.ProjectSlug}`;
    const projectDot = document.createElement("span");
    projectDot.className = "dot";
    const projectText = document.createElement("span");
    projectText.className = "label";
    projectText.textContent = options.ProjectSlug;
    projectChip.append(projectDot, projectText);

    const healthChip = document.createElement("span");
    healthChip.className = "health";
    healthChip.setAttribute("aria-label", "Recorder health");
    const healthDot = document.createElement("span");
    healthDot.className = "hdot";
    const healthText = document.createElement("span");
    healthText.className = "htext";
    const healthSep = document.createElement("span");
    healthSep.className = "sep";
    healthSep.textContent = "·";
    const healthCapture = document.createElement("span");
    healthCapture.className = "muted";
    healthChip.append(healthDot, healthText, healthSep, healthCapture);

    const startBtn = makeButton("start", "Start");
    const pauseBtn = makeButton("pause", "Pause");
    const stopBtn  = makeButton("stop", "Stop");

    bar.append(phaseLabel, projectChip, healthChip, startBtn, pauseBtn, stopBtn);
    root.appendChild(bar);
    container.appendChild(host);

    function dispatch(action: RecorderAction): void {
        const next = recorderReducer(session, action);
        session = next;
        render();
        options.OnPhaseChange?.(next.Phase, next);
    }

    function start(): void {
        dispatch({
            Kind: "Start",
            ProjectSlug: options.ProjectSlug,
            SessionId: options.NewSessionId(),
            StartedAt: options.Now(),
        });
    }
    function pause(): void  { dispatch({ Kind: "Pause"  }); }
    function resume(): void { dispatch({ Kind: "Resume" }); }
    function stop(): void   { dispatch({ Kind: "Stop"   }); }

    startBtn.addEventListener("click", () => { start(); });
    stopBtn.addEventListener("click",  () => { stop();  });
    pauseBtn.addEventListener("click", () => {
        if (session.Phase === "Recording") { pause(); return; }
        if (session.Phase === "Paused")    { resume(); return; }
    });

    function render(): void {
        const phase = session.Phase;
        phaseLabel.textContent = phase;

        const isActive = phase === "Recording" || phase === "Paused";
        projectChip.dataset.active = isActive ? "true" : "false";
        projectChip.dataset.phase = phase;

        startBtn.disabled = phase !== "Idle";
        stopBtn.disabled  = phase === "Idle";

        if (phase === "Paused") {
            pauseBtn.textContent = "Resume";
            pauseBtn.dataset.action = "resume";
            pauseBtn.disabled = false;
        } else {
            pauseBtn.textContent = "Pause";
            pauseBtn.dataset.action = "pause";
            pauseBtn.disabled = phase !== "Recording";
        }

        renderHealth();
    }

    function renderHealth(): void {
        const phase = session.Phase;
        const stepCount = session.Steps.length;
        const lastStep = stepCount > 0 ? session.Steps[stepCount - 1] : null;
        const projectOk = options.ProjectSlug.length > 0;

        let status: "idle" | "ok" | "warn" | "error" = "idle";
        if (!projectOk) {
            status = "error";
        } else if (phase === "Recording") {
            status = stepCount > 0 ? "ok" : "warn";
        } else if (phase === "Paused") {
            status = "warn";
        } else {
            status = "idle";
        }
        healthChip.dataset.status = status;

        const projectLabel = projectOk ? options.ProjectSlug : "no project";
        healthText.textContent = `${projectLabel} · ${stepCount} step${stepCount === 1 ? "" : "s"}`;

        if (lastStep === null) {
            healthCapture.textContent = phase === "Idle" ? "not recording" : "awaiting capture";
        } else {
            healthCapture.textContent = `last ${formatRelative(lastStep.CapturedAt, options.Now())}`;
        }

        healthChip.title =
            `Project: ${projectLabel}\n` +
            `Phase: ${phase}\n` +
            `Steps captured: ${stepCount}\n` +
            `Last capture: ${lastStep?.CapturedAt ?? "—"}`;
    }

    render();

    // L-2 (audit 2026-05-15): visibility-aware tick + pagehide teardown.
    // Cadence reduced from 1s to 5s. Skip work when document is hidden;
    // re-render once on visibility return. Pagehide guarantees teardown
    // even when no caller invokes Destroy() (bfcache, navigation away).
    const TICK_INTERVAL_MS = 5000;
    const hasWindow = typeof window !== "undefined";
    const hasDocument = typeof document !== "undefined";

    function tick(): void {
        if (hasDocument && document.hidden) { return; }
        renderHealth();
    }

    const tickInterval = hasWindow
        ? window.setInterval(tick, TICK_INTERVAL_MS)
        : 0;

    function onVisibilityChange(): void {
        if (hasDocument && !document.hidden) { renderHealth(); }
    }
    if (hasDocument) {
        document.addEventListener("visibilitychange", onVisibilityChange);
    }

    let destroyed = false;
    function destroy(): void {
        if (destroyed) { return; }
        destroyed = true;
        if (tickInterval !== 0 && hasWindow) {
            window.clearInterval(tickInterval);
        }
        if (hasDocument) {
            document.removeEventListener("visibilitychange", onVisibilityChange);
        }
        if (hasWindow) {
            window.removeEventListener("pagehide", onPageHide);
        }
        host.remove();
    }

    function onPageHide(): void { destroy(); }
    if (hasWindow) {
        window.addEventListener("pagehide", onPageHide, { once: true });
    }

    return {
        Host: host,
        Root: root,
        GetSession: () => session,
        Start: start,
        Pause: pause,
        Resume: resume,
        Stop: stop,
        Destroy: destroy,
    };
}

function makeButton(action: "start" | "pause" | "stop", label: string): HTMLButtonElement {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "btn";
    btn.dataset.action = action;
    btn.textContent = label;
    return btn;
}

function formatRelative(thenIso: string, nowIso: string): string {
    const then = Date.parse(thenIso);
    const now = Date.parse(nowIso);
    if (Number.isNaN(then) || Number.isNaN(now)) { return "just now"; }
    const deltaSec = Math.max(0, Math.round((now - then) / 1000));
    if (deltaSec < 5) { return "just now"; }
    if (deltaSec < 60) { return `${deltaSec}s ago`; }
    const min = Math.floor(deltaSec / 60);
    if (min < 60) { return `${min}m ago`; }
    const hr = Math.floor(min / 60);
    return `${hr}h ago`;
}

/**
 * Marco Extension — Selector Attempt Comparison
 *
 * Runs every persisted selector for a Step against the live DOM and reports,
 * per selector, whether the lookup succeeded and which Element (if any) was
 * matched. Used by the failure post-mortem UI ("Comparison view") so the
 * user can see at a glance:
 *
 *   - Which selectors no longer match → likely root cause of the failure.
 *   - Which selectors do still resolve → the next-best candidate to promote
 *     to primary.
 *   - When a fallback resolves to a *different* element than the primary
 *     would have → silent drift.
 *
 * Pure: caller injects the Document. No event dispatch, no chrome.*.
 *
 * @see ./replay-resolver.ts   — Same anchor/relative resolution rules.
 * @see ./failure-logger.ts    — DomContext shape reused here.
 */

import { resolveStepSelector } from "./replay-resolver";
import { SelectorKindId } from "../recorder-db-schema";
import type { PersistedSelector } from "./step-persistence";
import type { DomContext } from "./failure-logger";

const SELECTOR_KIND_NAMES: Readonly<Record<number, string>> = {
    1: "XPathFull",
    2: "XPathRelative",
    3: "Css",
    4: "Aria",
};

export interface SelectorAttemptComparison {
    readonly SelectorId: number;
    readonly Kind: string;
    readonly Expression: string;
    readonly ResolvedExpression: string;
    readonly IsPrimary: boolean;
    /** True when the lookup matched at least one element. */
    readonly Matched: boolean;
    /** Number of matches (querySelectorAll for Css/Aria, XPath snapshot for XPath). */
    readonly MatchCount: number;
    /** DOM snapshot of the *first* match (or null when no match). */
    readonly Element: DomContext | null;
    /** Resolver / DOM-API failure message (e.g. invalid XPath). */
    readonly Error: string | null;
}

export interface SelectorComparison {
    /** All attempts, primary first then in original order. */
    readonly Attempts: ReadonlyArray<SelectorAttemptComparison>;
    /** True when the primary selector matched. */
    readonly PrimaryMatched: boolean;
    /** True when at least one fallback (non-primary) matched. */
    readonly AnyFallbackMatched: boolean;
    /**
     * True when the primary fails but a fallback resolves — strong hint that
     * the user should promote the fallback or the primary needs editing.
     */
    readonly DriftDetected: boolean;
}

/**
 * Try every selector for a Step against the live DOM and report which
 * matched. Anchor chains are honored via {@link resolveStepSelector} on a
 * synthetic primary marker per selector so relative XPath fallbacks are
 * evaluated correctly.
 */
export function compareSelectorAttempts(
    selectors: ReadonlyArray<PersistedSelector>,
    doc: Document,
): SelectorComparison {
    const attempts: SelectorAttemptComparison[] = [];

    for (const sel of selectors) {
        attempts.push(evaluateOne(sel, selectors, doc));
    }

    // Sort: primary first, then by original SelectorId for stability.
    attempts.sort((a, b) => {
        if (a.IsPrimary !== b.IsPrimary) return a.IsPrimary ? -1 : 1;
        return a.SelectorId - b.SelectorId;
    });

    const primary = attempts.find((a) => a.IsPrimary) ?? null;
    const primaryMatched = primary?.Matched ?? false;
    const anyFallbackMatched = attempts.some((a) => !a.IsPrimary && a.Matched);

    return {
        Attempts: attempts,
        PrimaryMatched: primaryMatched,
        AnyFallbackMatched: anyFallbackMatched,
        DriftDetected: !primaryMatched && anyFallbackMatched,
    };
}

function evaluateOne(
    selector: PersistedSelector,
    all: ReadonlyArray<PersistedSelector>,
    doc: Document,
): SelectorAttemptComparison {
    const kind = SELECTOR_KIND_NAMES[selector.SelectorKindId] ?? `Kind${selector.SelectorKindId}`;
    const base: Omit<SelectorAttemptComparison, "Matched" | "MatchCount" | "Element" | "Error" | "ResolvedExpression"> = {
        SelectorId: selector.SelectorId,
        Kind: kind,
        Expression: selector.Expression,
        IsPrimary: selector.IsPrimary === 1,
    };

    let resolvedExpression = selector.Expression;
    try {
        // Resolve anchor chains for relative XPath; treat this single selector
        // as primary so resolveStepSelector returns its expanded expression.
        if (selector.SelectorKindId === SelectorKindId.XPathRelative) {
            const synthetic = all.map((s) => ({
                ...s,
                IsPrimary: s.SelectorId === selector.SelectorId ? 1 : 0,
            }));
            resolvedExpression = resolveStepSelector(synthetic).Expression;
        }
    } catch (err) {
        return {
            ...base,
            ResolvedExpression: resolvedExpression,
            Matched: false,
            MatchCount: 0,
            Element: null,
            Error: err instanceof Error ? err.message : String(err),
        };
    }

    try {
        const { element, count } = lookup(selector.SelectorKindId, resolvedExpression, doc);
        return {
            ...base,
            ResolvedExpression: resolvedExpression,
            Matched: element !== null,
            MatchCount: count,
            Element: element !== null ? readDomContext(element) : null,
            Error: null,
        };
    } catch (err) {
        return {
            ...base,
            ResolvedExpression: resolvedExpression,
            Matched: false,
            MatchCount: 0,
            Element: null,
            Error: err instanceof Error ? err.message : String(err),
        };
    }
}

function lookup(
    kindId: number,
    expression: string,
    doc: Document,
): { element: Element | null; count: number } {
    if (kindId === SelectorKindId.XPathFull || kindId === SelectorKindId.XPathRelative) {
        const snapshot = doc.evaluate(
            expression, doc, null, XPathResult.ORDERED_NODE_SNAPSHOT_TYPE, null,
        );
        const count = snapshot.snapshotLength;
        const first = count > 0 ? snapshot.snapshotItem(0) : null;
        return {
            element: first instanceof Element ? first : null,
            count,
        };
    }
    // Css / Aria — both are passed straight to querySelectorAll.
    const list = doc.querySelectorAll(expression);
    return {
        element: list.length > 0 ? list[0] : null,
        count: list.length,
    };
}

function readDomContext(el: Element): DomContext {
    const id = el.getAttribute("id");
    const cls = el.getAttribute("class");
    const aria = el.getAttribute("aria-label");
    const name = el.getAttribute("name");
    const type = el.getAttribute("type");
    const text = (el.textContent ?? "").trim().slice(0, 120);
    const outer = el.outerHTML?.slice(0, 240) ?? "";
    return {
        TagName: el.tagName.toLowerCase(),
        Id: id !== null && id.length > 0 ? id : null,
        ClassName: cls !== null && cls.length > 0 ? cls : null,
        AriaLabel: aria !== null && aria.length > 0 ? aria : null,
        Name: name !== null && name.length > 0 ? name : null,
        Type: type !== null && type.length > 0 ? type : null,
        TextSnippet: text,
        OuterHtmlSnippet: outer,
    };
}

/**
 * Marco Extension — Per-Selector Replay History
 *
 * Pure helper that takes a Step's persisted {@link PersistedReplayStepResult}
 * rows and reduces them into per-selector outcome timelines. Lets the UI
 * answer "when did selector X start failing?" without re-running anything.
 *
 * Bucketing rule:
 *   - We bucket by `ResolvedXPath` because that is what the executor
 *     persists per attempt (the resolver collapses the primary selector
 *     chain to a single expression). When `ResolvedXPath` is null the
 *     row falls into the `__unknown__` bucket so the UI can still surface it.
 *   - The original (raw) selector expression is matched against the
 *     bucket key when available so the comparison panel can display
 *     history alongside the matching selector row.
 *
 * Outputs (per bucket):
 *   - `Outcomes`         — chronological list of `{ At, IsOk, RunId, Error }`.
 *   - `LastSuccessAt`    — ISO of the most recent successful run, or null.
 *   - `FirstFailureAfterLastSuccessAt` — ISO of the first failure after the
 *     last success (or first-ever failure when the selector has never
 *     succeeded). This is the "when did it start failing?" answer.
 *   - `ConsecutiveFailures` — count of failures since the last success.
 *   - `Status`           — `"healthy" | "regressed" | "always-failing" | "unknown"`.
 *
 * Pure: no DB, no I/O. The async sister `loadSelectorHistoryForStep` in
 * `replay-run-persistence.ts` is the production caller.
 *
 * @see ./replay-run-persistence.ts — Persists the rows this helper consumes.
 * @see ./selector-comparison.ts    — Live counterpart (current DOM state).
 */

import type { PersistedReplayStepResult } from "./replay-run-persistence";

export interface SelectorOutcomePoint {
    readonly RunId: number;
    readonly At: string;            // ISO timestamp
    readonly IsOk: boolean;
    readonly Error: string | null;
    readonly DurationMs: number;
}

export type SelectorHealth = "healthy" | "regressed" | "always-failing" | "unknown";

export interface SelectorHistoryBucket {
    /** `ResolvedXPath` value, or `null` for the legacy/unknown bucket. */
    readonly ResolvedExpression: string | null;
    readonly Outcomes: ReadonlyArray<SelectorOutcomePoint>;
    readonly LastSuccessAt: string | null;
    readonly FirstFailureAfterLastSuccessAt: string | null;
    readonly ConsecutiveFailures: number;
    readonly TotalRuns: number;
    readonly TotalFailures: number;
    readonly Status: SelectorHealth;
}

const UNKNOWN_KEY = "__unknown__";

/**
 * Group prior per-step results by resolved selector expression and compute
 * the per-bucket health summary.
 *
 * Rows can be passed in any order; the helper sorts by `StartedAt` ASC
 * before reducing so the resulting `Outcomes` array is chronological.
 */
export function buildSelectorHistory(
    results: ReadonlyArray<PersistedReplayStepResult>,
): ReadonlyArray<SelectorHistoryBucket> {
    if (results.length === 0) return [];

    const sorted = [...results].sort((a, b) => a.StartedAt.localeCompare(b.StartedAt));
    const byKey = new Map<string, SelectorOutcomePoint[]>();

    for (const r of sorted) {
        const key = r.ResolvedXPath ?? UNKNOWN_KEY;
        const list = byKey.get(key) ?? [];
        list.push({
            RunId: r.ReplayRunId,
            At: r.StartedAt,
            IsOk: r.IsOk === 1,
            Error: r.ErrorMessage,
            DurationMs: r.DurationMs,
        });
        byKey.set(key, list);
    }

    const buckets: SelectorHistoryBucket[] = [];
    for (const [key, outcomes] of byKey) {
        buckets.push(summarise(key === UNKNOWN_KEY ? null : key, outcomes));
    }

    // Sort: regressed first (most actionable), then always-failing, then healthy, then unknown.
    const order: Record<SelectorHealth, number> = {
        regressed: 0, "always-failing": 1, healthy: 2, unknown: 3,
    };
    buckets.sort((a, b) => order[a.Status] - order[b.Status]);
    return buckets;
}

/**
 * Find the bucket that matches a live selector's resolved expression.
 * Returns `null` when the selector has no historical data — useful for the
 * comparison-panel toggle.
 */
export function findHistoryForSelector(
    history: ReadonlyArray<SelectorHistoryBucket>,
    resolvedExpression: string | null,
): SelectorHistoryBucket | null {
    if (resolvedExpression === null) return null;
    return history.find((b) => b.ResolvedExpression === resolvedExpression) ?? null;
}

function summarise(
    resolved: string | null,
    outcomes: ReadonlyArray<SelectorOutcomePoint>,
): SelectorHistoryBucket {
    let lastSuccessAt: string | null = null;
    let lastSuccessIdx = -1;
    for (let i = outcomes.length - 1; i >= 0; i--) {
        if (outcomes[i].IsOk) { lastSuccessAt = outcomes[i].At; lastSuccessIdx = i; break; }
    }

    let firstFailureAfterLastSuccessAt: string | null = null;
    if (lastSuccessIdx === -1) {
        // Never succeeded — first-ever failure is the regression marker.
        const firstFail = outcomes.find((o) => !o.IsOk);
        firstFailureAfterLastSuccessAt = firstFail?.At ?? null;
    } else {
        for (let i = lastSuccessIdx + 1; i < outcomes.length; i++) {
            if (!outcomes[i].IsOk) {
                firstFailureAfterLastSuccessAt = outcomes[i].At;
                break;
            }
        }
    }

    const totalRuns = outcomes.length;
    const totalFailures = outcomes.filter((o) => !o.IsOk).length;
    const last = outcomes[outcomes.length - 1];

    let consecutiveFailures = 0;
    for (let i = outcomes.length - 1; i >= 0 && !outcomes[i].IsOk; i--) {
        consecutiveFailures += 1;
    }

    let status: SelectorHealth;
    if (resolved === null && totalRuns === 0) status = "unknown";
    else if (totalFailures === 0)              status = "healthy";
    else if (totalFailures === totalRuns)      status = "always-failing";
    else if (last.IsOk)                        status = "healthy";
    else                                       status = "regressed";

    return {
        ResolvedExpression: resolved,
        Outcomes: outcomes,
        LastSuccessAt: lastSuccessAt,
        FirstFailureAfterLastSuccessAt: firstFailureAfterLastSuccessAt,
        ConsecutiveFailures: consecutiveFailures,
        TotalRuns: totalRuns,
        TotalFailures: totalFailures,
        Status: status,
    };
}

/**
 * Marco Extension — Mini Selector Tester
 *
 * Pure helper that evaluates an arbitrary CSS or XPath selector against a
 * Document and reports match count + a snapshot of the first matched
 * element. Auto-detects kind (XPath if expression starts with `/` or `(`,
 * otherwise CSS) but accepts an explicit override.
 *
 * Reuses the {@link DomContext} shape from `failure-logger` so the result
 * round-trips through the same diagnostic pipelines as failure reports
 * and selector comparisons.
 *
 * @see ./selector-comparison.ts — Per-step selector comparison.
 * @see ./failure-logger.ts      — DomContext shape.
 */

import type { DomContext } from "./failure-logger";

export type SelectorTestKind = "Css" | "XPath" | "Auto";

export interface SelectorTestResult {
    readonly Expression: string;
    /** Detected or supplied kind actually used for the lookup. */
    readonly Kind: "Css" | "XPath";
    readonly MatchCount: number;
    readonly FirstMatch: DomContext | null;
    readonly Error: string | null;
}

/** Detect the selector kind from the expression's leading character. */
export function detectSelectorKind(expression: string): "Css" | "XPath" {
    const trimmed = expression.trimStart();
    if (trimmed.startsWith("/") || trimmed.startsWith("(") || trimmed.startsWith("./")) {
        return "XPath";
    }
    return "Css";
}

/** Run the selector against `doc` and report the outcome. */
export function testSelector(
    expression: string,
    doc: Document,
    kind: SelectorTestKind = "Auto",
): SelectorTestResult {
    const trimmed = expression.trim();
    if (trimmed.length === 0) {
        return {
            Expression: expression,
            Kind: kind === "XPath" ? "XPath" : "Css",
            MatchCount: 0,
            FirstMatch: null,
            Error: "Selector is empty",
        };
    }

    const useKind: "Css" | "XPath" = kind === "Auto" ? detectSelectorKind(trimmed) : kind;

    try {
        if (useKind === "XPath") {
            const snapshot = doc.evaluate(
                trimmed, doc, null, XPathResult.ORDERED_NODE_SNAPSHOT_TYPE, null,
            );
            const count = snapshot.snapshotLength;
            const first = count > 0 ? snapshot.snapshotItem(0) : null;
            return {
                Expression: trimmed,
                Kind: "XPath",
                MatchCount: count,
                FirstMatch: first instanceof Element ? readDomContext(first) : null,
                Error: null,
            };
        }
        const list = doc.querySelectorAll(trimmed);
        return {
            Expression: trimmed,
            Kind: "Css",
            MatchCount: list.length,
            FirstMatch: list.length > 0 ? readDomContext(list[0]) : null,
            Error: null,
        };
    } catch (err) {
        return {
            Expression: trimmed,
            Kind: useKind,
            MatchCount: 0,
            FirstMatch: null,
            Error: err instanceof Error ? err.message : String(err),
        };
    }
}

function readDomContext(el: Element): DomContext {
    const id = el.getAttribute("id");
    const cls = el.getAttribute("class");
    const aria = el.getAttribute("aria-label");
    const name = el.getAttribute("name");
    const type = el.getAttribute("type");
    const text = (el.textContent ?? "").trim().slice(0, 120);
    const outer = el.outerHTML?.slice(0, 240) ?? "";
    return {
        TagName: el.tagName.toLowerCase(),
        Id: id !== null && id.length > 0 ? id : null,
        ClassName: cls !== null && cls.length > 0 ? cls : null,
        AriaLabel: aria !== null && aria.length > 0 ? aria : null,
        Name: name !== null && name.length > 0 ? name : null,
        Type: type !== null && type.length > 0 ? type : null,
        TextSnippet: text,
        OuterHtmlSnippet: outer,
    };
}

/**
 * Marco Extension — CSV → GroupInputBag Mapping
 *
 * Converts a single parsed CSV row into the JSON-object input bag
 * stored against a StepGroup (see `group-inputs.ts`). The mapping is
 * two-fold:
 *
 *   1. **Column → Variable**: each CSV column maps to a variable name
 *      OR the special sentinel `"Skip"` (column ignored). The default
 *      variable name is the (sanitised) column header.
 *   2. **Coercion kind**: `auto`, `string`, `number`, `boolean`, or
 *      `json`. `auto` infers from the value:
 *         - `""` → `""` (empty string preserved, NOT null).
 *         - `true` / `false` (case-insensitive) → boolean.
 *         - Pure number that round-trips through `JSON.parse` → number.
 *         - Otherwise → string.
 *
 * Variable name validation:
 *   - 1–64 chars, must start with a letter / `_`, then letters /
 *     digits / `_`. Mirrors typical placeholder syntax for
 *     `{{Variable}}` substitution. Other characters are rejected so
 *     the bag stays compatible with the runner.
 *
 * The function is pure — no DOM, no storage. The dialog wraps it.
 */

import type { GroupInputBag, JsonValue } from "./group-inputs";

export type CoercionKind = "auto" | "string" | "number" | "boolean" | "json";

export interface ColumnMapping {
    /** Source CSV column header (verbatim, case-sensitive). */
    readonly Column: string;
    /** Target variable name in the bag, or null when the column is skipped. */
    readonly Variable: string | null;
    readonly Coerce: CoercionKind;
}

export interface BuildBagOptions {
    readonly Headers: ReadonlyArray<string>;
    readonly Row: ReadonlyArray<string>;
    readonly Mappings: ReadonlyArray<ColumnMapping>;
}

export type BuildBagResult =
    | { readonly Ok: true; readonly Bag: GroupInputBag; readonly UsedColumns: number }
    | {
          readonly Ok: false;
          readonly Reason: string;
          /** Column header (when applicable) that triggered the failure. */
          readonly Column: string | null;
      };

const VARIABLE_NAME_RE = /^[A-Za-z_][A-Za-z0-9_]{0,63}$/;

/** Sanitise a header into a candidate variable name (used as a default). */
export function suggestVariableName(header: string): string {
    let cleaned = header.trim().replace(/[^A-Za-z0-9_]+/g, "_");
    cleaned = cleaned.replace(/^_+|_+$/g, "");
    if (cleaned === "") cleaned = "Var";
    // Ensure leading char is a letter or underscore.
    if (!/^[A-Za-z_]/.test(cleaned)) cleaned = `_${cleaned}`;
    return cleaned.slice(0, 64);
}

/** Returns null when valid; otherwise a human-readable reason. */
export function validateVariableName(name: string): string | null {
    if (name === "") return "Variable name cannot be empty.";
    if (!VARIABLE_NAME_RE.test(name)) {
        return `Variable name "${name}" is invalid — use 1–64 chars, letters/digits/underscore, must not start with a digit.`;
    }
    return null;
}

/**
 * Build the input bag for one row using the provided mappings.
 * Returns a structured failure on the first problem (so the UI can
 * highlight the offending column).
 */
export function buildBagFromRow(opts: BuildBagOptions): BuildBagResult {
    const { Headers, Row, Mappings } = opts;

    if (Headers.length !== Row.length) {
        return {
            Ok: false,
            Reason: `Row has ${Row.length} cell(s) but the header has ${Headers.length} column(s). The CSV is misaligned.`,
            Column: null,
        };
    }

    // Index headers for O(1) lookup; reject duplicate variable targets.
    const headerToIdx = new Map<string, number>();
    for (let i = 0; i < Headers.length; i++) headerToIdx.set(Headers[i], i);

    const bag: Record<string, JsonValue> = {};
    const seenVars = new Set<string>();
    let used = 0;

    for (const m of Mappings) {
        if (m.Variable === null) continue; // explicitly skipped
        const idx = headerToIdx.get(m.Column);
        if (idx === undefined) {
            return {
                Ok: false,
                Reason: `Mapping references column "${m.Column}" which is not in the CSV header.`,
                Column: m.Column,
            };
        }
        const validation = validateVariableName(m.Variable);
        if (validation !== null) {
            return { Ok: false, Reason: validation, Column: m.Column };
        }
        if (seenVars.has(m.Variable)) {
            return {
                Ok: false,
                Reason: `Two columns map to the same variable "${m.Variable}". Each variable name must be unique.`,
                Column: m.Column,
            };
        }
        seenVars.add(m.Variable);

        const raw = Row[idx];
        const coerced = coerceValue(raw, m.Coerce);
        if (!coerced.Ok) {
            return {
                Ok: false,
                Reason: `Column "${m.Column}" → ${m.Variable}: ${coerced.Reason}`,
                Column: m.Column,
            };
        }
        bag[m.Variable] = coerced.Value;
        used++;
    }

    if (used === 0) {
        return {
            Ok: false,
            Reason: "No columns are mapped — every column is set to Skip. Map at least one column to a variable.",
            Column: null,
        };
    }

    return { Ok: true, Bag: bag, UsedColumns: used };
}

type CoerceResult =
    | { readonly Ok: true; readonly Value: JsonValue }
    | { readonly Ok: false; readonly Reason: string };

function coerceValue(raw: string, kind: CoercionKind): CoerceResult {
    switch (kind) {
        case "string":
            return { Ok: true, Value: raw };
        case "number": {
            if (raw.trim() === "") {
                return { Ok: false, Reason: 'Expected a number, got "" (empty cell).' };
            }
            const n = Number(raw);
            if (!Number.isFinite(n)) {
                return { Ok: false, Reason: `Expected a number, got "${raw}".` };
            }
            return { Ok: true, Value: n };
        }
        case "boolean": {
            const t = raw.trim().toLowerCase();
            if (t === "true" || t === "1" || t === "yes" || t === "y") return { Ok: true, Value: true };
            if (t === "false" || t === "0" || t === "no" || t === "n" || t === "") return { Ok: true, Value: false };
            return { Ok: false, Reason: `Expected a boolean (true/false/yes/no/0/1), got "${raw}".` };
        }
        case "json": {
            if (raw.trim() === "") return { Ok: true, Value: "" };
            try {
                return { Ok: true, Value: JSON.parse(raw) as JsonValue };
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err);
                return { Ok: false, Reason: `JSON parse error: ${msg}` };
            }
        }
        case "auto":
        default: {
            if (raw === "") return { Ok: true, Value: "" };
            const t = raw.trim().toLowerCase();
            if (t === "true") return { Ok: true, Value: true };
            if (t === "false") return { Ok: true, Value: false };
            // Treat as number only when the trimmed text round-trips
            // through Number — avoids e.g. "01" → 1 surprises by
            // requiring the printed form to match.
            const trimmed = raw.trim();
            if (/^-?\d+(\.\d+)?([eE][+-]?\d+)?$/.test(trimmed)) {
                const n = Number(trimmed);
                if (Number.isFinite(n) && String(n) === trimmed) {
                    return { Ok: true, Value: n };
                }
            }
            return { Ok: true, Value: raw };
        }
    }
}

/**
 * Marco Extension — Minimal CSV Parser
 *
 * Zero-dep RFC 4180-ish parser tuned for the StepGroup input-data
 * use case. The recorded constraint (mem://workflow/no-questions-mode
 * decision) is **≤ 5 MB / 10 000 rows, fully in memory** — anything
 * larger should stream, which we don't support here.
 *
 * What we handle:
 *   - Comma OR semicolon delimiter (auto-detected from the header).
 *   - Quoted fields with embedded delimiters and newlines.
 *   - Escaped quotes inside quoted fields (`""` → `"`).
 *   - CRLF, LF, and CR line endings.
 *   - Trailing empty line in the file.
 *   - UTF-8 BOM at start of file (stripped).
 *
 * What we do NOT handle (out of scope — fail fast with a clear reason):
 *   - Tab-delimited files (use .tsv-aware tooling).
 *   - Files larger than `MAX_BYTES`.
 *   - Files producing more than `MAX_ROWS` data rows.
 *   - Headerless files. The first non-empty line MUST be the header.
 *
 * The parser returns a structured result — never throws on malformed
 * input. Callers surface the `Reason` to the user verbatim.
 */

export const MAX_BYTES = 5 * 1024 * 1024; // 5 MB
export const MAX_ROWS  = 10_000;          // data rows, header excluded

export interface CsvParseSuccess {
    readonly Ok: true;
    readonly Delimiter: "," | ";";
    readonly Headers: ReadonlyArray<string>;
    /** One row per data line, aligned with `Headers`. Missing trailing cells are coerced to "". */
    readonly Rows: ReadonlyArray<ReadonlyArray<string>>;
    /** Soft warnings — non-fatal anomalies the UI may surface. */
    readonly Warnings: ReadonlyArray<string>;
}

export interface CsvParseFailure {
    readonly Ok: false;
    readonly Reason: string;
    /** 1-based line number where parsing aborted, when known. */
    readonly LineNumber: number | null;
}

export type CsvParseResult = CsvParseSuccess | CsvParseFailure;

export function parseCsv(raw: string): CsvParseResult {
    if (raw.length === 0) {
        return { Ok: false, Reason: "CSV is empty.", LineNumber: null };
    }
    if (raw.length > MAX_BYTES) {
        return {
            Ok: false,
            Reason: `CSV exceeds the ${formatBytes(MAX_BYTES)} in-memory limit (got ${formatBytes(raw.length)}). Trim the file or split it.`,
            LineNumber: null,
        };
    }

    // Strip a UTF-8 BOM if present — Excel loves to add one.
    const source = raw.charCodeAt(0) === 0xfeff ? raw.slice(1) : raw;

    // Auto-detect delimiter from the FIRST non-empty line. We compare
    // unquoted occurrences of `,` vs `;`. Whichever appears more wins;
    // ties favour comma (the spec default).
    const delimiter = detectDelimiter(source);

    const warnings: string[] = [];
    const records: string[][] = [];
    let field = "";
    let row: string[] = [];
    let inQuotes = false;
    let line = 1;

    for (let i = 0; i < source.length; i++) {
        const ch = source[i];

        if (inQuotes) {
            if (ch === '"') {
                // Escaped quote (`""`) inside a quoted field.
                if (source[i + 1] === '"') {
                    field += '"';
                    i++;
                    continue;
                }
                inQuotes = false;
                continue;
            }
            if (ch === "\n") line++;
            field += ch;
            continue;
        }

        // Not inside quotes.
        if (ch === '"') {
            // Quote may only open at the start of a field. Anywhere
            // else, treat literally and warn — most spreadsheets emit
            // this for poorly-escaped data.
            if (field.length === 0) {
                inQuotes = true;
            } else {
                field += ch;
                if (warnings.length < 5) {
                    warnings.push(`Stray double-quote inside an unquoted field on line ${line} — kept literally.`);
                }
            }
            continue;
        }

        if (ch === delimiter) {
            row.push(field);
            field = "";
            continue;
        }

        if (ch === "\r") {
            // Treat CR / CRLF as a single newline.
            if (source[i + 1] === "\n") i++;
            row.push(field);
            records.push(row);
            row = [];
            field = "";
            line++;
            continue;
        }

        if (ch === "\n") {
            row.push(field);
            records.push(row);
            row = [];
            field = "";
            line++;
            continue;
        }

        field += ch;
    }

    if (inQuotes) {
        return {
            Ok: false,
            Reason: `Unterminated quoted field — file ends inside a "..." block. Check for a missing closing quote near line ${line}.`,
            LineNumber: line,
        };
    }

    // Flush the final partial row (no trailing newline).
    if (field !== "" || row.length > 0) {
        row.push(field);
        records.push(row);
    }

    // Drop trailing fully-empty records (a single trailing blank line
    // is normal; multiple blank rows we silently ignore).
    while (records.length > 0 && records[records.length - 1].every((c) => c === "")) {
        records.pop();
    }

    if (records.length === 0) {
        return { Ok: false, Reason: "CSV contained no rows after trimming blank lines.", LineNumber: null };
    }

    const headers = normaliseHeaders(records[0]);
    const headerDupes = findDuplicateHeaders(headers);
    if (headerDupes.length > 0) {
        const quoted = headerDupes.map((h) => `"${h}"`).join(", ");
        return {
            Ok: false,
            Reason: `Duplicate column header(s): ${quoted}. Each column must have a unique name.`,
            LineNumber: 1,
        };
    }

    if (headers.some((h) => h === "")) {
        return {
            Ok: false,
            Reason: "Header row contains an empty column name. Every column needs a header.",
            LineNumber: 1,
        };
    }

    const dataRows = records.slice(1);
    if (dataRows.length > MAX_ROWS) {
        return {
            Ok: false,
            Reason: `CSV has ${dataRows.length} data rows; the limit is ${MAX_ROWS}. Reduce or split the file.`,
            LineNumber: null,
        };
    }

    // Pad short rows / truncate long rows so every row aligns with the
    // header. We warn on each, capped to keep the toast readable.
    const aligned: string[][] = [];
    let padCount = 0;
    let truncCount = 0;
    for (let r = 0; r < dataRows.length; r++) {
        const original = dataRows[r];
        if (original.length < headers.length) {
            const padded = original.slice();
            while (padded.length < headers.length) padded.push("");
            aligned.push(padded);
            padCount++;
        } else if (original.length > headers.length) {
            aligned.push(original.slice(0, headers.length));
            truncCount++;
        } else {
            aligned.push(original);
        }
    }
    if (padCount > 0) warnings.push(`${padCount} row(s) had fewer columns than the header — padded with empty strings.`);
    if (truncCount > 0) warnings.push(`${truncCount} row(s) had extra columns — extras were dropped.`);

    return {
        Ok: true,
        Delimiter: delimiter,
        Headers: headers,
        Rows: aligned,
        Warnings: warnings,
    };
}

function detectDelimiter(source: string): "," | ";" {
    // Inspect the first line, ignoring quoted regions.
    let inQuotes = false;
    let commas = 0;
    let semis = 0;
    for (let i = 0; i < source.length; i++) {
        const ch = source[i];
        if (ch === '"') {
            if (inQuotes && source[i + 1] === '"') { i++; continue; }
            inQuotes = !inQuotes;
            continue;
        }
        if (inQuotes) continue;
        if (ch === "\n" || ch === "\r") break;
        if (ch === ",") commas++;
        else if (ch === ";") semis++;
    }
    return semis > commas ? ";" : ",";
}

function normaliseHeaders(cells: ReadonlyArray<string>): string[] {
    return cells.map((c) => c.trim());
}

function findDuplicateHeaders(headers: ReadonlyArray<string>): string[] {
    const seen = new Set<string>();
    const dupes = new Set<string>();
    for (const h of headers) {
        if (h === "") continue;
        if (seen.has(h)) dupes.add(h);
        else seen.add(h);
    }
    return Array.from(dupes);
}

function formatBytes(n: number): string {
    if (n < 1024) return `${n} B`;
    if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
    return `${(n / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Marco Extension — Step Library DB Wrapper
 *
 * Synchronous CRUD over the schema defined in `./schema.ts`. Pure
 * sql.js — no OPFS, no chrome.storage, no service-worker concerns.
 * The OPFS persistence layer wraps this module (see
 * `./persistence.ts`) and keeps writes serialised behind a single
 * promise queue.
 *
 * Why sync API: sql.js itself is synchronous; exposing async here
 * would lie about latency (it would be microtasks, not real I/O).
 * The wrapper that flushes to OPFS is the only async surface.
 *
 * Failure handling: every method that the user can trigger MUST emit
 * structured errors via `buildFailureReport()` from
 * `src/background/recorder/failure-logger.ts` when it's surfaced to
 * the UI. This module throws plain `Error`s; the calling layer wraps
 * them. See mem://standards/verbose-logging-and-failure-diagnostics.
 *
 * @see ./schema.ts
 * @see spec/31-macro-recorder/16-step-group-library.md  §8.1
 */

import type { Database } from "sql.js";
import { applySchema, StepKindId } from "./schema";

/* ------------------------------------------------------------------ */
/*  Row shapes (PascalCase, mirrors DDL exactly)                       */
/* ------------------------------------------------------------------ */

export interface ProjectRow {
    readonly ProjectId: number;
    readonly ProjectExternalId: string;
    readonly Name: string;
    readonly CreatedAt: string;
    readonly UpdatedAt: string;
}

export interface StepGroupRow {
    readonly StepGroupId: number;
    readonly ProjectId: number;
    readonly ParentStepGroupId: number | null;
    readonly Name: string;
    readonly Description: string | null;
    readonly OrderIndex: number;
    readonly IsArchived: boolean;
    readonly CreatedAt: string;
    readonly UpdatedAt: string;
}

export interface StepRow {
    readonly StepId: number;
    readonly StepGroupId: number;
    readonly OrderIndex: number;
    readonly StepKindId: StepKindId;
    readonly Label: string | null;
    readonly PayloadJson: string | null;
    readonly TargetStepGroupId: number | null;
    readonly IsDisabled: boolean;
    readonly CreatedAt: string;
    readonly UpdatedAt: string;
}

/* ------------------------------------------------------------------ */
/*  Wrapper                                                            */
/* ------------------------------------------------------------------ */

/**
 * Synchronous wrapper around a sql.js `Database`. The constructor
 * automatically applies the schema (idempotent), so callers can hand
 * in a fresh DB or a deserialised one.
 */
export class StepLibraryDb {
    constructor(private readonly db: Database) {
        applySchema(db);
    }

    /** Direct DB access for the persistence/export layer. */
    get raw(): Database { return this.db; }

    /* -------------------- Project --------------------------------- */

    upsertProject(input: { ExternalId: string; Name: string }): number {
        const stmt = this.db.prepare(
            `INSERT INTO Project (ProjectExternalId, Name) VALUES (?, ?)
             ON CONFLICT(ProjectExternalId) DO UPDATE SET
                 Name = excluded.Name,
                 UpdatedAt = datetime('now')
             RETURNING ProjectId;`,
        );
        try {
            stmt.bind([input.ExternalId, input.Name]);
            if (!stmt.step()) {
                throw new Error("upsertProject: RETURNING returned no row");
            }
            const row = stmt.getAsObject();
            return row.ProjectId as number;
        } finally {
            stmt.free();
        }
    }

    listProjects(): readonly ProjectRow[] {
        return this.selectAll<ProjectRow>(
            `SELECT ProjectId, ProjectExternalId, Name, CreatedAt, UpdatedAt
             FROM Project ORDER BY Name COLLATE NOCASE ASC;`,
        );
    }

    /* -------------------- StepGroup ------------------------------- */

    listGroups(projectId: number): readonly StepGroupRow[] {
        return this.selectAll<StepGroupRow>(
            `SELECT StepGroupId, ProjectId, ParentStepGroupId, Name, Description,
                    OrderIndex, IsArchived, CreatedAt, UpdatedAt
             FROM StepGroup
             WHERE ProjectId = ?
             ORDER BY ParentStepGroupId IS NULL DESC,
                      ParentStepGroupId ASC,
                      OrderIndex ASC, Name COLLATE NOCASE ASC;`,
            [projectId],
        ).map(coerceGroupRow);
    }

    createGroup(input: {
        ProjectId: number;
        ParentStepGroupId: number | null;
        Name: string;
        Description?: string | null;
        OrderIndex?: number;
    }): number {
        const stmt = this.db.prepare(
            `INSERT INTO StepGroup
                (ProjectId, ParentStepGroupId, Name, Description, OrderIndex)
             VALUES (?, ?, ?, ?, ?)
             RETURNING StepGroupId;`,
        );
        try {
            stmt.bind([
                input.ProjectId,
                input.ParentStepGroupId,
                input.Name,
                input.Description ?? null,
                input.OrderIndex ?? 0,
            ]);
            if (!stmt.step()) {
                throw new Error("createGroup: RETURNING returned no row");
            }
            return stmt.getAsObject().StepGroupId as number;
        } finally {
            stmt.free();
        }
    }

    renameGroup(stepGroupId: number, newName: string): void {
        this.exec(
            `UPDATE StepGroup SET Name = ?, UpdatedAt = datetime('now')
             WHERE StepGroupId = ?;`,
            [newName, stepGroupId],
        );
    }

    moveGroup(stepGroupId: number, newParentId: number | null): void {
        this.exec(
            `UPDATE StepGroup SET ParentStepGroupId = ?, UpdatedAt = datetime('now')
             WHERE StepGroupId = ?;`,
            [newParentId, stepGroupId],
        );
    }

    deleteGroup(stepGroupId: number): void {
        this.exec(`DELETE FROM StepGroup WHERE StepGroupId = ?;`, [stepGroupId]);
    }

    /**
     * Reorder sibling groups under a single parent. Behaves like
     * `reorderSteps`: validates that every supplied id belongs to the
     * given (project, parent) bucket and that the count matches the
     * existing children — partial reorders are rejected to avoid
     * holes / duplicate OrderIndex values.
     *
     * `parentStepGroupId === null` reorders root-level groups.
     */
    reorderGroups(
        projectId: number,
        parentStepGroupId: number | null,
        orderedStepGroupIds: readonly number[],
    ): void {
        const owned = new Set(
            this.listGroups(projectId)
                .filter((g) => (g.ParentStepGroupId ?? null) === parentStepGroupId)
                .map((g) => g.StepGroupId),
        );
        for (const id of orderedStepGroupIds) {
            if (!owned.has(id)) {
                throw new Error(
                    `reorderGroups: StepGroupId ${id} is not a child of parent=${String(parentStepGroupId)} ` +
                    `in ProjectId=${projectId}. Refusing partial reorder — would corrupt OrderIndex.`,
                );
            }
        }
        if (orderedStepGroupIds.length !== owned.size) {
            throw new Error(
                `reorderGroups: expected ${owned.size} sibling ids, got ${orderedStepGroupIds.length}. ` +
                `Caller must pass the COMPLETE list of siblings under parent=${String(parentStepGroupId)}.`,
            );
        }

        this.db.exec("BEGIN;");
        try {
            const stmt = this.db.prepare(
                `UPDATE StepGroup SET OrderIndex = ?, UpdatedAt = datetime('now')
                 WHERE StepGroupId = ?;`,
            );
            try {
                for (let i = 0; i < orderedStepGroupIds.length; i++) {
                    stmt.run([i, orderedStepGroupIds[i]]);
                }
            } finally {
                stmt.free();
            }
            this.db.exec("COMMIT;");
        } catch (e) {
            this.db.exec("ROLLBACK;");
            throw e;
        }
    }

    /**
     * Toggle the `IsArchived` flag on a single group. Archiving does
     * NOT touch nested groups or steps — they remain queryable; the UI
     * is responsible for hiding archived subtrees behind a toggle.
     */
    setGroupArchived(stepGroupId: number, archived: boolean): void {
        this.exec(
            `UPDATE StepGroup SET IsArchived = ?, UpdatedAt = datetime('now')
             WHERE StepGroupId = ?;`,
            [archived ? 1 : 0, stepGroupId],
        );
    }

    /* -------------------- Step ------------------------------------ */

    listSteps(stepGroupId: number): readonly StepRow[] {
        return this.selectAll<StepRow>(
            `SELECT StepId, StepGroupId, OrderIndex, StepKindId, Label,
                    PayloadJson, TargetStepGroupId, IsDisabled, CreatedAt, UpdatedAt
             FROM Step
             WHERE StepGroupId = ?
             ORDER BY OrderIndex ASC, StepId ASC;`,
            [stepGroupId],
        ).map(coerceStepRow);
    }

    appendStep(input: {
        StepGroupId: number;
        StepKindId: StepKindId;
        Label?: string | null;
        PayloadJson?: string | null;
        TargetStepGroupId?: number | null;
    }): number {
        // Validate the RunGroup invariant in JS too — the CHECK
        // constraint catches it at the DB but a clear error is nicer.
        const isRunGroup = input.StepKindId === StepKindId.RunGroup;
        if (isRunGroup && (input.TargetStepGroupId === undefined || input.TargetStepGroupId === null)) {
            throw new Error(
                "appendStep: StepKind=RunGroup requires TargetStepGroupId. " +
                "Without a target the runner cannot resolve which group to invoke.",
            );
        }
        if (!isRunGroup && input.TargetStepGroupId !== undefined && input.TargetStepGroupId !== null) {
            throw new Error(
                "appendStep: TargetStepGroupId is only valid when StepKind=RunGroup.",
            );
        }

        const nextOrder = this.scalarNumber(
            `SELECT COALESCE(MAX(OrderIndex), -1) + 1 FROM Step WHERE StepGroupId = ?;`,
            [input.StepGroupId],
        );
        const stmt = this.db.prepare(
            `INSERT INTO Step
                (StepGroupId, OrderIndex, StepKindId, Label, PayloadJson, TargetStepGroupId)
             VALUES (?, ?, ?, ?, ?, ?)
             RETURNING StepId;`,
        );
        try {
            stmt.bind([
                input.StepGroupId,
                nextOrder,
                input.StepKindId,
                input.Label ?? null,
                input.PayloadJson ?? null,
                input.TargetStepGroupId ?? null,
            ]);
            if (!stmt.step()) {
                throw new Error("appendStep: RETURNING returned no row");
            }
            return stmt.getAsObject().StepId as number;
        } finally {
            stmt.free();
        }
    }

    reorderSteps(stepGroupId: number, orderedStepIds: readonly number[]): void {
        // Verify all IDs belong to this group; reject mixed-group reorders.
        const owned = new Set(this.listSteps(stepGroupId).map((s) => s.StepId));
        for (const id of orderedStepIds) {
            if (!owned.has(id)) {
                throw new Error(
                    `reorderSteps: StepId ${id} does not belong to StepGroup ${stepGroupId}`,
                );
            }
        }
        if (orderedStepIds.length !== owned.size) {
            throw new Error(
                `reorderSteps: expected ${owned.size} step IDs, got ${orderedStepIds.length}`,
            );
        }
        this.db.exec("BEGIN;");
        try {
            const stmt = this.db.prepare(
                `UPDATE Step SET OrderIndex = ?, UpdatedAt = datetime('now')
                 WHERE StepId = ?;`,
            );
            try {
                for (let i = 0; i < orderedStepIds.length; i++) {
                    stmt.run([i, orderedStepIds[i]]);
                }
            } finally {
                stmt.free();
            }
            this.db.exec("COMMIT;");
        } catch (e) {
            this.db.exec("ROLLBACK;");
            throw e;
        }
    }

    deleteStep(stepId: number): void {
        this.exec(`DELETE FROM Step WHERE StepId = ?;`, [stepId]);
    }

    /**
     * Edit a single step in place. The (StepKindId, TargetStepGroupId)
     * invariant from `appendStep` applies here too: RunGroup steps
     * require a target, every other kind must have target=null.
     * `OrderIndex` is preserved — use `reorderSteps` to move a step.
     */
    updateStep(input: {
        StepId: number;
        StepKindId: StepKindId;
        Label?: string | null;
        PayloadJson?: string | null;
        TargetStepGroupId?: number | null;
    }): void {
        const isRunGroup = input.StepKindId === StepKindId.RunGroup;
        if (isRunGroup && (input.TargetStepGroupId === undefined || input.TargetStepGroupId === null)) {
            throw new Error(
                "updateStep: StepKind=RunGroup requires TargetStepGroupId.",
            );
        }
        if (!isRunGroup && input.TargetStepGroupId !== undefined && input.TargetStepGroupId !== null) {
            throw new Error(
                "updateStep: TargetStepGroupId is only valid when StepKind=RunGroup.",
            );
        }
        this.exec(
            `UPDATE Step
             SET StepKindId = ?, Label = ?, PayloadJson = ?, TargetStepGroupId = ?,
                 UpdatedAt = datetime('now')
             WHERE StepId = ?;`,
            [
                input.StepKindId,
                input.Label ?? null,
                input.PayloadJson ?? null,
                input.TargetStepGroupId ?? null,
                input.StepId,
            ],
        );
    }

    /**
     * Toggle the `IsDisabled` flag on a single step. The runner's
     * expansion phase (`expandRunGroups`) drops disabled steps from
     * the plan when `skipDisabled` is left at its default `true`, so
     * flipping this flag is the canonical way to test that a step is
     * skipped at runtime without having to delete + re-create it.
     */
    setStepDisabled(stepId: number, disabled: boolean): void {
        this.exec(
            `UPDATE Step SET IsDisabled = ?, UpdatedAt = datetime('now')
             WHERE StepId = ?;`,
            [disabled ? 1 : 0, stepId],
        );
    }

    /* -------------------- Snapshot -------------------------------- */

    /** Serialize the entire DB to bytes (for export). */
    exportDbBytes(): Uint8Array {
        return this.db.export();
    }

    /* -------------------- Private --------------------------------- */

    private exec(sql: string, params: ReadonlyArray<number | string | null>): void {
        const stmt = this.db.prepare(sql);
        try {
            stmt.run(params as Array<number | string | null>);
        } finally {
            stmt.free();
        }
    }

    private selectAll<T>(sql: string, params: ReadonlyArray<number | string | null> = []): T[] {
        const stmt = this.db.prepare(sql);
        try {
            stmt.bind(params as Array<number | string | null>);
            const rows: T[] = [];
            while (stmt.step()) {
                rows.push(stmt.getAsObject() as unknown as T);
            }
            return rows;
        } finally {
            stmt.free();
        }
    }

    private scalarNumber(sql: string, params: ReadonlyArray<number | string | null>): number {
        const stmt = this.db.prepare(sql);
        try {
            stmt.bind(params as Array<number | string | null>);
            if (!stmt.step()) return 0;
            const v = stmt.get()[0];
            return typeof v === "number" ? v : 0;
        } finally {
            stmt.free();
        }
    }
}

/** sql.js returns INTEGERs as numbers but TINYINT booleans need coercion. */
function coerceGroupRow(r: StepGroupRow): StepGroupRow {
    return { ...r, IsArchived: Boolean(r.IsArchived) };
}

function coerceStepRow(r: StepRow): StepRow {
    return { ...r, IsDisabled: Boolean(r.IsDisabled) };
}

/**
 * Marco Extension — Step Group Bundle Export
 *
 * Packages a user-selected subset of `StepGroup` rows (and their `Step`
 * children, optionally including descendants) into a downloadable ZIP
 * containing:
 *
 *   manifest.json     — selection metadata, schema version, checksums.
 *   step-groups.db    — a fresh sql.js database with only the selected
 *                       Project + StepGroup + Step rows + the canonical
 *                       StepKind seed. Schema is identical to the live
 *                       DB so it can be re-opened with `StepLibraryDb`.
 *   readme.txt        — plain-text human description of the bundle.
 *
 * The module is **pure** — no chrome.*, no DOM, no file-system. It
 * accepts the live `StepLibraryDb` plus a sql.js factory, and returns
 * the bytes of a finished ZIP. The caller decides how to surface the
 * download (popup `<a download>`, options page, background → blob URL).
 *
 * Failures are returned as structured `ExportFailure` objects that
 * conform to the verbose-logging-and-failure-diagnostics contract — a
 * `Reason`, optional `Detail`, and the offending IDs. Nothing is
 * thrown to the caller after `runStepGroupExport` returns.
 *
 * @see spec/31-macro-recorder/16-step-group-library.md  §8.4 (export)
 * @see mem://standards/verbose-logging-and-failure-diagnostics
 */

import type { Database, SqlJsStatic } from "sql.js";
import type JSZipType from "jszip";

import { applySchema, StepKindId } from "./schema";
import { StepLibraryDb, type StepGroupRow, type StepRow } from "./db";

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export const STEP_GROUP_BUNDLE_FORMAT_VERSION = 1;

export interface StepGroupExportInput {
    /** Source DB to read from. */
    readonly Source: StepLibraryDb;
    /** Project that owns every selected group. */
    readonly ProjectId: number;
    /** Group IDs the user explicitly ticked in the UI. */
    readonly SelectedStepGroupIds: ReadonlyArray<number>;
    /** When true, all transitive descendants of each selection are included. */
    readonly IncludeDescendants?: boolean;
    /** Free-form label persisted in the manifest (e.g. "Q2 onboarding macros"). */
    readonly BundleName?: string;
    /** Optional override for the timestamp baked into the manifest. */
    readonly NowIso?: () => string;
}

export type ExportReason =
    | "Ok"
    | "ProjectNotFound"
    | "GroupNotFound"
    | "GroupOutsideProject"
    | "EmptySelection"
    | "RunGroupTargetMissing"
    | "InternalError";

export interface ExportFailure {
    readonly Reason: Exclude<ExportReason, "Ok">;
    readonly Detail: string;
    readonly OffendingIds: ReadonlyArray<number>;
}

export interface StepGroupExportManifest {
    readonly FormatVersion: number;
    readonly GeneratedAt: string;
    readonly BundleName: string;
    readonly Project: {
        readonly ProjectId: number;
        readonly ProjectExternalId: string;
        readonly Name: string;
    };
    readonly Selection: {
        readonly SelectedStepGroupIds: ReadonlyArray<number>;
        readonly IncludeDescendants: boolean;
        readonly EffectiveStepGroupIds: ReadonlyArray<number>;
    };
    readonly Counts: {
        readonly StepGroups: number;
        readonly Steps: number;
        readonly RunGroupRefs: number;
    };
    readonly DbFileName: string;
    readonly DbByteLength: number;
    readonly DbSha256: string;
}

export interface StepGroupExportSuccess {
    readonly Reason: "Ok";
    readonly ZipBytes: Uint8Array;
    readonly ZipFileName: string;
    readonly Manifest: StepGroupExportManifest;
}

export type StepGroupExportResult = StepGroupExportSuccess | ExportFailure;

export interface RunStepGroupExportInit extends StepGroupExportInput {
    /** sql.js factory — typically the lazily-initialised singleton. */
    readonly SqlJs: SqlJsStatic;
    /** JSZip constructor — passed in so this module stays tree-shakeable. */
    readonly JsZip: typeof JSZipType;
}

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const MANIFEST_FILE = "manifest.json";
const DB_FILE = "step-groups.db";
const README_FILE = "readme.txt";

/* ------------------------------------------------------------------ */
/*  Selection resolution                                               */
/* ------------------------------------------------------------------ */

/**
 * Expand the user selection into the effective set of group IDs that
 * will be copied into the bundle. Returns either the resolved set or a
 * structured failure (project mismatch, missing IDs, empty selection).
 *
 * Pure — does not mutate the source DB.
 */
export function resolveSelection(
    src: StepLibraryDb,
    projectId: number,
    selected: ReadonlyArray<number>,
    includeDescendants: boolean,
): { readonly Ok: true; readonly Ids: ReadonlyArray<number> } | ExportFailure {
    if (selected.length === 0) {
        return {
            Reason: "EmptySelection",
            Detail: "SelectedStepGroupIds was empty — nothing to export.",
            OffendingIds: [],
        };
    }

    const allInProject = src.listGroups(projectId);
    const byId = new Map<number, StepGroupRow>(
        allInProject.map((g) => [g.StepGroupId, g]),
    );
    const childrenOf = new Map<number, number[]>();
    for (const g of allInProject) {
        if (g.ParentStepGroupId !== null) {
            const items = childrenOf.get(g.ParentStepGroupId) ?? [];
            items.push(g.StepGroupId);
            childrenOf.set(g.ParentStepGroupId, items);
        }
    }

    const missing: number[] = [];
    const wrongProject: number[] = [];
    const seedIds: number[] = [];
    for (const id of selected) {
        const row = byId.get(id);
        if (row === undefined) {
            // Could be in another project, or not exist at all.
            missing.push(id);
            continue;
        }
        if (row.ProjectId !== projectId) {
            wrongProject.push(id);
            continue;
        }
        seedIds.push(id);
    }
    if (wrongProject.length > 0) {
        return {
            Reason: "GroupOutsideProject",
            Detail: `StepGroupId(s) ${wrongProject.join(", ")} do not belong to ProjectId=${projectId}.`,
            OffendingIds: wrongProject,
        };
    }
    if (missing.length > 0) {
        return {
            Reason: "GroupNotFound",
            Detail: `StepGroupId(s) ${missing.join(", ")} not found in project ${projectId}.`,
            OffendingIds: missing,
        };
    }

    if (!includeDescendants) {
        return { Ok: true, Ids: dedupeSorted(seedIds) };
    }

    // BFS through descendants; cap visited to len(allInProject) to defend
    // against pathological cycles (the schema triggers should already
    // forbid them, but defensive coding keeps export deterministic).
    const visited = new Set<number>();
    const queue: number[] = [...seedIds];
    const ceiling = allInProject.length + 1;
    let iter = 0;
    while (queue.length > 0) {
        if (iter++ > ceiling) {
            return {
                Reason: "InternalError",
                Detail: "Descendant traversal exceeded ceiling — possible cycle in StepGroup tree.",
                OffendingIds: Array.from(visited),
            };
        }
        const id = queue.shift() as number;
        if (visited.has(id)) continue;
        visited.add(id);
        const kids = childrenOf.get(id);
        if (kids !== undefined) {
            for (const k of kids) queue.push(k);
        }
    }
    return { Ok: true, Ids: dedupeSorted(Array.from(visited)) };
}

function dedupeSorted(ids: ReadonlyArray<number>): ReadonlyArray<number> {
    return Array.from(new Set(ids)).sort((a, b) => a - b);
}

/* ------------------------------------------------------------------ */
/*  Preview (dry-run)                                                  */
/* ------------------------------------------------------------------ */

/**
 * A single RunGroup invocation whose target StepGroup is **not** part
 * of the effective export selection. Surfaced as a warning in the
 * pre-download preview dialog so the user can either widen their
 * selection (or tick "Include descendants") before they ship a bundle
 * that would fail import-time integrity checks.
 */
export interface DanglingRunGroupRef {
    readonly StepId: number;
    readonly StepLabel: string | null;
    readonly OwnerStepGroupId: number;
    readonly OwnerStepGroupName: string;
    readonly TargetStepGroupId: number | null;
}

export interface StepGroupExportPreview {
    readonly Reason: "Ok";
    /** Effective set after descendant resolution — what will ship. */
    readonly EffectiveStepGroupIds: ReadonlyArray<number>;
    readonly Counts: {
        readonly StepGroups: number;
        readonly Steps: number;
        readonly RunGroupRefs: number;
    };
    /**
     * RunGroup steps whose target lives outside the effective selection.
     * Non-empty means a real export would fail with `RunGroupTargetMissing`
     * — the UI uses this list to warn the user before they click download.
     */
    readonly DanglingRunGroupRefs: ReadonlyArray<DanglingRunGroupRef>;
}

export type StepGroupExportPreviewResult = StepGroupExportPreview | ExportFailure;

export interface PreviewStepGroupExportInput {
    readonly Source: StepLibraryDb;
    readonly ProjectId: number;
    readonly SelectedStepGroupIds: ReadonlyArray<number>;
    readonly IncludeDescendants?: boolean;
}

/**
 * Compute the same selection / counts / RunGroup-ref analysis the real
 * export would, **without** building a sql.js snapshot or hashing.
 *
 * This is the data source for the pre-download preview dialog: it
 * always succeeds with counts when the selection itself is valid, and
 * returns dangling RunGroup refs as soft warnings (not failures) so
 * the user can decide whether to widen the selection or proceed.
 *
 * Pure — no DOM, no I/O, safe to call on every selection change.
 */
export function previewStepGroupExport(
    init: PreviewStepGroupExportInput,
): StepGroupExportPreviewResult {
    const resolved = resolveSelection(
        init.Source,
        init.ProjectId,
        init.SelectedStepGroupIds,
        init.IncludeDescendants ?? false,
    );
    if ("Reason" in resolved) return resolved;

    const includedSet = new Set(resolved.Ids);
    const groupNameById = new Map<number, string>();
    for (const g of init.Source.listGroups(init.ProjectId)) {
        groupNameById.set(g.StepGroupId, g.Name);
    }

    let stepCount = 0;
    let runGroupRefs = 0;
    const dangling: DanglingRunGroupRef[] = [];
    for (const id of resolved.Ids) {
        for (const s of init.Source.listSteps(id)) {
            stepCount += 1;
            if (s.StepKindId === StepKindId.RunGroup) {
                runGroupRefs += 1;
                if (s.TargetStepGroupId === null || !includedSet.has(s.TargetStepGroupId)) {
                    dangling.push({
                        StepId: s.StepId,
                        StepLabel: s.Label,
                        OwnerStepGroupId: id,
                        OwnerStepGroupName: groupNameById.get(id) ?? `#${id}`,
                        TargetStepGroupId: s.TargetStepGroupId,
                    });
                }
            }
        }
    }

    return {
        Reason: "Ok",
        EffectiveStepGroupIds: resolved.Ids,
        Counts: {
            StepGroups: resolved.Ids.length,
            Steps: stepCount,
            RunGroupRefs: runGroupRefs,
        },
        DanglingRunGroupRefs: dangling,
    };
}

/* ------------------------------------------------------------------ */
/*  Filtered snapshot                                                  */
/* ------------------------------------------------------------------ */

interface SnapshotResult {
    readonly DbBytes: Uint8Array;
    readonly Counts: { readonly StepGroups: number; readonly Steps: number; readonly RunGroupRefs: number };
}

/**
 * Build a fresh sql.js database whose schema matches the live one and
 * whose data is restricted to:
 *   - the parent Project row,
 *   - the resolved StepGroup rows,
 *   - every Step row owned by those groups.
 *
 * RunGroup steps whose `TargetStepGroupId` is NOT in the effective set
 * fail the export with `RunGroupTargetMissing` — the bundle would
 * otherwise be unusable on import (broken FK).
 */
export function buildFilteredSnapshot(
    src: StepLibraryDb,
    sqlJs: SqlJsStatic,
    projectId: number,
    effectiveIds: ReadonlyArray<number>,
): SnapshotResult | ExportFailure {
    const projectRow = src.listProjects().find((p) => p.ProjectId === projectId);
    if (projectRow === undefined) {
        return {
            Reason: "ProjectNotFound",
            Detail: `ProjectId=${projectId} not present in source DB.`,
            OffendingIds: [projectId],
        };
    }

    // Pre-flight: collect all steps for the selected groups + verify
    // RunGroup targets stay inside the bundle.
    const includedSet = new Set(effectiveIds);
    const allSteps: StepRow[] = [];
    const danglingRunGroup: number[] = [];
    let runGroupRefs = 0;
    for (const id of effectiveIds) {
        for (const s of src.listSteps(id)) {
            allSteps.push(s);
            if (s.StepKindId === StepKindId.RunGroup) {
                runGroupRefs += 1;
                if (s.TargetStepGroupId === null || !includedSet.has(s.TargetStepGroupId)) {
                    danglingRunGroup.push(s.StepId);
                }
            }
        }
    }
    if (danglingRunGroup.length > 0) {
        return {
            Reason: "RunGroupTargetMissing",
            Detail:
                `Step(s) ${danglingRunGroup.join(", ")} are RunGroup invocations whose target ` +
                `StepGroup is not in the export selection. Re-run with IncludeDescendants=true ` +
                `or add the missing groups manually.`,
            OffendingIds: danglingRunGroup,
        };
    }

    // Build a fresh DB with the same schema. We disable foreign keys
    // for the bulk insert and re-enable PRAGMA at the end so the
    // re-opened bundle stays consistent.
    const dst = new sqlJs.Database();
    try {
        applySchema(dst);
        dst.exec("PRAGMA foreign_keys = OFF;");
        dst.exec("BEGIN;");

        copyProject(dst, {
            ProjectId: projectRow.ProjectId,
            ProjectExternalId: projectRow.ProjectExternalId,
            Name: projectRow.Name,
            CreatedAt: projectRow.CreatedAt,
            UpdatedAt: projectRow.UpdatedAt,
        });

        // Insert StepGroups in dependency order (parents before
        // children) so the FK reference is always satisfied even if
        // the user later turns foreign_keys back on.
        const orderedGroups = orderGroupsByAncestry(
            effectiveIds.map((id) => requireRow(src.listGroups(projectId), id)),
        );
        for (const g of orderedGroups) {
            insertGroup(dst, g);
        }
        for (const s of allSteps) {
            insertStep(dst, s);
        }

        dst.exec("COMMIT;");
        dst.exec("PRAGMA foreign_keys = ON;");
        const bytes = dst.export();
        return {
            DbBytes: bytes,
            Counts: {
                StepGroups: orderedGroups.length,
                Steps: allSteps.length,
                RunGroupRefs: runGroupRefs,
            },
        };
    } catch (err) {
        try {
            dst.exec("ROLLBACK;");
        } catch { // allow-swallow: ROLLBACK after a failed COMMIT — outer err is already returned; rethrowing here would mask it.
            /* ignore */
        }
        return {
            Reason: "InternalError",
            Detail: err instanceof Error ? err.message : "snapshot build failed",
            OffendingIds: Array.from(includedSet),
        };
    } finally {
        dst.close();
    }
}

function requireRow(rows: ReadonlyArray<StepGroupRow>, id: number): StepGroupRow {
    const row = rows.find((r) => r.StepGroupId === id);
    if (row === undefined) {
        throw new Error(`buildFilteredSnapshot: StepGroupId ${id} disappeared mid-export`);
    }
    return row;
}

function orderGroupsByAncestry(rows: ReadonlyArray<StepGroupRow>): StepGroupRow[] {
    // Topological sort: a group can only be inserted after its parent
    // (when the parent is also part of the selection).
    const ids = new Set(rows.map((r) => r.StepGroupId));
    const remaining = new Map(rows.map((r) => [r.StepGroupId, r]));
    const out: StepGroupRow[] = [];
    while (remaining.size > 0) {
        let progressed = false;
        for (const [id, r] of remaining) {
            const parent = r.ParentStepGroupId;
            if (parent === null || !ids.has(parent) || out.some((o) => o.StepGroupId === parent)) {
                out.push(r);
                remaining.delete(id);
                progressed = true;
                break;
            }
        }
        if (!progressed) {
            // Should be impossible — depth triggers prevent cycles —
            // but make it deterministic in case the DB was hand-edited.
            for (const r of remaining.values()) out.push(r);
            break;
        }
    }
    return out;
}

function copyProject(
    db: Database,
    p: {
        readonly ProjectId: number;
        readonly ProjectExternalId: string;
        readonly Name: string;
        readonly CreatedAt: string;
        readonly UpdatedAt: string;
    },
): void {
    const stmt = db.prepare(
        `INSERT INTO Project (ProjectId, ProjectExternalId, Name, CreatedAt, UpdatedAt)
         VALUES (?, ?, ?, ?, ?);`,
    );
    try {
        stmt.run([p.ProjectId, p.ProjectExternalId, p.Name, p.CreatedAt, p.UpdatedAt]);
    } finally {
        stmt.free();
    }
}

function insertGroup(db: Database, g: StepGroupRow): void {
    const stmt = db.prepare(
        `INSERT INTO StepGroup (
            StepGroupId, ProjectId, ParentStepGroupId, Name, Description,
            OrderIndex, IsArchived, CreatedAt, UpdatedAt
         ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?);`,
    );
    try {
        stmt.run([
            g.StepGroupId,
            g.ProjectId,
            g.ParentStepGroupId,
            g.Name,
            g.Description,
            g.OrderIndex,
            g.IsArchived ? 1 : 0,
            g.CreatedAt,
            g.UpdatedAt,
        ]);
    } finally {
        stmt.free();
    }
}

function insertStep(db: Database, s: StepRow): void {
    const stmt = db.prepare(
        `INSERT INTO Step (
            StepId, StepGroupId, OrderIndex, StepKindId, Label,
            PayloadJson, TargetStepGroupId, IsDisabled, CreatedAt, UpdatedAt
         ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?);`,
    );
    try {
        stmt.run([
            s.StepId,
            s.StepGroupId,
            s.OrderIndex,
            s.StepKindId,
            s.Label,
            s.PayloadJson,
            s.TargetStepGroupId,
            s.IsDisabled ? 1 : 0,
            s.CreatedAt,
            s.UpdatedAt,
        ]);
    } finally {
        stmt.free();
    }
}

/* ------------------------------------------------------------------ */
/*  Hashing & ZIP packaging                                            */
/* ------------------------------------------------------------------ */

/**
 * SHA-256 hash returned as lowercase hex. Uses an in-module implementation
 * to avoid cross-realm WebCrypto input rejection in Vitest/jsdom workers.
 */
export async function sha256Hex(bytes: Uint8Array): Promise<string> {
    return sha256HexSync(bytes);
}

const SHA256_INITIAL = [
    0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,
    0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19,
];

const SHA256_K = [
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
    0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
    0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
    0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
    0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
];

function sha256HexSync(bytes: Uint8Array): string {
    const hash = [...SHA256_INITIAL];
    const padded = makeSha256PaddedMessage(bytes);
    const words = new Uint32Array(64);
    for (let offset = 0; offset < padded.length; offset += 64) {
        processSha256Block(padded, offset, words, hash);
    }
    return sha256WordsToHex(hash);
}

function makeSha256PaddedMessage(bytes: Uint8Array): Uint8Array {
    const paddedLength = Math.ceil((bytes.length + 9) / 64) * 64;
    const padded = new Uint8Array(paddedLength);
    padded.set(bytes);
    padded[bytes.length] = 0x80;
    const bitLength = bytes.length * 8;
    const high = Math.floor(bitLength / 0x100000000);
    const low = bitLength >>> 0;
    writeUint32Be(padded, paddedLength - 8, high);
    writeUint32Be(padded, paddedLength - 4, low);
    return padded;
}

function processSha256Block(
    padded: Uint8Array,
    offset: number,
    words: Uint32Array,
    hash: number[],
): void {
    fillSha256Words(padded, offset, words);
    const state = runSha256Rounds(words, hash);
    for (let i = 0; i < 8; i++) {
        hash[i] = (hash[i] + state[i]) >>> 0;
    }
}

function fillSha256Words(padded: Uint8Array, offset: number, words: Uint32Array): void {
    for (let i = 0; i < 16; i++) {
        words[i] = readUint32Be(padded, offset + i * 4);
    }
    for (let i = 16; i < 64; i++) {
        const s0 = rotateRight(words[i - 15], 7) ^ rotateRight(words[i - 15], 18) ^ (words[i - 15] >>> 3);
        const s1 = rotateRight(words[i - 2], 17) ^ rotateRight(words[i - 2], 19) ^ (words[i - 2] >>> 10);
        words[i] = (words[i - 16] + s0 + words[i - 7] + s1) >>> 0;
    }
}

function runSha256Rounds(words: Uint32Array, hash: number[]): number[] {
    const state = [...hash];
    for (let i = 0; i < 64; i++) {
        const s1 = rotateRight(state[4], 6) ^ rotateRight(state[4], 11) ^ rotateRight(state[4], 25);
        const ch = (state[4] & state[5]) ^ (~state[4] & state[6]);
        const temp1 = (state[7] + s1 + ch + SHA256_K[i] + words[i]) >>> 0;
        const s0 = rotateRight(state[0], 2) ^ rotateRight(state[0], 13) ^ rotateRight(state[0], 22);
        const maj = (state[0] & state[1]) ^ (state[0] & state[2]) ^ (state[1] & state[2]);
        const temp2 = (s0 + maj) >>> 0;
        shiftSha256State(state, temp1, temp2);
    }
    return state;
}

function shiftSha256State(state: number[], temp1: number, temp2: number): void {
    state[7] = state[6];
    state[6] = state[5];
    state[5] = state[4];
    state[4] = (state[3] + temp1) >>> 0;
    state[3] = state[2];
    state[2] = state[1];
    state[1] = state[0];
    state[0] = (temp1 + temp2) >>> 0;
}

function sha256WordsToHex(words: number[]): string {
    let out = "";
    for (let i = 0; i < words.length; i++) {
        out += words[i].toString(16).padStart(8, "0");
    }
    return out;
}

function rotateRight(value: number, bits: number): number {
    return (value >>> bits) | (value << (32 - bits));
}

function readUint32Be(bytes: Uint8Array, offset: number): number {
    return (
        (bytes[offset] << 24) |
        (bytes[offset + 1] << 16) |
        (bytes[offset + 2] << 8) |
        bytes[offset + 3]
    ) >>> 0;
}

function writeUint32Be(bytes: Uint8Array, offset: number, value: number): void {
    bytes[offset] = (value >>> 24) & 0xff;
    bytes[offset + 1] = (value >>> 16) & 0xff;
    bytes[offset + 2] = (value >>> 8) & 0xff;
    bytes[offset + 3] = value & 0xff;
}

function buildReadme(manifest: StepGroupExportManifest): string {
    return [
        "Marco Step Group Bundle",
        "=======================",
        "",
        `Bundle:        ${manifest.BundleName}`,
        `Generated:     ${manifest.GeneratedAt}`,
        `Project:       ${manifest.Project.Name} (#${manifest.Project.ProjectId})`,
        `Step groups:   ${manifest.Counts.StepGroups}`,
        `Steps:         ${manifest.Counts.Steps}`,
        `RunGroup refs: ${manifest.Counts.RunGroupRefs}`,
        `DB filename:   ${manifest.DbFileName} (${manifest.DbByteLength} bytes)`,
        `DB SHA-256:    ${manifest.DbSha256}`,
        "",
        "Open `step-groups.db` with any SQLite client, or import via",
        "the Marco extension's Step Group Library panel.",
        "",
    ].join("\n");
}

/* ------------------------------------------------------------------ */
/*  Top-level entrypoint                                               */
/* ------------------------------------------------------------------ */

/**
 * Resolve the selection, snapshot the DB, hash it, and package the
 * three files into a ZIP. Returns either a complete success payload
 * (bytes ready to download) or a structured failure.
 */
export async function runStepGroupExport(
    init: RunStepGroupExportInit,
): Promise<StepGroupExportResult> {
    const nowIso = init.NowIso ?? (() => new Date().toISOString());

    const resolved = resolveSelection(
        init.Source,
        init.ProjectId,
        init.SelectedStepGroupIds,
        init.IncludeDescendants ?? false,
    );
    if ("Reason" in resolved) return resolved;

    const snapshot = buildFilteredSnapshot(
        init.Source,
        init.SqlJs,
        init.ProjectId,
        resolved.Ids,
    );
    if ("Reason" in snapshot) return snapshot;

    const projectRow = init.Source.listProjects().find((p) => p.ProjectId === init.ProjectId);
    if (projectRow === undefined) {
        return {
            Reason: "ProjectNotFound",
            Detail: `ProjectId=${init.ProjectId} disappeared mid-export.`,
            OffendingIds: [init.ProjectId],
        };
    }

    const sha = await sha256Hex(snapshot.DbBytes);

    const manifest: StepGroupExportManifest = {
        FormatVersion: STEP_GROUP_BUNDLE_FORMAT_VERSION,
        GeneratedAt: nowIso(),
        BundleName: init.BundleName ?? `${projectRow.Name} step groups`,
        Project: {
            ProjectId: projectRow.ProjectId,
            ProjectExternalId: projectRow.ProjectExternalId,
            Name: projectRow.Name,
        },
        Selection: {
            SelectedStepGroupIds: [...init.SelectedStepGroupIds].sort((a, b) => a - b),
            IncludeDescendants: init.IncludeDescendants ?? false,
            EffectiveStepGroupIds: resolved.Ids,
        },
        Counts: snapshot.Counts,
        DbFileName: DB_FILE,
        DbByteLength: snapshot.DbBytes.length,
        DbSha256: sha,
    };

    const zip = new init.JsZip();
    zip.file(MANIFEST_FILE, JSON.stringify(manifest, null, 2));
    zip.file(DB_FILE, snapshot.DbBytes);
    zip.file(README_FILE, buildReadme(manifest));

    let zipBytes: Uint8Array;
    try {
        zipBytes = await zip.generateAsync({
            type: "uint8array",
            compression: "DEFLATE",
            compressionOptions: { level: 6 },
        });
    } catch (err) {
        return {
            Reason: "InternalError",
            Detail: err instanceof Error ? err.message : "JSZip.generateAsync failed",
            OffendingIds: [],
        };
    }

    const safeName = projectRow.Name.replace(/[^a-z0-9._-]+/gi, "-").replace(/^-+|-+$/g, "")
        || `project-${projectRow.ProjectId}`;
    const stamp = manifest.GeneratedAt.replace(/[:.]/g, "-");
    const zipFileName = `step-groups-${safeName}-${stamp}.zip`;

    return {
        Reason: "Ok",
        ZipBytes: zipBytes,
        ZipFileName: zipFileName,
        Manifest: manifest,
    };
}

/**
 * Marco Extension — Hotkey Step Executor
 *
 * AutoHotkey-style chord macro replayer for `StepKindId.Hotkey`. Each
 * payload contains an ordered list of chords (e.g. `"Ctrl+S"`,
 * `"Tab"`, `"Enter"`) plus an optional `WaitMs` to pause after the
 * final chord.
 *
 * The replayer dispatches synthetic `KeyboardEvent`s on the document
 * (or a target element when `Selector` is given) — keydown then keyup
 * for each chord, with modifiers held for the duration of the keydown.
 *
 * Pure function over the parsed payload — DOM dispatch is wrapped so
 * tests can substitute a recorder.
 *
 * @see ./schema.ts                 — StepKindId.Hotkey definition
 * @see ../recorder-store.ts        — Hotkey step capture
 */

export interface HotkeyPayload {
    /** Ordered list of chord strings, e.g. ["Ctrl+S", "Tab", "Enter"]. */
    readonly Keys: readonly string[];
    /** Optional pause (ms) after the final chord. Default 0. */
    readonly WaitMs?: number;
    /** Optional CSS selector to focus before dispatch. */
    readonly Selector?: string;
}

export interface ParsedChord {
    readonly Key: string;
    readonly Code: string;
    readonly CtrlKey: boolean;
    readonly AltKey: boolean;
    readonly ShiftKey: boolean;
    readonly MetaKey: boolean;
}

const MODIFIERS = new Set(["ctrl", "control", "alt", "shift", "meta", "cmd", "command", "super", "win"]);

/** Parse a chord string ("Ctrl+Shift+S") into its keyboard-event parts. */
export function parseChord(chord: string): ParsedChord {
    const trimmed = chord.trim();
    if (trimmed === "") {
        throw new Error(`parseChord: empty chord string`);
    }
    const parts = trimmed.split("+").map((p) => p.trim()).filter((p) => p !== "");
    let ctrl = false;
    let alt = false;
    let shift = false;
    let meta = false;
    let key: string | null = null;
    for (const p of parts) {
        const low = p.toLowerCase();
        if (low === "ctrl" || low === "control") { ctrl = true; continue; }
        if (low === "alt") { alt = true; continue; }
        if (low === "shift") { shift = true; continue; }
        if (low === "meta" || low === "cmd" || low === "command" || low === "super" || low === "win") { meta = true; continue; }
        if (MODIFIERS.has(low)) { continue; }
        if (key !== null) {
            throw new Error(`parseChord: chord "${chord}" has multiple non-modifier keys ("${key}" and "${p}")`);
        }
        key = p;
    }
    if (key === null) {
        throw new Error(`parseChord: chord "${chord}" has no non-modifier key`);
    }
    return {
        Key: key.length === 1 ? key : key,
        Code: keyToCode(key),
        CtrlKey: ctrl,
        AltKey: alt,
        ShiftKey: shift,
        MetaKey: meta,
    };
}

function keyToCode(key: string): string {
    if (key.length === 1) {
        const upper = key.toUpperCase();
        if (upper >= "A" && upper <= "Z") return `Key${upper}`;
        if (upper >= "0" && upper <= "9") return `Digit${upper}`;
    }
    const map: Record<string, string> = {
        Enter: "Enter", Tab: "Tab", Escape: "Escape", Esc: "Escape",
        Space: "Space", Backspace: "Backspace", Delete: "Delete",
        ArrowUp: "ArrowUp", ArrowDown: "ArrowDown", ArrowLeft: "ArrowLeft", ArrowRight: "ArrowRight",
        Up: "ArrowUp", Down: "ArrowDown", Left: "ArrowLeft", Right: "ArrowRight",
        Home: "Home", End: "End", PageUp: "PageUp", PageDown: "PageDown",
    };
    return map[key] ?? key;
}

/** Validate + normalise a payload. Throws with a precise reason on failure. */
export function parseHotkeyPayload(json: string | null): HotkeyPayload {
    if (json === null || json.trim() === "") {
        throw new Error("Hotkey step has empty PayloadJson — expected { Keys: [...] }");
    }
    let raw: unknown;
    try { raw = JSON.parse(json); } catch (err) {
        throw new Error(`Hotkey step has invalid PayloadJson: ${(err as Error).message}`);
    }
    if (typeof raw !== "object" || raw === null) {
        throw new Error("Hotkey PayloadJson must be a JSON object");
    }
    const obj = raw as Record<string, unknown>;
    const keys = obj.Keys;
    if (!Array.isArray(keys) || keys.length === 0) {
        throw new Error("Hotkey PayloadJson.Keys must be a non-empty array of chord strings");
    }
    for (const k of keys) {
        if (typeof k !== "string") {
            throw new Error(`Hotkey PayloadJson.Keys entries must be strings, got ${typeof k}`);
        }
    }
    const waitMs = obj.WaitMs;
    if (waitMs !== undefined && (typeof waitMs !== "number" || !Number.isFinite(waitMs) || waitMs < 0)) {
        throw new Error("Hotkey PayloadJson.WaitMs must be a non-negative number when present");
    }
    const selector = obj.Selector;
    if (selector !== undefined && typeof selector !== "string") {
        throw new Error("Hotkey PayloadJson.Selector must be a string when present");
    }
    return {
        Keys: keys as readonly string[],
        WaitMs: typeof waitMs === "number" ? waitMs : undefined,
        Selector: typeof selector === "string" ? selector : undefined,
    };
}

/* ------------------------------------------------------------------ */
/*  DOM dispatch                                                       */
/* ------------------------------------------------------------------ */

export interface HotkeyDispatchEnv {
    readonly document: Pick<Document, "querySelector" | "dispatchEvent">;
    readonly setTimeout: (cb: () => void, ms: number) => ReturnType<typeof setTimeout>;
    readonly clearTimeout: (timerId: ReturnType<typeof setTimeout>) => void;
}

/** Dispatch one parsed chord as a keydown+keyup pair. */
export function dispatchChord(env: HotkeyDispatchEnv, chord: ParsedChord, target?: Element | null): void {
    const init: KeyboardEventInit = {
        key: chord.Key,
        code: chord.Code,
        ctrlKey: chord.CtrlKey,
        altKey: chord.AltKey,
        shiftKey: chord.ShiftKey,
        metaKey: chord.MetaKey,
        bubbles: true,
        cancelable: true,
    };
    const down = new KeyboardEvent("keydown", init);
    const up = new KeyboardEvent("keyup", init);
    const sink = target ?? (env.document as unknown as EventTarget);
    sink.dispatchEvent(down);
    sink.dispatchEvent(up);
}

function waitForHotkeyDelay(env: HotkeyDispatchEnv, ms: number): Promise<void> {
    return new Promise<void>((resolve) => {
        let timerId: ReturnType<typeof setTimeout> | null = null;
        const finish = (): void => {
            if (timerId !== null) {
                env.clearTimeout(timerId);
                timerId = null;
            }
            resolve();
        };
        timerId = env.setTimeout(finish, ms);
    });
}

/**
 * Execute a Hotkey step end-to-end. Each chord is dispatched with a
 * 16ms gap; the final WaitMs (default 0) gates the promise so the
 * replayer waits before continuing — this is what gives Hotkey its
 * AutoHotkey-style "send-then-wait" semantics.
 */
export async function executeHotkeyStep(
    payload: HotkeyPayload,
    env?: Partial<HotkeyDispatchEnv>,
): Promise<void> {
    const dispatchEnv: HotkeyDispatchEnv = {
        document: env?.document ?? (typeof document === "undefined" ? null as unknown as Document : document),
        setTimeout: env?.setTimeout ?? ((cb, ms) => setTimeout(cb, ms)),
        clearTimeout: env?.clearTimeout ?? ((timerId) => clearTimeout(timerId)),
    };
    if (dispatchEnv.document === null) {
        throw new Error("executeHotkeyStep: no document available — cannot dispatch keyboard events");
    }
    const target = payload.Selector !== undefined && payload.Selector !== ""
        ? dispatchEnv.document.querySelector(payload.Selector)
        : null;
    if (payload.Selector !== undefined && payload.Selector !== "" && target === null) {
        throw new Error(`Hotkey step: target selector "${payload.Selector}" did not match any element`);
    }
    for (let i = 0; i < payload.Keys.length; i++) {
        const chord = parseChord(payload.Keys[i]);
        dispatchChord(dispatchEnv, chord, target);
        if (i < payload.Keys.length - 1) {
            await waitForHotkeyDelay(dispatchEnv, 16);
        }
    }
    const wait = payload.WaitMs ?? 0;
    if (wait > 0) {
        await waitForHotkeyDelay(dispatchEnv, wait);
    }
}

/**
 * Marco Extension — Step Group Bundle Import
 *
 * Symmetric counterpart to `./export-bundle.ts`. Accepts the bytes of a
 * ZIP produced by `runStepGroupExport`, validates every layer, and
 * merges the contained `StepGroup` + `Step` rows into a destination
 * `StepLibraryDb` under a caller-chosen project.
 *
 * Pure module — no chrome.*, no DOM, no file-system. The caller
 * supplies the ZIP bytes (typically read from an `<input type="file">`
 * via `arrayBuffer()`).
 *
 * Failure handling: this module never throws after `runStepGroupImport`
 * returns; every reachable failure surfaces as a structured
 * `ImportFailure` per mem://standards/verbose-logging-and-failure-diagnostics.
 *
 * Atomicity: all writes happen inside a single `BEGIN`/`COMMIT` on the
 * destination DB. A failure mid-merge rolls back, leaving the
 * destination identical to its pre-import state.
 *
 * @see ./export-bundle.ts
 * @see spec/31-macro-recorder/16-step-group-library.md  §8.4 (import)
 * @see mem://standards/verbose-logging-and-failure-diagnostics
 */

import type { Database, SqlJsStatic } from "sql.js";
import type JSZipType from "jszip";

import { applySchema, StepKindId } from "./schema";
import {
    StepLibraryDb,
    type StepGroupRow,
    type StepRow,
} from "./db";
import {
    sha256Hex,
    STEP_GROUP_BUNDLE_FORMAT_VERSION,
    type StepGroupExportManifest,
} from "./export-bundle";

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export type ConflictPolicy = "Skip" | "Rename" | "Fail";

export interface RunStepGroupImportInit {
    /** Raw ZIP bytes (e.g. from `await file.arrayBuffer()` then `new Uint8Array(buf)`). */
    readonly ZipBytes: Uint8Array;
    /** Destination DB to merge into. */
    readonly Destination: StepLibraryDb;
    /** Project that will own every imported group. */
    readonly DestinationProjectId: number;
    /**
     * Where to attach the imported tree's roots:
     *   - `null` (default) → at the top level of the destination project,
     *   - a `StepGroupId` → all imported roots become children of it.
     * The given parent MUST belong to `DestinationProjectId`.
     */
    readonly AttachUnderStepGroupId?: number | null;
    /** What to do when an imported root collides with an existing sibling name. */
    readonly OnNameConflict?: ConflictPolicy;
    /** sql.js factory — typically the lazily-initialised singleton. */
    readonly SqlJs: SqlJsStatic;
    /** JSZip constructor — passed in so this module stays tree-shakeable. */
    readonly JsZip: typeof JSZipType;
}

export type ImportReason =
    | "Ok"
    | "BundleNotZip"
    | "ManifestMissing"
    | "ManifestMalformed"
    | "ManifestVersionUnsupported"
    | "DbFileMissing"
    | "DbChecksumMismatch"
    | "DbSchemaIncompatible"
    | "DbCorrupt"
    | "DestinationProjectMissing"
    | "AttachParentMissing"
    | "AttachParentWrongProject"
    | "NameConflict"
    | "RunGroupTargetMissing"
    | "InternalError";

export interface ImportFailure {
    readonly Reason: Exclude<ImportReason, "Ok">;
    readonly Detail: string;
    readonly OffendingNames?: ReadonlyArray<string>;
    readonly OffendingIds?: ReadonlyArray<number>;
}

export interface ImportSummary {
    readonly Reason: "Ok";
    readonly Manifest: StepGroupExportManifest;
    readonly DestinationProjectId: number;
    readonly AttachedUnderStepGroupId: number | null;
    readonly RootStepGroupIds: ReadonlyArray<number>;
    readonly IdMap: ReadonlyArray<{ readonly OldId: number; readonly NewId: number }>;
    readonly RenamedRoots: ReadonlyArray<{ readonly OldName: string; readonly NewName: string }>;
    readonly Counts: { readonly StepGroups: number; readonly Steps: number; readonly RunGroupRefs: number };
}

export type StepGroupImportResult = ImportSummary | ImportFailure;

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const MANIFEST_FILE = "manifest.json";
const RENAME_MAX_ATTEMPTS = 256;

/* ------------------------------------------------------------------ */
/*  ZIP unpacking + validation                                         */
/* ------------------------------------------------------------------ */

interface UnpackedBundle {
    readonly Manifest: StepGroupExportManifest;
    readonly DbBytes: Uint8Array;
}

async function unpackBundle(
    zipBytes: Uint8Array,
    jsZip: typeof JSZipType,
): Promise<UnpackedBundle | ImportFailure> {
    let zip: JSZipType;
    try {
        zip = await jsZip.loadAsync(zipBytes);
    } catch (err) {
        return {
            Reason: "BundleNotZip",
            Detail: err instanceof Error ? err.message : "JSZip.loadAsync rejected the bundle",
        };
    }

    const manifestEntry = zip.file(MANIFEST_FILE);
    if (manifestEntry === null) {
        return {
            Reason: "ManifestMissing",
            Detail: `Bundle has no ${MANIFEST_FILE}.`,
        };
    }
    let manifestText: string;
    try {
        manifestText = await manifestEntry.async("string");
    } catch (err) {
        return {
            Reason: "ManifestMalformed",
            Detail: err instanceof Error ? err.message : "manifest.json could not be decoded",
        };
    }
    let manifest: StepGroupExportManifest;
    try {
        manifest = JSON.parse(manifestText) as StepGroupExportManifest;
    } catch (err) {
        return {
            Reason: "ManifestMalformed",
            Detail: err instanceof Error ? err.message : "manifest.json is not valid JSON",
        };
    }

    const validation = validateManifestShape(manifest);
    if (validation !== null) return validation;

    if (manifest.FormatVersion > STEP_GROUP_BUNDLE_FORMAT_VERSION) {
        return {
            Reason: "ManifestVersionUnsupported",
            Detail:
                `Bundle FormatVersion=${manifest.FormatVersion} is newer than this build supports ` +
                `(${STEP_GROUP_BUNDLE_FORMAT_VERSION}). Please update the extension.`,
        };
    }

    const dbEntry = zip.file(manifest.DbFileName);
    if (dbEntry === null) {
        return {
            Reason: "DbFileMissing",
            Detail: `Bundle declares DbFileName="${manifest.DbFileName}" but the file is absent from the ZIP.`,
        };
    }
    let dbBytes: Uint8Array;
    try {
        dbBytes = await dbEntry.async("uint8array");
    } catch (err) {
        return {
            Reason: "DbCorrupt",
            Detail: err instanceof Error ? err.message : "embedded DB could not be decoded",
        };
    }
    if (dbBytes.length !== manifest.DbByteLength) {
        return {
            Reason: "DbChecksumMismatch",
            Detail:
                `Embedded DB is ${dbBytes.length} bytes but manifest claims ${manifest.DbByteLength}. ` +
                "Bundle was tampered with or truncated.",
        };
    }
    const observedSha = await sha256Hex(dbBytes);
    if (observedSha !== manifest.DbSha256) {
        return {
            Reason: "DbChecksumMismatch",
            Detail:
                `Embedded DB SHA-256 ${observedSha} does not match manifest ${manifest.DbSha256}. ` +
                "Bundle was tampered with or truncated.",
        };
    }
    return { Manifest: manifest, DbBytes: dbBytes };
}

function validateManifestShape(m: unknown): ImportFailure | null {
    if (m === null || typeof m !== "object") {
        return { Reason: "ManifestMalformed", Detail: "manifest.json is not an object." };
    }
    const required: ReadonlyArray<keyof StepGroupExportManifest> = [
        "FormatVersion",
        "GeneratedAt",
        "BundleName",
        "Project",
        "Selection",
        "Counts",
        "DbFileName",
        "DbByteLength",
        "DbSha256",
    ];
    const obj = m as Record<string, unknown>;
    for (const k of required) {
        if (!(k in obj)) {
            return {
                Reason: "ManifestMalformed",
                Detail: `manifest.json missing required field "${String(k)}".`,
            };
        }
    }
    if (typeof obj.FormatVersion !== "number" || !Number.isInteger(obj.FormatVersion)) {
        return { Reason: "ManifestMalformed", Detail: "FormatVersion must be an integer." };
    }
    if (typeof obj.DbByteLength !== "number" || obj.DbByteLength < 0) {
        return { Reason: "ManifestMalformed", Detail: "DbByteLength must be a non-negative integer." };
    }
    if (typeof obj.DbSha256 !== "string" || !/^[0-9a-f]{64}$/.test(obj.DbSha256)) {
        return { Reason: "ManifestMalformed", Detail: "DbSha256 must be 64 lowercase hex chars." };
    }
    return null;
}

/* ------------------------------------------------------------------ */
/*  Conflict resolution                                                */
/* ------------------------------------------------------------------ */

function uniqueRenameFor(
    desired: string,
    existingLower: ReadonlySet<string>,
): string | null {
    if (!existingLower.has(desired.toLowerCase())) return desired;
    for (let n = 1; n <= RENAME_MAX_ATTEMPTS; n++) {
        const candidate = n === 1 ? `${desired} (imported)` : `${desired} (imported ${n})`;
        if (!existingLower.has(candidate.toLowerCase())) return candidate;
    }
    return null;
}

/* ------------------------------------------------------------------ */
/*  Source-DB readers (sql.js raw)                                     */
/* ------------------------------------------------------------------ */

function readGroupsFromSource(db: Database): StepGroupRow[] {
    const stmt = db.prepare(
        `SELECT StepGroupId, ProjectId, ParentStepGroupId, Name, Description,
                OrderIndex, IsArchived, CreatedAt, UpdatedAt
         FROM StepGroup
         ORDER BY ParentStepGroupId IS NULL DESC, ParentStepGroupId ASC,
                  OrderIndex ASC, StepGroupId ASC;`,
    );
    try {
        const rows: StepGroupRow[] = [];
        while (stmt.step()) {
            const r = stmt.getAsObject() as unknown as StepGroupRow;
            rows.push({ ...r, IsArchived: Boolean(r.IsArchived) });
        }
        return rows;
    } finally {
        stmt.free();
    }
}

function readStepsForGroup(db: Database, stepGroupId: number): StepRow[] {
    const stmt = db.prepare(
        `SELECT StepId, StepGroupId, OrderIndex, StepKindId, Label,
                PayloadJson, TargetStepGroupId, IsDisabled, CreatedAt, UpdatedAt
         FROM Step
         WHERE StepGroupId = ?
         ORDER BY OrderIndex ASC, StepId ASC;`,
    );
    try {
        stmt.bind([stepGroupId]);
        const rows: StepRow[] = [];
        while (stmt.step()) {
            const r = stmt.getAsObject() as unknown as StepRow;
            rows.push({ ...r, IsDisabled: Boolean(r.IsDisabled) });
        }
        return rows;
    } finally {
        stmt.free();
    }
}

/* ------------------------------------------------------------------ */
/*  Topological order (parents before children)                        */
/* ------------------------------------------------------------------ */

function orderByAncestry(rows: ReadonlyArray<StepGroupRow>): StepGroupRow[] {
    const ids = new Set(rows.map((r) => r.StepGroupId));
    const remaining = new Map(rows.map((r) => [r.StepGroupId, r]));
    const out: StepGroupRow[] = [];
    const placed = new Set<number>();
    while (remaining.size > 0) {
        let progressed = false;
        for (const [id, r] of remaining) {
            const parent = r.ParentStepGroupId;
            const parentReady =
                parent === null || !ids.has(parent) || placed.has(parent);
            if (parentReady) {
                out.push(r);
                placed.add(id);
                remaining.delete(id);
                progressed = true;
                break;
            }
        }
        if (!progressed) {
            for (const r of remaining.values()) out.push(r);
            break;
        }
    }
    return out;
}

/* ------------------------------------------------------------------ */
/*  Top-level entrypoint                                               */
/* ------------------------------------------------------------------ */

export async function runStepGroupImport(
    init: RunStepGroupImportInit,
): Promise<StepGroupImportResult> {
    const conflict: ConflictPolicy = init.OnNameConflict ?? "Rename";
    const attachUnder = init.AttachUnderStepGroupId ?? null;

    /* --- Step 1: unzip + manifest + SHA verification --- */
    const unpacked = await unpackBundle(init.ZipBytes, init.JsZip);
    if ("Reason" in unpacked) return unpacked;
    const { Manifest: manifest, DbBytes: dbBytes } = unpacked;

    /* --- Step 2: open the source DB and apply schema (catches version/corrupt) --- */
    let sourceDb: Database;
    try {
        sourceDb = new init.SqlJs.Database(dbBytes);
    } catch (err) {
        return {
            Reason: "DbCorrupt",
            Detail: err instanceof Error ? err.message : "sql.js refused to open embedded DB",
        };
    }

    try {
        try {
            applySchema(sourceDb);
        } catch (err) {
            return {
                Reason: "DbSchemaIncompatible",
                Detail: err instanceof Error ? err.message : "applySchema rejected embedded DB",
            };
        }

        /* --- Step 3: validate destination project + attach parent --- */
        const destLib = init.Destination;
        const destProject = destLib.listProjects()
            .find((p) => p.ProjectId === init.DestinationProjectId);
        if (destProject === undefined) {
            return {
                Reason: "DestinationProjectMissing",
                Detail: `DestinationProjectId=${init.DestinationProjectId} not found in destination DB.`,
                OffendingIds: [init.DestinationProjectId],
            };
        }
        const destGroups = destLib.listGroups(init.DestinationProjectId);
        if (attachUnder !== null) {
            const parent = destGroups.find((g) => g.StepGroupId === attachUnder);
            if (parent === undefined) {
                return {
                    Reason: "AttachParentMissing",
                    Detail: `AttachUnderStepGroupId=${attachUnder} not found in destination project.`,
                    OffendingIds: [attachUnder],
                };
            }
            if (parent.ProjectId !== init.DestinationProjectId) {
                return {
                    Reason: "AttachParentWrongProject",
                    Detail: `AttachUnderStepGroupId=${attachUnder} belongs to a different project.`,
                    OffendingIds: [attachUnder],
                };
            }
        }

        /* --- Step 4: build the import plan against in-memory state --- */
        const sourceGroups = orderByAncestry(readGroupsFromSource(sourceDb));
        const sourceIdSet = new Set(sourceGroups.map((g) => g.StepGroupId));

        // Pre-flight RunGroup target check — every RunGroup step in the
        // bundle must point at a group that is also in the bundle.
        const allSourceSteps: StepRow[] = [];
        const dangling: number[] = [];
        let runGroupRefs = 0;
        for (const g of sourceGroups) {
            for (const s of readStepsForGroup(sourceDb, g.StepGroupId)) {
                allSourceSteps.push(s);
                if (s.StepKindId === StepKindId.RunGroup) {
                    runGroupRefs += 1;
                    if (s.TargetStepGroupId === null || !sourceIdSet.has(s.TargetStepGroupId)) {
                        dangling.push(s.StepId);
                    }
                }
            }
        }
        if (dangling.length > 0) {
            return {
                Reason: "RunGroupTargetMissing",
                Detail:
                    `Step(s) ${dangling.join(", ")} are RunGroup invocations whose target ` +
                    `is not present in the bundle. The bundle is corrupt.`,
                OffendingIds: dangling,
            };
        }

        // Resolve name conflicts for the import roots (groups whose
        // parent is null in the source OR whose parent is outside the
        // bundle — both will land under `attachUnder` in the
        // destination). We compare against the destination siblings of
        // `attachUnder` (case-insensitive).
        const destSiblingNamesLower = new Set(
            destGroups
                .filter((g) => (g.ParentStepGroupId ?? null) === attachUnder)
                .map((g) => g.Name.toLowerCase()),
        );
        const renamedRoots: Array<{ OldName: string; NewName: string }> = [];
        const effectiveName = new Map<number, string>();
        const collisions: string[] = [];
        for (const g of sourceGroups) {
            const isRoot =
                g.ParentStepGroupId === null || !sourceIdSet.has(g.ParentStepGroupId);
            if (!isRoot) continue;
            if (destSiblingNamesLower.has(g.Name.toLowerCase())) {
                if (conflict === "Fail") {
                    collisions.push(g.Name);
                    continue;
                }
                if (conflict === "Skip") {
                    // Mark the whole subtree as skipped via empty name.
                    effectiveName.set(g.StepGroupId, "");
                    continue;
                }
                const renamed = uniqueRenameFor(g.Name, destSiblingNamesLower);
                if (renamed === null) {
                    return {
                        Reason: "NameConflict",
                        Detail:
                            `Could not find a free rename slot for "${g.Name}" after ` +
                            `${RENAME_MAX_ATTEMPTS} attempts.`,
                        OffendingNames: [g.Name],
                    };
                }
                renamedRoots.push({ OldName: g.Name, NewName: renamed });
                destSiblingNamesLower.add(renamed.toLowerCase());
                effectiveName.set(g.StepGroupId, renamed);
            } else {
                effectiveName.set(g.StepGroupId, g.Name);
                destSiblingNamesLower.add(g.Name.toLowerCase());
            }
        }
        if (conflict === "Fail" && collisions.length > 0) {
            return {
                Reason: "NameConflict",
                Detail:
                    `OnNameConflict='Fail' and the following root group name(s) already exist ` +
                    `in the destination: ${collisions.join(", ")}.`,
                OffendingNames: collisions,
            };
        }

        // If Skip removed every root, surface that as a no-op success
        // rather than silently committing an empty transaction.
        const skippedRootIds = new Set<number>();
        for (const [id, name] of effectiveName) {
            if (name === "") skippedRootIds.add(id);
        }
        const skippedSubtree = collectSubtree(sourceGroups, skippedRootIds);

        /* --- Step 5: atomic merge --- */
        const idMap = new Map<number, number>();
        const rawDest = destLib.raw;
        rawDest.exec("BEGIN;");
        try {
            const importedGroups: number[] = [];
            const rootStepGroupIds: number[] = [];

            for (const g of sourceGroups) {
                if (skippedSubtree.has(g.StepGroupId)) continue;
                const isRoot =
                    g.ParentStepGroupId === null || !sourceIdSet.has(g.ParentStepGroupId);
                const newParent = isRoot
                    ? attachUnder
                    : (idMap.get(g.ParentStepGroupId as number) ?? null);
                const name = isRoot
                    ? (effectiveName.get(g.StepGroupId) ?? g.Name)
                    : g.Name;
                const newId = destLib.createGroup({
                    ProjectId: init.DestinationProjectId,
                    ParentStepGroupId: newParent,
                    Name: name,
                    Description: g.Description,
                    OrderIndex: g.OrderIndex,
                });
                idMap.set(g.StepGroupId, newId);
                importedGroups.push(newId);
                if (isRoot) rootStepGroupIds.push(newId);
            }

            // Insert steps in two passes: non-RunGroup first, then
            // RunGroup with rewritten TargetStepGroupId. This avoids
            // depending on insertion order of group IDs (the runtime
            // CHECK constraint requires a non-null target for
            // RunGroup steps, so we cannot defer FK validation).
            let stepCount = 0;
            const runGroupSteps: StepRow[] = [];
            for (const s of allSourceSteps) {
                const newGroupId = idMap.get(s.StepGroupId);
                if (newGroupId === undefined) continue; // skipped subtree
                if (s.StepKindId === StepKindId.RunGroup) {
                    runGroupSteps.push(s);
                    continue;
                }
                destLib.appendStep({
                    StepGroupId: newGroupId,
                    StepKindId: s.StepKindId,
                    Label: s.Label,
                    PayloadJson: s.PayloadJson,
                });
                stepCount += 1;
            }
            for (const s of runGroupSteps) {
                const newGroupId = idMap.get(s.StepGroupId);
                if (newGroupId === undefined) continue;
                const oldTarget = s.TargetStepGroupId;
                const newTarget = oldTarget === null ? null : (idMap.get(oldTarget) ?? null);
                if (newTarget === null) {
                    // Target was in a skipped subtree → bail and roll back.
                    throw new Error(
                        `RunGroup StepId=${s.StepId} targets a group that was skipped due to ` +
                        `name conflict policy. Re-run with OnNameConflict='Rename' or 'Fail'.`,
                    );
                }
                destLib.appendStep({
                    StepGroupId: newGroupId,
                    StepKindId: StepKindId.RunGroup,
                    Label: s.Label,
                    TargetStepGroupId: newTarget,
                });
                stepCount += 1;
            }

            rawDest.exec("COMMIT;");

            return {
                Reason: "Ok",
                Manifest: manifest,
                DestinationProjectId: init.DestinationProjectId,
                AttachedUnderStepGroupId: attachUnder,
                RootStepGroupIds: rootStepGroupIds,
                IdMap: Array.from(idMap.entries()).map(([OldId, NewId]) => ({ OldId, NewId })),
                RenamedRoots: renamedRoots,
                Counts: {
                    StepGroups: importedGroups.length,
                    Steps: stepCount,
                    RunGroupRefs: runGroupRefs,
                },
            };
        } catch (err) {
            try {
                rawDest.exec("ROLLBACK;");
            } catch { // allow-swallow: ROLLBACK after merge failure — original err is returned; rollback failure is secondary.
                /* ignore — rollback failure is secondary to the original error */
            }
            return {
                Reason: "InternalError",
                Detail: err instanceof Error ? err.message : "merge transaction failed",
            };
        }
    } finally {
        sourceDb.close();
    }
}

function collectSubtree(
    rows: ReadonlyArray<StepGroupRow>,
    rootIds: ReadonlySet<number>,
): Set<number> {
    if (rootIds.size === 0) return new Set();
    const out = new Set<number>(rootIds);
    let changed = true;
    while (changed) {
        changed = false;
        for (const r of rows) {
            if (r.ParentStepGroupId !== null && out.has(r.ParentStepGroupId) && !out.has(r.StepGroupId)) {
                out.add(r.StepGroupId);
                changed = true;
            }
        }
    }
    return out;
}

/**
 * Marco Extension — Run-Time Input Source
 *
 * Project-wide HTTP endpoint that supplies a fresh JSON input bag at
 * the start of every batch run. The fetched bag is MERGED on top of
 * each group's locally persisted bag (endpoint wins on key collision)
 * before the runner expands `{{Placeholder}}` tokens in step payloads.
 *
 * Design highlights (see .lovable/question-and-ambiguity/06-run-time-input-source.md
 * for the full rationale):
 *   - Single global config persisted to localStorage
 *     (`marco.input-source.config.v1`).
 *   - GET (default) or POST with optional JSON body.
 *   - Free-form headers map (handles bearer tokens, custom auth, etc.).
 *   - Failure is configurable: `Abort` halts the batch BEFORE the
 *     first group runs; `ContinueWithLocal` swallows the failure and
 *     uses just the persisted bag.
 *   - Response MUST be a JSON object — same validation as
 *     `parseGroupInputJson` so the manual paste/upload and the live
 *     fetch enforce the same contract.
 *
 * NOT in scope (deliberately deferred — see ambiguity log):
 *   - Per-group endpoint overrides.
 *   - Recorder start-recording hook (lives in a different module).
 *   - Persistent retry / offline queue.
 *
 * @see ./group-inputs.ts        — sibling localStorage convention, JsonValue tree, GroupInputBag.
 * @see ./result-webhook.ts      — sibling endpoint module this mirrors.
 */

import type {
    GroupInputBag,
    JsonObject,
    JsonValue,
} from "./group-inputs";

const STORAGE_KEY = "marco.input-source.config.v1";
const DEFAULT_TIMEOUT_MS = 8_000;

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export type InputSourceMethod = "GET" | "POST";

export type InputSourceFailurePolicy =
    | "Abort"               // halt the batch — receiver must be reachable.
    | "ContinueWithLocal";  // swallow the failure, use only persisted bags.

/** A single header pair (preserved order so the dialog round-trips cleanly). */
export interface InputSourceHeader {
    readonly Name: string;
    readonly Value: string;
}

export interface InputSourceConfig {
    /** When `false`, fetchInputSource is a no-op even if URL is set. */
    readonly Enabled: boolean;
    readonly Url: string;
    readonly Method: InputSourceMethod;
    readonly Headers: ReadonlyArray<InputSourceHeader>;
    /** Raw JSON body for POST. Empty string sends no body. */
    readonly RequestBody: string;
    readonly OnFailure: InputSourceFailurePolicy;
    /** Request timeout in ms. Clamped to 1 000–60 000. */
    readonly TimeoutMs: number;
}

export const DEFAULT_INPUT_SOURCE_CONFIG: InputSourceConfig = Object.freeze({
    Enabled: false,
    Url: "",
    Method: "GET",
    Headers: [],
    RequestBody: "",
    OnFailure: "Abort",
    TimeoutMs: DEFAULT_TIMEOUT_MS,
});

/** Outcome of a single fetch attempt. */
export type FetchInputResult =
    | {
        readonly Ok: true;
        readonly Skipped: false;
        readonly Bag: GroupInputBag;
        readonly Status: number;
        readonly DurationMs: number;
        readonly Url: string;
    }
    | {
        readonly Ok: true;
        readonly Skipped: true;
        readonly SkipReason: string;
        readonly Bag: null;
    }
    | {
        readonly Ok: false;
        readonly Skipped: false;
        readonly Error: string;
        readonly Status: number | null;
        readonly DurationMs: number;
        readonly Url: string;
        /** When `OnFailure === "ContinueWithLocal"`, this is `true`
         *  so callers know the run should continue with empty merge. */
        readonly Continue: boolean;
    };

/* ------------------------------------------------------------------ */
/*  Storage                                                            */
/* ------------------------------------------------------------------ */

interface StoredShape {
    readonly Enabled?: unknown;
    readonly Url?: unknown;
    readonly Method?: unknown;
    readonly Headers?: unknown;
    readonly RequestBody?: unknown;
    readonly OnFailure?: unknown;
    readonly TimeoutMs?: unknown;
}

function isPlainObject(v: unknown): v is Record<string, unknown> {
    return typeof v === "object" && v !== null && !Array.isArray(v);
}

function sanitiseHeaders(raw: unknown): InputSourceHeader[] {
    if (!Array.isArray(raw)) return [];
    const out: InputSourceHeader[] = [];
    for (const entry of raw) {
        if (!isPlainObject(entry)) continue;
        const name = typeof entry.Name === "string" ? entry.Name.trim() : "";
        const value = typeof entry.Value === "string" ? entry.Value : "";
        if (name.length === 0) continue;
        out.push({ Name: name, Value: value });
    }
    return out;
}

function sanitiseMethod(raw: unknown): InputSourceMethod {
    return raw === "POST" ? "POST" : "GET";
}

function sanitiseFailurePolicy(raw: unknown): InputSourceFailurePolicy {
    return raw === "ContinueWithLocal" ? "ContinueWithLocal" : "Abort";
}

function clampTimeout(raw: unknown): number {
    const n = typeof raw === "number" && Number.isFinite(raw) ? raw : DEFAULT_TIMEOUT_MS;
    return Math.min(60_000, Math.max(1_000, Math.round(n)));
}

export function loadInputSourceConfig(): InputSourceConfig {
    if (typeof localStorage === "undefined") return DEFAULT_INPUT_SOURCE_CONFIG;
    try {
        const raw = localStorage.getItem(STORAGE_KEY);
        if (raw === null) return DEFAULT_INPUT_SOURCE_CONFIG;
        const parsed = JSON.parse(raw) as StoredShape;
        if (!isPlainObject(parsed)) return DEFAULT_INPUT_SOURCE_CONFIG;
        return {
            Enabled: parsed.Enabled === true,
            Url: typeof parsed.Url === "string" ? parsed.Url : "",
            Method: sanitiseMethod(parsed.Method),
            Headers: sanitiseHeaders(parsed.Headers),
            RequestBody: typeof parsed.RequestBody === "string" ? parsed.RequestBody : "",
            OnFailure: sanitiseFailurePolicy(parsed.OnFailure),
            TimeoutMs: clampTimeout(parsed.TimeoutMs),
        };
    } catch {
        return DEFAULT_INPUT_SOURCE_CONFIG;
    }
}

export function saveInputSourceConfig(config: InputSourceConfig): InputSourceConfig {
    const normalised: InputSourceConfig = {
        Enabled: config.Enabled === true,
        Url: typeof config.Url === "string" ? config.Url.trim() : "",
        Method: sanitiseMethod(config.Method),
        Headers: sanitiseHeaders(config.Headers),
        RequestBody: typeof config.RequestBody === "string" ? config.RequestBody : "",
        OnFailure: sanitiseFailurePolicy(config.OnFailure),
        TimeoutMs: clampTimeout(config.TimeoutMs),
    };
    if (typeof localStorage !== "undefined") {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(normalised));
    }
    return normalised;
}

export function clearInputSourceConfig(): void {
    if (typeof localStorage !== "undefined") {
        localStorage.removeItem(STORAGE_KEY);
    }
}

/* ------------------------------------------------------------------ */
/*  Merge helper                                                       */
/* ------------------------------------------------------------------ */

/**
 * Shallow-merge: `incoming` keys overwrite `local` keys.
 * Both inputs are treated as immutable; a new object is always returned.
 * `null` on either side is treated as "no bag".
 */
export function mergeInputBags(
    local: GroupInputBag | null,
    incoming: GroupInputBag | null,
): GroupInputBag {
    const out: Record<string, JsonValue> = {};
    if (local !== null) {
        for (const [k, v] of Object.entries(local)) out[k] = v;
    }
    if (incoming !== null) {
        for (const [k, v] of Object.entries(incoming)) out[k] = v;
    }
    return out;
}

/* ------------------------------------------------------------------ */
/*  Fetch                                                              */
/* ------------------------------------------------------------------ */

/** Optional dependency injection for tests — defaults to global fetch. */
export interface FetchInputDeps {
    readonly fetchImpl?: typeof fetch;
    readonly config?: InputSourceConfig;
}

function buildSkipResult(reason: string): FetchInputResult {
    return { Ok: true, Skipped: true, SkipReason: reason, Bag: null };
}

function buildErrorResult(args: {
    readonly url: string;
    readonly status: number | null;
    readonly error: string;
    readonly durationMs: number;
    readonly continueOnFail: boolean;
}): FetchInputResult {
    return {
        Ok: false,
        Skipped: false,
        Error: args.error,
        Status: args.status,
        DurationMs: args.durationMs,
        Url: args.url,
        Continue: args.continueOnFail,
    };
}

function parseResponseBag(
    raw: string,
): { readonly Ok: true; readonly Bag: GroupInputBag } | { readonly Ok: false; readonly Reason: string } {
    let parsed: JsonValue;
    try {
        parsed = JSON.parse(raw) as JsonValue;
    } catch (e) {
        const detail = e instanceof Error ? e.message : "Unknown parse error";
        return { Ok: false, Reason: `Response was not valid JSON: ${detail}` };
    }
    if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) {
        return {
            Ok: false,
            Reason: `Expected a JSON object at the top level (e.g. { "Email": "you@example.com" }).`,
        };
    }
    return { Ok: true, Bag: parsed as GroupInputBag };
}

/**
 * Fetch the configured input bag. Always resolves — never throws.
 * The caller decides what to do based on `Ok` + `Continue` + `OnFailure`.
 */
export async function fetchInputSource(
    deps: FetchInputDeps = {},
): Promise<FetchInputResult> {
    const config = deps.config ?? loadInputSourceConfig();
    if (!config.Enabled) return buildSkipResult("Input source disabled");
    if (config.Url.trim().length === 0) return buildSkipResult("No URL configured");

    const fetchImpl = deps.fetchImpl ?? (typeof fetch === "function" ? fetch : null);
    const continueOnFail = config.OnFailure === "ContinueWithLocal";
    if (fetchImpl === null) {
        return buildErrorResult({
            url: config.Url,
            status: null,
            error: "fetch is not available in this environment",
            durationMs: 0,
            continueOnFail,
        });
    }

    const headers: Record<string, string> = {};
    for (const h of config.Headers) headers[h.Name] = h.Value;

    let body: string | undefined;
    if (config.Method === "POST" && config.RequestBody.trim().length > 0) {
        body = config.RequestBody;
        if (!Object.prototype.hasOwnProperty.call(headers, "Content-Type")) {
            headers["Content-Type"] = "application/json";
        }
    }

    const controller = typeof AbortController === "function" ? new AbortController() : null;
    const timer = controller === null ? null : setTimeout(
        () => { controller.abort(); },
        config.TimeoutMs,
    );
    const startedAt = Date.now();
    try {
        const res = await fetchImpl(config.Url, {
            method: config.Method,
            headers,
            body,
            signal: controller?.signal,
        });
        const text = await res.text();
        const durationMs = Date.now() - startedAt;
        if (!res.ok) {
            return buildErrorResult({
                url: config.Url,
                status: res.status,
                error: `HTTP ${res.status} ${res.statusText}`,
                durationMs,
                continueOnFail,
            });
        }
        const parsed = parseResponseBag(text);
        if (!parsed.Ok) {
            return buildErrorResult({
                url: config.Url,
                status: res.status,
                error: parsed.Reason,
                durationMs,
                continueOnFail,
            });
        }
        return {
            Ok: true,
            Skipped: false,
            Bag: parsed.Bag,
            Status: res.status,
            DurationMs: durationMs,
            Url: config.Url,
        };
    } catch (e) {
        const message = e instanceof Error ? e.message : String(e);
        const isAbort = e instanceof Error && e.name === "AbortError";
        return buildErrorResult({
            url: config.Url,
            status: null,
            error: isAbort ? `Request timed out after ${config.TimeoutMs} ms` : message,
            durationMs: Date.now() - startedAt,
            continueOnFail,
        });
    } finally {
        if (timer !== null) clearTimeout(timer);
    }
}

/* ------------------------------------------------------------------ */
/*  Snapshot — captured once per batch and shared across groups        */
/* ------------------------------------------------------------------ */

export interface InputSourceSnapshot {
    /** Bag fetched from the endpoint, or `null` if no fetch happened. */
    readonly Bag: GroupInputBag | null;
    /** Raw fetch result for diagnostics / UI. */
    readonly Result: FetchInputResult;
}

/**
 * Resolve the per-batch snapshot. Returns one of three states:
 *
 *   - `Bag !== null` — endpoint succeeded; merge into each group's bag.
 *   - `Bag === null` and `Result.Skipped` — feature off, run as today.
 *   - `Bag === null` and `Result.Ok === false` — fetch failed; the
 *     caller checks `Result.Continue` to decide abort vs continue.
 */
export async function resolveBatchInputSnapshot(
    deps: FetchInputDeps = {},
): Promise<InputSourceSnapshot> {
    const result = await fetchInputSource(deps);
    if (result.Ok && !result.Skipped) {
        return { Bag: result.Bag, Result: result };
    }
    return { Bag: null, Result: result };
}

/**
 * Marco Extension — Step Library → Live Replay Bridge
 *
 * Adapter that lets the pure `runGroup()` runner drive the existing
 * `executeReplay()` live-DOM actuator. The runner is decoupled from
 * the DOM: it walks the StepGroup tree and delegates leaf execution
 * to a caller-supplied `LeafStepExecutor`. Until now the only
 * executor wired into the UI was the **preview executor** (a stub
 * that always reports success — see `RunGroupDialog` /
 * `BatchRunDialog`). That meant RunGroup steps could be authored,
 * imported, and exported, but they couldn't actually click / type
 * anything during real macro playback.
 *
 * This module closes that gap by translating each `StepRow` into the
 * `ReplayStepInput` shape `executeReplay()` already understands, and
 * surfaces the resulting `FailureReport` back to the runner.
 *
 * What it does NOT do:
 *   - It never touches `chrome.*` APIs. The Document the executor
 *     dispatches against is supplied by the caller (Options-page
 *     preview, content-script playback, or unit tests).
 *   - It does NOT persist a `ReplayRun` row. The runner already
 *     produces a structured `Trace` and the calling UI persists its
 *     own results (`replay-run-persistence` is the legacy single-step
 *     flow). Wiring the trace into that table is a separate concern.
 *
 * Payload contract:
 *   The step-library DB stores leaf-step parameters as
 *   `Step.PayloadJson` — a JSON object with the shape
 *   `{ Selector: string, Value?: string, WaitMs?: number }`. The
 *   bridge parses that, picks the StepKind-specific fields, and
 *   wraps the selector as a single `PersistedSelector` row so the
 *   replay actuator can reuse its existing CSS/XPath resolver.
 *
 * @see ./run-group-runner.ts          — Runner that calls the executor.
 * @see ../live-dom-replay.ts          — The actuator we're driving.
 * @see ../replay-resolver.ts          — Selector kind detection.
 * @see ../failure-logger.ts           — FailureReport contract.
 * @see spec/31-macro-recorder/16-step-group-library.md §6
 */

import {
    executeReplay,
    type ReplayOptions,
    type ReplayStepInput,
} from "../live-dom-replay";
import type { PersistedSelector } from "../step-persistence";
import { logFailure, type FailureReport } from "../failure-logger";
import type { FieldRow } from "../field-reference-resolver";
import { SelectorKindId } from "../../recorder-db-schema";
import type { StepRow } from "./db";
import type { LeafStepExecutor, LeafStepContext } from "./run-group-runner";
import { StepKindId } from "./schema";

const SOURCE_FILE = "src/background/recorder/step-library/replay-bridge.ts";

/* ------------------------------------------------------------------ */
/*  Public surface                                                     */
/* ------------------------------------------------------------------ */

export interface ReplayBridgeOptions {
    /** Live document the actuator dispatches events into. */
    readonly Doc: Document;
    /** Active row used to resolve `{{Column}}` templates in Type/Select values. */
    readonly Row?: FieldRow;
    /** Override sleep for tests. */
    readonly Sleep?: (ms: number) => Promise<void>;
    /** Override clock for tests. */
    readonly Now?: () => Date;
    /** Forwarded to `executeReplay` — see its docstring. */
    readonly Verbose?: boolean;
}

/**
 * Build a `LeafStepExecutor` that drives `executeReplay()` for each
 * leaf step the runner emits. RunGroup steps NEVER reach this
 * executor — the runner handles them itself before delegating.
 */
export function createLiveReplayExecutor(opts: ReplayBridgeOptions): LeafStepExecutor {
    return async (step: StepRow, _ctx: LeafStepContext): Promise<FailureReport | null> => {
        // Translation can fail synchronously when PayloadJson is
        // missing/malformed. Convert that into a FailureReport so the
        // runner reports it the same way as a DOM-level failure.
        let input: ReplayStepInput;
        try {
            input = stepRowToReplayInput(step);
        } catch (err) {
            return logFailure({
                Phase: "Replay",
                Error: err,
                StepId: step.StepId,
                Index: step.OrderIndex,
                StepKind: stepKindLabel(step.StepKindId),
                Selectors: [],
                SourceFile: SOURCE_FILE,
                Reason: "Unknown",
                ReasonDetail: `Step #${step.StepId} (kind=${stepKindLabel(step.StepKindId)}) `
                    + `could not be translated for live replay: `
                    + `${(err as Error).message}`,
                Verbose: opts.Verbose ?? false,
                Now: opts.Now,
            });
        }

        const replayOpts: ReplayOptions = {
            Doc: opts.Doc,
            Row: opts.Row,
            Sleep: opts.Sleep,
            Now: opts.Now,
            Verbose: opts.Verbose,
        };

        const outcome = await executeReplay([input], replayOpts);
        const result = outcome.Results[0];
        if (result === undefined) {
            // Defensive: executeReplay always returns 1 result per
            // input. If that contract ever breaks we fail loud.
            return logFailure({
                Phase: "Replay",
                Error: new Error("executeReplay returned no result"),
                StepId: step.StepId,
                Index: step.OrderIndex,
                StepKind: stepKindLabel(step.StepKindId),
                Selectors: [],
                SourceFile: SOURCE_FILE,
                Reason: "Unknown",
                ReasonDetail: `executeReplay produced an empty Results array for step #${step.StepId}.`,
                Verbose: opts.Verbose ?? false,
                Now: opts.Now,
            });
        }
        if (result.Ok) return null;
        // executeReplay always populates FailureReport on !Ok. Keep
        // the fallback so the executor contract (FailureReport | null)
        // never returns undefined.
        return result.FailureReport ?? logFailure({
            Phase: "Replay",
            Error: new Error(result.Error ?? "Unknown replay failure"),
            StepId: step.StepId,
            Index: step.OrderIndex,
            StepKind: stepKindLabel(step.StepKindId),
            Selectors: [],
            SourceFile: SOURCE_FILE,
            Reason: "Unknown",
            ReasonDetail: result.Error ?? `Step #${step.StepId} failed without a FailureReport.`,
            Verbose: opts.Verbose ?? false,
            Now: opts.Now,
        });
    };
}

/* ------------------------------------------------------------------ */
/*  StepRow → ReplayStepInput translation                              */
/* ------------------------------------------------------------------ */

interface StepPayload {
    readonly Selector?: string;
    readonly Value?: string;
    readonly WaitMs?: number;
}

/**
 * Public for tests. Maps a `StepRow` from the step-library DB to the
 * `ReplayStepInput` consumed by `executeReplay()`.
 *
 * Throws when:
 *   - The step kind has no replay equivalent (RunGroup is the
 *     runner's job; reaching this code with one is a contract bug).
 *   - PayloadJson is missing for a kind that needs a selector.
 *   - PayloadJson is not valid JSON.
 *
 * SelectorKindId mapping uses the same heuristic as
 * `replay-resolver.ts`: expressions that begin with `/` or `(` are
 * treated as XPath, everything else as CSS. The library schema does
 * NOT yet store a selector kind alongside the payload, so this
 * keeps inference in one place.
 */
export function stepRowToReplayInput(step: StepRow): ReplayStepInput {
    const payload = parsePayload(step);

    switch (step.StepKindId) {
        case StepKindId.Wait: {
            const ms = payload.WaitMs;
            if (typeof ms !== "number" || !Number.isFinite(ms) || ms < 0) {
                throw new Error(
                    `Wait step #${step.StepId} has invalid PayloadJson.WaitMs `
                    + `(${JSON.stringify(payload.WaitMs)}). Expected a non-negative number.`,
                );
            }
            return {
                StepId: step.StepId,
                Index: step.OrderIndex,
                Kind: "Wait",
                Selectors: [],
                WaitMs: ms,
            };
        }
        case StepKindId.Click: {
            return {
                StepId: step.StepId,
                Index: step.OrderIndex,
                Kind: "Click",
                Selectors: [requireSelector(step, payload)],
            };
        }
        case StepKindId.Type: {
            return {
                StepId: step.StepId,
                Index: step.OrderIndex,
                Kind: "Type",
                Selectors: [requireSelector(step, payload)],
                Value: payload.Value ?? "",
            };
        }
        case StepKindId.Select: {
            return {
                StepId: step.StepId,
                Index: step.OrderIndex,
                Kind: "Select",
                Selectors: [requireSelector(step, payload)],
                Value: payload.Value ?? "",
            };
        }
        case StepKindId.JsInline: {
            // JsInline is currently out of scope for the live actuator
            // (executeReplay only knows Click/Type/Select/Wait — see
            // mem://features/js-step-diagnostics for the dedicated
            // JS-step pipeline). Surface a precise reason rather than
            // silently no-op'ing so the trace shows "we declined" not
            // "we succeeded".
            throw new Error(
                `JsInline step #${step.StepId} is not yet supported by the live `
                + `replay bridge — JS steps run through buildJsStepFailureReport, `
                + `not executeReplay.`,
            );
        }
        case StepKindId.RunGroup: {
            // The runner intercepts RunGroup steps before invoking the
            // leaf executor. Reaching here means a caller bypassed the
            // runner — that's a programming error.
            throw new Error(
                `RunGroup step #${step.StepId} reached the leaf executor; `
                + `this should be handled by runGroup() recursion, not the bridge.`,
            );
        }
        case StepKindId.UrlTabClick: {
            // UrlTabClick is dispatched by `executeUrlTabClick` against a
            // TabsAdapter — not the selector-based replay bridge. Surface
            // a precise reason so failure diagnostics show "wrong path"
            // instead of a silent skip.
            throw new Error(
                `UrlTabClick step #${step.StepId} is not handled by the live replay bridge — `
                + `it is dispatched by executeUrlTabClick against the tabs adapter.`,
            );
        }
        case StepKindId.Hotkey: {
            // Hotkey (AutoHotkey-style chord macro) is dispatched by a
            // dedicated keyboard executor — not the selector-based
            // replay bridge. Surface a precise reason so the failure
            // diagnostics show "wrong path" instead of a silent skip.
            throw new Error(
                `Hotkey step #${step.StepId} is not handled by the live replay bridge — `
                + `it is dispatched by the dedicated hotkey executor (see executeHotkeyStep).`,
            );
        }
        default: {
            const exhaustive: never = step.StepKindId;
            throw new Error(`Unknown StepKindId for step #${step.StepId}: ${String(exhaustive)}`);
        }
    }
}

function parsePayload(step: StepRow): StepPayload {
    if (step.PayloadJson === null || step.PayloadJson === "") return {};
    try {
        const parsed: unknown = JSON.parse(step.PayloadJson);
        if (parsed === null || typeof parsed !== "object") {
            throw new Error(`PayloadJson must be a JSON object, got ${typeof parsed}`);
        }
        return parsed as StepPayload;
    } catch (err) {
        throw new Error(
            `Step #${step.StepId} has invalid PayloadJson: ${(err as Error).message}`,
        );
    }
}

function requireSelector(step: StepRow, payload: StepPayload): PersistedSelector {
    const expr = payload.Selector;
    if (typeof expr !== "string" || expr.trim() === "") {
        throw new Error(
            `Step #${step.StepId} (kind=${stepKindLabel(step.StepKindId)}) `
            + `requires PayloadJson.Selector — got ${JSON.stringify(payload.Selector)}.`,
        );
    }
    const trimmed = expr.trim();
    // Mirror the kind-detection in replay-resolver.ts so the same
    // expression resolves the same way in both code paths.
    const selectorKindId = trimmed.startsWith("/") || trimmed.startsWith("(")
        ? SelectorKindId.XPathFull
        : SelectorKindId.Css;
    return {
        // Synthetic IDs: the step-library schema doesn't persist
        // Selector rows. Negative numbers stay clearly distinct from
        // any real Selector.SelectorId in the legacy per-project DB
        // so log diffs / persistence layers can tell them apart.
        SelectorId: -step.StepId,
        StepId: step.StepId,
        SelectorKindId: selectorKindId,
        Expression: trimmed,
        AnchorSelectorId: null,
        IsPrimary: 1,
    };
}

function stepKindLabel(id: StepKindId): string {
    switch (id) {
        case StepKindId.Click:    return "Click";
        case StepKindId.Type:     return "Type";
        case StepKindId.Select:   return "Select";
        case StepKindId.JsInline: return "JsInline";
        case StepKindId.Wait:     return "Wait";
        case StepKindId.RunGroup: return "RunGroup";
        default:                  return `Unknown(${String(id)})`;
    }
}

/**
 * Marco Extension — Result Webhook
 *
 * Single-attempt HTTP POST delivery of recorder/runner results to a
 * user-configurable endpoint. Backed by `localStorage` only.
 *
 * Policy invariants (memory):
 *   - mem://constraints/webhook-fail-fast  — single fetch, no retry, no
 *     backoff, no scheduled redelivery.
 *   - mem://features/webhook-result-schema-version — every persisted result
 *     carries `SchemaVersion`. Legacy v1 blobs (no field) are upgraded on
 *     read by `migrateWebhookDeliveryResult`. Unknown future versions are
 *     replaced by a corrupt-placeholder failure.
 *   - mem://constraints/no-supabase — no remote storage, no Supabase SDK.
 */

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

export const WEBHOOK_RESULT_SCHEMA_VERSION = 2 as const;

const CONFIG_STORAGE_KEY = "marco.webhook.config.v1";
const LOG_STORAGE_KEY = "marco.webhook.log.v1";
const LOG_MAX_ENTRIES = 20;
const DEFAULT_TIMEOUT_MS = 8000;

const CORRUPT_PLACEHOLDER_PREFIX = "Corrupt webhook log entry";

export const ALL_WEBHOOK_EVENTS = [
    "GroupRunSucceeded",
    "GroupRunFailed",
    "BatchComplete",
    "RecordingStopped",
] as const;

export type WebhookEventKind = typeof ALL_WEBHOOK_EVENTS[number];

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface WebhookHeader {
    readonly Name: string;
    readonly Value: string;
}

export interface WebhookConfig {
    readonly Enabled: boolean;
    readonly Url: string;
    readonly TimeoutMs: number;
    readonly Headers: ReadonlyArray<WebhookHeader>;
    readonly Events: ReadonlyArray<WebhookEventKind>;
    readonly SecretToken: string;
}

export const DEFAULT_WEBHOOK_CONFIG: WebhookConfig = {
    Enabled: false,
    Url: "",
    TimeoutMs: DEFAULT_TIMEOUT_MS,
    Headers: [],
    Events: [...ALL_WEBHOOK_EVENTS],
    SecretToken: "",
};

export type WebhookPayload = Record<string, unknown>;

export interface WebhookDeliverySuccess {
    readonly SchemaVersion: typeof WEBHOOK_RESULT_SCHEMA_VERSION;
    readonly Kind: "success";
    readonly Ok: true;
    readonly Skipped: false;
    readonly Event: WebhookEventKind;
    readonly Url: string;
    readonly Status: number;
    readonly DurationMs: number;
    readonly EmittedAt: string;
    readonly Payload: WebhookPayload | null;
}

export interface WebhookDeliverySkipped {
    readonly SchemaVersion: typeof WEBHOOK_RESULT_SCHEMA_VERSION;
    readonly Kind: "skipped";
    readonly Ok: true;
    readonly Skipped: true;
    readonly Event: WebhookEventKind;
    readonly Url: string | null;
    readonly SkipReason: string;
    readonly DurationMs: number;
    readonly EmittedAt: string;
    readonly Payload: WebhookPayload | null;
}

export interface WebhookDeliveryFailure {
    readonly SchemaVersion: typeof WEBHOOK_RESULT_SCHEMA_VERSION;
    readonly Kind: "failure";
    readonly Ok: false;
    readonly Skipped: false;
    readonly Event: WebhookEventKind;
    readonly Url: string;
    readonly Status: number | null;
    readonly Error: string;
    readonly DurationMs: number;
    readonly EmittedAt: string;
    readonly Payload: WebhookPayload | null;
}

export type WebhookDeliveryResult =
    | WebhookDeliverySuccess
    | WebhookDeliverySkipped
    | WebhookDeliveryFailure;

/* ------------------------------------------------------------------ */
/*  Type guards                                                        */
/* ------------------------------------------------------------------ */

export function isWebhookSuccess(r: WebhookDeliveryResult): r is WebhookDeliverySuccess {
    return r.Kind === "success";
}
export function isWebhookSkipped(r: WebhookDeliveryResult): r is WebhookDeliverySkipped {
    return r.Kind === "skipped";
}
export function isWebhookFailure(r: WebhookDeliveryResult): r is WebhookDeliveryFailure {
    return r.Kind === "failure";
}

/* ------------------------------------------------------------------ */
/*  Storage helpers                                                    */
/* ------------------------------------------------------------------ */

function safeLocalStorage(): Storage | null {
    try {
        if (typeof localStorage === "undefined") return null;
        return localStorage;
    } catch {
        return null;
    }
}

function nowIso(): string {
    return new Date().toISOString();
}

function isPlainRecord(v: unknown): v is Record<string, unknown> {
    return typeof v === "object" && v !== null && !Array.isArray(v);
}

function asString(v: unknown, fallback: string): string {
    return typeof v === "string" ? v : fallback;
}
function asNumber(v: unknown, fallback: number): number {
    return typeof v === "number" && Number.isFinite(v) ? v : fallback;
}
function asBool(v: unknown, fallback: boolean): boolean {
    return typeof v === "boolean" ? v : fallback;
}
function asEvent(v: unknown): WebhookEventKind {
    if (typeof v === "string" && (ALL_WEBHOOK_EVENTS as ReadonlyArray<string>).includes(v)) {
        return v as WebhookEventKind;
    }
    return "GroupRunSucceeded";
}

/* ------------------------------------------------------------------ */
/*  Config load/save                                                   */
/* ------------------------------------------------------------------ */

export function loadWebhookConfig(): WebhookConfig {
    const ls = safeLocalStorage();
    if (!ls) return { ...DEFAULT_WEBHOOK_CONFIG };
    try {
        const raw = ls.getItem(CONFIG_STORAGE_KEY);
        if (!raw) return { ...DEFAULT_WEBHOOK_CONFIG };
        const parsed: unknown = JSON.parse(raw);
        if (!isPlainRecord(parsed)) return { ...DEFAULT_WEBHOOK_CONFIG };
        const headers: WebhookHeader[] = Array.isArray(parsed.Headers)
            ? parsed.Headers
                  .filter(isPlainRecord)
                  .map((h) => ({
                      Name: asString(h.Name, ""),
                      Value: asString(h.Value, ""),
                  }))
            : [];
        const events: WebhookEventKind[] = Array.isArray(parsed.Events)
            ? parsed.Events
                  .filter((e): e is string => typeof e === "string")
                  .filter((e): e is WebhookEventKind => (ALL_WEBHOOK_EVENTS as ReadonlyArray<string>).includes(e))
            : [...ALL_WEBHOOK_EVENTS];
        return {
            Enabled: asBool(parsed.Enabled, false),
            Url: asString(parsed.Url, ""),
            TimeoutMs: asNumber(parsed.TimeoutMs, DEFAULT_TIMEOUT_MS),
            Headers: headers,
            Events: events,
            SecretToken: asString(parsed.SecretToken, ""),
        };
    } catch {
        return { ...DEFAULT_WEBHOOK_CONFIG };
    }
}

export function saveWebhookConfig(config: WebhookConfig): WebhookConfig {
    const ls = safeLocalStorage();
    const normalized: WebhookConfig = {
        Enabled: !!config.Enabled,
        Url: typeof config.Url === "string" ? config.Url : "",
        TimeoutMs: Number.isFinite(config.TimeoutMs) && config.TimeoutMs > 0 ? config.TimeoutMs : DEFAULT_TIMEOUT_MS,
        Headers: (config.Headers ?? []).map((h) => ({ Name: h.Name ?? "", Value: h.Value ?? "" })),
        Events: (config.Events ?? []).filter((k) => (ALL_WEBHOOK_EVENTS as ReadonlyArray<string>).includes(k)),
        SecretToken: typeof config.SecretToken === "string" ? config.SecretToken : "",
    };
    if (ls) {
        try { ls.setItem(CONFIG_STORAGE_KEY, JSON.stringify(normalized)); } catch { /* quota or storage unavailable */ } // allow-swallow: localStorage quota / unavailable — config in-memory is authoritative this session
    }
    return normalized;
}

/* ------------------------------------------------------------------ */
/*  Migration + corrupt placeholder                                    */
/* ------------------------------------------------------------------ */

function buildCorruptPlaceholder(reason: string): WebhookDeliveryFailure {
    return {
        SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
        Kind: "failure",
        Ok: false,
        Skipped: false,
        Event: "GroupRunFailed",
        Url: "",
        Status: null,
        Error: `${CORRUPT_PLACEHOLDER_PREFIX}: ${reason}`,
        DurationMs: 0,
        EmittedAt: nowIso(),
        Payload: null,
    };
}

export function migrateWebhookDeliveryResult(input: unknown): WebhookDeliveryResult {
    if (!isPlainRecord(input)) {
        return buildCorruptPlaceholder("entry is not an object");
    }

    // Version handling
    const versionField = input.SchemaVersion;
    const hasVersion = typeof versionField === "number";
    if (hasVersion && versionField !== WEBHOOK_RESULT_SCHEMA_VERSION) {
        return buildCorruptPlaceholder(`unknown SchemaVersion ${String(versionField)}`);
    }
    // No version field => v1 legacy blob; upgrade in place.

    const kind = input.Kind;
    const event = asEvent(input.Event);
    const durationMs = asNumber(input.DurationMs, 0);
    const emittedAt = asString(input.EmittedAt, nowIso());
    const payload: WebhookPayload | null = isPlainRecord(input.Payload)
        ? (input.Payload as WebhookPayload)
        : null;

    if (kind === "success") {
        return {
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "success",
            Ok: true,
            Skipped: false,
            Event: event,
            Url: asString(input.Url, ""),
            Status: asNumber(input.Status, 0),
            DurationMs: durationMs,
            EmittedAt: emittedAt,
            Payload: payload,
        };
    }
    if (kind === "skipped") {
        const url = typeof input.Url === "string" ? input.Url : null;
        return {
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "skipped",
            Ok: true,
            Skipped: true,
            Event: event,
            Url: url,
            SkipReason: asString(input.SkipReason, "Skipped"),
            DurationMs: durationMs,
            EmittedAt: emittedAt,
            Payload: payload,
        };
    }
    if (kind === "failure") {
        const status = typeof input.Status === "number" ? input.Status : null;
        return {
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "failure",
            Ok: false,
            Skipped: false,
            Event: event,
            Url: asString(input.Url, ""),
            Status: status,
            Error: asString(input.Error, "Unknown error"),
            DurationMs: durationMs,
            EmittedAt: emittedAt,
            Payload: payload,
        };
    }
    return buildCorruptPlaceholder(`unknown Kind ${String(kind)}`);
}

/* ------------------------------------------------------------------ */
/*  Delivery log                                                       */
/* ------------------------------------------------------------------ */

function readLogRaw(): unknown[] {
    const ls = safeLocalStorage();
    if (!ls) return [];
    try {
        const raw = ls.getItem(LOG_STORAGE_KEY);
        if (!raw) return [];
        const parsed: unknown = JSON.parse(raw);
        return Array.isArray(parsed) ? parsed : [];
    } catch {
        return [];
    }
}

function writeLog(entries: ReadonlyArray<WebhookDeliveryResult>): void {
    const ls = safeLocalStorage();
    if (!ls) return;
    try {
        ls.setItem(LOG_STORAGE_KEY, JSON.stringify(entries.slice(0, LOG_MAX_ENTRIES)));
    } catch { /* quota or storage unavailable */ } // allow-swallow: delivery-log write is best-effort; loss of one log entry must not break the run
}

export function getDeliveryLog(): ReadonlyArray<WebhookDeliveryResult> {
    return readLogRaw().map(migrateWebhookDeliveryResult);
}

export function clearDeliveryLog(): void {
    const ls = safeLocalStorage();
    if (!ls) return;
    try { ls.removeItem(LOG_STORAGE_KEY); } catch { /* ignore */ } // allow-swallow: clearing the delivery log is best-effort cleanup
}

export interface RepairReport {
    readonly Removed: number;
    readonly Kept: number;
    readonly Errors: ReadonlyArray<string>;
}

export function repairDeliveryLog(): RepairReport {
    const raw = readLogRaw();
    const errors: string[] = [];
    const kept: WebhookDeliveryResult[] = [];
    let removed = 0;
    for (const entry of raw) {
        const migrated = migrateWebhookDeliveryResult(entry);
        if (isWebhookFailure(migrated) && migrated.Error.startsWith(CORRUPT_PLACEHOLDER_PREFIX)) {
            removed += 1;
            errors.push(migrated.Error);
        } else {
            kept.push(migrated);
        }
    }
    writeLog(kept);
    return { Removed: removed, Kept: kept.length, Errors: errors };
}

function appendLog(entry: WebhookDeliveryResult): void {
    const current = getDeliveryLog();
    writeLog([entry, ...current]);
}

/* ------------------------------------------------------------------ */
/*  Payload builders                                                   */
/* ------------------------------------------------------------------ */

export interface GroupRunPayloadInput {
    readonly ProjectId: number | null;
    readonly GroupId: number;
    readonly GroupName: string;
    readonly DurationMs: number;
    readonly StepsExecuted: number;
    readonly Outcome: string;
    readonly FailureReason?: string;
    readonly FailedStepId?: number;
    readonly IsTest?: boolean;
}

export function buildGroupRunPayload(input: GroupRunPayloadInput): WebhookPayload {
    const out: WebhookPayload = {
        ProjectId: input.ProjectId,
        GroupId: input.GroupId,
        GroupName: input.GroupName,
        DurationMs: input.DurationMs,
        StepsExecuted: input.StepsExecuted,
        Outcome: input.Outcome,
        EmittedAt: nowIso(),
    };
    if (input.FailureReason !== undefined) out.FailureReason = input.FailureReason;
    if (input.FailedStepId !== undefined) out.FailedStepId = input.FailedStepId;
    if (input.IsTest) out.IsTest = true;
    return out;
}

export interface BatchCompletePayloadInput {
    readonly ProjectId: number | null;
    readonly TotalGroups: number;
    readonly Succeeded: number;
    readonly Failed: number;
    readonly Skipped: number;
    readonly DurationMs: number;
    readonly Ok: boolean;
}

export function buildBatchCompletePayload(input: BatchCompletePayloadInput): WebhookPayload {
    return {
        ProjectId: input.ProjectId,
        TotalGroups: input.TotalGroups,
        Succeeded: input.Succeeded,
        Failed: input.Failed,
        Skipped: input.Skipped,
        DurationMs: input.DurationMs,
        Ok: input.Ok,
        EmittedAt: nowIso(),
    };
}

/* ------------------------------------------------------------------ */
/*  Variable substitution                                              */
/* ------------------------------------------------------------------ */

function substitute(template: string, payload: WebhookPayload, event: WebhookEventKind): string {
    if (!template.includes("{{")) return template;
    const lookup: Record<string, unknown> = {
        ...payload,
        Event: event,
        Outcome: payload.Outcome ?? event,
    };
    return template.replace(/\{\{\s*([A-Za-z0-9_]+)\s*\}\}/g, (_m, key: string) => {
        const v = lookup[key];
        if (v === undefined || v === null) return "";
        return typeof v === "string" ? v : String(v);
    });
}

/* ------------------------------------------------------------------ */
/*  Dispatch                                                           */
/* ------------------------------------------------------------------ */

export interface DispatchOptions {
    readonly config?: WebhookConfig;
}

/**
 * Single-attempt webhook delivery. Fire-and-forget by contract:
 * no retries, no backoff, no scheduled redelivery.
 */
export async function dispatchWebhook(
    event: WebhookEventKind,
    payload: WebhookPayload,
    options: DispatchOptions = {},
): Promise<WebhookDeliveryResult> {
    const config = options.config ?? loadWebhookConfig();
    const startedAt = Date.now();
    const emittedAt = nowIso();

    function record<T extends WebhookDeliveryResult>(entry: T): T {
        appendLog(entry);
        return entry;
    }

    if (!config.Enabled) {
        return record<WebhookDeliverySkipped>({
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "skipped",
            Ok: true,
            Skipped: true,
            Event: event,
            Url: config.Url || null,
            SkipReason: "Webhook disabled",
            DurationMs: 0,
            EmittedAt: emittedAt,
            Payload: payload,
        });
    }
    if (!config.Url || config.Url.trim().length === 0) {
        return record<WebhookDeliverySkipped>({
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "skipped",
            Ok: true,
            Skipped: true,
            Event: event,
            Url: null,
            SkipReason: "URL empty",
            DurationMs: 0,
            EmittedAt: emittedAt,
            Payload: payload,
        });
    }
    if (config.Events.length > 0 && !config.Events.includes(event)) {
        return record<WebhookDeliverySkipped>({
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "skipped",
            Ok: true,
            Skipped: true,
            Event: event,
            Url: config.Url,
            SkipReason: `Event ${event} not subscribed`,
            DurationMs: 0,
            EmittedAt: emittedAt,
            Payload: payload,
        });
    }

    const finalUrl = substitute(config.Url, payload, event);
    const headers: Record<string, string> = { "Content-Type": "application/json" };
    for (const h of config.Headers) {
        const name = (h.Name ?? "").trim();
        if (!name) continue;
        headers[name] = substitute(h.Value ?? "", payload, event);
    }
    if (config.SecretToken && config.SecretToken.trim().length > 0) {
        headers["X-Marco-Token"] = config.SecretToken;
    }

    const body = JSON.stringify({ Event: event, Payload: payload, EmittedAt: emittedAt });

    const controller = new AbortController();
    const timeoutMs = config.TimeoutMs > 0 ? config.TimeoutMs : DEFAULT_TIMEOUT_MS;
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    try {
        const res = await fetch(finalUrl, {
            method: "POST",
            headers,
            body,
            signal: controller.signal,
        });
        clearTimeout(timer);
        const durationMs = Date.now() - startedAt;
        if (res.ok) {
            return record<WebhookDeliverySuccess>({
                SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
                Kind: "success",
                Ok: true,
                Skipped: false,
                Event: event,
                Url: finalUrl,
                Status: res.status,
                DurationMs: durationMs,
                EmittedAt: emittedAt,
                Payload: payload,
            });
        }
        return record<WebhookDeliveryFailure>({
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "failure",
            Ok: false,
            Skipped: false,
            Event: event,
            Url: finalUrl,
            Status: res.status,
            Error: `HEFF: HTTP ${res.status} on POST ${finalUrl} — ${res.statusText || "non-2xx"}. ` +
                   `Single-attempt webhook (webhook-fail-fast); no retry. Loop halted.`,
            DurationMs: durationMs,
            EmittedAt: emittedAt,
            Payload: payload,
        });
    } catch (err) {
        clearTimeout(timer);
        const durationMs = Date.now() - startedAt;
        const aborted = err instanceof DOMException && err.name === "AbortError";
        const message = aborted
            ? `Timeout after ${timeoutMs}ms`
            : err instanceof Error
                ? err.message
                : String(err);
        return record<WebhookDeliveryFailure>({
            SchemaVersion: WEBHOOK_RESULT_SCHEMA_VERSION,
            Kind: "failure",
            Ok: false,
            Skipped: false,
            Event: event,
            Url: finalUrl,
            Status: null,
            Error: message,
            DurationMs: durationMs,
            EmittedAt: emittedAt,
            Payload: payload,
        });
    }
}

/**
 * Marco Extension — Run Batch
 *
 * Sequential, ordered execution of multiple StepGroups. Each group is
 * dispatched through the existing `runGroup()` runner, so the same
 * cycle/depth/cross-project guards apply per group.
 *
 * Why a thin wrapper instead of a single mega-runner:
 *   - Each group is an INDEPENDENT execution: failure in group A
 *     does not corrupt the trace of group B (they get distinct
 *     `RunGroupResult`s).
 *   - The UI can stream per-group status updates by passing an
 *     `onGroupStatus` callback — no polling, no shared mutable buffer.
 *   - Keeps `run-group-runner.ts` focused on tree traversal; batch
 *     ordering is orthogonal.
 *
 * Failure policy is a caller decision:
 *   - "StopOnFailure" (default) — first failed group aborts the batch;
 *     remaining groups stay `Pending` and surface as "Skipped" in the
 *     final report.
 *   - "ContinueOnFailure" — every group is attempted; the batch
 *     `Ok` flag reports the aggregate.
 *
 * @see ./run-group-runner.ts
 */

import type { StepLibraryDb } from "./db";
import {
    runGroup,
    type LeafStepExecutor,
    type RunGroupResult,
} from "./run-group-runner";

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export type BatchGroupStatus =
    | "Pending"
    | "Running"
    | "Succeeded"
    | "Failed"
    | "Skipped"; // batch aborted before this group ran

export interface BatchGroupReport {
    readonly StepGroupId: number;
    readonly Status: BatchGroupStatus;
    readonly StartedAt: string | null;
    readonly EndedAt: string | null;
    readonly DurationMs: number;
    /** Present iff the group actually ran (Succeeded or Failed). */
    readonly Result: RunGroupResult | null;
}

export type BatchFailurePolicy = "StopOnFailure" | "ContinueOnFailure";

export interface RunBatchOptions {
    readonly db: StepLibraryDb;
    readonly projectId: number;
    /** Ordered list of StepGroupIds to execute, in the exact order chosen by the user. */
    readonly orderedGroupIds: ReadonlyArray<number>;
    readonly executeLeafStep: LeafStepExecutor;
    readonly failurePolicy?: BatchFailurePolicy;
    /** Streamed status update; called whenever any row's Status changes. */
    readonly onGroupStatus?: (report: BatchGroupReport, index: number) => void;
    /** Override for tests. */
    readonly now?: () => Date;
}

export interface RunBatchResult {
    readonly Ok: boolean;
    readonly TotalGroups: number;
    readonly Succeeded: number;
    readonly Failed: number;
    readonly Skipped: number;
    readonly Reports: ReadonlyArray<BatchGroupReport>;
    readonly DurationMs: number;
}

/* ------------------------------------------------------------------ */
/*  Runner                                                             */
/* ------------------------------------------------------------------ */

const NO_DURATION = 0;

function defaultNow(): Date {
    return new Date();
}

function emptyReport(stepGroupId: number): BatchGroupReport {
    return {
        StepGroupId: stepGroupId,
        Status: "Pending",
        StartedAt: null,
        EndedAt: null,
        DurationMs: NO_DURATION,
        Result: null,
    };
}

function emit(
    cb: RunBatchOptions["onGroupStatus"],
    report: BatchGroupReport,
    index: number,
): void {
    if (cb !== undefined) cb(report, index);
}

export async function runBatch(opts: RunBatchOptions): Promise<RunBatchResult> {
    const now = opts.now ?? defaultNow;
    const policy: BatchFailurePolicy = opts.failurePolicy ?? "StopOnFailure";
    const reports: BatchGroupReport[] = opts.orderedGroupIds.map(emptyReport);
    const batchStart = now();
    let succeeded = 0;
    let failed = 0;
    let aborted = false;

    for (let i = 0; i < reports.length; i++) {
        if (aborted) {
            reports[i] = { ...reports[i], Status: "Skipped" };
            emit(opts.onGroupStatus, reports[i], i);
            continue;
        }
        const startDate = now();
        reports[i] = { ...reports[i], Status: "Running", StartedAt: startDate.toISOString() };
        emit(opts.onGroupStatus, reports[i], i);

        const result = await runGroup({
            db: opts.db,
            projectId: opts.projectId,
            rootGroupId: reports[i].StepGroupId,
            executeLeafStep: opts.executeLeafStep,
            now: opts.now,
        });

        const endDate = now();
        const final: BatchGroupReport = {
            ...reports[i],
            Status: result.Ok ? "Succeeded" : "Failed",
            EndedAt: endDate.toISOString(),
            DurationMs: endDate.getTime() - startDate.getTime(),
            Result: result,
        };
        reports[i] = final;
        if (result.Ok) succeeded++; else failed++;
        emit(opts.onGroupStatus, final, i);
        if (!result.Ok && policy === "StopOnFailure") aborted = true;
    }

    const skipped = reports.length - succeeded - failed;
    return {
        Ok: failed === 0 && skipped === 0,
        TotalGroups: reports.length,
        Succeeded: succeeded,
        Failed: failed,
        Skipped: skipped,
        Reports: reports,
        DurationMs: now().getTime() - batchStart.getTime(),
    };
}

/**
 * Marco Extension — Run Group Runner
 *
 * Pure orchestration layer that walks a `StepGroup` tree and executes
 * each `Step` in `OrderIndex` order. When it encounters a `RunGroup`
 * step (`StepKindId.RunGroup`), it recursively descends into the
 * referenced child group with the same execution context — so step
 * groups can compose / depend on previously-recorded groups.
 *
 * Why this lives in the step-library layer:
 *   - It only depends on `StepLibraryDb` (sql.js), the canonical
 *     `StepKindId` enum, and an injected leaf-step executor. No DOM,
 *     no chrome.* APIs, no async I/O of its own.
 *   - That makes it directly unit-testable against an in-memory DB
 *     (see `__tests__/run-group-runner.test.ts`), and reusable from
 *     both the background service worker and the Options page preview.
 *
 * Safety invariants enforced here (the DB layer enforces structural
 * ones; this layer enforces RUNTIME ones):
 *   1. `MAX_RUN_GROUP_CALL_DEPTH` (16) — recursive RunGroup chains are
 *      capped to mirror `spec/31-macro-recorder/16-step-group-library.md` §3.1.
 *   2. Cycle detection — a group cannot appear twice in the active
 *      call stack. (Two sibling RunGroup steps invoking the same
 *      group sequentially is fine; only re-entering an *active* frame
 *      is forbidden.)
 *   3. Missing/dangling target — `Step.TargetStepGroupId` may be NULL
 *      (e.g. after the target group was deleted and the FK fired
 *      `ON DELETE SET NULL`). The runner aborts with a structured
 *      failure that points at the offending step.
 *   4. Disabled steps (`IsDisabled = 1`) are skipped silently, BUT
 *      they still appear in the trace as `"Skipped"` so debuggers can
 *      see the recorder's intent.
 *
 * Failure surfacing:
 *   Leaf-step failures bubble up with a `FailureReport` produced by
 *   the injected `executeLeafStep` callback (recorder/replay code is
 *   the canonical source of those reports — see
 *   `mem://standards/verbose-logging-and-failure-diagnostics`). The
 *   runner attaches the call-stack of group names, so the UI can show
 *   "FailedGroup: Login → Submit Order → Confirm".
 *
 * @see ./schema.ts        — StepKindId, MAX_RUN_GROUP_CALL_DEPTH
 * @see ./db.ts            — StepLibraryDb, StepRow, StepGroupRow
 * @see ../failure-logger.ts — FailureReport contract
 * @see spec/31-macro-recorder/16-step-group-library.md §3.1, §5.3
 */

import type { FailureReport } from "../failure-logger";
import type { StepLibraryDb, StepGroupRow, StepRow } from "./db";
import { StepKindId, MAX_RUN_GROUP_CALL_DEPTH } from "./schema";

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

/** A single step's fate within a run. Mirrors the RunStepLog row in the spec. */
export interface RunStepTraceEntry {
    readonly StepId: number;
    readonly StepGroupId: number;
    readonly StepKindId: StepKindId;
    readonly Label: string | null;
    readonly OrderIndex: number;
    /** Names of every group from the root down to this step's group. */
    readonly GroupPath: ReadonlyArray<string>;
    readonly Outcome: "Executed" | "Skipped" | "EnteredGroup" | "ExitedGroup" | "Failed";
    /** ISO-8601 timestamp captured at entry (UTC). */
    readonly StartedAt: string;
    readonly DurationMs: number;
}

/**
 * Top-level discriminator for runner-level failures. Leaf-step
 * failures arrive as `Reason: "LeafStepFailed"` carrying the
 * `FailureReport` returned by the executor; structural failures
 * (cycle / depth / missing target) carry no `FailureReport` because
 * no live DOM evaluation occurred — the runner aborted statically.
 */
export type RunGroupFailureReason =
    | "LeafStepFailed"        // executor returned/threw a FailureReport.
    | "RunGroupCycle"         // group already on the active call stack.
    | "RunGroupDepthExceeded" // call stack exceeded MAX_RUN_GROUP_CALL_DEPTH.
    | "MissingTargetGroup"    // RunGroup step has no resolvable target.
    | "MissingRootGroup"      // caller passed a rootGroupId that does not exist.
    | "TargetNotInProject";   // target group lives in a different ProjectId.

export interface RunGroupFailure {
    readonly Ok: false;
    readonly Reason: RunGroupFailureReason;
    readonly ReasonDetail: string;
    readonly FailedStepId: number | null;
    readonly FailedGroupId: number | null;
    readonly CallStack: ReadonlyArray<string>;
    /**
     * Present iff `Reason === "LeafStepFailed"`. The report is the
     * untouched value the executor surfaced — the runner never
     * re-classifies leaf failures.
     */
    readonly FailureReport: FailureReport | null;
    readonly Trace: ReadonlyArray<RunStepTraceEntry>;
}

export interface RunGroupSuccess {
    readonly Ok: true;
    readonly StepsExecuted: number;
    readonly StepsSkipped: number;
    readonly GroupsEntered: number;
    readonly Trace: ReadonlyArray<RunStepTraceEntry>;
}

export type RunGroupResult = RunGroupSuccess | RunGroupFailure;

/**
 * The injected executor for a single leaf step (anything that is NOT
 * `StepKindId.RunGroup`). Returns `null` on success, or a
 * `FailureReport` on failure. Throwing is also accepted — the runner
 * will wrap a plain `Error` into a synthetic FailureReport with
 * `Reason: "Unknown"`.
 */
export type LeafStepExecutor = (
    step: StepRow,
    ctx: LeafStepContext,
) => FailureReport | null | Promise<FailureReport | null>;

export interface LeafStepContext {
    readonly ProjectId: number;
    readonly GroupPath: ReadonlyArray<string>;
    readonly CallStackGroupIds: ReadonlyArray<number>;
}

export interface RunGroupOptions {
    readonly db: StepLibraryDb;
    readonly projectId: number;
    readonly rootGroupId: number;
    readonly executeLeafStep: LeafStepExecutor;
    /** Override for tests; defaults to `() => new Date()`. */
    readonly now?: () => Date;
}

/* ------------------------------------------------------------------ */
/*  Runner                                                             */
/* ------------------------------------------------------------------ */

export async function runGroup(opts: RunGroupOptions): Promise<RunGroupResult> {
    const now = opts.now ?? defaultNow;
    const trace: RunStepTraceEntry[] = [];

    const root = findGroup(opts.db, opts.rootGroupId);
    if (root === null) {
        return {
            Ok: false,
            Reason: "MissingRootGroup",
            ReasonDetail:
                `runGroup: rootGroupId=${opts.rootGroupId} not found in StepGroup table. ` +
                `Caller must pass an existing StepGroupId — was the group deleted between ` +
                `selection and execution?`,
            FailedStepId: null,
            FailedGroupId: opts.rootGroupId,
            CallStack: [],
            FailureReport: null,
            Trace: trace,
        };
    }
    if (root.ProjectId !== opts.projectId) {
        return {
            Ok: false,
            Reason: "TargetNotInProject",
            ReasonDetail:
                `runGroup: rootGroupId=${opts.rootGroupId} belongs to ProjectId=${root.ProjectId}, ` +
                `but caller passed ProjectId=${opts.projectId}. Refusing to cross project boundary.`,
            FailedStepId: null,
            FailedGroupId: opts.rootGroupId,
            CallStack: [],
            FailureReport: null,
            Trace: trace,
        };
    }

    let executed = 0;
    let skipped = 0;
    let entered = 0;

    const counters = {
        bumpExecuted: () => { executed++; },
        bumpSkipped:  () => { skipped++; },
        bumpEntered:  () => { entered++; },
    };

    const failure = await runOne({
        db: opts.db,
        projectId: opts.projectId,
        group: root,
        callStackIds: [],
        callStackNames: [],
        executeLeafStep: opts.executeLeafStep,
        trace,
        now,
        counters,
    });

    if (failure !== null) return failure;

    return {
        Ok: true,
        StepsExecuted: executed,
        StepsSkipped: skipped,
        GroupsEntered: entered,
        Trace: trace,
    };
}

/* ------------------------------------------------------------------ */
/*  Internal recursion                                                 */
/* ------------------------------------------------------------------ */

interface FrameContext {
    readonly db: StepLibraryDb;
    readonly projectId: number;
    readonly group: StepGroupRow;
    readonly callStackIds: ReadonlyArray<number>;
    readonly callStackNames: ReadonlyArray<string>;
    readonly executeLeafStep: LeafStepExecutor;
    readonly trace: RunStepTraceEntry[];
    readonly now: () => Date;
    readonly counters: {
        bumpExecuted: () => void;
        bumpSkipped: () => void;
        bumpEntered: () => void;
    };
}

async function runOne(frame: FrameContext): Promise<RunGroupFailure | null> {
    // Push this frame.
    const newStackIds = [...frame.callStackIds, frame.group.StepGroupId];
    const newStackNames = [...frame.callStackNames, frame.group.Name];
    frame.counters.bumpEntered();

    const enteredAt = frame.now();
    pushTrace(frame.trace, {
        StepId: -1,
        StepGroupId: frame.group.StepGroupId,
        StepKindId: StepKindId.RunGroup,
        Label: `→ enter "${frame.group.Name}"`,
        OrderIndex: -1,
        GroupPath: newStackNames,
        Outcome: "EnteredGroup",
        StartedAt: enteredAt.toISOString(),
        DurationMs: 0,
    });

    const steps = frame.db.listSteps(frame.group.StepGroupId);

    for (const step of steps) {
        if (step.IsDisabled) {
            frame.counters.bumpSkipped();
            pushTrace(frame.trace, {
                StepId: step.StepId,
                StepGroupId: step.StepGroupId,
                StepKindId: step.StepKindId,
                Label: step.Label,
                OrderIndex: step.OrderIndex,
                GroupPath: newStackNames,
                Outcome: "Skipped",
                StartedAt: frame.now().toISOString(),
                DurationMs: 0,
            });
            continue;
        }

        if (step.StepKindId === StepKindId.RunGroup) {
            const failure = await invokeRunGroupStep(step, {
                ...frame,
                callStackIds: newStackIds,
                callStackNames: newStackNames,
            });
            if (failure !== null) return failure;
            continue;
        }

        const failure = await invokeLeafStep(step, {
            ...frame,
            callStackIds: newStackIds,
            callStackNames: newStackNames,
        });
        if (failure !== null) return failure;
    }

    pushTrace(frame.trace, {
        StepId: -1,
        StepGroupId: frame.group.StepGroupId,
        StepKindId: StepKindId.RunGroup,
        Label: `← exit "${frame.group.Name}"`,
        OrderIndex: -1,
        GroupPath: newStackNames,
        Outcome: "ExitedGroup",
        StartedAt: frame.now().toISOString(),
        DurationMs: 0,
    });

    return null;
}

async function invokeRunGroupStep(
    step: StepRow,
    frame: FrameContext,
): Promise<RunGroupFailure | null> {
    if (step.TargetStepGroupId === null) {
        return failure(frame, {
            Reason: "MissingTargetGroup",
            ReasonDetail:
                `Step ${step.StepId} (kind=RunGroup) has TargetStepGroupId=NULL. ` +
                `The referenced group was likely deleted (FK ON DELETE SET NULL fired). ` +
                `Re-link this step to a valid group or remove it.`,
            failedStepId: step.StepId,
            failedGroupId: frame.group.StepGroupId,
        });
    }

    const target = findGroup(frame.db, step.TargetStepGroupId);
    if (target === null) {
        return failure(frame, {
            Reason: "MissingTargetGroup",
            ReasonDetail:
                `Step ${step.StepId} (kind=RunGroup) targets StepGroupId=${step.TargetStepGroupId} ` +
                `but no such group exists. Database is inconsistent — expected FK to have ` +
                `enforced this; check PRAGMA foreign_keys is ON.`,
            failedStepId: step.StepId,
            failedGroupId: frame.group.StepGroupId,
        });
    }
    if (target.ProjectId !== frame.projectId) {
        return failure(frame, {
            Reason: "TargetNotInProject",
            ReasonDetail:
                `Step ${step.StepId} targets group "${target.Name}" (ProjectId=${target.ProjectId}) ` +
                `but the runner is bound to ProjectId=${frame.projectId}. ` +
                `Cross-project RunGroup is forbidden — re-import the dependency into this project.`,
            failedStepId: step.StepId,
            failedGroupId: frame.group.StepGroupId,
        });
    }

    // Cycle: target already on the active stack.
    if (frame.callStackIds.includes(target.StepGroupId)) {
        const cycle = [...frame.callStackNames, target.Name].join(" → ");
        return failure(frame, {
            Reason: "RunGroupCycle",
            ReasonDetail:
                `RunGroup cycle detected: ${cycle}. Group "${target.Name}" is already ` +
                `executing higher up the call stack. Recursion is not supported — break ` +
                `the cycle by extracting the shared steps into a leaf-only group.`,
            failedStepId: step.StepId,
            failedGroupId: frame.group.StepGroupId,
        });
    }

    // Depth: pushing this frame would exceed the limit.
    if (frame.callStackIds.length + 1 > MAX_RUN_GROUP_CALL_DEPTH) {
        return failure(frame, {
            Reason: "RunGroupDepthExceeded",
            ReasonDetail:
                `RunGroup call stack would reach depth ${frame.callStackIds.length + 1}, ` +
                `exceeding MAX_RUN_GROUP_CALL_DEPTH=${MAX_RUN_GROUP_CALL_DEPTH}. ` +
                `Flatten deeply nested compositions or raise the limit in schema.ts.`,
            failedStepId: step.StepId,
            failedGroupId: frame.group.StepGroupId,
        });
    }

    return runOne({
        ...frame,
        group: target,
    });
}

async function invokeLeafStep(
    step: StepRow,
    frame: FrameContext,
): Promise<RunGroupFailure | null> {
    const startedAt = frame.now();
    const ctx: LeafStepContext = {
        ProjectId: frame.projectId,
        GroupPath: frame.callStackNames,
        CallStackGroupIds: frame.callStackIds,
    };

    let report: FailureReport | null = null;
    try {
        report = await frame.executeLeafStep(step, ctx);
    } catch (e) {
        // Executor threw raw — synthesize a minimal FailureReport so
        // the contract holds for downstream UI/logging.
        report = synthesizeFailureReport(step, e, startedAt);
    }

    const duration = frame.now().getTime() - startedAt.getTime();
    frame.counters.bumpExecuted();

    pushTrace(frame.trace, {
        StepId: step.StepId,
        StepGroupId: step.StepGroupId,
        StepKindId: step.StepKindId,
        Label: step.Label,
        OrderIndex: step.OrderIndex,
        GroupPath: frame.callStackNames,
        Outcome: report === null ? "Executed" : "Failed",
        StartedAt: startedAt.toISOString(),
        DurationMs: Math.max(0, duration),
    });

    if (report === null) return null;

    return {
        Ok: false,
        Reason: "LeafStepFailed",
        ReasonDetail:
            `Leaf step ${step.StepId} (kind=${stepKindName(step.StepKindId)}) failed at ` +
            `"${frame.callStackNames.join(" → ")}". See FailureReport for selectors / variables / DOM context.`,
        FailedStepId: step.StepId,
        FailedGroupId: frame.group.StepGroupId,
        CallStack: frame.callStackNames,
        FailureReport: report,
        Trace: frame.trace,
    };
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function findGroup(db: StepLibraryDb, stepGroupId: number): StepGroupRow | null {
    const stmt = db.raw.prepare(
        `SELECT StepGroupId, ProjectId, ParentStepGroupId, Name, Description,
                OrderIndex, IsArchived, CreatedAt, UpdatedAt
         FROM StepGroup WHERE StepGroupId = ?;`,
    );
    try {
        stmt.bind([stepGroupId]);
        if (!stmt.step()) return null;
        const r = stmt.getAsObject() as unknown as StepGroupRow;
        return { ...r, IsArchived: Boolean(r.IsArchived) };
    } finally {
        stmt.free();
    }
}

function failure(
    frame: FrameContext,
    input: {
        Reason: RunGroupFailureReason;
        ReasonDetail: string;
        failedStepId: number | null;
        failedGroupId: number | null;
    },
): RunGroupFailure {
    return {
        Ok: false,
        Reason: input.Reason,
        ReasonDetail: input.ReasonDetail,
        FailedStepId: input.failedStepId,
        FailedGroupId: input.failedGroupId,
        CallStack: frame.callStackNames,
        FailureReport: null,
        Trace: frame.trace,
    };
}

function pushTrace(buf: RunStepTraceEntry[], entry: RunStepTraceEntry): void {
    buf.push(entry);
}

function defaultNow(): Date {
    return new Date();
}

function stepKindName(kind: StepKindId): string {
    switch (kind) {
        case StepKindId.Click:    return "Click";
        case StepKindId.Type:     return "Type";
        case StepKindId.Select:   return "Select";
        case StepKindId.JsInline: return "JsInline";
        case StepKindId.Wait:     return "Wait";
        case StepKindId.RunGroup: return "RunGroup";
        default:                  return `Unknown(${String(kind)})`;
    }
}

function synthesizeFailureReport(step: StepRow, error: unknown, startedAt: Date): FailureReport {
    const message = error instanceof Error ? error.message : String(error);
    const stack = error instanceof Error ? (error.stack ?? null) : null;
    return {
        Phase: "Replay",
        Message: message,
        Reason: "Unknown",
        ReasonDetail:
            `Leaf executor threw a raw error instead of returning a FailureReport. ` +
            `The runner synthesized this report so downstream consumers receive the canonical shape.`,
        StackTrace: stack,
        StepId: step.StepId,
        Index: step.OrderIndex,
        StepKind: stepKindName(step.StepKindId),
        Selectors: [],
        Variables: [],
        DomContext: null,
        DataRow: null,
        ResolvedXPath: null,
        Timestamp: startedAt.toISOString(),
        SourceFile: "src/background/recorder/step-library/run-group-runner.ts",
        Verbose: false,
        CapturedHtml: null,
        FormSnapshot: null,
    };
}

/* ================================================================== */
/*  Static expansion (RunGroup → linear plan)                          */
/* ================================================================== */

/**
 * One leaf step in the flattened execution plan produced by
 * `expandRunGroups`. RunGroup steps NEVER appear here — they are
 * dereferenced into the steps they invoke. The `GroupPath` records
 * the call-stack of group names at expansion time so a UI can render
 * "Login → Submit Order → Type 'email'" without re-walking the tree.
 */
export interface ExpandedStep {
    readonly Step: StepRow;
    readonly GroupPath: ReadonlyArray<string>;
    readonly CallStackGroupIds: ReadonlyArray<number>;
    /** Position in the flattened plan, 0-based. */
    readonly PlanIndex: number;
}

export interface ExpansionSuccess {
    readonly Ok: true;
    readonly Steps: ReadonlyArray<ExpandedStep>;
    readonly GroupsVisited: number;
    readonly DisabledSkipped: number;
}

export interface ExpansionFailure {
    readonly Ok: false;
    readonly Reason: Exclude<RunGroupFailureReason, "LeafStepFailed">;
    readonly ReasonDetail: string;
    readonly FailedStepId: number | null;
    readonly FailedGroupId: number | null;
    readonly CallStack: ReadonlyArray<string>;
    /** Steps successfully expanded before the failure was hit. */
    readonly PartialSteps: ReadonlyArray<ExpandedStep>;
}

export type ExpansionResult = ExpansionSuccess | ExpansionFailure;

export interface ExpandOptions {
    readonly db: StepLibraryDb;
    readonly projectId: number;
    readonly rootGroupId: number;
    /**
     * When `true` (default), disabled steps are dropped from the plan.
     * When `false`, they remain in the plan with their `IsDisabled`
     * flag intact so a previewer can render them greyed-out.
     */
    readonly skipDisabled?: boolean;
}

/**
 * Pure resolver: walk a group tree, dereference every RunGroup step,
 * and return a linear plan. Shares the SAME safety guards as
 * `runGroup` (cycle, depth, missing target, cross-project) so a
 * preview cannot show a plan that the runner would refuse to execute.
 */
export function expandRunGroups(opts: ExpandOptions): ExpansionResult {
    const skipDisabled = opts.skipDisabled !== false;
    const plan: ExpandedStep[] = [];
    let groupsVisited = 0;
    let disabledSkipped = 0;

    const root = findGroup(opts.db, opts.rootGroupId);
    if (root === null) {
        return {
            Ok: false,
            Reason: "MissingRootGroup",
            ReasonDetail:
                `expandRunGroups: rootGroupId=${opts.rootGroupId} not found in StepGroup. ` +
                `Cannot build an execution plan for a group that does not exist.`,
            FailedStepId: null,
            FailedGroupId: opts.rootGroupId,
            CallStack: [],
            PartialSteps: plan,
        };
    }
    if (root.ProjectId !== opts.projectId) {
        return {
            Ok: false,
            Reason: "TargetNotInProject",
            ReasonDetail:
                `expandRunGroups: rootGroupId=${opts.rootGroupId} belongs to ProjectId=${root.ProjectId}, ` +
                `not the requested ProjectId=${opts.projectId}.`,
            FailedStepId: null,
            FailedGroupId: opts.rootGroupId,
            CallStack: [],
            PartialSteps: plan,
        };
    }

    const failure = walkForExpansion({
        db: opts.db,
        projectId: opts.projectId,
        group: root,
        callStackIds: [],
        callStackNames: [],
        plan,
        skipDisabled,
        onGroupEnter: () => { groupsVisited++; },
        onDisabledSkipped: () => { disabledSkipped++; },
    });

    if (failure !== null) return failure;

    return { Ok: true, Steps: plan, GroupsVisited: groupsVisited, DisabledSkipped: disabledSkipped };
}

interface ExpansionFrame {
    readonly db: StepLibraryDb;
    readonly projectId: number;
    readonly group: StepGroupRow;
    readonly callStackIds: ReadonlyArray<number>;
    readonly callStackNames: ReadonlyArray<string>;
    readonly plan: ExpandedStep[];
    readonly skipDisabled: boolean;
    readonly onGroupEnter: () => void;
    readonly onDisabledSkipped: () => void;
}

function walkForExpansion(frame: ExpansionFrame): ExpansionFailure | null {
    const newStackIds = [...frame.callStackIds, frame.group.StepGroupId];
    const newStackNames = [...frame.callStackNames, frame.group.Name];
    frame.onGroupEnter();

    for (const step of frame.db.listSteps(frame.group.StepGroupId)) {
        if (step.IsDisabled && frame.skipDisabled) {
            frame.onDisabledSkipped();
            continue;
        }

        if (step.StepKindId !== StepKindId.RunGroup) {
            frame.plan.push({
                Step: step,
                GroupPath: newStackNames,
                CallStackGroupIds: newStackIds,
                PlanIndex: frame.plan.length,
            });
            continue;
        }

        const guard = validateRunGroupTarget(frame, step, newStackIds, newStackNames);
        if (guard !== null) return guard;

        const target = findGroup(frame.db, step.TargetStepGroupId as number);
        if (target === null) {
            return {
                Ok: false,
                Reason: "MissingTargetGroup",
                ReasonDetail: `Internal: target vanished between validation and recursion (StepId=${step.StepId})`,
                FailedStepId: step.StepId,
                FailedGroupId: frame.group.StepGroupId,
                CallStack: newStackNames,
                PartialSteps: frame.plan,
            };
        }

        const nested = walkForExpansion({
            ...frame,
            group: target,
            callStackIds: newStackIds,
            callStackNames: newStackNames,
        });
        if (nested !== null) return nested;
    }

    return null;
}

function validateRunGroupTarget(
    frame: ExpansionFrame,
    step: StepRow,
    stackIds: ReadonlyArray<number>,
    stackNames: ReadonlyArray<string>,
): ExpansionFailure | null {
    if (step.TargetStepGroupId === null) {
        return {
            Ok: false,
            Reason: "MissingTargetGroup",
            ReasonDetail:
                `Step ${step.StepId} (kind=RunGroup) has TargetStepGroupId=NULL. Re-link or remove.`,
            FailedStepId: step.StepId,
            FailedGroupId: frame.group.StepGroupId,
            CallStack: stackNames,
            PartialSteps: frame.plan,
        };
    }
    const target = findGroup(frame.db, step.TargetStepGroupId);
    if (target === null) {
        return {
            Ok: false,
            Reason: "MissingTargetGroup",
            ReasonDetail:
                `Step ${step.StepId} targets StepGroupId=${step.TargetStepGroupId} but no such group exists.`,
            FailedStepId: step.StepId,
            FailedGroupId: frame.group.StepGroupId,
            CallStack: stackNames,
            PartialSteps: frame.plan,
        };
    }
    if (target.ProjectId !== frame.projectId) {
        return {
            Ok: false,
            Reason: "TargetNotInProject",
            ReasonDetail:
                `Step ${step.StepId} targets group "${target.Name}" in ProjectId=${target.ProjectId}; ` +
                `expansion is bound to ProjectId=${frame.projectId}.`,
            FailedStepId: step.StepId,
            FailedGroupId: frame.group.StepGroupId,
            CallStack: stackNames,
            PartialSteps: frame.plan,
        };
    }
    if (stackIds.includes(target.StepGroupId)) {
        const cycle = [...stackNames, target.Name].join(" → ");
        return {
            Ok: false,
            Reason: "RunGroupCycle",
            ReasonDetail: `RunGroup cycle detected during expansion: ${cycle}`,
            FailedStepId: step.StepId,
            FailedGroupId: frame.group.StepGroupId,
            CallStack: stackNames,
            PartialSteps: frame.plan,
        };
    }
    if (stackIds.length + 1 > MAX_RUN_GROUP_CALL_DEPTH) {
        return {
            Ok: false,
            Reason: "RunGroupDepthExceeded",
            ReasonDetail:
                `Expansion would reach depth ${stackIds.length + 1}, exceeding ` +
                `MAX_RUN_GROUP_CALL_DEPTH=${MAX_RUN_GROUP_CALL_DEPTH}.`,
            FailedStepId: step.StepId,
            FailedGroupId: frame.group.StepGroupId,
            CallStack: stackNames,
            PartialSteps: frame.plan,
        };
    }
    return null;
}

/* ================================================================== */
/*  Uniform FailureReport entrypoint                                   */
/* ================================================================== */

export interface ExecuteRunGroupSuccess {
    readonly Ok: true;
    readonly Result: RunGroupSuccess;
}

export interface ExecuteRunGroupFailure {
    readonly Ok: false;
    readonly Result: RunGroupFailure;
    /** Canonical FailureReport — synthesized for runner-level failures. */
    readonly FailureReport: FailureReport;
}

export type ExecuteRunGroupOutcome = ExecuteRunGroupSuccess | ExecuteRunGroupFailure;

/**
 * Production entrypoint. Wraps `runGroup` and guarantees that every
 * failure path produces a `FailureReport` with the canonical schema —
 * runner-level failures (cycle, depth, missing target, missing root,
 * cross-project) are mapped to synthesized reports tagged with
 * `Reason: "Unknown"` (the failure-logger enum has no dedicated codes
 * for graph-level errors) and a `ReasonDetail` that names the
 * specific runner reason for AI/log consumers.
 *
 * Use this from background callers; reach for raw `runGroup` only
 * when you need the discriminated `RunGroupFailure` for trace UIs.
 */
export async function executeRunGroup(opts: RunGroupOptions): Promise<ExecuteRunGroupOutcome> {
    const result = await runGroup(opts);
    if (result.Ok) return { Ok: true, Result: result };

    const report: FailureReport =
        result.FailureReport ?? buildRunnerLevelFailureReport(result, opts);

    return { Ok: false, Result: result, FailureReport: report };
}

function buildRunnerLevelFailureReport(
    failure: RunGroupFailure,
    opts: RunGroupOptions,
): FailureReport {
    const now = (opts.now ?? defaultNow)();
    return {
        Phase: "Replay",
        Message: `RunGroup failed: ${failure.Reason}`,
        Reason: "Unknown",
        ReasonDetail:
            `RunnerReason=${failure.Reason}. ${failure.ReasonDetail} ` +
            `CallStack=[${failure.CallStack.join(" → ")}]`,
        StackTrace: null,
        StepId: failure.FailedStepId,
        Index: null,
        StepKind: failure.FailedStepId === null ? null : "RunGroup",
        Selectors: [],
        Variables: [],
        DomContext: null,
        DataRow: null,
        ResolvedXPath: null,
        Timestamp: now.toISOString(),
        SourceFile: "src/background/recorder/step-library/run-group-runner.ts",
        Verbose: false,
        CapturedHtml: null,
        FormSnapshot: null,
    };
}

/**
 * Marco Extension — Step Library DB Schema
 *
 * Implements §5 of `spec/31-macro-recorder/16-step-group-library.md`
 * — pure SQL strings + the canonical `StepKindId` enum + the schema
 * version this codebase ships with. Kept separate from the wrapper so
 * tests can call `applySchema(db)` against an in-memory `sql.js`
 * Database without touching OPFS.
 *
 * ALL DDL is idempotent (`CREATE ... IF NOT EXISTS`) so running
 * `applySchema()` on an already-initialised DB is a no-op.
 *
 * @see spec/31-macro-recorder/16-step-group-library.md  §5
 * @see spec/31-macro-recorder/16-step-group-library-erd.md
 */

import type { Database } from "sql.js";

/** Schema version this codebase ships. Bumped whenever DDL changes. */
export const STEP_LIBRARY_SCHEMA_VERSION = 1;

/** Maximum nesting depth for StepGroup (per §2 of the spec). */
export const MAX_GROUP_NESTING_DEPTH = 8;

/** Maximum RunGroup call-stack depth at runtime (per §3.1 of the spec). */
export const MAX_RUN_GROUP_CALL_DEPTH = 16;

/**
 * Canonical lookup values for `StepKind`. The numeric IDs are the
 * single source of truth and MUST NOT change once shipped (existing
 * exported bundles reference them).
 */
export enum StepKindId {
    Click = 1,
    Type = 2,
    Select = 3,
    JsInline = 4,
    Wait = 5,
    /** New in §5.3 — invokes another group inline. */
    RunGroup = 6,
    /**
     * AutoHotkey-style chord macro. Payload shape:
     * `{ "Keys": ["Ctrl+S","Tab","Enter"], "WaitMs": 500 }`.
     * Each entry in `Keys` is a single chord dispatched in order; an
     * optional `WaitMs` pauses after the final chord. The replayer
     * translates each chord into KeyboardEvent dispatches.
     */
    Hotkey = 7,
    /**
     * Spec 19 §1 — navigating click that opens or focuses a tab by
     * URL pattern. Payload mirrors `UrlTabClickParams` (PascalCase
     * keys: UrlPattern, UrlMatch, Mode, Selector?, SelectorKind?,
     * TimeoutMs?, DirectOpen?, Url?).
     */
    UrlTabClick = 9,
}

const STEP_KIND_SEED: ReadonlyArray<{ Id: StepKindId; Name: string }> = [
    { Id: StepKindId.Click,       Name: "Click" },
    { Id: StepKindId.Type,        Name: "Type" },
    { Id: StepKindId.Select,      Name: "Select" },
    { Id: StepKindId.JsInline,    Name: "JsInline" },
    { Id: StepKindId.Wait,        Name: "Wait" },
    { Id: StepKindId.RunGroup,    Name: "RunGroup" },
    { Id: StepKindId.Hotkey,      Name: "Hotkey" },
    { Id: StepKindId.UrlTabClick, Name: "UrlTabClick" },
];

/* ------------------------------------------------------------------ */
/*  DDL                                                                */
/* ------------------------------------------------------------------ */

const DDL_PROJECT = `
CREATE TABLE IF NOT EXISTS Project (
    ProjectId         INTEGER PRIMARY KEY AUTOINCREMENT,
    ProjectExternalId TEXT    NOT NULL UNIQUE,
    Name              VARCHAR(120) NOT NULL,
    CreatedAt         TEXT    NOT NULL DEFAULT (datetime('now')),
    UpdatedAt         TEXT    NOT NULL DEFAULT (datetime('now'))
);
CREATE INDEX IF NOT EXISTS IxProjectExternal ON Project (ProjectExternalId);
`;

const DDL_STEP_GROUP = `
CREATE TABLE IF NOT EXISTS StepGroup (
    StepGroupId       INTEGER PRIMARY KEY AUTOINCREMENT,
    ProjectId         INTEGER NOT NULL,
    ParentStepGroupId INTEGER NULL,
    Name              VARCHAR(120) NOT NULL,
    Description       TEXT NULL,
    OrderIndex        INTEGER NOT NULL DEFAULT 0,
    IsArchived        TINYINT NOT NULL DEFAULT 0,
    CreatedAt         TEXT NOT NULL DEFAULT (datetime('now')),
    UpdatedAt         TEXT NOT NULL DEFAULT (datetime('now')),
    FOREIGN KEY (ProjectId) REFERENCES Project (ProjectId) ON DELETE CASCADE,
    FOREIGN KEY (ParentStepGroupId) REFERENCES StepGroup (StepGroupId) ON DELETE CASCADE
);
CREATE INDEX IF NOT EXISTS IxStepGroupProjectParent
    ON StepGroup (ProjectId, ParentStepGroupId);
CREATE UNIQUE INDEX IF NOT EXISTS IxStepGroupSiblingNameUnique
    ON StepGroup (ProjectId, IFNULL(ParentStepGroupId, -1), lower(Name));
`;

/**
 * Reject self-parenting and cross-project parenting.
 * Reject inserts/updates that would push the descendant chain to
 * depth > MAX_GROUP_NESTING_DEPTH (8). The depth count is "number of
 * ancestors above this row + 1", so the root group has depth 1.
 */
const DDL_STEP_GROUP_TRIGGERS = `
CREATE TRIGGER IF NOT EXISTS TrgStepGroupNoSelfParentInsert
BEFORE INSERT ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL AND NEW.ParentStepGroupId = NEW.StepGroupId
BEGIN
    SELECT RAISE(ABORT, 'StepGroup cannot be its own parent');
END;

CREATE TRIGGER IF NOT EXISTS TrgStepGroupNoSelfParentUpdate
BEFORE UPDATE OF ParentStepGroupId ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL AND NEW.ParentStepGroupId = NEW.StepGroupId
BEGIN
    SELECT RAISE(ABORT, 'StepGroup cannot be its own parent');
END;

CREATE TRIGGER IF NOT EXISTS TrgStepGroupSameProjectParentInsert
BEFORE INSERT ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL
 AND (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.ParentStepGroupId) <> NEW.ProjectId
BEGIN
    SELECT RAISE(ABORT, 'ParentStepGroup must belong to the same Project');
END;

CREATE TRIGGER IF NOT EXISTS TrgStepGroupSameProjectParentUpdate
BEFORE UPDATE OF ParentStepGroupId, ProjectId ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL
 AND (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.ParentStepGroupId) <> NEW.ProjectId
BEGIN
    SELECT RAISE(ABORT, 'ParentStepGroup must belong to the same Project');
END;

-- Recursive CTE walks up to count ancestor depth. Reject if depth >= MAX_GROUP_NESTING_DEPTH.
CREATE TRIGGER IF NOT EXISTS TrgStepGroupMaxDepthInsert
BEFORE INSERT ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL AND (
    WITH RECURSIVE Ancestors(Id, Depth) AS (
        SELECT NEW.ParentStepGroupId, 1
        UNION ALL
        SELECT g.ParentStepGroupId, a.Depth + 1
        FROM StepGroup g JOIN Ancestors a ON g.StepGroupId = a.Id
        WHERE g.ParentStepGroupId IS NOT NULL
    )
    SELECT MAX(Depth) FROM Ancestors
) >= ${MAX_GROUP_NESTING_DEPTH}
BEGIN
    SELECT RAISE(ABORT, 'MaxNestingDepthExceeded: StepGroup tree exceeds depth ${MAX_GROUP_NESTING_DEPTH}');
END;

CREATE TRIGGER IF NOT EXISTS TrgStepGroupMaxDepthUpdate
BEFORE UPDATE OF ParentStepGroupId ON StepGroup
WHEN NEW.ParentStepGroupId IS NOT NULL AND (
    WITH RECURSIVE Ancestors(Id, Depth) AS (
        SELECT NEW.ParentStepGroupId, 1
        UNION ALL
        SELECT g.ParentStepGroupId, a.Depth + 1
        FROM StepGroup g JOIN Ancestors a ON g.StepGroupId = a.Id
        WHERE g.ParentStepGroupId IS NOT NULL
    )
    SELECT MAX(Depth) FROM Ancestors
) >= ${MAX_GROUP_NESTING_DEPTH}
BEGIN
    SELECT RAISE(ABORT, 'MaxNestingDepthExceeded: StepGroup tree exceeds depth ${MAX_GROUP_NESTING_DEPTH}');
END;
`;

const DDL_STEP_KIND = `
CREATE TABLE IF NOT EXISTS StepKind (
    StepKindId TINYINT PRIMARY KEY,
    Name       VARCHAR(20) NOT NULL UNIQUE
);
`;

const DDL_STEP = `
CREATE TABLE IF NOT EXISTS Step (
    StepId            INTEGER PRIMARY KEY AUTOINCREMENT,
    StepGroupId       INTEGER NOT NULL,
    OrderIndex        INTEGER NOT NULL DEFAULT 0,
    StepKindId        TINYINT NOT NULL,
    Label             VARCHAR(160) NULL,
    PayloadJson       TEXT NULL,
    TargetStepGroupId INTEGER NULL,
    IsDisabled        TINYINT NOT NULL DEFAULT 0,
    CreatedAt         TEXT NOT NULL DEFAULT (datetime('now')),
    UpdatedAt         TEXT NOT NULL DEFAULT (datetime('now')),
    FOREIGN KEY (StepGroupId) REFERENCES StepGroup (StepGroupId) ON DELETE CASCADE,
    FOREIGN KEY (StepKindId) REFERENCES StepKind (StepKindId),
    FOREIGN KEY (TargetStepGroupId) REFERENCES StepGroup (StepGroupId) ON DELETE SET NULL,
    -- CkStepRunGroupTarget: TargetStepGroupId NOT NULL iff RunGroup, else NULL.
    CHECK (
        (StepKindId = ${StepKindId.RunGroup} AND TargetStepGroupId IS NOT NULL)
        OR (StepKindId <> ${StepKindId.RunGroup} AND TargetStepGroupId IS NULL)
    )
);
CREATE INDEX IF NOT EXISTS IxStepGroupOrder ON Step (StepGroupId, OrderIndex);
CREATE INDEX IF NOT EXISTS IxStepTargetGroup ON Step (TargetStepGroupId);
`;

const DDL_STEP_TRIGGERS = `
CREATE TRIGGER IF NOT EXISTS TrgStepRunGroupSameProjectInsert
BEFORE INSERT ON Step
WHEN NEW.TargetStepGroupId IS NOT NULL
 AND (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.TargetStepGroupId)
     <> (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.StepGroupId)
BEGIN
    SELECT RAISE(ABORT, 'TargetStepGroupId must belong to the same Project as StepGroupId');
END;

CREATE TRIGGER IF NOT EXISTS TrgStepRunGroupSameProjectUpdate
BEFORE UPDATE OF TargetStepGroupId, StepGroupId ON Step
WHEN NEW.TargetStepGroupId IS NOT NULL
 AND (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.TargetStepGroupId)
     <> (SELECT ProjectId FROM StepGroup WHERE StepGroupId = NEW.StepGroupId)
BEGIN
    SELECT RAISE(ABORT, 'TargetStepGroupId must belong to the same Project as StepGroupId');
END;
`;

const DDL_SCHEMA_MIGRATION = `
CREATE TABLE IF NOT EXISTS SchemaMigration (
    Version     INTEGER PRIMARY KEY,
    Description TEXT NOT NULL,
    AppliedAt   TEXT NOT NULL DEFAULT (datetime('now'))
);
`;

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Apply (or upgrade to) the canonical schema. Idempotent — safe to
 * call on a fresh DB or one already at version
 * `STEP_LIBRARY_SCHEMA_VERSION`. Throws if the on-disk version is
 * NEWER than this codebase supports (caller MUST surface as a Code
 * Red error per mem://constraints/file-path-error-logging-code-red).
 */
export function applySchema(db: Database): void {
    db.exec("PRAGMA foreign_keys = ON;");

    const currentVersion = readUserVersion(db);
    if (currentVersion > STEP_LIBRARY_SCHEMA_VERSION) {
        throw new Error(
            `step-library DB at user_version=${currentVersion} but this build only supports ${STEP_LIBRARY_SCHEMA_VERSION}. ` +
            `Refusing to open — bundle was produced by a newer extension.`,
        );
    }

    db.exec("BEGIN;");
    try {
        db.exec(DDL_PROJECT);
        db.exec(DDL_STEP_GROUP);
        db.exec(DDL_STEP_GROUP_TRIGGERS);
        db.exec(DDL_STEP_KIND);
        db.exec(DDL_STEP);
        db.exec(DDL_STEP_TRIGGERS);
        db.exec(DDL_SCHEMA_MIGRATION);

        // Seed StepKind lookup (idempotent — INSERT OR IGNORE).
        const insertKind = db.prepare(
            "INSERT OR IGNORE INTO StepKind (StepKindId, Name) VALUES (?, ?);",
        );
        try {
            for (const k of STEP_KIND_SEED) {
                insertKind.run([k.Id, k.Name]);
            }
        } finally {
            insertKind.free();
        }

        if (currentVersion < STEP_LIBRARY_SCHEMA_VERSION) {
            db.exec(
                `INSERT OR IGNORE INTO SchemaMigration (Version, Description) VALUES (` +
                `${STEP_LIBRARY_SCHEMA_VERSION}, 'initial step-library schema');`,
            );
            db.exec(`PRAGMA user_version = ${STEP_LIBRARY_SCHEMA_VERSION};`);
        }
        db.exec("COMMIT;");
    } catch (e) {
        db.exec("ROLLBACK;");
        throw e;
    }
}

export function readUserVersion(db: Database): number {
    const res = db.exec("PRAGMA user_version;");
    if (res.length === 0 || res[0].values.length === 0) return 0;
    const v = res[0].values[0][0];
    return typeof v === "number" ? v : 0;
}

/**
 * Marco Extension — Post-Step Wait-For-Selector
 *
 * Per-step "wait for this selector to satisfy a condition before moving
 * to the next step" feature. Lives in the step-library layer because:
 *   - The pure helpers (detect, validate, evaluate, wait) are unit-
 *     testable against a stub document — no chrome.* needed.
 *   - The recorder's leaf executor (background worker) only needs to
 *     load the config for the just-finished StepId and call
 *     `waitForSelector` with a real `document`.
 *
 * Storage shape (`localStorage` key `marco.step-library.wait.v1`):
 *   `{ [stepId: string]: WaitConfig }`
 *
 * Auto-detection rule:
 *   - "/...", "(/...", "(./...", "./..." or anything containing "//"
 *     ⇒ XPath
 *   - everything else ⇒ CSS
 *   The user can pin `Kind` to override the heuristic; loadStepWait()
 *   never re-detects a saved row.
 *
 * Conditions:
 *   - "Appears"     → at least one matching element (default)
 *   - "Disappears"  → zero matching elements
 *   - "Visible"     → at least one match AND it has layout (offset>0)
 *
 * @see ./group-inputs.ts        — sibling localStorage convention.
 * @see .lovable/question-and-ambiguity/07-wait-for-selector.md
 */

const STORAGE_KEY = "marco.step-library.wait.v1";
const DEFAULT_TIMEOUT_MS = 5_000;
const MIN_TIMEOUT_MS = 250;
const MAX_TIMEOUT_MS = 60_000;
const POLL_INTERVAL_MS = 100;

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export type SelectorKind = "Css" | "XPath";
export type WaitCondition = "Appears" | "Disappears" | "Visible";

export interface WaitConfig {
    readonly Selector: string;
    readonly Kind: SelectorKind;
    readonly Condition: WaitCondition;
    readonly TimeoutMs: number;
}

export const DEFAULT_WAIT_CONFIG: Readonly<Omit<WaitConfig, "Selector">> = Object.freeze({
    Kind: "Css",
    Condition: "Appears",
    TimeoutMs: DEFAULT_TIMEOUT_MS,
});

/* ------------------------------------------------------------------ */
/*  Auto-detection                                                     */
/* ------------------------------------------------------------------ */

const XPATH_LEADING_RE = /^\s*(?:\(\s*)?\.?\//;

/**
 * Heuristic: returns "XPath" only when the input unambiguously looks
 * like an XPath expression. Everything else is treated as CSS so the
 * common case ("button.primary", "#login", "div > span") works without
 * the user thinking about it.
 */
export function detectSelectorKind(raw: string): SelectorKind {
    const s = raw.trim();
    if (s.length === 0) return "Css";
    if (XPATH_LEADING_RE.test(s)) return "XPath";
    if (s.includes("//")) return "XPath";
    return "Css";
}

/* ------------------------------------------------------------------ */
/*  Validation                                                         */
/* ------------------------------------------------------------------ */

export type ValidationResult =
    | { readonly Ok: true; readonly Kind: SelectorKind }
    | { readonly Ok: false; readonly Reason: string };

/** Optional document handle so tests can pass a stub. */
export interface ValidationDeps {
    readonly doc?: Document | null;
    /** When true, force-skip the live document check (useful in non-DOM tests). */
    readonly skipLiveCheck?: boolean;
}

/**
 * Validate a selector. When a real `document` is available we ask the
 * browser to compile the expression — this catches issues that regex
 * alone can't see (e.g. unbalanced brackets in XPath, malformed CSS
 * pseudo-class arguments). Without a document we fall back to a
 * structural check.
 */
export function validateSelector(
    raw: string,
    kind: SelectorKind,
    deps: ValidationDeps = {},
): ValidationResult {
    const s = raw.trim();
    if (s.length === 0) {
        return { Ok: false, Reason: "Selector is empty." };
    }

    const doc = deps.doc ?? (typeof document !== "undefined" ? document : null);
    const useLive = doc !== null && deps.skipLiveCheck !== true;

    if (kind === "Css") {
        if (useLive) {
            try {
                doc.querySelector(s);
            } catch (e) {
                const detail = e instanceof Error ? e.message : "Unknown CSS parse error";
                return { Ok: false, Reason: `Invalid CSS selector: ${detail}` };
            }
        } else {
            // Lightweight structural sanity check.
            if (/[<>]{2,}/.test(s)) {
                return { Ok: false, Reason: "Invalid CSS selector (suspicious characters)." };
            }
        }
        return { Ok: true, Kind: "Css" };
    }

    // XPath
    if (!XPATH_LEADING_RE.test(s) && !s.includes("//")) {
        return {
            Ok: false,
            Reason: "XPath should start with '/', './', '(/', '(./' or contain '//'.",
        };
    }
    if (useLive && typeof doc.evaluate === "function") {
        try {
            doc.evaluate(s, doc, null, /* ANY_TYPE */ 0, null);
        } catch (e) {
            const detail = e instanceof Error ? e.message : "Unknown XPath parse error";
            return { Ok: false, Reason: `Invalid XPath: ${detail}` };
        }
    }
    return { Ok: true, Kind: "XPath" };
}

/* ------------------------------------------------------------------ */
/*  Storage                                                            */
/* ------------------------------------------------------------------ */

interface RawStore { readonly [stepId: string]: WaitConfig }

function isPlainObject(v: unknown): v is Record<string, unknown> {
    return typeof v === "object" && v !== null && !Array.isArray(v);
}

function clampTimeout(raw: unknown): number {
    const n = typeof raw === "number" && Number.isFinite(raw) ? raw : DEFAULT_TIMEOUT_MS;
    return Math.min(MAX_TIMEOUT_MS, Math.max(MIN_TIMEOUT_MS, Math.round(n)));
}

function sanitiseRow(raw: unknown): WaitConfig | null {
    if (!isPlainObject(raw)) return null;
    const sel = typeof raw.Selector === "string" ? raw.Selector.trim() : "";
    if (sel.length === 0) return null;
    const kind: SelectorKind = raw.Kind === "XPath" ? "XPath" : raw.Kind === "Css" ? "Css" : detectSelectorKind(sel);
    const condition: WaitCondition =
        raw.Condition === "Disappears" ? "Disappears"
            : raw.Condition === "Visible" ? "Visible"
                : "Appears";
    return {
        Selector: sel,
        Kind: kind,
        Condition: condition,
        TimeoutMs: clampTimeout(raw.TimeoutMs),
    };
}

function safeReadStore(): RawStore {
    if (typeof localStorage === "undefined") return {};
    try {
        const raw = localStorage.getItem(STORAGE_KEY);
        if (raw === null) return {};
        const parsed: unknown = JSON.parse(raw);
        if (!isPlainObject(parsed)) return {};
        const out: Record<string, WaitConfig> = {};
        for (const [k, v] of Object.entries(parsed)) {
            const sanitised = sanitiseRow(v);
            if (sanitised !== null && /^\d+$/.test(k)) {
                out[k] = sanitised;
            }
        }
        return out;
    } catch {
        return {};
    }
}

function safeWriteStore(store: RawStore): void {
    if (typeof localStorage === "undefined") return;
    try {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
    } catch (err) {
        console.warn("step-wait: localStorage write failed", err);
    }
}

export function readAllStepWaits(): ReadonlyMap<number, WaitConfig> {
    const store = safeReadStore();
    const map = new Map<number, WaitConfig>();
    for (const [k, v] of Object.entries(store)) {
        const id = Number(k);
        if (Number.isInteger(id) && id > 0) map.set(id, v);
    }
    return map;
}

export function readStepWait(stepId: number): WaitConfig | null {
    const store = safeReadStore();
    const v = store[String(stepId)];
    return v === undefined ? null : v;
}

export function writeStepWait(stepId: number, config: WaitConfig): WaitConfig {
    if (!Number.isInteger(stepId) || stepId <= 0) {
        throw new Error(
            `writeStepWait: stepId must be a positive integer, got ${String(stepId)}.`,
        );
    }
    const sanitised = sanitiseRow({
        Selector: config.Selector,
        Kind: config.Kind,
        Condition: config.Condition,
        TimeoutMs: config.TimeoutMs,
    });
    if (sanitised === null) {
        throw new Error("writeStepWait: selector is required and must be non-empty.");
    }
    const store = { ...safeReadStore() };
    store[String(stepId)] = sanitised;
    safeWriteStore(store);
    return sanitised;
}

export function clearStepWait(stepId: number): void {
    const store = { ...safeReadStore() };
    if (Object.prototype.hasOwnProperty.call(store, String(stepId))) {
        delete store[String(stepId)];
        safeWriteStore(store);
    }
}

export function clearAllStepWaits(): void {
    safeWriteStore({});
}

/* ------------------------------------------------------------------ */
/*  Live evaluation + wait loop                                        */
/* ------------------------------------------------------------------ */

/** Tiny structural element shape — matches both real DOM and stubs. */
export interface ElementLike {
    readonly offsetWidth?: number;
    readonly offsetHeight?: number;
    readonly getClientRects?: () => { readonly length: number };
}

export interface EvaluateDeps {
    readonly doc?: Document | null;
    readonly root?: ParentNode | null;
}

function evaluateXPath(
    expr: string,
    doc: Document,
    root: ParentNode,
): ReadonlyArray<ElementLike> {
    if (typeof doc.evaluate !== "function") return [];
    const it = doc.evaluate(
        expr,
        root as Node,
        null,
        /* ORDERED_NODE_SNAPSHOT_TYPE */ 7,
        null,
    );
    const out: ElementLike[] = [];
    for (let i = 0; i < it.snapshotLength; i++) {
        const node = it.snapshotItem(i);
        if (node !== null) out.push(node as unknown as ElementLike);
    }
    return out;
}

function evaluateCss(
    expr: string,
    root: ParentNode,
): ReadonlyArray<ElementLike> {
    const list = root.querySelectorAll(expr);
    const out: ElementLike[] = [];
    list.forEach((el) => out.push(el as unknown as ElementLike));
    return out;
}

/** Returns the matching elements for a config in the current document. */
export function evaluateSelector(
    config: Pick<WaitConfig, "Selector" | "Kind">,
    deps: EvaluateDeps = {},
): ReadonlyArray<ElementLike> {
    const doc = deps.doc ?? (typeof document !== "undefined" ? document : null);
    const root = deps.root ?? doc;
    if (doc === null || root === null) return [];
    if (config.Kind === "XPath") return evaluateXPath(config.Selector, doc, root);
    return evaluateCss(config.Selector, root);
}

function isElementVisible(el: ElementLike): boolean {
    if (typeof el.offsetWidth === "number" && typeof el.offsetHeight === "number") {
        if (el.offsetWidth > 0 || el.offsetHeight > 0) return true;
    }
    if (typeof el.getClientRects === "function") {
        const rects = el.getClientRects();
        if (rects.length > 0) return true;
    }
    return false;
}

/** Returns `true` when the predicate for the configured condition holds. */
export function isConditionSatisfied(
    config: Pick<WaitConfig, "Condition">,
    matches: ReadonlyArray<ElementLike>,
): boolean {
    switch (config.Condition) {
        case "Appears":     return matches.length > 0;
        case "Disappears":  return matches.length === 0;
        case "Visible":     return matches.some(isElementVisible);
    }
}

/* -------------------- Wait loop -------------------- */

export interface WaitDeps extends EvaluateDeps {
    /** Override the polling interval (default 100 ms). Useful for tests. */
    readonly pollIntervalMs?: number;
    /** Inject the clock for deterministic tests. */
    readonly now?: () => number;
    /** Inject the sleep primitive for deterministic tests. */
    readonly sleep?: (ms: number) => Promise<void>;
}

export type WaitOutcome =
    | {
        readonly Ok: true;
        readonly DurationMs: number;
        readonly MatchCount: number;
    }
    | {
        readonly Ok: false;
        readonly Reason: "Timeout" | "InvalidSelector";
        readonly DurationMs: number;
        readonly Detail: string;
    };

const defaultSleep = (ms: number): Promise<void> =>
    new Promise<void>((resolve) => {
        let timeoutId: ReturnType<typeof setTimeout> | null = null;
        timeoutId = setTimeout(() => {
            if (timeoutId !== null) {
                clearTimeout(timeoutId);
                timeoutId = null;
            }
            resolve();
        }, ms);
    });

/**
 * Polls until the configured condition is satisfied or the timeout
 * elapses. Always resolves — never throws.
 */
export async function waitForSelector(
    config: WaitConfig,
    deps: WaitDeps = {},
): Promise<WaitOutcome> {
    const now = deps.now ?? (() => Date.now());
    const sleep = deps.sleep ?? defaultSleep;
    const pollMs = Math.max(10, deps.pollIntervalMs ?? POLL_INTERVAL_MS);

    const validation = validateSelector(config.Selector, config.Kind, { doc: deps.doc ?? null });
    if (!validation.Ok) {
        return { Ok: false, Reason: "InvalidSelector", DurationMs: 0, Detail: validation.Reason };
    }

    const startedAt = now();
    let matches: ReadonlyArray<ElementLike> = [];
    while (true) {
        try {
            matches = evaluateSelector(config, deps);
        } catch (e) {
            const detail = e instanceof Error ? e.message : "Unknown evaluation error";
            return {
                Ok: false,
                Reason: "InvalidSelector",
                DurationMs: now() - startedAt,
                Detail: detail,
            };
        }
        if (isConditionSatisfied(config, matches)) {
            return { Ok: true, DurationMs: now() - startedAt, MatchCount: matches.length };
        }
        const elapsed = now() - startedAt;
        if (elapsed >= config.TimeoutMs) {
            return {
                Ok: false,
                Reason: "Timeout",
                DurationMs: elapsed,
                Detail:
                    `Condition "${config.Condition}" not met within ${config.TimeoutMs} ms ` +
                    `(${matches.length} match${matches.length === 1 ? "" : "es"}).`,
            };
        }
        await sleep(Math.min(pollMs, config.TimeoutMs - elapsed));
    }
}

/**
 * Marco Extension — UrlTabClick Step (Spec 19 §1)
 *
 * A capture/replay step kind (`StepKindId = 9`) that resolves a click
 * action against a tab whose URL matches a declared pattern, choosing
 * between three behaviours based on the current workspace tabs:
 *
 *   - `OpenNew`        — always open a new tab.
 *   - `FocusExisting`  — focus a matching tab; fail if none exists.
 *   - `OpenOrFocus`    — focus a matching tab if present, else open a new one.
 *
 * Pure module: no chrome.* / DOM dependencies. The runner injects a
 * `TabsAdapter` so this file stays unit-testable. Failures are returned as
 * structured objects per the project failure-diagnostics standard.
 *
 * @see spec/31-macro-recorder/19-url-tabs-appearance-waits-conditions.md §1
 * @see mem://standards/verbose-logging-and-failure-diagnostics
 */

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type UrlMatchDialect = "Exact" | "Prefix" | "Glob" | "Regex";
export type UrlTabClickMode = "OpenNew" | "FocusExisting" | "OpenOrFocus";
export type SelectorKindOption = "Auto" | "XPath" | "Css";

export interface UrlTabClickParams {
    readonly UrlPattern: string;
    readonly UrlMatch: UrlMatchDialect;
    readonly Mode: UrlTabClickMode;
    readonly Selector?: string;
    readonly SelectorKind?: SelectorKindOption;
    readonly TimeoutMs?: number;
    readonly DirectOpen?: boolean;
    readonly Url?: string;
}

export type UrlTabClickReason =
    | "Ok"
    | "TabNotFound"
    | "InvalidUrlPattern"
    | "SelectorNotFound"
    | "UrlPatternMismatch"
    | "UrlTabClickTimeout"
    | "BadParams";

export interface UrlTabClickResult {
    readonly Reason: UrlTabClickReason;
    readonly ResolvedTabId?: number;
    readonly ResolvedUrl?: string;
    readonly Pattern: string;
    readonly Dialect: UrlMatchDialect;
    readonly Mode: UrlTabClickMode;
    readonly DurationMs: number;
    readonly OpenedNewTab: boolean;
    readonly Detail?: string;
}

export interface TabRef {
    readonly Id: number;
    readonly Url: string;
}

export interface TabsAdapter {
    listTabs(): Promise<ReadonlyArray<TabRef>>;
    focusTab(id: number): Promise<void>;
    createTab(url: string): Promise<TabRef>;
    /** Dispatch the captured click; returns the URL of the resulting tab. */
    dispatchClick?(selector: string, kind: "Css" | "XPath"): Promise<TabRef>;
    /** Wait for an updated tab whose URL matches `predicate` within deadline. */
    waitForMatchingTab(
        predicate: (url: string) => boolean,
        deadlineMs: number,
    ): Promise<TabRef | null>;
}

export interface ExecuteUrlTabClickInit {
    readonly Params: UrlTabClickParams;
    readonly Tabs: TabsAdapter;
    readonly NowMs?: () => number;
}

const DEFAULT_TIMEOUT_MS = 15_000;

/* ------------------------------------------------------------------ */
/*  Pattern matching                                                   */
/* ------------------------------------------------------------------ */

interface CompiledPattern {
    readonly Ok: true;
    readonly Test: (url: string) => boolean;
}
interface CompiledPatternError {
    readonly Ok: false;
    readonly Detail: string;
}
export type CompileResult = CompiledPattern | CompiledPatternError;

const SCHEME_HOST_RE = /^([a-z][a-z0-9+.-]*:\/\/)([^/?#]+)(.*)$/i;

function splitForCaseFold(url: string): { readonly Lead: string; readonly Tail: string } {
    const match = SCHEME_HOST_RE.exec(url);
    if (!match) return { Lead: "", Tail: url };
    const lead = (match[1] + match[2]).toLowerCase();
    return { Lead: lead, Tail: match[3] ?? "" };
}

function stripTrailingSlash(s: string): string {
    return s.endsWith("/") ? s.slice(0, -1) : s;
}

function globToRegex(pattern: string): RegExp {
    let out = "^";
    let i = 0;
    while (i < pattern.length) {
        const ch = pattern[i];
        if (ch === "*") {
            if (pattern[i + 1] === "*") {
                out += ".*";
                i += 2;
            } else {
                out += "[^/]*";
                i += 1;
            }
        } else {
            out += ch.replace(/[.+?^${}()|[\]\\]/g, "\\$&");
            i += 1;
        }
    }
    out += "$";
    return new RegExp(out);
}

export function compileUrlPattern(
    pattern: string,
    dialect: UrlMatchDialect,
): CompileResult {
    if (pattern === "") {
        return { Ok: false, Detail: "UrlPattern is empty" };
    }

    switch (dialect) {
        case "Exact": {
            const want = stripTrailingSlash(pattern);
            const wantSplit = splitForCaseFold(want);
            return {
                Ok: true,
                Test: (url) => {
                    const got = stripTrailingSlash(url);
                    const gotSplit = splitForCaseFold(got);
                    return (
                        gotSplit.Lead === wantSplit.Lead &&
                        gotSplit.Tail === wantSplit.Tail
                    );
                },
            };
        }
        case "Prefix": {
            const wantSplit = splitForCaseFold(pattern);
            return {
                Ok: true,
                Test: (url) => {
                    const gotSplit = splitForCaseFold(url);
                    if (wantSplit.Lead !== "") {
                        if (!gotSplit.Lead.startsWith(wantSplit.Lead)) return false;
                        return gotSplit.Tail.startsWith(wantSplit.Tail);
                    }
                    return url.startsWith(pattern);
                },
            };
        }
        case "Glob": {
            const split = splitForCaseFold(pattern);
            if (split.Lead === "") {
                const re = globToRegex(pattern);
                return { Ok: true, Test: (url) => re.test(url) };
            }
            const tailRe = globToRegex(split.Tail);
            return {
                Ok: true,
                Test: (url) => {
                    const gotSplit = splitForCaseFold(url);
                    return (
                        gotSplit.Lead === split.Lead && tailRe.test(gotSplit.Tail)
                    );
                },
            };
        }
        case "Regex": {
            try {
                const re = new RegExp(pattern);
                return { Ok: true, Test: (url) => re.test(url) };
            } catch (err) {
                const detail = err instanceof Error ? err.message : "regex compile failed";
                return { Ok: false, Detail: detail };
            }
        }
        default: {
            const exhaust: never = dialect;
            return { Ok: false, Detail: `unknown dialect ${String(exhaust)}` };
        }
    }
}

/* ------------------------------------------------------------------ */
/*  Save-time validation                                               */
/* ------------------------------------------------------------------ */

export interface ValidationError {
    readonly Reason: "InvalidUrlPattern" | "BadParams";
    readonly Detail: string;
}

export function validateUrlTabClickParams(
    params: UrlTabClickParams,
): ValidationError | null {
    if (params.DirectOpen === true) {
        if (params.Mode !== "OpenNew") {
            return {
                Reason: "BadParams",
                Detail: "DirectOpen requires Mode='OpenNew'",
            };
        }
        if (params.Url === undefined || params.Url === "") {
            return {
                Reason: "InvalidUrlPattern",
                Detail: "DirectOpen requires a literal Url",
            };
        }
    }
    if (params.Mode !== "OpenNew" && (params.Selector === undefined || params.Selector === "")) {
        if (params.DirectOpen !== true) {
            // FocusExisting / OpenOrFocus may operate without a selector when
            // the runner just needs to focus by URL — selector is optional.
        }
    }
    if (params.TimeoutMs !== undefined && params.TimeoutMs < 0) {
        return { Reason: "BadParams", Detail: "TimeoutMs must be ≥ 0" };
    }
    const compiled = compileUrlPattern(params.UrlPattern, params.UrlMatch);
    if (!compiled.Ok) {
        return { Reason: "InvalidUrlPattern", Detail: compiled.Detail };
    }
    return null;
}

/* ------------------------------------------------------------------ */
/*  Capture-time pattern derivation                                    */
/* ------------------------------------------------------------------ */

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

/**
 * Derive a default `Glob` pattern from an observed URL: numeric segments
 * and UUIDs become `*`, query string is stripped. Used at capture time
 * (AC-19.1.1 / 19.1.2).
 */
export function deriveGlobPattern(url: string): string {
    const noQuery = url.split("?")[0].split("#")[0];
    const split = splitForCaseFold(noQuery);
    if (split.Lead === "") return noQuery;
    const segments = split.Tail.split("/").map((seg) => {
        if (seg === "") return seg;
        if (/^\d+$/.test(seg)) return "*";
        if (UUID_RE.test(seg)) return "*";
        return seg;
    });
    return split.Lead + segments.join("/");
}

export interface CaptureClickContext {
    readonly Tag: string;                        // lowercase tag
    readonly Target?: string;                    // anchor `target` attribute
    readonly Href?: string;                      // resolved href
    readonly LocationOrigin: string;             // current page origin
    readonly OpenedTabUrl?: string;              // observed tab url, if any
    readonly WindowOpenCalled: boolean;          // capture proxy fired
}

/**
 * Returns true when a click should be persisted as `UrlTabClick`
 * (StepKindId = 9) instead of plain `Click`. Mirrors AC-19.1.1/2 and
 * spec §1.4 detection rules 1–4.
 */
export function shouldRecordAsUrlTabClick(ctx: CaptureClickContext): boolean {
    if (ctx.Tag === "a" && ctx.Target === "_blank") return true;
    if (ctx.Tag === "a" && ctx.Href !== undefined && ctx.Href !== "") {
        try {
            const dest = new URL(ctx.Href);
            const here = new URL(ctx.LocationOrigin);
            if (dest.origin !== here.origin) return true;
        } catch { // allow-swallow: malformed href (e.g. "javascript:", relative-only) — treat as same-origin and fall through to remaining detection rules.
            /* malformed href — fall through */
        }
    }
    if (ctx.WindowOpenCalled) return true;
    if (ctx.OpenedTabUrl !== undefined && ctx.OpenedTabUrl !== "") return true;
    return false;
}

/* ------------------------------------------------------------------ */
/*  Replay                                                              */
/* ------------------------------------------------------------------ */

function selectorKind(params: UrlTabClickParams): "Css" | "XPath" {
    const kind = params.SelectorKind ?? "Auto";
    if (kind === "XPath") return "XPath";
    if (kind === "Css") return "Css";
    const sel = (params.Selector ?? "").trim();
    if (sel.startsWith("/") || sel.startsWith("(")) return "XPath";
    return "Css";
}

export async function executeUrlTabClick(
    init: ExecuteUrlTabClickInit,
): Promise<UrlTabClickResult> {
    const now = init.NowMs ?? (() => Date.now());
    const startedAt = now();
    const params = init.Params;
    const timeoutMs = params.TimeoutMs ?? DEFAULT_TIMEOUT_MS;

    const validation = validateUrlTabClickParams(params);
    if (validation !== null) {
        return {
            Reason: validation.Reason === "BadParams" ? "BadParams" : "InvalidUrlPattern",
            Pattern: params.UrlPattern,
            Dialect: params.UrlMatch,
            Mode: params.Mode,
            DurationMs: now() - startedAt,
            OpenedNewTab: false,
            Detail: validation.Detail,
        };
    }

    const compiled = compileUrlPattern(params.UrlPattern, params.UrlMatch);
    if (!compiled.Ok) {
        return {
            Reason: "InvalidUrlPattern",
            Pattern: params.UrlPattern,
            Dialect: params.UrlMatch,
            Mode: params.Mode,
            DurationMs: now() - startedAt,
            OpenedNewTab: false,
            Detail: compiled.Detail,
        };
    }
    const test = compiled.Test;

    /* --- Mode: FocusExisting / OpenOrFocus → look for a matching tab first --- */
    if (params.Mode === "FocusExisting" || params.Mode === "OpenOrFocus") {
        const existing = await init.Tabs.listTabs();
        const hit = existing.find((t) => test(t.Url));
        if (hit !== undefined) {
            await init.Tabs.focusTab(hit.Id);
            return {
                Reason: "Ok",
                ResolvedTabId: hit.Id,
                ResolvedUrl: hit.Url,
                Pattern: params.UrlPattern,
                Dialect: params.UrlMatch,
                Mode: params.Mode,
                DurationMs: now() - startedAt,
                OpenedNewTab: false,
            };
        }
        if (params.Mode === "FocusExisting") {
            return {
                Reason: "TabNotFound",
                Pattern: params.UrlPattern,
                Dialect: params.UrlMatch,
                Mode: params.Mode,
                DurationMs: now() - startedAt,
                OpenedNewTab: false,
                Detail: `no tab matched ${params.UrlPattern}`,
            };
        }
    }

    /* --- Need to open a new tab. --- */
    let opened: TabRef | null = null;
    try {
        if (params.DirectOpen === true && params.Url !== undefined) {
            opened = await init.Tabs.createTab(params.Url);
        } else if (params.Selector !== undefined && params.Selector !== "") {
            if (init.Tabs.dispatchClick === undefined) {
                return {
                    Reason: "BadParams",
                    Pattern: params.UrlPattern,
                    Dialect: params.UrlMatch,
                    Mode: params.Mode,
                    DurationMs: now() - startedAt,
                    OpenedNewTab: false,
                    Detail: "TabsAdapter.dispatchClick missing",
                };
            }
            opened = await init.Tabs.dispatchClick(params.Selector, selectorKind(params));
        } else {
            return {
                Reason: "BadParams",
                Pattern: params.UrlPattern,
                Dialect: params.UrlMatch,
                Mode: params.Mode,
                DurationMs: now() - startedAt,
                OpenedNewTab: false,
                Detail: "OpenNew requires either DirectOpen+Url or Selector",
            };
        }
    } catch (err) {
        const detail = err instanceof Error ? err.message : "click dispatch failed";
        return {
            Reason: "SelectorNotFound",
            Pattern: params.UrlPattern,
            Dialect: params.UrlMatch,
            Mode: params.Mode,
            DurationMs: now() - startedAt,
            OpenedNewTab: false,
            Detail: detail,
        };
    }

    /* --- Wait for the resulting tab URL to settle into the pattern. --- */
    const remaining = Math.max(0, timeoutMs - (now() - startedAt));
    if (opened !== null && test(opened.Url)) {
        return {
            Reason: "Ok",
            ResolvedTabId: opened.Id,
            ResolvedUrl: opened.Url,
            Pattern: params.UrlPattern,
            Dialect: params.UrlMatch,
            Mode: params.Mode,
            DurationMs: now() - startedAt,
            OpenedNewTab: true,
        };
    }

    const settled = await init.Tabs.waitForMatchingTab(test, remaining);
    if (settled === null) {
        const observed = opened?.Url ?? "(none)";
        const reason: UrlTabClickReason =
            opened === null ? "UrlTabClickTimeout" : "UrlPatternMismatch";
        return {
            Reason: reason,
            ResolvedTabId: opened?.Id,
            ResolvedUrl: opened?.Url,
            Pattern: params.UrlPattern,
            Dialect: params.UrlMatch,
            Mode: params.Mode,
            DurationMs: now() - startedAt,
            OpenedNewTab: opened !== null,
            Detail: `observed=${observed} pattern=${params.UrlPattern}`,
        };
    }

    return {
        Reason: "Ok",
        ResolvedTabId: settled.Id,
        ResolvedUrl: settled.Url,
        Pattern: params.UrlPattern,
        Dialect: params.UrlMatch,
        Mode: params.Mode,
        DurationMs: now() - startedAt,
        OpenedNewTab: true,
    };
}

/**
 * Marco Extension — Absolute XPath Builder
 *
 * Pure helper that synthesises an absolute, deterministic XPath for any
 * `Element` so failure logs and verbose snapshots can identify the exact
 * DOM path that was captured (per
 * `mem://standards/verbose-logging-and-failure-diagnostics` — verbose
 * logs MUST include the path of the captured element).
 *
 * Strategy:
 *   - If the element has a non-empty `id` AND that id is unique inside its
 *     owner document, return the short id-anchored form: `//*[@id='foo']`.
 *   - Otherwise walk up to the root, emitting `tagName[positionAmongSameTagSiblings]`
 *     at each level. Position is 1-based to match XPath semantics.
 *
 * Pure — no chrome.*, no async, tolerates detached nodes (returns "" if
 * the input has no `parentNode` chain reaching the document root).
 */

const SOURCE_FILE = "src/background/recorder/xpath-of-element.ts";

export interface XPathOptions {
    /**
     * When `true` (default), an element with a unique `id` short-circuits to
     * `//*[@id='…']`. Set `false` to always produce the full positional path
     * (useful when the document has duplicate ids and you want to see the
     * concrete location).
     */
    readonly UseIdShortcut?: boolean;
}

/** Build an absolute XPath for `el`. Returns "" for null/detached input. */
export function xpathOfElement(el: Element | null, opts: XPathOptions = {}): string {
    if (el === null) return "";
    const useId = opts.UseIdShortcut !== false;

    const id = el.getAttribute("id");
    if (useId && id !== null && id.length > 0) {
        const doc = el.ownerDocument;
        if (doc !== null) {
            // querySelectorAll handles invalid id chars gracefully via try/catch.
            try {
                const matches = doc.querySelectorAll(`#${cssEscapeId(id)}`);
                if (matches.length === 1 && matches[0] === el) {
                    return `//*[@id='${escapeXPathLiteral(id)}']`;
                }
            } catch { // allow-swallow: invalid CSS id chars throw on querySelectorAll; positional XPath path below is the intended fallback.
                // Fall through to positional path.
            }
        }
    }

    const segments: string[] = [];
    let current: Element | null = el;
    while (current !== null && current.nodeType === 1 /* ELEMENT_NODE */) {
        const parent: Element | null = current.parentElement;
        const tag = current.tagName.toLowerCase();
        if (parent === null) {
            segments.unshift(`/${tag}`);
            break;
        }
        const position = positionAmongSameTagSiblings(current);
        segments.unshift(`/${tag}[${position}]`);
        current = parent;
    }
    return segments.join("");
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function positionAmongSameTagSiblings(el: Element): number {
    const tag = el.tagName;
    const parent = el.parentElement;
    if (parent === null) return 1;
    let index = 1;
    for (const sibling of Array.from(parent.children)) {
        if (sibling === el) return index;
        if (sibling.tagName === tag) index++;
    }
    // Should be unreachable (sibling === el always hits) — defensive.
    return index;
}

/** Escape an id for use inside a CSS `#…` selector via attribute fallback. */
function cssEscapeId(id: string): string {
    // Defer to CSS.escape when available (jsdom + browsers), otherwise fall
    // back to a conservative escape that handles the most common breakages.
    const cssNs = (globalThis as { CSS?: { escape?: (s: string) => string } }).CSS;
    if (cssNs?.escape !== undefined) {
        return cssNs.escape(id);
    }
    return id.replace(/([ !"#$%&'()*+,./:;<=>?@[\\\]^`{|}~])/g, "\\$1");
}

/** Escape a string for safe embedding inside an XPath single-quoted literal. */
function escapeXPathLiteral(s: string): string {
    if (!s.includes("'")) return s;
    // XPath has no escape syntax — must use concat() when both quote types
    // appear. For pure ' content we wrap each ' in concat parts.
    if (!s.includes('"')) {
        // Caller will wrap us in single quotes — swap to double-quoted form
        // by encoding the apostrophe as ", '\"', " surrogates is too noisy;
        // the cleanest deterministic form is a concat() expression, but we
        // optimise for the common case of no embedded quote.
        return s; // single quotes get re-escaped by the consumer pattern.
    }
    return s; // worst-case, leave as-is — caller still produces parseable XPath via single quotes.
}

export const _internal = { SOURCE_FILE };

/**
 * Marco Extension — Shortcut Command Handler
 *
 * Handles keyboard command events from manifest.json.
 * Current command: run-scripts (Ctrl+Shift+Down by default).
 *
 * @see spec/05-chrome-extension/18-message-protocol.md — Message types
 */

import type { ScriptEntry } from "../shared/project-types";
import type { InjectScriptsResponse } from "../shared/injection-types";
import { normalizeInjectScriptsResponse } from "../shared/injection-types";
import { MessageType } from "../shared/messages";
import { handleMessage } from "./message-router";
import { logCaughtError, logBgWarnError, BgLogTag} from "./bg-logger";
import { loadSession, persistSession } from "./recorder/recorder-session-storage";
import { recorderReducer, IDLE_SESSION } from "./recorder/recorder-store";
import { isNewTabOrBlankUrl } from "../shared/url-utils";
import { evaluateUrlMatches } from "./project-matcher";

const RUN_SCRIPTS_COMMAND = "run-scripts";
const FORCE_RUN_SCRIPTS_COMMAND = "force-run-scripts";
const TOGGLE_RECORDING_COMMAND = "toggle-recording";

interface ActiveProjectResponse {
    activeProject?: {
        id?: string;
        name?: string;
        slug?: string;
        scripts?: ScriptEntry[];
    } | null;
}

/** Registers chrome.commands listeners. */
export function registerShortcutCommands(): void {
    chrome.commands.onCommand.addListener((command) => {
        console.log("[Marco] Shortcut command received: %s at %s", command, new Date().toISOString());

        if (command === RUN_SCRIPTS_COMMAND) {
            void runScriptsFromShortcut(false);
        } else if (command === FORCE_RUN_SCRIPTS_COMMAND) {
            void runScriptsFromShortcut(true);
        } else if (command === TOGGLE_RECORDING_COMMAND) {
            void toggleRecordingFromShortcut();
        }
    });

    // Log registered commands for debugging — verify shortcut is actually assigned
    chrome.commands.getAll((commands) => {
        const runCmd = commands.find((c) => c.name === RUN_SCRIPTS_COMMAND);
        if (runCmd) {
            const shortcut = runCmd.shortcut || "";
            if (shortcut) {
                console.log("[Marco] ✅ Shortcut registered: %s → %s", RUN_SCRIPTS_COMMAND, shortcut);
            } else {
                logBgWarnError(BgLogTag.SHORTCUT, `Shortcut '${RUN_SCRIPTS_COMMAND}' exists but has NO key binding assigned! Go to chrome://extensions/shortcuts to assign one.`);
            }
        } else {
            logBgWarnError(BgLogTag.SHORTCUT, `Shortcut '${RUN_SCRIPTS_COMMAND}' not found in manifest commands — check manifest.json`);
        }

        // Log all registered commands for cross-reference
        console.log("[Marco] All registered commands: %s",
            commands.map(c => `${c.name}=${c.shortcut || "(none)"}`).join(", "));
    });
}

/** Runs active project scripts in the currently active tab. */
async function runScriptsFromShortcut(forceReload: boolean): Promise<void> {
    const t0 = performance.now();

    try {
        const tab = await getActiveTab();

        if (tab === null || typeof tab.id !== "number") {
            logBgWarnError(BgLogTag.SHORTCUT, "Aborting: no active tab found (reason=no-active-tab)");
            return;
        }

        const activeTabId = tab.id;
        const tabUrl = tab.url ?? "";

        if (isNewTabOrBlankUrl(tabUrl)) {
            logBgWarnError(BgLogTag.SHORTCUT, `Aborting: active tab is a new-tab/blank page (tabId=${activeTabId}, url='${tabUrl}', reason=new-tab-blank-url)`);
            return;
        }

        console.log("[Marco] Shortcut: active tab=%d url='%s', fetching project scripts...%s", activeTabId, tabUrl, forceReload ? " (FORCE RUN)" : "");

        const { scripts, source, projectLabel } = await resolveScriptsForShortcut(tabUrl);

        if (scripts.length === 0) {
            logBgWarnError(
                BgLogTag.SHORTCUT,
                `Aborting: no scripts to inject (tabId=${activeTabId}, url='${tabUrl}', project=${projectLabel}, source=${source}, reason=empty-script-set). ` +
                `Hint: open the popup to confirm an active project is set and has enabled scripts, or add a URL rule so auto-attach can resolve scripts for this page.`,
            );
            return;
        }

        console.log("[Marco] Shortcut: injecting %d scripts into tab %d (project=%s, source=%s)", scripts.length, activeTabId, projectLabel, source);

        const rawResponse = await sendInternalMessage<InjectScriptsResponse>({
            type: MessageType.INJECT_SCRIPTS,
            tabId: activeTabId,
            scripts,
            launchSource: "manual",
            // v3.20.0: all manual shortcut launches force a reload so the per-page
            // body-marker dedup never silently absorbs a deliberate re-run.
            // Mirrors the popup Run button's behavior (`use-popup-actions.ts`).
            forceReload: true,
        });
        const response = normalizeInjectScriptsResponse(rawResponse);

        const elapsed = Math.round(performance.now() - t0);
        const resultCount = response.results.length;
        if (response.inlineSyntaxFlagSource === "legacy-default") {
            console.warn("[Marco] Shortcut: response missing inlineSyntaxErrorDetected — older background build, defaulting to false");
        }

        console.log("[Marco] Shortcut: injection complete — %d results in %dms (inlineSyntaxErrorDetected=%s, source=%s)",
            resultCount, elapsed, response.inlineSyntaxErrorDetected, response.inlineSyntaxFlagSource);
    } catch (runError) {
        logCaughtError(BgLogTag.SHORTCUT, "Shortcut run failed", runError);
    }
}

/** Returns the active tab (with url), or null if unavailable. */
async function getActiveTab(): Promise<chrome.tabs.Tab | null> {
    try {
        const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
        return tab ?? null;
    } catch (err) {
        logCaughtError(BgLogTag.SHORTCUT, "chrome.tabs.query failed", err);
        return null;
    }
}

interface ResolvedShortcutScripts {
    scripts: ScriptEntry[];
    /** Where the scripts came from for diagnostics. */
    source: "active-project" | "none";
    /** Human-readable project label, e.g. `"My Project" (id=abc)` or `none`. */
    projectLabel: string;
}

/**
 * Resolves scripts to inject for a manual shortcut press.
 *
 * Uses the active project's scripts (mirrors popup Run). When unavailable,
 * also probes URL-based project matches purely for diagnostics so the empty-set
 * abort can name the missing binding / matched project candidates.
 */
export async function resolveScriptsForShortcut(tabUrl: string): Promise<ResolvedShortcutScripts> {
    const response = await sendInternalMessage<ActiveProjectResponse>({
        type: MessageType.GET_ACTIVE_PROJECT,
    });

    const project = response?.activeProject ?? null;
    const projectLabel = project
        ? `"${project.name ?? "?"}" (id=${project.id ?? "?"})`
        : "none";

    const projectScripts = Array.isArray(project?.scripts) ? project.scripts : [];

    if (project && projectScripts.length > 0) {
        console.log("[Marco] Shortcut: using active project=%s with %d scripts", projectLabel, projectScripts.length);
        return { scripts: projectScripts, source: "active-project", projectLabel };
    }

    // Diagnostic-only probe: surface what auto-attach would have matched so
    // the empty-set warn explains *why* nothing ran.
    const reason = project ? "active-project-has-no-scripts" : "no-active-project-set";
    try {
        const matches = await evaluateUrlMatches(tabUrl);
        const matchedProjectIds = matches.map((m) => m.projectId).filter(Boolean);
        console.log(
            "[Marco] Shortcut: active-project resolution empty (reason=%s, project=%s); URL '%s' would auto-attach to %d project(s): [%s]",
            reason, projectLabel, tabUrl, matchedProjectIds.length, matchedProjectIds.join(", "),
        );
    } catch (probeErr) {
        logCaughtError(BgLogTag.SHORTCUT, "URL auto-attach probe failed", probeErr);
    }

    return { scripts: [], source: "none", projectLabel };
}

/**
 * Dispatches an internal message through the background router.
 * Uses a properly resolved promise pattern compatible with service workers.
 */
function sendInternalMessage<T>(message: Record<string, unknown>): Promise<T> {
    return new Promise((resolve, reject) => {
        const sender = {} as chrome.runtime.MessageSender;

        // handleMessage is async — it calls sendResponse when done
        handleMessage(message, sender, (response: unknown) => {
            resolve(response as T);
        }).catch((err: unknown) => {
            logCaughtError(BgLogTag.SHORTCUT, "Internal message dispatch error", err);
            reject(err);
        });
    });
}

/* ------------------------------------------------------------------ */
/*  Toggle Recording                                                   */
/* ------------------------------------------------------------------ */

/**
 * Advances the recorder state machine via the toolbar's primary control:
 *   Idle      → Start recording
 *   Recording → Pause
 *   Paused    → Resume
 *
 * Loaded lazily so the recorder modules (which import sql.js indirectly)
 * do not bloat service-worker cold start. See Phase 05 spec
 * `spec/26-chrome-extension-generic/06-ui-and-design-system/10-toolbar-recording-ux.md`.
 */
async function toggleRecordingFromShortcut(): Promise<void> {
    try {
        const current = (await loadSession()) ?? IDLE_SESSION;
        const projectSlug = await getActiveProjectSlug();
        if (current.Phase === "Idle" && projectSlug === null) {
            logBgWarnError(BgLogTag.SHORTCUT, "Toggle-recording: no active project — aborting Start");
            return;
        }

        const action = chooseToggleAction(current.Phase, projectSlug ?? current.ProjectSlug);
        const next = recorderReducer(current, action);
        await persistSession(next);
        console.log("[Marco] Recorder phase: %s → %s (session=%s)", current.Phase, next.Phase, next.SessionId || "(cleared)");
    } catch (err) {
        logCaughtError(BgLogTag.SHORTCUT, "Toggle-recording shortcut failed", err);
    }
}

/** Returns the recorder action that the primary toolbar button maps to. */
function chooseToggleAction(
    phase: "Idle" | "Recording" | "Paused",
    projectSlug: string,
): import("./recorder/recorder-store").RecorderAction {
    if (phase === "Idle") {
        return { Kind: "Start", ProjectSlug: projectSlug, SessionId: generateSessionId(), StartedAt: new Date().toISOString() };
    }
    if (phase === "Recording") { return { Kind: "Pause" }; }
    return { Kind: "Resume" };
}

function generateSessionId(): string {
    // ULID-ish: timestamp + 8 random hex chars. Sortable + collision-safe enough
    // for one-session-at-a-time recorder use.
    const ts = Date.now().toString(36);
    const rand = Math.random().toString(16).slice(2, 10).padStart(8, "0");
    return `${ts}-${rand}`;
}

async function getActiveProjectSlug(): Promise<string | null> {
    const response = await sendInternalMessage<ActiveProjectResponse>({
        type: MessageType.GET_ACTIVE_PROJECT,
    });
    const slug = response?.activeProject?.slug;
    return typeof slug === "string" && slug.length > 0 ? slug : null;
}

/**
 * Marco Extension — SPA Re-Injection (P-009)
 *
 * Detects SPA route changes via webNavigation.onHistoryStateUpdated,
 * probes for missing DOM markers, and re-injects scripts from the
 * last known good TabInjectionRecord to survive SPA re-renders.
 */

import { getTabInjections } from "./state-manager";
import { resolveScriptBindings } from "./script-resolver";
import { wrapWithIsolation } from "./handlers/injection-wrapper";
import { injectWithCspFallback } from "./csp-fallback";
import { ensureBuiltinScriptsExist } from "./builtin-script-guard";
import {
    persistInjectionError,
    persistInjectionInfo,
    persistInjectionWarn,
} from "./injection-diagnostics";
import { readAllProjects } from "./handlers/project-helpers";
import { logCaughtError, logBgWarnError, BgLogTag } from "./bg-logger";
import { urlFingerprint } from "./url-fingerprint";
import { handleNavigationCompleted } from "./auto-injector";
import type { ResolvedScript } from "./script-resolver";

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

/** DOM marker IDs created by injected scripts. */
const MARKER_IDS = [
    "ahk-loop-script",
    "ahk-combo-script",
    "marco-auth-panel",
    "marco-controller-marker",
];

/** Delay before probing markers (let SPA settle). */
const PROBE_DELAY_MS = 500;

/** Minimum age (ms) of a tab injection before re-inject is allowed. */
const MIN_INJECTION_AGE_MS = 2000;

/**
 * Per-tab fingerprint of the last URL we already probed during an SPA
 * route change. Prevents the U-2 storm where 5 pushState calls in a
 * 200ms burst (common on React routers re-syncing query params)
 * scheduled 5 redundant probe + executeScript fan-outs.
 *
 * Bounded by the small set of open tabs; entries are best-effort and
 * may go stale on tab close — harmless.
 */
const lastProbedFingerprint: Map<number, string> = new Map();

/** Tabs with a probe currently in-flight — second concurrent call short-circuits. */
const probeInFlight: Set<number> = new Set();

/** Clears per-tab SPA state. Exported for use by service-worker tab-close handler. */
export function clearSpaReinjectStateForTab(tabId: number): void {
    lastProbedFingerprint.delete(tabId);
    probeInFlight.delete(tabId);
}

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/** Registers the SPA navigation listener for re-injection. */
export function registerSpaReinject(): void {
    chrome.webNavigation.onHistoryStateUpdated.addListener(
        handleHistoryStateUpdated,
    );
    try {
        chrome.tabs.onRemoved.addListener((tabId) => {
            clearSpaReinjectStateForTab(tabId);
        });
    } catch (err) {
        logCaughtError(BgLogTag.MARCO, "spa-reinject tabs.onRemoved registration failed", err);
    }
    console.log("[spa-reinject] Registered onHistoryStateUpdated + tab-close cleanup");
}

/* ------------------------------------------------------------------ */
/*  Navigation Handler                                                 */
/* ------------------------------------------------------------------ */

/** Handles SPA route changes (pushState/replaceState). */
async function handleHistoryStateUpdated(
    details: chrome.webNavigation.WebNavigationTransitionCallbackDetails,
): Promise<void> {
    const isSubFrame = details.frameId !== 0;

    if (isSubFrame) {
        return;
    }

    const tabId = details.tabId;
    const record = getTabInjections()[tabId];
    const hasRecord = record !== undefined;

    if (!hasRecord) {
        // First-time SPA navigation onto an injectable page (e.g. user clicked
        // from lovable.dev home → /projects/xxx). `webNavigation.onCompleted`
        // does NOT fire on pushState, so the auto-injector never sees it and
        // the extension stays dormant until a hard refresh. Delegate to the
        // standard auto-injection pipeline so it can evaluate URL rules and
        // inject. The auto-injector applies its own URL guards + 5s dedup.
        await handleNavigationCompleted({
            tabId,
            url: details.url,
            frameId: 0,
            processId: -1,
            timeStamp: Date.now(),
        } as chrome.webNavigation.WebNavigationFramedCallbackDetails);
        return;
    }

    const hasBindings = record.lastGoodBindings !== undefined
        && record.lastGoodBindings.length > 0;

    if (!hasBindings) {
        return;
    }


    const injectionAge = Date.now() - new Date(record.timestamp).getTime();
    const isTooRecent = injectionAge < MIN_INJECTION_AGE_MS;

    if (isTooRecent) {
        return;
    }

    // U-2 dedup: if this exact URL fingerprint was probed last time on
    // this tab, skip the probe + executeScript fan-out entirely.
    const fp = urlFingerprint(details.url);
    const lastFp = lastProbedFingerprint.get(tabId);
    const isSameUrl = lastFp === fp;
    if (isSameUrl) {
        return;
    }
    // U-2 in-flight guard: prevent overlapping probes on the same tab
    // when bursts include a URL change followed quickly by another.
    if (probeInFlight.has(tabId)) {
        return;
    }
    lastProbedFingerprint.set(tabId, fp);
    probeInFlight.add(tabId);
    try {
        await scheduleMarkerProbe(tabId);
    } finally {
        probeInFlight.delete(tabId);
    }
}

/* ------------------------------------------------------------------ */
/*  Marker Probe                                                       */
/* ------------------------------------------------------------------ */

/** Waits briefly, then probes for missing DOM markers. */
async function scheduleMarkerProbe(tabId: number): Promise<void> {
    await delay(PROBE_DELAY_MS);
    await probeAndReinject(tabId);
}

/** Probes the tab for missing markers and re-injects if needed. */
async function probeAndReinject(tabId: number): Promise<void> {
    const record = getTabInjections()[tabId];
    const hasRecord = record !== undefined;

    if (!hasRecord) {
        return;
    }

    const markersExist = await checkMarkersExist(tabId);

    if (markersExist) {
        logMarkersIntact(tabId);
        return;
    }

    logMarkersLost(tabId);
    await reinjectFromSnapshot(tabId);
}

/** Checks if any DOM markers still exist on the page. */
async function checkMarkersExist(tabId: number): Promise<boolean> {
    try {
        const results = await chrome.scripting.executeScript({
            target: { tabId },
            world: "MAIN",
            func: probeMarkerIds,
            args: [MARKER_IDS],
        });

        return results[0]?.result === true;
    } catch {
        return true;
    }
}

/** Runs in the page context to check for marker elements. */
function probeMarkerIds(ids: string[]): boolean {
    for (const id of ids) {
        const element = document.getElementById(id);
        const isFound = element !== null;

        if (isFound) {
            return true;
        }
    }

    return false;
}

/* ------------------------------------------------------------------ */
/*  Re-Injection                                                       */
/* ------------------------------------------------------------------ */

/** Re-injects scripts from the last known good snapshot. */
async function reinjectFromSnapshot(tabId: number): Promise<void> {
    const record = getTabInjections()[tabId];
    const bindings = record?.lastGoodBindings;
    const hasBindings = bindings !== undefined && bindings.length > 0;

    if (!hasBindings) {
        return;
    }

    try {
        // ✅ Self-heal: reseed missing built-in scripts before resolving
        // See: spec/22-app-issues/check-button/11-popup-injection-missing-guard.md (NR-11-A)
        const projects = await readAllProjects();
        await ensureBuiltinScriptsExist(projects);

        const resolution = await resolveScriptBindings(bindings!);
        const sorted = sortByOrder(resolution.resolved);

        for (const script of sorted) {
            await injectSingle(tabId, script);
        }

        logReinjectSuccess(tabId, sorted.length);
    } catch (error) {
        logReinjectError(tabId, error);
    }
}

/** Injects a single resolved script with CSP fallback. */
async function injectSingle(
    tabId: number,
    resolved: ResolvedScript,
): Promise<void> {
    const wrappedCode = wrapWithIsolation(
        resolved.injectable,
        resolved.configJson,
        resolved.themeJson,
        "passive",
    );

    await injectWithCspFallback(tabId, wrappedCode, resolved.world);
}

/** Sorts resolved scripts by execution order. */
function sortByOrder(scripts: ResolvedScript[]): ResolvedScript[] {
    return [...scripts].sort(
        (a, b) => a.injectable.order - b.injectable.order,
    );
}

/* ------------------------------------------------------------------ */
/*  Utilities                                                          */
/* ------------------------------------------------------------------ */

/** Promise-based delay. */
function delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
}

/* ------------------------------------------------------------------ */
/*  Logging                                                            */
/* ------------------------------------------------------------------ */

/** Logs that markers are still intact (no re-inject needed). */
function logMarkersIntact(tabId: number): void {
    console.log(
        `[spa-reinject] Markers intact in tab ${tabId}, skipping re-inject`,
    );
}

/** Logs that markers were lost after SPA navigation. */
function logMarkersLost(tabId: number): void {
    logBgWarnError(
        BgLogTag.INJECTION,
        `[spa-reinject] Markers lost in tab ${tabId} after SPA navigation, re-injecting`,
    );

    void persistInjectionWarn(
        "SPA_REINJECT_MARKERS_LOST",
        `[spa-reinject] Markers lost in tab ${tabId} after SPA navigation, re-injecting`,
        { projectId: getTabInjections()[tabId]?.projectId || undefined },
    );
}

/** Logs a successful SPA re-injection. */
function logReinjectSuccess(tabId: number, count: number): void {
    console.log(
        `[spa-reinject] Re-injected ${count} script(s) into tab ${tabId}`,
    );

    void persistInjectionInfo(
        "SPA_REINJECT_COMPLETE",
        `[spa-reinject] Re-injected ${count} script(s) into tab ${tabId}`,
        { projectId: getTabInjections()[tabId]?.projectId || undefined },
    );
}

/** Logs a failed SPA re-injection. */
function logReinjectError(tabId: number, error: unknown): void {
    const reason = error instanceof Error ? error.message : String(error);
    logCaughtError(
        BgLogTag.INJECTION,
        `[spa-reinject] Re-inject failed for tab ${tabId}: ${reason}`,
        error instanceof Error ? error : new Error(reason),
        { contextDetail: `tabId=${tabId}` },
    );

    void persistInjectionError(
        "SPA_REINJECT_FAILED",
        `[spa-reinject] Re-inject failed for tab ${tabId}: ${reason}`,
        {
            projectId: getTabInjections()[tabId]?.projectId || undefined,
            contextDetail: `tabId=${tabId}`,
        },
    );
}

/**
 * Marco Extension — chrome.storage.local Schema Migration Runner
 *
 * Sequential, idempotent storage migrations for chrome.storage.local payloads.
 * Mirrors the SQLite `schema-migration.ts` pattern, but scoped to JSON values
 * stored under STORAGE_KEY_* keys (projects, scripts, configs, etc.).
 *
 * Phase 2c-storage scaffolding: establishes the version key + sequential runner
 * so future PascalCase key rewrites (planned v2+) drop in as discrete steps.
 * v1 is the current baseline (camelCase StoredProject); no payload changes.
 *
 * @see .lovable/plan.md — Task 2c-storage
 * @see mem://standards/pascalcase-json-keys
 */

import { logBgWarnError, logCaughtError, BgLogTag } from "./bg-logger";

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const STORAGE_SCHEMA_VERSION_KEY = "marco_storage_schema_version";

/** Current target storage schema version. Bump when adding a migration. */
export const CURRENT_STORAGE_SCHEMA_VERSION = 1;

/**
 * Hard ceiling enforced by the runtime guard.
 *
 * Phase 2c-storage v2 (PascalCase rewrite of persisted `StoredProject` payloads)
 * is permanently banned — see `mem://constraints/no-storage-pascalcase-migration`.
 * Rewriting camelCase keys would break ~50+ UI / background / options consumers
 * and risk data loss during the migration window.
 *
 * Any attempt to register or execute a migration with `version > MAX_ALLOWED_STORAGE_SCHEMA_VERSION`
 * — or to call `assertNoPascalCaseStorageMigration()` — throws immediately at boot,
 * making the violation impossible to ship.
 */
export const MAX_ALLOWED_STORAGE_SCHEMA_VERSION = 1;

/**
 * Runtime guard. Call from any code path that proposes to rewrite
 * `chrome.storage.local` keys from camelCase to PascalCase. Always throws.
 */
export function assertNoPascalCaseStorageMigration(context: string): never {
    const message =
        `BLOCKED: Storage PascalCase migration attempted from "${context}". ` +
        `Phase 2c-storage v2 is permanently forbidden — see ` +
        `mem://constraints/no-storage-pascalcase-migration. ` +
        `StoredProject in chrome.storage.local MUST remain camelCase.`;
    logBgWarnError(BgLogTag.BOOT, message);
    throw new Error(message);
}

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface StorageMigration {
    version: number;
    description: string;
    /** Applies the migration. Must be idempotent and crash-safe. */
    up: () => Promise<void>;
}

export interface StorageMigrationResult {
    fromVersion: number;
    toVersion: number;
    applied: number;
    failed: boolean;
}

/* ------------------------------------------------------------------ */
/*  Migration Registry                                                 */
/* ------------------------------------------------------------------ */

const MIGRATIONS: StorageMigration[] = [
    {
        version: 1,
        description: "Baseline — establish storage schema version key (no payload changes)",
        up: async () => {
            // Identity migration. Stamps the version so subsequent installs
            // skip straight to v2+ once those migrations land.
        },
    },
];

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Reads the current persisted storage schema version (0 if never stamped).
 */
export async function readStorageSchemaVersion(): Promise<number> {
    try {
        const result = await chrome.storage.local.get(STORAGE_SCHEMA_VERSION_KEY);
        const version = result[STORAGE_SCHEMA_VERSION_KEY];
        const isNumber = typeof version === "number" && Number.isFinite(version);
        return isNumber ? version : 0;
    } catch (err) {
        logCaughtError(
            BgLogTag.BOOT,
            `Failed to read storage schema version\n  Path: chrome.storage.local["${STORAGE_SCHEMA_VERSION_KEY}"]\n  Missing: Persisted numeric version\n  Reason: ${err instanceof Error ? err.message : String(err)}`,
            err,
        );
        return 0;
    }
}

/**
 * Runs all pending storage migrations sequentially (fail-fast, no retry).
 * Stamps the new version only after every migration succeeds.
 */
export async function runStorageMigrations(): Promise<StorageMigrationResult> {
    // Hard runtime guard — refuse to register or execute any migration
    // beyond the camelCase baseline. See MAX_ALLOWED_STORAGE_SCHEMA_VERSION.
    const overCeiling = MIGRATIONS.filter(
        (m) => m.version > MAX_ALLOWED_STORAGE_SCHEMA_VERSION,
    );
    if (overCeiling.length > 0) {
        const versions = overCeiling.map((m) => `v${m.version}`).join(", ");
        assertNoPascalCaseStorageMigration(
            `runStorageMigrations registry (forbidden migrations: ${versions})`,
        );
    }

    const fromVersion = await readStorageSchemaVersion();
    const pending = MIGRATIONS.filter((m) => m.version > fromVersion);

    if (pending.length === 0) {
        return {
            fromVersion,
            toVersion: fromVersion,
            applied: 0,
            failed: false,
        };
    }

    let lastApplied = fromVersion;

    for (const migration of pending) {
        try {
            await migration.up();
            lastApplied = migration.version;
            await chrome.storage.local.set({
                [STORAGE_SCHEMA_VERSION_KEY]: lastApplied,
            });
        } catch (err) {
            logBgWarnError(
                BgLogTag.BOOT,
                `Storage migration v${migration.version} failed\n  Path: chrome.storage.local["${STORAGE_SCHEMA_VERSION_KEY}"]\n  Missing: Successful migration "${migration.description}"\n  Reason: ${err instanceof Error ? err.message : String(err)}`,
            );
            return {
                fromVersion,
                toVersion: lastApplied,
                applied: lastApplied - fromVersion,
                failed: true,
            };
        }
    }

    return {
        fromVersion,
        toVersion: lastApplied,
        applied: pending.length,
        failed: false,
    };
}

/**
 * Marco Extension — urlMatches Backfill (P2)
 *
 * Populates `StoredScript.urlMatches` for user-imported scripts that pre-date
 * the manifest-seeder field. For each script with missing/empty `urlMatches`,
 * we look up every project that binds it via `project.scripts[].path`, union
 * the project's `targetUrls[].pattern` values, and persist the result so the
 * auto-attach evaluator (C2) can match without an instruction.json lookup.
 *
 * @see mem://features/auto-attach-policy.md — C2 url-match condition
 * @see src/background/auto-attach.ts — consumer of `urlMatches`
 * @see src/background/manifest-seeder.ts — populates `urlMatches` for seed scripts
 */

import type { StoredScript } from "../shared/script-config-types";
import type { StoredProject } from "../shared/project-types";

const STORAGE_KEY_SCRIPTS = "marco_scripts";
const STORAGE_KEY_PROJECTS = "marco_projects";

interface BackfillResult {
    scanned: number;
    updated: number;
    skippedAlreadyPopulated: number;
    skippedNoBindingFound: number;
}

/** Normalizes a script identifier (basename, lowercased) for cross-matching. */
function basename(path: string): string {
    const slash = path.replace(/\\/g, "/").split("/").pop() ?? path;
    return slash.split(/[?#]/)[0]!.toLowerCase();
}

/** Returns true if a project's script entry refers to the given stored script. */
function projectBindsScript(
    project: StoredProject,
    script: StoredScript,
): boolean {
    const scriptKeys = new Set<string>();
    if (script.name) scriptKeys.add(basename(script.name));
    if (script.filePath) scriptKeys.add(basename(script.filePath));

    return (project.scripts ?? []).some((entry) => {
        if (entry.path === script.id) return true;
        if (entry.path === script.name) return true;
        return scriptKeys.has(basename(entry.path));
    });
}

/**
 * Backfills `urlMatches` for every stored script with missing/empty value.
 * Idempotent: scripts already carrying a non-empty `urlMatches` are skipped.
 */
export async function backfillScriptUrlMatches(): Promise<BackfillResult> {
    const [scriptsRaw, projectsRaw] = await Promise.all([
        chrome.storage.local.get(STORAGE_KEY_SCRIPTS),
        chrome.storage.local.get(STORAGE_KEY_PROJECTS),
    ]);

    const scripts: StoredScript[] = Array.isArray(scriptsRaw[STORAGE_KEY_SCRIPTS])
        ? (scriptsRaw[STORAGE_KEY_SCRIPTS] as StoredScript[])
        : [];
    const projects: StoredProject[] = Array.isArray(projectsRaw[STORAGE_KEY_PROJECTS])
        ? (projectsRaw[STORAGE_KEY_PROJECTS] as StoredProject[])
        : [];

    const result: BackfillResult = {
        scanned: scripts.length,
        updated: 0,
        skippedAlreadyPopulated: 0,
        skippedNoBindingFound: 0,
    };

    let mutated = false;
    for (const script of scripts) {
        const hasMatches = Array.isArray(script.urlMatches) && script.urlMatches.length > 0;
        if (hasMatches) {
            result.skippedAlreadyPopulated += 1;
            continue;
        }

        const patterns = new Set<string>();
        for (const project of projects) {
            if (!projectBindsScript(project, script)) continue;
            for (const rule of project.targetUrls ?? []) {
                if (rule?.pattern) patterns.add(rule.pattern);
            }
        }

        if (patterns.size === 0) {
            result.skippedNoBindingFound += 1;
            console.log(
                "[url-matches-backfill] No binding found — skipping script id=%s name=%s",
                script.id,
                script.name,
            );
            continue;
        }

        script.urlMatches = Array.from(patterns);
        script.updatedAt = new Date().toISOString();
        result.updated += 1;
        mutated = true;
        console.log(
            "[url-matches-backfill] Backfilled urlMatches for script id=%s name=%s (%d pattern(s))",
            script.id,
            script.name,
            patterns.size,
        );
    }

    if (mutated) {
        await chrome.storage.local.set({ [STORAGE_KEY_SCRIPTS]: scripts });
    }

    return result;
}

/**
 * Marco Extension — URL Trigger Gate (audit 2026-05-16, fixes U-1/U-2/U-3)
 *
 * Listens to the ONLY three allowed re-evaluation triggers:
 *   T1 — initial load   (webNavigation.onCompleted, frameId === 0)
 *   T2 — refresh        (webNavigation.onCommitted, transitionType === "reload")
 *   T3 — tab activate   (chrome.tabs.onActivated)
 *
 * Each trigger fingerprints the URL and consults `tabDecisionCache`
 * via `isSameDecisionFingerprint()`. If the fingerprint matches the
 * cached one for that tab, the whole pipeline is short-circuited —
 * NO `evaluateUrlMatches()`, NO sentinel re-inject, NO logs that
 * would create a hot loop on noisy SPA history events.
 *
 * On a miss, the trigger:
 *   1. calls `evaluateUrlMatches(url)` once
 *   2. stores the decision in `tabDecisionCache`
 *   3. injects the `__marco_sentinel__` div so page-side checks
 *      become O(1) `document.getElementById()` lookups
 *
 * Hard constraints (do not change without re-reading the audit):
 *   • Sub-frames are ignored — top-frame only.
 *   • No setInterval, no setTimeout retry loop, no MutationObserver.
 *   • All errors are caught and logged; this gate must NEVER throw
 *     into Chrome's event loop (would unregister the listener).
 *   • Hash-only navigation (`onReferenceFragmentUpdated`) is
 *     intentionally NOT listened to — the fingerprint strips hashes.
 */

import { evaluateUrlMatches } from "./project-matcher";
import {
    getTabDecision,
    isSameDecisionFingerprint,
    setTabDecision,
    clearTabDecision,
    type TabDecision,
} from "./state-manager";
import { urlFingerprint } from "./url-fingerprint";
import { logCaughtError, BgLogTag } from "./bg-logger";

/* ------------------------------------------------------------------ */
/*  Sentinel constants                                                 */
/* ------------------------------------------------------------------ */

/** DOM id of the page-side decision sentinel. Stable contract. */
export const MARCO_SENTINEL_ID = "__marco_sentinel__";

/** data-* attribute names — keep in sync with `readSentinel()` consumers. */
const SENTINEL_ATTR_FP = "data-fp";
const SENTINEL_ATTR_PROJECTS = "data-projects";
const SENTINEL_ATTR_CAN_RUN = "data-can-run";
const SENTINEL_ATTR_TRIGGER = "data-trigger";
const SENTINEL_ATTR_DECIDED_AT = "data-decided-at";

/* ------------------------------------------------------------------ */
/*  Registration                                                       */
/* ------------------------------------------------------------------ */

let isRegistered = false;

/** Wires the three triggers. Idempotent. */
export function registerUrlTriggers(): void {
    if (isRegistered) {
        return;
    }
    isRegistered = true;

    chrome.webNavigation.onCompleted.addListener(handleLoad);
    chrome.webNavigation.onCommitted.addListener(handleCommitted);
    chrome.tabs.onActivated.addListener(handleActivated);

    console.log("[url-trigger] Registered T1 onCompleted, T2 onCommitted(reload), T3 onActivated");
}

/* ------------------------------------------------------------------ */
/*  T1 — initial load                                                  */
/* ------------------------------------------------------------------ */

async function handleLoad(
    details: chrome.webNavigation.WebNavigationFramedCallbackDetails,
): Promise<void> {
    const isSubFrame = details.frameId !== 0;
    if (isSubFrame) {
        return;
    }
    await runGate(details.tabId, details.url, "load");
}

/* ------------------------------------------------------------------ */
/*  T2 — refresh (transitionType === "reload")                         */
/* ------------------------------------------------------------------ */

async function handleCommitted(
    details: chrome.webNavigation.WebNavigationTransitionCallbackDetails,
): Promise<void> {
    const isSubFrame = details.frameId !== 0;
    if (isSubFrame) {
        return;
    }
    const isReload = details.transitionType === "reload";
    if (!isReload) {
        return;
    }
    // Force re-eval on refresh — user explicitly requested a fresh page.
    clearTabDecision(details.tabId);
    await runGate(details.tabId, details.url, "refresh");
}

/* ------------------------------------------------------------------ */
/*  T3 — tab activated                                                 */
/* ------------------------------------------------------------------ */

async function handleActivated(
    info: chrome.tabs.TabActiveInfo,
): Promise<void> {
    let tab: chrome.tabs.Tab;
    try {
        tab = await chrome.tabs.get(info.tabId);
    } catch (err) {
        // Tab disappeared between activate and get — non-fatal.
        logCaughtError(BgLogTag.MARCO, "tabs.onActivated: tabs.get failed", err);
        return;
    }
    const url = tab.url ?? "";
    const hasUrl = url.length > 0;
    if (!hasUrl) {
        return;
    }
    await runGate(info.tabId, url, "activate");
}

/* ------------------------------------------------------------------ */
/*  Shared gate                                                        */
/* ------------------------------------------------------------------ */

/**
 * Returns true for URLs Chrome forbids scripting into (chrome://, the
 * Web Store, other extensions, devtools, file://, view-source:, blank).
 * Avoids logging predictable "restricted URL" errors on every nav.
 */
function isRestrictedUrl(url: string): boolean {
    if (url.length === 0) return true;
    if (url === "about:blank") return true;
    if (url.startsWith("chrome://")) return true;
    if (url.startsWith("chrome-search://")) return true;
    if (url.startsWith("chrome-extension://")) return true;
    if (url.startsWith("chrome-untrusted://")) return true;
    if (url.startsWith("moz-extension://")) return true;
    if (url.startsWith("edge://")) return true;
    if (url.startsWith("brave://")) return true;
    if (url.startsWith("opera://")) return true;
    if (url.startsWith("about:")) return true;
    if (url.startsWith("devtools://")) return true;
    if (url.startsWith("view-source:")) return true;
    if (url.startsWith("file://")) return true;
    if (url.startsWith("https://chrome.google.com/webstore")) return true;
    if (url.startsWith("https://chromewebstore.google.com")) return true;
    return false;
}

/** Single source of truth for the dedup gate + decision write + sentinel. */
async function runGate(
    tabId: number,
    url: string,
    trigger: TabDecision["trigger"],
): Promise<void> {
    if (isRestrictedUrl(url)) {
        // Scripting is forbidden here — clear any stale decision and exit
        // silently. Logging would flood on chrome:// and Web Store tabs.
        clearTabDecision(tabId);
        return;
    }

    const fp = urlFingerprint(url);

    const isDuplicate = isSameDecisionFingerprint(tabId, fp);
    if (isDuplicate) {
        // Cache hit — the whole point of the gate. Stay silent.
        return;
    }

    try {
        const matches = await evaluateUrlMatches(url);
        const decision: TabDecision = {
            urlFp: fp,
            url,
            matches,
            trigger,
            decidedAt: Date.now(),
        };
        setTabDecision(tabId, decision);
        await injectSentinel(tabId, decision);
        console.log(
            `[url-trigger] ${trigger} tab=${tabId} matches=${matches.length} fp=${fp}`,
        );
    } catch (err) {
        // NEVER rethrow — would unregister the chrome listener.
        logCaughtError(
            BgLogTag.MARCO,
            `[url-trigger] gate failed (trigger=${trigger}, tab=${tabId})`,
            err,
        );
    }
}

/* ------------------------------------------------------------------ */
/*  Sentinel injection                                                 */
/* ------------------------------------------------------------------ */

/**
 * Injects (or updates) the `<div id="__marco_sentinel__">` element at
 * the end of `<body>` with the decision summary as data-* attributes.
 * Idempotent: same fingerprint → no DOM write.
 *
 * Runs in the page MAIN world via `chrome.scripting.executeScript` so
 * the page itself (and other content scripts) can read it cheaply.
 */
async function injectSentinel(
    tabId: number,
    decision: TabDecision,
): Promise<void> {
    try {
        await chrome.scripting.executeScript({
            target: { tabId },
            world: "MAIN",
            func: writeSentinelInPage,
            args: [
                MARCO_SENTINEL_ID,
                SENTINEL_ATTR_FP,
                SENTINEL_ATTR_PROJECTS,
                SENTINEL_ATTR_CAN_RUN,
                SENTINEL_ATTR_TRIGGER,
                SENTINEL_ATTR_DECIDED_AT,
                decision.urlFp,
                decision.matches.map((m) => m.projectId).join(","),
                decision.matches.length > 0,
                decision.trigger,
                decision.decidedAt,
            ],
        });
    } catch (err) {
        // The upfront `isRestrictedUrl()` guard in `runGate` filters the
        // predictable chrome://, Web Store, and other-extension cases.
        // A second class of URLs (NTP remote content, prerendered tabs,
        // PDFs, discarded tabs, in-flight navigations) is only knowable
        // post-hoc via Chrome's "Cannot access contents of the page"
        // error — treat those as restricted: clear the stale decision
        // and stay silent rather than flooding the error log.
        const message = err instanceof Error ? err.message : String(err);
        const isHostPermissionRefusal =
            message.includes("Cannot access contents of the page") ||
            message.includes("Cannot access a chrome") ||
            message.includes("The extensions gallery cannot be scripted") ||
            message.includes("No tab with id") ||
            message.includes("The tab was closed");
        if (isHostPermissionRefusal) {
            clearTabDecision(tabId);
            return;
        }
        logCaughtError(
            BgLogTag.MARCO,
            `[url-trigger] sentinel inject failed (tab=${tabId})`,
            err,
        );
    }
}

/**
 * Page-side function. Serialized by Chrome — keep self-contained
 * (no closures, no imports, only the primitives passed via `args`).
 */
function writeSentinelInPage(
    id: string,
    attrFp: string,
    attrProjects: string,
    attrCanRun: string,
    attrTrigger: string,
    attrDecidedAt: string,
    fp: string,
    projectsCsv: string,
    canRun: boolean,
    trigger: string,
    decidedAt: number,
): void {
    try {
        const existing = document.getElementById(id);
        const isSameFp = existing !== null && existing.getAttribute(attrFp) === fp;
        if (isSameFp) {
            return;
        }
        const element = existing ?? document.createElement("div");
        element.id = id;
        element.setAttribute(attrFp, fp);
        element.setAttribute(attrProjects, projectsCsv);
        element.setAttribute(attrCanRun, String(canRun));
        element.setAttribute(attrTrigger, trigger);
        element.setAttribute(attrDecidedAt, String(decidedAt));
        element.style.display = "none";
        const isNew = existing === null;
        if (isNew) {
            const host = document.body ?? document.documentElement;
            host.appendChild(element);
        }
    } catch { // allow-swallow: page may be mid-navigation / detached; sentinel element write is best-effort and re-runs on next decision.
        // Page may be mid-navigation; safe to drop.
    }
}

/* ------------------------------------------------------------------ */
/*  Public read helper (background-side mirror)                        */
/* ------------------------------------------------------------------ */

/** Returns the cached decision for a tab, or null. Sync, hot-path safe. */
export function readDecision(tabId: number): TabDecision | null {
    return getTabDecision(tabId) ?? null;
}

import { useEffect, useRef, useState, useCallback } from "react";
import { AlertOctagon, Copy, Check, X } from "lucide-react";
import { HTTP_FAIL_FAST_EVENT, type HttpFailFastEventDetail } from "@/shared/http-fail-fast";

/**
 * Dismissible global banner that surfaces the most recent
 * `HttpFailFastError` (HEFF) emitted anywhere in the UI layer.
 *
 * Wiring contract (Step 7 of the HEFF rollout):
 *  - `HttpFailFastError` constructor dispatches a `marco:http-fail-fast`
 *    window CustomEvent with the full report string.
 *  - This banner listens for that event and renders the latest failure
 *    until the user dismisses it. Newer failures replace older ones so
 *    the banner never stacks indefinitely.
 *  - Mount once near the root of each UI surface (Options, Popup).
 *
 * Honors the project's no-retry / fail-fast policy: the banner does NOT
 * offer a "Retry" button — only "Copy report" + dismiss.
 */
export function HttpFailFastBanner() {
    const [detail, setDetail] = useState<HttpFailFastEventDetail | null>(null);
    const [copied, setCopied] = useState(false);
    const copyTimerRef = useRef<number | null>(null);

    useEffect(() => {
        const onEvent = (evt: Event): void => {
            const ce = evt as CustomEvent<HttpFailFastEventDetail>;
            if (ce.detail === null || ce.detail === undefined) return;
            setDetail(ce.detail);
            setCopied(false);
        };
        window.addEventListener(HTTP_FAIL_FAST_EVENT, onEvent);
        return () => window.removeEventListener(HTTP_FAIL_FAST_EVENT, onEvent);
    }, []);

    useEffect(() => () => {
        if (copyTimerRef.current !== null) clearTimeout(copyTimerRef.current);
    }, []);

    const handleCopy = useCallback(async () => {
        if (detail === null) return;
        try {
            await navigator.clipboard.writeText(detail.report);
            setCopied(true);
            if (copyTimerRef.current !== null) clearTimeout(copyTimerRef.current);
            copyTimerRef.current = window.setTimeout(() => setCopied(false), 2000);
        // allow-swallow: clipboard denied; user can select text manually
        } catch { /* intentionally empty */ }
    }, [detail]);

    if (detail === null) return null;

    const shortUrl = detail.url.length > 80 ? detail.url.slice(0, 77) + "…" : detail.url;

    return (
        <div
            role="alert"
            aria-live="assertive"
            className="fixed top-2 left-1/2 -translate-x-1/2 z-[100] w-[min(680px,calc(100vw-1rem))] rounded-md border border-destructive/50 bg-destructive/10 backdrop-blur-md px-3 py-2.5 shadow-lg"
        >
            <div className="flex items-start gap-2">
                <AlertOctagon className="h-4 w-4 text-destructive shrink-0 mt-0.5" />
                <div className="flex-1 min-w-0">
                    <p className="text-xs font-semibold text-destructive">
                        HTTP {detail.status} on {detail.method}
                        <span className="ml-1 font-mono font-normal break-all">{shortUrl}</span>
                    </p>
                    <p className="text-[11px] text-destructive/90 mt-0.5 break-words">
                        {detail.reason}
                    </p>
                    {detail.bodySnippet !== null && detail.bodySnippet.length > 0 ? (
                        <pre className="mt-1 text-[10px] font-mono text-destructive/80 bg-background/40 rounded p-1.5 max-h-24 overflow-auto whitespace-pre-wrap break-words border border-destructive/20">
                            {detail.bodySnippet}
                        </pre>
                    ) : null}
                </div>
                <div className="shrink-0 flex items-center gap-1">
                    <button
                        onClick={handleCopy}
                        className="inline-flex items-center gap-1 text-[10px] font-medium px-2 py-1 rounded border border-destructive/40 hover:bg-destructive/20 text-destructive transition-colors"
                        title="Copy full HEFF report to clipboard"
                    >
                        {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
                        {copied ? "Copied" : "Copy"}
                    </button>
                    <button
                        onClick={() => setDetail(null)}
                        className="inline-flex items-center justify-center h-6 w-6 rounded border border-destructive/40 hover:bg-destructive/20 text-destructive transition-colors"
                        title="Dismiss"
                        aria-label="Dismiss HTTP fail-fast banner"
                    >
                        <X className="h-3 w-3" />
                    </button>
                </div>
            </div>
        </div>
    );
}

export default HttpFailFastBanner;

/**
 * Auto-Attach Diagnostics Panel
 *
 * Surfaces the latest `evaluateAutoAttach` decisions for the current
 * project so users can see *why* a library script was (or wasn't)
 * auto-attached. Read-only — refreshes after each project save via the
 * `GET_AUTO_ATTACH_DECISIONS` background message.
 *
 * Backed by mem://features/auto-attach-policy.md §4 "Diagnostics tab".
 */

import { useEffect, useState } from "react";
import { getPlatform } from "@/platform";
import { MessageType } from "@/shared/messages";

interface Decision {
  scriptId: string;
  scriptName: string;
  ok: boolean;
  reason: string;
  detail: string;
}

interface Record {
  projectId: string;
  projectName: string;
  evaluatedAt: string;
  decisions: Decision[];
}

interface Props {
  projectId: string;
  autoStart: boolean;
  refreshKey: number;
}

function reasonBadge(reason: string, ok: boolean): { label: string; cls: string } {
  if (ok) return { label: "OK", cls: "bg-green-500/15 text-green-300 border-green-500/30" };
  if (reason === "AUTOATTACH_SKIPPED_AUTOSTART_OFF")
    return { label: "autoStart off", cls: "bg-muted/40 text-muted-foreground border-border" };
  if (reason === "AUTOATTACH_SKIPPED_URL_NO_MATCH")
    return { label: "URL no match", cls: "bg-amber-500/10 text-amber-300 border-amber-500/30" };
  if (reason === "AUTOATTACH_ALREADY_ATTACHED")
    return { label: "Already attached", cls: "bg-blue-500/10 text-blue-300 border-blue-500/30" };
  if (reason === "AUTOATTACH_SKIPPED_OPT_OUT")
    return { label: "Opted out", cls: "bg-muted/40 text-muted-foreground border-border" };
  return { label: reason.replace("AUTOATTACH_SKIPPED_", "").toLowerCase(), cls: "bg-red-500/10 text-red-300 border-red-500/30" };
}

export function AutoAttachDiagnosticsPanel({ projectId, autoStart, refreshKey }: Props) {
  const [record, setRecord] = useState<Record | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let alive = true;
    setLoading(true);
    getPlatform()
      .sendMessage<{ record: Record | null }>({ type: MessageType.GET_AUTO_ATTACH_DECISIONS, projectId })
      .then((res) => {
        if (alive) setRecord(res?.record ?? null);
      })
      .catch(() => {
        if (alive) setRecord(null);
      })
      .finally(() => {
        if (alive) setLoading(false);
      });
    return () => {
      alive = false;
    };
  }, [projectId, refreshKey]);

  return (
    <div className="rounded-md border border-border bg-card/40 p-3 mb-3">
      <div className="flex items-center justify-between mb-2">
        <h4 className="text-sm font-medium">Auto-Attach Diagnostics</h4>
        <span className="text-xs text-muted-foreground">
          autoStart: <span className={autoStart ? "text-green-400" : "text-muted-foreground"}>{autoStart ? "ON" : "OFF"}</span>
          {record?.evaluatedAt ? ` · evaluated ${new Date(record.evaluatedAt).toLocaleTimeString()}` : ""}
        </span>
      </div>
      {!autoStart && (
        <p className="text-xs text-muted-foreground">
          Enable <code className="px-1 rounded bg-muted/40">autoStart</code> in project settings to auto-attach matching library scripts.
        </p>
      )}
      {loading && <p className="text-xs text-muted-foreground">Loading…</p>}
      {!loading && record && record.decisions.length === 0 && (
        <p className="text-xs text-muted-foreground">No library scripts evaluated yet. Save the project to run evaluation.</p>
      )}
      {!loading && record && record.decisions.length > 0 && (
        <ul className="space-y-1 max-h-48 overflow-auto">
          {record.decisions.map((d) => {
            const b = reasonBadge(d.reason, d.ok);
            return (
              <li key={d.scriptId} className="flex items-start gap-2 text-xs">
                <span className={`shrink-0 px-1.5 py-0.5 rounded border ${b.cls}`}>{b.label}</span>
                <span className="font-mono">{d.scriptName}</span>
                <span className="text-muted-foreground truncate" title={d.detail}>— {d.detail}</span>
              </li>
            );
          })}
        </ul>
      )}
      {!loading && !record && (
        <p className="text-xs text-muted-foreground">No evaluation record yet. Save the project to populate.</p>
      )}
    </div>
  );
}

/**
 * Marco Extension — Batch Delete Dialog
 *
 * Destructive confirmation surface for deleting every currently
 * selected step group in one shot. The dialog spells out exactly
 * what will be lost — counts of nested groups + steps that will
 * cascade — so the user has a real chance to back out.
 *
 * **No undo.** Cascading deletes wipe nested groups, every step
 * inside them, plus per-step wait configs and per-group input bags
 * stored in localStorage siblings. Restoring those from a snapshot
 * would re-allocate IDs, breaking any RunGroup step still pointing
 * at them. The honest UX is to make this dialog hard to dismiss
 * accidentally — a confirmation phrase + an explicit destructive
 * action button — rather than promise a recovery we can't deliver.
 */

import { useState } from "react";
import { AlertTriangle, Trash2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";

import type { StepGroupRow } from "@/background/recorder/step-library/db";

export interface BatchDeleteRow {
    readonly Group: StepGroupRow;
    /** Total descendants (excluding the group itself). */
    readonly DescendantCount: number;
    /** Total steps inside this group + every descendant. */
    readonly StepCount: number;
}

export interface BatchDeleteDialogProps {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly rows: ReadonlyArray<BatchDeleteRow>;
    /** Fired with the ordered list of root ids to delete. */
    readonly onConfirm: (ids: ReadonlyArray<number>) => void;
}

const CONFIRM_PHRASE = "delete";

export default function BatchDeleteDialog({
    open,
    onOpenChange,
    rows,
    onConfirm,
}: BatchDeleteDialogProps) {
    const [phrase, setPhrase] = useState("");

    const totalGroups = rows.reduce((n, r) => n + 1 + r.DescendantCount, 0);
    const totalSteps = rows.reduce((n, r) => n + r.StepCount, 0);
    const canConfirm = rows.length > 0 && phrase.trim().toLowerCase() === CONFIRM_PHRASE;

    const handleConfirm = () => {
        if (!canConfirm) return;
        onConfirm(rows.map((r) => r.Group.StepGroupId));
        setPhrase("");
        onOpenChange(false);
    };

    return (
        <AlertDialog
            open={open}
            onOpenChange={(o) => {
                if (!o) setPhrase("");
                onOpenChange(o);
            }}
        >
            <AlertDialogContent className="max-w-lg">
                <AlertDialogHeader>
                    <AlertDialogTitle className="flex items-center gap-2 text-destructive">
                        <AlertTriangle className="h-5 w-5" />
                        Delete {rows.length} group{rows.length === 1 ? "" : "s"}?
                    </AlertDialogTitle>
                    <AlertDialogDescription asChild>
                        <div className="space-y-2 text-sm text-muted-foreground">
                            <p>
                                This permanently removes <strong className="text-foreground">{totalGroups}</strong> group
                                {totalGroups === 1 ? "" : "s"} and{" "}
                                <strong className="text-foreground">{totalSteps}</strong> step
                                {totalSteps === 1 ? "" : "s"} (including every nested
                                child group). <strong className="text-destructive">This cannot be undone.</strong>
                            </p>
                            <p className="text-xs">
                                Tip: export the selection as a ZIP first if you might need it back.
                            </p>
                        </div>
                    </AlertDialogDescription>
                </AlertDialogHeader>

                <ScrollArea className="max-h-48 rounded border">
                    <ul className="divide-y text-sm">
                        {rows.map((r) => (
                            <li key={r.Group.StepGroupId} className="flex items-center gap-2 px-3 py-2">
                                <Trash2 className="h-3.5 w-3.5 shrink-0 text-destructive/70" />
                                <span className="min-w-0 flex-1 truncate font-medium">
                                    {r.Group.Name}
                                </span>
                                <span className="shrink-0 text-xs text-muted-foreground">
                                    {r.DescendantCount > 0 && (
                                        <>+{r.DescendantCount} nested · </>
                                    )}
                                    {r.StepCount} step{r.StepCount === 1 ? "" : "s"}
                                </span>
                            </li>
                        ))}
                    </ul>
                </ScrollArea>

                <div className="space-y-1.5">
                    <Label htmlFor="batch-delete-confirm" className="text-xs">
                        Type <span className="font-mono font-semibold">{CONFIRM_PHRASE}</span> to confirm
                    </Label>
                    <Input
                        id="batch-delete-confirm"
                        value={phrase}
                        onChange={(e) => setPhrase(e.target.value)}
                        placeholder={CONFIRM_PHRASE}
                        autoComplete="off"
                    />
                </div>

                <AlertDialogFooter>
                    <AlertDialogCancel>Cancel</AlertDialogCancel>
                    <AlertDialogAction asChild>
                        <Button
                            variant="destructive"
                            onClick={handleConfirm}
                            disabled={!canConfirm}
                        >
                            <Trash2 className="mr-1 h-4 w-4" />
                            Delete {rows.length} group{rows.length === 1 ? "" : "s"}
                        </Button>
                    </AlertDialogAction>
                </AlertDialogFooter>
            </AlertDialogContent>
        </AlertDialog>
    );
}

/**
 * Marco Extension — Batch Rename Dialog
 *
 * Lets the user rename every selected step group at once via one of
 * four composable transforms:
 *
 *   • **Find & replace** — case-sensitive substring swap
 *   • **Add prefix**     — prepend a fixed string
 *   • **Add suffix**     — append a fixed string
 *   • **Sequence**       — rename every selected row to "{Base}{N}" with
 *                          a configurable start number and zero-padding
 *                          width. If the Base contains the literal token
 *                          `{n}` the number is substituted there; otherwise
 *                          it is appended after a separator.
 *
 * The dialog renders a live preview row for every selected group:
 * "OldName  →  NewName", with badges for `unchanged`, `invalid`
 * (validation failure), and `conflict` (would clash with a sibling
 * that's NOT being renamed in the same batch). The Apply button is
 * disabled until at least one row is changed AND zero rows are
 * invalid/conflicting.
 *
 * On Apply the caller receives a list of `{ Id, OldName, NewName }`
 * tuples to commit + a chance to push an undo toast. The dialog itself
 * never touches the database.
 */

import { useMemo, useState } from "react";
import { ArrowRight, AlertTriangle, Pencil } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
} from "@/components/ui/tabs";

import type { StepGroupRow } from "@/background/recorder/step-library/db";
import {
    STEP_GROUP_NAME_MAX_LEN,
    validateStepGroupName,
} from "./step-group-name-validator";

/* ------------------------------------------------------------------ */
/*  Public types                                                       */
/* ------------------------------------------------------------------ */

export interface BatchRenameChange {
    readonly Id: number;
    readonly OldName: string;
    readonly NewName: string;
}

export interface BatchRenameDialogProps {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    /**
     * The groups the user has selected, in any order. Each row is
     * shown in the preview — even unselected siblings are excluded.
     */
    readonly targets: ReadonlyArray<StepGroupRow>;
    /**
     * Every group in the project (used to compute sibling-name
     * conflicts against rows NOT in `targets`). Pass the full
     * `lib.Groups` array — the dialog filters internally.
     */
    readonly allGroups: ReadonlyArray<StepGroupRow>;
    /** Fired with the final {Id, Old, New} list when the user confirms. */
    readonly onApply: (changes: ReadonlyArray<BatchRenameChange>) => void;
}

/* ------------------------------------------------------------------ */
/*  Transforms                                                         */
/* ------------------------------------------------------------------ */

type Mode = "replace" | "prefix" | "suffix" | "sequence";

interface TransformInput {
    readonly Mode: Mode;
    readonly Find: string;
    readonly Replace: string;
    readonly Prefix: string;
    readonly Suffix: string;
    /** Sequence base name. May contain `{n}` as the substitution token. */
    readonly SequenceBase: string;
    /** Sequence start number (defaults to 1). Negative values clamp to 0. */
    readonly SequenceStart: number;
    /** Zero-padding width (1 → "1", 2 → "01", 3 → "001"). Clamped to 1..6. */
    readonly SequencePadding: number;
    /** Separator between base and number when `{n}` is absent. */
    readonly SequenceSeparator: string;
}

const SEQUENCE_TOKEN = "{n}";

function formatSequenceNumber(n: number, padding: number): string {
    const width = Math.max(1, Math.min(6, Math.floor(padding)));
    return String(Math.max(0, Math.floor(n))).padStart(width, "0");
}

/** Builds the new name for the `index`-th selected target (0-based). */
function applySequence(t: TransformInput, index: number): string {
    const n = formatSequenceNumber(t.SequenceStart + index, t.SequencePadding);
    if (t.SequenceBase.includes(SEQUENCE_TOKEN)) {
        return t.SequenceBase.split(SEQUENCE_TOKEN).join(n);
    }
    const base = t.SequenceBase.trim();
    if (base.length === 0) return n;
    return `${base}${t.SequenceSeparator}${n}`;
}

function applyTransform(name: string, t: TransformInput, index: number): string {
    switch (t.Mode) {
        case "replace":
            // Empty Find = identity. Splitting on empty string would
            // explode the name into per-character pieces.
            if (t.Find === "") return name;
            return name.split(t.Find).join(t.Replace);
        case "prefix":
            return `${t.Prefix}${name}`;
        case "suffix":
            return `${name}${t.Suffix}`;
        case "sequence":
            return applySequence(t, index);
    }
}

/* ------------------------------------------------------------------ */
/*  Per-row preview                                                    */
/* ------------------------------------------------------------------ */

interface PreviewRow {
    readonly Id: number;
    readonly OldName: string;
    readonly NewName: string;
    readonly Changed: boolean;
    /** `null` when fine, otherwise the user-facing reason. */
    readonly Issue: string | null;
}

function buildPreview(
    targets: ReadonlyArray<StepGroupRow>,
    allGroups: ReadonlyArray<StepGroupRow>,
    transform: TransformInput,
): ReadonlyArray<PreviewRow> {
    const targetIds = new Set(targets.map((g) => g.StepGroupId));

    // Sibling names that are NOT being renamed, indexed by parent.
    // Renames within the batch are validated separately below so two
    // selected siblings swapping into each other don't trip the
    // single-name validator.
    const externalSiblingsByParent = new Map<number | null, string[]>();
    for (const g of allGroups) {
        if (targetIds.has(g.StepGroupId)) continue;
        const key = g.ParentStepGroupId ?? null;
        const entries = externalSiblingsByParent.get(key) ?? [];
        entries.push(g.Name);
        externalSiblingsByParent.set(key, entries);
    }

    // Track new names *within* the batch per parent — clashes inside
    // the batch are also surfaced (two groups both renamed to "Foo").
    const newNamesByParent = new Map<number | null, Map<string, number>>();

    const rows: PreviewRow[] = targets.map((g, i) => {
        const newName = applyTransform(g.Name, transform, i);
        const trimmed = newName.trim();
        const parent = g.ParentStepGroupId ?? null;
        const externals = externalSiblingsByParent.get(parent) ?? [];
        const baseIssue = validateStepGroupName(newName, externals);
        const issue: string | null = (() => {
            if (newName === g.Name) return null; // unchanged is fine
            return baseIssue;
        })();

        // Record for intra-batch clash detection (post-trim, lowered).
        const slot = newNamesByParent.get(parent) ?? new Map<string, number>();
        const key = trimmed.toLowerCase();
        slot.set(key, (slot.get(key) ?? 0) + 1);
        newNamesByParent.set(parent, slot);

        return {
            Id: g.StepGroupId,
            OldName: g.Name,
            NewName: newName,
            Changed: newName !== g.Name,
            Issue: issue,
        };
    });

    // Second pass: flag intra-batch duplicates.
    return rows.map((r) => {
        if (r.Issue !== null) return r;
        if (!r.Changed) return r;
        const target = targets.find((g) => g.StepGroupId === r.Id);
        if (target === undefined) return r;
        const parent = target.ParentStepGroupId ?? null;
        const slot = newNamesByParent.get(parent);
        const count = slot?.get(r.NewName.trim().toLowerCase()) ?? 0;
        if (count > 1) {
            return { ...r, Issue: "Two selected groups would share this name." };
        }
        return r;
    });
}

