export default function BatchRenameDialog({
    open,
    onOpenChange,
    targets,
    allGroups,
    onApply,
}: BatchRenameDialogProps) {
    const [mode, setMode] = useState<Mode>("replace");
    const [find, setFind] = useState("");
    const [replace, setReplace] = useState("");
    const [prefix, setPrefix] = useState("");
    const [suffix, setSuffix] = useState("");
    const [sequenceBase, setSequenceBase] = useState("");
    const [sequenceStart, setSequenceStart] = useState(1);
    const [sequencePadding, setSequencePadding] = useState(1);
    const [sequenceSeparator, setSequenceSeparator] = useState(" ");

    const transform: TransformInput = {
        Mode: mode,
        Find: find,
        Replace: replace,
        Prefix: prefix,
        Suffix: suffix,
        SequenceBase: sequenceBase,
        SequenceStart: sequenceStart,
        SequencePadding: sequencePadding,
        SequenceSeparator: sequenceSeparator,
    };
    const preview = useMemo(
        () => buildPreview(targets, allGroups, transform),
        // `transform` is stable enough — recompute whenever any input changes.
        // eslint-disable-next-line react-hooks/exhaustive-deps
        [targets, allGroups, mode, find, replace, prefix, suffix,
         sequenceBase, sequenceStart, sequencePadding, sequenceSeparator],
    );

    const changedCount = preview.filter((r) => r.Changed).length;
    const issueCount = preview.filter((r) => r.Issue !== null).length;
    const canApply = changedCount > 0 && issueCount === 0;

    const handleApply = () => {
        if (!canApply) return;
        const changes: BatchRenameChange[] = preview
            .filter((r) => r.Changed)
            .map((r) => ({ Id: r.Id, OldName: r.OldName, NewName: r.NewName.trim() }));
        onApply(changes);
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Pencil className="h-4 w-4" /> Batch rename
                    </DialogTitle>
                    <DialogDescription>
                        Renames every selected group using the chosen transform.
                        Preview the result below — Apply is blocked until all
                        conflicts are resolved.
                    </DialogDescription>
                </DialogHeader>

                <Tabs value={mode} onValueChange={(v) => setMode(v as Mode)}>
                    <TabsList className="grid w-full grid-cols-4">
                        <TabsTrigger value="replace">Find &amp; replace</TabsTrigger>
                        <TabsTrigger value="prefix">Add prefix</TabsTrigger>
                        <TabsTrigger value="suffix">Add suffix</TabsTrigger>
                        <TabsTrigger value="sequence">Sequence</TabsTrigger>
                    </TabsList>

                    <TabsContent value="replace" className="space-y-2 pt-3">
                        <div className="grid grid-cols-2 gap-2">
                            <div>
                                <Label htmlFor="batch-find" className="text-xs">Find</Label>
                                <Input
                                    id="batch-find"
                                    value={find}
                                    onChange={(e) => setFind(e.target.value)}
                                    placeholder="e.g. Old"
                                    maxLength={STEP_GROUP_NAME_MAX_LEN}
                                />
                            </div>
                            <div>
                                <Label htmlFor="batch-replace" className="text-xs">Replace with</Label>
                                <Input
                                    id="batch-replace"
                                    value={replace}
                                    onChange={(e) => setReplace(e.target.value)}
                                    placeholder="e.g. New"
                                    maxLength={STEP_GROUP_NAME_MAX_LEN}
                                />
                            </div>
                        </div>
                        <p className="text-xs text-muted-foreground">
                            Case-sensitive. Empty Find leaves names unchanged.
                        </p>
                    </TabsContent>

                    <TabsContent value="prefix" className="space-y-2 pt-3">
                        <Label htmlFor="batch-prefix" className="text-xs">Prefix</Label>
                        <Input
                            id="batch-prefix"
                            value={prefix}
                            onChange={(e) => setPrefix(e.target.value)}
                            placeholder="e.g. [archived] "
                            maxLength={STEP_GROUP_NAME_MAX_LEN}
                        />
                    </TabsContent>

                    <TabsContent value="suffix" className="space-y-2 pt-3">
                        <Label htmlFor="batch-suffix" className="text-xs">Suffix</Label>
                        <Input
                            id="batch-suffix"
                            value={suffix}
                            onChange={(e) => setSuffix(e.target.value)}
                            placeholder="e.g.  (v2)"
                            maxLength={STEP_GROUP_NAME_MAX_LEN}
                        />
                    </TabsContent>

                    <TabsContent value="sequence" className="space-y-2 pt-3">
                        <div className="grid grid-cols-[1fr_auto_auto_auto] gap-2">
                            <div>
                                <Label htmlFor="batch-seq-base" className="text-xs">
                                    Base name
                                </Label>
                                <Input
                                    id="batch-seq-base"
                                    value={sequenceBase}
                                    onChange={(e) => setSequenceBase(e.target.value)}
                                    placeholder="e.g. Login {n}"
                                    maxLength={STEP_GROUP_NAME_MAX_LEN}
                                />
                            </div>
                            <div className="w-20">
                                <Label htmlFor="batch-seq-start" className="text-xs">Start</Label>
                                <Input
                                    id="batch-seq-start"
                                    type="number"
                                    min={0}
                                    value={sequenceStart}
                                    onChange={(e) => setSequenceStart(Number(e.target.value) || 0)}
                                />
                            </div>
                            <div className="w-20">
                                <Label htmlFor="batch-seq-padding" className="text-xs">Padding</Label>
                                <Input
                                    id="batch-seq-padding"
                                    type="number"
                                    min={1}
                                    max={6}
                                    value={sequencePadding}
                                    onChange={(e) =>
                                        setSequencePadding(
                                            Math.max(1, Math.min(6, Number(e.target.value) || 1)),
                                        )
                                    }
                                />
                            </div>
                            <div className="w-16">
                                <Label htmlFor="batch-seq-sep" className="text-xs">Sep</Label>
                                <Input
                                    id="batch-seq-sep"
                                    value={sequenceSeparator}
                                    onChange={(e) => setSequenceSeparator(e.target.value)}
                                    placeholder=" "
                                    maxLength={4}
                                />
                            </div>
                        </div>
                        <p className="text-xs text-muted-foreground">
                            Use <code className="rounded bg-muted px-1">{"{n}"}</code> in the
                            base name to control where the number goes
                            (e.g. <code className="rounded bg-muted px-1">Step {"{n}"} — login</code>).
                            Without it, the number is appended after the separator.
                            Padding 2 → <code className="rounded bg-muted px-1">01</code>,
                            3 → <code className="rounded bg-muted px-1">001</code>.
                        </p>
                    </TabsContent>
                </Tabs>

                <div className="flex items-center justify-between text-xs text-muted-foreground">
                    <span>
                        {changedCount} of {preview.length} group(s) will change
                    </span>
                    {issueCount > 0 && (
                        <span className="flex items-center gap-1 text-destructive">
                            <AlertTriangle className="h-3.5 w-3.5" />
                            {issueCount} conflict{issueCount === 1 ? "" : "s"}
                        </span>
                    )}
                </div>

                <ScrollArea className="h-64 rounded border">
                    <ul className="divide-y text-sm">
                        {preview.map((r) => (
                            <li
                                key={r.Id}
                                className={[
                                    "flex items-center gap-2 px-3 py-2",
                                    r.Issue !== null ? "bg-destructive/5" : "",
                                ].join(" ")}
                            >
                                <span className="min-w-0 flex-1 truncate text-muted-foreground line-through decoration-muted-foreground/40">
                                    {r.OldName}
                                </span>
                                <ArrowRight className="h-3.5 w-3.5 shrink-0 text-muted-foreground/60" />
                                <span
                                    className={[
                                        "min-w-0 flex-1 truncate font-medium",
                                        r.Issue !== null
                                            ? "text-destructive"
                                            : r.Changed
                                                ? "text-foreground"
                                                : "text-muted-foreground",
                                    ].join(" ")}
                                    title={r.NewName}
                                >
                                    {r.NewName}
                                </span>
                                {!r.Changed && (
                                    <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] uppercase tracking-wide text-muted-foreground">
                                        Unchanged
                                    </span>
                                )}
                                {r.Issue !== null && (
                                    <span
                                        className="max-w-[18ch] truncate text-[10px] text-destructive"
                                        title={r.Issue}
                                    >
                                        {r.Issue}
                                    </span>
                                )}
                            </li>
                        ))}
                    </ul>
                </ScrollArea>

                <DialogFooter>
                    <Button variant="outline" onClick={() => onOpenChange(false)}>
                        Cancel
                    </Button>
                    <Button onClick={handleApply} disabled={!canApply}>
                        Rename {changedCount} group{changedCount === 1 ? "" : "s"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

/**
 * Marco Extension — Batch Run Dialog
 *
 * Runs a user-selected list of StepGroups one after another in the
 * order chosen, and shows a live per-group status row.
 *
 * The row order is FIRST seeded from the caller-provided
 * `initialOrder` (which is the order in which the user ticked the
 * checkboxes in the library tree). Inside the dialog the user can
 * still re-arrange via ▲ / ▼ before pressing Run.
 *
 * Execution itself is delegated to the pure `runBatch` helper so the
 * same code paths the unit tests cover are what the user clicks.
 *
 * @see src/background/recorder/step-library/run-batch.ts
 */

import { useEffect, useMemo, useState } from "react";
import { ChevronDown, ChevronRight, ChevronUp, Loader2, Play, X } from "lucide-react";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Switch } from "@/components/ui/switch";

import {
    runBatch,
    type BatchFailurePolicy,
    type BatchGroupReport,
    type BatchGroupStatus,
} from "@/background/recorder/step-library/run-batch";
import type { StepGroupRow, StepLibraryDb } from "@/background/recorder/step-library/db";
import type { LeafStepExecutor, RunStepTraceEntry } from "@/background/recorder/step-library/run-group-runner";
import { createLiveReplayExecutor } from "@/background/recorder/step-library/replay-bridge";
import {
    buildBatchCompletePayload,
    buildGroupRunPayload,
    dispatchWebhook,
} from "@/background/recorder/step-library/result-webhook";
import {
    mergeInputBags,
    resolveBatchInputSnapshot,
} from "@/background/recorder/step-library/input-source";
import type { GroupInputBag } from "@/background/recorder/step-library/group-inputs";

import RunResultsSummaryPanel from "./RunResultsSummaryPanel";
import RunTraceViewer from "./RunTraceViewer";

interface BatchRunDialogProps {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly db: StepLibraryDb | null;
    readonly projectId: number | null;
    readonly initialOrder: ReadonlyArray<number>;
    readonly groupsById: ReadonlyMap<number, StepGroupRow>;
    /** Locally-saved input bag per group, used as the merge baseline. */
    readonly groupInputs: ReadonlyMap<number, GroupInputBag>;
    /** Persists the merged bag back so the rest of the app sees it. */
    readonly onApplyMergedInput: (groupId: number, bag: GroupInputBag) => void;
}

const STATUS_STYLE: Record<BatchGroupStatus, string> = {
    Pending:   "bg-muted text-muted-foreground",
    Running:   "bg-primary/15 text-primary",
    Succeeded: "bg-emerald-500/15 text-emerald-600 dark:text-emerald-400",
    Failed:    "bg-destructive/15 text-destructive",
    Skipped:   "bg-amber-500/15 text-amber-600 dark:text-amber-400",
};

function move<T>(values: ReadonlyArray<T>, from: number, to: number): T[] {
    if (to < 0 || to >= values.length) return values.slice();
    const next = values.slice();
    [next[from], next[to]] = [next[to], next[from]];
    return next;
}

function formatDuration(ms: number): string {
    if (ms < 1000) return `${ms} ms`;
    return `${(ms / 1000).toFixed(2)} s`;
}

export default function BatchRunDialog(props: BatchRunDialogProps) {
    const {
        open, onOpenChange, db, projectId, initialOrder, groupsById,
        groupInputs, onApplyMergedInput,
    } = props;
    const [order, setOrder] = useState<ReadonlyArray<number>>(initialOrder);
    const [reports, setReports] = useState<ReadonlyArray<BatchGroupReport>>([]);
    const [running, setRunning] = useState(false);
    const [continueOnFailure, setContinueOnFailure] = useState(false);
    /**
     * Live mode swaps the always-success `previewExecutor` for the
     * `createLiveReplayExecutor` bridge so each leaf step actually
     * dispatches DOM events into the Options-page document via
     * `executeReplay()`. Defaults OFF — opening the dialog must
     * never mutate the page accidentally.
     */
    const [liveMode, setLiveMode] = useState(false);
    /**
     * Total wall-clock duration of the just-completed run. `null` until
     * the first run finishes; cleared back to `null` whenever the user
     * re-opens the dialog so a stale duration can't bleed into the
     * next batch's summary panel.
     */
    const [lastRunDurationMs, setLastRunDurationMs] = useState<number | null>(null);
    /**
     * Trace viewer is collapsed by default — long batches can produce
     * hundreds of trace entries and we don't want to bloat the dialog
     * height before the user opts in.
     */
    const [traceOpen, setTraceOpen] = useState(false);

    // Reset per-open: seed order, clear prior status rows + summary.
    useEffect(() => {
        if (open) {
            setOrder(initialOrder);
            setReports(initialOrder.map((id) => emptyReport(id)));
            setRunning(false);
            setLastRunDurationMs(null);
            setTraceOpen(false);
            setLiveMode(false);
        }
    }, [open, initialOrder]);

    const policy: BatchFailurePolicy = continueOnFailure ? "ContinueOnFailure" : "StopOnFailure";

    const handleRun = async () => {
        if (db === null || projectId === null) {
            toast.error("Library not ready");
            return;
        }
        if (order.length === 0) return;
        setRunning(true);

        // Resolve the run-time input source ONCE per batch and merge
        // it into each selected group's persisted bag before any group
        // executes. Honour the abort/continue policy stored on the
        // input-source config.
        const snapshot = await resolveBatchInputSnapshot();
        if (!snapshot.Result.Ok) {
            const continueAnyway = snapshot.Result.Continue;
            if (!continueAnyway) {
                setRunning(false);
                toast.error(`Input source failed: ${snapshot.Result.Error}. Run aborted.`);
                return;
            }
            toast.warning(`Input source failed: ${snapshot.Result.Error}. Continuing with local inputs.`);
        } else if (!snapshot.Result.Skipped && snapshot.Bag !== null) {
            const incoming = snapshot.Bag;
            for (const id of order) {
                const merged = mergeInputBags(groupInputs.get(id) ?? null, incoming);
                onApplyMergedInput(id, merged);
            }
            const keyCount = Object.keys(incoming).length;
            toast.success(`Input source: merged ${keyCount} key(s) into ${order.length} group(s)`);
        }

        setReports(order.map((id) => emptyReport(id)));
        const live: BatchGroupReport[] = order.map((id) => emptyReport(id));
        const executor: LeafStepExecutor = liveMode
            ? createLiveReplayExecutor({ Doc: document })
            : previewExecutor;
        const result = await runBatch({
            db,
            projectId,
            orderedGroupIds: order,
            executeLeafStep: executor,
            failurePolicy: policy,
            onGroupStatus: (report, idx) => {
                live[idx] = report;
                setReports(live.slice());
                // Fire per-group webhook on terminal statuses (fire-and-forget).
                if (report.Status === "Succeeded" || report.Status === "Failed") {
                    const groupRow = groupsById.get(report.StepGroupId);
                    const runResult = report.Result;
                    const failureReason = runResult !== null && !runResult.Ok
                        ? runResult.Reason
                        : undefined;
                    const failedStepId = runResult !== null && !runResult.Ok && runResult.FailedStepId !== null
                        ? runResult.FailedStepId
                        : undefined;
                    void dispatchWebhook(
                        report.Status === "Succeeded" ? "GroupRunSucceeded" : "GroupRunFailed",
                        buildGroupRunPayload({
                            ProjectId: projectId,
                            GroupId: report.StepGroupId,
                            GroupName: groupRow?.Name ?? `#${report.StepGroupId}`,
                            DurationMs: report.DurationMs,
                            StepsExecuted: runResult?.Trace.length ?? 0,
                            Outcome: report.Status,
                            FailureReason: failureReason,
                            FailedStepId: failedStepId,
                        }),
                    );
                }
            },
        });
        setRunning(false);
        setLastRunDurationMs(result.DurationMs);
        // Always emit a final BatchComplete event.
        void dispatchWebhook(
            "BatchComplete",
            buildBatchCompletePayload({
                ProjectId: projectId,
                TotalGroups: order.length,
                Succeeded: result.Succeeded,
                Failed: result.Failed,
                Skipped: result.Skipped,
                DurationMs: result.DurationMs,
                Ok: result.Ok,
            }),
        );
        if (result.Ok) {
            toast.success(`Batch complete — ${result.Succeeded} group(s) ran in ${formatDuration(result.DurationMs)}`);
        } else {
            toast.error(`Batch finished with ${result.Failed} failure(s), ${result.Skipped} skipped`);
        }
    };

    const summary = useMemo(() => {
        const counts = { Succeeded: 0, Failed: 0, Skipped: 0, Running: 0, Pending: 0 };
        for (const r of reports) counts[r.Status]++;
        return counts;
    }, [reports]);

    /**
     * Flatten every report's `Result.Trace` into a single ordered
     * stream for the trace viewer. Reports run sequentially in
     * `runBatch`, so concatenating in batch order preserves real
     * wall-clock order. Reports without a Result (Pending / Skipped
     * batch entries) contribute nothing.
     */
    const flatTrace = useMemo<ReadonlyArray<RunStepTraceEntry>>(() => {
        const out: RunStepTraceEntry[] = [];
        for (const r of reports) {
            const trace = r.Result?.Trace;
            if (trace !== undefined) out.push(...trace);
        }
        return out;
    }, [reports]);

    return (
        <Dialog open={open} onOpenChange={(o) => { if (!running) onOpenChange(o); }}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle>Run groups in batch</DialogTitle>
                    <DialogDescription>
                        Groups run sequentially in the order shown. Drag with the arrows to reorder before pressing Run.
                    </DialogDescription>
                </DialogHeader>

                <div className="flex items-center justify-between gap-4 rounded-md border bg-muted/30 px-3 py-2 text-sm">
                    <div className="flex items-center gap-3 text-muted-foreground">
                        <span>{order.length} group(s)</span>
                        {(summary.Succeeded + summary.Failed + summary.Skipped) > 0 && (
                            <span>
                                · {summary.Succeeded} ok · {summary.Failed} failed · {summary.Skipped} skipped
                            </span>
                        )}
                    </div>
                    <div className="flex items-center gap-4">
                        <label className="flex cursor-pointer items-center gap-2">
                            <Switch
                                checked={liveMode}
                                onCheckedChange={setLiveMode}
                                disabled={running}
                                aria-label="Live execution"
                            />
                            <span title="When on, each leaf step dispatches real DOM events into this page via the replay bridge.">Live execution</span>
                        </label>
                        <label className="flex cursor-pointer items-center gap-2">
                            <Switch
                                checked={continueOnFailure}
                                onCheckedChange={setContinueOnFailure}
                                disabled={running}
                                aria-label="Continue on failure"
                            />
                            <span>Continue on failure</span>
                        </label>
                    </div>
                </div>

                {lastRunDurationMs !== null && !running && (
                    <RunResultsSummaryPanel
                        reports={reports}
                        totalDurationMs={lastRunDurationMs}
                        groupName={(id) => groupsById.get(id)?.Name ?? `Group #${id}`}
                    />
                )}

                {lastRunDurationMs !== null && !running && flatTrace.length > 0 && (
                    <div className="space-y-2">
                        <button
                            type="button"
                            onClick={() => setTraceOpen((v) => !v)}
                            className="inline-flex items-center gap-1 text-xs font-medium text-muted-foreground hover:text-foreground"
                            aria-expanded={traceOpen}
                            aria-controls="run-trace-viewer"
                        >
                            {traceOpen ? <ChevronDown className="h-3.5 w-3.5" /> : <ChevronRight className="h-3.5 w-3.5" />}
                            {traceOpen ? "Hide" : "Show"} execution trace ({flatTrace.length} entries)
                        </button>
                        {traceOpen && (
                            <div id="run-trace-viewer">
                                <RunTraceViewer trace={flatTrace} />
                            </div>
                        )}
                    </div>
                )}

                <ScrollArea className="max-h-[55vh] rounded-md border">
                    <ol className="divide-y">
                        {order.map((gid, idx) => {
                            const group = groupsById.get(gid);
                            const report = reports[idx] ?? emptyReport(gid);
                            return (
                                <li key={gid} className="flex items-center gap-3 px-3 py-2">
                                    <span className="inline-flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-muted text-xs font-medium">
                                        {idx + 1}
                                    </span>
                                    <div className="min-w-0 flex-1">
                                        <div className="flex items-center gap-2">
                                            <span className="truncate text-sm font-medium">
                                                {group?.Name ?? `Group #${gid}`}
                                            </span>
                                            <StatusBadge status={report.Status} />
                                        </div>
                                        {report.Status === "Failed" && report.Result !== null && !report.Result.Ok && (
                                            <p className="mt-0.5 truncate text-xs text-destructive">
                                                {report.Result.Reason}: {report.Result.ReasonDetail}
                                            </p>
                                        )}
                                        {report.DurationMs > 0 && (
                                            <p className="mt-0.5 text-xs text-muted-foreground">
                                                {formatDuration(report.DurationMs)}
                                            </p>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className="h-7 w-7"
                                            disabled={running || idx === 0}
                                            onClick={() => setOrder((o) => move(o, idx, idx - 1))}
                                            aria-label="Move up"
                                        >
                                            <ChevronUp className="h-4 w-4" />
                                        </Button>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className="h-7 w-7"
                                            disabled={running || idx === order.length - 1}
                                            onClick={() => setOrder((o) => move(o, idx, idx + 1))}
                                            aria-label="Move down"
                                        >
                                            <ChevronDown className="h-4 w-4" />
                                        </Button>
                                        <Button
                                            variant="ghost"
                                            size="icon"
                                            className="h-7 w-7"
                                            disabled={running}
                                            onClick={() => setOrder((o) => o.filter((_, i) => i !== idx))}
                                            aria-label="Remove from batch"
                                        >
                                            <X className="h-4 w-4" />
                                        </Button>
                                    </div>
                                </li>
                            );
                        })}
                    </ol>
                </ScrollArea>

                <DialogFooter>
                    <Button variant="outline" disabled={running} onClick={() => onOpenChange(false)}>
                        Close
                    </Button>
                    <Button disabled={running || order.length === 0} onClick={handleRun}>
                        {running ? (
                            <><Loader2 className="mr-1 h-4 w-4 animate-spin" /> Running…</>
                        ) : (
                            <><Play className="mr-1 h-4 w-4" /> Run {order.length} group(s)</>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

function StatusBadge({ status }: { status: BatchGroupStatus }) {
    return (
        <span className={`rounded px-1.5 py-0.5 text-[10px] font-medium ${STATUS_STYLE[status]}`}>
            {status}
        </span>
    );
}

function emptyReport(id: number): BatchGroupReport {
    return { StepGroupId: id, Status: "Pending", StartedAt: null, EndedAt: null, DurationMs: 0, Result: null };
}

/**
 * Preview-mode leaf executor: the Options page can't actually click
 * DOM in a target tab, so every leaf step is reported as a
 * synthetic success. This still exercises the full runner pipeline
 * (group descent, RunGroup expansion, cycle detection) which is what
 * the batch UX is here to demonstrate. In production the recorder
 * background worker injects its own real executor.
 */
const previewExecutor: LeafStepExecutor = () => null;

/**
 * Marco Extension — Bundle Exchange Panel
 *
 * Dedicated import/export "screen" embedded in the Step Group Library
 * page. Surfaces the same `runStepGroupExport` / `runStepGroupImport`
 * pipelines the toolbar already calls, but as a labeled, two-column
 * card with:
 *
 *   - an explicit drag-and-drop zone for `.zip` bundles,
 *   - a count-aware Export button keyed off the parent's selection,
 *   - persistent "last export / last import" summaries so the user can
 *     confirm what just happened without re-reading toast history.
 *
 * The component is **purely presentational over callbacks** — it does
 * NOT touch sql.js or the bundle modules directly. That keeps the
 * library page as the single source of truth for the in-memory DB and
 * lets us unit-test this component in isolation later.
 */

import { useRef, useState } from "react";
import { Download, FileArchive, Upload } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";

export interface LastExportSummary {
    readonly FileName: string;
    readonly GroupCount: number;
    readonly StepCount: number;
    readonly At: string; // ISO timestamp
}

export interface LastImportSummary {
    readonly GroupCount: number;
    readonly StepCount: number;
    readonly RenameCount: number;
    readonly At: string;
}

interface BundleExchangePanelProps {
    readonly selectedCount: number;
    /**
     * Trigger an export. The boolean argument is the user's choice from
     * the "Include descendants" checkbox — when `true`, every transitive
     * sub-group of each ticked root is packaged; when `false`, only the
     * exact selection ships and any nested children are skipped.
     */
    readonly onExport: (includeDescendants: boolean) => void | Promise<void>;
    readonly onImportFile: (file: File) => void | Promise<void>;
    readonly lastExport: LastExportSummary | null;
    readonly lastImport: LastImportSummary | null;
    readonly disabled?: boolean;
}

const ACCEPT_ZIP = ".zip,application/zip";
const ZIP_MIME = "application/zip";

function formatTime(iso: string): string {
    try {
        return new Date(iso).toLocaleTimeString();
    } catch {
        return iso;
    }
}

function isZipFile(file: File): boolean {
    return file.type === ZIP_MIME || file.name.toLowerCase().endsWith(".zip");
}

export default function BundleExchangePanel(props: BundleExchangePanelProps) {
    const { selectedCount, onExport, onImportFile, lastExport, lastImport, disabled } = props;
    const inputRef = useRef<HTMLInputElement>(null);
    const [dragOver, setDragOver] = useState(false);
    /**
     * Default ON to preserve the long-standing behaviour ("Includes every
     * nested sub-group and step"). Users can untick it for a strict,
     * roots-only export — useful when migrating just the top-level
     * shells across projects without their inner step trees.
     */
    const [includeDescendants, setIncludeDescendants] = useState(true);

    const handleDrop = (ev: React.DragEvent<HTMLDivElement>) => {
        ev.preventDefault();
        setDragOver(false);
        const file = ev.dataTransfer.files?.[0];
        if (file === undefined) return;
        if (!isZipFile(file)) return; // silent ignore; UI will show no change
        void onImportFile(file);
    };

    const handlePicked = (ev: React.ChangeEvent<HTMLInputElement>) => {
        const file = ev.target.files?.[0];
        if (file !== undefined) void onImportFile(file);
        ev.target.value = "";
    };

    return (
        <Card className="flex flex-col gap-4 p-4">
            <header className="flex items-center gap-2">
                <FileArchive className="h-5 w-5 text-primary" />
                <h2 className="text-base font-semibold">Import / Export bundle</h2>
                <span className="text-xs text-muted-foreground">
                    Move step groups between projects or back them up as a portable .zip
                </span>
            </header>

            <div className="grid gap-4 md:grid-cols-2">
                {/* ---- Export side ---- */}
                <section className="flex flex-col gap-2 rounded-md border p-3">
                    <div className="flex items-center justify-between">
                        <div className="text-sm font-medium">Export selected groups</div>
                        <span className="text-xs text-muted-foreground">
                            {selectedCount} selected
                        </span>
                    </div>
                    <p className="text-xs text-muted-foreground">
                        Tick groups in the tree below to add them. Use the checkbox to control
                        whether nested sub-groups are packaged too.
                    </p>
                    <div className="flex items-start gap-2">
                        <Checkbox
                            id="export-include-descendants"
                            checked={includeDescendants}
                            onCheckedChange={(v) => setIncludeDescendants(v === true)}
                            disabled={disabled === true}
                            aria-describedby="export-include-descendants-help"
                        />
                        <div className="flex flex-col">
                            <Label
                                htmlFor="export-include-descendants"
                                className="cursor-pointer text-sm font-medium leading-none"
                            >
                                Include descendants
                            </Label>
                            <span
                                id="export-include-descendants-help"
                                className="mt-1 text-xs text-muted-foreground"
                            >
                                {includeDescendants
                                    ? "Every nested sub-group of each ticked group is packaged too."
                                    : "Only the exact groups you ticked ship — children are skipped."}
                            </span>
                        </div>
                    </div>
                    <Button
                        size="sm"
                        className="self-start"
                        disabled={disabled === true || selectedCount === 0}
                        onClick={() => void onExport(includeDescendants)}
                    >
                        <Download className="mr-1 h-4 w-4" />
                        Download .zip
                    </Button>
                    {lastExport !== null && (
                        <p className="mt-1 text-xs text-muted-foreground">
                            Last: <span className="font-mono">{lastExport.FileName}</span> ·
                            {" "}{lastExport.GroupCount} group(s) · {lastExport.StepCount} step(s) ·
                            {" "}{formatTime(lastExport.At)}
                        </p>
                    )}
                </section>

                {/* ---- Import side ---- */}
                <section className="flex flex-col gap-2 rounded-md border p-3">
                    <div className="text-sm font-medium">Import a bundle</div>
                    <div
                        onDragOver={(ev) => { ev.preventDefault(); setDragOver(true); }}
                        onDragLeave={() => setDragOver(false)}
                        onDrop={handleDrop}
                        onClick={() => inputRef.current?.click()}
                        role="button"
                        tabIndex={0}
                        onKeyDown={(ev) => {
                            if (ev.key === "Enter" || ev.key === " ") inputRef.current?.click();
                        }}
                        className={[
                            "flex cursor-pointer flex-col items-center justify-center gap-1 rounded-md border-2 border-dashed px-3 py-6 text-center text-xs transition",
                            dragOver
                                ? "border-primary bg-primary/10 text-primary"
                                : "border-muted-foreground/30 text-muted-foreground hover:border-primary hover:text-primary",
                            disabled === true ? "pointer-events-none opacity-50" : "",
                        ].join(" ")}
                        aria-label="Drop a .zip bundle here or click to browse"
                    >
                        <Upload className="h-5 w-5" />
                        <span className="font-medium">Drop a .zip here, or click to browse</span>
                        <span>Conflicting names are auto-renamed</span>
                    </div>
                    <input
                        ref={inputRef}
                        type="file"
                        accept={ACCEPT_ZIP}
                        className="hidden"
                        onChange={handlePicked}
                    />
                    {lastImport !== null && (
                        <p className="mt-1 text-xs text-muted-foreground">
                            Last: {lastImport.GroupCount} group(s) · {lastImport.StepCount} step(s)
                            {lastImport.RenameCount > 0
                                ? ` · ${lastImport.RenameCount} renamed`
                                : ""} · {formatTime(lastImport.At)}
                        </p>
                    )}
                </section>
            </div>
        </Card>
    );
}

/**
 * CsvInputDialog
 *
 * Upload (or paste) a CSV file, configure how each column maps to a
 * variable in the StepGroup's input bag, pick which row to apply, and
 * commit. The resulting bag is identical in shape to what the JSON
 * dialog produces — both feed the same `setGroupInput` call.
 *
 * Constraints (recorded in mem://workflow/no-questions-mode):
 *   - File ≤ 5 MB / ≤ 10 000 rows, fully in memory.
 *   - Pure presentation; the runner picks up the bag from
 *     `useStepLibrary.GroupInputs`.
 *
 * Why single-row apply: the input bag is a flat object keyed by
 * variable name — semantically only one row can be "the" current
 * input. Batch / iterate-rows mode is a separate workstream.
 */

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";

import {
    parseCsv,
    type CsvParseSuccess,
    MAX_BYTES,
} from "@/background/recorder/step-library/csv-parse";
import {
    buildBagFromRow,
    suggestVariableName,
    validateVariableName,
    type CoercionKind,
    type ColumnMapping,
} from "@/background/recorder/step-library/csv-mapping";
import type { GroupInputBag } from "@/background/recorder/step-library/group-inputs";

import { ChevronLeft, ChevronRight, FileSpreadsheet, Upload } from "lucide-react";

const COERCION_OPTIONS: ReadonlyArray<{ value: CoercionKind; label: string; hint: string }> = [
    { value: "auto",    label: "Auto",    hint: "Numbers, true/false, blank → empty string" },
    { value: "string",  label: "String",  hint: "Always treat as text" },
    { value: "number",  label: "Number",  hint: "Reject non-numeric cells" },
    { value: "boolean", label: "Boolean", hint: "true/false/yes/no/0/1" },
    { value: "json",    label: "JSON",    hint: "Parse cell as JSON" },
];

export interface CsvInputDialogProps {
    readonly open: boolean;
    readonly groupName: string | null;
    readonly groupId: number | null;
    readonly onOpenChange: (open: boolean) => void;
    readonly onApply: (groupId: number, bag: GroupInputBag) => void;
}

interface ParsedState {
    readonly Csv: CsvParseSuccess;
    readonly FileName: string | null;
}

export function CsvInputDialog(props: CsvInputDialogProps): JSX.Element {
    const { open, groupName, groupId, onOpenChange, onApply } = props;
    const { toast } = useToast();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [pasted, setPasted] = useState("");
    const [parsed, setParsed] = useState<ParsedState | null>(null);
    const [parseError, setParseError] = useState<string | null>(null);
    const [mappings, setMappings] = useState<ReadonlyArray<ColumnMapping>>([]);
    const [rowIndex, setRowIndex] = useState(0);
    const [dragOver, setDragOver] = useState(false);

    // Reset whenever the dialog opens.
    useEffect(() => {
        if (open) {
            setPasted("");
            setParsed(null);
            setParseError(null);
            setMappings([]);
            setRowIndex(0);
            setDragOver(false);
        }
    }, [open]);

    const acceptText = useCallback((text: string, fileName: string | null) => {
        const result = parseCsv(text);
        if (!result.Ok) {
            setParsed(null);
            setMappings([]);
            setParseError(result.Reason);
            return;
        }
        setParseError(null);
        setParsed({ Csv: result, FileName: fileName });
        // Default mapping: map every column to its sanitised header,
        // auto-coerce, dedupe collisions by suffixing.
        const seen = new Set<string>();
        const next: ColumnMapping[] = result.Headers.map((h) => {
            let v = suggestVariableName(h);
            let i = 2;
            while (seen.has(v)) v = `${suggestVariableName(h)}_${i++}`;
            seen.add(v);
            return { Column: h, Variable: v, Coerce: "auto" as CoercionKind };
        });
        setMappings(next);
        setRowIndex(0);
    }, []);

    const handleFile = useCallback(async (file: File) => {
        if (file.size > MAX_BYTES) {
            toast({
                variant: "destructive",
                title: "File too large",
                description: "CSV files must be 5 MB or smaller.",
            });
            return;
        }
        try {
            const text = await file.text();
            setPasted(""); // Pasted-text takes a back seat once we have a file.
            acceptText(text, file.name);
        } catch (err) {
            toast({
                variant: "destructive",
                title: "Could not read file",
                description: err instanceof Error ? err.message : String(err),
            });
        }
    }, [acceptText, toast]);

    const handleParseClick = useCallback(() => {
        acceptText(pasted, null);
    }, [pasted, acceptText]);

    const handleFilePick = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0] ?? null;
        e.target.value = "";
        if (file !== null) void handleFile(file);
    }, [handleFile]);

    const handleDrop = useCallback((e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        setDragOver(false);
        const file = e.dataTransfer.files[0] ?? null;
        if (file !== null) void handleFile(file);
    }, [handleFile]);

    const updateMapping = useCallback((column: string, patch: Partial<Omit<ColumnMapping, "Column">>) => {
        setMappings((prev) => prev.map((m) => (m.Column === column ? { ...m, ...patch } : m)));
    }, []);

    const buildResult = useMemo(() => {
        if (parsed === null) return null;
        const row = parsed.Csv.Rows[rowIndex] ?? null;
        if (row === null) return null;
        return buildBagFromRow({
            Headers: parsed.Csv.Headers,
            Row: row,
            Mappings: mappings,
        });
    }, [parsed, mappings, rowIndex]);

    const handleApply = useCallback(() => {
        if (groupId === null || buildResult === null || !buildResult.Ok) return;
        onApply(groupId, buildResult.Bag);
        toast({
            title: "CSV input applied",
            description: `Bound ${buildResult.UsedColumns} variable(s) from row ${rowIndex + 1} to "${groupName ?? "(unknown)"}".`,
        });
        onOpenChange(false);
    }, [groupId, groupName, buildResult, rowIndex, onApply, onOpenChange, toast]);

    const totalRows = parsed?.Csv.Rows.length ?? 0;
    const canStepBack = rowIndex > 0;
    const canStepFwd  = rowIndex < totalRows - 1;

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-3xl">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <FileSpreadsheet className="h-5 w-5" /> Import CSV input
                    </DialogTitle>
                    <DialogDescription>
                        Upload a CSV, choose how each column maps to a variable, then apply one row to{" "}
                        <span className="font-medium text-foreground">{groupName ?? "(no group selected)"}</span>.
                        Limits: 5&nbsp;MB / 10&nbsp;000 rows, in memory.
                    </DialogDescription>
                </DialogHeader>

                {/* ------- File / paste source ------- */}
                <div
                    onDragOver={(e) => { e.preventDefault(); if (!dragOver) setDragOver(true); }}
                    onDragLeave={() => setDragOver(false)}
                    onDrop={handleDrop}
                    className={[
                        "flex items-center justify-between gap-3 rounded border-2 border-dashed px-3 py-2 text-xs transition-colors",
                        dragOver ? "border-primary bg-primary/5" : "border-border bg-muted/30",
                    ].join(" ")}
                >
                    <div className="flex items-center gap-2 text-muted-foreground">
                        <Upload className="h-4 w-4" />
                        <span>
                            {parsed?.FileName != null
                                ? `Loaded: ${parsed.FileName}`
                                : "Drop a .csv file here, or paste below"}
                        </span>
                    </div>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => fileInputRef.current?.click()}
                    >
                        Choose file
                    </Button>
                    <input
                        ref={fileInputRef}
                        type="file"
                        accept=".csv,text/csv,application/csv,text/plain"
                        className="hidden"
                        onChange={handleFilePick}
                    />
                </div>

                {parsed === null && (
                    <div className="space-y-2">
                        <Textarea
                            value={pasted}
                            onChange={(e) => setPasted(e.target.value)}
                            placeholder={"Email,Age,Active\nyou@example.com,42,true"}
                            spellCheck={false}
                            className="h-32 font-mono text-xs"
                            aria-label="Paste CSV contents"
                        />
                        <div className="flex items-center justify-between">
                            <div className="text-xs text-destructive">
                                {parseError !== null ? parseError : ""}
                            </div>
                            <Button
                                size="sm"
                                onClick={handleParseClick}
                                disabled={pasted.trim() === ""}
                            >
                                Parse pasted CSV
                            </Button>
                        </div>
                    </div>
                )}

                {/* ------- Mapping table + row navigator ------- */}
                {parsed !== null && (
                    <div className="space-y-3">
                        {parsed.Csv.Warnings.length > 0 && (
                            <div className="rounded border border-amber-500/40 bg-amber-500/10 px-3 py-2 text-xs">
                                <div className="font-medium text-amber-600 dark:text-amber-300">Heads up</div>
                                <ul className="mt-1 list-disc space-y-0.5 pl-4 text-muted-foreground">
                                    {parsed.Csv.Warnings.map((w, i) => <li key={i}>{w}</li>)}
                                </ul>
                            </div>
                        )}

                        <div className="flex items-center justify-between rounded border bg-muted/30 px-3 py-2 text-xs">
                            <div className="text-muted-foreground">
                                <span className="font-medium text-foreground">{parsed.Csv.Headers.length}</span> column(s),{" "}
                                <span className="font-medium text-foreground">{totalRows}</span> data row(s),{" "}
                                delimiter{" "}
                                <code className="rounded bg-muted px-1">{parsed.Csv.Delimiter}</code>
                            </div>
                            <div className="flex items-center gap-2">
                                <Button
                                    variant="ghost" size="icon" className="h-7 w-7"
                                    disabled={!canStepBack}
                                    onClick={() => setRowIndex((i) => Math.max(0, i - 1))}
                                    aria-label="Previous row"
                                >
                                    <ChevronLeft className="h-4 w-4" />
                                </Button>
                                <span>
                                    Row{" "}
                                    <Input
                                        type="number"
                                        value={rowIndex + 1}
                                        min={1}
                                        max={Math.max(1, totalRows)}
                                        onChange={(e) => {
                                            const next = Math.max(1, Math.min(totalRows, Number(e.target.value) || 1));
                                            setRowIndex(next - 1);
                                        }}
                                        className="inline-block h-7 w-16 text-center"
                                    />
                                    {" / "}{totalRows}
                                </span>
                                <Button
                                    variant="ghost" size="icon" className="h-7 w-7"
                                    disabled={!canStepFwd}
                                    onClick={() => setRowIndex((i) => Math.min(totalRows - 1, i + 1))}
                                    aria-label="Next row"
                                >
                                    <ChevronRight className="h-4 w-4" />
                                </Button>
                            </div>
                        </div>

                        <ScrollArea className="h-72 rounded border">
                            <table className="w-full text-xs">
                                <thead className="sticky top-0 bg-card">
                                    <tr className="border-b">
                                        <th className="px-2 py-2 text-left font-medium">Column</th>
                                        <th className="px-2 py-2 text-left font-medium">Cell value (row {rowIndex + 1})</th>
                                        <th className="px-2 py-2 text-left font-medium">Variable</th>
                                        <th className="px-2 py-2 text-left font-medium">Type</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {parsed.Csv.Headers.map((header) => {
                                        const m = mappings.find((x) => x.Column === header);
                                        if (m === undefined) return null;
                                        const cell = parsed.Csv.Rows[rowIndex]?.[parsed.Csv.Headers.indexOf(header)] ?? "";
                                        const skipped = m.Variable === null;
                                        const validation = !skipped && m.Variable !== null
                                            ? validateVariableName(m.Variable)
                                            : null;
                                        return (
                                            <tr key={header} className="border-b last:border-0">
                                                <td className="px-2 py-1.5 align-middle font-medium">{header}</td>
                                                <td className="max-w-[14rem] truncate px-2 py-1.5 align-middle text-muted-foreground" title={cell}>
                                                    {cell === "" ? <em className="opacity-50">empty</em> : cell}
                                                </td>
                                                <td className="px-2 py-1.5 align-middle">
                                                    <div className="flex items-center gap-1">
                                                        <Input
                                                            value={m.Variable ?? ""}
                                                            disabled={skipped}
                                                            placeholder={skipped ? "(skipped)" : suggestVariableName(header)}
                                                            onChange={(e) => updateMapping(header, { Variable: e.target.value })}
                                                            className={[
                                                                "h-7",
                                                                validation !== null ? "border-destructive" : "",
                                                            ].join(" ")}
                                                            aria-invalid={validation !== null}
                                                            title={validation ?? undefined}
                                                        />
                                                        <Button
                                                            type="button"
                                                            variant="ghost"
                                                            size="sm"
                                                            className="h-7 px-2 text-xs"
                                                            onClick={() => updateMapping(header, {
                                                                Variable: skipped ? suggestVariableName(header) : null,
                                                            })}
                                                            title={skipped ? "Include this column" : "Skip this column"}
                                                        >
                                                            {skipped ? "Use" : "Skip"}
                                                        </Button>
                                                    </div>
                                                </td>
                                                <td className="px-2 py-1.5 align-middle">
                                                    <Select
                                                        value={m.Coerce}
                                                        onValueChange={(v) => updateMapping(header, { Coerce: v as CoercionKind })}
                                                        disabled={skipped}
                                                    >
                                                        <SelectTrigger className="h-7 w-[110px]">
                                                            <SelectValue />
                                                        </SelectTrigger>
                                                        <SelectContent>
                                                            {COERCION_OPTIONS.map((opt) => (
                                                                <SelectItem key={opt.value} value={opt.value} title={opt.hint}>
                                                                    {opt.label}
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                    </Select>
                                                </td>
                                            </tr>
                                        );
                                    })}
                                </tbody>
                            </table>
                        </ScrollArea>

                        <div className="min-h-[1.25rem] text-xs">
                            {buildResult === null ? (
                                <span className="text-muted-foreground">Pick a row to preview the resulting bag.</span>
                            ) : buildResult.Ok ? (
                                <span className="text-emerald-500">
                                    ✓ Will bind {buildResult.UsedColumns} variable(s) from row {rowIndex + 1}.
                                </span>
                            ) : (
                                <span className="text-destructive">
                                    {buildResult.Reason}
                                </span>
                            )}
                        </div>
                    </div>
                )}

                <DialogFooter className="gap-2 sm:gap-2">
                    <Button variant="ghost" onClick={() => onOpenChange(false)}>
                        Cancel
                    </Button>
                    {parsed !== null && (
                        <Button
                            variant="outline"
                            onClick={() => { setParsed(null); setMappings([]); setRowIndex(0); }}
                        >
                            Load a different file
                        </Button>
                    )}
                    <Button
                        onClick={handleApply}
                        disabled={groupId === null || buildResult === null || !buildResult.Ok}
                    >
                        Apply row {parsed === null ? "" : rowIndex + 1}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

/**
 * DismissedSitesCard — Options panel for the C9 auto-attach gate.
 *
 * Lets users review and revoke origins they have dismissed via the
 * (future) first-attach toast. Reads from `marco_dismissed_origins` in
 * `chrome.storage.local` through `dismissed-origins.ts` and calls
 * `unpersistDismissOrigin` on click.
 *
 * See: mem://features/auto-attach-policy (C9)
 */

import { useEffect, useState, useCallback } from "react";
import { Button } from "@/components/ui/button";
import { Trash2, RefreshCw, ShieldOff } from "lucide-react";
import { toast } from "sonner";
import {
    listPersistedDismissedOrigins,
    unpersistDismissOrigin,
} from "@/background/dismissed-origins";
import { logError } from "./options-logger";

export function DismissedSitesCard() {
    const [origins, setOrigins] = useState<string[]>([]);
    const [loading, setLoading] = useState(true);
    const [pending, setPending] = useState<string | null>(null);

    const refresh = useCallback(async () => {
        setLoading(true);
        try {
            const list = await listPersistedDismissedOrigins();
            setOrigins(list);
        } catch (err) {
            logError("DismissedSitesCard", "refresh failed", err);
            toast.error("Failed to load dismissed sites");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        void refresh();
    }, [refresh]);

    const onForget = useCallback(
        async (origin: string) => {
            setPending(origin);
            try {
                await unpersistDismissOrigin(origin);
                setOrigins((prev) => prev.filter((o) => o !== origin));
                toast.success(`Re-enabled auto-attach for ${origin}`);
            } catch (err) {
                logError("DismissedSitesCard", `unpersist ${origin} failed`, err);
                toast.error(`Failed to forget ${origin}`);
            } finally {
                setPending(null);
            }
        },
        [],
    );

    const hasOrigins = origins.length > 0;

    return (
        <div className="space-y-3">
            <div className="flex items-center justify-between gap-3">
                <p className="text-sm text-muted-foreground">
                    Sites where you chose <span className="font-medium">"Don't ask for this site"</span> in the auto-attach prompt. Removing a site re-enables the prompt next time you visit it.
                </p>
                <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => void refresh()}
                    disabled={loading}
                    aria-label="Refresh dismissed sites"
                >
                    <RefreshCw className={`h-4 w-4 ${loading ? "animate-spin" : ""}`} />
                </Button>
            </div>

            {loading && origins.length === 0 ? (
                <div className="rounded-md border border-border bg-muted/30 px-3 py-6 text-center text-sm text-muted-foreground">
                    Loading…
                </div>
            ) : !hasOrigins ? (
                <div className="rounded-md border border-dashed border-border bg-muted/20 px-3 py-6 text-center text-sm text-muted-foreground flex flex-col items-center gap-2">
                    <ShieldOff className="h-5 w-5 opacity-60" />
                    No sites dismissed. Auto-attach will prompt on first visit to any matching project URL.
                </div>
            ) : (
                <ul className="divide-y divide-border rounded-md border border-border bg-background">
                    {origins.map((origin) => (
                        <li
                            key={origin}
                            className="flex items-center justify-between gap-3 px-3 py-2"
                        >
                            <code className="text-sm font-mono text-foreground truncate">
                                {origin}
                            </code>
                            <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => void onForget(origin)}
                                disabled={pending === origin}
                                aria-label={`Forget ${origin}`}
                            >
                                <Trash2 className="h-4 w-4" />
                                <span className="ml-1.5">Forget</span>
                            </Button>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

