/**
 * Marco Extension — Run Group Dialog
 *
 * Single-group execution surface invoked from the library panel's
 * "Run group" button. Wraps the pure `runGroup()` runner with the
 * shared preview-mode `executeLeafStep` (every leaf reports success;
 * the dialog still exercises the full descent / RunGroup expansion /
 * cycle-detection pipeline) and renders three artefacts when the run
 * finishes:
 *
 *   1. **Failure card** — only when `!Result.Ok`. Shows the structured
 *      `Reason` enum, the runner's `ReasonDetail` sentence, the
 *      offending `FailedStepId` / `FailedGroupId`, and the call-stack
 *      that was active when the failure fired. If the leaf executor
 *      surfaced a `FailureReport`, its `Reason` is shown too.
 *   2. **Summary panel** — same `RunResultsSummaryPanel` the batch
 *      dialog uses, fed a single synthetic batch report so the four
 *      counters (Groups run / entered / Steps executed / skipped)
 *      stay consistent across both surfaces.
 *   3. **Trace viewer** — the full `RunStepTraceEntry[]` rendered by
 *      the shared `RunTraceViewer`, opened by default for single-group
 *      runs (in batches the viewer is collapsed because traces can be
 *      huge — for one group the trace is the whole point of the dialog).
 *
 * Pre-run state shows a one-line "Press Run to execute" prompt so the
 * dialog can be opened to inspect the target before committing.
 */

import { useEffect, useMemo, useState } from "react";
import { AlertTriangle, Loader2, Play } from "lucide-react";
import { toast } from "sonner";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Switch } from "@/components/ui/switch";

import {
    runGroup,
    type LeafStepExecutor,
    type RunGroupResult,
} from "@/background/recorder/step-library/run-group-runner";
import type { StepGroupRow, StepLibraryDb } from "@/background/recorder/step-library/db";
import type { BatchGroupReport } from "@/background/recorder/step-library/run-batch";
import { createLiveReplayExecutor } from "@/background/recorder/step-library/replay-bridge";

import RunResultsSummaryPanel from "./RunResultsSummaryPanel";
import RunTraceViewer from "./RunTraceViewer";

interface RunGroupDialogProps {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly db: StepLibraryDb | null;
    readonly projectId: number | null;
    readonly group: StepGroupRow | null;
    readonly groupName?: (id: number) => string;
}

/**
 * Preview-mode leaf executor — every leaf reports success so the user
 * can dry-run the descent / RunGroup expansion / cycle-detection
 * pipeline without touching the DOM. Switch to live mode via the
 * dialog toggle to drive `executeReplay()` end-to-end.
 */
const previewExecutor: LeafStepExecutor = () => null;

function formatDuration(ms: number): string {
    if (ms < 1000) return `${ms} ms`;
    return `${(ms / 1000).toFixed(2)} s`;
}

export default function RunGroupDialog(props: RunGroupDialogProps) {
    const { open, onOpenChange, db, projectId, group, groupName } = props;
    const [running, setRunning] = useState(false);
    const [result, setResult] = useState<RunGroupResult | null>(null);
    const [durationMs, setDurationMs] = useState<number>(0);
    /**
     * Live mode swaps the always-success `previewExecutor` for the
     * `createLiveReplayExecutor` bridge so each leaf step actually
     * dispatches `click` / `input` / `change` events into the Options
     * page document via `executeReplay()`. This is the entry point
     * that lets imported groups exercise the real replay pipeline
     * (selectors, variable substitution, structured FailureReports)
     * end-to-end. Defaults to OFF so opening the dialog never
     * mutates the page accidentally.
     */
    const [liveMode, setLiveMode] = useState(false);

    // Reset whenever the dialog re-opens or the target group changes
    // so a stale prior run can't bleed into a new invocation.
    useEffect(() => {
        if (open) {
            setRunning(false);
            setResult(null);
            setDurationMs(0);
            setLiveMode(false);
        }
    }, [open, group?.StepGroupId]);

    const handleRun = async () => {
        if (db === null || projectId === null || group === null) {
            toast.error("Library not ready");
            return;
        }
        setRunning(true);
        const executor: LeafStepExecutor = liveMode
            ? createLiveReplayExecutor({ Doc: document })
            : previewExecutor;
        const startedAt = performance.now();
        const r = await runGroup({
            db,
            projectId,
            rootGroupId: group.StepGroupId,
            executeLeafStep: executor,
        });
        const elapsed = Math.max(0, Math.round(performance.now() - startedAt));
        setResult(r);
        setDurationMs(elapsed);
        setRunning(false);
        if (r.Ok) {
            toast.success(`Ran "${group.Name}" — ${r.StepsExecuted} step(s) in ${formatDuration(elapsed)}`);
        } else {
            toast.error(`Run failed: ${r.Reason}`);
        }
    };

    /**
     * Wrap the single result in a synthetic `BatchGroupReport[]` so we
     * can re-use the existing summary panel without forking a second
     * aggregator. Status mirrors `Result.Ok`.
     */
    const summaryReports = useMemo<ReadonlyArray<BatchGroupReport>>(() => {
        if (result === null || group === null) return [];
        return [{
            StepGroupId: group.StepGroupId,
            Status: result.Ok ? "Succeeded" : "Failed",
            StartedAt: null,
            EndedAt: null,
            DurationMs: durationMs,
            Result: result,
        }];
    }, [result, group, durationMs]);

    return (
        <Dialog open={open} onOpenChange={(o) => { if (!running) onOpenChange(o); }}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle>
                        Run group{group !== null ? ` — ${group.Name}` : ""}
                    </DialogTitle>
                    <DialogDescription>
                        Executes this group. Disabled steps are skipped; nested RunGroup steps are expanded recursively up to the runner's depth limit.
                    </DialogDescription>
                </DialogHeader>

                <div className="flex items-center justify-between gap-4 rounded-md border bg-muted/30 px-3 py-2 text-sm">
                    <div className="min-w-0">
                        <div className="font-medium text-foreground">Live execution</div>
                        <div className="text-xs text-muted-foreground">
                            {liveMode
                                ? "Each leaf step dispatches real DOM events into this page via the replay bridge."
                                : "Preview mode — every leaf reports success without touching the DOM."}
                        </div>
                    </div>
                    <Switch
                        checked={liveMode}
                        onCheckedChange={setLiveMode}
                        disabled={running}
                        aria-label="Toggle live execution"
                    />
                </div>

                {result === null && !running && (
                    <div className="rounded-md border bg-muted/30 px-3 py-4 text-sm text-muted-foreground">
                        Press <strong className="text-foreground">Run</strong> to execute the group and capture its trace.
                    </div>
                )}

                {running && (
                    <div className="flex items-center justify-center gap-2 rounded-md border bg-muted/30 px-3 py-6 text-sm text-muted-foreground">
                        <Loader2 className="h-4 w-4 animate-spin" />
                        Running…
                    </div>
                )}

                {result !== null && !result.Ok && (
                    <FailureCard
                        result={result}
                        groupName={groupName}
                    />
                )}

                {result !== null && summaryReports.length > 0 && (
                    <RunResultsSummaryPanel
                        reports={summaryReports}
                        totalDurationMs={durationMs}
                        groupName={groupName}
                    />
                )}

                {result !== null && result.Trace.length > 0 && (
                    <RunTraceViewer trace={result.Trace} maxHeightClass="max-h-[40vh]" />
                )}

                <DialogFooter>
                    <Button
                        variant="outline"
                        disabled={running}
                        onClick={() => onOpenChange(false)}
                    >
                        Close
                    </Button>
                    <Button
                        disabled={running || group === null || db === null || projectId === null}
                        onClick={handleRun}
                    >
                        {running ? (
                            <><Loader2 className="mr-1 h-4 w-4 animate-spin" /> Running…</>
                        ) : (
                            <><Play className="mr-1 h-4 w-4" /> {result === null ? "Run" : "Run again"}</>
                        )}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

interface FailureCardProps {
    readonly result: RunGroupResult & { Ok: false };
    readonly groupName?: (id: number) => string;
}

/**
 * Surfaces the structured failure details. Layout mirrors the row
 * style used by the summary panel's failure list so the user sees
 * the same visual idiom across single-group + batch surfaces.
 */
function FailureCard({ result, groupName }: FailureCardProps) {
    const failedGroupName = result.FailedGroupId !== null
        ? (groupName?.(result.FailedGroupId) ?? `Group #${result.FailedGroupId}`)
        : null;

    return (
        <section
            className="rounded-md border border-destructive/40 bg-destructive/5 p-3"
            aria-label="Run failure details"
        >
            <header className="mb-2 flex items-center gap-2">
                <AlertTriangle className="h-4 w-4 text-destructive" />
                <h3 className="text-sm font-semibold text-destructive">Run failed</h3>
                <span className="rounded bg-destructive/15 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-destructive">
                    {result.Reason}
                </span>
            </header>

            <p className="mb-2 text-xs text-foreground">{result.ReasonDetail}</p>

            <dl className="grid grid-cols-2 gap-x-4 gap-y-1 text-xs">
                {result.FailedStepId !== null && (
                    <>
                        <dt className="text-muted-foreground">Failed step</dt>
                        <dd className="font-mono">#{result.FailedStepId}</dd>
                    </>
                )}
                {failedGroupName !== null && (
                    <>
                        <dt className="text-muted-foreground">Failed group</dt>
                        <dd className="truncate" title={failedGroupName}>{failedGroupName}</dd>
                    </>
                )}
                {result.CallStack.length > 0 && (
                    <>
                        <dt className="text-muted-foreground">Call stack</dt>
                        <dd
                            className="truncate font-mono"
                            title={result.CallStack.join(" › ")}
                        >
                            {result.CallStack.join(" › ")}
                        </dd>
                    </>
                )}
                {result.FailureReport !== null && (
                    <>
                        <dt className="text-muted-foreground">Leaf failure</dt>
                        <dd className="truncate" title={result.FailureReport.Reason}>
                            {result.FailureReport.Reason}
                        </dd>
                    </>
                )}
            </dl>
        </section>
    );
}

/**
 * Marco Extension — Run Results Summary Panel
 *
 * Aggregate report shown after a batch finishes (success **or** failure).
 *
 * Inputs are the per-group `BatchGroupReport[]` produced by `runBatch` —
 * we walk each group's `Result.Trace` to derive the four counters the
 * spec calls out:
 *
 *   - **Groups run** — every group whose status is `Succeeded` or `Failed`
 *     (i.e. the runner actually entered it). `Pending` and `Skipped`
 *     batch entries are NOT counted as "run" — they were either never
 *     reached because of a stop-on-failure abort, or skipped explicitly.
 *   - **Executed steps** — leaf steps that produced an `Executed`
 *     outcome in the trace. Mirrors `RunGroupSuccess.StepsExecuted`
 *     for successful runs; computed from the partial trace for
 *     failed runs so the panel still shows progress up to the point
 *     of failure.
 *   - **Skipped steps** — `IsDisabled` steps the runner short-circuited
 *     past. Same source of truth as `RunGroupSuccess.StepsSkipped`.
 *   - **Groups entered** — every `RunGroup` invocation including the
 *     root + recursive children. Pulled from the `EnteredGroup`
 *     outcomes in the trace, so a deep run that visits the same group
 *     multiple times via separate `RunGroup` steps is counted each
 *     time (matches `RunGroupSuccess.GroupsEntered`).
 *
 * Failures are also surfaced as a separate counter + a per-group list
 * with the structured failure reason, so the user can see WHY the run
 * stopped at a glance without scrolling the per-group rows above.
 *
 * Pure presentational. No state, no side effects — safe to mount and
 * unmount freely, idempotent re-renders.
 */

import { CheckCircle2, FastForward, FolderTree, ListChecks, Timer, XCircle } from "lucide-react";

import type { BatchGroupReport } from "@/background/recorder/step-library/run-batch";
import type { RunStepTraceEntry } from "@/background/recorder/step-library/run-group-runner";

interface RunResultsSummaryPanelProps {
    /** Per-group reports from the just-completed batch. */
    readonly reports: ReadonlyArray<BatchGroupReport>;
    /** Total wall-clock duration of the batch (ms). */
    readonly totalDurationMs: number;
    /** Lookup so failed-group entries can render the human-readable name. */
    readonly groupName?: (id: number) => string;
}

interface AggregateCounts {
    readonly GroupsRun: number;
    readonly StepsExecuted: number;
    readonly StepsSkipped: number;
    readonly GroupsEntered: number;
    readonly Failures: number;
}

function aggregate(reports: ReadonlyArray<BatchGroupReport>): AggregateCounts {
    let groupsRun = 0;
    let executed = 0;
    let skipped = 0;
    let entered = 0;
    let failures = 0;

    for (const r of reports) {
        if (r.Status === "Succeeded" || r.Status === "Failed") groupsRun++;
        if (r.Status === "Failed") failures++;

        const result = r.Result;
        if (result === null) continue;

        // Successful runs ship the canonical counters directly. We
        // still walk the trace for failed runs because RunGroupFailure
        // only carries the partial trace, not pre-computed counts.
        if (result.Ok) {
            executed += result.StepsExecuted;
            skipped += result.StepsSkipped;
            entered += result.GroupsEntered;
        } else {
            const partial = countsFromTrace(result.Trace);
            executed += partial.Executed;
            skipped += partial.Skipped;
            entered += partial.Entered;
        }
    }

    return {
        GroupsRun: groupsRun,
        StepsExecuted: executed,
        StepsSkipped: skipped,
        GroupsEntered: entered,
        Failures: failures,
    };
}

function countsFromTrace(trace: ReadonlyArray<RunStepTraceEntry>): {
    Executed: number; Skipped: number; Entered: number;
} {
    let exec = 0, skip = 0, ent = 0;
    for (const t of trace) {
        if (t.Outcome === "Executed") exec++;
        else if (t.Outcome === "Skipped") skip++;
        else if (t.Outcome === "EnteredGroup") ent++;
    }
    return { Executed: exec, Skipped: skip, Entered: ent };
}

function formatDuration(ms: number): string {
    if (ms < 1000) return `${ms} ms`;
    return `${(ms / 1000).toFixed(2)} s`;
}

export default function RunResultsSummaryPanel(props: RunResultsSummaryPanelProps) {
    const { reports, totalDurationMs, groupName } = props;
    const counts = aggregate(reports);
    const failedReports = reports.filter((r) => r.Status === "Failed");
    const overallOk = counts.Failures === 0 && counts.GroupsRun > 0;

    return (
        <section
            className="rounded-md border bg-card"
            aria-label="Run results summary"
        >
            <header className="flex items-center justify-between gap-2 border-b px-3 py-2">
                <div className="flex items-center gap-2">
                    {overallOk ? (
                        <CheckCircle2 className="h-4 w-4 text-emerald-600 dark:text-emerald-400" />
                    ) : (
                        <XCircle className="h-4 w-4 text-destructive" />
                    )}
                    <h3 className="text-sm font-semibold">
                        {overallOk ? "Run complete" : "Run finished with failures"}
                    </h3>
                </div>
                <div className="flex items-center gap-1 text-xs text-muted-foreground">
                    <Timer className="h-3.5 w-3.5" />
                    {formatDuration(totalDurationMs)}
                </div>
            </header>

            <div className="grid grid-cols-2 gap-2 p-3 sm:grid-cols-4">
                <Stat
                    icon={<FolderTree className="h-4 w-4" />}
                    label="Groups run"
                    value={counts.GroupsRun}
                />
                <Stat
                    icon={<FolderTree className="h-4 w-4" />}
                    label="Groups entered"
                    value={counts.GroupsEntered}
                    hint="Includes root + nested RunGroup invocations"
                />
                <Stat
                    icon={<ListChecks className="h-4 w-4" />}
                    label="Steps executed"
                    value={counts.StepsExecuted}
                    tone="success"
                />
                <Stat
                    icon={<FastForward className="h-4 w-4" />}
                    label="Steps skipped"
                    value={counts.StepsSkipped}
                    hint="Disabled steps short-circuited by the runner"
                    tone={counts.StepsSkipped > 0 ? "muted" : "default"}
                />
            </div>

            {failedReports.length > 0 && (
                <div className="border-t px-3 py-2">
                    <p className="mb-1 text-xs font-medium text-destructive">
                        {failedReports.length} group{failedReports.length === 1 ? "" : "s"} failed
                    </p>
                    <ul className="space-y-1 text-xs">
                        {failedReports.map((r) => {
                            const result = r.Result;
                            const reason = result !== null && !result.Ok ? result.Reason : "Unknown";
                            const detail = result !== null && !result.Ok ? result.ReasonDetail : "";
                            const name = groupName?.(r.StepGroupId) ?? `Group #${r.StepGroupId}`;
                            return (
                                <li
                                    key={r.StepGroupId}
                                    className="rounded border border-destructive/30 bg-destructive/5 px-2 py-1.5"
                                >
                                    <div className="flex items-center gap-2">
                                        <XCircle className="h-3.5 w-3.5 shrink-0 text-destructive" />
                                        <span className="truncate font-medium">{name}</span>
                                        <span className="rounded bg-destructive/15 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-destructive">
                                            {reason}
                                        </span>
                                    </div>
                                    {detail !== "" && (
                                        <p className="mt-0.5 text-muted-foreground line-clamp-2">
                                            {detail}
                                        </p>
                                    )}
                                </li>
                            );
                        })}
                    </ul>
                </div>
            )}
        </section>
    );
}

interface StatProps {
    readonly icon: React.ReactNode;
    readonly label: string;
    readonly value: number;
    readonly hint?: string;
    readonly tone?: "default" | "success" | "muted";
}

function Stat({ icon, label, value, hint, tone = "default" }: StatProps) {
    const valueClass =
        tone === "success" ? "text-emerald-600 dark:text-emerald-400"
        : tone === "muted" ? "text-muted-foreground"
        : "text-foreground";
    return (
        <div className="rounded-md border bg-muted/30 px-3 py-2" title={hint}>
            <div className="flex items-center gap-1.5 text-[11px] uppercase tracking-wide text-muted-foreground">
                {icon}
                <span>{label}</span>
            </div>
            <div className={`mt-1 text-2xl font-semibold tabular-nums ${valueClass}`}>
                {value}
            </div>
        </div>
    );
}

/** Exposed for unit tests so we can assert on the aggregator independently. */
export { aggregate as __aggregateForTest, countsFromTrace as __countsFromTraceForTest };

/**
 * Marco Extension — Step Editor Dialog
 *
 * Add/Edit form for a single Step inside a StepGroup. Used by the
 * Step Group Library panel's right-hand step preview.
 *
 * Modes:
 *   - "create": appended to the end of the parent group via
 *     `useStepLibrary.appendStep`. Returns focus on save.
 *   - "edit":  patches an existing step in place via
 *     `useStepLibrary.updateStep` (preserves OrderIndex).
 *
 * The form keeps the (StepKindId, TargetStepGroupId) invariant the
 * DB enforces: RunGroup steps require a target group; every other
 * kind hides the target picker.
 */

import { useEffect, useMemo, useState } from "react";
import { toast } from "sonner";
import { Plus, Save } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";

import type { StepGroupRow, StepRow } from "@/background/recorder/step-library/db";
import { StepKindId } from "@/background/recorder/step-library/schema";
import { stepKindLabel } from "@/hooks/use-step-library";
import { HotkeyChordCapture } from "@/components/recorder/HotkeyChordCapture";

/* ------------------------------------------------------------------ */
/*  Public surface                                                     */
/* ------------------------------------------------------------------ */

export type StepEditorMode =
    | { Kind: "create"; StepGroupId: number }
    | { Kind: "edit"; Step: StepRow };

export interface StepEditorDialogProps {
    readonly open: boolean;
    readonly mode: StepEditorMode | null;
    readonly groups: ReadonlyArray<StepGroupRow>;
    readonly onCancel: () => void;
    readonly onSubmit: (input: {
        StepKindId: StepKindId;
        Label: string | null;
        PayloadJson: string | null;
        TargetStepGroupId: number | null;
    }) => void;
}

/* ------------------------------------------------------------------ */
/*  Available kinds (RunGroup is conditional — see below)              */
/* ------------------------------------------------------------------ */

const KIND_OPTIONS: ReadonlyArray<StepKindId> = [
    StepKindId.Click,
    StepKindId.Type,
    StepKindId.Select,
    StepKindId.JsInline,
    StepKindId.Wait,
    StepKindId.RunGroup,
    StepKindId.Hotkey,
    StepKindId.UrlTabClick,
];

/**
 * Heuristic placeholder for the payload textarea so the user knows
 * what shape the runner expects. Mirrors the bridge translator in
 * `replay-bridge.ts` (Selector / Value / WaitMs).
 */
function payloadPlaceholderFor(kind: StepKindId): string {
    switch (kind) {
        case StepKindId.Click:
            return '{ "Selector": "#submit-button" }';
        case StepKindId.Type:
            return '{ "Selector": "#email", "Value": "user@example.com" }';
        case StepKindId.Select:
            return '{ "Selector": "#country", "Value": "US" }';
        case StepKindId.JsInline:
            return '{ "Script": "document.title = \\"hi\\";" }';
        case StepKindId.Wait:
            return '{ "WaitMs": 1000 }';
        case StepKindId.RunGroup:
            return "(payload not used — pick a target group below)";
        case StepKindId.Hotkey:
            return '{ "Keys": ["Ctrl+S","Tab","Enter"], "WaitMs": 500 }';
        case StepKindId.UrlTabClick:
            return "(use the URL tab click form below)";
        default:
            return "{ }";
    }
}

/* ------------------------------------------------------------------ */
/*  UrlTabClick form state                                             */
/* ------------------------------------------------------------------ */

type UrlMatchDialect = "Exact" | "Prefix" | "Glob" | "Regex";
type UrlTabClickMode = "OpenNew" | "FocusExisting" | "OpenOrFocus";
type SelectorKindOption = "Auto" | "XPath" | "Css";

interface UrlTabClickFormState {
    UrlPattern: string;
    UrlMatch: UrlMatchDialect;
    Mode: UrlTabClickMode;
    Selector: string;
    SelectorKind: SelectorKindOption;
    TimeoutMs: string;
    DirectOpen: boolean;
    Url: string;
}

const URL_TAB_CLICK_DEFAULTS: UrlTabClickFormState = {
    UrlPattern: "",
    UrlMatch: "Glob",
    Mode: "OpenOrFocus",
    Selector: "",
    SelectorKind: "Auto",
    TimeoutMs: "",
    DirectOpen: false,
    Url: "",
};

function hydrateUrlTabClickForm(payloadJson: string | null): UrlTabClickFormState {
    if (payloadJson === null || payloadJson === "") return { ...URL_TAB_CLICK_DEFAULTS };
    try {
        const p = JSON.parse(payloadJson) as Partial<Record<keyof UrlTabClickFormState, unknown>>;
        return {
            UrlPattern:   typeof p.UrlPattern === "string" ? p.UrlPattern : "",
            UrlMatch:     (p.UrlMatch === "Exact" || p.UrlMatch === "Prefix" || p.UrlMatch === "Glob" || p.UrlMatch === "Regex") ? p.UrlMatch : "Glob",
            Mode:         (p.Mode === "OpenNew" || p.Mode === "FocusExisting" || p.Mode === "OpenOrFocus") ? p.Mode : "OpenOrFocus",
            Selector:     typeof p.Selector === "string" ? p.Selector : "",
            SelectorKind: (p.SelectorKind === "XPath" || p.SelectorKind === "Css" || p.SelectorKind === "Auto") ? p.SelectorKind : "Auto",
            TimeoutMs:    typeof p.TimeoutMs === "number" ? String(p.TimeoutMs) : "",
            DirectOpen:   p.DirectOpen === true,
            Url:          typeof p.Url === "string" ? p.Url : "",
        };
    } catch {
        return { ...URL_TAB_CLICK_DEFAULTS };
    }
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export default function StepEditorDialog(props: StepEditorDialogProps): JSX.Element {
    const { open, mode, groups, onCancel, onSubmit } = props;

    const [kind, setKind] = useState<StepKindId>(StepKindId.Click);
    const [label, setLabel] = useState("");
    const [payloadJson, setPayloadJson] = useState("");
    const [targetGroupId, setTargetGroupId] = useState<number | null>(null);
    /** Hotkey-specific state. The chord list + waitMs are serialised
     *  into PayloadJson on submit; when editing an existing Hotkey we
     *  hydrate from the stored PayloadJson on open. */
    const [hotkeyChords, setHotkeyChords] = useState<readonly string[]>([]);
    const [hotkeyWaitMs, setHotkeyWaitMs] = useState<string>("");
    /** UrlTabClick-specific structured form. Serialised into PayloadJson
     *  on submit and hydrated from PayloadJson when editing. */
    const [urlTabClick, setUrlTabClick] = useState<UrlTabClickFormState>(URL_TAB_CLICK_DEFAULTS);
    const patchUrlTabClick = (patch: Partial<UrlTabClickFormState>): void =>
        setUrlTabClick((prev) => ({ ...prev, ...patch }));

    // Reset form whenever the dialog (re-)opens with a new mode.
    useEffect(() => {
        if (!open || mode === null) return;
        if (mode.Kind === "create") {
            setKind(StepKindId.Click);
            setLabel("");
            setPayloadJson("");
            setTargetGroupId(null);
            setHotkeyChords([]);
            setHotkeyWaitMs("");
            setUrlTabClick({ ...URL_TAB_CLICK_DEFAULTS });
        } else {
            setKind(mode.Step.StepKindId);
            setLabel(mode.Step.Label ?? "");
            setPayloadJson(mode.Step.PayloadJson ?? "");
            setTargetGroupId(mode.Step.TargetStepGroupId);
            // Hydrate hotkey form from PayloadJson when editing.
            if (mode.Step.StepKindId === StepKindId.Hotkey && mode.Step.PayloadJson !== null) {
                try {
                    const parsed = JSON.parse(mode.Step.PayloadJson) as { Keys?: unknown; WaitMs?: unknown };
                    setHotkeyChords(Array.isArray(parsed.Keys) ? parsed.Keys.filter((k): k is string => typeof k === "string") : []);
                    setHotkeyWaitMs(typeof parsed.WaitMs === "number" ? String(parsed.WaitMs) : "");
                } catch {
                    setHotkeyChords([]);
                    setHotkeyWaitMs("");
                }
            } else {
                setHotkeyChords([]);
                setHotkeyWaitMs("");
            }
            // Hydrate UrlTabClick form from PayloadJson when editing.
            setUrlTabClick(
                mode.Step.StepKindId === StepKindId.UrlTabClick
                    ? hydrateUrlTabClickForm(mode.Step.PayloadJson)
                    : { ...URL_TAB_CLICK_DEFAULTS },
            );
        }
    }, [open, mode]);

    /**
     * Forbid self-reference and (lightly) descendant-loops at the UI
     * level by hiding the current group and its descendants from the
     * target picker. Cycle detection still ultimately lives in the
     * runner, but blocking the obvious case here keeps the form sane.
     */
    const targetCandidates = useMemo(() => {
        if (mode === null) return groups;
        const ownerId = mode.Kind === "create"
            ? mode.StepGroupId
            : mode.Step.StepGroupId;
        // Compute descendant set of `ownerId` (BFS over ParentStepGroupId).
        const descendants = new Set<number>([ownerId]);
        let grew = true;
        while (grew) {
            grew = false;
            for (const g of groups) {
                if (
                    g.ParentStepGroupId !== null &&
                    descendants.has(g.ParentStepGroupId) &&
                    !descendants.has(g.StepGroupId)
                ) {
                    descendants.add(g.StepGroupId);
                    grew = true;
                }
            }
        }
        return groups.filter((g) => !descendants.has(g.StepGroupId) && !g.IsArchived);
    }, [groups, mode]);

    const handleSubmit = (): void => {
        // Hotkey kind has its own structured form — synthesise the
        // PayloadJson from the captured chord list + WaitMs.
        if (kind === StepKindId.Hotkey) {
            if (hotkeyChords.length === 0) {
                toast.error("Add at least one key combination for the Hotkey step.");
                return;
            }
            const waitTrim = hotkeyWaitMs.trim();
            const waitMs = waitTrim === "" ? undefined : Number(waitTrim);
            if (waitMs !== undefined && (!Number.isFinite(waitMs) || waitMs < 0)) {
                toast.error("Wait (ms) must be a non-negative number.");
                return;
            }
            const payload = waitMs === undefined
                ? { Keys: [...hotkeyChords] }
                : { Keys: [...hotkeyChords], WaitMs: waitMs };
            onSubmit({
                StepKindId: kind,
                Label: label.trim() === "" ? null : label.trim(),
                PayloadJson: JSON.stringify(payload),
                TargetStepGroupId: null,
            });
            return;
        }
        // UrlTabClick kind has its own structured form — validate the
        // pattern (mirrors `validateUrlTabClickParams` in url-tab-click.ts)
        // and serialise into PayloadJson.
        if (kind === StepKindId.UrlTabClick) {
            const u = urlTabClick;
            if (u.UrlPattern.trim() === "") {
                toast.error("URL pattern is required.");
                return;
            }
            if (u.DirectOpen) {
                if (u.Mode !== "OpenNew") {
                    toast.error("DirectOpen requires Mode = 'OpenNew'.");
                    return;
                }
                if (u.Url.trim() === "") {
                    toast.error("DirectOpen requires a literal URL.");
                    return;
                }
            }
            const timeoutTrim = u.TimeoutMs.trim();
            const timeoutMs = timeoutTrim === "" ? undefined : Number(timeoutTrim);
            if (timeoutMs !== undefined && (!Number.isFinite(timeoutMs) || timeoutMs < 0)) {
                toast.error("Timeout (ms) must be ≥ 0.");
                return;
            }
            // Reject obviously broken regex patterns at save time.
            if (u.UrlMatch === "Regex") {
                try { new RegExp(u.UrlPattern); } catch (err) {
                    const msg = err instanceof Error ? err.message : String(err);
                    toast.error("Invalid regex pattern", { description: msg });
                    return;
                }
            }
            const payload: Record<string, unknown> = {
                UrlPattern: u.UrlPattern.trim(),
                UrlMatch:   u.UrlMatch,
                Mode:       u.Mode,
            };
            if (u.Selector.trim() !== "") payload.Selector = u.Selector.trim();
            if (u.SelectorKind !== "Auto") payload.SelectorKind = u.SelectorKind;
            if (timeoutMs !== undefined)   payload.TimeoutMs = timeoutMs;
            if (u.DirectOpen)              payload.DirectOpen = true;
            if (u.Url.trim() !== "")       payload.Url = u.Url.trim();
            onSubmit({
                StepKindId: kind,
                Label: label.trim() === "" ? null : label.trim(),
                PayloadJson: JSON.stringify(payload),
                TargetStepGroupId: null,
            });
            return;
        }
        // Light JSON validation when a payload was provided. We allow
        // a blank payload (some kinds don't need one), but reject
        // obvious typos before they round-trip through the DB.
        const trimmedPayload = payloadJson.trim();
        if (trimmedPayload !== "" && kind !== StepKindId.RunGroup) {
            try {
                JSON.parse(trimmedPayload);
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err);
                toast.error("Payload is not valid JSON", { description: msg });
                return;
            }
        }
        if (kind === StepKindId.RunGroup && targetGroupId === null) {
            toast.error("Select a target group for the RunGroup step.");
            return;
        }
        onSubmit({
            StepKindId: kind,
            Label: label.trim() === "" ? null : label.trim(),
            PayloadJson: trimmedPayload === "" ? null : trimmedPayload,
            TargetStepGroupId: kind === StepKindId.RunGroup ? targetGroupId : null,
        });
    };

    const isEdit = mode?.Kind === "edit";

    return (
        <Dialog
            open={open}
            onOpenChange={(o) => { if (!o) onCancel(); }}
        >
            <DialogContent className="max-w-lg">
                <DialogHeader>
                    <DialogTitle>{isEdit ? "Edit step" : "Add step"}</DialogTitle>
                    <DialogDescription>
                        {isEdit
                            ? "Change the kind, label, or payload. Order is preserved — use the up/down buttons to move the step."
                            : "Append a new step to the end of this group."}
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-3">
                    <div className="space-y-1">
                        <Label htmlFor="step-kind">Kind</Label>
                        <Select
                            value={String(kind)}
                            onValueChange={(v) => {
                                const next = Number(v) as StepKindId;
                                setKind(next);
                                // Clear target when leaving RunGroup so
                                // the DB invariant (target=null) holds.
                                if (next !== StepKindId.RunGroup) setTargetGroupId(null);
                            }}
                        >
                            <SelectTrigger id="step-kind">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {KIND_OPTIONS.map((k) => (
                                    <SelectItem key={k} value={String(k)}>
                                        {stepKindLabel(k)}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-1">
                        <Label htmlFor="step-label">Label</Label>
                        <Input
                            id="step-label"
                            value={label}
                            maxLength={200}
                            placeholder="Optional human-readable name"
                            onChange={(e) => setLabel(e.target.value)}
                        />
                    </div>

                    {kind === StepKindId.RunGroup ? (
                        <div className="space-y-1">
                            <Label htmlFor="step-target">Target group</Label>
                            <Select
                                value={targetGroupId === null ? "" : String(targetGroupId)}
                                onValueChange={(v) => setTargetGroupId(v === "" ? null : Number(v))}
                            >
                                <SelectTrigger id="step-target">
                                    <SelectValue placeholder="Select a group to invoke" />
                                </SelectTrigger>
                                <SelectContent>
                                    {targetCandidates.length === 0 ? (
                                        <div className="px-2 py-1.5 text-xs text-muted-foreground">
                                            No eligible groups (a RunGroup step cannot reference its
                                            own group or descendants).
                                        </div>
                                    ) : targetCandidates.map((g) => (
                                        <SelectItem key={g.StepGroupId} value={String(g.StepGroupId)}>
                                            {g.Name} (#{g.StepGroupId})
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    ) : kind === StepKindId.Hotkey ? (
                        <div className="space-y-3">
                            <div className="space-y-1">
                                <Label htmlFor="hotkey-capture">Key combinations</Label>
                                <HotkeyChordCapture
                                    id="hotkey-capture"
                                    value={hotkeyChords}
                                    onChange={setHotkeyChords}
                                />
                                <p className="text-[11px] text-muted-foreground">
                                    Each chord is dispatched in order during playback (AutoHotkey-style).
                                    Backspace removes the last chord; Esc stops listening.
                                </p>
                            </div>
                            <div className="space-y-1">
                                <Label htmlFor="hotkey-wait">Wait after (ms, optional)</Label>
                                <Input
                                    id="hotkey-wait"
                                    type="number"
                                    min={0}
                                    value={hotkeyWaitMs}
                                    placeholder="e.g. 500"
                                    onChange={(e) => setHotkeyWaitMs(e.target.value)}
                                />
                            </div>
                        </div>
                    ) : kind === StepKindId.UrlTabClick ? (
                        <div className="space-y-3">
                            <div className="grid grid-cols-3 gap-2">
                                <div className="space-y-1 col-span-2">
                                    <Label htmlFor="utc-pattern">URL pattern</Label>
                                    <Input
                                        id="utc-pattern"
                                        value={urlTabClick.UrlPattern}
                                        placeholder="https://example.com/orders/*"
                                        onChange={(e) => patchUrlTabClick({ UrlPattern: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-1">
                                    <Label htmlFor="utc-match">Match</Label>
                                    <Select
                                        value={urlTabClick.UrlMatch}
                                        onValueChange={(v) => patchUrlTabClick({ UrlMatch: v as UrlMatchDialect })}
                                    >
                                        <SelectTrigger id="utc-match"><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="Exact">Exact</SelectItem>
                                            <SelectItem value="Prefix">Prefix</SelectItem>
                                            <SelectItem value="Glob">Glob</SelectItem>
                                            <SelectItem value="Regex">Regex</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            <div className="space-y-1">
                                <Label htmlFor="utc-mode">Mode</Label>
                                <Select
                                    value={urlTabClick.Mode}
                                    onValueChange={(v) => patchUrlTabClick({ Mode: v as UrlTabClickMode })}
                                >
                                    <SelectTrigger id="utc-mode"><SelectValue /></SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="OpenNew">Open new tab</SelectItem>
                                        <SelectItem value="FocusExisting">Focus existing tab</SelectItem>
                                        <SelectItem value="OpenOrFocus">Focus existing, else open</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            <div className="grid grid-cols-3 gap-2">
                                <div className="space-y-1 col-span-2">
                                    <Label htmlFor="utc-selector">Selector (optional)</Label>
                                    <Input
                                        id="utc-selector"
                                        value={urlTabClick.Selector}
                                        placeholder="#open-orders, //a[@data-id]"
                                        onChange={(e) => patchUrlTabClick({ Selector: e.target.value })}
                                    />
                                </div>
                                <div className="space-y-1">
                                    <Label htmlFor="utc-sel-kind">Selector kind</Label>
                                    <Select
                                        value={urlTabClick.SelectorKind}
                                        onValueChange={(v) => patchUrlTabClick({ SelectorKind: v as SelectorKindOption })}
                                    >
                                        <SelectTrigger id="utc-sel-kind"><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="Auto">Auto</SelectItem>
                                            <SelectItem value="Css">CSS</SelectItem>
                                            <SelectItem value="XPath">XPath</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>

                            <div className="space-y-1">
                                <Label htmlFor="utc-timeout">Timeout (ms, optional)</Label>
                                <Input
                                    id="utc-timeout"
                                    type="number"
                                    min={0}
                                    value={urlTabClick.TimeoutMs}
                                    placeholder="default 15000"
                                    onChange={(e) => patchUrlTabClick({ TimeoutMs: e.target.value })}
                                />
                            </div>

                            <div className="flex items-center gap-2">
                                <input
                                    id="utc-direct"
                                    type="checkbox"
                                    checked={urlTabClick.DirectOpen}
                                    onChange={(e) => patchUrlTabClick({
                                        DirectOpen: e.target.checked,
                                        Mode: e.target.checked ? "OpenNew" : urlTabClick.Mode,
                                    })}
                                />
                                <Label htmlFor="utc-direct" className="cursor-pointer">
                                    Direct open (skip click, navigate to literal URL)
                                </Label>
                            </div>

                            {urlTabClick.DirectOpen && (
                                <div className="space-y-1">
                                    <Label htmlFor="utc-url">Literal URL</Label>
                                    <Input
                                        id="utc-url"
                                        value={urlTabClick.Url}
                                        placeholder="https://example.com/orders/new"
                                        onChange={(e) => patchUrlTabClick({ Url: e.target.value })}
                                    />
                                </div>
                            )}

                            <p className="text-[11px] text-muted-foreground">
                                Saved as PayloadJson with PascalCase keys (UrlPattern, UrlMatch, Mode…).
                                Runner: <code>executeUrlTabClick</code>.
                            </p>
                        </div>
                    ) : (
                        <div className="space-y-1">
                            <Label htmlFor="step-payload">Payload JSON</Label>
                            <Textarea
                                id="step-payload"
                                value={payloadJson}
                                rows={6}
                                spellCheck={false}
                                placeholder={payloadPlaceholderFor(kind)}
                                onChange={(e) => setPayloadJson(e.target.value)}
                                className="font-mono text-xs"
                            />
                            <p className="text-[11px] text-muted-foreground">
                                Leave blank when the kind doesn't need a payload. The runner
                                expects PascalCase keys (Selector, Value, WaitMs, …).
                            </p>
                        </div>
                    )}
                </div>

                <DialogFooter>
                    <Button variant="ghost" onClick={onCancel}>Cancel</Button>
                    <Button onClick={handleSubmit}>
                        {isEdit
                            ? <><Save className="mr-1 h-4 w-4" /> Save</>
                            : <><Plus className="mr-1 h-4 w-4" /> Add step</>}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

/**
 * Marco Extension — Step Group Library Panel
 *
 * Two-pane Options page surface for browsing the recorder's step
 * groups, selecting them for import/export, and performing CRUD.
 *
 * Layout:
 *   ┌──────────────── Toolbar ──────────────┐
 *   │  Project · selected count · [New]     │
 *   │  [Import ZIP]  [Export Selected]      │
 *   ├────────────────┬──────────────────────┤
 *   │  Tree pane     │  Step preview pane   │
 *   │  (checkboxes,  │  (active group's     │
 *   │  ⋯ row menu)   │   ordered steps)     │
 *   └────────────────┴──────────────────────┘
 *
 * Data layer is the in-memory `useStepLibrary` hook (sql.js, persisted
 * to localStorage). All export/import calls go through the pure
 * modules (`runStepGroupExport` / `runStepGroupImport`) so the same
 * code paths the unit tests cover are what the user clicks.
 *
 * @see src/hooks/use-step-library.ts
 * @see src/background/recorder/step-library/export-bundle.ts
 * @see src/background/recorder/step-library/import-bundle.ts
 */

import { useEffect, useMemo, useRef, useState } from "react";
