function DetailField(props: { label: string; value: string; mono?: boolean }) {
    return (
        <div className="flex items-baseline gap-2">
            <span className="text-[10px] uppercase tracking-wide text-muted-foreground">
                {props.label}
            </span>
            <span className={props.mono === true ? "font-mono text-xs" : "text-xs"}>
                {props.value}
            </span>
        </div>
    );
}

/**
 * Reusable name input that wires together the label, the controlled
 * input, and a live-error region. Accessibility: the error message is
 * linked via `aria-describedby` and `aria-invalid` flips with `error`.
 */
function ValidatedNameField(props: {
    readonly id: string;
    readonly label: string;
    readonly value: string;
    readonly error: string | null;
    readonly placeholder?: string;
    readonly onChange: (value: string) => void;
    readonly onSubmit: () => void;
}) {
    const helpId = `${props.id}-help`;
    const invalid = props.error !== null && props.value !== "";
    return (
        <div className="space-y-2">
            <Label htmlFor={props.id}>{props.label}</Label>
            <Input
                id={props.id}
                value={props.value}
                maxLength={NAME_MAX_LEN}
                placeholder={props.placeholder}
                onChange={(e) => props.onChange(e.target.value)}
                onKeyDown={(e) => {
                    if (e.key === "Enter") props.onSubmit();
                }}
                aria-invalid={invalid}
                aria-describedby={helpId}
                autoFocus
                className={invalid ? "border-destructive focus-visible:ring-destructive" : ""}
            />
            <p
                id={helpId}
                className={`min-h-[1rem] text-xs ${
                    props.error === null ? "text-muted-foreground" : "text-destructive"
                }`}
            >
                {props.error ?? `${props.value.trim().length}/${NAME_MAX_LEN}`}
            </p>
        </div>
    );
}

/**
 * Marco Extension — Step Library Error State
 *
 * Shared, actionable error card surfaced by both the Step Group
 * Library tree panel and the list panel when `useStepLibrary` fails
 * to bootstrap. Renders the structured `StepLibraryLoadError`:
 *
 *   ┌──────────────────────────────────────────────┐
 *   │  ⚠   Title (kind-specific)                   │
 *   │      Hint — plain-language recovery advice   │
 *   │      ▸ Technical details (collapsible)       │
 *   │      [ Retry ]   [ Reset library ]           │
 *   └──────────────────────────────────────────────┘
 *
 * The Reset action is destructive (wipes localStorage), so it always
 * lives behind an AlertDialog confirmation. Retry is safe to spam —
 * it just bumps the bootstrap nonce in the hook.
 *
 * @see @/hooks/use-step-library — emits `LoadError`
 */

import { useState } from "react";
import { AlertTriangle, Database, RefreshCw, Trash2, WifiOff } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import type { StepLibraryLoadError } from "@/hooks/use-step-library";

export interface StepLibraryErrorStateProps {
    readonly error: StepLibraryLoadError;
    readonly onRetry: () => void;
    readonly onReset: () => void;
}

/**
 * Map each error kind to a short, human title + the icon that best
 * communicates it at a glance. Kept here (not in the hook) so the
 * presentation layer owns the wording.
 */
function titleAndIcon(kind: StepLibraryLoadError["Kind"]): { Title: string; Icon: typeof AlertTriangle } {
    switch (kind) {
        case "SqlJsLoad":
            return { Title: "Couldn't load the SQL engine", Icon: WifiOff };
        case "StorageRead":
            return { Title: "Couldn't read your saved library", Icon: Database };
        case "StorageWrite":
            return { Title: "Couldn't save to browser storage", Icon: Database };
        case "Unknown":
        default:
            return { Title: "Step library failed to open", Icon: AlertTriangle };
    }
}

export default function StepLibraryErrorState({ error, onRetry, onReset }: StepLibraryErrorStateProps) {
    const [showDetails, setShowDetails] = useState(false);
    const [confirmReset, setConfirmReset] = useState(false);
    const { Title, Icon } = titleAndIcon(error.Kind);

    return (
        <div className="flex h-full min-h-[400px] items-center justify-center p-6">
            <Card className="flex w-full max-w-xl flex-col gap-4 p-6">
                <div className="flex items-start gap-3">
                    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-destructive/10 text-destructive">
                        <Icon className="h-5 w-5" />
                    </div>
                    <div className="flex-1">
                        <h2 className="text-lg font-semibold tracking-tight">{Title}</h2>
                        <p className="mt-1 text-sm text-muted-foreground">{error.Hint}</p>
                    </div>
                </div>

                <div className="rounded border bg-muted/30 px-3 py-2 text-xs">
                    <button
                        type="button"
                        onClick={() => setShowDetails((s) => !s)}
                        className="font-medium text-muted-foreground hover:text-foreground"
                        aria-expanded={showDetails}
                    >
                        {showDetails ? "Hide technical details" : "Show technical details"}
                    </button>
                    {showDetails && (
                        <pre className="mt-2 max-h-40 overflow-auto whitespace-pre-wrap break-words font-mono text-[11px] text-muted-foreground">
                            {error.Kind}: {error.Message}
                        </pre>
                    )}
                </div>

                <div className="flex flex-wrap items-center justify-end gap-2">
                    {/* Reset is the destructive escape hatch — always
                        guarded by a confirmation since it wipes the
                        on-disk DB blob. */}
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setConfirmReset(true)}
                        title="Wipe the saved library and start fresh"
                    >
                        <Trash2 className="mr-1 h-4 w-4" />
                        Reset library
                    </Button>
                    <Button size="sm" onClick={onRetry}>
                        <RefreshCw className="mr-1 h-4 w-4" />
                        Retry
                    </Button>
                </div>
            </Card>

            <AlertDialog open={confirmReset} onOpenChange={setConfirmReset}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Reset the step library?</AlertDialogTitle>
                        <AlertDialogDescription>
                            This permanently deletes the saved step-group database from
                            your browser. Any groups, steps, or input data not exported
                            to a ZIP bundle will be lost. The page will reload.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                        <AlertDialogAction
                            className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                            onClick={onReset}
                        >
                            Reset and reload
                        </AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </div>
    );
}

/**
 * Marco Extension — Step Wait Selector Dialog
 *
 * Configure (or clear) the post-step wait condition for a single Step.
 * Wraps the pure helpers in `step-wait.ts` so the dialog stays
 * presentation-only.
 *
 * UX:
 *   - Selector field with live auto-detect badge (Css / XPath).
 *   - "Override" radio lets the user pin Kind when auto-detect picks
 *     the wrong language.
 *   - Condition select (Appears / Disappears / Visible).
 *   - Timeout in ms (clamped 250–60 000).
 *   - Save / Clear / Cancel.
 *
 * The dialog never persists until the user clicks Save, and always
 * round-trips through the sanitiser in `writeStepWait`.
 */

import { useEffect, useMemo, useState } from "react";
import { toast } from "sonner";
import { CheckCircle2, Eye, EyeOff, MousePointer2, SearchCheck, Trash2, XCircle } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";

import {
    DEFAULT_WAIT_CONFIG,
    clearStepWait,
    detectSelectorKind,
    evaluateSelector,
    readStepWait,
    validateSelector,
    writeStepWait,
    type ElementLike,
    type SelectorKind,
    type WaitCondition,
    type WaitConfig,
} from "@/background/recorder/step-library/step-wait";

/**
 * Result of clicking "Test selector" — counts matches in the current
 * options-page document so the user can see whether their expression
 * resolves anything before saving.
 *
 * Note: this only probes the page hosting the options UI, not the
 * recorder's target tab. It still catches the most common authoring
 * mistakes (typos, wrong axis, missing brackets) and proves the
 * expression compiles.
 */
interface TestResult {
    readonly Kind: SelectorKind;
    readonly TotalCount: number;
    readonly VisibleCount: number;
    readonly DurationMs: number;
    readonly Error: string | null;
}

function countVisible(matches: ReadonlyArray<ElementLike>): number {
    let n = 0;
    for (const el of matches) {
        const w = typeof el.offsetWidth === "number" ? el.offsetWidth : 0;
        const h = typeof el.offsetHeight === "number" ? el.offsetHeight : 0;
        if (w > 0 || h > 0) { n += 1; continue; }
        if (typeof el.getClientRects === "function" && el.getClientRects().length > 0) {
            n += 1;
        }
    }
    return n;
}

interface Props {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly stepId: number | null;
    readonly stepLabel: string | null;
    /** Notifies the parent to refresh its "has wait" badge state. */
    readonly onChange?: () => void;
}

type KindMode = "Auto" | "Css" | "XPath";

const CONDITION_LABELS: Record<WaitCondition, string> = {
    Appears: "Element appears in DOM",
    Disappears: "Element disappears from DOM",
    Visible: "Element is visible (has layout)",
};

const CONDITION_ICON: Record<WaitCondition, typeof Eye> = {
    Appears: MousePointer2,
    Disappears: EyeOff,
    Visible: Eye,
};

export default function StepWaitDialog(props: Props) {
    const { open, onOpenChange, stepId, stepLabel, onChange } = props;

    const [selector, setSelector] = useState("");
    const [kindMode, setKindMode] = useState<KindMode>("Auto");
    const [condition, setCondition] = useState<WaitCondition>(DEFAULT_WAIT_CONFIG.Condition);
    const [timeoutMs, setTimeoutMs] = useState<number>(DEFAULT_WAIT_CONFIG.TimeoutMs);
    const [hasExisting, setHasExisting] = useState(false);
    const [testResult, setTestResult] = useState<TestResult | null>(null);

    useEffect(() => {
        if (!open || stepId === null) return;
        const existing = readStepWait(stepId);
        if (existing === null) {
            setSelector("");
            setKindMode("Auto");
            setCondition(DEFAULT_WAIT_CONFIG.Condition);
            setTimeoutMs(DEFAULT_WAIT_CONFIG.TimeoutMs);
            setHasExisting(false);
        } else {
            setSelector(existing.Selector);
            setKindMode(existing.Kind);
            setCondition(existing.Condition);
            setTimeoutMs(existing.TimeoutMs);
            setHasExisting(true);
        }
        setTestResult(null);
    }, [open, stepId]);

    // Invalidate stale test results whenever the inputs change.
    useEffect(() => {
        setTestResult(null);
    }, [selector, kindMode]);

    const detected: SelectorKind = useMemo(
        () => detectSelectorKind(selector),
        [selector],
    );
    const effectiveKind: SelectorKind =
        kindMode === "Auto" ? detected : kindMode;

    const validation = useMemo(
        () => selector.trim().length === 0
            ? { Ok: true as const, Kind: effectiveKind }
            : validateSelector(selector, effectiveKind),
        [selector, effectiveKind],
    );

    const handleSave = () => {
        if (stepId === null) return;
        if (selector.trim().length === 0) {
            toast.error("Selector is required");
            return;
        }
        if (!validation.Ok) {
            toast.error(validation.Reason);
            return;
        }
        const next: WaitConfig = {
            Selector: selector.trim(),
            Kind: effectiveKind,
            Condition: condition,
            TimeoutMs: timeoutMs,
        };
        try {
            writeStepWait(stepId, next);
            toast.success("Wait condition saved");
            onChange?.();
            onOpenChange(false);
        } catch (e) {
            const detail = e instanceof Error ? e.message : "Unknown error";
            toast.error(`Could not save: ${detail}`);
        }
    };

    const handleTest = () => {
        if (selector.trim().length === 0) {
            toast.error("Enter a selector first");
            return;
        }
        if (!validation.Ok) {
            setTestResult({
                Kind: effectiveKind,
                TotalCount: 0,
                VisibleCount: 0,
                DurationMs: 0,
                Error: validation.Reason,
            });
            return;
        }
        const startedAt = performance.now();
        try {
            const matches = evaluateSelector({
                Selector: selector.trim(),
                Kind: effectiveKind,
            });
            const elapsed = Math.max(0, Math.round(performance.now() - startedAt));
            setTestResult({
                Kind: effectiveKind,
                TotalCount: matches.length,
                VisibleCount: countVisible(matches),
                DurationMs: elapsed,
                Error: null,
            });
        } catch (e) {
            const detail = e instanceof Error ? e.message : "Unknown evaluation error";
            setTestResult({
                Kind: effectiveKind,
                TotalCount: 0,
                VisibleCount: 0,
                DurationMs: Math.max(0, Math.round(performance.now() - startedAt)),
                Error: detail,
            });
        }
    };

    const handleClear = () => {
        if (stepId === null) return;
        clearStepWait(stepId);
        toast.success("Wait condition cleared");
        onChange?.();
        onOpenChange(false);
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-lg">
                <DialogHeader>
                    <DialogTitle>Wait after this step</DialogTitle>
                    <DialogDescription>
                        {stepLabel === null || stepLabel.length === 0
                            ? "After this step runs, wait for the selector below to satisfy the chosen condition before continuing."
                            : `After "${stepLabel}" runs, wait for this selector before continuing.`}
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-4">
                    {/* Selector */}
                    <div className="space-y-1.5">
                        <div className="flex items-center justify-between">
                            <Label htmlFor="wait-selector" className="text-sm font-medium">
                                Selector
                            </Label>
                            {selector.trim().length > 0 && (
                                <Badge variant={kindMode === "Auto" ? "secondary" : "outline"}>
                                    {kindMode === "Auto" ? `Auto · ${detected}` : effectiveKind}
                                </Badge>
                            )}
                        </div>
                        <Input
                            id="wait-selector"
                            placeholder="#submit-confirmation, .loading, //div[@id='ok']"
                            value={selector}
                            onChange={(e) => setSelector(e.target.value)}
                            className="font-mono text-sm"
                        />
                        {!validation.Ok && (
                            <p className="text-xs text-destructive">{validation.Reason}</p>
                        )}
                        <p className="text-xs text-muted-foreground">
                            Auto-detect picks XPath when the expression starts with <code>/</code>,
                            <code> ./</code>, <code>(/</code>, <code>(./</code>, or contains <code>//</code>.
                        </p>

                        {/* Test selector against the live document */}
                        <div className="flex items-center gap-2 pt-1">
                            <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                onClick={handleTest}
                                disabled={selector.trim().length === 0}
                            >
                                <SearchCheck className="mr-1 h-3.5 w-3.5" />
                                Test selector
                            </Button>
                            {testResult !== null && testResult.Error === null && (
                                <span
                                    className={
                                        testResult.TotalCount > 0
                                            ? "flex items-center gap-1 text-xs text-emerald-500"
                                            : "flex items-center gap-1 text-xs text-amber-500"
                                    }
                                >
                                    {testResult.TotalCount > 0
                                        ? <CheckCircle2 className="h-3.5 w-3.5" />
                                        : <XCircle className="h-3.5 w-3.5" />}
                                    {testResult.TotalCount} match
                                    {testResult.TotalCount === 1 ? "" : "es"}
                                    {testResult.TotalCount > 0 && (
                                        <span className="text-muted-foreground">
                                            · {testResult.VisibleCount} visible
                                        </span>
                                    )}
                                    <span className="text-muted-foreground">
                                        · {testResult.DurationMs} ms
                                    </span>
                                </span>
                            )}
                            {testResult !== null && testResult.Error !== null && (
                                <span className="flex items-center gap-1 text-xs text-destructive">
                                    <XCircle className="h-3.5 w-3.5" />
                                    {testResult.Error}
                                </span>
                            )}
                        </div>
                        {testResult !== null && testResult.Error === null && testResult.TotalCount === 0 && (
                            <p className="text-xs text-muted-foreground">
                                No elements matched on the current options page. The selector
                                will still be evaluated against the recorder's target tab at run
                                time — this preview only catches typos and compile errors.
                            </p>
                        )}
                    </div>

                    {/* Kind override */}
                    <div className="space-y-1.5">
                        <Label className="text-xs text-muted-foreground">Selector type</Label>
                        <Select
                            value={kindMode}
                            onValueChange={(v) => setKindMode(v as KindMode)}
                        >
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="Auto">Auto-detect</SelectItem>
                                <SelectItem value="Css">Force CSS</SelectItem>
                                <SelectItem value="XPath">Force XPath</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    {/* Condition */}
                    <div className="space-y-1.5">
                        <Label className="text-xs text-muted-foreground">Condition</Label>
                        <Select
                            value={condition}
                            onValueChange={(v) => setCondition(v as WaitCondition)}
                        >
                            <SelectTrigger>
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                {(["Appears", "Visible", "Disappears"] as const).map((c) => {
                                    const Icon = CONDITION_ICON[c];
                                    return (
                                        <SelectItem key={c} value={c}>
                                            <span className="flex items-center gap-2">
                                                <Icon className="h-3.5 w-3.5" />
                                                {CONDITION_LABELS[c]}
                                            </span>
                                        </SelectItem>
                                    );
                                })}
                            </SelectContent>
                        </Select>
                    </div>

                    {/* Timeout */}
                    <div className="space-y-1.5">
                        <Label htmlFor="wait-timeout" className="text-xs text-muted-foreground">
                            Timeout (ms, 250 – 60 000)
                        </Label>
                        <Input
                            id="wait-timeout"
                            type="number"
                            min={250}
                            max={60000}
                            step={250}
                            value={timeoutMs}
                            onChange={(e) => setTimeoutMs(
                                Number.parseInt(e.target.value, 10) || timeoutMs,
                            )}
                        />
                    </div>
                </div>

                <DialogFooter className="flex-col gap-2 sm:flex-row sm:justify-between">
                    <div>
                        {hasExisting && (
                            <Button variant="ghost" onClick={handleClear}>
                                <Trash2 className="mr-1 h-4 w-4" />
                                Remove wait
                            </Button>
                        )}
                    </div>
                    <div className="flex gap-2">
                        <Button variant="ghost" onClick={() => onOpenChange(false)}>
                            Cancel
                        </Button>
                        <Button onClick={handleSave}>Save</Button>
                    </div>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

/**
 * Token Seeder Status Indicator
 *
 * Compact row for the System Status panel that surfaces JWT seed
 * failures on inaccessible tabs and shows a live countdown until the
 * next retry attempt across all blocked tabs.
 *
 * Hides itself when no tabs are currently throttled. Clicking the row
 * toggles an inline expandable details drawer that lists every blocked
 * tab — its tabId, origin URL, classified failure reason, and how many
 * times Chrome has rejected the seed attempt.
 */

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { Badge } from "@/components/ui/badge";
import {
    Collapsible,
    CollapsibleContent,
    CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { ShieldOff, Timer, ChevronDown } from "lucide-react";
import { sendMessage } from "@/lib/message-client";
import { logError } from "./options-logger";
import {
    loadDiagnosticsCache,
    saveDiagnosticsCache,
} from "./token-seeder-diagnostics-cache";

interface InaccessibleSeedTarget {
    tabId: number;
    tabUrl: string;
    reason: string;
    code: string;
    firstFailureAt: number;
    lastFailureAt: number;
    attemptCount: number;
    cooldownMs: number;
}

interface TokenSeederDiagnostics {
    targets: InaccessibleSeedTarget[];
    cooldownMs: number;
    capturedAt: string;
}

const POLL_INTERVAL_MS = 5_000;
const TICK_INTERVAL_MS = 500;

type ErrorCategory = "host-permission" | "scripting-blocked" | "restricted-scheme" | "other";

const CATEGORY_LABELS: Record<ErrorCategory, string> = {
    "host-permission": "Host permission",
    "scripting-blocked": "Scripting blocked",
    "restricted-scheme": "Restricted scheme",
    other: "Other",
};

function categorizeCode(code: string): ErrorCategory {
    switch (code) {
        case "RESPECTIVE_HOST_PERMISSION":
        case "MISSING_HOST_PERMISSION":
        case "NO_HOST_PATTERN":
        case "PERMISSION_NOT_GRANTED":
            return "host-permission";
        case "PAGE_CONTENTS_BLOCKED":
        case "EXTENSIONS_GALLERY_BLOCKED":
        case "GENERIC_CANNOT_SCRIPT":
            return "scripting-blocked";
        case "RESTRICTED_SCHEME":
            return "restricted-scheme";
        default:
            return "other";
    }
}

function formatRemaining(ms: number): string {
    if (ms <= 0) return "ready";
    return `${Math.ceil(ms / 1000)}s`;
}

function formatRetryTimestamp(ts: number): string {
    try {
        return new Intl.DateTimeFormat("en-GB", {
            timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
            hour: "2-digit",
            minute: "2-digit",
            second: "2-digit",
            hour12: false,
        }).format(new Date(ts));
    } catch {
        return new Date(ts).toISOString();
    }
}

function formatOrigin(url: string): string {
    if (!url) return "(unknown)";
    try {
        const u = new URL(url);
        return u.origin;
    } catch {
        return url.length > 48 ? `${url.slice(0, 48)}…` : url;
    }
}

export function TokenSeederStatusIndicator() {
    const [data, setData] = useState<TokenSeederDiagnostics | null>(() => loadDiagnosticsCache());
    const [now, setNow] = useState<number>(() => Date.now());
    const [open, setOpen] = useState<boolean>(false);
    const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);
    const tickRef = useRef<ReturnType<typeof setInterval> | null>(null);

    const fetchDiagnostics = useCallback(async () => {
        try {
            const res = await sendMessage<TokenSeederDiagnostics>({
                type: "GET_TOKEN_SEEDER_DIAGNOSTICS",
            });
            setData(res);
            saveDiagnosticsCache(res);
        } catch (caught) {
            logError("TokenSeederStatusIndicator.fetchDiagnostics", "GET_TOKEN_SEEDER_DIAGNOSTICS failed — background may not be ready, will retry on next poll", caught);
        }
    }, []);

    useEffect(() => {
        void fetchDiagnostics();
        pollRef.current = setInterval(() => void fetchDiagnostics(), POLL_INTERVAL_MS);
        tickRef.current = setInterval(() => setNow(Date.now()), TICK_INTERVAL_MS);
        return () => {
            if (pollRef.current) clearInterval(pollRef.current);
            if (tickRef.current) clearInterval(tickRef.current);
        };
    }, [fetchDiagnostics]);

    const targets = data?.targets ?? [];

    const { nextRetryMs, nextRetryAt } = useMemo(() => {
        if (targets.length === 0) return { nextRetryMs: 0, nextRetryAt: 0 };
        let minRemaining = Number.POSITIVE_INFINITY;
        let minRetryAt = 0;
        for (const t of targets) {
            const retryAt = t.lastFailureAt + t.cooldownMs;
            const remaining = Math.max(0, retryAt - now);
            if (remaining < minRemaining) {
                minRemaining = remaining;
                minRetryAt = retryAt;
            }
        }
        return {
            nextRetryMs: minRemaining === Number.POSITIVE_INFINITY ? 0 : minRemaining,
            nextRetryAt: minRetryAt,
        };
    }, [targets, now]);

    const categoryCounts = useMemo(() => {
        const counts = new Map<ErrorCategory, number>();
        for (const t of targets) {
            const cat = categorizeCode(t.code);
            counts.set(cat, (counts.get(cat) ?? 0) + 1);
        }
        return counts;
    }, [targets]);

    if (targets.length === 0) {
        return null;
    }

    const isReady = nextRetryMs <= 0;

    const categorySummary = Array.from(categoryCounts.entries())
        .map(([cat, count]) => `${CATEGORY_LABELS[cat]}: ${count}`)
        .join(" · ");

    const retryLine = isReady
        ? "Retrying on next poll."
        : `Next retry at ${formatRetryTimestamp(nextRetryAt)} (in ${formatRemaining(nextRetryMs)}).`;

    const tooltip =
        `${targets.length} tab(s) blocked Chrome scripting access.\n` +
        `Categories — ${categorySummary || "Unknown"}.\n` +
        `${retryLine}\n` +
        `Click to view per-tab details.`;

    return (
        <Collapsible open={open} onOpenChange={setOpen}>
            <CollapsibleTrigger asChild>
                <button
                    type="button"
                    className="flex w-full items-center justify-between rounded-md border border-warning/40 bg-warning/10 px-3 py-2 text-left transition-colors hover:bg-warning/15 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                    title={tooltip}
                    aria-label="Toggle token seeder failure details"
                >
                    <div className="flex items-center gap-2 min-w-0">
                        <ShieldOff className="h-4 w-4 text-warning shrink-0" />
                        <span className="text-sm">Token Seed Blocked</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <Badge variant="outline" className="text-[10px]">
                            {targets.length} tab{targets.length === 1 ? "" : "s"}
                        </Badge>
                        <span className="flex items-center gap-1 text-xs font-mono text-muted-foreground">
                            <Timer className="h-3 w-3" />
                            {isReady ? "retrying…" : `retry in ${formatRemaining(nextRetryMs)}`}
                        </span>
                        <ChevronDown
                            className={`h-4 w-4 text-muted-foreground transition-transform ${open ? "rotate-180" : ""}`}
                        />
                    </div>
                </button>
            </CollapsibleTrigger>
            <CollapsibleContent>
                <div className="mt-2 rounded-md border border-warning/30 bg-background/40">
                    <ul
                        className="divide-y divide-border max-h-64 overflow-y-auto"
                        aria-label="Blocked tabs"
                    >
                        {targets.map((t) => {
                            const remaining = Math.max(0, t.cooldownMs - (now - t.lastFailureAt));
                            return (
                                <li
                                    key={t.tabId}
                                    className="px-3 py-2 text-xs space-y-1"
                                    data-tab-id={t.tabId}
                                >
                                    <div className="flex items-center justify-between gap-2">
                                        <span className="font-mono text-muted-foreground">
                                            tab #{t.tabId}
                                        </span>
                                        <Badge variant="outline" className="text-[10px]">
                                            {t.attemptCount} attempt{t.attemptCount === 1 ? "" : "s"}
                                        </Badge>
                                    </div>
                                    <div
                                        className="truncate text-foreground"
                                        title={t.tabUrl || "(unknown)"}
                                    >
                                        {formatOrigin(t.tabUrl)}
                                    </div>
                                    <div
                                        className="text-warning/90 break-words"
                                        title={t.reason}
                                    >
                                        <span className="font-mono text-[10px] uppercase tracking-wide text-warning">
                                            {t.code}
                                        </span>
                                        <span className="mx-1 text-muted-foreground">·</span>
                                        <span>{t.reason}</span>
                                    </div>
                                    <div className="flex items-center justify-end text-[10px] font-mono text-muted-foreground">
                                        {remaining <= 0
                                            ? "ready to retry"
                                            : `next retry in ${formatRemaining(remaining)}`}
                                    </div>
                                </li>
                            );
                        })}
                    </ul>
                </div>
            </CollapsibleContent>
        </Collapsible>
    );
}

