/**
 * A delivery-log entry is a "corrupt placeholder" when the loader could not
 * validate the original row and substituted a synthetic failure (see
 * `buildCorruptPlaceholder` in `result-webhook.ts`). We detect them by the
 * stable error-message prefix so the Repair button can show an accurate count
 * without leaking a brittle Kind discriminator.
 */
const CORRUPT_PLACEHOLDER_PREFIX = "Corrupt webhook log entry";

function isCorruptPlaceholder(entry: WebhookDeliveryResult): boolean {
    return isWebhookFailure(entry) && entry.Error.startsWith(CORRUPT_PLACEHOLDER_PREFIX);
}

interface Props {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
}

const EVENT_LABELS: Record<WebhookEventKind, string> = {
    GroupRunSucceeded: "Group run succeeded",
    GroupRunFailed: "Group run failed",
    BatchComplete: "Batch run complete",
    RecordingStopped: "Recording stopped",
};

function formatTime(iso: string): string {
    try {
        return new Date(iso).toLocaleTimeString();
    } catch {
        return iso;
    }
}

function formatPayloadJson(entry: WebhookDeliveryResult): string | null {
    if (entry.Payload === null || entry.Payload === undefined) return null;
    try {
        return JSON.stringify(entry.Payload, null, 2);
    } catch (err) {
        return `// Failed to serialise payload: ${err instanceof Error ? err.message : String(err)}`;
    }
}

function describeSuccess(entry: WebhookDeliverySuccess): string {
    return `Status: OK (HTTP ${entry.Status})`;
}

function describeSkipped(entry: WebhookDeliverySkipped): string {
    return `Status: Skipped\nSkip reason: ${entry.SkipReason}`;
}

function describeFailure(entry: WebhookDeliveryFailure): string {
    const httpPart = entry.Status !== null ? ` (HTTP ${entry.Status})` : "";
    return `Status: Failed${httpPart}\nError: ${entry.Error}`;
}

type VariantBadgeVariant = "default" | "secondary" | "outline" | "destructive";

interface VariantPresentation {
    readonly badgeLabel: string;
    readonly badgeVariant: VariantBadgeVariant;
    readonly badgeExtraClass: string;
    readonly rowClass: string;
    readonly hoverClass: string;
    readonly summaryDetail: string | null;
    readonly summaryDetailClass: string;
    readonly eventClass: string;
}

const ROW_SUCCESS = "rounded-md border border-emerald-500/30 bg-emerald-500/5 text-xs";
const ROW_SKIPPED = "rounded-md border border-dashed border-muted-foreground/40 bg-muted/10 text-xs";
const ROW_FAILED  = "rounded-md border border-destructive/60 bg-destructive/10 text-xs shadow-[0_0_0_1px_hsl(var(--destructive)/0.35)]";

function presentSuccess(entry: WebhookDeliverySuccess): VariantPresentation {
    return {
        badgeLabel: `OK ${entry.Status}`,
        badgeVariant: "default",
        badgeExtraClass: "",
        rowClass: ROW_SUCCESS,
        hoverClass: "hover:bg-emerald-500/10",
        summaryDetail: `HTTP ${entry.Status}`,
        summaryDetailClass: "text-emerald-300/90",
        eventClass: "",
    };
}

function presentSkipped(entry: WebhookDeliverySkipped): VariantPresentation {
    return {
        badgeLabel: "Skipped",
        badgeVariant: "outline",
        badgeExtraClass: "",
        rowClass: ROW_SKIPPED,
        hoverClass: "hover:bg-muted/30",
        summaryDetail: entry.SkipReason && entry.SkipReason.length > 0 ? entry.SkipReason : "(no reason recorded)",
        summaryDetailClass: "text-muted-foreground",
        eventClass: "",
    };
}

function presentFailure(entry: WebhookDeliveryFailure): VariantPresentation {
    const statusSuffix = entry.Status !== null ? ` ${entry.Status}` : "";
    const errorText = entry.Error && entry.Error.length > 0 ? entry.Error : "(no error message)";
    const httpPrefix = entry.Status !== null ? `HTTP ${entry.Status} — ` : "";
    return {
        badgeLabel: `Failed${statusSuffix}`,
        badgeVariant: "destructive",
        badgeExtraClass: "uppercase tracking-wide font-bold ring-1 ring-destructive/60 shadow-sm",
        rowClass: ROW_FAILED,
        hoverClass: "hover:bg-destructive/15",
        summaryDetail: `${httpPrefix}${errorText}`,
        summaryDetailClass: "text-destructive/90 font-medium",
        eventClass: "text-destructive font-semibold",
    };
}

function presentVariant(entry: WebhookDeliveryResult): VariantPresentation {
    if (isWebhookSuccess(entry)) return presentSuccess(entry);
    if (isWebhookSkipped(entry)) return presentSkipped(entry);
    return presentFailure(entry);
}

const CLIP_SEPARATOR = "─".repeat(48);
const CLIP_EOL = "\r\n";

function variantHeader(entry: WebhookDeliveryResult): string {
    if (isWebhookSkipped(entry)) return "[SKIPPED] Webhook Delivery";
    if (isWebhookSuccess(entry)) return "[SUCCESS] Webhook Delivery";
    return "[FAILURE] Webhook Delivery";
}

function variantStatusBlock(entry: WebhookDeliveryResult): string {
    if (isWebhookSkipped(entry)) return describeSkipped(entry);
    if (isWebhookSuccess(entry)) return describeSuccess(entry);
    if (isWebhookFailure(entry)) return describeFailure(entry);
    return "Status: <unknown>";
}

function buildLogClipboardText(entry: WebhookDeliveryResult): string {
    const sections: string[] = [];
    sections.push(CLIP_SEPARATOR);
    sections.push(variantHeader(entry));
    sections.push(CLIP_SEPARATOR);
    sections.push(
        [
            `Event:    ${entry.Event ?? "<missing>"}`,
            `Emitted:  ${entry.EmittedAt ?? "<missing>"}`,
            `Duration: ${entry.DurationMs ?? 0} ms`,
        ].join(CLIP_EOL),
    );
    sections.push(CLIP_SEPARATOR);
    sections.push(variantStatusBlock(entry));
    const payloadJson = formatPayloadJson(entry);
    if (payloadJson !== null) {
        sections.push(CLIP_SEPARATOR);
        sections.push("Payload:");
        sections.push(payloadJson);
    }
    sections.push(CLIP_SEPARATOR);
    // Normalise any embedded \n inside subsections to CRLF for a single
    // consistent line ending throughout the clipboard payload.
    return sections.join(CLIP_EOL).replace(/\r?\n/g, CLIP_EOL);
}

async function copyLogEntry(entry: WebhookDeliveryResult): Promise<void> {
    const text = buildLogClipboardText(entry);
    try {
        await navigator.clipboard.writeText(text);
        toast.success("Webhook details copied");
    } catch (err) {
        toast.error(`Copy failed: ${err instanceof Error ? err.message : String(err)}`);
    }
}

function entryStatusLabel(entry: WebhookDeliveryResult): string {
    if (isWebhookSkipped(entry)) return "Skipped";
    if (isWebhookSuccess(entry)) return "Success";
    return "Failure";
}

function entryStatusCode(entry: WebhookDeliveryResult): number | null {
    if (isWebhookSkipped(entry)) return null;
    return entry.Status ?? null;
}

function entryDetail(entry: WebhookDeliveryResult): string {
    if (isWebhookSkipped(entry)) return entry.SkipReason;
    if (isWebhookFailure(entry)) return entry.Error;
    return "";
}

function csvCell(value: string | number | null): string {
    if (value === null || value === undefined) return "";
    const s = String(value);
    if (/[",\n\r]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
    return s;
}

function buildJsonExport(entries: ReadonlyArray<WebhookDeliveryResult>): string {
    return JSON.stringify(
        {
            ExportedAt: new Date().toISOString(),
            Count: entries.length,
            Entries: entries,
        },
        null,
        2,
    );
}

function buildCsvExport(entries: ReadonlyArray<WebhookDeliveryResult>): string {
    const headers = ["Event", "EmittedAt", "Status", "HttpStatus", "DurationMs", "Detail", "PayloadJson"];
    const rows: string[] = [headers.join(",")];
    for (const entry of entries) {
        const payload = formatPayloadJson(entry);
        rows.push([
            csvCell(entry.Event ?? ""),
            csvCell(entry.EmittedAt ?? ""),
            csvCell(entryStatusLabel(entry)),
            csvCell(entryStatusCode(entry)),
            csvCell(entry.DurationMs ?? null),
            csvCell(entryDetail(entry)),
            csvCell(payload ?? ""),
        ].join(","));
    }
    return rows.join("\n");
}

function downloadFile(filename: string, mimeType: string, content: string): void {
    const blob = new Blob([content], { type: `${mimeType};charset=utf-8` });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    const _revokeId = window.setTimeout(() => URL.revokeObjectURL(url), 0);
    // Best-effort: if caller cancels synchronously, allow clearTimeout(_revokeId).
    void clearTimeout;
}

function exportFilteredLog(entries: ReadonlyArray<WebhookDeliveryResult>, format: "json" | "csv"): void {
    if (entries.length === 0) {
        toast.error("No entries match the current filters");
        return;
    }
    const stamp = new Date().toISOString().replace(/[:.]/g, "-");
    if (format === "json") {
        downloadFile(`webhook-log-${stamp}.json`, "application/json", buildJsonExport(entries));
    } else {
        downloadFile(`webhook-log-${stamp}.csv`, "text/csv", buildCsvExport(entries));
    }
    toast.success(`Exported ${entries.length} ${entries.length === 1 ? "entry" : "entries"} as ${format.toUpperCase()}`);
}

export default function WebhookSettingsDialog({ open, onOpenChange }: Props) {
    const [draft, setDraft] = useState<WebhookConfig>(DEFAULT_WEBHOOK_CONFIG);
    const [log, setLog] = useState<ReadonlyArray<WebhookDeliveryResult>>([]);
    const [busy, setBusy] = useState(false);
    const [expandedIdx, setExpandedIdx] = useState<number | null>(null);
    const [payloadOpenIdx, setPayloadOpenIdx] = useState<number | null>(null);
    const [statusFilter, setStatusFilter] = useState<"all" | "success" | "skipped" | "failure">("all");
    const [searchQuery, setSearchQuery] = useState("");
    const [repairConfirmOpen, setRepairConfirmOpen] = useState(false);
    const [repairBusy, setRepairBusy] = useState(false);

    useEffect(() => {
        if (open) {
            setDraft(loadWebhookConfig());
            setLog(getDeliveryLog());
            setSearchQuery("");
        }
    }, [open]);

    const eventSet = useMemo(() => new Set(draft.Events), [draft.Events]);

    const logCounts = useMemo(() => {
        let success = 0;
        let skipped = 0;
        let failure = 0;
        for (const entry of log) {
            if (isWebhookSkipped(entry)) skipped += 1;
            else if (isWebhookSuccess(entry)) success += 1;
            else failure += 1;
        }
        return { all: log.length, success, skipped, failure };
    }, [log]);

    const filteredLog = useMemo(() => {
        const query = searchQuery.trim().toLowerCase();
        return log.filter((entry) => {
            if (statusFilter === "skipped" && !isWebhookSkipped(entry)) return false;
            if (statusFilter === "success" && !isWebhookSuccess(entry)) return false;
            if (statusFilter === "failure" && (isWebhookSkipped(entry) || isWebhookSuccess(entry))) return false;
            if (query.length === 0) return true;
            const event = entry.Event?.toLowerCase() ?? "";
            const emitted = entry.EmittedAt?.toLowerCase() ?? "";
            const statusValue = isWebhookSkipped(entry) ? null : entry.Status;
            const status = statusValue === null || statusValue === undefined ? "" : String(statusValue);
            return event.includes(query) || emitted.includes(query) || status.includes(query);
        });
    }, [log, statusFilter, searchQuery]);

    const toggleEvent = (kind: WebhookEventKind, on: boolean) => {
        setDraft((prev) => {
            const next = new Set(prev.Events);
            if (on) next.add(kind); else next.delete(kind);
            return {
                ...prev,
                Events: ALL_WEBHOOK_EVENTS.filter((k) => next.has(k)),
            };
        });
    };

    const updateHeader = (idx: number, patch: Partial<WebhookHeader>) => {
        setDraft((prev) => ({
            ...prev,
            Headers: prev.Headers.map((h, i) => (i === idx ? { ...h, ...patch } : h)),
        }));
    };

    const addHeader = () => {
        setDraft((prev) => ({
            ...prev,
            Headers: [...prev.Headers, { Name: "", Value: "" }],
        }));
    };

    const removeHeader = (idx: number) => {
        setDraft((prev) => ({
            ...prev,
            Headers: prev.Headers.filter((_, i) => i !== idx),
        }));
    };

    const handleSave = () => {
        const saved = saveWebhookConfig(draft);
        setDraft(saved);
        toast.success("Webhook settings saved");
        onOpenChange(false);
    };

    const handleTest = async () => {
        const cfgToUse = saveWebhookConfig({ ...draft, Enabled: true });
        setDraft(cfgToUse);
        if (cfgToUse.Url.trim().length === 0) {
            toast.error("Add a URL before sending a test ping");
            return;
        }
        setBusy(true);
        const result = await dispatchWebhook(
            "GroupRunSucceeded",
            {
                ProjectId: 0,
                GroupId: 0,
                GroupName: "Webhook Test Ping",
                DurationMs: 0,
                StepsExecuted: 0,
                Outcome: "Succeeded",
                IsTest: true,
            },
            { config: cfgToUse },
        );
        setBusy(false);
        setLog(getDeliveryLog());
        if (isWebhookSkipped(result)) {
            toast.warning(`Skipped: ${result.SkipReason}`);
        } else if (isWebhookSuccess(result)) {
            toast.success(`Webhook reached endpoint (HTTP ${result.Status})`);
        } else {
            toast.error(`Webhook failed: ${result.Error}`);
        }
    };

    const handleClearLog = () => {
        clearDeliveryLog();
        setLog([]);
        setExpandedIdx(null);
        setPayloadOpenIdx(null);
    };

    const refreshLog = () => {
        setLog(getDeliveryLog());
    };

    const corruptCount = useMemo(
        () => log.reduce((acc, entry) => acc + (isCorruptPlaceholder(entry) ? 1 : 0), 0),
        [log],
    );

    const handleRepair = () => {
        setRepairBusy(true);
        try {
            const report = repairDeliveryLog();
            setLog(getDeliveryLog());
            setExpandedIdx(null);
            setPayloadOpenIdx(null);

            if (report.Removed === 0 && report.Errors.length === 0) {
                toast.success("No corrupted entries found — log is clean");
            } else if (report.Removed === 0 && report.Errors.length > 0) {
                // Storage-level corruption (unparsable JSON / wrong shape) — key was reset
                toast.success(`Reset corrupted webhook log storage (${report.Errors[0]})`);
            } else {
                toast.success(
                    `Repaired webhook log — removed ${report.Removed} corrupted entr${report.Removed === 1 ? "y" : "ies"}, kept ${report.Kept}`,
                );
            }
        } catch (err) {
            toast.error(`Repair failed: ${err instanceof Error ? err.message : String(err)}`);
        } finally {
            setRepairBusy(false);
            setRepairConfirmOpen(false);
        }
    };

    return (
        <>
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Webhook className="h-4 w-4" />
                        Result webhook
                    </DialogTitle>
                    <DialogDescription>
                        Send group-run, batch-run, and recording results to an external HTTP endpoint
                        as JSON. Leave disabled to opt out entirely.
                    </DialogDescription>
                </DialogHeader>

                <ScrollArea className="max-h-[60vh] pr-3">
                    <div className="space-y-5">
                        {/* Enable + URL + timeout */}
                        <section className="space-y-3 rounded-md border p-3">
                            <div className="flex items-center justify-between">
                                <Label htmlFor="hook-enabled" className="text-sm font-medium">
                                    Send results to webhook
                                </Label>
                                <Switch
                                    id="hook-enabled"
                                    checked={draft.Enabled}
                                    onCheckedChange={(v) => setDraft((p) => ({ ...p, Enabled: v }))}
                                />
                            </div>
                            <div className="space-y-1.5">
                                <Label htmlFor="hook-url" className="text-xs text-muted-foreground">
                                    Endpoint URL — supports {"{{GroupId}}"}, {"{{GroupName}}"}, {"{{Event}}"} tokens
                                </Label>
                                <Input
                                    id="hook-url"
                                    type="url"
                                    placeholder="https://example.com/webhooks/marco"
                                    value={draft.Url}
                                    onChange={(e) => setDraft((p) => ({ ...p, Url: e.target.value }))}
                                />
                            </div>
                            <div className="space-y-1.5">
                                <Label htmlFor="hook-timeout" className="text-xs text-muted-foreground">
                                    Timeout (ms, 1 000 – 60 000)
                                </Label>
                                <Input
                                    id="hook-timeout"
                                    type="number"
                                    min={1000}
                                    max={60000}
                                    step={500}
                                    value={draft.TimeoutMs}
                                    onChange={(e) => setDraft((p) => ({
                                        ...p,
                                        TimeoutMs: Number.parseInt(e.target.value, 10) || p.TimeoutMs,
                                    }))}
                                />
                            </div>
                        </section>

                        {/* Headers */}
                        <section className="space-y-2 rounded-md border p-3">
                            <div className="flex items-center justify-between">
                                <Label className="text-sm font-medium">Custom headers</Label>
                                <Button size="sm" variant="outline" onClick={addHeader}>
                                    <Plus className="mr-1 h-3.5 w-3.5" />
                                    Add header
                                </Button>
                            </div>
                            {draft.Headers.length === 0 ? (
                                <p className="text-xs text-muted-foreground">
                                    No custom headers. Add one for bearer tokens, signing keys, etc.
                                </p>
                            ) : (
                                <div className="space-y-2">
                                    {draft.Headers.map((h, i) => (
                                        <div key={i} className="flex items-center gap-2">
                                            <Input
                                                placeholder="Header name"
                                                value={h.Name}
                                                onChange={(e) => updateHeader(i, { Name: e.target.value })}
                                                className="flex-1"
                                            />
                                            <Input
                                                placeholder="Header value"
                                                value={h.Value}
                                                onChange={(e) => updateHeader(i, { Value: e.target.value })}
                                                className="flex-[2]"
                                            />
                                            <Button
                                                size="icon"
                                                variant="ghost"
                                                onClick={() => removeHeader(i)}
                                                aria-label={`Remove header ${h.Name || i + 1}`}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </section>

                        {/* Events */}
                        <section className="space-y-2 rounded-md border p-3">
                            <Label className="text-sm font-medium">Send on these events</Label>
                            <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                                {ALL_WEBHOOK_EVENTS.map((kind) => (
                                    <label
                                        key={kind}
                                        className="flex cursor-pointer items-center gap-2 rounded-md border bg-muted/30 px-2 py-1.5 text-sm"
                                    >
                                        <Checkbox
                                            checked={eventSet.has(kind)}
                                            onCheckedChange={(v) => toggleEvent(kind, v === true)}
                                        />
                                        <span className="truncate">{EVENT_LABELS[kind]}</span>
                                    </label>
                                ))}
                            </div>
                            {draft.Events.length === 0 && (
                                <p className="text-xs text-destructive">
                                    No events selected — webhook will never fire.
                                </p>
                            )}
                        </section>

                        {/* Delivery log */}
                        <section className="space-y-2 rounded-md border p-3">
                            <div className="flex items-center justify-between">
                                <Label className="text-sm font-medium">
                                    Recent deliveries
                                    <span className="ml-1.5 text-xs font-normal text-muted-foreground">
                                        ({log.length}/20)
                                    </span>
                                </Label>
                                <div className="flex items-center gap-2">
                                    <Button size="sm" variant="ghost" onClick={refreshLog} title="Refresh log">
                                        <RefreshCw className="h-3.5 w-3.5" />
                                    </Button>
                                    <Button size="sm" variant="outline" onClick={handleTest} disabled={busy}>
                                        <Send className="mr-1 h-3.5 w-3.5" />
                                        {busy ? "Sending…" : "Send test ping"}
                                    </Button>
                                    {corruptCount > 0 && (
                                        <Button
                                            size="sm"
                                            variant="outline"
                                            onClick={() => setRepairConfirmOpen(true)}
                                            disabled={repairBusy}
                                            title={`Remove ${corruptCount} corrupted entr${corruptCount === 1 ? "y" : "ies"} from the log`}
                                            className="border-destructive/60 text-destructive hover:bg-destructive/10"
                                        >
                                            <Wrench className="mr-1 h-3.5 w-3.5" />
                                            {repairBusy ? "Repairing…" : `Repair (${corruptCount})`}
                                        </Button>
                                    )}
                                    {log.length > 0 && (
                                        <DropdownMenu>
                                            <DropdownMenuTrigger asChild>
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    disabled={filteredLog.length === 0}
                                                    title="Export filtered results"
                                                >
                                                    <Download className="mr-1 h-3.5 w-3.5" />
                                                    Export ({filteredLog.length})
                                                </Button>
                                            </DropdownMenuTrigger>
                                            <DropdownMenuContent align="end" className="text-xs">
                                                <DropdownMenuItem onSelect={() => exportFilteredLog(filteredLog, "json")}>
                                                    Download as JSON
                                                </DropdownMenuItem>
                                                <DropdownMenuItem onSelect={() => exportFilteredLog(filteredLog, "csv")}>
                                                    Download as CSV
                                                </DropdownMenuItem>
                                            </DropdownMenuContent>
                                        </DropdownMenu>
                                    )}
                                    {log.length > 0 && (
                                        <Button size="sm" variant="ghost" onClick={handleClearLog}>
                                            Clear
                                        </Button>
                                    )}
                                </div>
                            </div>
                            {log.length > 0 && (
                                <div className="relative">
                                    <Search className="pointer-events-none absolute left-2 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" aria-hidden />
                                    <Input
                                        type="search"
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        placeholder="Filter by event, time, or status…"
                                        aria-label="Filter webhook deliveries by event, emitted time, or status"
                                        className="h-8 pl-7 pr-7 text-xs"
                                    />
                                    {searchQuery.length > 0 && (
                                        <button
                                            type="button"
                                            onClick={() => setSearchQuery("")}
                                            aria-label="Clear search"
                                            className="absolute right-2 top-1/2 -translate-y-1/2 rounded-sm p-0.5 text-muted-foreground hover:text-foreground"
                                        >
                                            <X className="h-3.5 w-3.5" />
                                        </button>
                                    )}
                                </div>
                            )}
                            {log.length > 0 && (
                                <div className="flex flex-wrap items-center gap-1.5" role="group" aria-label="Filter deliveries by status">
                                    {([
                                        { key: "all", label: "All", count: logCounts.all, activeClass: "bg-foreground text-background border-foreground" },
                                        { key: "success", label: "OK", count: logCounts.success, activeClass: "bg-emerald-500/20 text-emerald-300 border-emerald-500/60" },
                                        { key: "skipped", label: "Skipped", count: logCounts.skipped, activeClass: "bg-muted text-foreground border-muted-foreground/60" },
                                        { key: "failure", label: "Failed", count: logCounts.failure, activeClass: "bg-destructive/20 text-destructive border-destructive/60" },
                                    ] as const).map((chip) => {
                                        const active = statusFilter === chip.key;
                                        const disabled = chip.key !== "all" && chip.count === 0;
                                        return (
                                            <button
                                                key={chip.key}
                                                type="button"
                                                onClick={() => setStatusFilter(chip.key)}
                                                disabled={disabled}
                                                aria-pressed={active}
                                                className={`inline-flex items-center gap-1 rounded-full border px-2.5 py-0.5 text-[11px] font-medium transition-colors disabled:opacity-40 disabled:cursor-not-allowed ${active ? chip.activeClass : "border-border bg-transparent text-muted-foreground hover:bg-muted/40"}`}
                                            >
                                                {chip.label}
                                                <span className={`rounded-full px-1 text-[10px] ${active ? "bg-background/30" : "bg-muted/60"}`}>
                                                    {chip.count}
                                                </span>
                                            </button>
                                        );
                                    })}
                                </div>
                            )}
                            {log.length === 0 ? (
                                <div className="flex flex-col items-center justify-center gap-2 rounded-md border border-dashed border-muted-foreground/30 bg-muted/10 px-4 py-6 text-center">
                                    <Webhook className="h-6 w-6 text-muted-foreground/60" aria-hidden />
                                    <p className="text-sm font-medium text-foreground">No deliveries yet</p>
                                    <p className="text-xs text-muted-foreground max-w-xs">
                                        {draft.Enabled && draft.Url.trim().length > 0
                                            ? "The last 20 webhook attempts will appear here, newest first. Use \"Send test ping\" to verify your endpoint."
                                            : "Enable the webhook and set an endpoint URL above, then run a group or use \"Send test ping\" to see delivery results here."}
                                    </p>
                                </div>
                            ) : filteredLog.length === 0 ? (
                                <p className="rounded-md border border-dashed border-muted-foreground/30 bg-muted/10 px-3 py-4 text-center text-xs text-muted-foreground">
                                    {searchQuery.trim().length > 0
                                        ? <>No deliveries match search “{searchQuery}”{statusFilter !== "all" ? <> in “{statusFilter}”</> : null}. </>
                                        : <>No deliveries match the “{statusFilter}” filter. </>}
                                    <button
                                        type="button"
                                        className="underline underline-offset-2 hover:text-foreground"
                                        onClick={() => { setStatusFilter("all"); setSearchQuery(""); }}
                                    >
                                        Show all
                                    </button>
                                </p>
                            ) : (
                                <ul className="space-y-1.5">
                                    {filteredLog.map((entry, i) => {
                                        const presentation = presentVariant(entry);
                                        const hasSummaryDetail = presentation.summaryDetail !== null;
                                        // Every entry has at least Event/Emitted/Duration + a status block
                                        // (HTTP status for success, SkipReason for skipped, Error for failure),
                                        // so all rows are clickable to reveal the detail panel.
                                        const isExpandable = true;
                                        const isOpen = expandedIdx === i;
                                        return (
                                            <li
                                                key={`${entry.EmittedAt}-${i}`}
                                                className={presentation.rowClass}
                                            >
                                                <button
                                                    type="button"
                                                    className={`flex w-full items-center justify-between gap-2 px-2 py-1.5 text-left ${presentation.hoverClass}`}
                                                    onClick={() => isExpandable && setExpandedIdx(isOpen ? null : i)}
                                                    aria-expanded={isOpen}
                                                    aria-controls={`hook-log-detail-${i}`}
                                                    disabled={!isExpandable}
                                                >
                                                    <div className="flex min-w-0 items-center gap-2">
                                                        <Badge
                                                            variant={presentation.badgeVariant}
                                                            className={`shrink-0 ${presentation.badgeExtraClass}`}
                                                        >
                                                            {presentation.badgeLabel}
                                                        </Badge>
                                                        <span className={`shrink-0 font-mono ${presentation.eventClass}`}>{entry.Event}</span>
                                                        {hasSummaryDetail && (
                                                            <span className={`truncate ${presentation.summaryDetailClass}`}>
                                                                — {presentation.summaryDetail}
                                                            </span>
                                                        )}
                                                    </div>
                                                    <span className="flex shrink-0 items-center gap-1 text-muted-foreground">
                                                        <span>{formatTime(entry.EmittedAt)} · {entry.DurationMs} ms</span>
                                                        {isExpandable && (
                                                            <ChevronDown
                                                                className={`h-3.5 w-3.5 transition-transform ${isOpen ? "rotate-180" : ""}`}
                                                            />
                                                        )}
                                                    </span>
                                                </button>
                                                {isOpen && isExpandable && (
                                                    <div
                                                        id={`hook-log-detail-${i}`}
                                                        className="border-t px-2 py-1.5"
                                                    >
                                                        <dl className="grid grid-cols-[auto_1fr] gap-x-3 gap-y-1 text-[11px]">
                                                            <dt className="text-muted-foreground">Emitted</dt>
                                                            <dd className="font-mono">{entry.EmittedAt}</dd>
                                                            <dt className="text-muted-foreground">Duration</dt>
                                                            <dd className="font-mono">{entry.DurationMs} ms</dd>
                                                            {/* Consistent "HTTP <status>" row across all variants. Skipped entries
                                                                have no Status; failures may have null. Variant guards drive null handling. */}
                                                            {(() => {
                                                                let httpText: string;
                                                                let httpClass = "font-mono";
                                                                if (isWebhookSuccess(entry)) {
                                                                    httpText = `${entry.Status}`;
                                                                } else if (isWebhookSkipped(entry)) {
                                                                    httpText = "— (not sent)";
                                                                    httpClass = "font-mono text-muted-foreground";
                                                                } else if (isWebhookFailure(entry)) {
                                                                    httpText = entry.Status !== null ? `${entry.Status}` : "— (no response)";
                                                                    httpClass = entry.Status !== null
                                                                        ? "font-mono text-destructive"
                                                                        : "font-mono text-muted-foreground";
                                                                } else {
                                                                    httpText = "—";
                                                                    httpClass = "font-mono text-muted-foreground";
                                                                }
                                                                return (
                                                                    <>
                                                                        <dt className="text-muted-foreground">HTTP</dt>
                                                                        <dd className={httpClass}>{httpText}</dd>
                                                                    </>
                                                                );
                                                            })()}
                                                            {isWebhookSkipped(entry) && (
                                                                <>
                                                                    <dt className="text-muted-foreground">Skip reason</dt>
                                                                    <dd className="whitespace-pre-wrap break-words font-mono">
                                                                        {entry.SkipReason && entry.SkipReason.length > 0
                                                                            ? entry.SkipReason
                                                                            : "(no reason recorded)"}
                                                                    </dd>
                                                                </>
                                                            )}
                                                            {isWebhookFailure(entry) && (
                                                                <>
                                                                    <dt className="text-muted-foreground">Error</dt>
                                                                    <dd className="whitespace-pre-wrap break-words font-mono text-destructive">
                                                                        {entry.Error && entry.Error.length > 0
                                                                            ? entry.Error
                                                                            : "(no error message)"}
                                                                    </dd>
                                                                </>
                                                            )}
                                                        </dl>
                                                        {(() => {
                                                            const payloadJson = formatPayloadJson(entry);
                                                            const payloadOpen = payloadOpenIdx === i;
                                                            return (
                                                                <div className="mt-2 space-y-2">
                                                                    <div className="flex items-center justify-between gap-2">
                                                                        <button
                                                                            type="button"
                                                                            className="flex items-center gap-1 text-[11px] text-muted-foreground hover:text-foreground disabled:opacity-50"
                                                                            onClick={() => setPayloadOpenIdx(payloadOpen ? null : i)}
                                                                            disabled={payloadJson === null}
                                                                            aria-expanded={payloadOpen}
                                                                            aria-controls={`hook-log-payload-${i}`}
                                                                        >
                                                                            <ChevronDown
                                                                                className={`h-3 w-3 transition-transform ${payloadOpen ? "rotate-180" : ""}`}
                                                                            />
                                                                            {payloadJson === null
                                                                                ? "Raw JSON payload (not captured)"
                                                                                : payloadOpen ? "Hide raw JSON payload" : "Show raw JSON payload"}
                                                                        </button>
                                                                        <Button
                                                                            size="sm"
                                                                            variant="outline"
                                                                            onClick={() => void copyLogEntry(entry)}
                                                                        >
                                                                            <Copy className="mr-1 h-3.5 w-3.5" />
                                                                            Copy details
                                                                        </Button>
                                                                    </div>
                                                                    {payloadOpen && payloadJson !== null && (
                                                                        <pre
                                                                            id={`hook-log-payload-${i}`}
                                                                            className="max-h-64 overflow-auto rounded-md border bg-background/60 p-2 text-[11px] font-mono whitespace-pre-wrap break-words"
                                                                        >
                                                                            {payloadJson}
                                                                        </pre>
                                                                    )}
                                                                </div>
                                                            );
                                                        })()}
                                                    </div>
                                                )}
                                            </li>
                                        );
                                    })}
                                </ul>
                            )}
                        </section>
                    </div>
                </ScrollArea>

                <DialogFooter>
                    <Button variant="ghost" onClick={() => onOpenChange(false)}>Cancel</Button>
                    <Button onClick={handleSave}>Save settings</Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>

        <AlertDialog open={repairConfirmOpen} onOpenChange={setRepairConfirmOpen}>
            <AlertDialogContent>
                <AlertDialogHeader>
                    <AlertDialogTitle className="flex items-center gap-2">
                        <Wrench className="h-4 w-4 text-destructive" />
                        Repair corrupted webhook log?
                    </AlertDialogTitle>
                    <AlertDialogDescription asChild>
                        <div className="space-y-2 text-sm">
                            <p>
                                This will scan the locally stored webhook delivery log and
                                permanently remove every entry that fails validation
                                (missing/wrong fields, unparsable JSON, or wrong shape).
                            </p>
                            <p>
                                <span className="font-semibold text-destructive">{corruptCount}</span>{" "}
                                corrupted entr{corruptCount === 1 ? "y" : "ies"} will be removed.
                                Valid history is preserved.
                            </p>
                            <p className="text-xs text-muted-foreground">
                                This action cannot be undone.
                            </p>
                        </div>
                    </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                    <AlertDialogCancel disabled={repairBusy}>Cancel</AlertDialogCancel>
                    <AlertDialogAction
                        onClick={(e) => {
                            e.preventDefault();
                            handleRepair();
                        }}
                        disabled={repairBusy}
                        className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                    >
                        {repairBusy ? "Repairing…" : "Repair log"}
                    </AlertDialogAction>
                </AlertDialogFooter>
            </AlertDialogContent>
        </AlertDialog>
        </>
    );
}

/**
 * Extracted from ProjectDetailView.tsx (PERF-R1) — Injection Order Preview.
 *
 * Computes and renders the deterministic Global → Dependencies → Project
 * script execution order for a single StoredProject.
 */
import { useMemo, useState } from "react";
import {
  ChevronDown,
  ChevronRight,
  ListOrdered,
  ArrowDown,
  Globe,
  Link,
  FileCode,
} from "lucide-react";
import type { StoredProject } from "@/hooks/use-projects-scripts";

export interface InjectionOrderPreviewProps {
  project: StoredProject;
  allProjects: StoredProject[];
  globalProjects: StoredProject[];
  deps: Array<{ projectId: string; version: string }>;
  isGlobal: boolean;
}

interface OrderEntry {
  step: number;
  label: string;
  scriptName: string;
  stage: "global" | "dependency" | "project";
  projectName: string;
  isEnabled: boolean;
  order: number;
}

// eslint-disable-next-line max-lines-per-function
export function InjectionOrderPreview({ project, allProjects, globalProjects, deps, isGlobal }: InjectionOrderPreviewProps) {
  const [expanded, setExpanded] = useState(true);

  // eslint-disable-next-line max-lines-per-function
  const entries = useMemo(() => {
    const result: OrderEntry[] = [];
    let step = 1;

    if (!isGlobal) {
      for (const gp of globalProjects) {
        const scripts = gp.scripts ?? [];
        if (scripts.length === 0) {
          result.push({ step: step++, label: "SDK Init", scriptName: gp.name, stage: "global", projectName: gp.name, isEnabled: true, order: -1000 });
        } else {
          for (const s of scripts) {
            result.push({ step: step++, label: s.path.split("/").pop() ?? s.path, scriptName: s.path, stage: "global", projectName: gp.name, isEnabled: true, order: s.order });
          }
        }
      }
    }

    const visited = new Set<string>();
    const collectDeps = (depList: Array<{ projectId: string; version: string }>) => {
      for (const dep of depList) {
        if (visited.has(dep.projectId)) continue;
        visited.add(dep.projectId);
        const depProject = allProjects.find((p) => p.id === dep.projectId);
        if (!depProject) continue;
        if (depProject.isGlobal) continue;
        if (depProject.dependencies?.length) {
          collectDeps(depProject.dependencies);
        }
        const scripts = depProject.scripts ?? [];
        if (scripts.length === 0) {
          result.push({ step: step++, label: depProject.name, scriptName: depProject.name, stage: "dependency", projectName: depProject.name, isEnabled: true, order: -500 });
        } else {
          for (const s of scripts) {
            result.push({ step: step++, label: s.path.split("/").pop() ?? s.path, scriptName: s.path, stage: "dependency", projectName: depProject.name, isEnabled: true, order: s.order });
          }
        }
      }
    };
    collectDeps(deps);

    for (const s of project.scripts ?? []) {
      result.push({ step: step++, label: s.path.split("/").pop() ?? s.path, scriptName: s.path, stage: "project", projectName: project.name, isEnabled: true, order: s.order });
    }

    return result;
  }, [project, allProjects, globalProjects, deps, isGlobal]);

  if (entries.length === 0) {
    return (
      <div className="rounded-md bg-muted/30 p-2.5">
        <p className="text-[10px] text-muted-foreground">
          <strong>Injection order:</strong> No scripts configured.
        </p>
      </div>
    );
  }

  const stageColor = (stage: OrderEntry["stage"]) => {
    switch (stage) {
      case "global": return "bg-primary/10 text-primary border-primary/30";
      case "dependency": return "bg-accent/50 text-accent-foreground border-accent/30";
      case "project": return "bg-[hsl(var(--success))]/10 text-[hsl(var(--success))] border-[hsl(var(--success))]/30";
    }
  };

  const stageLabel = (stage: OrderEntry["stage"]) => {
    switch (stage) {
      case "global": return "Global";
      case "dependency": return "Dep";
      case "project": return "Main";
    }
  };

  const stageIcon = (stage: OrderEntry["stage"]) => {
    switch (stage) {
      case "global": return Globe;
      case "dependency": return Link;
      case "project": return FileCode;
    }
  };

  return (
    <div className="rounded-md border border-border bg-muted/10 overflow-hidden">
      <button
        onClick={() => setExpanded(!expanded)}
        className="w-full flex items-center gap-2 px-3 py-2 text-left hover:bg-muted/30 transition-colors"
      >
        {expanded ? (
          <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" />
        ) : (
          <ChevronRight className="h-3.5 w-3.5 text-muted-foreground" />
        )}
        <ListOrdered className="h-3.5 w-3.5 text-primary" />
        <span className="text-[11px] font-bold text-foreground">Injection Order Preview</span>
        <span className="text-[10px] font-mono text-muted-foreground ml-auto">{entries.length} script{entries.length !== 1 ? "s" : ""}</span>
      </button>

      {expanded && (
        <div className="border-t border-border">
          <div className="flex items-center gap-3 px-3 py-1.5 bg-muted/20 border-b border-border">
            <span className="text-[9px] font-medium text-muted-foreground uppercase tracking-wider">Stages:</span>
            {(["global", "dependency", "project"] as const).map((stage) => {
              const count = entries.filter((e) => e.stage === stage).length;
              if (count === 0) return null;
              const Icon = stageIcon(stage);
              return (
                <span key={stage} className={`inline-flex items-center gap-1 text-[9px] font-medium px-1.5 py-0.5 rounded-full border ${stageColor(stage)}`}>
                  <Icon className="h-2.5 w-2.5" />
                  {stageLabel(stage)} ({count})
                </span>
              );
            })}
          </div>

          <div className="divide-y divide-border/50">
            {entries.map((entry, i) => {
              const Icon = stageIcon(entry.stage);
              const showStageDivider = i > 0 && entries[i - 1].stage !== entry.stage;

              return (
                <div key={`${entry.stage}-${entry.scriptName}-${i}`}>
                  {showStageDivider && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-muted/30">
                      <ArrowDown className="h-2.5 w-2.5 text-muted-foreground" />
                      <span className="text-[9px] font-medium text-muted-foreground uppercase tracking-wider">
                        {entry.stage === "dependency" ? "Dependencies" : entry.stage === "project" ? "Project Scripts" : "Global"}
                      </span>
                    </div>
                  )}
                  <div className="flex items-center gap-2 px-3 py-1.5 hover:bg-muted/20 transition-colors">
                    <span className="text-[10px] font-mono text-muted-foreground w-5 text-right shrink-0">
                      {entry.step}.
                    </span>

                    <div className="relative flex items-center justify-center w-4 shrink-0">
                      <div className={`h-2.5 w-2.5 rounded-full border-2 ${
                        entry.stage === "global"
                          ? "border-primary bg-primary/20"
                          : entry.stage === "dependency"
                            ? "border-accent-foreground/50 bg-accent/30"
                            : "border-[hsl(var(--success))] bg-[hsl(var(--success))]/20"
                      }`} />
                      {i < entries.length - 1 && (
                        <div className="absolute top-full left-1/2 -translate-x-1/2 w-px h-3 bg-border" />
                      )}
                    </div>

                    <span className={`inline-flex items-center gap-0.5 text-[9px] font-medium px-1.5 py-0.5 rounded border shrink-0 ${stageColor(entry.stage)}`}>
                      <Icon className="h-2.5 w-2.5" />
                      {stageLabel(entry.stage)}
                    </span>

                    <span className="text-[11px] font-mono text-foreground truncate min-w-0">
                      {entry.label}
                    </span>

                    {entry.stage !== "project" && (
                      <span className="text-[9px] text-muted-foreground truncate ml-auto shrink-0">
                        from {entry.projectName}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          <div className="px-3 py-1.5 bg-muted/20 border-t border-border">
            <p className="text-[9px] text-muted-foreground">
              {isGlobal
                ? "⚡ This is a global project — auto-injected before any matched project."
                : "Injection order: Global → Dependencies (topological) → Project scripts. Each script runs in sequence."}
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * Marco Extension — Recorder Empty State
 *
 * Rendered inside RecorderVisualisationPanel when the active project has
 * zero captured steps. Surfaces the most common root causes with a quick
 * remediation action for each so users aren't stuck staring at a blank tab.
 */

import { AlertCircle, CheckCircle2, Circle, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";

export type CauseStatus = "ok" | "warn" | "error";

export interface RecorderEmptyStateProps {
    readonly projectSlug: string;
    readonly hasDbError: boolean;
    readonly onReload: () => void;
}

interface CauseRow {
    readonly title: string;
    readonly detail: string;
    readonly status: CauseStatus;
    readonly action?: { label: string; onClick: () => void };
}

export function RecorderEmptyState({
    projectSlug,
    hasDbError,
    onReload,
}: RecorderEmptyStateProps): JSX.Element {
    const projectMissing = projectSlug.trim().length === 0;

    const causes: ReadonlyArray<CauseRow> = [
        {
            title: "Project selected",
            detail: projectMissing
                ? "No ProjectSlug is active. Steps cannot be saved without a project."
                : `Active project: ${projectSlug}`,
            status: projectMissing ? "error" : "ok",
        },
        {
            title: "Recorder database initialized",
            detail: hasDbError
                ? "The recorder DB failed to load. Reload to re-initialize the SQLite store."
                : "Recorder DB responded successfully.",
            status: hasDbError ? "error" : "ok",
            action: hasDbError
                ? { label: "Reload data", onClick: onReload }
                : undefined,
        },
        {
            title: "Recording session is active",
            detail:
                "Open any tab and click Start on the floating Marco toolbar (top-right). " +
                "Keyboard: Ctrl+Alt+P resume · Ctrl+Alt+; pause · Ctrl+Alt+. stop.",
            status: "warn",
        },
    ];

    return (
        <div className="border border-border rounded-md bg-card/50 p-6 space-y-4">
            <div className="flex items-start gap-3">
                <AlertCircle className="h-5 w-5 text-amber-500 shrink-0 mt-0.5" />
                <div>
                    <h3 className="text-sm font-semibold">No steps recorded yet</h3>
                    <p className="text-xs text-muted-foreground mt-1">
                        This project has no captured steps. The most likely causes are listed below.
                    </p>
                </div>
            </div>

            <ul className="space-y-2">
                {causes.map((c) => (
                    <li
                        key={c.title}
                        className="flex items-start gap-3 p-3 rounded-md border border-border/60 bg-background/40"
                    >
                        <CauseIcon status={c.status} />
                        <div className="flex-1 min-w-0">
                            <div className="text-xs font-medium">{c.title}</div>
                            <div className="text-xs text-muted-foreground mt-0.5">{c.detail}</div>
                        </div>
                        {c.action !== undefined && (
                            <Button
                                size="sm"
                                variant="outline"
                                className="h-7 gap-1.5 shrink-0"
                                onClick={c.action.onClick}
                            >
                                <RefreshCw className="h-3 w-3" />
                                {c.action.label}
                            </Button>
                        )}
                    </li>
                ))}
            </ul>
        </div>
    );
}

function CauseIcon({ status }: { status: CauseStatus }): JSX.Element {
    if (status === "ok") {
        return <CheckCircle2 className="h-4 w-4 text-emerald-500 shrink-0 mt-0.5" />;
    }
    if (status === "error") {
        return <AlertCircle className="h-4 w-4 text-destructive shrink-0 mt-0.5" />;
    }
    return <Circle className="h-4 w-4 text-amber-500 shrink-0 mt-0.5" />;
}

/**
 * Marco Extension — Recorder Step Detail (Phase 10 + 14)
 *
 * Right-pane detail view for one selected Step:
 *   - Variable rename (PascalCase free-text, server enforces uniqueness)
 *   - Description / tag chips / cross-project links (Phase 14)
 *   - Persisted Selector rows (primary highlighted)
 *   - Bound DataSource column (if any)
 *
 * All edits route to handlers passed by `RecorderVisualisationPanel`, which
 * in turn use the hook's local-state splice helpers — so the row re-renders
 * with the latest Description, tags, and link targets without a full reload.
 */

import { useEffect, useState } from "react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { X } from "lucide-react";
import type {
    StepRow,
    SelectorRow,
    DataSourceRow,
    FieldBindingRow,
    StepLinkSlot,
} from "@/hooks/use-recorder-project-data";

const SELECTOR_KIND_LABEL: Record<number, string> = {
    1: "XPathFull",
    2: "XPathRelative",
    3: "Css",
    4: "Aria",
};

interface Props {
    step: StepRow;
    selectors: ReadonlyArray<SelectorRow>;
    dataSources: ReadonlyArray<DataSourceRow>;
    bindings: ReadonlyArray<FieldBindingRow>;
    /** Cached tag list for this step (from the hook). */
    tags: ReadonlyArray<string>;
    onRename: (stepId: number, newName: string) => Promise<void>;
    onDescriptionSave: (stepId: number, description: string | null) => Promise<void>;
    onTagsSave: (stepId: number, tags: ReadonlyArray<string>) => Promise<void>;
    onLinkChange: (
        stepId: number,
        slot: StepLinkSlot,
        targetProjectSlug: string | null,
    ) => Promise<void>;
}

export function RecorderStepDetail({
    step,
    selectors,
    dataSources,
    bindings,
    tags,
    onRename,
    onDescriptionSave,
    onTagsSave,
    onLinkChange,
}: Props) {
    const [draftName, setDraftName] = useState(step.VariableName);
    const [renameError, setRenameError] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false);

    const [draftDesc, setDraftDesc] = useState(step.Description ?? "");
    const [descSaving, setDescSaving] = useState(false);
    const [descError, setDescError] = useState<string | null>(null);

    const [draftTag, setDraftTag] = useState("");
    const [tagsError, setTagsError] = useState<string | null>(null);

    const [linkError, setLinkError] = useState<string | null>(null);

    useEffect(() => {
        setDraftName(step.VariableName);
        setRenameError(null);
        setDraftDesc(step.Description ?? "");
        setDescError(null);
        setDraftTag("");
        setTagsError(null);
        setLinkError(null);
    }, [step.StepId, step.VariableName, step.Description]);

    const isDirty = draftName !== step.VariableName;
    const isDescDirty = draftDesc !== (step.Description ?? "");
    const binding = bindings.find((b) => b.StepId === step.StepId) ?? null;
    const boundDs = binding ? dataSources.find((d) => d.DataSourceId === binding.DataSourceId) : null;

    const handleSave = async () => {
        if (!isDirty) return;
        setIsSaving(true);
        setRenameError(null);
        try {
            await onRename(step.StepId, draftName.trim());
        } catch (err) {
            setRenameError(err instanceof Error ? err.message : String(err));
        } finally {
            setIsSaving(false);
        }
    };

    const handleDescSave = async () => {
        if (!isDescDirty) return;
        setDescSaving(true);
        setDescError(null);
        try {
            const trimmed = draftDesc.trim();
            await onDescriptionSave(step.StepId, trimmed.length === 0 ? null : trimmed);
        } catch (err) {
            setDescError(err instanceof Error ? err.message : String(err));
        } finally {
            setDescSaving(false);
        }
    };

    const handleAddTag = async () => {
        const next = draftTag.trim();
        if (next.length === 0) return;
        if (tags.includes(next)) {
            setDraftTag("");
            return;
        }
        setTagsError(null);
        try {
            await onTagsSave(step.StepId, [...tags, next]);
            setDraftTag("");
        } catch (err) {
            setTagsError(err instanceof Error ? err.message : String(err));
        }
    };

    const handleRemoveTag = async (name: string) => {
        setTagsError(null);
        try {
            await onTagsSave(step.StepId, tags.filter((t) => t !== name));
        } catch (err) {
            setTagsError(err instanceof Error ? err.message : String(err));
        }
    };

    const handleLinkSave = async (slot: StepLinkSlot, raw: string) => {
        setLinkError(null);
        try {
            const trimmed = raw.trim();
            await onLinkChange(step.StepId, slot, trimmed.length === 0 ? null : trimmed);
        } catch (err) {
            setLinkError(err instanceof Error ? err.message : String(err));
        }
    };

    return (
        <div className="space-y-4">
            {/* Identity */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Variable
                </h3>
                <div className="flex gap-2">
                    <Input
                        value={draftName}
                        onChange={(e) => setDraftName(e.target.value)}
                        className="font-mono text-sm h-8"
                    />
                    <Button size="sm" onClick={handleSave} disabled={!isDirty || isSaving}>
                        {isSaving ? "Saving…" : "Rename"}
                    </Button>
                </div>
                {renameError && (
                    <p className="text-xs text-destructive font-mono">{renameError}</p>
                )}
                <div className="text-[10px] text-muted-foreground font-mono">
                    StepId={step.StepId} • OrderIndex={step.OrderIndex} • Captured {step.CapturedAt}
                </div>
            </section>

            {/* Description (Phase 14) */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Description
                </h3>
                <Textarea
                    value={draftDesc}
                    onChange={(e) => setDraftDesc(e.target.value)}
                    rows={2}
                    placeholder="Optional notes about this step…"
                    className="text-xs"
                />
                <div className="flex items-center gap-2">
                    <Button
                        size="sm"
                        variant="outline"
                        onClick={handleDescSave}
                        disabled={!isDescDirty || descSaving}
                    >
                        {descSaving ? "Saving…" : "Save description"}
                    </Button>
                    {descError && (
                        <span className="text-xs text-destructive font-mono">{descError}</span>
                    )}
                </div>
            </section>

            {/* Tags (Phase 14) */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Tags ({tags.length})
                </h3>
                <div className="flex flex-wrap gap-1.5">
                    {tags.length === 0 && (
                        <span className="text-xs text-muted-foreground italic">No tags.</span>
                    )}
                    {tags.map((t) => (
                        <Badge
                            key={t}
                            variant="secondary"
                            className="gap-1 pl-2 pr-1 py-0.5 text-[10px] font-mono"
                        >
                            {t}
                            <button
                                type="button"
                                onClick={() => void handleRemoveTag(t)}
                                aria-label={`Remove tag ${t}`}
                                className="hover:text-destructive"
                            >
                                <X className="h-3 w-3" />
                            </button>
                        </Badge>
                    ))}
                </div>
                <div className="flex gap-2">
                    <Input
                        value={draftTag}
                        onChange={(e) => setDraftTag(e.target.value)}
                        onKeyDown={(e) => {
                            if (e.key === "Enter") {
                                e.preventDefault();
                                void handleAddTag();
                            }
                        }}
                        placeholder="Add tag…"
                        className="font-mono text-xs h-8"
                    />
                    <Button
                        size="sm"
                        variant="outline"
                        onClick={handleAddTag}
                        disabled={draftTag.trim().length === 0}
                    >
                        Add
                    </Button>
                </div>
                {tagsError && (
                    <p className="text-xs text-destructive font-mono">{tagsError}</p>
                )}
            </section>

            {/* Cross-project links (Phase 14) */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Cross-project links
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                    <LinkSlotEditor
                        label="On success → project"
                        initialValue={step.OnSuccessProjectId ?? ""}
                        onSave={(v) => handleLinkSave("OnSuccessProjectId", v)}
                    />
                    <LinkSlotEditor
                        label="On failure → project"
                        initialValue={step.OnFailureProjectId ?? ""}
                        onSave={(v) => handleLinkSave("OnFailureProjectId", v)}
                    />
                </div>
                {linkError && (
                    <p className="text-xs text-destructive font-mono">{linkError}</p>
                )}
            </section>

            {/* Selectors */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Selectors ({selectors.length})
                </h3>
                {selectors.length === 0 ? (
                    <p className="text-xs text-muted-foreground italic">No selectors persisted.</p>
                ) : (
                    <ul className="space-y-1.5">
                        {selectors.map((sel) => (
                            <li
                                key={sel.SelectorId}
                                className={`rounded-md border px-2.5 py-2 text-xs space-y-1 ${
                                    sel.IsPrimary === 1
                                        ? "border-primary/60 bg-primary/5"
                                        : "border-border bg-card"
                                }`}
                            >
                                <div className="flex items-center gap-2">
                                    <Badge variant="outline" className="text-[10px] py-0 px-1.5 font-mono">
                                        {SELECTOR_KIND_LABEL[sel.SelectorKindId] ?? `Kind${sel.SelectorKindId}`}
                                    </Badge>
                                    {sel.IsPrimary === 1 && (
                                        <Badge className="text-[10px] py-0 px-1.5 bg-primary text-primary-foreground">
                                            Primary
                                        </Badge>
                                    )}
                                    {sel.AnchorSelectorId !== null && (
                                        <span className="text-[10px] text-muted-foreground font-mono">
                                            anchor=#{sel.AnchorSelectorId}
                                        </span>
                                    )}
                                </div>
                                <code className="block font-mono text-[11px] break-all text-foreground/90">
                                    {sel.Expression}
                                </code>
                            </li>
                        ))}
                    </ul>
                )}
            </section>

            {/* Field binding */}
            <section className="space-y-2">
                <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Field Binding
                </h3>
                {binding === null ? (
                    <p className="text-xs text-muted-foreground italic">
                        No data-source column bound to this step.
                    </p>
                ) : (
                    <div className="rounded-md border border-border bg-card px-2.5 py-2 text-xs space-y-1">
                        <div className="font-mono">
                            <span className="text-primary">{`{{${binding.ColumnName}}}`}</span>{" "}
                            <span className="text-muted-foreground">→</span>{" "}
                            <span>{boundDs?.FilePath ?? `DataSourceId=${binding.DataSourceId}`}</span>
                        </div>
                        {boundDs && (
                            <div className="text-[10px] text-muted-foreground">
                                Columns: {boundDs.Columns.join(", ")} • Rows: {boundDs.RowCount}
                            </div>
                        )}
                    </div>
                )}
            </section>
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  LinkSlotEditor — small inline input for one cross-project slot     */
/* ------------------------------------------------------------------ */

interface LinkSlotEditorProps {
    label: string;
    initialValue: string;
    onSave: (value: string) => Promise<void>;
}

function LinkSlotEditor({ label, initialValue, onSave }: LinkSlotEditorProps) {
    const [draft, setDraft] = useState(initialValue);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        setDraft(initialValue);
    }, [initialValue]);

    const isDirty = draft !== initialValue;

    const handleClick = async () => {
        if (!isDirty) return;
        setSaving(true);
        try {
            await onSave(draft);
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="space-y-1">
            <label className="text-[10px] uppercase tracking-wide text-muted-foreground">
                {label}
            </label>
            <div className="flex gap-1.5">
                <Input
                    value={draft}
                    onChange={(e) => setDraft(e.target.value)}
                    placeholder="project-slug or empty"
                    className="font-mono text-xs h-8"
                />
                <Button
                    size="sm"
                    variant="outline"
                    onClick={handleClick}
                    disabled={!isDirty || saving}
                >
                    {saving ? "…" : "Save"}
                </Button>
            </div>
        </div>
    );
}

/**
 * Marco Extension — Recorder Step Graph (Phase 10)
 *
 * Left-rail vertical list of persisted Steps for one project, ordered by
 * `OrderIndex` ASC. Selecting a row notifies the parent which renders the
 * detail panel. Pure presentational — all data fetching lives in the
 * parent's `useRecorderProjectData` hook.
 */

import { useMemo } from "react";
import type { StepRow } from "@/hooks/use-recorder-project-data";
import { Button } from "@/components/ui/button";
import { ChevronRight, Trash2 } from "lucide-react";
import {
    buildExecutionNextPreview,
    type ProjectSummary,
    type StepLinks,
} from "@/background/recorder/execution-next-preview";
import { ExecutionNextBadge } from "@/components/recorder/ExecutionNextBadge";

const STEP_KIND_LABEL: Record<number, string> = {
    1: "Click",
    2: "Type",
    3: "Select",
    4: "JsInline",
    5: "Wait",
};

interface Props {
    steps: ReadonlyArray<StepRow>;
    selectedStepId: number | null;
    onSelect: (stepId: number) => void;
    onDelete: (stepId: number) => void;
    /** Optional cross-project links per StepId (Phase 14). */
    links?: ReadonlyMap<number, StepLinks>;
    /** Optional project lookup so links render the friendly name. */
    projects?: ReadonlyMap<string, ProjectSummary>;
}

export function RecorderStepGraph({ steps, selectedStepId, onSelect, onDelete, links, projects }: Props) {
    const previewByStepId = useMemo(() => {
        const list = buildExecutionNextPreview({
            steps: steps.map((s) => ({
                StepId: s.StepId,
                OrderIndex: s.OrderIndex,
                VariableName: s.VariableName,
                Label: s.Label,
            })),
            links,
            projects,
        });
        return new Map(list.map((p) => [p.StepId, p]));
    }, [steps, links, projects]);

    if (steps.length === 0) {
        return (
            <div className="text-xs text-muted-foreground p-4 border border-dashed border-border rounded-md">
                No recorded steps yet. Use the recorder shortcut
                (<kbd className="px-1 py-0.5 bg-muted rounded text-[10px]">Ctrl/Cmd+Shift+R</kbd>)
                to start capturing.
            </div>
        );
    }

    return (
        <ol className="space-y-1">
            {steps.map((step) => {
                const isSelected = step.StepId === selectedStepId;
                const preview = previewByStepId.get(step.StepId);
                return (
                    <li key={step.StepId}>
                        <div
                            className={`group flex items-center gap-2 rounded-md border px-2 py-1.5 text-xs transition-colors ${
                                isSelected
                                    ? "border-primary bg-primary/10"
                                    : "border-border bg-card hover:bg-primary/5"
                            }`}
                        >
                            <button
                                type="button"
                                onClick={() => onSelect(step.StepId)}
                                className="flex-1 flex items-center gap-2 text-left"
                            >
                                <span className="font-mono text-[10px] text-muted-foreground w-6 shrink-0">
                                    {step.OrderIndex}
                                </span>
                                <span className="font-mono text-primary shrink-0 w-16 truncate">
                                    {STEP_KIND_LABEL[step.StepKindId] ?? `Kind${step.StepKindId}`}
                                </span>
                                <span className="font-medium truncate">{step.VariableName}</span>
                                <span className="text-muted-foreground truncate">— {step.Label}</span>
                                <ChevronRight className="h-3 w-3 ml-auto shrink-0 text-muted-foreground" />
                            </button>
                            <Button
                                size="icon"
                                variant="ghost"
                                className="h-6 w-6 opacity-0 group-hover:opacity-100"
                                onClick={() => onDelete(step.StepId)}
                                title="Delete step"
                            >
                                <Trash2 className="h-3 w-3 text-destructive" />
                            </Button>
                        </div>
                        {preview !== undefined && <ExecutionNextBadge preview={preview} />}
                    </li>
                );
            })}
        </ol>
    );
}

/**
 * Marco Extension — Recorder Visualisation Panel (Phase 10)
 *
 * Project-scoped tab that visualises persisted Macro Recorder data:
 *   - Step graph (left rail) — ordered list of `Step` rows
 *   - Detail panel (right) — selectors, field binding, variable rename
 *   - Data Source summary chips
 *
 * All data flows through `useRecorderProjectData(projectSlug)` which calls
 * the existing `RECORDER_STEP_LIST`, `RECORDER_DATA_SOURCE_LIST`, and
 * `RECORDER_FIELD_BINDING_LIST` background handlers (Phases 07-09).
 *
 * @see spec/31-macro-recorder/10-project-visualisation.md
 */

import { useCallback, useEffect, useState } from "react";
import {
    useRecorderProjectData,
    type SelectorRow,
} from "@/hooks/use-recorder-project-data";
import { sendMessage } from "@/lib/message-client";
import { RecorderStepGraph } from "./RecorderStepGraph";
import { RecorderStepDetail } from "./RecorderStepDetail";
import { RecorderEmptyState } from "./RecorderEmptyState";
import { downloadRecorderExport, type ExportFormat } from "./recorder-export";
import { runRecorderSelfTest, RecorderSelfTestError } from "./recorder-self-test";
import { Loader2, Database, Download, FlaskConical } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { toast } from "sonner";
import { logError } from "../options-logger";

interface Props {
    projectSlug: string;
}

export default function RecorderVisualisationPanel({ projectSlug }: Props) {
    const {
        data,
        loading,
        error,
        reload,
        loadSelectors,
        tagsByStep,
        updateStepMeta,
        setStepTags,
        setStepLink,
    } = useRecorderProjectData(projectSlug);
    const [selectedStepId, setSelectedStepId] = useState<number | null>(null);
    const [selectors, setSelectors] = useState<ReadonlyArray<SelectorRow>>([]);
    const [selectorsLoading, setSelectorsLoading] = useState(false);
    const [selfTestRunning, setSelfTestRunning] = useState(false);

    const handleSelfTest = useCallback(async () => {
        setSelfTestRunning(true);
        try {
            const result = await runRecorderSelfTest(projectSlug);
            await reload();
            toast.success(
                `Self-test passed — wrote StepId ${result.InsertedStepId}, verified, cleaned up (${result.DurationMs}ms)`,
            );
        } catch (err) {
            const phase = err instanceof RecorderSelfTestError ? err.Phase : "unknown";
            const msg = err instanceof Error ? err.message : "Self-test failed";
            toast.error(`Recorder self-test failed (${phase}): ${msg}`);
            logError(
                "RecorderVisualisationPanel.selfTest",
                `runRecorderSelfTest failed at phase='${phase}' for project='${projectSlug}': ${msg}`,
                err,
            );
        } finally {
            setSelfTestRunning(false);
        }
    }, [projectSlug, reload]);

    /* Auto-select the first Step when data loads / refreshes. */
    useEffect(() => {
        if (data === null || data.steps.length === 0) {
            setSelectedStepId(null);
            return;
        }
        const stillExists = data.steps.some((s) => s.StepId === selectedStepId);
        if (!stillExists) {
            setSelectedStepId(data.steps[0].StepId);
        }
    }, [data, selectedStepId]);

    /* Refetch selectors whenever the active step changes. */
    useEffect(() => {
        if (selectedStepId === null) {
            setSelectors([]);
            return;
        }
        let cancelled = false;
        setSelectorsLoading(true);
        loadSelectors(selectedStepId)
            .then((rows) => {
                if (!cancelled) setSelectors(rows);
            })
            .finally(() => {
                if (!cancelled) setSelectorsLoading(false);
            });
        return () => { cancelled = true; };
    }, [selectedStepId, loadSelectors]);

    const handleRename = useCallback(
        async (stepId: number, newName: string) => {
            try {
                await sendMessage({
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    type: "RECORDER_STEP_RENAME" as any,
                    projectSlug,
                    stepId,
                    newVariableName: newName,
                });
                toast.success(`Renamed step #${stepId} → ${newName}`);
                await reload();
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Failed to rename step";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.rename",
                    `RECORDER_STEP_RENAME failed for project='${projectSlug}' stepId=${stepId} newName='${newName}': ${msg}`,
                    err,
                );
                throw err;
            }
        },
        [projectSlug, reload],
    );

    const handleDelete = useCallback(
        async (stepId: number) => {
            const confirmed = confirm(`Delete step #${stepId}? This cannot be undone.`);
            if (!confirmed) return;
            try {
                await sendMessage({
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    type: "RECORDER_STEP_DELETE" as any,
                    projectSlug,
                    stepId,
                });
                toast.success("Step deleted");
                await reload();
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Failed to delete step";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.delete",
                    `RECORDER_STEP_DELETE failed for project='${projectSlug}' stepId=${stepId}: ${msg}`,
                    err,
                );
            }
        },
        [projectSlug, reload],
    );

    /* -------- Phase 14 — meta / tags / link refreshers --------------- */

    const handleDescriptionSave = useCallback(
        async (stepId: number, description: string | null) => {
            try {
                await updateStepMeta(stepId, { Description: description });
                toast.success("Description updated");
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Failed to update description";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.description",
                    `updateStepMeta(Description) failed for project='${projectSlug}' stepId=${stepId}: ${msg}`,
                    err,
                );
                throw err;
            }
        },
        [projectSlug, updateStepMeta],
    );

    const handleTagsSave = useCallback(
        async (stepId: number, tags: ReadonlyArray<string>) => {
            try {
                await setStepTags(stepId, tags);
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Failed to update tags";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.tags",
                    `setStepTags failed for project='${projectSlug}' stepId=${stepId} tags=[${tags.join(",")}]: ${msg}`,
                    err,
                );
                throw err;
            }
        },
        [projectSlug, setStepTags],
    );

    const handleLinkChange = useCallback(
        async (
            stepId: number,
            slot: "OnSuccessProjectId" | "OnFailureProjectId",
            targetProjectSlug: string | null,
        ) => {
            try {
                await setStepLink(stepId, slot, targetProjectSlug);
                toast.success(
                    targetProjectSlug === null
                        ? `${slot} cleared`
                        : `${slot} → ${targetProjectSlug}`,
                );
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Failed to update link";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.link",
                    `setStepLink(${slot}=${targetProjectSlug ?? "null"}) failed for project='${projectSlug}' stepId=${stepId}: ${msg}`,
                    err,
                );
                throw err;
            }
        },
        [projectSlug, setStepLink],
    );

    /* Forward load failures into the global Error Drawer (once per error). */
    useEffect(() => {
        if (error === null) { return; }
        logError(
            "RecorderVisualisationPanel.load",
            `useRecorderProjectData failed for project='${projectSlug}': ${error}`,
        );
    }, [error, projectSlug]);

    const handleExport = useCallback(
        (format: ExportFormat) => {
            if (data === null) { return; }
            if (data.steps.length === 0) {
                toast.error("Nothing to export — no steps recorded yet.");
                return;
            }
            try {
                downloadRecorderExport({ projectSlug, data, tagsByStep }, format);
                toast.success(`Exported ${data.steps.length} step(s) as ${format.toUpperCase()}`);
            } catch (err) {
                const msg = err instanceof Error ? err.message : "Export failed";
                toast.error(msg);
                logError(
                    "RecorderVisualisationPanel.export",
                    `downloadRecorderExport(format='${format}') failed for project='${projectSlug}' steps=${data.steps.length}: ${msg}`,
                    err,
                );
            }
        },
        [data, projectSlug, tagsByStep],
    );
    if (loading) {
        return (
            <div className="flex items-center gap-2 text-xs text-muted-foreground p-4">
                <Loader2 className="h-4 w-4 animate-spin" /> Loading recorder data…
            </div>
        );
    }
    if (error) {
        return (
            <div className="space-y-3">
                <div className="text-xs text-destructive p-3 border border-destructive/40 rounded-md bg-destructive/5 font-mono">
                    {error}
                </div>
                <RecorderEmptyState
                    projectSlug={projectSlug}
                    hasDbError={true}
                    onReload={() => { void reload(); }}
                />
            </div>
        );
    }
    if (data === null) return null;

    const selectedStep = data.steps.find((s) => s.StepId === selectedStepId) ?? null;

    return (
        <div className="space-y-4">
            {/* Header: data sources summary + export */}
            <div className="flex flex-wrap items-center gap-2">
                <span className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                    Data Sources:
                </span>
                {data.dataSources.length === 0 ? (
                    <span className="text-xs text-muted-foreground italic">none attached</span>
                ) : (
                    data.dataSources.map((ds) => (
                        <Badge key={ds.DataSourceId} variant="outline" className="gap-1.5 font-mono text-[10px]">
                            <Database className="h-3 w-3" />
                            {ds.FilePath} · {ds.RowCount}r × {ds.Columns.length}c
                        </Badge>
                    ))
                )}
                <div className="ml-auto flex items-center gap-2">
                    <Button
                        variant="outline"
                        size="sm"
                        className="h-8 gap-1.5"
                        onClick={() => { void handleSelfTest(); }}
                        disabled={selfTestRunning}
                        title="Insert a dummy step, verify it appears, and clean it up. Failures land in the Error Drawer."
                    >
                        {selfTestRunning ? (
                            <Loader2 className="h-3.5 w-3.5 animate-spin" />
                        ) : (
                            <FlaskConical className="h-3.5 w-3.5" />
                        )}
                        Run self-test
                    </Button>
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button
                                variant="outline"
                                size="sm"
                                className="h-8 gap-1.5"
                                disabled={data.steps.length === 0}
                                title={
                                    data.steps.length === 0
                                        ? "Record at least one step before exporting"
                                        : `Export ${data.steps.length} step(s)`
                                }
                            >
                                <Download className="h-3.5 w-3.5" />
                                Export
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                            <DropdownMenuItem onClick={() => handleExport("json")}>
                                Download as JSON
                            </DropdownMenuItem>
                            <DropdownMenuItem onClick={() => handleExport("csv")}>
                                Download as CSV
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>
            </div>

            {/* Two-column layout — or empty-state when no steps recorded */}
            {data.steps.length === 0 ? (
                <RecorderEmptyState
                    projectSlug={projectSlug}
                    hasDbError={false}
                    onReload={() => { void reload(); }}
                />
            ) : (
                <div className="grid grid-cols-1 lg:grid-cols-[minmax(280px,1fr)_2fr] gap-4">
                    <div className="space-y-2">
                        <h3 className="text-xs font-bold uppercase tracking-wide text-muted-foreground">
                            Steps ({data.steps.length})
                        </h3>
                        <RecorderStepGraph
                            steps={data.steps}
                            selectedStepId={selectedStepId}
                            onSelect={setSelectedStepId}
                            onDelete={handleDelete}
                        />
                    </div>
                    <div className="border border-border rounded-md bg-card/50 p-4">
                        {selectedStep === null ? (
                            <p className="text-xs text-muted-foreground italic">
                                Select a step from the list to inspect its selectors and binding.
                            </p>
                        ) : selectorsLoading ? (
                            <div className="flex items-center gap-2 text-xs text-muted-foreground">
                                <Loader2 className="h-3.5 w-3.5 animate-spin" /> Loading selectors…
                            </div>
                        ) : (
                            <RecorderStepDetail
                                step={selectedStep}
                                selectors={selectors}
                                dataSources={data.dataSources}
                                bindings={data.bindings}
                                tags={tagsByStep.get(selectedStep.StepId) ?? []}
                                onRename={handleRename}
                                onDescriptionSave={handleDescriptionSave}
                                onTagsSave={handleTagsSave}
                                onLinkChange={handleLinkChange}
                            />
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

/**
 * Marco Extension — Recorder Self-Test
 *
 * Inserts a dummy Step (Wait kind) via RECORDER_STEP_INSERT, lists steps to
 * verify the new row appears, then deletes it via RECORDER_STEP_DELETE so
 * the project is left clean.
 *
 * Throws SelfTestError with phase + reason on any failure so the caller can
 * surface it via toast + logError (Error Drawer).
 */

import { sendMessage } from "@/lib/message-client";
import { logError } from "../options-logger";

/** SelectorKindId.Css per src/background/recorder-db-schema.ts */
const SELECTOR_KIND_CSS = 3;
/** StepKindId.Wait — chosen because it requires no action params. */
const STEP_KIND_WAIT = 5;

export type SelfTestPhase = "insert" | "verify" | "cleanup";

export class RecorderSelfTestError extends Error {
    public readonly Phase: SelfTestPhase;
    public readonly ProjectSlug: string;
    public constructor(phase: SelfTestPhase, projectSlug: string, message: string) {
        super(message);
        this.name = "RecorderSelfTestError";
        this.Phase = phase;
        this.ProjectSlug = projectSlug;
    }
}

export interface SelfTestResult {
    readonly InsertedStepId: number;
    readonly VariableName: string;
    readonly StepCountBefore: number;
    readonly StepCountAfter: number;
    readonly DurationMs: number;
}

interface InsertResponse { isOk: true; step: { StepId: number } }
interface ListResponse  { steps: ReadonlyArray<{ StepId: number; VariableName: string }> }

export async function runRecorderSelfTest(projectSlug: string): Promise<SelfTestResult> {
    if (projectSlug.trim().length === 0) {
        throw new RecorderSelfTestError("insert", projectSlug, "ProjectSlug is empty — select a project first.");
    }

    const startedAt = Date.now();
    const variableName = `__selftest_${startedAt}`;

    const before = await listSteps(projectSlug, "insert");
    const insertedStepId = await insertDummyStep(projectSlug, variableName);

    try {
        const after = await listSteps(projectSlug, "verify");
        const found = after.find((s) => s.StepId === insertedStepId);
        if (found === undefined) {
            throw new RecorderSelfTestError(
                "verify",
                projectSlug,
                `Inserted StepId=${insertedStepId} not present in RECORDER_STEP_LIST after write.`,
            );
        }
        if (found.VariableName !== variableName) {
            throw new RecorderSelfTestError(
                "verify",
                projectSlug,
                `Round-trip mismatch — wrote VariableName='${variableName}', read '${found.VariableName}'.`,
            );
        }

        await deleteStep(projectSlug, insertedStepId);

        return {
            InsertedStepId: insertedStepId,
            VariableName: variableName,
            StepCountBefore: before.length,
            StepCountAfter: after.length,
            DurationMs: Date.now() - startedAt,
        };
    } catch (err) {
        // Best-effort cleanup; do not mask the original error.
        await deleteStep(projectSlug, insertedStepId).catch((cleanupErr: unknown) => {
            logError("recorderSelfTest.cleanup", `deleteStep failed for insertedStepId=${insertedStepId} during error-recovery cleanup — original error will still be rethrown`, cleanupErr);
            return undefined;
        });
        throw err;
    }
}

async function insertDummyStep(projectSlug: string, variableName: string): Promise<number> {
    try {
        const response = await sendMessage<InsertResponse>({
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            type: "RECORDER_STEP_INSERT" as any,
            projectSlug,
            draft: {
                StepKindId: STEP_KIND_WAIT,
                VariableName: variableName,
                Label: "Recorder self-test (auto-cleanup)",
                InlineJs: null,
                ParamsJson: null,
                IsBreakpoint: false,
                Selectors: [{
                    SelectorKindId: SELECTOR_KIND_CSS,
                    Expression: ".__marco_selftest__",
                    AnchorSelectorId: null,
                    IsPrimary: true,
                }],
            },
        });
        if (typeof response?.step?.StepId !== "number") {
            throw new Error("RECORDER_STEP_INSERT returned no StepId");
        }
        return response.step.StepId;
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        throw new RecorderSelfTestError("insert", projectSlug, msg);
    }
}

async function listSteps(projectSlug: string, phase: SelfTestPhase): Promise<ListResponse["steps"]> {
    try {
        const response = await sendMessage<ListResponse>({
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            type: "RECORDER_STEP_LIST" as any,
            projectSlug,
        });
        return response?.steps ?? [];
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        throw new RecorderSelfTestError(phase, projectSlug, `RECORDER_STEP_LIST failed: ${msg}`);
    }
}

async function deleteStep(projectSlug: string, stepId: number): Promise<void> {
    try {
        await sendMessage({
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            type: "RECORDER_STEP_DELETE" as any,
            projectSlug,
            stepId,
        });
    } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        throw new RecorderSelfTestError("cleanup", projectSlug, `RECORDER_STEP_DELETE(stepId=${stepId}) failed: ${msg}`);
    }
}

/**
 * Token Seeder Diagnostics Cache
 *
 * Persists the most recent token-seeder diagnostics snapshot in
 * localStorage so the System Status indicator and full diagnostics
 * panel can hydrate immediately on mount — letting the cooldown
 * countdown resume correctly when the operator reopens the options
 * page instead of flashing empty until the next background poll.
 *
 * The cache is intentionally short-lived: snapshots older than the
 * MAX cooldown window are discarded because every blocked tab will
 * have either retried or been cleared by the background by then.
 */
import { logError } from "./options-logger";

export interface InaccessibleSeedTargetCacheEntry {
    tabId: number;
    tabUrl: string;
    reason: string;
    code: string;
    firstFailureAt: number;
    lastFailureAt: number;
    attemptCount: number;
    cooldownMs: number;
}

export interface TokenSeederDiagnosticsCache {
    targets: InaccessibleSeedTargetCacheEntry[];
    cooldownMs: number;
    capturedAt: string;
}

const STORAGE_KEY = "marco.tokenSeeder.diagnosticsCache.v1";
// Max age past the longest cooldown before we treat the cache as stale.
const MAX_STALE_GRACE_MS = 5 * 60_000; // 5 minutes

function getStorage(): Storage | null {
    try {
        if (typeof window === "undefined") return null;
        return window.localStorage;
    } catch {
        return null;
    }
}

export function loadDiagnosticsCache(): TokenSeederDiagnosticsCache | null {
    const storage = getStorage();
    if (!storage) return null;
    try {
        const raw = storage.getItem(STORAGE_KEY);
        if (!raw) return null;
        const parsed = JSON.parse(raw) as TokenSeederDiagnosticsCache;
        if (!parsed || !Array.isArray(parsed.targets)) return null;

        // Drop snapshots whose youngest failure is older than cooldown + grace.
        const now = Date.now();
        const maxLastFailure = parsed.targets.reduce(
            (acc, t) => Math.max(acc, t.lastFailureAt ?? 0),
            0,
        );
        const cooldown = parsed.cooldownMs ?? 0;
        if (
            maxLastFailure > 0 &&
            now - maxLastFailure > cooldown + MAX_STALE_GRACE_MS
        ) {
            storage.removeItem(STORAGE_KEY);
            return null;
        }

        return parsed;
    } catch {
        return null;
    }
}

export function saveDiagnosticsCache(snapshot: TokenSeederDiagnosticsCache | null): void {
    const storage = getStorage();
    if (!storage) return;
    try {
        if (!snapshot || snapshot.targets.length === 0) {
            storage.removeItem(STORAGE_KEY);
            return;
        }
        storage.setItem(STORAGE_KEY, JSON.stringify(snapshot));
    } catch (caught) {
        logError("tokenSeederDiagnosticsCache.save", "localStorage quota or serialization failure — cache write skipped (non-fatal)", caught);
    }
}

export function clearDiagnosticsCache(): void {
    const storage = getStorage();
    if (!storage) return;
    try {
        storage.removeItem(STORAGE_KEY);
    } catch (caught) {
        logError("tokenSeederDiagnosticsCache.clear", "localStorage.removeItem failed — cache entry may persist until next overwrite", caught);
    }
}

import { useState, useCallback, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { Bug, Check, Loader2 } from "lucide-react";
import { sendMessage } from "@/lib/message-client";
import { toast } from "sonner";

interface ErrorEntry {
  id?: number;
  timestamp?: string;
  level?: string;
  source?: string;
  category?: string;
  error_code?: string;
  message?: string;
  stack_trace?: string;
  context?: string;
  script_id?: string;
  project_id?: string;
  script_file?: string;
  ext_version?: string;
  resolved?: number;
}

interface VerificationResult {
  marcoSdk: boolean;
  extRoot: boolean;
  mcClass: boolean;
  mcInstance: boolean;
  uiContainer: boolean;
  markerEl: boolean;
  verifiedAt: string;
}

interface SessionLog {
  id?: number;
  timestamp?: string;
  level?: string;
  source?: string;
  category?: string;
  action?: string;
  detail?: string;
  message?: string;
}

/** Chunk filenames that produce useless stack traces (minified build artifacts). */
const CHUNK_STACK_PATTERN = /\b(chunk-[a-z0-9]+|assets\/[a-z0-9-]+)\.(js|mjs|cjs):\d+:\d+/i;

/** Strip stack trace lines that only reference build chunks with no source value. */
function cleanStackTrace(raw: string): string {
  const lines = raw.split("\n");
  const useful = lines.filter((line) => !CHUNK_STACK_PATTERN.test(line));
  // If all lines were chunks, keep original first line for minimal context
  if (useful.length === 0 && lines.length > 0) return lines[0];
  return useful.join("\n");
}

function formatError(e: ErrorEntry, i: number): string {
  const ts = e.timestamp ?? "";
  const code = e.error_code ?? "UNKNOWN";
  const msg = e.message ?? "(no message)";
  const file = e.script_file ? ` [${e.script_file}]` : "";
  const script = e.script_id ? ` script=${e.script_id}` : "";
  const project = e.project_id ? ` project=${e.project_id}` : "";
  const cleanedStack = e.stack_trace ? cleanStackTrace(e.stack_trace) : "";
  const stack = cleanedStack ? `\n      Stack: ${cleanedStack}` : "";
  const contextLine = e.context ? `\n      Context: ${e.context}` : "";

  return `  ${i + 1}. ${ts}  ${code}${file}${script}${project}\n      ${msg}${stack}${contextLine}`;
}

function formatLog(l: SessionLog): string {
  const ts = l.timestamp ?? "";
  const lvl = (l.level ?? "info").toUpperCase().padEnd(5);
  const src = l.source ?? "—";
  const detail = l.action
    ? `[${l.category}] ${l.action}: ${l.detail ?? ""}`
    : l.message ?? "";
  return `  ${ts}  ${lvl}  ${src}  ${detail}`;
}

// eslint-disable-next-line max-lines-per-function, sonarjs/cognitive-complexity
function buildInjectionReport(
  errors: ErrorEntry[],
  logs: SessionLog[],
  status: Record<string, unknown> | null,
  health: Record<string, unknown> | null,
  verification?: VerificationResult | null,
): string {
  const sections: string[] = [];

  sections.push(
    "═══════════════════════════════════════════",
    "  Marco Injection Diagnostics",
    `  Generated: ${new Date().toISOString()}`,
    `  Version: ${status?.version ?? "?"}`,
    `  Health: ${health?.state ?? "?"}`,
    `  Boot: ${status?.bootStep ?? "?"}  |  Persistence: ${status?.persistenceMode ?? "?"}`,
    "═══════════════════════════════════════════",
  );

  // Errors section
  sections.push("");
  sections.push(`── INJECTION ERRORS (${errors.length}) ──────────────`);
  if (errors.length > 0) {
    sections.push(...errors.map(formatError));
  } else {
    sections.push("  (no unresolved errors)");
  }

  // Prompt-loading diagnostics (filter logs for prompt/config/injection)
  const diagLogs = logs.filter((l) => {
    const text = `${l.source ?? ""} ${l.category ?? ""} ${l.action ?? ""} ${l.detail ?? ""} ${l.message ?? ""}`.toLowerCase();
    return (
      text.includes("prompt") ||
      text.includes("inject") ||
      text.includes("config") ||
      text.includes("preamble") ||
      text.includes("json") ||
      text.includes("fetch") ||
      text.includes("load") ||
      text.includes("error") ||
      text.includes("fail")
    );
  });

  sections.push("");
  sections.push(`── PROMPT & INJECTION LOGS (${diagLogs.length}) ─────`);
  if (diagLogs.length > 0) {
    sections.push(...diagLogs.map(formatLog));
  } else {
    sections.push("  (no matching diagnostics)");
  }

  // Post-injection verification
  sections.push("");
  sections.push("── POST-INJECTION VERIFICATION ───────────");
  if (verification) {
    const icon = (ok: boolean) => ok ? "✅" : "❌";
    sections.push(`  window.marco (SDK)           : ${icon(verification.marcoSdk)}`);
    sections.push(`  window.RiseupAsiaMacroExt     : ${icon(verification.extRoot)}`);
    sections.push(`  window.MacroController (class): ${icon(verification.mcClass)}`);
    sections.push(`  api.mc (singleton instance)   : ${icon(verification.mcInstance)}`);
    sections.push(`  #macro-loop-container (UI)    : ${icon(verification.uiContainer)}`);
    sections.push(`  [data-marco-injected] marker  : ${verification.markerEl ? "✅" : "⚠️ (not required)"}`);
    sections.push(`  Verified at: ${verification.verifiedAt}`);
  } else {
    sections.push("  (no verification data — inject scripts first)");
  }

  // Health details
  if (health && Array.isArray((health as { details?: string[] }).details)) {
    const details = (health as { details: string[] }).details;
    if (details.length > 0) {
      sections.push("");
      sections.push("── HEALTH DETAILS ────────────────────────");
      details.forEach((d) => sections.push(`  • ${d}`));
    }
  }

  // Extension status (version, boot step, persistence mode, etc.)
  sections.push("");
  sections.push("── EXTENSION STATUS ─────────────────────");
  if (status) {
    const { bootTimings, ...rest } = status as Record<string, unknown> & { bootTimings?: unknown };
    const keys = Object.entries(rest);
    for (const [key, value] of keys) {
      const display = typeof value === "object" ? JSON.stringify(value) : String(value ?? "—");
      sections.push(`  ${key}: ${display}`);
    }
  } else {
    sections.push("  (status unavailable)");
  }

  sections.push("");
  return sections.join("\n");
}

// eslint-disable-next-line max-lines-per-function
export function InjectionCopyButton() {
  const [state, setState] = useState<"idle" | "loading" | "copied">("idle");
  const [errorCount, setErrorCount] = useState(0);
  const [isPulsing, setIsPulsing] = useState(false);

  // PERF-6 (2026-04-25): subscribe to the existing ERROR_COUNT_CHANGED
  // broadcast (same channel use-error-count.ts uses) instead of polling
  // every 15s. The poll is kept as a slow fallback (60s) and is paused
  // while the popup tab is hidden.
  useEffect(() => {
    let cancelled = false;
    let prevCount = 0;
    let pollTimerId: ReturnType<typeof setInterval> | null = null;

    const applyCount = (newCount: number): void => {
      if (cancelled) return;
      if (newCount > prevCount && prevCount >= 0) {
        setIsPulsing(true);
        setTimeout(() => { if (!cancelled) setIsPulsing(false); }, 3000);
      }
      prevCount = newCount;
      setErrorCount(newCount);
    };

    const poll = async () => {
      try {
        const res = await sendMessage<{ errors: ErrorEntry[] }>({ type: "GET_ACTIVE_ERRORS" });
        applyCount(res.errors?.length ?? 0);
      } catch { /* silent */ } // allow-swallow: poll failure is non-critical; next tick retries
    };

    // Real-time listener — same broadcast use-error-count.ts subscribes to.
    const runtime = (typeof chrome !== "undefined" ? chrome.runtime : undefined) as
      | { onMessage?: { addListener: (handler: (msg: unknown) => void) => void; removeListener: (handler: (msg: unknown) => void) => void } }
      | undefined;
    const hasRuntime = runtime?.onMessage !== undefined;
    let listenerAttached = false;

    const handleBroadcast = (message: unknown): void => {
      const msg = message as { type?: string; count?: number } | null;
      if (msg?.type === "ERROR_COUNT_CHANGED") {
        applyCount(msg.count ?? 0);
      }
    };

    if (hasRuntime) {
      try {
        runtime!.onMessage!.addListener(handleBroadcast);
        listenerAttached = true;
      } catch { /* extension context invalidated */ } // allow-swallow: extension context invalidated during teardown
    }

    // PERF-7-style visibility pause: only poll while visible.
    const startPoll = (): void => {
      if (pollTimerId !== null) return;
      // 60s when the broadcast is wired (fallback only); 15s otherwise.
      const intervalMs = listenerAttached ? 60_000 : 15_000;
      pollTimerId = setInterval(() => void poll(), intervalMs);
    };
    const stopPoll = (): void => {
      if (pollTimerId !== null) { clearInterval(pollTimerId); pollTimerId = null; }
    };
    const onVisChange = (): void => {
      if (document.hidden) stopPoll(); else startPoll();
    };

    void poll();
    if (!document.hidden) startPoll();
    document.addEventListener("visibilitychange", onVisChange);

    return () => {
      cancelled = true;
      stopPoll();
      document.removeEventListener("visibilitychange", onVisChange);
      if (listenerAttached) {
        try { runtime!.onMessage!.removeListener(handleBroadcast); } catch { /* ignore */ } // allow-swallow: extension context already torn down
      }
    };
  }, []);

  const handleCopy = useCallback(async () => {
    setState("loading");

    try {
      const [errorsRes, logsRes, statusRes, healthRes, injectionsRes] = await Promise.allSettled([
        sendMessage<{ errors: ErrorEntry[] }>({ type: "GET_ACTIVE_ERRORS" }),
        sendMessage<{ logs: SessionLog[] }>({ type: "GET_RECENT_LOGS", limit: 500 }),
        sendMessage<Record<string, unknown>>({ type: "GET_STATUS" }),
        sendMessage<Record<string, unknown>>({ type: "GET_HEALTH_STATUS" }),
        // Fetch verification from active tab's injection record
        (async () => {
          const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
          if (!tab?.id) return null;
          const res = await sendMessage<{ injections: Record<number, unknown> }>({ type: "GET_TAB_INJECTIONS", tabId: tab.id });
          const record = res?.injections?.[tab.id] as { verification?: VerificationResult } | null;
          return record?.verification ?? null;
        })(),
      ]);

      const errors = errorsRes.status === "fulfilled" ? errorsRes.value.errors ?? [] : [];
      const logs = logsRes.status === "fulfilled" ? logsRes.value.logs ?? [] : [];
      const status = statusRes.status === "fulfilled" ? statusRes.value : null;
      const health = healthRes.status === "fulfilled" ? healthRes.value : null;
      const verification = injectionsRes.status === "fulfilled" ? injectionsRes.value as VerificationResult | null : null;

      const report = buildInjectionReport(errors, logs, status, health, verification);
      await navigator.clipboard.writeText(report);

      setErrorCount(errors.length);
      setState("copied");
      toast.success(`Copied ${errors.length} errors + ${logs.length} diagnostic logs`);
      setTimeout(() => setState("idle"), 2000);
    } catch (err) {
      setState("idle");
      toast.error(err instanceof Error ? err.message : "Copy failed");
    }
  }, []);

  const isLoading = state === "loading";
  const isCopied = state === "copied";
  const isIdle = state === "idle";

  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Button
          size="sm"
          variant="outline"
          className="h-7 text-[10px] gap-1.5 hover:bg-destructive/15 hover:text-destructive border-destructive/30 relative"
          onClick={handleCopy}
          disabled={isLoading}
        >
          {isLoading && <Loader2 className="h-3 w-3 animate-spin" />}
          {isCopied && <Check className="h-3 w-3 text-primary" />}
          {isIdle && (
            <span className="relative">
              <Bug className="h-3 w-3" />
              {errorCount > 0 && (
                <span className={`absolute -top-1.5 -right-1.5 flex h-3 min-w-[0.75rem] items-center justify-center rounded-full bg-destructive px-0.5 text-[7px] font-bold text-destructive-foreground leading-none ${isPulsing ? "animate-[pulse_1s_cubic-bezier(0.4,0,0.6,1)_3]" : ""}`}>
                  {errorCount > 99 ? "99+" : errorCount}
                </span>
              )}
            </span>
          )}
          {isCopied ? "Copied!" : "Copy Injection Logs"}
        </Button>
      </TooltipTrigger>
      <TooltipContent side="top">
        <p className="text-xs max-w-[220px]">
          {errorCount > 0
            ? `${errorCount} unresolved error${errorCount !== 1 ? "s" : ""} — copy injection diagnostics to clipboard`
            : "Copy injection errors, stack traces, prompt-loading diagnostics & health status to clipboard"}
        </p>
      </TooltipContent>
    </Tooltip>
  );
}

/**
 * Marco Extension — Drift Element Diff View
 *
 * Side-by-side comparison of the **primary** (recorded / expected) element
 * versus the **fallback** element that actually matched during replay, with
 * per-attribute changes highlighted. Rendered when
 * `SelectorComparison.DriftDetected === true` so the user can immediately
 * see *how* the page diverged from the recording.
 *
 * Pure presentation — diff data is computed by `diffDriftElements`.
 */

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ArrowRight, AlertTriangle, CheckCircle2, GitCompare, Clock } from "lucide-react";
import type { DomContext } from "@/background/recorder/failure-logger";
import {
    diffDriftElements,
    type DriftChangeKind,
    type DriftElementDiff,
    type DriftFieldDiff,
    type DriftVerdict,
} from "@/background/recorder/drift-element-diff";
import type { SelectorHistoryBucket } from "@/background/recorder/selector-history";
import {
    buildDriftTimeline,
    formatDuration,
    type DriftTimeline,
} from "@/background/recorder/drift-timeline";

interface DriftElementDiffViewProps {
    /** Recorded / expected element snapshot (or null when never captured). */
    readonly primary: DomContext | null;
    /** Element the fallback selector actually matched (or null when none). */
    readonly fallback: DomContext | null;
    /** Optional precomputed diff — if omitted the component computes it. */
    readonly diff?: DriftElementDiff;
    /**
     * Per-selector replay history bucket for the *primary* selector. When
     * supplied a compact "last ok ↔ first drift" timeline is rendered.
     */
    readonly history?: SelectorHistoryBucket | null;
    /** Test seam: override "now" for relative-time formatting. */
    readonly now?: Date;
}

const VERDICT_META: Readonly<Record<DriftVerdict, { label: string; tone: "warn" | "info" | "ok" | "error" }>> = {
    Identical: { label: "Identical", tone: "ok" },
    AttributeDrift: { label: "Attribute drift", tone: "warn" },
    RenamedIdentity: { label: "Renamed identity", tone: "warn" },
    DifferentElement: { label: "Different element", tone: "error" },
    PrimaryMissing: { label: "No recorded snapshot", tone: "info" },
    FallbackMissing: { label: "No fallback matched", tone: "error" },
};

const FIELD_LABELS: Readonly<Record<string, string>> = {
    TagName: "Tag",
    Id: "id",
    ClassName: "class",
    AriaLabel: "aria-label",
    Name: "name",
    Type: "type",
    TextSnippet: "Text",
    OuterHtmlSnippet: "Outer HTML",
};

export function DriftElementDiffView({ primary, fallback, diff, history, now }: DriftElementDiffViewProps) {
    const computed = diff ?? diffDriftElements(primary, fallback);
    const verdict = VERDICT_META[computed.Verdict];
    const timeline = history !== undefined
        ? buildDriftTimeline(history, { Now: now })
        : null;

    return (
        <Card>
            <CardHeader className="pb-3">
                <CardTitle className="flex items-center justify-between gap-2 text-sm">
                    <span className="flex items-center gap-2">
                        <GitCompare className="h-4 w-4" />
                        Drift element diff
                    </span>
                    <VerdictBadge verdict={computed.Verdict} label={verdict.label} />
                </CardTitle>
            </CardHeader>

            <CardContent className="space-y-4">
                {timeline !== null && timeline.State !== "no-history" && (
                    <DriftTimelineStrip timeline={timeline} />
                )}

                {!computed.HasChanges && computed.Verdict === "Identical" ? (
                    <p className="flex items-center gap-2 text-sm text-muted-foreground">
                        <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                        Primary and fallback elements are identical — no drift to highlight.
                    </p>
                ) : (
                    <>
                        <ColumnHeader />
                        <div className="divide-y rounded-md border">
                            {computed.Fields.map((field) => (
                                <FieldRow key={field.Field} field={field} />
                            ))}
                        </div>

                        {(computed.ClassList.Added.length > 0 || computed.ClassList.Removed.length > 0) && (
                            <ClassListDiff
                                added={computed.ClassList.Added}
                                removed={computed.ClassList.Removed}
                                shared={computed.ClassList.Shared}
                            />
                        )}
                    </>
                )}
            </CardContent>
        </Card>
    );
}

function DriftTimelineStrip({ timeline }: { timeline: DriftTimeline }) {
    const { State, LastSuccess, FirstDrift, HealthyDurationMs, FailuresSinceDrift } = timeline;

    if (State === "healthy" && LastSuccess !== null) {
        return (
            <div className="flex items-center gap-2 rounded-md border border-emerald-500/40 bg-emerald-500/5 px-3 py-2 text-xs">
                <Clock className="h-3.5 w-3.5 text-emerald-500 shrink-0" aria-hidden />
                <span className="font-medium text-emerald-700 dark:text-emerald-300">
                    No drift on record
                </span>
                <span className="text-muted-foreground">
                    last ok {LastSuccess.RelativeLabel}
                </span>
                <code className="ml-auto text-[10px] text-muted-foreground" title={LastSuccess.At}>
                    run #{LastSuccess.RunId}
                </code>
            </div>
        );
    }

    if (State === "always-failing" && FirstDrift !== null) {
        return (
            <div className="flex items-center gap-2 rounded-md border border-destructive/40 bg-destructive/5 px-3 py-2 text-xs">
                <Clock className="h-3.5 w-3.5 text-destructive shrink-0" aria-hidden />
                <span className="font-medium text-destructive">Never matched</span>
                <span className="text-muted-foreground">
                    first failure {FirstDrift.RelativeLabel}
                    {FailuresSinceDrift > 1 && ` · ${FailuresSinceDrift} failures total`}
                </span>
                <code className="ml-auto text-[10px] text-muted-foreground" title={FirstDrift.At}>
                    run #{FirstDrift.RunId}
                </code>
            </div>
        );
    }

    if (State === "drifted" && LastSuccess !== null && FirstDrift !== null) {
        return (
            <div className="rounded-md border border-amber-500/40 bg-amber-500/5 px-3 py-2 text-xs space-y-1.5">
                <div className="flex items-center gap-1.5 font-medium text-amber-700 dark:text-amber-300">
                    <Clock className="h-3.5 w-3.5 shrink-0" aria-hidden />
                    Drift timeline
                    {HealthyDurationMs !== null && (
                        <Badge variant="outline" className="ml-1 border-amber-500/40 text-[10px] text-amber-700 dark:text-amber-300">
                            healthy for {formatDuration(HealthyDurationMs)}
                        </Badge>
                    )}
                </div>
                <div className="flex items-center gap-2 font-mono">
                    <span
                        className="flex items-center gap-1 rounded bg-emerald-500/10 px-1.5 py-0.5 text-emerald-700 dark:text-emerald-300"
                        title={LastSuccess.At}
                    >
                        <CheckCircle2 className="h-3 w-3" aria-hidden />
                        ok · {LastSuccess.RelativeLabel}
                        <span className="text-[10px] text-muted-foreground">
                            #{LastSuccess.RunId}
                        </span>
                    </span>
                    <ArrowRight className="h-3 w-3 text-muted-foreground" aria-hidden />
                    <span
                        className="flex items-center gap-1 rounded bg-destructive/10 px-1.5 py-0.5 text-destructive"
                        title={FirstDrift.At}
                    >
                        <AlertTriangle className="h-3 w-3" aria-hidden />
                        drift · {FirstDrift.RelativeLabel}
                        <span className="text-[10px] text-muted-foreground">
                            #{FirstDrift.RunId}
                        </span>
                    </span>
                    {FailuresSinceDrift > 1 && (
                        <span className="ml-auto text-[10px] text-muted-foreground">
                            +{FailuresSinceDrift - 1} more failure{FailuresSinceDrift === 2 ? "" : "s"}
                        </span>
                    )}
                </div>
                {FirstDrift.Error !== null && (
                    <div className="text-[11px] text-muted-foreground italic break-words">
                        First error: {FirstDrift.Error}
                    </div>
                )}
            </div>
        );
    }

    return null;
}

function VerdictBadge({ verdict, label }: { verdict: DriftVerdict; label: string }) {
    const tone = VERDICT_META[verdict].tone;
    if (tone === "ok") {
        return (
            <Badge variant="outline" className="border-emerald-500/40 text-emerald-600 dark:text-emerald-400">
                <CheckCircle2 className="mr-1 h-3 w-3" />
                {label}
            </Badge>
        );
    }
    if (tone === "error") {
        return (
            <Badge variant="destructive">
                <AlertTriangle className="mr-1 h-3 w-3" />
                {label}
            </Badge>
        );
    }
    if (tone === "warn") {
        return (
            <Badge variant="outline" className="border-amber-500/40 text-amber-600 dark:text-amber-400">
                <AlertTriangle className="mr-1 h-3 w-3" />
                {label}
            </Badge>
        );
    }
    return <Badge variant="secondary">{label}</Badge>;
}

function ColumnHeader() {
    return (
        <div className="grid grid-cols-[110px_1fr_24px_1fr] items-center gap-2 px-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            <span>Field</span>
            <span>Primary (recorded)</span>
            <span aria-hidden />
            <span>Fallback (matched)</span>
        </div>
    );
}

function FieldRow({ field }: { field: DriftFieldDiff }) {
    const label = FIELD_LABELS[field.Field] ?? field.Field;
    return (
        <div className="grid grid-cols-[110px_1fr_24px_1fr] items-start gap-2 px-2 py-2 text-sm">
            <span className="pt-0.5 font-mono text-xs text-muted-foreground">{label}</span>
            <ValueCell value={field.Primary} change={field.Change} side="primary" />
            <ArrowRight className="mt-1 h-4 w-4 text-muted-foreground" aria-hidden />
            <ValueCell value={field.Fallback} change={field.Change} side="fallback" />
        </div>
    );
}

function ValueCell({
    value,
    change,
    side,
}: {
    readonly value: string | null;
    readonly change: DriftChangeKind;
    readonly side: "primary" | "fallback";
}) {
    const empty = value === null || value === "";
    const highlight = changeClass(change, side);
    return (
        <code
            className={`block whitespace-pre-wrap break-words rounded px-1.5 py-1 font-mono text-xs ${highlight}`}
            data-change={change}
            data-side={side}
        >
            {empty ? <span className="italic text-muted-foreground">∅</span> : value}
        </code>
    );
}

function changeClass(change: DriftChangeKind, side: "primary" | "fallback"): string {
    if (change === "Unchanged") return "bg-muted/40 text-foreground";
    if (change === "Modified") {
        return side === "primary"
            ? "bg-rose-500/10 text-rose-700 dark:text-rose-300"
            : "bg-emerald-500/10 text-emerald-700 dark:text-emerald-300";
    }
    if (change === "Added") {
        return side === "fallback"
            ? "bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
            : "bg-muted/40 text-muted-foreground";
    }
    // Removed
    return side === "primary"
        ? "bg-rose-500/10 text-rose-700 dark:text-rose-300 line-through"
        : "bg-muted/40 text-muted-foreground";
}

function ClassListDiff({
    added,
    removed,
    shared,
}: {
    readonly added: ReadonlyArray<string>;
    readonly removed: ReadonlyArray<string>;
    readonly shared: ReadonlyArray<string>;
}) {
    return (
        <div className="space-y-2 rounded-md border bg-muted/30 p-3">
            <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
                class list changes
            </p>
            <div className="flex flex-wrap gap-1.5">
                {removed.map((c) => (
                    <Badge
                        key={`r-${c}`}
                        variant="outline"
                        className="border-rose-500/40 font-mono text-xs text-rose-600 line-through dark:text-rose-400"
                    >
                        −{c}
                    </Badge>
                ))}
                {added.map((c) => (
                    <Badge
                        key={`a-${c}`}
                        variant="outline"
                        className="border-emerald-500/40 font-mono text-xs text-emerald-600 dark:text-emerald-400"
                    >
                        +{c}
                    </Badge>
                ))}
                {shared.map((c) => (
                    <Badge key={`s-${c}`} variant="secondary" className="font-mono text-xs">
                        {c}
                    </Badge>
                ))}
            </div>
        </div>
    );
}

/**
 * Marco Extension — Failure Details Panel
 *
 * Pure presentational view of a {@link FailureReport}, designed to live
 * inside the drift / selector-comparison flow so the user (and any AI they
 * paste this into) can see the full diagnostic surface at a glance:
 *
 *   - Top-level `Reason` short-code + `ReasonDetail` sentence.
 *   - `ResolvedXPath` actually evaluated against the live DOM.
 *   - Every `SelectorAttempt` with strategy, expression, resolved
 *     expression, primary flag, match outcome, and per-attempt
 *     `FailureReason` + `FailureDetail`.
 *   - Every `VariableContext` with name, source, row/column, resolved
 *     value, type, and per-variable `FailureReason` + `FailureDetail`.
 *
 * Conformance: mem://standards/verbose-logging-and-failure-diagnostics —
 * "Display the full failure details (selector/XPath, reason, and variable
 *  diagnostics) in the drift/comparison UI when a selector fails."
 *
 * Pure: no DOM mutation, no chrome.*, no async. Renders whatever the
 * caller passes; absent fields collapse silently.
 */

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    AlertOctagon,
    AlertTriangle,
    CheckCircle2,
    XCircle,
    Crosshair,
    FileWarning,
    Variable,
} from "lucide-react";
import type {
    FailureReport,
    FailureReasonCode,
    SelectorAttempt,
} from "@/background/recorder/failure-logger";
import type { VariableContext } from "@/background/recorder/field-reference-resolver";
import { FormSnapshotTable } from "./FormSnapshotTable";

interface FailureDetailsPanelProps {
    readonly report: FailureReport;
    /** Hide the outer Card chrome — useful when embedding inside another card. */
    readonly embedded?: boolean;
}

/* ------------------------------------------------------------------ */
/*  Reason classification                                              */
/* ------------------------------------------------------------------ */

type ReasonGroup = "variable" | "selector" | "syntax" | "timeout" | "other";

const REASON_GROUP: Readonly<Record<FailureReasonCode, ReasonGroup>> = {
    VariableMissing:        "variable",
    VariableNull:           "variable",
    VariableUndefined:      "variable",
    VariableEmpty:          "variable",
    VariableTypeMismatch:   "variable",
    ZeroMatches:            "selector",
    PrimaryMissedFallbackOk:"selector",
    NoSelectors:            "selector",
    XPathSyntaxError:       "syntax",
    CssSyntaxError:         "syntax",
    UnresolvedAnchor:       "syntax",
    EmptyExpression:        "syntax",
    Timeout:                "timeout",
    ConditionTimeout:       "timeout",
    JsThrew:                "other",
    Unknown:                "other",
};

const GROUP_TONE: Readonly<Record<ReasonGroup, string>> = {
    variable: "border-amber-500/40 bg-amber-500/10 text-amber-700 dark:text-amber-300",
    selector: "border-destructive/40 bg-destructive/10 text-destructive",
    syntax:   "border-rose-500/40 bg-rose-500/10 text-rose-700 dark:text-rose-300",
    timeout:  "border-sky-500/40 bg-sky-500/10 text-sky-700 dark:text-sky-300",
    other:    "border-border bg-muted/40 text-foreground",
};

const GROUP_LABEL: Readonly<Record<ReasonGroup, string>> = {
    variable: "Variable failure",
    selector: "Selector failure",
    syntax:   "Selector syntax error",
    timeout:  "Timeout",
    other:    "Failure",
};

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export function FailureDetailsPanel({ report, embedded }: FailureDetailsPanelProps) {
    const group = REASON_GROUP[report.Reason] ?? "other";
    const targetXPath = report.DomContext?.XPath ?? null;
    const body = (
        <div className="space-y-3">
            <ReasonBanner
                reason={report.Reason}
                detail={report.ReasonDetail}
                phase={report.Phase}
                group={group}
                verbose={report.Verbose}
            />
            {report.ResolvedXPath !== null && (
                <ResolvedXPathRow label="Resolved XPath" xpath={report.ResolvedXPath} />
            )}
            {targetXPath !== null && targetXPath.length > 0 && targetXPath !== report.ResolvedXPath && (
                <ResolvedXPathRow label="Target XPath" xpath={targetXPath} />
            )}
            {report.Selectors.length > 0 && <SelectorAttemptsBlock attempts={report.Selectors} />}
            {report.Variables.length > 0 && <VariablesBlock variables={report.Variables} />}
            {report.FormSnapshot !== null && (
                <FormSnapshotTable snapshot={report.FormSnapshot} title="Form data at failure" />
            )}
            {report.Verbose && report.CapturedHtml !== null && (
                <CapturedHtmlBlock html={report.CapturedHtml} />
            )}
            <SourceFooter file={report.SourceFile} timestamp={report.Timestamp} stepId={report.StepId} stepKind={report.StepKind} />
        </div>
    );

    if (embedded === true) {
        return (
            <section
                aria-label="Failure details"
                data-testid="failure-details-panel"
                className="rounded-md border border-border bg-card/40 p-3"
            >
                {body}
            </section>
        );
    }

    return (
        <Card data-testid="failure-details-panel">
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                    <FileWarning className="h-4 w-4 text-destructive" />
                    Failure details
                    <Badge variant="outline" className="ml-1 text-[10px]">
                        {report.Phase}
                    </Badge>
                </CardTitle>
            </CardHeader>
            <CardContent>{body}</CardContent>
        </Card>
    );
}

/* ------------------------------------------------------------------ */
/*  Sub-components                                                     */
/* ------------------------------------------------------------------ */

function ReasonBanner({
    reason,
    detail,
    phase,
    group,
    verbose,
}: {
    readonly reason: FailureReasonCode;
    readonly detail: string;
    readonly phase: string;
    readonly group: ReasonGroup;
    readonly verbose: boolean;
}) {
    return (
        <div
            role="alert"
            data-testid="failure-reason-banner"
            data-reason={reason}
            data-group={group}
            data-verbose={verbose}
            className={`rounded-md border px-3 py-2 text-xs ${GROUP_TONE[group]}`}
        >
            <div className="flex items-center gap-2 flex-wrap">
                <AlertOctagon className="h-3.5 w-3.5 shrink-0" aria-hidden />
                <span className="font-semibold uppercase tracking-wide">{GROUP_LABEL[group]}</span>
                <Badge variant="outline" className="text-[10px] font-mono">
                    {reason}
                </Badge>
                {verbose && (
                    <Badge
                        variant="default"
                        className="text-[10px]"
                        title="Verbose logging was ON when this report was captured"
                    >
                        VERBOSE
                    </Badge>
                )}
                <span className="ml-auto text-[10px] opacity-70">{phase}</span>
            </div>
            <p className="mt-1 break-words whitespace-pre-wrap">{detail}</p>
        </div>
    );
}

function ResolvedXPathRow({ label, xpath }: { readonly label: string; readonly xpath: string }) {
    return (
        <div
            data-testid="failure-resolved-xpath"
            data-label={label}
            className="rounded-md border border-border bg-muted/30 px-3 py-2 text-xs"
        >
            <div className="flex items-center gap-2 text-muted-foreground">
                <Crosshair className="h-3 w-3" aria-hidden />
                <span className="uppercase tracking-wide font-medium">{label}</span>
            </div>
            <code className="mt-1 block break-all font-mono text-foreground">{xpath}</code>
        </div>
    );
}

function CapturedHtmlBlock({ html }: { readonly html: string }) {
    return (
        <section
            data-testid="failure-captured-html"
            className="rounded-md border border-border bg-muted/30 p-2.5 text-xs space-y-1.5"
        >
            <header className="flex items-center gap-2 text-muted-foreground">
                <FileWarning className="h-3 w-3" aria-hidden />
                <span className="uppercase tracking-wide font-medium">Captured HTML (verbose)</span>
                <Badge variant="outline" className="ml-auto text-[10px]">
                    {html.length.toLocaleString()} chars
                </Badge>
            </header>
            <ScrollArea className="max-h-48">
                <pre className="whitespace-pre-wrap break-all font-mono text-[11px] text-foreground">
                    {html}
                </pre>
            </ScrollArea>
        </section>
    );
}

function SelectorAttemptsBlock({ attempts }: { attempts: ReadonlyArray<SelectorAttempt> }) {
    return (
        <section data-testid="failure-selector-attempts" className="space-y-1.5">
            <header className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-muted-foreground">
                <Crosshair className="h-3 w-3" aria-hidden />
                Selector attempts
                <Badge variant="secondary" className="text-[10px]">{attempts.length}</Badge>
            </header>
            <ScrollArea className="max-h-56 pr-2">
                <ul className="space-y-1.5">
                    {attempts.map((a, i) => (
                        <SelectorAttemptRow key={`${a.SelectorId ?? "noid"}-${i}`} attempt={a} />
                    ))}
                </ul>
            </ScrollArea>
        </section>
    );
}

function SelectorAttemptRow({ attempt }: { attempt: SelectorAttempt }) {
    const Icon = attempt.Matched ? CheckCircle2 : XCircle;
    const tone = attempt.Matched ? "text-emerald-500" : "text-destructive";
    const border = attempt.IsPrimary
        ? attempt.Matched ? "border-emerald-500/40" : "border-destructive/40"
        : "border-border";
    const expr = attempt.ResolvedExpression.length > 0
        ? attempt.ResolvedExpression
        : attempt.Expression;
    const showResolvedDistinct =
        attempt.ResolvedExpression !== attempt.Expression && attempt.Expression.length > 0;

    return (
        <li
            data-testid="failure-attempt-row"
            data-matched={attempt.Matched}
            data-primary={attempt.IsPrimary}
            className={`rounded-md border ${border} bg-card p-2 text-xs space-y-1`}
        >
            <div className="flex items-center gap-2">
                <Icon className={`h-3.5 w-3.5 shrink-0 ${tone}`} aria-hidden />
                <Badge variant="outline" className="text-[10px] px-1.5 py-0">{attempt.Strategy}</Badge>
                {attempt.IsPrimary && (
                    <Badge variant="default" className="text-[10px] px-1.5 py-0">PRIMARY</Badge>
                )}
                <code className="text-muted-foreground truncate" title={expr}>
                    {expr}
                </code>
                <Badge variant="secondary" className="ml-auto text-[10px] px-1.5 py-0">
                    {attempt.MatchCount} match{attempt.MatchCount === 1 ? "" : "es"}
                </Badge>
            </div>
            {showResolvedDistinct && (
                <div className="pl-5 text-[11px] text-muted-foreground">
                    Stored: <code className="break-all">{attempt.Expression}</code>
                </div>
            )}
            {!attempt.Matched && (
                <div className="pl-5 text-[11px] text-destructive flex items-start gap-1">
                    <AlertTriangle className="h-3 w-3 mt-0.5 shrink-0" aria-hidden />
                    <span>
                        <span className="font-mono">{attempt.FailureReason}</span>
                        {attempt.FailureDetail !== null && (
                            <> — <span className="break-words">{attempt.FailureDetail}</span></>
                        )}
                    </span>
                </div>
            )}
        </li>
    );
}

function VariablesBlock({ variables }: { variables: ReadonlyArray<VariableContext> }) {
    const failed = variables.filter((v) => v.FailureReason !== "Resolved");
    return (
        <section data-testid="failure-variables" className="space-y-1.5">
            <header className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-muted-foreground">
                <Variable className="h-3 w-3" aria-hidden />
                Variables
                <Badge variant="secondary" className="text-[10px]">{variables.length}</Badge>
                {failed.length > 0 && (
                    <Badge variant="destructive" className="text-[10px]">{failed.length} failed</Badge>
                )}
            </header>
            <ul className="space-y-1.5">
                {variables.map((v, i) => (
                    <VariableRow key={`${v.Name}-${i}`} variable={v} />
                ))}
            </ul>
        </section>
    );
}

function VariableRow({ variable }: { variable: VariableContext }) {
    const ok = variable.FailureReason === "Resolved";
    const Icon = ok ? CheckCircle2 : XCircle;
    const tone = ok ? "text-emerald-500" : "text-destructive";
    const border = ok ? "border-border" : "border-destructive/40";
    const valueLabel = variable.ResolvedValue === null
        ? "<null>"
        : JSON.stringify(variable.ResolvedValue);

    return (
        <li
            data-testid="failure-variable-row"
            data-resolved={ok}
            className={`rounded-md border ${border} bg-card p-2 text-xs space-y-1`}
        >
            <div className="flex items-center gap-2 flex-wrap">
                <Icon className={`h-3.5 w-3.5 shrink-0 ${tone}`} aria-hidden />
                <code className="font-mono text-foreground">{`{{${variable.Name}}}`}</code>
                <Badge variant="outline" className="text-[10px] px-1.5 py-0">{variable.ValueType}</Badge>
                <span className="text-muted-foreground text-[11px]">from {variable.Source}</span>
                {variable.RowIndex !== null && (
                    <span className="text-muted-foreground text-[11px]">
                        · row {variable.RowIndex}
                    </span>
                )}
                {variable.Column !== null && variable.Column !== variable.Name && (
                    <span className="text-muted-foreground text-[11px]">· col {variable.Column}</span>
                )}
            </div>
            <div className="pl-5 text-[11px]">
                <span className="text-muted-foreground">Value: </span>
                <code className="break-all text-foreground">{valueLabel}</code>
            </div>
            {!ok && (
                <div className="pl-5 text-[11px] text-destructive flex items-start gap-1">
                    <AlertTriangle className="h-3 w-3 mt-0.5 shrink-0" aria-hidden />
                    <span>
                        <span className="font-mono">{variable.FailureReason}</span>
                        {variable.FailureDetail !== null && (
                            <> — <span className="break-words">{variable.FailureDetail}</span></>
                        )}
                    </span>
                </div>
            )}
        </li>
    );
}

function SourceFooter({
    file,
    timestamp,
    stepId,
    stepKind,
}: {
    readonly file: string;
    readonly timestamp: string;
    readonly stepId: number | null;
    readonly stepKind: string | null;
}) {
    return (
        <footer
            data-testid="failure-source-footer"
            className="flex flex-wrap items-center gap-x-3 gap-y-1 pt-1 text-[10px] text-muted-foreground border-t border-border"
        >
            <span>at <code className="font-mono">{file}</code></span>
            {stepId !== null && <span>StepId={stepId}</span>}
            {stepKind !== null && <span>Kind={stepKind}</span>}
            <span className="ml-auto font-mono">{timestamp}</span>
        </footer>
    );
}

/**
 * Marco Extension — Failure Reports Panel
 *
 * Renders a list of structured {@link FailureReport}s with per-row
 * checkboxes and a single "Export selected" button that downloads the
 * selection as a JSON bundle suitable for sharing with an AI assistant.
 *
 * Pure presentation — the parent passes the report list. Bundle building
 * and filename formatting live in `./failure-export.ts` so they can be
 * tested without jsdom.
 */

import { useMemo, useState } from "react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { FileDown, AlertTriangle, ChevronDown, ChevronRight, ClipboardCopy } from "lucide-react";
import { toast } from "sonner";
import type { FailureReport } from "@/background/recorder/failure-logger";
import {
    buildFailureBundle,
    serializeFailureBundle,
    serializeJson,
    buildFailureBundleFilename,
    pickLastFailureReport,
    buildLastFailureFilename,
    listStepFailureOptions,
    pickFailureReportByStepId,
    DEFAULT_EXPORT_FORMAT,
    type ExportFormat,
} from "./failure-export";
import { validateFailureReportPayload } from "./failure-report-validator";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { FailureDetailsPanel } from "./FailureDetailsPanel";
import { SelectorReplayTracePanel } from "./SelectorReplayTracePanel";

interface FailureReportsPanelProps {
    readonly reports: ReadonlyArray<FailureReport>;
    /** Test seam: override the `download` side effect. */
    readonly onDownload?: (filename: string, contents: string) => void;
    /**
     * Test seam: override the clipboard side effect. Defaults to
     * `navigator.clipboard.writeText`. Returning a rejected promise
     * triggers the failure toast.
     */
    readonly onCopy?: (contents: string) => Promise<void>;
}

function defaultCopy(contents: string): Promise<void> {
    if (typeof navigator === "undefined" || !navigator.clipboard) {
        return Promise.reject(new Error("Clipboard API unavailable in this context"));
    }
    return navigator.clipboard.writeText(contents);
}

function defaultDownload(filename: string, contents: string): void {
    const blob = new Blob([contents], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
}

function rowKey(r: FailureReport, idx: number): string {
    return `${r.Timestamp}#${r.StepId ?? "noid"}#${idx}`;
}

const STEP_OPTION_NULL = "__null_step__";

export function FailureReportsPanel({ reports, onDownload, onCopy }: FailureReportsPanelProps) {
    const [selected, setSelected] = useState<ReadonlySet<string>>(new Set());
    const [expanded, setExpanded] = useState<ReadonlySet<string>>(new Set());
    const [pickedStep, setPickedStep] = useState<string | null>(null);
    const [exportFormat, setExportFormat] = useState<ExportFormat>(DEFAULT_EXPORT_FORMAT);

    const stepOptions = useMemo(() => listStepFailureOptions(reports), [reports]);

    // Reset / auto-clear the picker when the option list shrinks below the current pick.
    const validPickedStep = useMemo(() => {
        if (pickedStep === null) return null;
        const exists = stepOptions.some(
            (o) => (o.StepId === null ? STEP_OPTION_NULL : String(o.StepId)) === pickedStep,
        );
        return exists ? pickedStep : null;
    }, [pickedStep, stepOptions]);

    const allKeys = useMemo(() => reports.map((r, i) => rowKey(r, i)), [reports]);
    const allSelected = selected.size > 0 && selected.size === reports.length;
    const noneSelected = selected.size === 0;

    const toggle = (key: string) => {
        setSelected((prev) => {
            const next = new Set(prev);
            if (next.has(key)) { next.delete(key); } else { next.add(key); }
            return next;
        });
    };

    const toggleExpanded = (key: string) => {
        setExpanded((prev) => {
            const next = new Set(prev);
            if (next.has(key)) { next.delete(key); } else { next.add(key); }
            return next;
        });
    };

    const toggleAll = () => {
        setSelected(allSelected ? new Set() : new Set(allKeys));
    };

    const handleExport = () => {
        const picked = reports.filter((_, i) => selected.has(rowKey(reports[i], i)));
        if (picked.length === 0) {
            toast.error("Select at least one failure to export");
            return;
        }
        const bundle = buildFailureBundle(picked);
        const filename = buildFailureBundleFilename();
        const contents = serializeFailureBundle(bundle, exportFormat);
        (onDownload ?? defaultDownload)(filename, contents);
        const validation = validateFailureReportPayload(contents);
        if (!validation.Valid) {
            toast.warning(`Exported ${filename} — schema warning`, {
                description: validation.Summary,
            });
        } else {
            toast.success(`Exported ${picked.length} failure report${picked.length === 1 ? "" : "s"}`);
        }
    };

    const handleExportLast = () => {
        const last = pickLastFailureReport(reports);
        if (last === null) {
            toast.error("No failures recorded yet");
            return;
        }
        const filename = buildLastFailureFilename(last);
        const contents = serializeJson(last, exportFormat);
        (onDownload ?? defaultDownload)(filename, contents);
        const stepLabel = last.StepId !== null ? ` (Step #${last.StepId})` : "";
        const validation = validateFailureReportPayload(contents);
        if (!validation.Valid) {
            toast.warning(`Downloaded ${filename} — schema warning`, {
                description: validation.Summary,
            });
        } else {
            toast.success(`Downloaded ${filename}`, {
                description: `Last failure${stepLabel} saved as JSON`,
            });
        }
    };

    const handleCopyLast = async () => {
        const last = pickLastFailureReport(reports);
        if (last === null) {
            toast.error("No failures recorded yet");
            return;
        }
        const contents = serializeJson(last, exportFormat);
        const stepLabel = last.StepId !== null ? ` (Step #${last.StepId})` : "";
        try {
            await (onCopy ?? defaultCopy)(contents);
        } catch (e) {
            toast.error("Copy failed — clipboard unavailable", {
                description: (e as Error).message,
            });
            return;
        }
        const validation = validateFailureReportPayload(contents);
        if (!validation.Valid) {
            toast.warning(`Copied last failure${stepLabel} — schema warning`, {
                description: validation.Summary,
            });
        } else {
            toast.success(`Copied last failure${stepLabel} to clipboard`, {
                description: `${contents.length.toLocaleString()} chars — paste into your ticket or chat`,
            });
        }
    };

    const handleExportByStep = () => {
        if (validPickedStep === null) {
            toast.error("Pick a Step first");
            return;
        }
        const stepId = validPickedStep === STEP_OPTION_NULL ? null : Number(validPickedStep);
        const report = pickFailureReportByStepId(reports, stepId);
        if (report === null) {
            toast.error(
                stepId === null
                    ? "No failures without a Step ID"
                    : `No failures recorded for Step #${stepId}`,
            );
            return;
        }
        const filename = buildLastFailureFilename(report);
        const contents = serializeJson(report, exportFormat);
        (onDownload ?? defaultDownload)(filename, contents);
        const stepLabel = stepId === null ? " (no Step ID)" : ` (Step #${stepId})`;
        const validation = validateFailureReportPayload(contents);
        if (!validation.Valid) {
            toast.warning(`Downloaded ${filename} — schema warning`, {
                description: validation.Summary,
            });
        } else {
            toast.success(`Downloaded ${filename}`, {
                description: `Latest failure for${stepLabel} saved as JSON`,
            });
        }
    };

    return (
        <Card>
            <CardHeader className="flex flex-col gap-2 pb-2 sm:flex-row sm:items-center sm:justify-between">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4 text-destructive" />
                    Failure Reports
                    <Badge variant="secondary" className="ml-1">{reports.length}</Badge>
                </CardTitle>
                <div className="flex flex-wrap items-center gap-2">
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={toggleAll}
                        disabled={reports.length === 0}
                    >
                        {allSelected ? "Clear" : "Select all"}
                    </Button>
                    <Select
                        value={exportFormat}
                        onValueChange={(v) => setExportFormat(v as ExportFormat)}
                    >
                        <SelectTrigger
                            className="h-8 w-[140px] text-xs"
                            aria-label="JSON output format for exported failure reports"
                            title="Choose Pretty (2-space indent, easier to read in tickets) or Minified (single line, smaller files)"
                        >
                            <SelectValue placeholder="Format…" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="pretty">Pretty JSON</SelectItem>
                            <SelectItem value="minified">Minified JSON</SelectItem>
                        </SelectContent>
                    </Select>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleCopyLast}
                        disabled={reports.length === 0}
                        aria-label="Copy last failure report JSON to clipboard"
                        title="Copy the most recent failure report JSON to the clipboard for pasting into a ticket or chat"
                    >
                        <ClipboardCopy className="h-3.5 w-3.5 mr-1.5" />
                        Copy last failure JSON
                    </Button>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleExportLast}
                        disabled={reports.length === 0}
                        aria-label="Export last failure report as JSON"
                        title="Download the most recent failure report (selectors, EvaluatedAttempts, variables) as JSON"
                    >
                        <FileDown className="h-3.5 w-3.5 mr-1.5" />
                        Export last failure
                    </Button>
                    <div className="flex items-center gap-1.5">
                        <Select
                            value={validPickedStep ?? ""}
                            onValueChange={(v) => setPickedStep(v === "" ? null : v)}
                            disabled={stepOptions.length === 0}
                        >
                            <SelectTrigger
                                className="h-8 w-[180px] text-xs"
                                aria-label="Choose a Step ID to export its latest failure"
                            >
                                <SelectValue placeholder="Pick step…" />
                            </SelectTrigger>
                            <SelectContent>
                                {stepOptions.map((o) => {
                                    const value = o.StepId === null ? STEP_OPTION_NULL : String(o.StepId);
                                    const label = o.StepId === null
                                        ? "(no Step ID)"
                                        : `Step #${o.StepId}`;
                                    const kind = o.StepKind ? ` · ${o.StepKind}` : "";
                                    const count = o.Count > 1 ? ` ×${o.Count}` : "";
                                    return (
                                        <SelectItem key={value} value={value}>
                                            {label}{kind}{count}
                                        </SelectItem>
                                    );
                                })}
                            </SelectContent>
                        </Select>
                        <Button
                            variant="outline"
                            size="sm"
                            onClick={handleExportByStep}
                            disabled={validPickedStep === null}
                            aria-label="Export the latest failure report for the picked Step ID"
                            title="Download the most recent failure report for the picked Step ID as JSON"
                        >
                            <FileDown className="h-3.5 w-3.5 mr-1.5" />
                            Export step
                        </Button>
                    </div>
                    <Button
                        variant="default"
                        size="sm"
                        onClick={handleExport}
                        disabled={noneSelected}
                        aria-label="Export selected failure reports"
                    >
                        <FileDown className="h-3.5 w-3.5 mr-1.5" />
                        Export failure reports
                    </Button>
                </div>
            </CardHeader>
            <CardContent>
                {reports.length === 0 ? (
                    <p className="text-xs text-muted-foreground italic py-4 text-center">
                        No failures recorded.
                    </p>
                ) : (
                    <ScrollArea className="h-64 pr-2">
                        <ul className="space-y-1.5">
                            {reports.map((r, i) => {
                                const key = rowKey(r, i);
                                const checked = selected.has(key);
                                const isExpanded = expanded.has(key);
                                const ChevronIcon = isExpanded ? ChevronDown : ChevronRight;
                                return (
                                    <li
                                        key={key}
                                        className="rounded-md border border-border bg-card px-2.5 py-2 space-y-2"
                                    >
                                        <div className="flex items-start gap-2">
                                            <Checkbox
                                                id={`fr-${key}`}
                                                checked={checked}
                                                onCheckedChange={() => toggle(key)}
                                                aria-label={`Select failure report ${i + 1}`}
                                            />
                                            <label
                                                htmlFor={`fr-${key}`}
                                                className="flex-1 cursor-pointer text-xs space-y-0.5"
                                            >
                                                <div className="flex items-center gap-1.5 flex-wrap">
                                                    <Badge
                                                        variant={r.Phase === "Replay" ? "destructive" : "outline"}
                                                        className="text-[10px] px-1.5 py-0"
                                                    >
                                                        {r.Phase}
                                                    </Badge>
                                                    <Badge variant="outline" className="text-[10px] px-1.5 py-0 font-mono">
                                                        {r.Reason}
                                                    </Badge>
                                                    {r.StepKind !== null && (
                                                        <span className="text-muted-foreground">{r.StepKind}</span>
                                                    )}
                                                    {r.StepId !== null && (
                                                        <span className="text-muted-foreground">· Step #{r.StepId}</span>
                                                    )}
                                                    <span className="text-muted-foreground ml-auto">
                                                        {r.Timestamp}
                                                    </span>
                                                </div>
                                                <p className="text-foreground line-clamp-2">{r.Message}</p>
                                            </label>
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                className="h-6 px-1.5 -mt-0.5"
                                                onClick={() => toggleExpanded(key)}
                                                aria-label={isExpanded ? `Hide details for failure ${i + 1}` : `Show details for failure ${i + 1}`}
                                                aria-expanded={isExpanded}
                                            >
                                                <ChevronIcon className="h-3.5 w-3.5" />
                                                <span className="ml-1 text-[10px]">{isExpanded ? "Hide" : "Details"}</span>
                                            </Button>
                                        </div>
                                        {isExpanded && (
                                            <div className="space-y-2">
                                                <FailureDetailsPanel report={r} embedded />
                                                <SelectorReplayTracePanel report={r} embedded />
                                            </div>
                                        )}
                                    </li>
                                );
                            })}
                        </ul>
                    </ScrollArea>
                )}
            </CardContent>
        </Card>
    );
}

/**
 * Marco Extension — Form Snapshot Table
 *
 * Pure presentational view of a {@link FormSnapshot}. Renders a compact
 * table of every captured field with type, required marker, sensitive
 * mask icon, and (when verbose) the captured value.
 *
 * Used in three surfaces (per
 * mem://features/form-snapshot-capture):
 *   1. Inline on each recorded step card whose `FormSnapshot` is non-null.
 *   2. Inside `FailureDetailsPanel` when the failing step carries one.
 *   3. As an icon-only badge on `SelectorReplayTracePanel` rows (separate
 *      tiny `<FormSnapshotBadge>` export).
 *
 * Pure: no DOM mutation, no chrome.*, no async. Renders whatever the
 * caller passes; absent fields collapse silently.
 */

import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    ClipboardList,
    Lock,
    Asterisk,
    EyeOff,
} from "lucide-react";
import type { FormSnapshot, FormFieldMeta } from "@/background/recorder/form-snapshot";

interface FormSnapshotTableProps {
    readonly snapshot: FormSnapshot;
    /** Hide the surrounding section/border — useful inside another card. */
    readonly embedded?: boolean;
    /** Override the section heading. */
    readonly title?: string;
}

export function FormSnapshotTable({ snapshot, embedded, title }: FormSnapshotTableProps) {
    const valueByName = new Map<string, { Value: string; Masked: boolean }>();
    if (snapshot.Values !== null) {
        for (const v of snapshot.Values) {
            valueByName.set(v.Name, { Value: v.Value, Masked: v.Masked });
        }
    }

    const heading = title ?? "Form snapshot";
    const verboseTone = snapshot.Verbose
        ? "border-amber-500/40 bg-amber-500/5"
        : "border-border bg-muted/20";

    const body = (
        <div className="space-y-2" data-testid="form-snapshot-table">
            <header className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-muted-foreground">
                <ClipboardList className="h-3 w-3" aria-hidden />
                <span className="font-medium">{heading}</span>
                <Badge variant="secondary" className="text-[10px]">
                    {snapshot.Fields.length} field{snapshot.Fields.length === 1 ? "" : "s"}
                </Badge>
                {snapshot.Form.Id !== null && (
                    <span className="text-[11px] text-muted-foreground normal-case tracking-normal">
                        #{snapshot.Form.Id}
                    </span>
                )}
                {snapshot.Verbose ? (
                    <Badge variant="default" className="ml-auto text-[10px]" title="Captured under verbose logging — values included (sensitive fields masked)">
                        VALUES
                    </Badge>
                ) : (
                    <Badge variant="outline" className="ml-auto text-[10px]" title="Verbose logging was OFF — only field names + types captured">
                        <EyeOff className="h-2.5 w-2.5 mr-1" aria-hidden />
                        NAMES ONLY
                    </Badge>
                )}
            </header>

            <ScrollArea className="max-h-56 pr-2">
                <table className="w-full text-xs">
                    <thead>
                        <tr className="text-[10px] uppercase tracking-wide text-muted-foreground border-b border-border">
                            <th className="text-left font-medium py-1 pr-2">Field</th>
                            <th className="text-left font-medium py-1 pr-2">Type</th>
                            {snapshot.Verbose && (
                                <th className="text-left font-medium py-1">Value</th>
                            )}
                        </tr>
                    </thead>
                    <tbody>
                        {snapshot.Fields.map((f, i) => (
                            <FieldRow
                                key={`${f.Name}-${i}`}
                                field={f}
                                value={valueByName.get(f.Name) ?? null}
                                showValue={snapshot.Verbose}
                            />
                        ))}
                    </tbody>
                </table>
            </ScrollArea>
        </div>
    );

    if (embedded === true) return body;

    return (
        <section
            aria-label="Form snapshot"
            data-testid="form-snapshot-section"
            data-verbose={snapshot.Verbose}
            className={`rounded-md border ${verboseTone} p-2.5`}
        >
            {body}
        </section>
    );
}

function FieldRow({
    field, value, showValue,
}: {
    readonly field: FormFieldMeta;
    readonly value: { Value: string; Masked: boolean } | null;
    readonly showValue: boolean;
}) {
    return (
        <tr
            data-testid="form-snapshot-row"
            data-name={field.Name}
            data-sensitive={field.Sensitive}
            className="border-b border-border/40 last:border-0"
        >
            <td className="py-1 pr-2 align-top">
                <div className="flex items-center gap-1 flex-wrap">
                    <code className="font-mono text-foreground">{field.Name}</code>
                    {field.Required && (
                        <Asterisk className="h-2.5 w-2.5 text-destructive" aria-label="required" />
                    )}
                    {field.Sensitive && (
                        <Lock className="h-2.5 w-2.5 text-amber-500" aria-label="sensitive" />
                    )}
                </div>
            </td>
            <td className="py-1 pr-2 align-top">
                <Badge variant="outline" className="text-[10px] px-1.5 py-0 font-mono">
                    {field.Type}
                </Badge>
            </td>
            {showValue && (
                <td className="py-1 align-top">
                    {value === null ? (
                        <span className="text-muted-foreground italic">—</span>
                    ) : (
                        <code
                            className={`font-mono break-all ${value.Masked ? "text-amber-600 dark:text-amber-400" : "text-foreground"}`}
                            data-masked={value.Masked}
                        >
                            {value.Value.length === 0 ? <span className="italic text-muted-foreground">empty</span> : value.Value}
                        </code>
                    )}
                </td>
            )}
        </tr>
    );
}

/**
 * Compact pill version — just "snapshot: N fields", optional sensitive
 * count. Used in the Selector Replay Trace rows so the user knows the
 * step carries form data without expanding the full panel.
 */
export function FormSnapshotBadge({ snapshot }: { readonly snapshot: FormSnapshot }) {
    const sensitive = snapshot.Fields.filter((f) => f.Sensitive).length;
    const label = `snapshot: ${snapshot.Fields.length} field${snapshot.Fields.length === 1 ? "" : "s"}`;
    const title = snapshot.Verbose
        ? `Form snapshot captured with values (${sensitive} sensitive masked)`
        : `Form snapshot — names + types only (verbose OFF)`;

    return (
        <Badge
            variant="outline"
            className="text-[10px] px-1.5 py-0 inline-flex items-center gap-1"
            data-testid="form-snapshot-badge"
            data-verbose={snapshot.Verbose}
            title={title}
        >
            <ClipboardList className="h-2.5 w-2.5" aria-hidden />
            {label}
            {sensitive > 0 && <Lock className="h-2.5 w-2.5 text-amber-500" aria-hidden />}
        </Badge>
    );
}

/**
 * Marco Extension — Hotkey Chord Capture
 *
 * Reusable input that listens for keyboard events and turns each
 * chord (keydown with optional modifiers) into a string entry. Used
 * by the Step Editor Dialog (Hotkey kind) and by the Floating
 * Controller's quick-add panel.
 *
 * Behaviour:
 *   - Click the capture box to activate; press a key combination → it
 *     is captured as "Ctrl+Shift+S" style.
 *   - Captured chords stack as removable chips above the box.
 *   - The most recently captured chord is summarised in the box itself
 *     and persists through Esc / outside-click so the user has an
 *     immediate visual confirmation of what was just pressed.
 *   - `Backspace` while empty deletes the last chip.
 *   - Pressing `Escape` cancels capture mode (chord list is preserved).
 *   - Clicking anywhere outside the component also exits capture mode.
 *
 * The component is fully controlled — caller owns `value` and reacts
 * to `onChange`.
 */

import { useCallback, useEffect, useRef, useState } from "react";
import { X, Keyboard, History } from "lucide-react";

import { cn } from "@/lib/utils";

export interface HotkeyChordCaptureProps {
    readonly value: readonly string[];
    readonly onChange: (next: readonly string[]) => void;
    readonly placeholder?: string;
    readonly className?: string;
    readonly id?: string;
}

const MODIFIER_KEYS = new Set(["Control", "Shift", "Alt", "Meta", "OS"]);

function eventToChord(e: KeyboardEvent): string | null {
    if (MODIFIER_KEYS.has(e.key)) { return null; }
    const parts: string[] = [];
    if (e.ctrlKey) parts.push("Ctrl");
    if (e.altKey) parts.push("Alt");
    if (e.shiftKey) parts.push("Shift");
    if (e.metaKey) parts.push("Meta");
    let key = e.key;
    if (key === " ") { key = "Space"; }
    if (key.length === 1) { key = key.toUpperCase(); }
    parts.push(key);
    return parts.join("+");
}

export function HotkeyChordCapture(props: HotkeyChordCaptureProps): JSX.Element {
    const { value, onChange, placeholder, className, id } = props;
    const [active, setActive] = useState(false);
    /**
     * Sticky summary of the most-recently-captured chord. Survives chip
     * removal, Esc, and outside-click so the user always sees what they
     * just pressed without having to recount the chord chips.
     */
    const [lastChord, setLastChord] = useState<string | null>(null);
    const boxRef = useRef<HTMLDivElement | null>(null);
    const containerRef = useRef<HTMLDivElement | null>(null);

    const onKeyDown = useCallback((e: KeyboardEvent) => {
        if (!active) { return; }
        if (e.key === "Escape") {
            e.preventDefault();
            setActive(false);
            boxRef.current?.blur();
            return;
        }
        if (e.key === "Backspace" && !e.ctrlKey && !e.altKey && !e.metaKey && !e.shiftKey && value.length > 0) {
            // Only consume backspace when no other key is pressed —
            // otherwise allow "Ctrl+Backspace" etc. to be captured.
            e.preventDefault();
            onChange(value.slice(0, -1));
            return;
        }
        const chord = eventToChord(e);
        if (chord === null) { return; }
        e.preventDefault();
        e.stopPropagation();
        setLastChord(chord);
        onChange([...value, chord]);
    }, [active, value, onChange]);

    useEffect(() => {
        if (!active) { return; }
        const box = boxRef.current;
        if (box === null) { return; }
        box.addEventListener("keydown", onKeyDown);
        return () => box.removeEventListener("keydown", onKeyDown);
    }, [active, onKeyDown]);

    /**
     * Outside-click guard. Pointer-down is used (not click) so the
     * deactivation runs *before* focus moves elsewhere — otherwise
     * onBlur already fires and this is redundant. The pointer path
     * also catches mousedown on non-focusable surfaces.
     */
    useEffect(() => {
        if (!active) { return; }
        const onPointerDown = (e: PointerEvent) => {
            const root = containerRef.current;
            if (root === null) { return; }
            if (e.target instanceof Node && root.contains(e.target)) { return; }
            setActive(false);
            boxRef.current?.blur();
        };
        document.addEventListener("pointerdown", onPointerDown, true);
        return () => document.removeEventListener("pointerdown", onPointerDown, true);
    }, [active]);

    const removeChord = (idx: number) => {
        const next = value.slice();
        next.splice(idx, 1);
        onChange(next);
    };

    return (
        <div ref={containerRef} className={cn("space-y-1.5", className)}>
            <div className="flex flex-wrap gap-1.5 min-h-[1.75rem]">
                {value.length === 0 ? (
                    <span className="text-[11px] text-muted-foreground italic self-center">
                        No chords yet — focus the box below and press keys.
                    </span>
                ) : value.map((chord, i) => (
                    <span
                        key={`${chord}-${i}`}
                        className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded bg-secondary text-secondary-foreground text-[11px] font-mono"
                        data-testid="hotkey-chord-chip"
                    >
                        {chord}
                        <button
                            type="button"
                            aria-label={`Remove chord ${chord}`}
                            onClick={() => removeChord(i)}
                            className="opacity-60 hover:opacity-100"
                        >
                            <X className="h-3 w-3" />
                        </button>
                    </span>
                ))}
            </div>
            <div
                ref={boxRef}
                id={id}
                role="textbox"
                tabIndex={0}
                aria-label="Hotkey capture area — focus then press keys"
                onFocus={() => setActive(true)}
                onBlur={() => setActive(false)}
                onClick={() => boxRef.current?.focus()}
                className={cn(
                    "border rounded px-2 py-1.5 text-xs cursor-text transition-colors outline-none",
                    "focus-visible:ring-2 focus-visible:ring-ring",
                    active
                        ? "border-primary bg-primary/5 text-foreground"
                        : "border-border bg-background text-muted-foreground hover:border-primary/50",
                )}
                data-testid="hotkey-capture-box"
                aria-live="polite"
            >
                <div className="flex items-center justify-between gap-2">
                    <span className="inline-flex items-center gap-1.5">
                        <Keyboard className="h-3 w-3" />
                        {active
                            ? "Listening… press a key combination (Esc to stop)"
                            : (placeholder ?? "Click here, then press the key combination to record")}
                    </span>
                    {lastChord !== null ? (
                        <span
                            className="inline-flex items-center gap-1 text-[10px] font-mono text-muted-foreground"
                            data-testid="hotkey-last-chord"
                            title={`Last captured chord: ${lastChord}`}
                        >
                            <History className="h-3 w-3" />
                            <span className="text-foreground">{lastChord}</span>
                        </span>
                    ) : null}
                </div>
            </div>
        </div>
    );
}

/**
 * Marco Extension — Keyword Event Bulk Context Menu
 *
 * Right-click menu for the keyword events list. Shown on selected rows;
 * exposes bulk Run-state toggles, Add/Remove tags, Rename in sequence,
 * Export selected as ZIP, and Delete.
 *
 * Why a dedicated component:
 *   • Keeps `KeywordEventsPanel.tsx` focused on layout/selection plumbing.
 *   • Centralises the dialog state for the three multi-step actions
 *     (tags, rename, export) so reuse by other surfaces (Steps, Sessions,
 *     Scripts/Projects) is a matter of swapping the data source.
 *
 * The Export action ships JSON-in-ZIP today; the SQLite-in-ZIP pipeline is
 * a separate roadmap item tracked in plan.md.
 */

import { useEffect, useMemo, useState } from "react";
import { logError } from "./recorder-logger";
import {
    Download,
    Eye,
    EyeOff,
    FolderTree,
    HelpCircle,
    Pencil,
    Tag,
    TagsIcon,
    Trash2,
    Upload,
} from "lucide-react";
import {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipTrigger,
} from "@/components/ui/tooltip";

import {
    ContextMenu,
    ContextMenuContent,
    ContextMenuItem,
    ContextMenuLabel,
    ContextMenuSeparator,
    ContextMenuTrigger,
} from "@/components/ui/context-menu";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import {
    DEFAULT_SEQUENCE_RENAME,
    collectCategories,
    computeSequencePreview,
    mergeTags,
    normaliseCategory,
    parseTagInput,
    removeTags,
    renderSequenceName,
    type SequencePreviewIssue,
    type SequenceRenameInput,
} from "@/lib/keyword-event-bulk-actions";
import {
    downloadKeywordEventsZip,
    type KeywordEventsExportProgress,
} from "@/lib/keyword-events-sqlite-export";
import { Progress } from "@/components/ui/progress";
import {
    buildPatchFromImport,
    diffMatchedFields,
    planImportMatches,
    readKeywordEventsZip,
    type ImportMatchPlan,
    type KeywordEventsImportResult,
} from "@/lib/keyword-events-sqlite-import";
import type { KeywordEvent } from "@/hooks/use-keyword-events";

export interface KeywordEventBulkContextMenuProps {
    /** The row this menu wraps. Right-clicking it opens the menu. */
    readonly children: React.ReactNode;
    /** Events that are currently part of the selection set. */
    readonly selectedEvents: ReadonlyArray<KeywordEvent>;
    /** Every event in the panel — used by Rename-in-sequence to detect
     *  collisions with rows the user did NOT select. Optional; when omitted
     *  collision detection is skipped. */
    readonly allEvents?: ReadonlyArray<KeywordEvent>;
    /** Called when the user right-clicks a row that isn't yet selected — the
     *  parent should add it to the selection so the menu acts on it. */
    readonly onContextOpenForUnselected?: () => void;
    /** True when the wrapped row is itself in the selection. */
    readonly isRowSelected: boolean;
    /** Apply a patch to one event by id. */
    readonly onUpdateEvent: (id: string, patch: Partial<Omit<KeywordEvent, "Id">>) => void;
    /** Delete one event by id. */
    readonly onRemoveEvent: (id: string) => void;
    /** Clear the selection set (called after destructive actions). */
    readonly onClearSelection: () => void;
}

type DialogKind = null | "tags-add" | "tags-remove" | "category" | "rename" | "export" | "import" | "delete";

export function KeywordEventBulkContextMenu(
    props: KeywordEventBulkContextMenuProps,
): JSX.Element {
    const {
        children, selectedEvents, allEvents, isRowSelected, onContextOpenForUnselected,
        onUpdateEvent, onRemoveEvent, onClearSelection,
    } = props;

    const [dialog, setDialog] = useState<DialogKind>(null);
    const count = selectedEvents.length;

    const handleOpenChange = (open: boolean): void => {
        if (open && !isRowSelected) onContextOpenForUnselected?.();
    };

    const handleEnable = (enabled: boolean): void => {
        for (const ev of selectedEvents) onUpdateEvent(ev.Id, { Enabled: enabled });
    };

    const handleDeleteConfirmed = (): void => {
        for (const ev of selectedEvents) onRemoveEvent(ev.Id);
        onClearSelection();
        setDialog(null);
    };

    return (
        <>
            <ContextMenu onOpenChange={handleOpenChange}>
                <ContextMenuTrigger asChild>{children}</ContextMenuTrigger>
                <ContextMenuContent
                    className="w-56"
                    data-testid="keyword-events-context-menu"
                >
                    <ContextMenuLabel className="text-xs text-muted-foreground">
                        {count} selected
                    </ContextMenuLabel>
                    <ContextMenuSeparator />
                    <ContextMenuItem
                        onSelect={() => handleEnable(true)}
                        data-testid="keyword-events-context-enable"
                    >
                        <Eye className="mr-2 h-4 w-4" /> Enable
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => handleEnable(false)}
                        data-testid="keyword-events-context-disable"
                    >
                        <EyeOff className="mr-2 h-4 w-4" /> Disable
                    </ContextMenuItem>
                    <ContextMenuSeparator />
                    <ContextMenuItem
                        onSelect={() => setDialog("tags-add")}
                        data-testid="keyword-events-context-tags-add"
                    >
                        <Tag className="mr-2 h-4 w-4" /> Add labels…
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => setDialog("tags-remove")}
                        data-testid="keyword-events-context-tags-remove"
                    >
                        <TagsIcon className="mr-2 h-4 w-4" /> Remove labels…
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => setDialog("category")}
                        data-testid="keyword-events-context-category"
                    >
                        <FolderTree className="mr-2 h-4 w-4" /> Set category…
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => setDialog("rename")}
                        data-testid="keyword-events-context-rename"
                    >
                        <Pencil className="mr-2 h-4 w-4" /> Rename in sequence…
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => setDialog("export")}
                        data-testid="keyword-events-context-export"
                    >
                        <Download className="mr-2 h-4 w-4" /> Export selected as ZIP…
                    </ContextMenuItem>
                    <ContextMenuItem
                        onSelect={() => setDialog("import")}
                        data-testid="keyword-events-context-import"
                    >
                        <Upload className="mr-2 h-4 w-4" /> Update selected from ZIP…
                    </ContextMenuItem>
                    <ContextMenuSeparator />
                    <ContextMenuItem
                        className="text-destructive focus:text-destructive"
                        onSelect={() => setDialog("delete")}
                        data-testid="keyword-events-context-delete"
                    >
                        <Trash2 className="mr-2 h-4 w-4" /> Delete…
                    </ContextMenuItem>
                </ContextMenuContent>
            </ContextMenu>

            <BulkTagsDialog
                mode="add"
                open={dialog === "tags-add"}
                onOpenChange={(o) => setDialog(o ? "tags-add" : null)}
                selectedEvents={selectedEvents}
                onApply={(tags) => {
                    for (const ev of selectedEvents) {
                        onUpdateEvent(ev.Id, { Tags: mergeTags(ev.Tags, tags) });
                    }
                }}
            />
            <BulkTagsDialog
                mode="remove"
                open={dialog === "tags-remove"}
                onOpenChange={(o) => setDialog(o ? "tags-remove" : null)}
                selectedEvents={selectedEvents}
                onApply={(tags) => {
                    for (const ev of selectedEvents) {
                        onUpdateEvent(ev.Id, { Tags: removeTags(ev.Tags, tags) });
                    }
                }}
            />
            <BulkRenameSequenceDialog
                open={dialog === "rename"}
                onOpenChange={(o) => setDialog(o ? "rename" : null)}
                selectedEvents={selectedEvents}
                allEvents={allEvents}
                onApply={(input) => {
                    selectedEvents.forEach((ev, i) => {
                        onUpdateEvent(ev.Id, { Keyword: renderSequenceName(input, i) });
                    });
                }}
            />
            <BulkCategoryDialog
                open={dialog === "category"}
                onOpenChange={(o) => setDialog(o ? "category" : null)}
                selectedEvents={selectedEvents}
                onApply={(category) => {
                    for (const ev of selectedEvents) {
                        onUpdateEvent(ev.Id, { Category: category });
                    }
                }}
            />
            <BulkExportDialog
                open={dialog === "export"}
                onOpenChange={(o) => setDialog(o ? "export" : null)}
                selectedEvents={selectedEvents}
            />
            <BulkImportDialog
                open={dialog === "import"}
                onOpenChange={(o) => setDialog(o ? "import" : null)}
                selectedEvents={selectedEvents}
                onApply={(plan) => {
                    for (const m of plan.matches) {
                        onUpdateEvent(m.target.Id, buildPatchFromImport(m.source));
                    }
                }}
            />
            <BulkDeleteConfirmDialog
                open={dialog === "delete"}
                onOpenChange={(o) => setDialog(o ? "delete" : null)}
                selectedEvents={selectedEvents}
                onConfirm={handleDeleteConfirmed}
            />
        </>
    );
}

/* ------------------------------------------------------------------ */
/*  Tags dialog                                                       */
/* ------------------------------------------------------------------ */

interface BulkTagsDialogProps {
    readonly mode: "add" | "remove";
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly selectedEvents: ReadonlyArray<KeywordEvent>;
    readonly onApply: (tags: string[]) => void;
}

function BulkTagsDialog(props: BulkTagsDialogProps): JSX.Element {
    const { mode, open, onOpenChange, selectedEvents, onApply } = props;
    const [raw, setRaw] = useState("");
    const tags = useMemo(() => parseTagInput(raw), [raw]);
    const existing = useMemo(() => {
        const all = new Set<string>();
        for (const ev of selectedEvents) {
            (ev.Tags ?? []).forEach(t => all.add(t));
        }
        return Array.from(all).sort((a, b) => a.localeCompare(b));
    }, [selectedEvents]);

    const handleApply = (): void => {
        if (tags.length === 0) return;
        onApply(tags);
        setRaw("");
        onOpenChange(false);
    };

    const title = mode === "add" ? "Add labels" : "Remove labels";
    const desc = mode === "add"
        ? `Label ${selectedEvents.length} selected event${selectedEvents.length === 1 ? "" : "s"}.`
        : `Remove labels from ${selectedEvents.length} selected event${selectedEvents.length === 1 ? "" : "s"}.`;

    return (
        <Dialog open={open} onOpenChange={(o) => { if (!o) setRaw(""); onOpenChange(o); }}>
            <DialogContent data-testid={`keyword-events-bulk-tags-dialog-${mode}`}>
                <DialogHeader>
                    <DialogTitle>{title}</DialogTitle>
                    <DialogDescription>{desc} Separate labels with commas or spaces.</DialogDescription>
                </DialogHeader>
                <div className="space-y-3">
                    <div className="space-y-1.5">
                        <Label htmlFor="bulk-tags-input">Labels</Label>
                        <Input
                            id="bulk-tags-input"
                            value={raw}
                            onChange={(e) => setRaw(e.target.value)}
                            placeholder="e.g. login, smoke, regression"
                            autoFocus
                            data-testid="keyword-events-bulk-tags-input"
                        />
                    </div>
                    {tags.length > 0 && (
                        <div className="flex flex-wrap gap-1">
                            {tags.map(t => (
                                <Badge key={t} variant="secondary" className="text-[10px]">{t}</Badge>
                            ))}
                        </div>
                    )}
                    {mode === "remove" && existing.length > 0 && (
                        <div className="space-y-1">
                            <p className="text-[11px] text-muted-foreground">Existing labels on selection:</p>
                            <div className="flex flex-wrap gap-1">
                                {existing.map(t => (
                                    <Badge
                                        key={t}
                                        variant="outline"
                                        className="cursor-pointer text-[10px]"
                                        onClick={() => setRaw(r => r.length === 0 ? t : `${r}, ${t}`)}
                                    >
                                        {t}
                                    </Badge>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
                <DialogFooter>
                    <Button variant="ghost" onClick={() => onOpenChange(false)}>Cancel</Button>
                    <Button
                        onClick={handleApply}
                        disabled={tags.length === 0}
                        data-testid={`keyword-events-bulk-tags-apply-${mode}`}
                    >
                        {mode === "add" ? "Add" : "Remove"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}

/* ------------------------------------------------------------------ */
/*  Rename in sequence dialog                                          */
/* ------------------------------------------------------------------ */

interface BulkRenameSequenceDialogProps {
    readonly open: boolean;
    readonly onOpenChange: (open: boolean) => void;
    readonly selectedEvents: ReadonlyArray<KeywordEvent>;
    readonly allEvents?: ReadonlyArray<KeywordEvent>;
    readonly onApply: (input: SequenceRenameInput) => void;
}

// ──────────────────────────────────────────────────────────────────────────
//  Persisted Sequence settings: versioned envelope + migration chain
// ──────────────────────────────────────────────────────────────────────────
//
// Storage shape (v2+):
//     { v: <number>, data: <SequenceRenameInput> }
//
// Legacy (v1) shape that may exist on disk:
//     { Base, Start, Padding, Separator }   ← bare object, no envelope
//
// To evolve the schema:
//   1. Bump CURRENT_SEQUENCE_VERSION.
//   2. Append a migration to SEQUENCE_MIGRATIONS that takes the previous
//      version's payload and returns the next one. Migrations run in
//      sequence and are idempotent (re-running on already-current data
//      is a no-op because the version stamp matches).
//   3. Field-validate the final result in `coerceSequenceInput()` so any
//      garbage from older builds still falls back to safe defaults.
//
// The localStorage KEY itself is stable across versions to avoid orphaned
// keys from older releases piling up in users' browser storage.
const SEQUENCE_RENAME_STORAGE_KEY = "marco.bulkRename.sequence";

/** Bump this whenever the persisted shape changes in a non-additive way. */
const CURRENT_SEQUENCE_VERSION = 2;

/** Legacy key used before the versioned envelope was introduced. */
const LEGACY_SEQUENCE_KEY_V1 = "marco.bulkRename.sequence.v1";

interface VersionedSequenceEnvelope {
    readonly v: number;
    readonly data: SequenceRenameInput;
}

/**
 * Migration chain: index `i` upgrades a payload from version `i+1` to `i+2`.
 * Each migration receives the *raw* parsed JSON (shape is whatever the
 * previous version persisted) and returns the next version's payload.
 *
 * Add new migrations to the end of this array — never reorder or remove.
 */
const SEQUENCE_MIGRATIONS: ReadonlyArray<(prev: Partial<SequenceRenameInput>) => Partial<SequenceRenameInput>> = [
    // v1 → v2: no shape change, just wrapped in {v, data} envelope. The
    // wrapping is handled by the loader; this migration is identity.
    (prev) => prev,
    // Example for future use:
    //   v2 → v3: rename `Padding` to `MinDigits`
    // (prev) => ({ ...prev, MinDigits: prev.Padding ?? 2 }),
];

/** Field-validate and clamp a raw object into a safe SequenceRenameInput. */
function coerceSequenceInput(parsed: Partial<SequenceRenameInput>): SequenceRenameInput {
    return {
        Base: typeof parsed.Base === "string" ? parsed.Base : DEFAULT_SEQUENCE_RENAME.Base,
        Start: typeof parsed.Start === "number" && Number.isFinite(parsed.Start)
            ? Math.max(0, Math.floor(parsed.Start))
            : DEFAULT_SEQUENCE_RENAME.Start,
        Padding: typeof parsed.Padding === "number" && Number.isFinite(parsed.Padding)
            ? Math.max(1, Math.min(6, Math.floor(parsed.Padding)))
            : DEFAULT_SEQUENCE_RENAME.Padding,
        Separator: typeof parsed.Separator === "string"
            ? parsed.Separator
            : DEFAULT_SEQUENCE_RENAME.Separator,
    };
}

/** Run migrations from `fromVersion` up to CURRENT_SEQUENCE_VERSION. */
function migrateSequencePayload(payload: Partial<SequenceRenameInput>, fromVersion: number): Partial<SequenceRenameInput> {
    let current = payload;
    let v = fromVersion;
    while (v < CURRENT_SEQUENCE_VERSION) {
        const migration = SEQUENCE_MIGRATIONS[v - 1];
        if (!migration) break;  // no migration registered → stop and let coerce fix it
        current = migration(current);
        v++;
    }
    return current;
}

function loadPersistedSequence(): SequenceRenameInput {
    if (typeof localStorage === "undefined") return DEFAULT_SEQUENCE_RENAME;
    try {
        // 1. Prefer the current versioned key.
        const raw = localStorage.getItem(SEQUENCE_RENAME_STORAGE_KEY);
        if (raw) {
            const parsed = JSON.parse(raw) as Partial<VersionedSequenceEnvelope> | Partial<SequenceRenameInput>;
            // Versioned envelope?
            if (parsed && typeof parsed === "object" && "v" in parsed && typeof parsed.v === "number" && "data" in parsed && parsed.data) {
                const migrated = migrateSequencePayload(parsed.data, parsed.v);
                return coerceSequenceInput(migrated);
            }
            // Bare object found under the new key (shouldn't happen, but treat as v1).
            const migrated = migrateSequencePayload(parsed as Partial<SequenceRenameInput>, 1);
            return coerceSequenceInput(migrated);
        }
        // 2. Fall back to the legacy v1 key (one-shot migration; we'll
        //    rewrite under the new key on the next persist).
        const legacy = localStorage.getItem(LEGACY_SEQUENCE_KEY_V1);
        if (legacy) {
            const parsed = JSON.parse(legacy) as Partial<SequenceRenameInput>;
            const migrated = migrateSequencePayload(parsed, 1);
            return coerceSequenceInput(migrated);
        }
        return DEFAULT_SEQUENCE_RENAME;
    } catch {
        return DEFAULT_SEQUENCE_RENAME;
    }
}

function persistSequence(input: SequenceRenameInput): void {
    if (typeof localStorage === "undefined") return;
    try {
        const envelope: VersionedSequenceEnvelope = { v: CURRENT_SEQUENCE_VERSION, data: input };
        localStorage.setItem(SEQUENCE_RENAME_STORAGE_KEY, JSON.stringify(envelope));
        // Best-effort cleanup of the legacy key once we've successfully
        // written the new one — keeps user storage tidy across upgrades.
        if (localStorage.getItem(LEGACY_SEQUENCE_KEY_V1) !== null) {
            localStorage.removeItem(LEGACY_SEQUENCE_KEY_V1);
        }
    } catch (caught) {
        logError("KeywordEventBulkContextMenu.persistSequence", `localStorage write failed for key="${SEQUENCE_RENAME_STORAGE_KEY}" — dialog will work but won't remember last used settings`, caught);
    }
}

function clearPersistedSequence(): void {
    if (typeof localStorage === "undefined") return;
    try {
        localStorage.removeItem(SEQUENCE_RENAME_STORAGE_KEY);
        localStorage.removeItem(LEGACY_SEQUENCE_KEY_V1);
    } catch (caught) {
        logError("KeywordEventBulkContextMenu.clearPersistedSequence", `localStorage.removeItem failed for keys=[${SEQUENCE_RENAME_STORAGE_KEY}, ${LEGACY_SEQUENCE_KEY_V1}] — in-memory reset still applies`, caught);
    }
}

export function BulkRenameSequenceDialog(props: BulkRenameSequenceDialogProps): JSX.Element {
    const { open, onOpenChange, selectedEvents, allEvents, onApply } = props;
    const [input, setInput] = useState<SequenceRenameInput>(loadPersistedSequence);

    // Re-hydrate from storage whenever the dialog is reopened so other surfaces
    // that use the same key (or another tab) stay in sync.
    useEffect(() => {
        if (open) setInput(loadPersistedSequence());
    }, [open]);

    // Cross-tab live sync: when another tab writes to the same localStorage key,
    // refresh this dialog's fields immediately so all open Batch Rename dialogs
    // stay in lockstep. The `storage` event only fires in OTHER tabs, never the
    // one that wrote it, so we never clobber the user's in-progress edits here.
    useEffect(() => {
        if (!open) return;
        if (typeof window === "undefined") return;
        const handler = (e: StorageEvent): void => {
            if (e.key !== SEQUENCE_RENAME_STORAGE_KEY) return;
            setInput(loadPersistedSequence());
        };
        window.addEventListener("storage", handler);
        return () => window.removeEventListener("storage", handler);
    }, [open]);

    // Persist edits live (debounced via React's batching) so other open tabs
    // receive the `storage` event and mirror the changes immediately. Skipped
    // while the dialog is closed to avoid writing default values on mount.
    useEffect(() => {
        if (!open) return;
        persistSequence(input);
    }, [open, input]);

    // Build the set of "outside" keywords once per (allEvents, selection) change.
    // Selected events are excluded so renaming an event back to its own name
    // doesn't falsely flag a collision.
    const outsideKeywords = useMemo(() => {
        if (!allEvents || allEvents.length === 0) return [];
        const selectedIds = new Set(selectedEvents.map(e => e.Id));
        return allEvents
            .filter(e => !selectedIds.has(e.Id))
            .map(e => e.Keyword);
    }, [allEvents, selectedEvents]);

    const summary = useMemo(
        () => computeSequencePreview(selectedEvents, input, outsideKeywords),
        [selectedEvents, input, outsideKeywords],
    );
    const previewRows = summary.Rows.slice(0, 8);

    const handleApply = (): void => {
        if (!summary.IsValid) return;
        persistSequence(input);
        onApply(input);
        onOpenChange(false);
    };

    // Keyboard shortcuts:
    //   • Enter (in any text/number field)        → submit (handled by <form>).
    //   • Ctrl/Cmd+Enter from anywhere in dialog → submit even when focus
    //     is on a non-form control (e.g. the help button).
    //   • Escape                                  → close (Dialog default).
    const handleDialogKeyDown = (e: React.KeyboardEvent<HTMLDivElement>): void => {
        if ((e.ctrlKey || e.metaKey) && e.key === "Enter") {
            e.preventDefault();
            handleApply();
        }
    };

    const handleSubmit = (e: React.FormEvent<HTMLFormElement>): void => {
        e.preventDefault();
        handleApply();
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent
                data-testid="keyword-events-bulk-rename-dialog"
                onKeyDown={handleDialogKeyDown}
            >
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        Rename in sequence
                        <TooltipProvider delayDuration={150}>
                            <Tooltip>
                                <TooltipTrigger asChild>
                                    <button
                                        type="button"
                                        aria-label="How {n} and Separator work"
                                        className="text-muted-foreground hover:text-foreground"
                                        data-testid="keyword-events-bulk-rename-help"
                                    >
                                        <HelpCircle className="h-4 w-4" />
                                    </button>
                                </TooltipTrigger>
                                <TooltipContent side="right" className="max-w-xs text-xs leading-relaxed">
                                    <p className="mb-1 font-semibold">How sequencing works</p>
                                    <p className="mb-1">
                                        <code>{"{n}"}</code> is replaced with the row number, starting at <em>Start number</em> and zero-padded to <em>Padding</em> digits.
                                    </p>
                                    <p className="mb-1">
                                        Example: base <code>Login {"{n}"}</code>, start <code>1</code>, padding <code>2</code> →
                                        <code> Login 01</code>, <code>Login 02</code>…
                                    </p>
                                    <p>
                                        <strong>Separator</strong> is appended only when the base has no <code>{"{n}"}</code>. e.g. base <code>Step</code> with separator <code>-</code> → <code>Step-01</code>.
                                    </p>
                                </TooltipContent>
                            </Tooltip>
                        </TooltipProvider>
                    </DialogTitle>
                    <DialogDescription>
                        Renames {selectedEvents.length} event{selectedEvents.length === 1 ? "" : "s"}.
                        Use <code>{"{n}"}</code> in the base to control number placement.
                    </DialogDescription>
                </DialogHeader>
                <form onSubmit={handleSubmit} data-testid="keyword-events-bulk-rename-form">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="col-span-2 space-y-1.5">
                            <Label htmlFor="bulk-rename-base">Base name</Label>
                            <Input
                                id="bulk-rename-base"
                                value={input.Base}
                                onChange={(e) => setInput(s => ({ ...s, Base: e.target.value }))}
                                autoFocus
                                tabIndex={1}
                                data-testid="keyword-events-bulk-rename-base"
                            />
                        </div>
                        <div className="space-y-1.5">
                            <Label htmlFor="bulk-rename-start">Start number</Label>
                            <Input
                                id="bulk-rename-start"
                                type="number"
                                min={0}
                                value={input.Start}
                                tabIndex={2}
                                onChange={(e) => setInput(s => ({ ...s, Start: Math.max(0, Number(e.target.value) || 0) }))}
                                data-testid="keyword-events-bulk-rename-start"
                            />
                        </div>
                        <div className="space-y-1.5">
                            <Label htmlFor="bulk-rename-padding">Padding</Label>
                            <Input
                                id="bulk-rename-padding"
                                type="number"
                                min={1}
                                max={6}
                                value={input.Padding}
                                tabIndex={3}
                                onChange={(e) => setInput(s => ({ ...s, Padding: Math.max(1, Math.min(6, Number(e.target.value) || 1)) }))}
                                data-testid="keyword-events-bulk-rename-padding"
                            />
                        </div>
                        <div className="col-span-2 space-y-1.5">
                            <Label htmlFor="bulk-rename-separator" className="flex items-baseline justify-between gap-2">
                                <span>Separator</span>
                                <span className="text-[11px] font-normal text-muted-foreground">
                                    Only applied when <code className="rounded bg-muted px-1 py-0.5">{"{n}"}</code> is not in the base
                                </span>
                            </Label>
                            <Input
                                id="bulk-rename-separator"
                                value={input.Separator}
                                tabIndex={4}
                                onChange={(e) => setInput(s => ({ ...s, Separator: e.target.value }))}
                                data-testid="keyword-events-bulk-rename-separator"
                            />
                            <p className="text-[11px] text-muted-foreground">
                                Example: base <code className="rounded bg-muted px-1 py-0.5">Step</code> + separator <code className="rounded bg-muted px-1 py-0.5">-</code> → <code className="rounded bg-muted px-1 py-0.5">Step-01</code>. Ignored if base already contains <code className="rounded bg-muted px-1 py-0.5">{"{n}"}</code>.
                            </p>
                        </div>
                    </div>

                    <SequenceFormulaExample start={input.Start} padding={input.Padding} />

                    <PreviewSummaryBanner summary={summary} />

                    <div className="mt-2 rounded-md border border-border bg-muted/30 p-2 text-xs">
                        <p className="mb-1 font-medium text-muted-foreground">Preview</p>
                        <ul className="space-y-0.5 font-mono" data-testid="keyword-events-bulk-rename-preview">
                            {previewRows.map((row) => {
                                const hasIssue = row.Issues.length > 0;
                                const nextClass = hasIssue
                                    ? "truncate text-destructive font-semibold"
                                    : "truncate text-foreground";
                                return (
                                    <li
                                        key={row.Id}
                                        className="flex items-center gap-2"
                                        data-testid="keyword-events-bulk-rename-preview-row"
                                        data-issues={row.Issues.join(",")}
                                    >
                                        <span className="truncate text-muted-foreground line-through">{row.Old}</span>
                                        <span aria-hidden>→</span>
                                        <span className={nextClass}>{row.Next || "(empty)"}</span>
                                        {row.Issues.map(issue => (
                                            <Badge
                                                key={issue}
                                                variant="destructive"
                                                className="h-4 px-1 text-[10px] uppercase tracking-wide"
                                            >
                                                {issueLabel(issue)}
                                            </Badge>
                                        ))}
                                    </li>
                                );
                            })}
                            {summary.Rows.length > previewRows.length && (
                                <li className="text-muted-foreground">…and {summary.Rows.length - previewRows.length} more</li>
                            )}
                        </ul>
                    </div>
                    <DialogFooter className="mt-3 sm:justify-between">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={() => {
                                clearPersistedSequence();
                                setInput(DEFAULT_SEQUENCE_RENAME);
                            }}
                            tabIndex={7}
                            data-testid="keyword-events-bulk-rename-reset"
                        >
                            Reset to defaults
                        </Button>
                        <div className="flex gap-2">
                            <Button type="button" variant="ghost" onClick={() => onOpenChange(false)} tabIndex={6}>Cancel</Button>
                            <Button
                                type="submit"
                                disabled={!summary.IsValid || selectedEvents.length === 0}
                                tabIndex={5}
                                data-testid="keyword-events-bulk-rename-apply"
                            >
                                Rename
                            </Button>
                        </div>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

function issueLabel(issue: SequencePreviewIssue): string {
    switch (issue) {
        case "duplicate": return "duplicate";
        case "collision": return "collision";
        case "empty":     return "empty";
        case "too-long":  return "too long";
    }
}

function PreviewSummaryBanner({ summary }: { readonly summary: ReturnType<typeof computeSequencePreview> }): JSX.Element | null {
    if (summary.IsValid) return null;
    const parts: string[] = [];
    if (summary.DuplicateCount > 0) parts.push(`${summary.DuplicateCount} duplicate${summary.DuplicateCount === 1 ? "" : "s"}`);
    if (summary.CollisionCount > 0) parts.push(`${summary.CollisionCount} collide with existing names`);
    if (summary.EmptyCount > 0)     parts.push(`${summary.EmptyCount} empty`);
    if (summary.TooLongCount > 0)   parts.push(`${summary.TooLongCount} too long`);

    const collidingRows = summary.Rows.filter(r => r.CollidesWith.length > 0);

    return (
        <div
            role="alert"
            className="rounded-md border border-destructive/40 bg-destructive/10 px-2 py-1.5 text-xs text-destructive"
            data-testid="keyword-events-bulk-rename-issues"
        >
            <div>Cannot apply: {parts.join(" · ")}.</div>
            {collidingRows.length > 0 && (
                <details
                    className="mt-1.5"
                    data-testid="keyword-events-bulk-rename-collision-details"
                >
                    <summary className="cursor-pointer select-none font-medium underline-offset-2 hover:underline">
                        Show {collidingRows.length} collision{collidingRows.length === 1 ? "" : "s"}
                    </summary>
                    <ul className="mt-1.5 space-y-0.5 pl-3 font-mono">
                        {collidingRows.map(row => (
                            <li
                                key={row.Id}
                                data-testid="keyword-events-bulk-rename-collision-row"
                                data-row-id={row.Id}
                            >
                                <span className="font-semibold">{row.Next || "(empty)"}</span>
                                {" → already used by "}
                                <span>{row.CollidesWith.map(k => `“${k}”`).join(", ")}</span>
                            </li>
                        ))}
                    </ul>
                </details>
            )}
        </div>
    );
}

function SequenceFormulaExample({ start, padding }: { readonly start: number; readonly padding: number }): JSX.Element {
    const example: SequenceRenameInput = {
        Base: "Login {n}",
        Start: start,
        Padding: padding,
        Separator: "",
    };
    const samples = [0, 1, 2].map(i => renderSequenceName(example, i));
    return (
        <p
            className="mt-2 text-[11px] text-muted-foreground"
            data-testid="keyword-events-bulk-rename-formula-example"
        >
            Example with current Start ({start}) &amp; Padding ({padding}):{" "}
            <code className="rounded bg-muted px-1 py-0.5">Login {"{n}"}</code> →{" "}
            <code className="rounded bg-muted px-1 py-0.5">{samples.join(", ")}</code>
        </p>
    );
}
