                                    >
                                        {c}
                                    </Badge>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
                <DialogFooter className="gap-2 sm:gap-2">
                    <Button variant="ghost" onClick={() => onOpenChange(false)}>Cancel</Button>
                    <Button
                        variant="outline"
                        onClick={handleClear}
                        data-testid="keyword-events-bulk-category-clear"
                    >
                        Clear category
                    </Button>
                    <Button
                        onClick={handleSet}
                        disabled={normalised === undefined}
