/*  Live chain timeline log                                            */
/* ------------------------------------------------------------------ */

interface ChainTimelineLogProps {
    readonly timeline: TimelineState;
    readonly running: boolean;
}

/**
 * Live progress log rendered between the chain controls and the editor
 * list. Hidden when no chain has ever run so the panel stays compact.
 * Auto-scrolls to the newest entry while a chain is running so users see
 * the active step without manual scrolling.
 */
function ChainTimelineLog(props: ChainTimelineLogProps): JSX.Element | null {
    const { timeline, running } = props;
    const scrollerRef = useRef<HTMLDivElement | null>(null);

    // Auto-scroll to the bottom whenever the entry count changes — but
    // only while the chain is live, so users can scroll back through a
    // finished log without being yanked to the end.
    useEffect(() => {
        if (!running) { return; }
        const el = scrollerRef.current;
        if (el === null) { return; }
        el.scrollTop = el.scrollHeight;
    }, [running, timeline.Entries.length]);

    if (timeline.StartedAtMs === null && timeline.Entries.length === 0) {
        return null;
    }

    return (
        <div
            className="rounded-md border border-border bg-muted/20 p-2 space-y-1.5"
            data-testid="keyword-event-chain-timeline"
        >
            <div className="flex items-center gap-2 px-1">
                <ListOrdered className="h-3.5 w-3.5 text-muted-foreground" />
                <span className="text-xs font-medium text-muted-foreground">
                    Chain timeline
                </span>
                {running && (
                    <Badge
                        variant="outline"
                        className="text-[9px] border-primary/60 text-primary animate-pulse ml-1"
                    >
                        Live
                    </Badge>
                )}
                <span className="ml-auto text-[10px] text-muted-foreground tabular-nums">
                    {timeline.Entries.length} {timeline.Entries.length === 1 ? "entry" : "entries"}
                </span>
            </div>
            <div
                ref={scrollerRef}
                className="max-h-32 overflow-y-auto rounded bg-background/50 px-2 py-1.5 font-mono text-[11px] leading-5"
                data-testid="keyword-event-chain-timeline-scroll"
            >
                {timeline.Entries.map((e) => (
                    <TimelineRow key={e.Id} entry={e} />
                ))}
            </div>
        </div>
    );
}

function formatOffset(ms: number): string {
    const total = Math.max(0, Math.floor(ms));
    const seconds = Math.floor(total / 1000);
    const remainder = total % 1000;
    const padded = remainder.toString().padStart(3, "0");
    return `${seconds.toString().padStart(2, "0")}.${padded}s`;
}

interface TimelineRowProps {
    readonly entry: TimelineEntry;
}

function TimelineRow(props: TimelineRowProps): JSX.Element {
    const { entry } = props;
    const offset = formatOffset(entry.AtMs);

    if (entry.Kind === "EventStart") {
        return (
            <div className="flex items-start gap-2 text-foreground" data-testid="timeline-event-start">
                <span className="text-muted-foreground tabular-nums">{offset}</span>
                <Play className="h-3 w-3 mt-0.5 text-primary shrink-0" />
                <span className="truncate">
                    <span className="text-muted-foreground">[{entry.Index + 1}/{entry.Total}]</span>{" "}
                    <span className="font-semibold">{entry.Keyword}</span>
                </span>
            </div>
        );
    }
    if (entry.Kind === "Step") {
        return (
            <div className="flex items-start gap-2 text-muted-foreground pl-3" data-testid="timeline-step">
                <span className="tabular-nums">{offset}</span>
                <Circle className="h-2.5 w-2.5 mt-1 text-muted-foreground/70 shrink-0" />
                <span className="truncate">
                    <span className="opacity-70">#{entry.StepIndex + 1}</span>{" "}
                    {entry.Label}
                </span>
            </div>
        );
    }
    if (entry.Kind === "EventEnd") {
        const Icon = entry.Aborted ? XCircle : entry.Completed ? CheckCircle2 : XCircle;
        const tone = entry.Aborted
            ? "text-destructive"
            : entry.Completed ? "text-emerald-500" : "text-destructive";
        const label = entry.Aborted ? "aborted" : entry.Completed ? "done" : "failed";
        return (
            <div className="flex items-start gap-2" data-testid="timeline-event-end">
                <span className="text-muted-foreground tabular-nums">{offset}</span>
                <Icon className={cn("h-3 w-3 mt-0.5 shrink-0", tone)} />
                <span className={cn("truncate", tone)}>
                    <span className="font-semibold">{entry.Keyword}</span> {label}
                </span>
            </div>
        );
    }
    // ChainEnd
    const tone = entry.Aborted ? "text-destructive" : "text-emerald-500";
    return (
        <div className="flex items-start gap-2 mt-1" data-testid="timeline-chain-end">
            <span className="text-muted-foreground tabular-nums">{offset}</span>
            <Square className="h-3 w-3 mt-0.5 text-muted-foreground shrink-0" />
            <span className={cn("truncate font-semibold", tone)}>
                Chain {entry.Aborted ? "aborted" : "complete"} — {entry.Completed}/{entry.Attempted}
            </span>
        </div>
    );
}

interface KeywordEventCardProps {
    readonly event: import("@/hooks/use-keyword-events").KeywordEvent;
    readonly isRunning: boolean;
    readonly currentStepIndex: number | null;
    readonly onPlay: () => void;
    readonly onCancel: () => void;
    readonly onRemove: () => void;
    readonly onUpdate: (patch: Partial<Omit<import("@/hooks/use-keyword-events").KeywordEvent, "Id">>) => void;
    readonly onAddStep: (step: Omit<import("@/hooks/use-keyword-events").KeywordEventStep, "Id">) => void;
    readonly onRemoveStep: (stepId: string) => void;
    readonly onMoveStep: (stepId: string, dir: "up" | "down") => void;
    /** Bulk step actions invoked by the per-step right-click context menu. */
    readonly onRemoveSteps: (eventId: string, stepIds: readonly string[]) => void;
    readonly onSetStepsEnabled: (eventId: string, stepIds: readonly string[], enabled: boolean) => void;
    readonly onRelabelSteps: (eventId: string, stepIds: readonly string[], labels: readonly string[]) => void;
    /**
     * Optional drag-handle element rendered at the start of the card header.
     * The sortable wrapper supplies a `<button>` bound to dnd-kit listeners;
     * leaving it `undefined` makes the card non-draggable (used by tests).
     */
    readonly dragHandle?: React.ReactNode;
    /** Whether this event is part of the current multi-selection. */
    readonly selected?: boolean;
    /** Click on the card chrome (not on inputs/buttons). Carries modifiers. */
    readonly onRowClick?: (event: React.MouseEvent<HTMLDivElement>) => void;
    /** Toggle this event's checkbox. Receives the source mouse event so the
     *  parent can honour Shift to extend a range from the anchor. */
    readonly onToggleSelect?: (checked: boolean, mouseEvent?: React.MouseEvent<HTMLButtonElement>) => void;
}

function KeywordEventCard(props: KeywordEventCardProps): JSX.Element {
    const {
        event, isRunning, currentStepIndex,
        onPlay, onCancel, onRemove, onUpdate, onAddStep, onRemoveStep, onMoveStep,
        onRemoveSteps, onSetStepsEnabled, onRelabelSteps,
        dragHandle, selected, onRowClick, onToggleSelect,
    } = props;
    const [keyCombo, setKeyCombo] = useState("");
    const [waitMs, setWaitMs] = useState("500");

    // Per-event step multi-selection. Scoped to this card so each event
    // tracks its own anchor — selecting a step in one event must not
    // change the selection in another.
    const stepIds = event.Steps.map(s => s.Id);
    const stepSelection = useShiftClickSelection(stepIds);
    const isMacRow = typeof navigator !== "undefined" && /Mac|iPhone|iPad/i.test(navigator.platform);
    const handleStepRowClick = (sid: string, ev: React.MouseEvent): void => {
        if ((ev.target as HTMLElement | null)?.closest("button,input,textarea,select,label")) return;
        stepSelection.handleClick(sid, modifiersFromMouseEvent(ev.nativeEvent, isMacRow));
    };

    // Live validation drives both inline messages and the disabled state of
    // the Run button + the per-step Add buttons.
    const comboValidation = validateCombo(keyCombo);
    const waitValidation = validateWait(waitMs);
    const stepIssues = validateEventSteps(event);
    const issuesByIndex = new Map(stepIssues.map(i => [i.Index, i] as const));
    const runnable = isEventRunnable(event);
    const runDisabledReason: string | null = !event.Enabled
        ? "Event is disabled"
        : event.Steps.length === 0
            ? "Add at least one step"
            : stepIssues.length > 0
                ? `${stepIssues.length} step${stepIssues.length === 1 ? "" : "s"} need${stepIssues.length === 1 ? "s" : ""} fixing`
                : null;

    return (
        <div
            className={cn(
                "rounded-md border border-border bg-card/60 p-3 space-y-3 transition-shadow",
                isRunning && "ring-2 ring-primary shadow-[0_0_0_1px_hsl(var(--primary)/0.3)]",
                stepIssues.length > 0 && !isRunning && "border-destructive/50",
                selected && "ring-2 ring-primary/60 bg-primary/5",
            )}
            data-testid={`keyword-event-${event.Id}`}
            data-selected={selected ? "true" : undefined}
            onClick={onRowClick}
        >
            <div className="flex items-center gap-2">
                {dragHandle}
                {onToggleSelect && (
                    <Checkbox
                        checked={!!selected}
                        onClick={(e) => {
                            e.stopPropagation();
                            onToggleSelect(!selected, e as React.MouseEvent<HTMLButtonElement>);
                        }}
                        aria-label={`Select ${event.Keyword}`}
                        data-testid={`keyword-event-select-${event.Id}`}
                    />
                )}
                <Input
                    value={event.Keyword}
                    onChange={e => onUpdate({ Keyword: e.target.value })}
                    className="h-8 font-medium"
                    aria-label="Keyword"
                />
                <div className="flex items-center gap-1.5">
                    <Switch
                        checked={event.Enabled}
                        onCheckedChange={v => onUpdate({ Enabled: v })}
                        aria-label="Enabled"
                    />
                    <Label className="text-xs text-muted-foreground">{event.Enabled ? "On" : "Off"}</Label>
                </div>
                {isRunning ? (
                    <Button
                        size="sm"
                        variant="destructive"
                        className="h-8"
                        onClick={onCancel}
                        data-testid={`keyword-event-stop-${event.Id}`}
                        aria-label="Stop keyword event playback"
                    >
                        <Square className="h-3.5 w-3.5 mr-1" /> Stop
                    </Button>
                ) : (
                    <Button
                        size="sm"
                        variant="secondary"
                        className="h-8"
                        onClick={onPlay}
                        disabled={!runnable}
                        data-testid={`keyword-event-play-${event.Id}`}
                        aria-label="Run keyword event"
                        title={runDisabledReason ?? "Run this keyword event"}
                    >
                        <Play className="h-3.5 w-3.5 mr-1" /> Run
                    </Button>
                )}
                <Button size="icon" variant="ghost" className="h-8 w-8 text-destructive" onClick={onRemove} aria-label="Remove keyword event">
                    <Trash2 className="h-4 w-4" />
                </Button>
            </div>

            {isRunning && currentStepIndex !== null && currentStepIndex >= 0 && currentStepIndex < event.Steps.length && (
                <LiveDispatchPreview
                    eventId={event.Id}
                    step={event.Steps[currentStepIndex]}
                    stepIndex={currentStepIndex}
                    totalSteps={event.Steps.length}
                />
            )}

            <Input
                value={event.Description}
                onChange={e => onUpdate({ Description: e.target.value })}
                placeholder="Optional description"
                className="h-8 text-xs"
            />

            <TargetPickerRow
                eventId={event.Id}
                value={event.Target ?? DEFAULT_KEYWORD_EVENT_TARGET}
                onChange={(next) => onUpdate({ Target: next })}
            />

            <PauseAfterRow
                eventId={event.Id}
                value={event.PauseAfterMs}
                onChange={(next) => onUpdate({ PauseAfterMs: next })}
            />

            {stepIssues.length > 0 && (
                <p
                    className="text-[10px] text-destructive"
                    role="status"
                    data-testid={`keyword-event-issues-${event.Id}`}
                >
                    {stepIssues.length} step{stepIssues.length === 1 ? "" : "s"} need{stepIssues.length === 1 ? "s" : ""} fixing — Run is disabled until resolved.
                </p>
            )}

            <div className="space-y-1.5">
                {event.Steps.length === 0 && (
                    <p className="text-xs text-muted-foreground italic">No steps yet — add a key press or wait below.</p>
                )}
                {stepSelection.selected.size > 0 && (
                    <div
                        className="flex items-center gap-2 rounded border border-border/60 bg-muted/30 px-2 py-1 text-[10px]"
                        data-testid={`keyword-event-step-selection-toolbar-${event.Id}`}
                    >
                        <span className="font-medium" data-testid={`keyword-event-step-selection-count-${event.Id}`}>
                            {stepSelection.selected.size} step{stepSelection.selected.size === 1 ? "" : "s"} selected
                        </span>
                        <Button
                            size="sm"
                            variant="ghost"
                            className="ml-auto h-5 px-1.5 text-[10px]"
                            onClick={(e) => { e.stopPropagation(); stepSelection.clear(); }}
                            data-testid={`keyword-event-step-selection-clear-${event.Id}`}
                        >
                            Clear
                        </Button>
                    </div>
                )}
                {/* eslint-disable-next-line max-lines-per-function -- step row + context-menu wrapper kept inline for selection scope */}
                {event.Steps.map((s, i) => {
                    const issue = issuesByIndex.get(i);
                    const stepSelected = stepSelection.isSelected(s.Id);
                    const stepDisabled = s.Enabled === false;
                    return (
                        <KeywordEventStepContextMenu
                            key={s.Id}
                            step={s}
                            event={event}
                            selectedStepIds={stepSelection.selected}
                            onSetEnabled={onSetStepsEnabled}
                            onRemove={onRemoveSteps}
                            onRelabel={onRelabelSteps}
                            onAfterRemove={() => stepSelection.clear()}
                            onContextOpenForUnselected={() => {
                                stepSelection.handleClick(s.Id, { shiftKey: false, toggleKey: false });
                            }}
                        >
                        <div
                            className={cn(
                                "flex flex-col gap-0.5 rounded bg-muted/40 px-2 py-1.5 text-xs transition-colors cursor-pointer",
                                currentStepIndex === i && "bg-primary/15 ring-1 ring-primary/40",
                                issue && "bg-destructive/10 ring-1 ring-destructive/40",
                                stepSelected && "bg-primary/20 ring-1 ring-primary/60",
                                stepDisabled && "opacity-60",
                            )}
                            data-testid={`keyword-event-step-${event.Id}-${i}`}
                            data-invalid={issue ? "true" : undefined}
                            data-selected={stepSelected ? "true" : undefined}
                            data-step-disabled={stepDisabled ? "true" : undefined}
                            onClick={(e) => { e.stopPropagation(); handleStepRowClick(s.Id, e); }}
                        >
                            <div className="flex items-center gap-2">
                                <Checkbox
                                    checked={stepSelected}
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        const me = e as React.MouseEvent<HTMLButtonElement>;
                                        if (me.shiftKey) {
                                            stepSelection.handleClick(s.Id, { shiftKey: true, toggleKey: false });
                                        } else {
                                            stepSelection.handleClick(s.Id, { shiftKey: false, toggleKey: true });
                                        }
                                    }}
                                    aria-label={`Select step ${i + 1}`}
                                    data-testid={`keyword-event-step-select-${event.Id}-${i}`}
                                    className="h-3.5 w-3.5"
                                />
                                <Badge variant="outline" className="text-[10px] w-6 justify-center">{i + 1}</Badge>
                                {s.Label && (
                                    <Badge
                                        variant="secondary"
                                        className="text-[10px] px-1.5"
                                        data-testid={`keyword-event-step-label-${event.Id}-${i}`}
                                    >
                                        {s.Label}
                                    </Badge>
                                )}
                                {s.Kind === "Key" ? (
                                    <>
                                        <Keyboard className={cn("h-3.5 w-3.5", issue ? "text-destructive" : "text-primary")} />
                                        <code className="font-mono">{s.Combo || <span className="italic opacity-70">(empty)</span>}</code>
                                    </>
                                ) : (
                                    <>
                                        <Clock className={cn("h-3.5 w-3.5", issue ? "text-destructive" : "text-primary")} />
                                        <span>Wait <strong>{String(s.DurationMs)}</strong> ms</span>
                                    </>
                                )}
                                <div className="ml-auto flex items-center gap-0.5">
                                    <Button size="icon" variant="ghost" className="h-6 w-6" onClick={(e) => { e.stopPropagation(); onMoveStep(s.Id, "up"); }} disabled={i === 0} aria-label="Move step up">
                                        <ArrowUp className="h-3 w-3" />
                                    </Button>
                                    <Button size="icon" variant="ghost" className="h-6 w-6" onClick={(e) => { e.stopPropagation(); onMoveStep(s.Id, "down"); }} disabled={i === event.Steps.length - 1} aria-label="Move step down">
                                        <ArrowDown className="h-3 w-3" />
                                    </Button>
                                    <Button size="icon" variant="ghost" className="h-6 w-6 text-destructive" onClick={(e) => { e.stopPropagation(); onRemoveStep(s.Id); }} aria-label="Remove step">
                                        <Trash2 className="h-3 w-3" />
                                    </Button>
                                </div>
                            </div>
                            {issue && (
                                <p className="text-[10px] text-destructive pl-8">{issue.Message}</p>
                            )}
                        </div>
                        </KeywordEventStepContextMenu>
                    );
                })}
            </div>

            <Separator />

            <div className="grid grid-cols-2 gap-2">
                <div className="space-y-1">
                    <div className="flex items-center gap-1.5">
                        <Input
                            value={keyCombo}
                            onChange={e => setKeyCombo(e.target.value)}
                            placeholder="Enter / Ctrl+Tab"
                            className={cn(
                                "h-8 text-xs",
                                keyCombo.length > 0 && !comboValidation.Valid && "border-destructive focus-visible:ring-destructive",
                            )}
                            aria-label="Key combo"
                            aria-invalid={keyCombo.length > 0 && !comboValidation.Valid ? true : undefined}
                            data-testid={`keyword-event-key-input-${event.Id}`}
                        />
                        <Button
                            size="sm"
                            variant="secondary"
                            className="h-8 shrink-0"
                            disabled={!comboValidation.Valid}
                            onClick={() => {
                                if (!comboValidation.Valid) { return; }
                                onAddStep({ Kind: "Key", Combo: keyCombo.trim() } as Omit<import("@/hooks/use-keyword-events").KeywordEventStep, "Id">);
                                setKeyCombo("");
                            }}
                            data-testid={`keyword-event-key-add-${event.Id}`}
                            title={comboValidation.Valid ? "Add key step" : comboValidation.Message}
                        >
                            <Plus className="h-3 w-3 mr-1" /> Key
                        </Button>
                    </div>
                    {keyCombo.length > 0 && !comboValidation.Valid && (
                        <p
                            className="text-[10px] text-destructive"
                            data-testid={`keyword-event-key-error-${event.Id}`}
                        >
                            {comboValidation.Message}
                        </p>
                    )}
                </div>
                <div className="space-y-1">
                    <div className="flex items-center gap-1.5">
                        <Input
                            type="number"
                            min={0}
                            value={waitMs}
                            onChange={e => setWaitMs(e.target.value)}
                            placeholder="ms"
                            className={cn(
                                "h-8 text-xs",
                                !waitValidation.Valid && "border-destructive focus-visible:ring-destructive",
                            )}
                            aria-label="Wait duration in milliseconds"
                            aria-invalid={!waitValidation.Valid ? true : undefined}
                            data-testid={`keyword-event-wait-input-${event.Id}`}
                        />
                        <Button
                            size="sm"
                            variant="secondary"
                            className="h-8 shrink-0"
                            disabled={!waitValidation.Valid}
                            onClick={() => {
                                if (!waitValidation.Valid) { return; }
                                onAddStep({ Kind: "Wait", DurationMs: waitValidation.Ms } as Omit<import("@/hooks/use-keyword-events").KeywordEventStep, "Id">);
                            }}
                            data-testid={`keyword-event-wait-add-${event.Id}`}
                            title={waitValidation.Valid ? "Add wait step" : waitValidation.Message}
                        >
                            <Plus className="h-3 w-3 mr-1" /> Wait
                        </Button>
                    </div>
                    {!waitValidation.Valid && (
                        <p
                            className="text-[10px] text-destructive"
                            data-testid={`keyword-event-wait-error-${event.Id}`}
                        >
                            {waitValidation.Message}
                        </p>
                    )}
                </div>
            </div>
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  Per-event target picker                                            */
/* ------------------------------------------------------------------ */

interface TargetPickerRowProps {
    readonly eventId: string;
    readonly value: KeywordEventTarget;
    readonly onChange: (next: KeywordEventTarget) => void;
}

/**
 * Three-mode target picker. When `Selector` is chosen we render a CSS
 * selector input below the picker and live-validate it via
 * `document.querySelector` so users see an inline error before they hit
 * Run. The check is wrapped in try/catch because invalid CSS throws.
 */
function TargetPickerRow(props: TargetPickerRowProps): JSX.Element {
    const { eventId, value, onChange } = props;
    const isSelector = value.Kind === "Selector";
    const selectorText = isSelector ? value.Selector : "";

    const handleKindChange = (raw: string): void => {
        if (raw === "ActiveElement" || raw === "Body") {
            onChange({ Kind: raw });
            return;
        }
        if (raw === "Selector") {
            onChange({ Kind: "Selector", Selector: selectorText });
        }
    };

    // Live selector check — distinguishes "syntactically invalid" (red) from
    // "valid but matches nothing" (amber) from "matches" (green).
    const selectorStatus: "empty" | "invalid" | "no-match" | "match" = (() => {
        if (!isSelector) { return "empty"; }
        const trimmed = selectorText.trim();
        if (trimmed === "") { return "empty"; }
        if (typeof document === "undefined") { return "no-match"; }
        try {
            const node = document.querySelector(trimmed);
            return node === null ? "no-match" : "match";
        } catch {
            return "invalid";
        }
    })();

    return (
        <div
            className="rounded border border-border/60 bg-muted/20 p-2 space-y-1.5"
            data-testid={`keyword-event-target-${eventId}`}
        >
            <div className="flex items-center gap-2">
                <Target className="h-3.5 w-3.5 text-muted-foreground" />
                <Label className="text-xs font-medium">Dispatch target</Label>
                <Select value={value.Kind} onValueChange={handleKindChange}>
                    <SelectTrigger
                        className="h-7 w-44 text-xs ml-auto"
                        data-testid={`keyword-event-target-kind-${eventId}`}
                        aria-label="Dispatch target"
                    >
                        <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="ActiveElement">
                            <span className="inline-flex items-center gap-2">
                                <Crosshair className="h-3 w-3" /> Active element
                            </span>
                        </SelectItem>
                        <SelectItem value="Body">
                            <span className="inline-flex items-center gap-2">
                                <Target className="h-3 w-3" /> document.body
                            </span>
                        </SelectItem>
                        <SelectItem value="Selector">
                            <span className="inline-flex items-center gap-2">
                                <Keyboard className="h-3 w-3" /> CSS selector…
                            </span>
                        </SelectItem>
                    </SelectContent>
                </Select>
            </div>
            {isSelector ? (
                <div className="space-y-1">
                    <Input
                        value={selectorText}
                        onChange={(e) => onChange({ Kind: "Selector", Selector: e.target.value })}
                        placeholder="#chat-input, textarea[name='msg'], …"
                        className={cn(
                            "h-7 text-xs font-mono",
                            selectorStatus === "invalid" && "border-destructive focus-visible:ring-destructive",
                            selectorStatus === "no-match" && "border-amber-500/60",
                            selectorStatus === "match" && "border-emerald-500/60",
                        )}
                        aria-label="CSS selector for dispatch target"
                        aria-invalid={selectorStatus === "invalid" ? true : undefined}
                        data-testid={`keyword-event-target-selector-${eventId}`}
                        data-status={selectorStatus}
                    />
                    {selectorStatus === "invalid" ? (
                        <p className="text-[10px] text-destructive">Invalid CSS selector — playback will fall back to document.body.</p>
                    ) : selectorStatus === "no-match" ? (
                        <p className="text-[10px] text-amber-500">No element matches yet — playback will fall back to document.body if still unmatched.</p>
                    ) : selectorStatus === "match" ? (
                        <p className="text-[10px] text-emerald-500">Matches an element on the current page.</p>
                    ) : (
                        <p className="text-[10px] text-muted-foreground">Enter a CSS selector for the dispatch target.</p>
                    )}
                </div>
            ) : (
                <p className="text-[10px] text-muted-foreground">
                    {value.Kind === "ActiveElement"
                        ? "Dispatches on whichever element has focus when playback runs."
                        : "Dispatches directly on document.body — useful for global hotkey listeners."}
                </p>
            )}
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  Live dispatch preview                                              */
/* ------------------------------------------------------------------ */

interface LiveDispatchPreviewProps {
    readonly eventId: string;
    readonly step: import("@/hooks/use-keyword-events").KeywordEventStep;
    readonly stepIndex: number;
    readonly totalSteps: number;
}

/**
 * Pill rendered beneath the card header while playback is running. Shows
 * the modifiers + key currently being dispatched (or the wait duration when
 * the active step is a Wait), plus a step counter so the user can correlate
 * with the step list below.
 */
function LiveDispatchPreview(props: LiveDispatchPreviewProps): JSX.Element {
    const { eventId, step, stepIndex, totalSteps } = props;
    const preview: DispatchPreview = buildDispatchPreview(step);
    const ariaLabel = `Now dispatching: ${previewToString(preview)}`;

    return (
        <div
            className={cn(
                "flex items-center gap-2 rounded-md border border-primary/40 bg-primary/10",
                "px-2.5 py-1.5 text-xs animate-in fade-in slide-in-from-top-1",
            )}
            role="status"
            aria-live="polite"
            aria-label={ariaLabel}
            data-testid={`keyword-event-live-preview-${eventId}`}
            data-step-index={stepIndex}
            data-step-kind={preview.Kind}
        >
            <span className="relative flex h-2 w-2 shrink-0">
                <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-primary/60" />
                <span className="relative inline-flex h-2 w-2 rounded-full bg-primary" />
            </span>
            <span className="text-[10px] uppercase tracking-wide text-muted-foreground shrink-0">
                Dispatching
            </span>
            {preview.Kind === "Key" ? (
                <div
                    className="flex items-center gap-1 flex-wrap"
                    data-testid={`keyword-event-live-preview-keys-${eventId}`}
                >
                    {preview.Modifiers.map((mod) => (
                        <kbd
                            key={mod}
                            className="px-1.5 py-0.5 rounded bg-background border border-border font-mono text-[10px] shadow-sm"
                            data-testid={`keyword-event-live-preview-mod-${eventId}-${mod}`}
                        >
                            {mod}
                        </kbd>
                    ))}
                    {preview.Modifiers.length > 0 && preview.HasKey && (
                        <span className="text-muted-foreground text-[10px]">+</span>
                    )}
                    {preview.HasKey ? (
                        <kbd
                            className="px-1.5 py-0.5 rounded bg-primary/20 border border-primary/50 font-mono text-[10px] text-primary-foreground shadow-sm"
                            data-testid={`keyword-event-live-preview-key-${eventId}`}
                        >
                            {preview.Key}
                        </kbd>
                    ) : (
                        <span
                            className="text-[10px] italic text-destructive"
                            data-testid={`keyword-event-live-preview-empty-${eventId}`}
                        >
                            (no key)
                        </span>
                    )}
                </div>
            ) : (
                <div
                    className="flex items-center gap-1.5"
                    data-testid={`keyword-event-live-preview-wait-${eventId}`}
                >
                    <Clock className="h-3 w-3 text-primary" />
                    <span className="font-mono text-[11px]">
                        Wait <strong>{preview.DurationMs}</strong> ms
                    </span>
                </div>
            )}
            <span className="ml-auto text-[10px] text-muted-foreground shrink-0">
                Step {stepIndex + 1} / {totalSteps}
            </span>
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  Sortable wrapper                                                   */
/* ------------------------------------------------------------------ */

/**
 * Wraps {@link KeywordEventCard} with `useSortable` so the parent list
 * can render it inside a `SortableContext`. Supplies a `<button>` drag
 * handle (rendered inside the card header) bound to dnd-kit listeners —
 * the rest of the card body stays interactive (Run, inputs, switches).
 */
function SortableKeywordEventCard(props: KeywordEventCardProps): JSX.Element {
    const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
        id: props.event.Id,
    });

    const style: React.CSSProperties = {
        transform: CSS.Transform.toString(transform),
        transition,
        opacity: isDragging ? 0.6 : 1,
        zIndex: isDragging ? 10 : undefined,
    };

    const handle = (
        <button
            type="button"
            className={cn(
                "shrink-0 inline-flex items-center justify-center h-8 w-6 rounded",
                "text-muted-foreground hover:text-foreground hover:bg-muted/50",
                "cursor-grab active:cursor-grabbing touch-none",
                "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary",
            )}
            aria-label={`Drag to reorder ${props.event.Keyword}`}
            data-testid={`keyword-event-drag-handle-${props.event.Id}`}
            {...attributes}
            {...listeners}
        >
            <GripVertical className="h-4 w-4" />
        </button>
    );

    return (
        <div
            ref={setNodeRef}
            style={style}
            data-testid={`keyword-event-sortable-${props.event.Id}`}
            data-dragging={isDragging ? "true" : undefined}
        >
            <KeywordEventCard {...props} dragHandle={handle} />
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  Per-event pause override                                           */
/* ------------------------------------------------------------------ */

interface PauseAfterRowProps {
    readonly eventId: string;
    readonly value: number | undefined;
    readonly onChange: (next: number | undefined) => void;
}

const PAUSE_OVERRIDE_MIN = 0;
const PAUSE_OVERRIDE_MAX = 60_000;

/**
 * Compact row that lets the user opt into a per-event pause override that
 * replaces the chain's global `PauseMs` for the gap *after* this event
 * finishes. When the toggle is off we strip the field (`onChange(undefined)`)
 * so the chain runner falls back to the global value. The numeric input is
 * clamped to the same `[0, 60_000]` ms range as the global setting and
 * exposes both red/amber inline validation and a `data-status` marker for
 * tests.
 */
function PauseAfterRow(props: PauseAfterRowProps): JSX.Element {
    const { eventId, value, onChange } = props;
    const enabled = typeof value === "number" && Number.isFinite(value) && value >= 0;
    const draftRef = useRef<string>(enabled ? String(value) : String(DEFAULT_CHAIN_SETTINGS.PauseMs));
    const [draft, setDraft] = useState<string>(draftRef.current);

    // Keep the draft in sync when the persisted value is changed externally
    // (e.g. another tab updates localStorage and the hook rehydrates).
    useEffect(() => {
        if (enabled && String(value) !== draftRef.current) {
            draftRef.current = String(value);
            setDraft(draftRef.current);
        }
    }, [enabled, value]);

    const parsed = Number(draft);
    const draftValid = draft.trim() !== ""
        && !Number.isNaN(parsed)
        && Number.isFinite(parsed)
        && parsed >= PAUSE_OVERRIDE_MIN
        && parsed <= PAUSE_OVERRIDE_MAX;

    const handleToggle = (checked: boolean): void => {
        if (!checked) {
            onChange(undefined);
            return;
        }
        // Re-enabling restores the last good draft (or the global default).
        const restore = draftValid ? Math.floor(parsed) : DEFAULT_CHAIN_SETTINGS.PauseMs;
        draftRef.current = String(restore);
        setDraft(draftRef.current);
        onChange(restore);
    };

    const handleDraftChange = (raw: string): void => {
        setDraft(raw);
        if (!enabled) { return; }
        const n = Number(raw);
        if (raw.trim() === "" || Number.isNaN(n) || !Number.isFinite(n)) { return; }
        const clamped = Math.max(PAUSE_OVERRIDE_MIN, Math.min(PAUSE_OVERRIDE_MAX, Math.floor(n)));
        draftRef.current = String(clamped);
        onChange(clamped);
    };

    return (
        <div
            className={cn(
                "rounded border border-border/60 bg-muted/20 p-2 space-y-1.5",
                enabled && "border-primary/40",
            )}
            data-testid={`keyword-event-pause-after-${eventId}`}
            data-enabled={enabled ? "true" : "false"}
        >
            <div className="flex items-center gap-2">
                <Clock className="h-3.5 w-3.5 text-muted-foreground" />
                <Label
                    htmlFor={`kev-pause-toggle-${eventId}`}
                    className="text-xs font-medium cursor-pointer"
                >
                    Override chain pause after this event
                </Label>
                <Switch
                    id={`kev-pause-toggle-${eventId}`}
                    checked={enabled}
                    onCheckedChange={handleToggle}
                    aria-label="Override chain pause after this event"
                    data-testid={`keyword-event-pause-after-toggle-${eventId}`}
                    className="ml-auto"
                />
            </div>
            {enabled ? (
                <div className="flex items-center gap-2">
                    <Input
                        type="number"
                        min={PAUSE_OVERRIDE_MIN}
                        max={PAUSE_OVERRIDE_MAX}
                        step={50}
                        value={draft}
                        onChange={(e) => handleDraftChange(e.target.value)}
                        className={cn(
                            "h-7 w-24 text-xs",
                            !draftValid && "border-destructive focus-visible:ring-destructive",
                        )}
                        aria-label="Pause after this event in milliseconds"
                        aria-invalid={!draftValid ? true : undefined}
                        data-testid={`keyword-event-pause-after-input-${eventId}`}
                    />
                    <span className="text-[10px] text-muted-foreground">ms</span>
                    <p className="text-[10px] text-muted-foreground ml-auto max-w-xs text-right">
                        {draftValid
                            ? "Replaces the chain's global pause for the gap after this event."
                            : `Enter a number between ${PAUSE_OVERRIDE_MIN} and ${PAUSE_OVERRIDE_MAX}.`}
                    </p>
                </div>
            ) : (
                <p className="text-[10px] text-muted-foreground">
                    Off — uses the chain's global pause setting.
                </p>
            )}
        </div>
    );
}

/**
 * Marco Extension — Live Recorded Actions Tree
 *
 * Real-time view of `session.Steps` from the active {@link useRecordingSession}.
 * Renders the in-flight steps (Click / Type / Select / Submit / Wait / JsInline)
 * as a clickable list inside the Floating Controller's Expanded mode. Updates
 * automatically as the recorder appends new steps because the source hook
 * re-renders on every storage change.
 *
 * This is intentionally separate from {@link RecorderLiveTreePanel}, which
 * shows the *persisted* Step Group library. This component shows the
 * *transient* draft of the active session — the actions the user is
 * recording right now.
 *
 * ## Selection scroll/highlight contract
 *
 * Selection can be either internal (user clicks a row) or external (the
 * Options page drives `selectedStepId` from the URL / detail panel).
 * Whenever the active selection changes, the matching row is scrolled
 * into view via `scrollIntoView({ block: "nearest" })` and pulses a
 * highlight ring for ~1.2s so the user can locate it without manually
 * scrolling the long action list.
 */

import { useEffect, useMemo, useRef, useState } from "react";
import {
    Clock,
    FileCode2,
    MousePointerClick,
    Send,
    SquareCheck,
    Type as TypeIcon,
} from "lucide-react";

import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import {
    detectTransport,
    subscribeRecorderSession,
    type RecorderSyncTransport,
} from "@/lib/recorder-session-sync";
import type {
    RecordedStep,
    RecordedStepKind,
    RecordingSession,
} from "@/background/recorder/recorder-session-types";

interface KindMeta {
    readonly Icon: typeof MousePointerClick;
    readonly Label: string;
    readonly Tone: string;
}

const KIND_META: Record<RecordedStepKind, KindMeta> = {
    Click:    { Icon: MousePointerClick, Label: "Click",  Tone: "text-primary" },
    Type:     { Icon: TypeIcon,          Label: "Type",   Tone: "text-blue-400" },
    Select:   { Icon: SquareCheck,       Label: "Select", Tone: "text-emerald-400" },
    Submit:   { Icon: Send,              Label: "Submit", Tone: "text-purple-400" },
    Wait:     { Icon: Clock,             Label: "Wait",   Tone: "text-amber-400" },
    JsInline: { Icon: FileCode2,         Label: "JS",     Tone: "text-pink-400" },
};

const HIGHLIGHT_PULSE_MS = 1200;

export interface LiveRecordedActionsTreeProps {
    readonly className?: string;
    readonly onStepClick?: (step: RecordedStep) => void;
    /**
     * Controlled selection. When provided, the tree treats this StepId as the
     * active selection (Options page passes the StepId currently shown in the
     * detail panel). Internal click selection is still honored when this is
     * `null` or `undefined`.
     */
    readonly selectedStepId?: string | null;
}

export function LiveRecordedActionsTree(props: LiveRecordedActionsTreeProps): JSX.Element {
    const { className, onStepClick, selectedStepId: controlledStepId } = props;

    // Subscribe directly to the shared backend transport so this tree
    // stays in lockstep with the active session even if no parent
    // (Options page, Floating Controller) is currently mounted.
    const [session, setSession] = useState<RecordingSession | null>(null);
    const [transport, setTransport] = useState<RecorderSyncTransport>(() => detectTransport());
    useEffect(() => {
        setTransport(detectTransport());
        return subscribeRecorderSession(setSession);
    }, []);

    const steps = session?.Steps ?? [];
    const [internalStepId, setInternalStepId] = useState<string | null>(null);

    // Controlled selection wins over internal clicks so the Options page can
    // drive which row is highlighted without extra plumbing.
    const activeStepId = useMemo<string | null>(() => {
        if (controlledStepId !== undefined && controlledStepId !== null) { return controlledStepId; }
        return internalStepId;
    }, [controlledStepId, internalStepId]);

    // ─────────────────────────────────────────────────────────────────────
    // Refs: one per row so we can scroll the matching row into view.
    // The map is rebuilt each render via the callback ref pattern; rows that
    // unmount remove themselves automatically.
    // ─────────────────────────────────────────────────────────────────────
    const scrollRef = useRef<HTMLDivElement | null>(null);
    const rowRefs = useRef<Map<string, HTMLLIElement>>(new Map());
    const setRowRef = (stepId: string) => (node: HTMLLIElement | null): void => {
        if (node === null) { rowRefs.current.delete(stepId); return; }
        rowRefs.current.set(stepId, node);
    };

    // Auto-scroll to the latest step when a new one arrives so the user
    // always sees the most recent action without manual scrolling. Only fires
    // when the user has not pinned a specific selection; otherwise the
    // selection-scroll effect below takes precedence.
    const lastCountRef = useRef<number>(0);
    useEffect(() => {
        if (activeStepId === null && steps.length > lastCountRef.current) {
            const node = scrollRef.current;
            if (node !== null) { node.scrollTop = node.scrollHeight; }
        }
        lastCountRef.current = steps.length;
    }, [steps.length, activeStepId]);

    // Selection scroll + highlight pulse. Runs whenever the active selection
    // changes (internal click OR controlled prop change) so the matching row
    // is always visible regardless of how it was selected. Also re-runs when
    // the underlying step list grows so a controlled selection set *before*
    // the session loaded still gets scrolled/pulsed once its row mounts.
    const [pulseStepId, setPulseStepId] = useState<string | null>(null);
    useEffect(() => {
        if (activeStepId === null) { return; }
        const node = rowRefs.current.get(activeStepId);
        if (node === undefined) { return; }
        // `block: "nearest"` keeps the row visible without jumping if it's
        // already in view, which avoids jitter when the user clicks a visible row.
        node.scrollIntoView({ block: "nearest", behavior: "smooth" });
        setPulseStepId(activeStepId);
        const timer = window.setTimeout(() => { setPulseStepId(null); }, HIGHLIGHT_PULSE_MS);
        return () => { window.clearTimeout(timer); };
    }, [activeStepId, steps.length]);

    const isRecording = session?.Phase === "Recording";
    const isPaused = session?.Phase === "Paused";


    return (
        <div
            className={cn(
                "rounded-md border border-border/60 bg-background/40 p-2 space-y-1.5",
                className,
            )}
            data-testid="live-recorded-actions-tree"
        >
            <div className="flex items-center justify-between text-[10px] uppercase tracking-wider text-muted-foreground px-1">
                <div className="flex items-center gap-1.5">
                    <span
                        className={cn(
                            "h-1.5 w-1.5 rounded-full",
                            isRecording ? "bg-destructive animate-pulse" :
                            isPaused ? "bg-amber-400" : "bg-muted",
                        )}
                        aria-hidden
                    />
                    <span>Live actions</span>
                </div>
                <div className="flex items-center gap-1">
                    <Badge
                        variant="outline"
                        className={cn(
                            "text-[9px] px-1 py-0 font-mono",
                            transport === "chrome.storage" && "border-emerald-400/40 text-emerald-400",
                            transport === "memory" && "border-amber-400/40 text-amber-400",
                        )}
                        title={`Live transport: ${transport}`}
                        data-testid="live-actions-transport"
                    >
                        {transport === "chrome.storage" ? "ext" : transport === "localStorage" ? "preview" : "mem"}
                    </Badge>
                    <Badge variant="outline" className="text-[10px] px-1.5 py-0">
                        {steps.length}
                    </Badge>
                </div>
            </div>

            <ScrollArea className="h-[180px]">
                <div ref={scrollRef} className="pr-2">
                    {steps.length === 0 ? (
                        <p className="text-[11px] text-muted-foreground text-center py-6 italic">
                            {session === null
                                ? "No active session — press Play to start recording."
                                : "Waiting for the first action…"}
                        </p>
                    ) : (
                        <ul className="space-y-1" role="tree" aria-label="Recorded actions">
                            {steps.map((step) => (
                                <ActionRow
                                    key={step.StepId}
                                    rowRef={setRowRef(step.StepId)}
                                    step={step}
                                    selected={activeStepId === step.StepId}
                                    pulsing={pulseStepId === step.StepId}
                                    onClick={() => {
                                        setInternalStepId(step.StepId);
                                        onStepClick?.(step);
                                    }}
                                />
                            ))}
                        </ul>
                    )}
                </div>
            </ScrollArea>
        </div>
    );
}

interface ActionRowProps {
    readonly step: RecordedStep;
    readonly selected: boolean;
    readonly pulsing: boolean;
    readonly onClick: () => void;
    readonly rowRef: (node: HTMLLIElement | null) => void;
}

function ActionRow(props: ActionRowProps): JSX.Element {
    const { step, selected, pulsing, onClick, rowRef } = props;
    const meta = KIND_META[step.Kind];
    const Icon = meta.Icon;
    const selectorPreview = step.Selector?.XPathRelative ?? step.Selector?.XPathFull ?? "";

    return (
        <li
            ref={rowRef}
            role="treeitem"
            aria-selected={selected}
            data-step-id={step.StepId}
            data-pulsing={pulsing ? "true" : undefined}
        >
            <button
                type="button"
                onClick={onClick}
                className={cn(
                    "w-full text-left flex items-start gap-2 rounded px-1.5 py-1 text-[11px]",
                    "hover:bg-primary/10 transition-colors",
                    selected && "bg-primary/15 ring-1 ring-primary/40",
                    pulsing && "ring-2 ring-primary animate-pulse",
                )}
                data-testid={`live-action-${step.StepId}`}
                title={selectorPreview}
            >
                <Badge variant="outline" className="text-[9px] w-5 justify-center shrink-0 mt-0.5">
                    {step.Index + 1}
                </Badge>
                <Icon className={cn("h-3.5 w-3.5 shrink-0 mt-0.5", meta.Tone)} />
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                        <span className="font-medium">{meta.Label}</span>
                        {step.VariableName ? (
                            <code className="text-[10px] text-muted-foreground font-mono truncate">
                                ${step.VariableName}
                            </code>
                        ) : null}
                    </div>
                    <div className="text-[10px] text-muted-foreground truncate">
                        {step.Label || selectorPreview || "—"}
                    </div>
                </div>
            </button>
        </li>
    );
}

/**
 * Marco Extension — Recorder Control Bar
 *
 * Always-visible Play / Pause / Stop control strip for the recorder. Buttons
 * enable/disable based on the active {@link RecordingSession} phase:
 *
 *   • Play   — enabled when no session OR Phase === "Paused" (acts as Resume)
 *   • Pause  — enabled only when Phase === "Recording"
 *   • Stop   — enabled when a session exists (Recording or Paused)
 *
 * Purely presentational over {@link useRecordingSession}; safe to mount in
 * the Options page or any other surface that wants quick recorder controls.
 */

import { Pause, Play, Square } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { useRecordingSession } from "@/hooks/use-recording-session";
import { KeywordEventsPanel } from "@/components/recorder/KeywordEventsPanel";

export interface RecorderControlBarProps {
    /** Project slug used when starting a fresh session. Defaults to "default". */
    readonly projectSlug?: string;
    readonly className?: string;
}

export function RecorderControlBar(props: RecorderControlBarProps): JSX.Element {
    const { projectSlug, className } = props;
    const { session, start, pause, resume, stop } = useRecordingSession();

    const phase = session?.Phase ?? "Idle";
    const isRecording = phase === "Recording";
    const isPaused = phase === "Paused";
    const isActive = isRecording || isPaused;

    const playEnabled = !isActive || isPaused;
    const pauseEnabled = isRecording;
    const stopEnabled = isActive;

    const handlePlay = () => {
        if (isPaused) { void resume(); return; }
        if (!isActive) { void start(projectSlug); }
    };

    return (
        <div
            className={cn(
                "inline-flex items-center gap-2 rounded-md border border-border bg-card/80 p-1.5",
                className,
            )}
            role="toolbar"
            aria-label="Recorder controls"
            data-testid="recorder-control-bar"
        >
            <Button
                size="sm"
                variant="secondary"
                disabled={!playEnabled}
                onClick={handlePlay}
                className="h-8 px-3"
                aria-label={isPaused ? "Resume recording" : "Start recording"}
                data-testid="recorder-control-play"
            >
                <Play className="h-3.5 w-3.5 mr-1" />
                {isPaused ? "Resume" : "Play"}
            </Button>
            <Button
                size="sm"
                variant="secondary"
                disabled={!pauseEnabled}
                onClick={() => { void pause(); }}
                className="h-8 px-3"
                aria-label="Pause recording"
                data-testid="recorder-control-pause"
            >
                <Pause className="h-3.5 w-3.5 mr-1" />
                Pause
            </Button>
            <Button
                size="sm"
                variant="destructive"
                disabled={!stopEnabled}
                onClick={() => { void stop(); }}
                className="h-8 px-3"
                aria-label="Stop recording"
                data-testid="recorder-control-stop"
            >
                <Square className="h-3.5 w-3.5 mr-1" />
                Stop
            </Button>
            <Badge
                variant="outline"
                className="text-[10px] uppercase tracking-wider ml-1"
                data-testid="recorder-control-phase"
            >
                {phase}
            </Badge>
            <KeywordEventsPanel className="ml-1" />
        </div>
    );
}

/**
 * Marco Extension — Recorder Live Tree Panel
 *
 * Compact in-page tree of `Project → StepGroup → SubGroup → Steps`
 * rendered inside the Floating Controller's Expanded mode. Reads from
 * the same `useStepLibrary` hook as the Options Step Group Library
 * panel, so any step the recorder appends shows up here within one
 * React tick and the Options panel updates in lockstep (both share the
 * same `localStorage`-backed sql.js DB).
 *
 * Selection is broadcast via {@link useRecorderSelection} so clicking
 * a row here also activates the matching row in Options, and clicking
 * in Options highlights the corresponding row here.
 *
 * @see ../../hooks/use-step-library.ts
 * @see ../../hooks/use-recorder-selection.ts
 * @see ./FloatingController.tsx
 */

import { useEffect, useMemo, useState } from "react";
import {
    ChevronDown,
    ChevronRight,
    FolderOpen,
    Folder,
    Layers,
    Search,
    X,
} from "lucide-react";

import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { stepKindLabel, useStepLibrary } from "@/hooks/use-step-library";
import { useRecorderSelection } from "@/hooks/use-recorder-selection";
import { filterLiveTree } from "@/lib/live-tree-filter";
import type { StepGroupRow, StepRow } from "@/background/recorder/step-library/db";

interface TreeNode {
    readonly Group: StepGroupRow;
    readonly Children: TreeNode[];
}

function buildForest(groups: ReadonlyArray<StepGroupRow>): TreeNode[] {
    const byParent = new Map<number | null, StepGroupRow[]>();
    for (const g of groups) {
        const key = g.ParentStepGroupId;
        const list = byParent.get(key) ?? [];
        list.push(g);
        byParent.set(key, list);
    }
    const sortFn = (a: StepGroupRow, b: StepGroupRow) =>
        a.OrderIndex - b.OrderIndex || a.Name.localeCompare(b.Name);
    const build = (parent: number | null): TreeNode[] =>
        (byParent.get(parent) ?? [])
            .slice()
            .sort(sortFn)
            .map((g) => ({ Group: g, Children: build(g.StepGroupId) }));
    return build(null);
}

function defaultExpanded(forest: TreeNode[]): Set<number> {
    // Auto-expand root + first level so the user sees structure
    // without an extra click after the controller opens.
    const set = new Set<number>();
    for (const root of forest) {
        set.add(root.Group.StepGroupId);
        for (const child of root.Children) {
            set.add(child.Group.StepGroupId);
        }
    }
    return set;
}

export function RecorderLiveTreePanel(): JSX.Element {
    const lib = useStepLibrary();
    const { selection, select } = useRecorderSelection("controller");
    const [expanded, setExpanded] = useState<Set<number>>(new Set());
    const [didAutoExpand, setDidAutoExpand] = useState(false);
    const [query, setQuery] = useState("");

    const forest = useMemo(() => buildForest(lib.Groups), [lib.Groups]);

    // Filter the forest by the search query. When the query is empty this
    // returns the original forest at zero cost so the unfiltered render path
    // is unchanged.
    const filtered = useMemo(
        () => filterLiveTree(forest, lib.StepsByGroup, query),
        [forest, lib.StepsByGroup, query],
    );

    const isFiltering = query.trim().length > 0;

    useEffect(() => {
        if (didAutoExpand || forest.length === 0) { return; }
        setExpanded(defaultExpanded(forest));
        setDidAutoExpand(true);
    }, [didAutoExpand, forest]);

    // While filtering, force-expand every ancestor of a match so the user
    // can see results without manual clicking. We *merge* into the user's
    // expansion set instead of replacing it so collapsing-after-clearing
    // restores their previous state.
    useEffect(() => {
        if (!isFiltering) { return; }
        setExpanded((prev) => {
            const next = new Set(prev);
            for (const id of filtered.ExpandIds) { next.add(id); }
            return next;
        });
    }, [isFiltering, filtered.ExpandIds]);

    // When the Options panel selects a group, expand its ancestor chain.
    useEffect(() => {
        if (selection.StepGroupId === null) { return; }
        setExpanded((prev) => {
            const next = new Set(prev);
            let cursor: number | null = selection.StepGroupId;
            const byId = new Map(lib.Groups.map((g) => [g.StepGroupId, g] as const));
            while (cursor !== null) {
                next.add(cursor);
                const row = byId.get(cursor);
                cursor = row?.ParentStepGroupId ?? null;
            }
            return next;
        });
    }, [selection.StepGroupId, lib.Groups]);

    const toggle = (id: number) => {
        setExpanded((prev) => {
            const next = new Set(prev);
            if (next.has(id)) { next.delete(id); } else { next.add(id); }
            return next;
        });
    };

    if (lib.Loading) {
        return <div className="text-[11px] text-muted-foreground p-2">Loading library…</div>;
    }
    if (lib.Project === null) {
        return <div className="text-[11px] text-muted-foreground p-2">No project loaded.</div>;
    }

    const visibleForest = isFiltering ? filtered.Forest : forest;
    const visibleStepsByGroup = isFiltering ? filtered.StepsByGroup : lib.StepsByGroup;

    return (
        <div className="border-t border-border/40 mt-1 pt-1.5">
            <div className="flex items-center gap-1.5 px-1 pb-1">
                <Layers className="h-3 w-3 text-muted-foreground" />
                <span className="text-[10px] uppercase tracking-widest text-muted-foreground">Live tree</span>
                <Badge variant="outline" className="ml-auto text-[9px] px-1">
                    {lib.Groups.length} group{lib.Groups.length === 1 ? "" : "s"}
                </Badge>
            </div>
            <div className="relative px-1 pb-1.5">
                <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3 w-3 text-muted-foreground pointer-events-none" />
                <Input
                    type="search"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Filter groups & steps…"
                    aria-label="Filter live tree"
                    data-testid="live-tree-search"
                    className="h-7 text-[11px] pl-6 pr-7"
                />
                {query.length > 0 ? (
                    <button
                        type="button"
                        onClick={() => setQuery("")}
                        aria-label="Clear filter"
                        data-testid="live-tree-search-clear"
                        className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                    >
                        <X className="h-3 w-3" />
                    </button>
                ) : null}
            </div>
            {isFiltering ? (
                <div
                    className="px-2 pb-1 text-[10px] text-muted-foreground flex items-center justify-between"
                    data-testid="live-tree-search-summary"
                >
                    <span>
                        {filtered.GroupMatchCount} group{filtered.GroupMatchCount === 1 ? "" : "s"},{" "}
                        {filtered.StepMatchCount} step{filtered.StepMatchCount === 1 ? "" : "s"}
                    </span>
                </div>
            ) : null}
            <ScrollArea className="h-[220px] pr-1">
                <div className="px-1 pb-1">
                    {!isFiltering ? (
                        <ProjectRow
                            name={lib.Project.Name}
                            active={selection.StepGroupId === null}
                            onClick={() => select({ StepGroupId: null, StepId: null })}
                        />
                    ) : null}
                    {visibleForest.length === 0 ? (
                        <div
                            className="text-[11px] text-muted-foreground italic px-3 pt-1"
                            data-testid="live-tree-empty"
                        >
                            {isFiltering
                                ? `No matches for "${query.trim()}".`
                                : "No groups yet — recorded steps will appear here."}
                        </div>
                    ) : visibleForest.map((node) => (
                        <GroupNode
                            key={node.Group.StepGroupId}
                            node={node}
                            depth={1}
                            expanded={expanded}
                            onToggle={toggle}
                            selectedGroupId={selection.StepGroupId}
                            selectedStepId={selection.StepId}
                            stepsByGroup={visibleStepsByGroup}
                            onSelect={(payload) => select(payload)}
                        />
                    ))}
                </div>
            </ScrollArea>
        </div>
    );
}

/* ------------------------------------------------------------------ */
/*  Subcomponents                                                      */
/* ------------------------------------------------------------------ */

function ProjectRow(props: { name: string; active: boolean; onClick: () => void }): JSX.Element {
    return (
        <button
            type="button"
            onClick={props.onClick}
            className={cn(
                "w-full flex items-center gap-1.5 px-1.5 py-1 rounded text-left transition-colors",
                "text-[12px]",
                props.active ? "bg-primary/10 text-foreground" : "hover:bg-muted/50 text-foreground",
            )}
            data-testid="controller-tree-project"
        >
            <Folder className="h-3 w-3 text-muted-foreground" />
            <span className="font-medium truncate">{props.name}</span>
        </button>
    );
}

interface GroupNodeProps {
    readonly node: TreeNode;
    readonly depth: number;
    readonly expanded: ReadonlySet<number>;
    readonly onToggle: (id: number) => void;
    readonly selectedGroupId: number | null;
    readonly selectedStepId: number | null;
    readonly stepsByGroup: ReadonlyMap<number, ReadonlyArray<StepRow>>;
    readonly onSelect: (payload: { StepGroupId: number | null; StepId: number | null }) => void;
}

function GroupNode(props: GroupNodeProps): JSX.Element {
    const { node, depth, expanded, onToggle, selectedGroupId, selectedStepId, stepsByGroup, onSelect } = props;
    const isOpen = expanded.has(node.Group.StepGroupId);
    const isActive = selectedGroupId === node.Group.StepGroupId && selectedStepId === null;
    const steps = stepsByGroup.get(node.Group.StepGroupId) ?? [];
    const hasChildren = node.Children.length > 0 || steps.length > 0;
    return (
        <div>
            <div
                className={cn(
                    "flex items-center gap-1 rounded transition-colors group",
                    isActive ? "bg-primary/10" : "hover:bg-muted/40",
                )}
                style={{ paddingLeft: `${depth * 10}px` }}
            >
                <button
                    type="button"
                    onClick={() => onToggle(node.Group.StepGroupId)}
                    className="p-0.5 text-muted-foreground hover:text-foreground"
                    aria-label={isOpen ? "Collapse" : "Expand"}
                    aria-expanded={isOpen}
                    disabled={!hasChildren}
                >
                    {hasChildren
                        ? (isOpen ? <ChevronDown className="h-3 w-3" /> : <ChevronRight className="h-3 w-3" />)
                        : <span className="inline-block w-3" />}
                </button>
                <button
                    type="button"
                    onClick={() => onSelect({ StepGroupId: node.Group.StepGroupId, StepId: null })}
                    className="flex-1 min-w-0 flex items-center gap-1.5 py-0.5 text-left text-[12px]"
                    data-testid={`controller-tree-group-${node.Group.StepGroupId}`}
                >
                    {isOpen ? <FolderOpen className="h-3 w-3 text-muted-foreground" /> : <Folder className="h-3 w-3 text-muted-foreground" />}
                    <span className="truncate">{node.Group.Name}</span>
                    {steps.length > 0 ? (
                        <Badge variant="outline" className="text-[9px] px-1 ml-auto">{steps.length}</Badge>
                    ) : null}
                </button>
            </div>
            {isOpen ? (
                <>
                    {node.Children.map((child) => (
                        <GroupNode
                            key={child.Group.StepGroupId}
                            node={child}
                            depth={depth + 1}
                            expanded={expanded}
                            onToggle={onToggle}
                            selectedGroupId={selectedGroupId}
                            selectedStepId={selectedStepId}
                            stepsByGroup={stepsByGroup}
                            onSelect={onSelect}
                        />
                    ))}
                    {steps.map((step) => (
                        <StepRowNode
                            key={step.StepId}
                            step={step}
                            depth={depth + 1}
                            isActive={selectedStepId === step.StepId}
                            onClick={() => onSelect({ StepGroupId: node.Group.StepGroupId, StepId: step.StepId })}
                        />
                    ))}
                </>
            ) : null}
        </div>
    );
}

function StepRowNode(props: {
    readonly step: StepRow;
    readonly depth: number;
    readonly isActive: boolean;
    readonly onClick: () => void;
}): JSX.Element {
    const { step, depth, isActive, onClick } = props;
    return (
        <button
            type="button"
            onClick={onClick}
            className={cn(
                "w-full flex items-center gap-1.5 py-0.5 rounded text-left text-[11px] transition-colors",
                isActive ? "bg-primary/15 text-foreground" : "hover:bg-muted/40 text-muted-foreground",
            )}
            style={{ paddingLeft: `${depth * 10 + 18}px` }}
            data-testid={`controller-tree-step-${step.StepId}`}
        >
            <Badge variant="secondary" className="text-[9px] px-1 py-0 font-mono">
                {stepKindLabel(step.StepKindId)}
            </Badge>
            <span className="truncate">
                {step.Label ?? `Step #${step.StepId}`}
            </span>
        </button>
    );
}

/**
 * Marco Extension — Selector Comparison Panel
 *
 * Visualises the per-selector outcome of a replay attempt so the user can
 * see at a glance which selector failed and which DOM element (if any) was
 * found. Designed to live next to or inside the failure post-mortem flow.
 *
 * Pure presentation — the comparison itself is computed by
 * `compareSelectorAttempts` (background module). This component only renders
 * the result.
 */

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { CheckCircle2, XCircle, AlertTriangle, Crosshair, FileDown, History, Star } from "lucide-react";
import { toast } from "sonner";
import type { SelectorComparison, SelectorAttemptComparison } from "@/background/recorder/selector-comparison";
import type { DomContext, FailureReport } from "@/background/recorder/failure-logger";
import {
    findHistoryForSelector,
    type SelectorHistoryBucket,
} from "@/background/recorder/selector-history";
import {
    buildSelectorComparisonBundle,
    buildSelectorComparisonFilename,
    serializeSelectorComparisonBundle,
} from "./selector-comparison-export";
import { FailureDetailsPanel } from "./FailureDetailsPanel";

/**
 * Promote-to-primary callback. Host owns persistence (DB write). Returning
 * a rejected promise (or throwing) surfaces an error toast in the panel.
 */
export type PromoteToPrimaryHandler = (selectorId: number) => void | Promise<void>;

interface SelectorComparisonPanelProps {
    readonly comparison: SelectorComparison;
    /** Optional StepId stamped into the export filename + bundle metadata. */
    readonly stepId?: number;
    /** Optional page URL stamped into the export bundle metadata. */
    readonly url?: string;
    /** Per-selector replay history. When supplied the toggle is enabled. */
    readonly history?: ReadonlyArray<SelectorHistoryBucket>;
    /**
     * When supplied, each matching non-primary attempt renders a
     * "Promote to primary" action. The handler is responsible for
     * persisting the change (DB UPDATE) and refreshing the parent state.
     */
    readonly onPromoteToPrimary?: PromoteToPrimaryHandler;
    /**
     * Structured failure report associated with this comparison. When
     * supplied, the full diagnostic surface (Reason, ResolvedXPath, every
     * SelectorAttempt with its FailureReason+Detail, and VariableContext)
     * is rendered inline so the user can see *why* the selector failed
     * without leaving the comparison view.
     */
    readonly failureReport?: FailureReport;
    /** Test seam: override the default download side effect. */
    readonly onDownload?: (filename: string, contents: string) => void;
}

function defaultDownload(filename: string, contents: string): void {
    const blob = new Blob([contents], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
}

function elementSummary(el: DomContext | null): string {
    if (el === null) return "no match";
    const attrs: string[] = [];
    if (el.Id !== null)        attrs.push(`#${el.Id}`);
    if (el.ClassName !== null) attrs.push(`.${el.ClassName.split(/\s+/).filter(Boolean).join(".")}`);
    const attrSegment = attrs.length > 0 ? ` ${attrs.join("")}` : "";
    const head = `<${el.TagName}${attrSegment}>`;
    if (el.TextSnippet.length === 0) return head;
    return `${head} "${el.TextSnippet}"`;
}

const STATUS_TONE: Record<SelectorHistoryBucket["Status"], string> = {
    healthy:           "border-emerald-500/40 text-emerald-700 dark:text-emerald-300",
    regressed:         "border-amber-500/40   text-amber-700   dark:text-amber-300",
    "always-failing":  "border-destructive/40 text-destructive",
    unknown:           "border-border         text-muted-foreground",
};

function HistoryBlock({ bucket }: { bucket: SelectorHistoryBucket }) {
    const last10 = bucket.Outcomes.slice(-10);
    return (
        <div className={`mt-2 ml-5 rounded-md border ${STATUS_TONE[bucket.Status]} bg-card/50 p-2 text-[11px] space-y-1`}>
            <div className="flex items-center gap-2">
                <History className="h-3 w-3" aria-hidden />
                <span className="uppercase tracking-wide font-semibold">{bucket.Status}</span>
                <span className="text-muted-foreground">
                    · {bucket.TotalRuns} run{bucket.TotalRuns === 1 ? "" : "s"}
                    , {bucket.TotalFailures} failure{bucket.TotalFailures === 1 ? "" : "s"}
                </span>
            </div>
            {bucket.LastSuccessAt !== null && (
                <div className="text-muted-foreground">
                    Last success: <code>{bucket.LastSuccessAt}</code>
                </div>
            )}
            {bucket.FirstFailureAfterLastSuccessAt !== null && (
                <div className="text-muted-foreground">
                    Started failing: <code>{bucket.FirstFailureAfterLastSuccessAt}</code>
                    {bucket.ConsecutiveFailures > 0 && (
                        <span> · {bucket.ConsecutiveFailures} in a row</span>
                    )}
                </div>
            )}
            <div className="flex items-end gap-0.5 h-4 pt-1" aria-label="Recent run outcomes">
                {last10.map((o) => (
                    <span
                        key={o.RunId}
                        title={`${o.At} — ${o.IsOk ? "ok" : (o.Error ?? "fail")}`}
                        className={`w-2 h-3 rounded-sm ${o.IsOk ? "bg-emerald-500" : "bg-destructive"}`}
                    />
                ))}
            </div>
        </div>
    );
}

interface AttemptRowProps {
    readonly attempt: SelectorAttemptComparison;
    readonly history: SelectorHistoryBucket | null;
    readonly showHistory: boolean;
    readonly onPromote: ((selectorId: number) => void) | null;
    readonly isPromoting: boolean;
}

function AttemptRow({ attempt, history, showHistory, onPromote, isPromoting }: AttemptRowProps) {
    const matched = attempt.Matched;
    const Icon = matched ? CheckCircle2 : XCircle;
    const tone = matched ? "text-emerald-500" : "text-destructive";
    const border = attempt.IsPrimary
        ? matched ? "border-emerald-500/40" : "border-destructive/40"
        : "border-border";

    const canPromote = onPromote !== null && matched && !attempt.IsPrimary;

    return (
        <li className={`rounded-md border ${border} bg-card p-2.5 text-xs space-y-1`}>
            <div className="flex items-center gap-2">
                <Icon className={`h-3.5 w-3.5 ${tone}`} aria-hidden />
                <Badge variant="outline" className="text-[10px] px-1.5 py-0">{attempt.Kind}</Badge>
                {attempt.IsPrimary && (
                    <Badge variant="default" className="text-[10px] px-1.5 py-0">PRIMARY</Badge>
                )}
                <code className="text-muted-foreground truncate" title={attempt.Expression}>
                    {attempt.Expression}
                </code>
                <Badge variant="secondary" className="ml-auto text-[10px] px-1.5 py-0">
                    {attempt.MatchCount} match{attempt.MatchCount === 1 ? "" : "es"}
                </Badge>
                {canPromote && (
                    <Button
                        size="sm"
                        variant="outline"
                        className="h-6 px-2 text-[10px]"
                        onClick={() => onPromote!(attempt.SelectorId)}
                        disabled={isPromoting}
                        aria-label={`Promote selector ${attempt.SelectorId} to primary`}
                        title="Promote this fallback to primary for this step"
                    >
                        <Star className="h-3 w-3 mr-1" />
                        {isPromoting ? "Promoting…" : "Promote to primary"}
                    </Button>
                )}
            </div>

            {attempt.ResolvedExpression !== attempt.Expression && (
                <div className="text-[11px] text-muted-foreground pl-5">
                    Resolved: <code>{attempt.ResolvedExpression}</code>
                </div>
            )}

            <div className="flex items-start gap-2 pl-5">
                <Crosshair className="h-3 w-3 mt-0.5 text-muted-foreground shrink-0" aria-hidden />
                <code className={`${matched ? "text-foreground" : "text-muted-foreground italic"} break-all`}>
                    {elementSummary(attempt.Element)}
                </code>
            </div>

            {attempt.Error !== null && (
                <div className="pl-5 text-destructive text-[11px]">Error: {attempt.Error}</div>
            )}

            {showHistory && history !== null && <HistoryBlock bucket={history} />}
            {showHistory && history === null && (
                <div className="ml-5 mt-1 text-[11px] text-muted-foreground italic">
                    No prior replay history for this selector.
                </div>
            )}
        </li>
    );
}

export function SelectorComparisonPanel({ comparison, stepId, url, history, onPromoteToPrimary, failureReport, onDownload }: SelectorComparisonPanelProps) {
    const { Attempts, PrimaryMatched, AnyFallbackMatched, DriftDetected } = comparison;
    const hasHistory = history !== undefined;
    const [showHistory, setShowHistory] = useState(false);
    const [promotingId, setPromotingId] = useState<number | null>(null);

    const handleExport = () => {
        const bundle = buildSelectorComparisonBundle(comparison, { StepId: stepId, Url: url });
        const filename = buildSelectorComparisonFilename(stepId ?? null);
        const contents = serializeSelectorComparisonBundle(bundle);
        (onDownload ?? defaultDownload)(filename, contents);
        toast.success(`Exported selector comparison (${Attempts.length} attempt${Attempts.length === 1 ? "" : "s"})`);
    };

    const handlePromote = onPromoteToPrimary
        ? async (selectorId: number) => {
            setPromotingId(selectorId);
            try {
                await onPromoteToPrimary(selectorId);
                toast.success(`Promoted selector #${selectorId} to primary`);
            } catch (err) {
                toast.error(
                    `Failed to promote selector: ${err instanceof Error ? err.message : String(err)}`,
                );
            } finally {
                setPromotingId(null);
            }
        }
        : null;

    return (
        <Card>
            <CardHeader className="pb-2 flex flex-row items-center justify-between">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                    <Crosshair className="h-4 w-4 text-primary" />
                    Selector Comparison
                    <Badge
                        variant={PrimaryMatched ? "secondary" : "destructive"}
                        className="ml-1 text-[10px]"
                    >
                        {PrimaryMatched ? "Primary OK" : "Primary failed"}
                    </Badge>
                    {AnyFallbackMatched && (
                        <Badge variant="outline" className="text-[10px]">Fallback found</Badge>
                    )}
                </CardTitle>
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-1.5">
                        <Switch
                            id="show-history"
                            checked={showHistory && hasHistory}
                            onCheckedChange={(v) => setShowHistory(Boolean(v))}
                            disabled={!hasHistory}
                            aria-label="Show prior replay outcomes per selector"
                        />
                        <Label
                            htmlFor="show-history"
                            className={`text-[11px] flex items-center gap-1 ${hasHistory ? "" : "text-muted-foreground"}`}
                        >
                            <History className="h-3 w-3" aria-hidden />
                            History
                        </Label>
                    </div>
                    <Button
                        variant="outline"
                        size="sm"
                        onClick={handleExport}
                        disabled={Attempts.length === 0}
                        aria-label="Export selector comparison as JSON"
                    >
                        <FileDown className="h-3.5 w-3.5 mr-1.5" />
                        Export selector comparison
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="space-y-3">
                {DriftDetected && (
                    <div className="flex items-start gap-2 rounded-md border border-amber-500/40 bg-amber-500/10 p-2 text-xs text-amber-700 dark:text-amber-300">
                        <AlertTriangle className="h-3.5 w-3.5 mt-0.5 shrink-0" />
                        <span>
                            <strong>Selector drift:</strong> the primary selector no longer matches,
                            but a fallback resolved. Consider promoting the fallback or repairing the primary.
                        </span>
                    </div>
                )}
                {failureReport !== undefined && (
                    <FailureDetailsPanel report={failureReport} embedded />
                )}
                {Attempts.length === 0 ? (
                    <p className="text-xs text-muted-foreground italic py-2 text-center">
                        No selectors recorded for this step.
                    </p>
                ) : (
                    <ul className="space-y-2">
                        {Attempts.map((a) => (
                            <AttemptRow
                                key={a.SelectorId}
                                attempt={a}
                                history={hasHistory ? findHistoryForSelector(history, a.ResolvedExpression) : null}
                                showHistory={showHistory && hasHistory}
                                onPromote={handlePromote}
                                isPromoting={promotingId === a.SelectorId}
                            />
                        ))}
                    </ul>
                )}
            </CardContent>
        </Card>
    );
}

/**
 * Marco Extension — Selector Replay Trace Panel
 *
 * Step-by-step view of the resolver's evaluation order for one
 * {@link FailureReport}. Renders the primary attempt first, then each
 * fallback in declared order, with status icons that mirror the live
 * replay loop:
 *
 *   ✓ matched  — resolved, replay stopped here.
 *   ✗ missed   — evaluated, 0 matches, advanced.
 *   ⚠ errored  — evaluated but threw (syntax / unresolved anchor / JS).
 *   ○ pending  — never run because an earlier step matched.
 *
 * Pure presentational. All ordering & classification lives in
 * `./selector-replay-trace.ts` so it can be unit-tested headlessly.
 *
 * Conformance: mem://standards/verbose-logging-and-failure-diagnostics.
 */

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
    CheckCircle2,
    XCircle,
    AlertTriangle,
    Circle,
    ListOrdered,
    ArrowRight,
} from "lucide-react";
import type { FailureReport } from "@/background/recorder/failure-logger";
import {
    buildReplayTrace,
    type TraceStep,
    type TraceStepStatus,
} from "./selector-replay-trace";
import { FormSnapshotBadge } from "./FormSnapshotTable";

interface SelectorReplayTracePanelProps {
    readonly report: FailureReport;
    /** Hide the outer Card chrome — useful when embedding inside another card. */
    readonly embedded?: boolean;
}

const STATUS_TONE: Readonly<Record<TraceStepStatus, string>> = {
    matched: "border-emerald-500/40 bg-emerald-500/5",
    missed:  "border-destructive/40 bg-destructive/5",
    errored: "border-rose-500/40 bg-rose-500/5",
    pending: "border-border bg-muted/20 opacity-70",
};

const STATUS_ICON_TONE: Readonly<Record<TraceStepStatus, string>> = {
    matched: "text-emerald-500",
    missed:  "text-destructive",
    errored: "text-rose-500",
    pending: "text-muted-foreground",
};

const STATUS_LABEL: Readonly<Record<TraceStepStatus, string>> = {
    matched: "MATCHED",
    missed:  "MISSED",
    errored: "ERROR",
    pending: "SKIPPED",
};

function StatusIcon({ status }: { readonly status: TraceStepStatus }) {
    const cls = `h-3.5 w-3.5 shrink-0 ${STATUS_ICON_TONE[status]}`;
    switch (status) {
        case "matched": return <CheckCircle2 className={cls} aria-hidden />;
        case "missed":  return <XCircle className={cls} aria-hidden />;
        case "errored": return <AlertTriangle className={cls} aria-hidden />;
        case "pending": return <Circle className={cls} aria-hidden />;
    }
}

export function SelectorReplayTracePanel({ report, embedded }: SelectorReplayTracePanelProps) {
    const trace = buildReplayTrace(report.Selectors);

    const body = (
        <div className="space-y-2.5" data-testid="selector-replay-trace">
            <SummaryBar
                total={trace.Summary.Total}
                evaluated={trace.Summary.Evaluated}
                skipped={trace.Summary.Skipped}
                stoppedAt={trace.Summary.StoppedAt}
                outcome={trace.Summary.Outcome}
                snapshot={report.FormSnapshot}
            />
            {trace.Steps.length === 0 ? (
                <p
                    data-testid="trace-empty"
                    className="text-xs italic text-muted-foreground py-3 text-center"
                >
                    No selector attempts were recorded for this failure.
                </p>
            ) : (
                <ScrollArea className="max-h-72 pr-2">
                    <ol className="space-y-1.5">
                        {trace.Steps.map((s) => (
                            <TraceStepRow key={s.Order} step={s} />
                        ))}
                    </ol>
                </ScrollArea>
            )}
        </div>
    );

    if (embedded === true) {
        return (
            <section
                aria-label="Selector replay trace"
                data-testid="selector-replay-trace-panel"
                className="rounded-md border border-border bg-card/40 p-3"
            >
                <header className="flex items-center gap-2 text-[11px] uppercase tracking-wide text-muted-foreground mb-2">
                    <ListOrdered className="h-3 w-3" aria-hidden />
                    Replay trace
                </header>
                {body}
            </section>
        );
    }

    return (
        <Card data-testid="selector-replay-trace-panel">
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                    <ListOrdered className="h-4 w-4 text-primary" />
                    Selector replay trace
                </CardTitle>
            </CardHeader>
            <CardContent>{body}</CardContent>
        </Card>
    );
}

/* ------------------------------------------------------------------ */
/*  Sub-components                                                     */
/* ------------------------------------------------------------------ */

function SummaryBar({
    total,
    evaluated,
    skipped,
    stoppedAt,
    outcome,
    snapshot,
}: {
    readonly total: number;
    readonly evaluated: number;
    readonly skipped: number;
    readonly stoppedAt: number | null;
    readonly outcome: "matched" | "exhausted" | "empty";
    readonly snapshot: FailureReport["FormSnapshot"];
}) {
    const tone =
        outcome === "matched"
            ? "border-emerald-500/40 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
            : outcome === "exhausted"
                ? "border-destructive/40 bg-destructive/10 text-destructive"
                : "border-border bg-muted/30 text-muted-foreground";

    const headline =
        outcome === "matched"
            ? `Stopped at step ${stoppedAt} — replay matched.`
            : outcome === "exhausted"
                ? "All candidates exhausted — no match."
                : "Nothing to replay.";

    return (
        <div
            role="status"
            data-testid="trace-summary"
            data-outcome={outcome}
            className={`rounded-md border px-3 py-2 text-xs ${tone}`}
        >
            <div className="flex items-center gap-2 flex-wrap">
                <span className="font-semibold">{headline}</span>
                <Badge variant="outline" className="text-[10px] ml-auto">
                    {evaluated}/{total} evaluated
                </Badge>
                {skipped > 0 && (
                    <Badge variant="secondary" className="text-[10px]">
                        {skipped} skipped
                    </Badge>
                )}
                {snapshot !== null && <FormSnapshotBadge snapshot={snapshot} />}
            </div>
        </div>
    );
}

function TraceStepRow({ step }: { readonly step: TraceStep }) {
    const showResolvedDistinct =
        step.ResolvedExpression !== step.Expression && step.Expression.length > 0;

    return (
        <li
            data-testid="trace-step-row"
            data-order={step.Order}
            data-status={step.Status}
            data-role={step.Role}
            className={`relative rounded-md border ${STATUS_TONE[step.Status]} p-2 text-xs space-y-1`}
        >
            <div className="flex items-center gap-2 flex-wrap">
                <Badge variant="outline" className="text-[10px] font-mono px-1.5 py-0">
                    #{step.Order}
                </Badge>
                <StatusIcon status={step.Status} />
                <Badge
                    variant={step.Status === "matched" ? "default" : "outline"}
                    className="text-[10px] px-1.5 py-0"
                >
                    {STATUS_LABEL[step.Status]}
                </Badge>
                <Badge variant="outline" className="text-[10px] px-1.5 py-0">
                    {step.Role}
                </Badge>
                <Badge variant="secondary" className="text-[10px] px-1.5 py-0">
                    {step.Strategy}
                </Badge>
                <Badge variant="secondary" className="text-[10px] px-1.5 py-0 ml-auto">
                    {step.MatchCount} match{step.MatchCount === 1 ? "" : "es"}
                </Badge>
            </div>

            <div className="pl-5">
                <code
                    className="block break-all font-mono text-foreground"
                    title={step.ResolvedExpression}
                >
                    {step.ResolvedExpression}
                </code>
                {showResolvedDistinct && (
                    <div className="text-[11px] text-muted-foreground mt-0.5">
                        Stored: <code className="break-all">{step.Expression}</code>
                    </div>
                )}
            </div>

            <div className="pl-5 flex items-start gap-1 text-[11px] text-muted-foreground">
                <ArrowRight className="h-3 w-3 mt-0.5 shrink-0" aria-hidden />
                <span>
                    {step.Note}
                    {(step.Status === "missed" || step.Status === "errored") && (
                        <>
                            {" "}
                            <span className="font-mono text-destructive">
                                ({step.FailureReason})
                            </span>
                        </>
                    )}
                </span>
            </div>
        </li>
    );
}

/**
 * Marco Extension — Mini Selector Tester
 *
 * Tiny inline tool: paste a CSS or XPath selector and immediately see the
 * match count, the first matched element, and any syntax error. Auto-
 * detects kind from the leading character but exposes a manual override.
 *
 * Pure presentation around `testSelector` (background module). Defaults to
 * the live `document` but accepts an injectable `doc` for tests.
 */

import { useMemo, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Crosshair, CheckCircle2, XCircle, AlertTriangle } from "lucide-react";
import {
    testSelector,
    detectSelectorKind,
    type SelectorTestKind,
} from "@/background/recorder/selector-tester";
import type { DomContext } from "@/background/recorder/failure-logger";

interface SelectorTesterPanelProps {
    /** Defaults to `document`. Inject a sandbox doc in tests. */
    readonly doc?: Document;
}

function elementSummary(el: DomContext | null): string {
    if (el === null) return "no match";
    const attrs: string[] = [];
    if (el.Id !== null)        attrs.push(`#${el.Id}`);
    if (el.ClassName !== null) attrs.push(`.${el.ClassName.split(/\s+/).filter(Boolean).join(".")}`);
    const attrSegment = attrs.length > 0 ? ` ${attrs.join("")}` : "";
    const head = `<${el.TagName}${attrSegment}>`;
    if (el.TextSnippet.length === 0) return head;
    return `${head} "${el.TextSnippet}"`;
}

const KIND_OPTIONS: ReadonlyArray<{ readonly value: SelectorTestKind; readonly label: string }> = [
    { value: "Auto",  label: "Auto"  },
    { value: "Css",   label: "CSS"   },
    { value: "XPath", label: "XPath" },
];

export function SelectorTesterPanel({ doc }: SelectorTesterPanelProps = {}) {
    const [expression, setExpression] = useState("");
    const [kind, setKind] = useState<SelectorTestKind>("Auto");
    const targetDoc = doc ?? (typeof document !== "undefined" ? document : null);

    const result = useMemo(() => {
        if (targetDoc === null || expression.trim().length === 0) return null;
        return testSelector(expression, targetDoc, kind);
    }, [expression, kind, targetDoc]);

    const detectedKind = expression.trim().length > 0
        ? (kind === "Auto" ? detectSelectorKind(expression) : kind)
        : null;

    const matched = result !== null && result.Error === null && result.MatchCount > 0;
    const errored = result !== null && result.Error !== null;

    return (
        <Card>
            <CardHeader className="pb-2">
                <CardTitle className="text-sm font-semibold flex items-center gap-2">
                    <Crosshair className="h-4 w-4 text-primary" />
                    Selector Tester
                </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
                <div className="flex gap-2">
                    <Input
                        value={expression}
                        onChange={(e) => setExpression(e.target.value)}
                        placeholder="#go    or    //button[@id='go']"
                        className="font-mono text-xs"
                        aria-label="Selector expression"
                        spellCheck={false}
                    />
                    <div className="flex rounded-md border border-border overflow-hidden shrink-0">
                        {KIND_OPTIONS.map((o) => (
                            <Button
                                key={o.value}
                                type="button"
                                variant={kind === o.value ? "default" : "ghost"}
                                size="sm"
                                className="rounded-none h-9 px-2 text-[11px]"
                                onClick={() => setKind(o.value)}
                            >
                                {o.label}
                            </Button>
                        ))}
                    </div>
                </div>

                {detectedKind !== null && (
                    <div className="flex items-center gap-2 text-[11px] text-muted-foreground">
                        <Badge variant="outline" className="text-[10px] px-1.5 py-0">
                            {detectedKind}
                        </Badge>
                        {kind === "Auto" && <span>auto-detected</span>}
                    </div>
                )}

                {result === null ? (
                    <p className="text-xs text-muted-foreground italic py-2 text-center">
                        Paste a CSS or XPath selector to test it against the current page.
                    </p>
                ) : errored ? (
                    <div className="flex items-start gap-2 rounded-md border border-destructive/40 bg-destructive/10 p-2 text-xs text-destructive">
                        <AlertTriangle className="h-3.5 w-3.5 mt-0.5 shrink-0" />
                        <span>{result.Error}</span>
                    </div>
                ) : (
                    <div className="space-y-2">
                        <div className="flex items-center gap-2">
                            {matched
                                ? <CheckCircle2 className="h-4 w-4 text-emerald-500" aria-hidden />
                                : <XCircle className="h-4 w-4 text-destructive" aria-hidden />}
                            <Badge
                                variant={matched ? "secondary" : "destructive"}
                                className="text-[10px] px-1.5 py-0"
                            >
                                {result.MatchCount} match{result.MatchCount === 1 ? "" : "es"}
                            </Badge>
                        </div>
                        <div className="rounded-md border border-border bg-card px-2.5 py-2 text-xs">
                            <div className="text-[10px] uppercase tracking-wide text-muted-foreground mb-1">
                                First match
                            </div>
                            <code className={`break-all ${matched ? "text-foreground" : "text-muted-foreground italic"}`}>
                                {elementSummary(result.FirstMatch)}
                            </code>
                            {result.FirstMatch !== null && result.FirstMatch.OuterHtmlSnippet.length > 0 && (
                                <pre className="mt-1.5 text-[11px] text-muted-foreground whitespace-pre-wrap break-all">
                                    {result.FirstMatch.OuterHtmlSnippet}
                                </pre>
                            )}
                        </div>
                    </div>
                )}
            </CardContent>
        </Card>
    );
}

