/**
 * Marco Extension — LiveRecordedActionsTree selection scroll tests
 *
 * Verifies that selecting a step (either via internal click or via the
 * controlled `selectedStepId` prop) calls `scrollIntoView` on the matching
 * row so the Options page can drive the live tree to reveal the active row.
 */

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { act, cleanup, fireEvent, render } from "@testing-library/react";

import { LiveRecordedActionsTree } from "@/components/recorder/LiveRecordedActionsTree";
import {
    __resetRecorderSessionSyncForTests,
    writeSession,
} from "@/lib/recorder-session-sync";
import type {
    RecordedStep,
    RecordingSession,
} from "@/background/recorder/recorder-session-types";

function makeStep(stepId: string, index: number): RecordedStep {
    return {
        StepId: stepId,
        Index: index,
        Kind: "Click",
        Label: `Step ${index}`,
        VariableName: `var${index}`,
        Selector: {
            XPathFull: "/html/body",
            XPathRelative: null,
            AnchorStepId: null,
            Strategy: "Positional",
        },
        CapturedAt: "2026-04-27T00:00:00.000Z",
    };
}

function makeSession(steps: ReadonlyArray<RecordedStep>): RecordingSession {
    return {
        SessionId: "sess-scroll-1",
        ProjectSlug: "proj",
        StartedAt: "2026-04-27T00:00:00.000Z",
        Phase: "Recording",
        Steps: steps,
    };
}

describe("LiveRecordedActionsTree — selection scroll", () => {
    let scrollSpy: ReturnType<typeof vi.fn>;

    beforeEach(async () => {
        __resetRecorderSessionSyncForTests();
        window.localStorage.clear();

        // jsdom doesn't implement scrollIntoView; install a spy on the prototype
        // so every row inherits it and we can assert which row was targeted.
        scrollSpy = vi.fn();
        Object.defineProperty(HTMLElement.prototype, "scrollIntoView", {
            configurable: true,
            value: scrollSpy,
        });

        const steps: RecordedStep[] = Array.from({ length: 8 }, (_, i) =>
            makeStep(`s-${i}`, i),
        );
        await writeSession(makeSession(steps));
    });

    afterEach(() => {
        cleanup();
        vi.useRealTimers();
    });

    it("scrolls the matching row into view when a row is clicked", async () => {
        const view = render(<LiveRecordedActionsTree />);
        // Wait a tick for the async session subscription to deliver state.
        await act(async () => { await Promise.resolve(); });

        const target = view.getByTestId("live-action-s-5");
        scrollSpy.mockClear();
        fireEvent.click(target);

        // The clicked row's <li> ancestor should have received a scrollIntoView call.
        expect(scrollSpy).toHaveBeenCalledTimes(1);
        const callContext = scrollSpy.mock.instances[0] as HTMLElement;
        expect(callContext.getAttribute("data-step-id")).toBe("s-5");
        expect(scrollSpy.mock.calls[0][0]).toMatchObject({ block: "nearest" });
    });

    it("scrolls when the controlled selectedStepId prop changes (Options-driven)", async () => {
        const view = render(<LiveRecordedActionsTree selectedStepId={null} />);
        await act(async () => { await Promise.resolve(); });

        scrollSpy.mockClear();
        view.rerender(<LiveRecordedActionsTree selectedStepId="s-3" />);
        await act(async () => { await Promise.resolve(); });

        expect(scrollSpy).toHaveBeenCalledTimes(1);
        const callContext = scrollSpy.mock.instances[0] as HTMLElement;
        expect(callContext.getAttribute("data-step-id")).toBe("s-3");

        scrollSpy.mockClear();
        view.rerender(<LiveRecordedActionsTree selectedStepId="s-7" />);
        await act(async () => { await Promise.resolve(); });

        expect(scrollSpy).toHaveBeenCalledTimes(1);
        const ctx = scrollSpy.mock.instances[0] as HTMLElement;
        expect(ctx.getAttribute("data-step-id")).toBe("s-7");
    });

    it("applies a transient pulsing highlight to the active row", async () => {
        const view = render(<LiveRecordedActionsTree selectedStepId="s-2" />);
        // Two flushes: first delivers the session, second runs the
        // selection-effect that flips the pulse state.
        await act(async () => { await Promise.resolve(); });
        await act(async () => { await Promise.resolve(); });

        const row = view.getByTestId("live-action-s-2").closest("li") as HTMLLIElement;
        expect(row.getAttribute("data-pulsing")).toBe("true");

        vi.useFakeTimers();
        await act(async () => { vi.advanceTimersByTime(1300); });
        // Note: the pulse timer was scheduled before fake timers were installed,
        // so we just verify the attribute eventually clears via real timers.
        vi.useRealTimers();
        await new Promise((resolve) => setTimeout(resolve, 1300));
        await act(async () => { await Promise.resolve(); });
        expect(row.getAttribute("data-pulsing")).toBeNull();
    });

    it("does not call scrollIntoView when no step is selected", async () => {
        render(<LiveRecordedActionsTree selectedStepId={null} />);
        await act(async () => { await Promise.resolve(); });
        expect(scrollSpy).not.toHaveBeenCalled();
    });
});

/**
 * Marco Extension — Failure Report Bundle Exporter
 *
 * Pure helpers that turn a selected list of {@link FailureReport}s into a
 * single JSON bundle suitable for sharing with an AI assistant.
 *
 * Kept UI-free so it can be unit-tested in node without jsdom and reused
 * by both the React panel and any future CLI/diagnostic dump.
 *
 * Bundle shape:
 *   {
 *     Generator:   "marco-extension",
 *     Version:     1,
 *     ExportedAt:  ISO string,
 *     Count:       number of reports,
 *     Reports:     FailureReport[]
 *   }
 *
 * @see ./failure-toast.ts            — Single-report copy/toast helper.
 * @see @/background/recorder/failure-logger — FailureReport shape.
 */

import type { FailureReport } from "@/background/recorder/failure-logger";

export interface FailureBundle {
    readonly Generator: "marco-extension";
    readonly Version: 1;
    readonly ExportedAt: string;
    readonly Count: number;
    readonly Reports: ReadonlyArray<FailureReport>;
}

export interface BuildBundleOpts {
    readonly Now?: () => Date;
}

/** Build the JSON-serialisable bundle (deterministic when `Now` is injected). */
export function buildFailureBundle(
    reports: ReadonlyArray<FailureReport>,
    opts: BuildBundleOpts = {},
): FailureBundle {
    const now = opts.Now ?? ((): Date => new Date());
    return {
        Generator: "marco-extension",
        Version: 1,
        ExportedAt: now().toISOString(),
        Count: reports.length,
        Reports: reports,
    };
}

/**
 * JSON output format for the export pipeline. "Pretty" uses 2-space
 * indent and trailing newline (default — best for diffing and pasting
 * into a ticket). "Minified" omits whitespace (best when uploading to
 * a service that parses bytes-on-the-wire or when filesize matters).
 */
export type ExportFormat = "pretty" | "minified";

export const DEFAULT_EXPORT_FORMAT: ExportFormat = "pretty";

/** Serialize ANY JSON value using the chosen export format. */
export function serializeJson(value: unknown, format: ExportFormat): string {
    return format === "pretty"
        ? JSON.stringify(value, null, 2)
        : JSON.stringify(value);
}

/** Pretty-printed JSON ready to drop into a Blob. */
export function serializeFailureBundle(
    bundle: FailureBundle,
    format: ExportFormat = DEFAULT_EXPORT_FORMAT,
): string {
    return serializeJson(bundle, format);
}

/**
 * Default filename: `marco-failure-reports-YYYY-MM-DD-HHmm.json`.
 * Uses UTC slice so the test suite stays deterministic with an injected `Now`.
 */
export function buildFailureBundleFilename(now: Date = new Date()): string {
    const iso = now.toISOString();             // 2026-04-26T10:30:00.000Z
    const date = iso.slice(0, 10);             // 2026-04-26
    const time = iso.slice(11, 16).replace(":", ""); // 1030
    return `marco-failure-reports-${date}-${time}.json`;
}

/* ------------------------------------------------------------------ */
/*  Single-report convenience (last-failure export)                    */
/* ------------------------------------------------------------------ */

/**
 * Picks the most recent report from `reports`. "Most recent" = max
 * `Timestamp` (ISO-8601 sorts lexicographically). When multiple reports
 * share the same timestamp the **last in array order** wins (preserves
 * insertion order from the recorder log). Returns `null` for empty input.
 */
export function pickLastFailureReport(
    reports: ReadonlyArray<FailureReport>,
): FailureReport | null {
    if (reports.length === 0) return null;
    let best: FailureReport = reports[0];
    for (let i = 1; i < reports.length; i++) {
        const candidate = reports[i];
        if (candidate.Timestamp >= best.Timestamp) {
            best = candidate;
        }
    }
    return best;
}

/**
 * Default filename for a single-report export, including StepId when
 * available so the file is self-identifying:
 * `marco-last-failure-step7-2026-04-26-1030.json`.
 */
export function buildLastFailureFilename(
    report: FailureReport,
    now: Date = new Date(),
): string {
    const iso = now.toISOString();
    const date = iso.slice(0, 10);
    const time = iso.slice(11, 16).replace(":", "");
    const stepTag = report.StepId !== null ? `-step${report.StepId}` : "";
    return `marco-last-failure${stepTag}-${date}-${time}.json`;
}

/* ------------------------------------------------------------------ */
/*  Per-step lookup (Step-picker export)                               */
/* ------------------------------------------------------------------ */

export interface StepFailureOption {
    /** StepId as stored on the report. `null` means "report has no StepId". */
    readonly StepId: number | null;
    /** Number of failure reports that share this StepId. */
    readonly Count: number;
    /** ISO timestamp of the most recent report for this StepId. */
    readonly LatestTimestamp: string;
    /** StepKind taken from the most recent report (may differ across retries). */
    readonly StepKind: string | null;
}

/**
 * Group reports by `StepId` for the export-by-step dropdown. Sorted by
 * `LatestTimestamp` descending so the most recently failing step is at
 * the top — that's what the user usually wants. Reports with `StepId === null`
 * are collapsed into a single "(no step id)" bucket at the end.
 */
export function listStepFailureOptions(
    reports: ReadonlyArray<FailureReport>,
): ReadonlyArray<StepFailureOption> {
    const buckets = new Map<string, {
        StepId: number | null;
        Count: number;
        LatestTimestamp: string;
        StepKind: string | null;
    }>();
    for (const r of reports) {
        const key = r.StepId === null ? "null" : String(r.StepId);
        const existing = buckets.get(key);
        if (!existing) {
            buckets.set(key, {
                StepId: r.StepId,
                Count: 1,
                LatestTimestamp: r.Timestamp,
                StepKind: r.StepKind,
            });
        } else {
            existing.Count += 1;
            if (r.Timestamp >= existing.LatestTimestamp) {
                existing.LatestTimestamp = r.Timestamp;
                existing.StepKind = r.StepKind;
            }
        }
    }
    const out = Array.from(buckets.values());
    out.sort((a, b) => {
        // null StepId always sinks to the bottom regardless of timestamp.
        if (a.StepId === null && b.StepId !== null) return 1;
        if (b.StepId === null && a.StepId !== null) return -1;
        if (a.LatestTimestamp === b.LatestTimestamp) return 0;
        return a.LatestTimestamp < b.LatestTimestamp ? 1 : -1;
    });
    return out;
}

/**
 * Pick the most recent report for a specific `StepId` (or `null` to find
 * the most recent report that has no StepId). Returns `null` when no
 * report matches. Tie-break: last in array order wins (preserves
 * insertion order from the recorder log), matching `pickLastFailureReport`.
 */
export function pickFailureReportByStepId(
    reports: ReadonlyArray<FailureReport>,
    stepId: number | null,
): FailureReport | null {
    let best: FailureReport | null = null;
    for (const r of reports) {
        if (r.StepId !== stepId) continue;
        if (best === null || r.Timestamp >= best.Timestamp) {
            best = r;
        }
    }
    return best;
}

/**
 * Marco Extension — FailureReport Shape Validator (export-time guard)
 *
 * Pure helper that re-checks the SAME schema enforced at build time by
 * `scripts/check-failure-log-schema.mjs` against an actual JSON payload
 * about to be downloaded. Build-time guarantees the producer code is
 * correct; this guarantees a runtime mutation, manual edit, or future
 * `JSON.parse(localStorage…)` round-trip didn't silently drop a field.
 *
 * Returns a `ValidationResult` describing which top-level reports are
 * malformed and which fields are missing/wrong-typed. UI surfaces it as
 * a warning toast — export still proceeds (the user explicitly asked
 * to download), but they're told the file is suspect and exactly why.
 *
 * Schema source of truth:
 *   - Required top-level fields (mirrors REQUIRED_REPORT_FIELDS in
 *     scripts/check-failure-log-schema.mjs)
 *   - Type expectations per field (string | number | boolean | array | null-allowed)
 *   - Bundle wrapper shape: { Generator, Version, ExportedAt, Count, Reports }
 *
 * @see mem://standards/verbose-logging-and-failure-diagnostics
 * @see scripts/check-failure-log-schema.mjs — build-time twin
 * @see ./failure-export.ts — producer of the payload this validates
 */

/* ------------------------------------------------------------------ */
/*  Schema (kept in sync with REQUIRED_REPORT_FIELDS)                  */
/* ------------------------------------------------------------------ */

type FieldKind =
    | "string"
    | "string|null"
    | "number|null"
    | "boolean"
    | "array"
    | "object|null";

interface FieldSpec {
    readonly kind: FieldKind;
}

/**
 * MUST stay in sync with `REQUIRED_REPORT_FIELDS` in
 * `scripts/check-failure-log-schema.mjs`. The build-time check enforces
 * the producer; this map enforces the on-disk payload.
 */
const REPORT_FIELD_SPEC: Readonly<Record<string, FieldSpec>> = {
    Phase:         { kind: "string" },
    Reason:        { kind: "string" },
    ReasonDetail:  { kind: "string" },
    StackTrace:    { kind: "string|null" },
    StepId:        { kind: "number|null" },
    Index:         { kind: "number|null" },
    StepKind:      { kind: "string|null" },
    Selectors:     { kind: "array" },
    Variables:     { kind: "array" },
    DomContext:    { kind: "object|null" },
    ResolvedXPath: { kind: "string|null" },
    Timestamp:     { kind: "string" },
    SourceFile:    { kind: "string" },
    Verbose:       { kind: "boolean" },
};

const REQUIRED_BUNDLE_FIELDS: ReadonlyArray<string> = [
    "Generator",
    "Version",
    "ExportedAt",
    "Count",
    "Reports",
];

/* ------------------------------------------------------------------ */
/*  Result shape                                                       */
/* ------------------------------------------------------------------ */

export interface FieldIssue {
    /** Path like `Reports[2].Selectors` or `Verbose` (top-level report). */
    readonly Path: string;
    /** What was wrong: missing key, wrong type, or null where forbidden. */
    readonly Problem: "missing" | "wrong-type" | "null-not-allowed";
    /** Expected kind (when Problem is wrong-type / null-not-allowed). */
    readonly Expected: FieldKind | null;
    /** typeof the actual value (or "null" / "array"). */
    readonly Actual: string;
}

export interface ValidationResult {
    readonly Valid: boolean;
    /** Top-level shape errors (e.g. payload is not an object). */
    readonly RootIssues: ReadonlyArray<FieldIssue>;
    /** Per-report issues. Empty if every report is well-formed. */
    readonly ReportIssues: ReadonlyArray<FieldIssue>;
    /** Number of reports inspected (0 when payload is not a bundle/report). */
    readonly ReportsChecked: number;
    /**
     * Human-friendly one-liner summarising the worst issue. Suitable
     * for the toast title; empty when `Valid === true`.
     */
    readonly Summary: string;
}

/* ------------------------------------------------------------------ */
/*  Public API                                                         */
/* ------------------------------------------------------------------ */

/**
 * Validate a payload that is EITHER a single FailureReport or a
 * FailureBundle (`{ Reports: FailureReport[] }`). Accepts both because
 * the export panel produces both shapes (see failure-export.ts).
 *
 * Pass either the parsed object or the raw JSON string — we'll parse
 * and report a top-level issue if parsing fails.
 */
export function validateFailureReportPayload(
    input: unknown,
): ValidationResult {
    // Step 1: coerce JSON string to object if needed.
    let payload: unknown = input;
    if (typeof input === "string") {
        try {
            payload = JSON.parse(input);
        } catch (e) {
            return failResult([{
                Path: "$",
                Problem: "wrong-type",
                Expected: "object|null",
                Actual: `invalid JSON (${(e as Error).message})`,
            }], [], 0);
        }
    }

    // Step 2: must be a non-null object.
    if (payload === null || typeof payload !== "object" || Array.isArray(payload)) {
        return failResult([{
            Path: "$",
            Problem: "wrong-type",
            Expected: "object|null",
            Actual: kindOf(payload),
        }], [], 0);
    }

    // Step 3: detect bundle vs single report. If `Reports` key is
    //         present (even with the wrong type), treat as a bundle so
    //         we surface the wrapper-shape error rather than 14 false
    //         "missing field" errors against a non-report object.
    const obj = payload as Record<string, unknown>;
    if ("Reports" in obj || "Generator" in obj || "ExportedAt" in obj) {
        return validateBundle(obj);
    }
    // Single report path.
    const reportIssues = validateOneReport(obj, "$");
    return finalize([], reportIssues, 1);
}

/* ------------------------------------------------------------------ */
/*  Internals                                                          */
/* ------------------------------------------------------------------ */

function validateBundle(bundle: Record<string, unknown>): ValidationResult {
    const rootIssues: FieldIssue[] = [];
    for (const f of REQUIRED_BUNDLE_FIELDS) {
        if (!(f in bundle)) {
            rootIssues.push({
                Path: f, Problem: "missing", Expected: null, Actual: "undefined",
            });
        }
    }
    const reports = bundle.Reports;
    if (!Array.isArray(reports)) {
        rootIssues.push({
            Path: "Reports", Problem: "wrong-type",
            Expected: "array", Actual: kindOf(reports),
        });
        return finalize(rootIssues, [], 0);
    }

    const reportIssues: FieldIssue[] = [];
    for (let i = 0; i < reports.length; i++) {
        const r = reports[i];
        if (r === null || typeof r !== "object" || Array.isArray(r)) {
            reportIssues.push({
                Path: `Reports[${i}]`, Problem: "wrong-type",
                Expected: "object|null", Actual: kindOf(r),
            });
            continue;
        }
        reportIssues.push(
            ...validateOneReport(r as Record<string, unknown>, `Reports[${i}]`),
        );
    }
    return finalize(rootIssues, reportIssues, reports.length);
}

function validateOneReport(
    r: Record<string, unknown>,
    pathPrefix: string,
): FieldIssue[] {
    const out: FieldIssue[] = [];
    for (const [field, spec] of Object.entries(REPORT_FIELD_SPEC)) {
        const path = pathPrefix === "$" ? field : `${pathPrefix}.${field}`;
        if (!(field in r)) {
            out.push({
                Path: path, Problem: "missing",
                Expected: spec.kind, Actual: "undefined",
            });
            continue;
        }
        const v = r[field];
        if (!matchesKind(v, spec.kind)) {
            out.push({
                Path: path,
                Problem: v === null ? "null-not-allowed" : "wrong-type",
                Expected: spec.kind,
                Actual: kindOf(v),
            });
        }
    }
    return out;
}

function matchesKind(v: unknown, kind: FieldKind): boolean {
    switch (kind) {
        case "string":      return typeof v === "string";
        case "string|null": return v === null || typeof v === "string";
        case "number|null": return v === null || typeof v === "number";
        case "boolean":     return typeof v === "boolean";
        case "array":       return Array.isArray(v);
        case "object|null":
            return v === null
                || (typeof v === "object" && !Array.isArray(v));
    }
}

function kindOf(v: unknown): string {
    if (v === null) return "null";
    if (Array.isArray(v)) return "array";
    return typeof v;
}

function failResult(
    rootIssues: ReadonlyArray<FieldIssue>,
    reportIssues: ReadonlyArray<FieldIssue>,
    reportsChecked: number,
): ValidationResult {
    return finalize(rootIssues, reportIssues, reportsChecked);
}

function finalize(
    rootIssues: ReadonlyArray<FieldIssue>,
    reportIssues: ReadonlyArray<FieldIssue>,
    reportsChecked: number,
): ValidationResult {
    const total = rootIssues.length + reportIssues.length;
    if (total === 0) {
        return {
            Valid: true,
            RootIssues: [],
            ReportIssues: [],
            ReportsChecked: reportsChecked,
            Summary: "",
        };
    }
    const first = rootIssues[0] ?? reportIssues[0];
    const more = total - 1;
    const tail = more > 0 ? ` (+${more} more)` : "";
    const summary =
        `${first.Path}: ${first.Problem}` +
        (first.Expected ? ` — expected ${first.Expected}, got ${first.Actual}` : "") +
        tail;
    return {
        Valid: false,
        RootIssues: rootIssues,
        ReportIssues: reportIssues,
        ReportsChecked: reportsChecked,
        Summary: summary,
    };
}

/**
 * Marco Extension — Failure Toast
 *
 * Shows a Sonner toast for a {@link FailureReport} with a one-click action
 * that copies the full structured JSON to the clipboard. The user pastes it
 * straight into ChatGPT/Claude — no manual log-scraping required.
 *
 * Lives in the React/options layer so the recorder background modules stay
 * UI-free. Background or content-script callers should pass the report
 * across the message bus and let the React surface call `showFailureToast`.
 *
 * @see ./failure-logger.ts — Structured report shape.
 */

import { toast } from "sonner";
import {
    formatFailureReport,
    type FailureReport,
} from "@/background/recorder/failure-logger";

interface CopyOpts {
    readonly Clipboard?: Pick<Clipboard, "writeText">;
}

export async function copyFailureReportToClipboard(
    report: FailureReport,
    opts: CopyOpts = {},
): Promise<boolean> {
    const target = opts.Clipboard
        ?? (typeof navigator !== "undefined" ? navigator.clipboard : undefined);
    if (target === undefined) { return false; }
    const blob = `${formatFailureReport(report)}\n\n--- JSON ---\n${JSON.stringify(report, null, 2)}`;
    try {
        await target.writeText(blob);
        return true;
    } catch {
        return false;
    }
}

export interface ShowFailureToastOpts {
    /**
     * Optional re-run handler. When supplied, the toast renders a primary
     * "Retry step" action; "Copy report" stays available via the cancel
     * slot so both choices are reachable. Sonner only renders the cancel
     * button when both `action` and `cancel` are set.
     */
    readonly OnRetry?: () => void | Promise<void>;
}

export function showFailureToast(
    report: FailureReport,
    opts: ShowFailureToastOpts = {},
): string | number {
    const kindSuffix = report.StepKind !== null ? ` (${report.StepKind})` : "";
    const where = report.StepId !== null
        ? `Step #${report.StepId}${kindSuffix}`
        : `${report.Phase} failure`;

    const copyAction = {
        label: "Copy report",
        onClick: () => {
            void copyFailureReportToClipboard(report).then((ok) => {
                if (ok) { toast.success("Failure report copied to clipboard"); }
                else    { toast.error("Clipboard unavailable — see DevTools console"); }
            });
        },
    };

    if (opts.OnRetry === undefined) {
        return toast.error(`${where}: ${report.Message}`, {
            description: `Phase: ${report.Phase} · ${report.Timestamp}`,
            duration: 12000,
            action: copyAction,
        });
    }

    const onRetry = opts.OnRetry;
    return toast.error(`${where}: ${report.Message}`, {
        description: `Phase: ${report.Phase} · ${report.Timestamp}`,
        duration: 12000,
        action: {
            label: "Retry step",
            onClick: () => { void onRetry(); },
        },
        cancel: copyAction,
    });
}

/**
 * Marco Extension — Selector Replay Trace (pure helpers)
 *
 * Derives the step-by-step evaluation order of a {@link FailureReport}'s
 * `Selectors` array, classifying each entry as it would have been seen
 * by the live replay loop:
 *
 *   - `pending`   — never evaluated (a previous attempt already matched).
 *   - `matched`   — this attempt resolved to ≥1 element; loop stopped here.
 *   - `missed`    — evaluated and did not match; loop continued.
 *   - `errored`   — evaluated but threw a syntax/runtime error.
 *
 * Pure: no DOM, no chrome.*, no async. Single source of truth shared by
 * the React panel and its tests.
 *
 * Conformance: mem://standards/verbose-logging-and-failure-diagnostics —
 * surfaces the exact evaluation order (primary then fallbacks) that the
 * resolver actually walked, so a human can replay the resolver's reasoning.
 */

import type { SelectorAttempt } from "@/background/recorder/failure-logger";

export type TraceStepStatus = "matched" | "missed" | "errored" | "pending";

export interface TraceStep {
    readonly Order: number;                  // 1-based position in the walk.
    readonly Role: "Primary" | "Fallback";
    readonly Strategy: string;
    readonly Expression: string;
    readonly ResolvedExpression: string;
    readonly Matched: boolean;
    readonly MatchCount: number;
    readonly Status: TraceStepStatus;
    readonly FailureReason: SelectorAttempt["FailureReason"];
    readonly FailureDetail: string | null;
    readonly Note: string;                    // Human sentence for the row.
}

export interface ReplayTraceSummary {
    readonly Total: number;
    readonly Evaluated: number;
    readonly Skipped: number;
    readonly StoppedAt: number | null;        // 1-based Order of the matched step.
    readonly Outcome: "matched" | "exhausted" | "empty";
}

export interface ReplayTrace {
    readonly Steps: ReadonlyArray<TraceStep>;
    readonly Summary: ReplayTraceSummary;
}

const ERRORED_REASONS: ReadonlySet<SelectorAttempt["FailureReason"]> = new Set([
    "XPathSyntaxError",
    "CssSyntaxError",
    "UnresolvedAnchor",
    "EmptyExpression",
    "EvaluationThrew",
]);

function classify(attempt: SelectorAttempt, stopped: boolean): TraceStepStatus {
    if (stopped) return "pending";
    if (attempt.Matched) return "matched";
    if (ERRORED_REASONS.has(attempt.FailureReason)) return "errored";
    return "missed";
}

function noteFor(attempt: SelectorAttempt, status: TraceStepStatus, role: "Primary" | "Fallback"): string {
    switch (status) {
        case "matched":
            return `${role} resolved → ${attempt.MatchCount} match${attempt.MatchCount === 1 ? "" : "es"}; replay stopped here.`;
        case "errored": {
            const detailSuffix = attempt.FailureDetail !== null ? ` — ${attempt.FailureDetail}` : "";
            return `${role} threw ${attempt.FailureReason}${detailSuffix}.`;
        }
        case "missed":
            return `${role} returned 0 matches; advancing to next candidate.`;
        case "pending":
            return `${role} not evaluated — earlier attempt already matched.`;
    }
}

/**
 * Walk the attempts array in declared order (resolver guarantees primary
 * first, then fallbacks) and produce a per-step trace mirroring what the
 * live replay loop actually executed.
 */
export function buildReplayTrace(attempts: ReadonlyArray<SelectorAttempt>): ReplayTrace {
    if (attempts.length === 0) {
        return {
            Steps: [],
            Summary: { Total: 0, Evaluated: 0, Skipped: 0, StoppedAt: null, Outcome: "empty" },
        };
    }

    const steps: TraceStep[] = [];
    let stoppedAt: number | null = null;
    let evaluated = 0;

    for (let i = 0; i < attempts.length; i++) {
        const a = attempts[i];
        const stopped = stoppedAt !== null;
        const status = classify(a, stopped);
        const role: "Primary" | "Fallback" = a.IsPrimary ? "Primary" : "Fallback";
        if (!stopped) {
            evaluated++;
            if (status === "matched") stoppedAt = i + 1;
        }
        steps.push({
            Order: i + 1,
            Role: role,
            Strategy: a.Strategy,
            Expression: a.Expression,
            ResolvedExpression: a.ResolvedExpression.length > 0 ? a.ResolvedExpression : a.Expression,
            Matched: a.Matched,
            MatchCount: a.MatchCount,
            Status: status,
            FailureReason: a.FailureReason,
            FailureDetail: a.FailureDetail,
            Note: noteFor(a, status, role),
        });
    }

    return {
        Steps: steps,
        Summary: {
            Total: attempts.length,
            Evaluated: evaluated,
            Skipped: attempts.length - evaluated,
            StoppedAt: stoppedAt,
            Outcome: stoppedAt !== null ? "matched" : "exhausted",
        },
    };
}

/**
 * Marco Extension — Content Script: Message Relay
 *
 * Bridges communication between injected scripts (macro controller)
 * and the background service worker. Listens for window.postMessage
 * from the page, validates origin/source, forwards to background via
 * chrome.runtime.sendMessage, and relays responses back.
 *
 * Also forwards unsolicited broadcasts from the background back to
 * the page via window.postMessage.
 *
 * See spec/05-chrome-extension/43-macro-controller-extension-bridge.md
 *
 * Canonical source — chrome-extension/src/content-scripts/ re-exports from here.
 */

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const SOURCE_CONTROLLER = "marco-controller";
const SOURCE_SDK = "marco-sdk";
const SOURCE_EXTENSION = "marco-extension";
const RESPONSE_TYPE = "RESPONSE";

/** Message types that are allowed to be forwarded from page to background. */
const ALLOWED_TYPES = new Set([
    "USER_SCRIPT_LOG",
    "USER_SCRIPT_ERROR",
    "USER_SCRIPT_DATA_SET",
    "USER_SCRIPT_DATA_GET",
    "USER_SCRIPT_DATA_DELETE",
    "USER_SCRIPT_DATA_KEYS",
    "USER_SCRIPT_DATA_GET_ALL",
    "USER_SCRIPT_DATA_CLEAR",
    "RECORD_CYCLE_METRIC",
    "GET_RUN_STATS",
    "GET_CONFIG",
    "GET_TOKEN",
    "REFRESH_TOKEN",
    "GET_API_STATUS",
    "GET_API_ENDPOINTS",
    // ─── Prompt CRUD (Spec 45) ───
    "GET_PROMPTS",
    "SAVE_PROMPT",
    "DELETE_PROMPT",
    "REORDER_PROMPTS",
    // ─── Project KV Store (Issue 50) ───
    "KV_GET",
    "KV_SET",
    "KV_DELETE",
    "KV_LIST",
    // ─── Grouped KV Store (Issue 60) ───
    "GKV_GET",
    "GKV_SET",
    "GKV_DELETE",
    "GKV_LIST",
    "GKV_CLEAR_GROUP",
    // ─── Project File Storage (Issue 50) ───
    "FILE_SAVE",
    "FILE_GET",
    "FILE_LIST",
    "FILE_DELETE",
    // ─── Marco SDK (Spec 18) ───
    "AUTH_GET_TOKEN",
    "AUTH_GET_SOURCE",
    "AUTH_REFRESH",
    "AUTH_IS_EXPIRED",
    "AUTH_GET_JWT",
    "COOKIES_GET",
    "COOKIES_GET_DETAIL",
    "COOKIES_GET_ALL",
    "CONFIG_GET",
    "CONFIG_GET_ALL",
    "CONFIG_SET",
    "XPATH_GET",
    "XPATH_GET_ALL",
    "FILE_READ",
    // ─── Script Hot-Reload (Issue 77) ───
    "GET_SCRIPT_INFO",
    "HOT_RELOAD_SCRIPT",
    // ─── Project SQLite / KV / role-scoped prompt CRUD ───
    // Every DB call in standalone-scripts/macro-controller/src/db/*
    // (prompt-db, prompt-revision-db, prompt-role-db, macro-db,
    // project-chat-submit-db, database-modal-data, seed-plan-next,
    // reseed-command, database-json-migrate) posts this type via
    // sendToExtension. Omitting it here made the content-script relay
    // reject the message with "Blocked disallowed message type:
    // PROJECT_API", surfacing as red "Load error" rows for every role
    // (plan / next / generic) in the Prompt Library modal.
    "PROJECT_API",
]);

/** Broadcast types sent from background → content script → page. */
const BROADCAST_TYPES = new Set([
    "CONFIG_UPDATED",
    "CONFIG_CHANGED",
    "TOKEN_EXPIRED",
    "TOKEN_UPDATED",
]);

/* ------------------------------------------------------------------ */
/*  Rate Limiting                                                      */
/* ------------------------------------------------------------------ */

const RATE_LIMIT_WINDOW_MS = 1000;
const RATE_LIMIT_MAX = 100;

let rateLimitCount = 0;
let rateLimitResetTime = Date.now() + RATE_LIMIT_WINDOW_MS;

/**
 * Checks whether the current message should be rate-limited.
 * Returns true if the message is allowed, false if throttled.
 */
function checkRateLimit(): boolean {
    const now = Date.now();
    const isWindowExpired = now >= rateLimitResetTime;

    if (isWindowExpired) {
        rateLimitCount = 0;
        rateLimitResetTime = now + RATE_LIMIT_WINDOW_MS;
    }

    rateLimitCount++;

    return rateLimitCount <= RATE_LIMIT_MAX;
}

/* ------------------------------------------------------------------ */
/*  Page → Background Relay                                            */
/* ------------------------------------------------------------------ */

/**
 * Validates and forwards messages from the page to the background.
 * Only processes messages with source === 'marco-controller' and
 * an allowed message type.
 */
function handlePageMessage(event: MessageEvent): void {
    const isFromSamePage = event.source === window;

    if (!isFromSamePage) {
        return;
    }

    const data = event.data as Record<string, unknown>;
    const messageSource = data?.source as string | undefined;
    const isFromController = messageSource === SOURCE_CONTROLLER;
    const isFromSdk = messageSource === SOURCE_SDK;

    if (!isFromController && !isFromSdk) {
        return;
    }

    const requestId = typeof data.requestId === "string"
        ? data.requestId
        : undefined;

    const messageType = String(data.type ?? "");
    const isAllowedType = ALLOWED_TYPES.has(messageType);

    if (!isAllowedType) {
        console.warn(
            `[Marco Relay] Blocked disallowed message type: "${messageType}" from source "${String(data.source ?? "unknown")}". Allowed types: ${[...ALLOWED_TYPES].join(", ")}`,
        );
        postResponseToPage(requestId, {
            isOk: false,
            errorMessage: `Blocked disallowed message type: ${messageType}`,
        }, isFromSdk);
        return;
    }

    const isWithinRateLimit = checkRateLimit();

    if (!isWithinRateLimit) {
        console.warn(`[Marco Relay] Rate limit exceeded, dropping message type="${messageType}" from source="${String(data.source ?? "unknown")}". Too many messages in sliding window.`);
        postResponseToPage(requestId, {
            isOk: false,
            errorMessage: "Relay rate limit exceeded",
        }, isFromSdk);
        return;
    }

    forwardToBackground(data, requestId, isFromSdk);
}

/**
 * Sends the validated message to the background service worker
 * and relays the response back to the page.
 *
 * L-5 (audit 2026-05-15): bound the number of in-flight sendMessage
 * callbacks. A stuck/slow background worker that never invokes the
 * callback would otherwise let the page accumulate unbounded closures.
 */
const MAX_INFLIGHT_RELAY_REQUESTS = 50;
let _inFlightRelayRequests = 0;

function forwardToBackground(
    message: Record<string, unknown>,
    requestId: string | undefined,
    isSdkSource: boolean = false,
): void {
    if (_inFlightRelayRequests >= MAX_INFLIGHT_RELAY_REQUESTS) {
        console.warn(
            `[Marco Relay] In-flight cap reached (${MAX_INFLIGHT_RELAY_REQUESTS}) — rejecting message type="${String(message.type ?? "unknown")}" to prevent leak`,
        );
        postResponseToPage(requestId, {
            isOk: false,
            errorMessage: "Relay overloaded — too many in-flight requests",
        }, isSdkSource);
        return;
    }

    _inFlightRelayRequests++;
    let settled = false;
    const release = (): void => {
        if (settled) { return; }
        settled = true;
        _inFlightRelayRequests--;
    };

    try {
        chrome.runtime.sendMessage(message, (response: unknown) => {
            const hasError = chrome.runtime.lastError;

            if (hasError) {
                release();
                postResponseToPage(requestId, {
                    isOk: false,
                    errorMessage:
                        chrome.runtime.lastError?.message ??
                        "Extension context invalidated",
                }, isSdkSource);
                return;
            }

            release();
            postResponseToPage(requestId, response, isSdkSource);
        });
    } catch (sendError) {
        release();
        const errorMessage = sendError instanceof Error
            ? sendError.message
            : String(sendError);

        postResponseToPage(requestId, {
            isOk: false,
            errorMessage: errorMessage || "Failed to send message to extension",
        }, isSdkSource);
    }
}

/**
 * Posts a response back to the page.
 * SDK messages use a different response format (source: "marco-sdk-response").
 */
function postResponseToPage(
    requestId: string | undefined,
    payload: unknown,
    isSdkResponse: boolean = false,
): void {
    if (isSdkResponse) {
        // SDK bridge expects { source: "marco-sdk-response", requestId, result/error }
        const sdkPayload = payload as Record<string, unknown> | null;
        const hasError = sdkPayload && sdkPayload.isOk === false;
        window.postMessage(
            {
                source: "marco-sdk-response",
                requestId: requestId ?? null,
                ...(hasError
                    ? { error: sdkPayload.errorMessage ?? "Unknown error" }
                    : { result: sdkPayload }),
            },
            "*",
        );
    } else {
        window.postMessage(
            {
                source: SOURCE_EXTENSION,
                type: RESPONSE_TYPE,
                requestId: requestId ?? null,
                payload,
            },
            "*",
        );
    }
}

/* ------------------------------------------------------------------ */
/*  Background → Page Relay (Broadcasts)                               */
/* ------------------------------------------------------------------ */

/**
 * Listens for unsolicited messages from the background service worker
 * (e.g., CONFIG_UPDATED, TOKEN_EXPIRED) and forwards them to the page.
 */
function handleBackgroundMessage(
    message: Record<string, unknown>,
    _sender: chrome.runtime.MessageSender,
    sendResponse: (response?: unknown) => void,
): boolean {
    const messageType = message.type as string;

    // ─── Background → Page request/response: workspace probe ───
    // Used by the "Open Lovable Tabs" panel in macro-controller to ask each
    // tab what workspace it has detected. We forward to the MAIN-world page
    // responder via window.postMessage and wait for a matching reply.
    if (messageType === "PROBE_DETECTED_WORKSPACE") {
        probeDetectedWorkspaceFromPage(sendResponse);
        return true; // async response
    }

    const isBroadcast = BROADCAST_TYPES.has(messageType);

    if (!isBroadcast) {
        return false;
    }

    // Forward to controller.
    // Include both top-level fields and payload for backward compatibility.
    const forwardedPayload = (message.payload ?? message) as Record<string, unknown>;

    window.postMessage(
        {
            ...forwardedPayload,
            source: SOURCE_EXTENSION,
            type: messageType,
            payload: forwardedPayload,
        },
        "*",
    );

    // Also forward CONFIG_CHANGED to SDK listeners
    if (messageType === "CONFIG_CHANGED") {
        const payload = (message.payload ?? message) as Record<string, unknown>;
        window.postMessage(
            {
                source: "marco-sdk-event",
                type: "CONFIG_CHANGED",
                key: payload.key,
                value: payload.value,
            },
            "*",
        );
    }

    return false; // No async response needed
}

/**
 * Asks the MAIN-world macro-controller (via window.postMessage) for its
 * detected workspace snapshot, then resolves via sendResponse. Times out
 * gracefully so a tab without the controller injected never blocks the
 * background handler.
 */
const PROBE_REQUEST_SOURCE = "marco-extension-request";
const PROBE_RESPONSE_SOURCE = "marco-controller-response";
const PROBE_TYPE = "GET_DETECTED_WORKSPACE";
const PROBE_TIMEOUT_MS = 600;

function probeDetectedWorkspaceFromPage(
    sendResponse: (response?: unknown) => void,
): void {
    const requestId = "wsprobe_" + Date.now() + "_" + Math.random().toString(36).slice(2, 8);
    let settled = false;

    const finish = (payload: unknown, ok: boolean, error?: string): void => {
        if (settled) return;
        settled = true;
        window.removeEventListener("message", onReply);
        sendResponse({ isOk: ok, payload: payload, errorMessage: error });
    };

    const onReply = (event: MessageEvent): void => {
        if (event.source !== window) return;
        const data = event.data as Record<string, unknown> | null;
        if (!data) return;
        if (data.source !== PROBE_RESPONSE_SOURCE) return;
        if (data.type !== PROBE_TYPE) return;
        if (data.requestId !== requestId) return;
        finish(data.payload ?? null, data.payload !== null && data.payload !== undefined,
            typeof data.errorMessage === "string" ? data.errorMessage : undefined);
    };

    window.addEventListener("message", onReply);
    window.postMessage({
        source: PROBE_REQUEST_SOURCE,
        type: PROBE_TYPE,
        requestId: requestId,
    }, "*");

    setTimeout(() => finish(null, false, "probe timeout — controller not responding"), PROBE_TIMEOUT_MS);
}

/* ------------------------------------------------------------------ */
/*  Initialization                                                     */
/* ------------------------------------------------------------------ */

function initMessageRelay(): void {
    // Sentinel for programmatic re-injection detection
    if ((window as unknown as Record<string, unknown>).__marcoRelayActive) {
        console.log("[Marco] Message relay already active — skipping duplicate init");
        return;
    }
    (window as unknown as Record<string, unknown>).__marcoRelayActive = true;

    // Page → Background
    window.addEventListener("message", handlePageMessage);

    // Background → Page
    chrome.runtime.onMessage.addListener(handleBackgroundMessage);

    console.log("[Marco] Message relay initialized");
}

initMessageRelay();

/* ------------------------------------------------------------------ */
/*  Home-Screen / Lovable-Dashboard Bootstrap                          */
/*  Moved out of message-relay into the standalone `lovable-dashboard` */
/*  project (standalone-scripts/lovable-dashboard). That script is     */
/*  auto-injected by the background standalone-seeder pipeline; do not */
/*  boot it here to avoid double-injection.                            */
/* ------------------------------------------------------------------ */

/**
 * Marco Extension — Prompt Injector (Content Script)
 *
 * v2.170.0: Refactored to standalone bundle injected via
 * `chrome.scripting.executeScript({ files: [...] })`. Args are handed off
 * via `chrome.storage.session` keyed by a correlation ID; the result is
 * posted back to the background via `chrome.runtime.sendMessage`.
 *
 * Bundle activation contract:
 *   1. Background writes args to `chrome.storage.session` under
 *      `marco_prompt_args.<correlationId>` (TTL: until consumed).
 *   2. Background calls `executeScript({ files: ["content-scripts/prompt-injector.js"] })`.
 *      Chrome may still pass extra metadata via the `world: "ISOLATED"` content-script
 *      `chrome.scripting.executeScript` API. We rely on session storage instead.
 *   3. Bundle bootstrap reads ALL pending args, runs `injectPromptText` for each one,
 *      then posts `{ type: "PROMPT_INJECT_RESULT", correlationId, success, verified, ... }`
 *      and deletes the consumed key.
 *
 * Why pull-all-pending instead of single-key:
 *   `executeScript({ files })` does not let us pass argv. The content script has no
 *   way to know its correlation ID at startup. Reading the entire pending queue and
 *   processing every entry is robust to repeat injection and lost runs.
 */

import { logError } from "./prompt-injector-logger";

/* ------------------------------------------------------------------ */
/*  Editor Discovery                                                   */
/* ------------------------------------------------------------------ */

function findEditorByXPath(xpath: string): HTMLElement | null {
    try {
        const result = document.evaluate(xpath, document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null);
        const node = result.singleNodeValue;
        if (!node) return null;
        // Walk up to find the nearest contenteditable or input/textarea
        let el = node as HTMLElement;
        while (el && el !== document.body) {
            if (el.getAttribute?.("contenteditable") === "true" ||
                el instanceof HTMLTextAreaElement ||
                el instanceof HTMLInputElement) {
                return el;
            }
            el = el.parentElement as HTMLElement;
        }
        return null;
    } catch {
        return null;
    }
}

function findTiptapEditor(chatBoxXPath?: string): HTMLElement | null {
    // Try XPath-based discovery first
    if (chatBoxXPath) {
        const xpathResult = findEditorByXPath(chatBoxXPath);
        if (xpathResult) return xpathResult;
    }

    // Fallback: CSS selectors
    const selectors = [
        ".tiptap.ProseMirror",
        ".ProseMirror[contenteditable='true']",
        "[contenteditable='true'].tiptap",
        "form [contenteditable='true']",
        "[role='textbox'][contenteditable='true']",
        "textarea",
    ];

    for (const sel of selectors) {
        const el = document.querySelector<HTMLElement>(sel);
        if (el) return el;
    }
    return null;
}

/* ------------------------------------------------------------------ */
/*  DOM Append Insertion                                               */
/* ------------------------------------------------------------------ */

/**
 * Appends prompt text to the editor using direct DOM manipulation.
 * For contenteditable: creates a <p> element and appends it.
 * For textarea/input: appends text to .value.
 * Never uses clipboard APIs or execCommand.
 */
function appendToEditor(editor: HTMLElement, text: string): boolean {
    try {
        editor.focus();

        if (editor instanceof HTMLTextAreaElement || editor instanceof HTMLInputElement) {
            // For textarea/input: append text to existing value
            const currentVal = editor.value ?? "";
            const newVal = currentVal + (currentVal.length > 0 ? "\n" : "") + text;
            const nativeSetter =
                Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, "value")?.set ??
                Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, "value")?.set;

            if (nativeSetter) {
                nativeSetter.call(editor, newVal);
            } else {
                editor.value = newVal;
            }
            editor.dispatchEvent(new Event("input", { bubbles: true }));
            editor.dispatchEvent(new Event("change", { bubbles: true }));
        } else {
            // For contenteditable (ProseMirror/Tiptap): create a <p> and append it
            const p = document.createElement("p");
            p.textContent = text;
            editor.appendChild(p);
            // Dispatch input event so the editor framework picks up the change
            editor.dispatchEvent(new InputEvent("input", { bubbles: true, inputType: "insertText" }));
            // Move cursor to end of the new content
            const sel = window.getSelection();
            if (sel) {
                const range = document.createRange();
                range.selectNodeContents(p);
                range.collapse(false);
                sel.removeAllRanges();
                sel.addRange(range);
            }
        }

        console.log(`[Marco] Prompt appended (${text.length} chars)`);
        return true;
    } catch (err) {
        logError(
            "appendToEditor",
            `Prompt append failed\n  Path: DOM target element (contenteditable/textarea/ProseMirror)\n  Missing: Successful text insertion of ${text.length} chars\n  Reason: ${err instanceof Error ? err.message : String(err)} — DOM element may not be found or not editable`,
            err,
        );
        return false;
    }
}

/* ------------------------------------------------------------------ */
/*  Auto-Submit                                                        */
/* ------------------------------------------------------------------ */

function findSubmitButton(): HTMLElement | null {
    const selectors = [
        'button[type="submit"]',
        'form button:last-of-type',
        'button[aria-label*="send" i]',
        'button[aria-label*="submit" i]',
        'button svg[class*="arrow"]',
        'button svg[class*="send"]',
        'form [role="button"]',
    ];

    for (const sel of selectors) {
        const el = document.querySelector<HTMLElement>(sel);
        if (el) {
            const btn = el.closest("button") ?? el;
            if (btn && !btn.hasAttribute("disabled")) return btn as HTMLElement;
        }
    }

    // Fallback: last enabled button inside a form containing the editor
    const editor = findTiptapEditor();
    if (editor) {
        const form = editor.closest("form");
        if (form) {
            const buttons = form.querySelectorAll<HTMLButtonElement>("button:not([disabled])");
            if (buttons.length > 0) return buttons[buttons.length - 1];
        }
    }

    return null;
}

function triggerSubmit(): boolean {
    const btn = findSubmitButton();
    if (btn) {
        console.log("[Marco] Auto-submit: clicking send button");
        btn.click();
        return true;
    }

    const editor = findTiptapEditor();
    if (editor) {
        console.log("[Marco] Auto-submit: sending Enter key");
        editor.dispatchEvent(new KeyboardEvent("keydown", {
            key: "Enter",
            code: "Enter",
            keyCode: 13,
            which: 13,
            bubbles: true,
            cancelable: true,
        }));
        return true;
    }

    return false;
}

/* ------------------------------------------------------------------ */
/*  Public API (still exported for future imports)                     */
/* ------------------------------------------------------------------ */

export interface InjectOptions {
    autoSubmit?: boolean;
    submitDelayMs?: number;
    chatBoxXPath?: string;
}

export interface InjectResult {
    success: boolean;
    method: string;
    verified: boolean;
    submitted: boolean;
}

export async function injectPromptText(text: string, options?: InjectOptions): Promise<InjectResult> {
    const editor = findTiptapEditor(options?.chatBoxXPath);
    if (!editor) {
        return { success: false, method: "none", verified: false, submitted: false };
    }

    const success = appendToEditor(editor, text);

    // Auto-submit after injection
    let submitted = false;
    if (success && (options?.autoSubmit ?? true)) {
        const delay = options?.submitDelayMs ?? 200;
        console.log(`[Marco] Waiting ${delay}ms before auto-submit`);
        await new Promise(r => setTimeout(r, delay));
        submitted = triggerSubmit();
    }

    return {
        success,
        method: success ? "dom-append" : "none",
        verified: success,
        submitted,
    };
}

/* ------------------------------------------------------------------ */
/*  Bootstrap — runs immediately when injected via                     */
/*  chrome.scripting.executeScript({ files: [...] })                   */
/* ------------------------------------------------------------------ */

/** Session-storage namespace shared with the background handler. */
const PROMPT_ARGS_KEY = "marco_prompt_args";

/** Result-message type — handled by an inline one-shot listener in the background. */
const PROMPT_INJECT_RESULT = "PROMPT_INJECT_RESULT";

interface PendingPromptArgs {
    text: string;
    chatBoxXPath?: string;
    autoSubmit?: boolean;
    submitDelayMs?: number;
}

/**
 * Drains all pending prompt-injection requests from session storage,
 * runs each one, and posts the result back. Idempotent: if no pending
 * requests exist, the bootstrap is a no-op (so this bundle is safe to
 * load statically in the future).
 */
// eslint-disable-next-line max-lines-per-function, sonarjs/cognitive-complexity -- content-script bootstrap: chrome guards + listener wiring + handshake all need shared closure
async function bootstrap(): Promise<void> {
    if (typeof chrome === "undefined" || !chrome.storage?.session || !chrome.runtime?.sendMessage) {
        return;
    }

    let pending: Record<string, PendingPromptArgs> = {};
    try {
        const stored = await chrome.storage.session.get(PROMPT_ARGS_KEY);
        pending = (stored[PROMPT_ARGS_KEY] as Record<string, PendingPromptArgs> | undefined) ?? {};
    } catch (err) {
        logError(
            "bootstrap.readSession",
            `Failed to read session storage\n  Path: chrome.storage.session.${PROMPT_ARGS_KEY}\n  Missing: pending args object\n  Reason: ${err instanceof Error ? err.message : String(err)}`,
            err,
        );
        return;
    }

    const correlationIds = Object.keys(pending);
    if (correlationIds.length === 0) return;

    for (const correlationId of correlationIds) {
        const args = pending[correlationId];
        let result: InjectResult;
        try {
            result = await injectPromptText(args.text, {
                chatBoxXPath: args.chatBoxXPath,
                autoSubmit: args.autoSubmit,
                submitDelayMs: args.submitDelayMs,
            });
        } catch (err) {
            result = {
                success: false,
                method: "error",
                verified: false,
                submitted: false,
            };
            logError(
                "bootstrap.injectPromptText",
                `Injection threw\n  Path: injectPromptText(correlationId=${correlationId})\n  Missing: completed injection\n  Reason: ${err instanceof Error ? err.message : String(err)}`,
                err,
            );
        }

        try {
            await chrome.runtime.sendMessage({
                type: PROMPT_INJECT_RESULT,
                correlationId,
                ...result,
            });
        } catch (err) {
            // Background may have torn down — no recovery possible.
            logError(
                "bootstrap.sendResult",
                `Failed to post result\n  Path: chrome.runtime.sendMessage(PROMPT_INJECT_RESULT, correlationId=${correlationId})\n  Missing: result delivery to background\n  Reason: ${err instanceof Error ? err.message : String(err)}`,
                err,
            );
        }
    }

    // Clear consumed args so a subsequent injection starts clean.
    try {
        const remaining = await chrome.storage.session.get(PROMPT_ARGS_KEY);
        const map = (remaining[PROMPT_ARGS_KEY] as Record<string, PendingPromptArgs> | undefined) ?? {};
        for (const id of correlationIds) delete map[id];
        if (Object.keys(map).length === 0) {
            await chrome.storage.session.remove(PROMPT_ARGS_KEY);
        } else {
            await chrome.storage.session.set({ [PROMPT_ARGS_KEY]: map });
        }
    } catch (err) {
        console.warn(
            `[Marco] prompt-injector: failed to clear consumed args (non-fatal): ${err instanceof Error ? err.message : String(err)}`,
        );
    }
}

void bootstrap();

/**
 * Marco Extension — useDraggable hook
 *
 * Pointer-driven drag for the floating recorder controller. Position is
 * persisted to `localStorage` under {@link POSITION_STORAGE_KEY} so it
 * survives reloads. Coordinates are clamped to the viewport on drag and on
 * window resize so the panel can never escape the screen.
 *
 * Returns:
 *   • `position` — current `{ x, y }` (or `null` until the user drags once;
 *     consumers should fall back to their default top/right CSS).
 *   • `containerRef` — attach to the draggable element (used for measuring
 *     bounds when clamping).
 *   • `handleProps` — spread onto the drag-handle element. Adds the
 *     pointer-down listener, cursor styles, and ARIA hints.
 *   • `isDragging` — true while a drag gesture is in flight.
 *
 * @see ../components/recorder/FloatingController.tsx
 */

import { useCallback, useEffect, useRef, useState } from "react";

export const POSITION_STORAGE_KEY = "marco-floating-controller-position";

export interface DragPosition {
    readonly x: number;
    readonly y: number;
}

interface PointerOffset {
    readonly dx: number;
    readonly dy: number;
}

const EDGE_PADDING_PX = 4;

function loadPosition(): DragPosition | null {
    if (typeof window === "undefined") { return null; }
    try {
        const raw = window.localStorage.getItem(POSITION_STORAGE_KEY);
        if (raw === null) { return null; }
        const parsed: unknown = JSON.parse(raw);
        if (
            typeof parsed === "object" && parsed !== null &&
            typeof (parsed as DragPosition).x === "number" &&
            typeof (parsed as DragPosition).y === "number" &&
            Number.isFinite((parsed as DragPosition).x) &&
            Number.isFinite((parsed as DragPosition).y)
        ) {
            return { x: (parsed as DragPosition).x, y: (parsed as DragPosition).y };
        }
    } catch { /* ignore */ } // allow-swallow: corrupt stored position falls back to default
    return null;
}

function savePosition(p: DragPosition): void {
    if (typeof window === "undefined") { return; }
    try { window.localStorage.setItem(POSITION_STORAGE_KEY, JSON.stringify(p)); } catch { /* ignore */ } // allow-swallow: localStorage quota/denied; position is convenience-only
}

function clamp(p: DragPosition, width: number, height: number): DragPosition {
    if (typeof window === "undefined") { return p; }
    const maxX = Math.max(EDGE_PADDING_PX, window.innerWidth - width - EDGE_PADDING_PX);
    const maxY = Math.max(EDGE_PADDING_PX, window.innerHeight - height - EDGE_PADDING_PX);
    return {
        x: Math.min(Math.max(EDGE_PADDING_PX, p.x), maxX),
        y: Math.min(Math.max(EDGE_PADDING_PX, p.y), maxY),
    };
}

export interface UseDraggableResult {
    readonly position: DragPosition | null;
    readonly isDragging: boolean;
    readonly containerRef: React.RefObject<HTMLDivElement>;
    readonly handleProps: {
        readonly onPointerDown: (e: React.PointerEvent<HTMLElement>) => void;
        readonly style: React.CSSProperties;
        readonly role: "button";
        readonly "aria-label": string;
        readonly "data-testid": string;
    };
    /** Reset to the default (top-right) position. */
    readonly reset: () => void;
}

export function useDraggable(): UseDraggableResult {
    const containerRef = useRef<HTMLDivElement>(null);
    const [position, setPosition] = useState<DragPosition | null>(() => loadPosition());
    const [isDragging, setIsDragging] = useState<boolean>(false);
    const offsetRef = useRef<PointerOffset>({ dx: 0, dy: 0 });
    const activePointerRef = useRef<number | null>(null);

    /* Reclamp on resize so the panel never gets stranded off-screen. */
    useEffect(() => {
        if (typeof window === "undefined") { return; }
        const onResize = () => {
            setPosition((prev) => {
                if (prev === null) { return prev; }
                const el = containerRef.current;
                if (el === null) { return prev; }
                const rect = el.getBoundingClientRect();
                const next = clamp(prev, rect.width, rect.height);
                if (next.x === prev.x && next.y === prev.y) { return prev; }
                savePosition(next);
                return next;
            });
        };
        window.addEventListener("resize", onResize);
        return () => window.removeEventListener("resize", onResize);
    }, []);

    const onPointerMove = useCallback((e: PointerEvent) => {
        if (activePointerRef.current === null || e.pointerId !== activePointerRef.current) { return; }
        const el = containerRef.current;
        const rect = el?.getBoundingClientRect();
        const w = rect?.width ?? 0;
        const h = rect?.height ?? 0;
        const next = clamp(
            { x: e.clientX - offsetRef.current.dx, y: e.clientY - offsetRef.current.dy },
            w,
            h,
        );
        setPosition(next);
    }, []);

    const onPointerUp = useCallback((e: PointerEvent) => {
        if (activePointerRef.current === null || e.pointerId !== activePointerRef.current) { return; }
        activePointerRef.current = null;
        setIsDragging(false);
        window.removeEventListener("pointermove", onPointerMove);
        window.removeEventListener("pointerup", onPointerUp);
        window.removeEventListener("pointercancel", onPointerUp);
        setPosition((p) => {
            if (p !== null) { savePosition(p); }
            return p;
        });
    }, [onPointerMove]);

    const onPointerDown = useCallback((e: React.PointerEvent<HTMLElement>) => {
        // Ignore non-primary buttons (e.g. right-click) and keyboard activation.
        if (e.button !== 0) { return; }
        const el = containerRef.current;
        if (el === null) { return; }
        const rect = el.getBoundingClientRect();
        offsetRef.current = { dx: e.clientX - rect.left, dy: e.clientY - rect.top };
        activePointerRef.current = e.pointerId;
        setIsDragging(true);
        // Seed the position with the current rect so the first move is smooth
        // even when we were still using the default top/right CSS.
        setPosition((prev) => prev ?? clamp({ x: rect.left, y: rect.top }, rect.width, rect.height));
        window.addEventListener("pointermove", onPointerMove);
        window.addEventListener("pointerup", onPointerUp);
        window.addEventListener("pointercancel", onPointerUp);
        e.preventDefault();
    }, [onPointerMove, onPointerUp]);

    const reset = useCallback(() => {
        setPosition(null);
        if (typeof window !== "undefined") {
            try { window.localStorage.removeItem(POSITION_STORAGE_KEY); } catch { /* ignore */ } // allow-swallow: localStorage denied; reset is best-effort
        }
    }, []);

    return {
        position,
        isDragging,
        containerRef,
        handleProps: {
            onPointerDown,
            style: { cursor: isDragging ? "grabbing" : "grab", touchAction: "none" },
            role: "button",
            "aria-label": "Drag floating controller",
            "data-testid": "controller-drag-handle",
        },
        reset,
    };
}

/**
 * Marco Extension — Recorder Project Data Hook
 *
 * Phase 10 — Project Visualisation.
 *
 * Loads the four recorder-scoped collections for one project:
 *   - Steps (ordered by OrderIndex ASC)
 *   - Selectors per Step (lazily, on demand)
 *   - DataSources
 *   - FieldBindings
 *
 * Exposes a single `reload()` so the panel can refresh after rename/delete.
 *
 * @see spec/31-macro-recorder/10-project-visualisation.md
 */

import { useCallback, useEffect, useState } from "react";
import { sendMessage } from "@/lib/message-client";

/* ------------------------------------------------------------------ */
/*  PascalCase row shapes (mirror server records)                      */
/* ------------------------------------------------------------------ */

export interface StepRow {
    readonly StepId: number;
    readonly StepKindId: number;
    readonly StepStatusId: number;
    readonly OrderIndex: number;
    readonly VariableName: string;
    readonly Label: string;
    readonly InlineJs: string | null;
    readonly IsBreakpoint: number;
    readonly CapturedAt: string;
    readonly UpdatedAt: string;
    /* Phase 14 chain fields (server returns them on every RECORDER_STEP_LIST). */
    readonly Description: string | null;
    readonly IsDisabled: number;
    readonly RetryCount: number;
    readonly TimeoutMs: number | null;
    readonly OnSuccessProjectId: string | null;
    readonly OnFailureProjectId: string | null;
}

export interface StepMetaPatch {
    readonly Label?: string;
    readonly Description?: string | null;
    readonly IsDisabled?: boolean;
    readonly RetryCount?: number;
    readonly TimeoutMs?: number | null;
}

export type StepLinkSlot = "OnSuccessProjectId" | "OnFailureProjectId";

export interface SelectorRow {
    readonly SelectorId: number;
    readonly StepId: number;
    readonly SelectorKindId: number;
    readonly Expression: string;
    readonly AnchorSelectorId: number | null;
    readonly IsPrimary: number;
}

export interface DataSourceRow {
    readonly DataSourceId: number;
    readonly DataSourceKindId: number;
    readonly FilePath: string;
    readonly Columns: ReadonlyArray<string>;
    readonly RowCount: number;
    readonly CreatedAt: string;
}

export interface FieldBindingRow {
    readonly FieldBindingId: number;
    readonly StepId: number;
    readonly DataSourceId: number;
    readonly ColumnName: string;
    readonly CreatedAt: string;
}

export interface RecorderProjectData {
    readonly steps: ReadonlyArray<StepRow>;
    readonly dataSources: ReadonlyArray<DataSourceRow>;
    readonly bindings: ReadonlyArray<FieldBindingRow>;
}

interface HookResult {
    data: RecorderProjectData | null;
    loading: boolean;
    error: string | null;
    reload: () => Promise<void>;
    loadSelectors: (stepId: number) => Promise<ReadonlyArray<SelectorRow>>;
    /** Phase 14 — per-step tag cache, keyed by StepId. */
    tagsByStep: ReadonlyMap<number, ReadonlyArray<string>>;
    /** Patch step meta and splice the returned row into local state. */
    updateStepMeta: (stepId: number, patch: StepMetaPatch) => Promise<void>;
    /** Replace the tag set for a step and cache the returned list. */
    setStepTags: (stepId: number, tags: ReadonlyArray<string>) => Promise<void>;
    /** Set/clear OnSuccessProjectId or OnFailureProjectId for a step. */
    setStepLink: (
        stepId: number,
        slot: StepLinkSlot,
        targetProjectSlug: string | null,
    ) => Promise<void>;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

export function useRecorderProjectData(projectSlug: string): HookResult {
    const [data, setData] = useState<RecorderProjectData | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [tagsByStep, setTagsByStep] = useState<ReadonlyMap<number, ReadonlyArray<string>>>(
        new Map(),
    );

    const reload = useCallback(async () => {
        if (!projectSlug) return;
        setLoading(true);
        setError(null);
        try {
            const [stepsRes, dsRes, fbRes] = await Promise.all([
                sendMessage<{ steps: ReadonlyArray<StepRow> }>({
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    type: "RECORDER_STEP_LIST" as any,
                    projectSlug,
                }),
                sendMessage<{ dataSources: ReadonlyArray<DataSourceRow> }>({
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    type: "RECORDER_DATA_SOURCE_LIST" as any,
                    projectSlug,
                }),
                sendMessage<{ bindings: ReadonlyArray<FieldBindingRow> }>({
                    // eslint-disable-next-line @typescript-eslint/no-explicit-any
                    type: "RECORDER_FIELD_BINDING_LIST" as any,
                    projectSlug,
                }),
            ]);
            setData({
                steps: stepsRes.steps ?? [],
                dataSources: dsRes.dataSources ?? [],
                bindings: fbRes.bindings ?? [],
            });
        } catch (err) {
            setError(err instanceof Error ? err.message : String(err));
            setData({ steps: [], dataSources: [], bindings: [] });
        } finally {
            setLoading(false);
        }
    }, [projectSlug]);

    const loadSelectors = useCallback(
        async (stepId: number): Promise<ReadonlyArray<SelectorRow>> => {
            const list = await sendMessage<{ selectors: ReadonlyArray<SelectorRow> }>({
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                type: "RECORDER_STEP_SELECTORS_LIST" as any,
                projectSlug,
                stepId,
            }).catch(() => ({ selectors: [] as ReadonlyArray<SelectorRow> }));
            return list.selectors;
        },
        [projectSlug],
    );

    /* -------- Phase 14 — local-state refresh helpers ----------------- */

    const spliceStep = useCallback((updated: StepRow) => {
        setData((prev) => {
            if (prev === null) return prev;
            return {
                ...prev,
                steps: prev.steps.map((s) => (s.StepId === updated.StepId ? updated : s)),
            };
        });
    }, []);

    const updateStepMeta = useCallback(
        async (stepId: number, patch: StepMetaPatch) => {
            const res = await sendMessage<{ isOk: true; step: StepRow }>({
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                type: "RECORDER_STEP_UPDATE_META" as any,
                projectSlug,
                stepId,
                patch,
            });
            spliceStep(res.step);
        },
        [projectSlug, spliceStep],
    );

    const setStepTags = useCallback(
        async (stepId: number, tags: ReadonlyArray<string>) => {
            const res = await sendMessage<{ isOk: true; tags: ReadonlyArray<string> }>({
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                type: "RECORDER_STEP_TAGS_SET" as any,
                projectSlug,
                stepId,
                tags,
            });
            setTagsByStep((prev) => {
                const next = new Map(prev);
                next.set(stepId, res.tags);
                return next;
            });
        },
        [projectSlug],
    );

    const setStepLink = useCallback(
        async (
            stepId: number,
            slot: StepLinkSlot,
            targetProjectSlug: string | null,
        ) => {
            const res = await sendMessage<{ isOk: true; step: StepRow }>({
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                type: "RECORDER_STEP_LINK_SET" as any,
                projectSlug,
                stepId,
                slot,
                targetProjectSlug,
            });
            spliceStep(res.step);
        },
        [projectSlug, spliceStep],
    );

    useEffect(() => {
        void reload();
    }, [reload]);

    return {
        data,
        loading,
        error,
        reload,
        loadSelectors,
        tagsByStep,
        updateStepMeta,
        setStepTags,
        setStepLink,
    };
}

/**
 * Marco Extension — Active Recording Session Hook
 *
 * Subscribes the React UI to the recorder draft maintained by the extension
 * backend. All transport details (chrome.storage.local in extension context,
 * window.localStorage in the preview, in-memory fallback otherwise) are
 * encapsulated in {@link recorder-session-sync}, so this hook is a thin
 * React binding plus the imperative dispatchers (start/pause/resume/stop).
 *
 * @see ../lib/recorder-session-sync.ts                  — shared transport
 * @see ../background/recorder/recorder-store.ts          — pure reducer
 * @see ../background/recorder/recorder-session-storage.ts — backend writer
 */

import { useCallback, useEffect, useState } from "react";

import {
    recorderReducer,
    type RecorderAction,
} from "@/background/recorder/recorder-store";
import type { RecordingSession } from "@/background/recorder/recorder-session-types";
import {
    readSession,
    subscribeRecorderSession,
    writeSession,
} from "@/lib/recorder-session-sync";

export interface UseRecordingSessionResult {
    /** Current active session, or null when Idle / no draft. */
    readonly session: RecordingSession | null;
    /** True while the initial storage read is in flight. */
    readonly loading: boolean;
    readonly start: (projectSlug?: string) => Promise<void>;
    readonly pause: () => Promise<void>;
    readonly resume: () => Promise<void>;
    readonly stop: () => Promise<void>;
}

function newSessionId(): string {
    const c = (globalThis as { crypto?: { randomUUID?: () => string } }).crypto;
    if (c?.randomUUID !== undefined) { return c.randomUUID(); }
    return `sess-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

export function useRecordingSession(): UseRecordingSessionResult {
    const [session, setSession] = useState<RecordingSession | null>(null);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        let cancelled = false;
        const unsubscribe = subscribeRecorderSession((next) => {
            if (cancelled) { return; }
            setSession(next);
            setLoading(false);
        });
        return () => {
            cancelled = true;
            unsubscribe();
        };
    }, []);

    const dispatch = useCallback(async (action: RecorderAction) => {
        const current = await readSession();
        if (current === null) { return; }
        const next = recorderReducer(current, action);
        await writeSession(next);
        // The transport will broadcast back to us, but set local state
        // synchronously too so the dispatcher feels instant.
        setSession(next.Phase === "Idle" ? null : next);
    }, []);

    const start = useCallback(async (projectSlug?: string) => {
        const current = await readSession();
        if (current !== null && current.Phase !== "Idle") { return; }
        const seed: RecordingSession = {
            SessionId: "",
            ProjectSlug: projectSlug ?? "default",
            StartedAt: "",
            Phase: "Idle",
            Steps: [],
        };
        const next = recorderReducer(seed, {
            Kind: "Start",
            ProjectSlug: projectSlug ?? "default",
            SessionId: newSessionId(),
            StartedAt: new Date().toISOString(),
        });
        await writeSession(next);
        setSession(next);
    }, []);

    const pause = useCallback(() => dispatch({ Kind: "Pause" }), [dispatch]);
    const resume = useCallback(() => dispatch({ Kind: "Resume" }), [dispatch]);
    const stop = useCallback(() => dispatch({ Kind: "Stop" }), [dispatch]);

    return { session, loading, start, pause, resume, stop };
}

/**
 * Marco Extension — useShiftClickSelection
 *
 * Generic Gmail-style multi-select hook. Tracks an ordered list of item ids
 * and a current selection set, plus an "anchor" id used for shift-click range
 * extension.
 *
 *   • Plain click (no modifier)     → selects only that row, anchor = row.
 *   • Ctrl/Cmd-click                → toggles that row, anchor = row.
 *   • Shift-click                   → selects every row between anchor and
 *                                     row inclusive (replaces selection).
 *                                     If no anchor yet, behaves like a plain
 *                                     click and sets the anchor.
 *
 * Designed as a pure hook so it can drive any list (keyword events, steps,
 * sessions, scripts, projects). Caller passes the current ordered ids on
 * every render — we recompute nothing extra unless the ids actually change.
 *
 * Selection survives reorder/insertion: ids that disappear from the list are
 * silently pruned so the selection set never holds dangling references.
 *
 * @see ./__tests__/use-shift-click-selection.test.tsx
 */

import { useCallback, useEffect, useMemo, useRef, useState } from "react";

export type SelectionId = string | number;

export interface ShiftClickModifiers {
    readonly shiftKey: boolean;
    /** Either Ctrl (Win/Linux) or Meta/⌘ (macOS). Caller normalises. */
    readonly toggleKey: boolean;
}

export interface UseShiftClickSelectionApi<Id extends SelectionId> {
    /** Read-only Set of currently-selected ids. */
    readonly selected: ReadonlySet<Id>;
    /** Current anchor id (last "primary" click), or null if none. */
    readonly anchor: Id | null;
    /** Convenience: true when `id` is in the selection set. */
    readonly isSelected: (id: Id) => boolean;
    /**
     * Handle a click on `id` honouring shift / toggle modifiers. Returns the
     * resulting selection so callers can react synchronously if needed.
     */
    readonly handleClick: (id: Id, mods: ShiftClickModifiers) => ReadonlySet<Id>;
    /** Replace the selection with the given ids (e.g. "Select all"). */
    readonly setSelection: (ids: Iterable<Id>) => void;
    /** Empty the selection and clear the anchor. */
    readonly clear: () => void;
}

/**
 * Computes the inclusive range of ids between `from` and `to` in `orderedIds`.
 * Order of `from`/`to` does not matter. Unknown ids return an empty array.
 */
export function computeRange<Id extends SelectionId>(
    orderedIds: ReadonlyArray<Id>,
    from: Id,
    to: Id,
): Id[] {
    const fromIdx = orderedIds.indexOf(from);
    const toIdx = orderedIds.indexOf(to);
    if (fromIdx < 0 || toIdx < 0) return [];
    const [lo, hi] = fromIdx <= toIdx ? [fromIdx, toIdx] : [toIdx, fromIdx];
    return orderedIds.slice(lo, hi + 1);
}

/**
 * Pure selection reducer — exported for unit tests so we can assert the
 * full transition table without spinning up React.
 */
export function reduceSelectionClick<Id extends SelectionId>(
    current: ReadonlySet<Id>,
    anchor: Id | null,
    orderedIds: ReadonlyArray<Id>,
    clickedId: Id,
    mods: ShiftClickModifiers,
): { next: Set<Id>; nextAnchor: Id | null } {
    if (mods.shiftKey && anchor !== null && anchor !== clickedId) {
        const range = computeRange(orderedIds, anchor, clickedId);
        if (range.length > 0) {
            return { next: new Set(range), nextAnchor: anchor };
        }
        // Range failed (anchor pruned) — treat as a plain click.
    }

    if (mods.toggleKey) {
        const next = new Set(current);
        if (next.has(clickedId)) {
            next.delete(clickedId);
        } else {
            next.add(clickedId);
        }
        return { next, nextAnchor: clickedId };
    }

    return { next: new Set<Id>([clickedId]), nextAnchor: clickedId };
}

export function useShiftClickSelection<Id extends SelectionId>(
    orderedIds: ReadonlyArray<Id>,
): UseShiftClickSelectionApi<Id> {
    const [selected, setSelected] = useState<ReadonlySet<Id>>(() => new Set<Id>());
    const [anchor, setAnchor] = useState<Id | null>(null);

    // Keep latest snapshot in a ref so handleClick stays referentially stable.
    const stateRef = useRef({ selected, anchor, orderedIds });
    stateRef.current = { selected, anchor, orderedIds };

    // Prune ids that vanished from the list (e.g. after delete/filter).
    useEffect(() => {
        const known = new Set(orderedIds);
        const pruned = new Set<Id>();
        let mutated = false;
        for (const id of selected) {
            if (known.has(id)) {
                pruned.add(id);
            } else {
                mutated = true;
            }
        }
        if (mutated) setSelected(pruned);
        if (anchor !== null && !known.has(anchor)) setAnchor(null);
    }, [orderedIds, selected, anchor]);

    const handleClick = useCallback((id: Id, mods: ShiftClickModifiers): ReadonlySet<Id> => {
        const snap = stateRef.current;
        const { next, nextAnchor } = reduceSelectionClick(
            snap.selected, snap.anchor, snap.orderedIds, id, mods,
        );
        setSelected(next);
        setAnchor(nextAnchor);
        return next;
    }, []);

    const setSelection = useCallback((ids: Iterable<Id>) => {
        setSelected(new Set(ids));
    }, []);

    const clear = useCallback(() => {
        setSelected(new Set<Id>());
        setAnchor(null);
    }, []);

    const isSelected = useCallback((id: Id) => selected.has(id), [selected]);

    return useMemo(() => ({
        selected, anchor, isSelected, handleClick, setSelection, clear,
    }), [selected, anchor, isSelected, handleClick, setSelection, clear]);
}

/**
 * Convenience: derive {shiftKey, toggleKey} from a native MouseEvent honouring
 * the platform (Cmd on macOS, Ctrl elsewhere).
 */
export function modifiersFromMouseEvent(
    event: { shiftKey: boolean; ctrlKey: boolean; metaKey: boolean },
    isMac: boolean,
): ShiftClickModifiers {
    return {
        shiftKey: event.shiftKey,
        toggleKey: isMac ? event.metaKey : event.ctrlKey,
    };
}

/**
 * Marco Extension — useStepGroupBatchActions
 *
 * Cross-panel helper that powers the toolbar batch actions:
 *
 *   • `buildDeletePreview` — given selected ids, walks the full
 *     groups list and returns one `BatchDeleteRow` per *root* of the
 *     selection (no duplicate listing of descendants the user would
 *     also lose). Each row carries cascading counts for the dialog.
 *
 *   • `applyBatchRename` — commits a list of rename changes, then
 *     returns a closure that re-applies the original names. Callers
 *     wire that closure to the toast's "Undo" action.
 *
 * Pure functions on top of the existing `useStepLibrary` API — no
 * extra DB schema needed. Keeping them outside the panels means they
 * can be unit-tested without React.
 *
 * @see ./BatchRenameDialog.tsx
 * @see ./BatchDeleteDialog.tsx
 */

import { useCallback } from "react";

import type { StepGroupRow } from "@/background/recorder/step-library/db";
import type { UseStepLibraryApi } from "@/hooks/use-step-library";
import type { BatchDeleteRow } from "@/components/options/BatchDeleteDialog";
import type { BatchRenameChange } from "@/components/options/BatchRenameDialog";

/* ------------------------------------------------------------------ */
/*  Delete preview                                                     */
/* ------------------------------------------------------------------ */

/**
 * Build the per-row delete preview shown in `BatchDeleteDialog`.
 *
 * Important: when the user selects a parent AND its child, only the
 * parent appears in the dialog — the child is implicitly deleted by
 * the cascade and listing it twice would inflate the totals. We do
 * include the child's nested+step counts in the parent's roll-up.
 */
export function buildDeletePreview(
    selectedIds: ReadonlyArray<number>,
    allGroups: ReadonlyArray<StepGroupRow>,
    stepsByGroup: ReadonlyMap<number, ReadonlyArray<unknown>>,
): BatchDeleteRow[] {
    const selected = new Set(selectedIds);
    const byParent = new Map<number | null, StepGroupRow[]>();
    const byId = new Map<number, StepGroupRow>();
    for (const g of allGroups) {
        byId.set(g.StepGroupId, g);
        const key = g.ParentStepGroupId ?? null;
        const items = byParent.get(key) ?? [];
        items.push(g);
        byParent.set(key, items);
    }

    // A "root of selection" = a selected group whose nearest selected
    // ancestor is itself. Deleting the ancestor cascades, so listing
    // descendants would double-count.
    const isRoot = (g: StepGroupRow): boolean => {
        let cursor: number | null = g.ParentStepGroupId ?? null;
        while (cursor !== null) {
            if (selected.has(cursor)) return false;
            const parent = byId.get(cursor);
            cursor = parent?.ParentStepGroupId ?? null;
        }
        return true;
    };

    const countSubtree = (rootId: number): { Descendants: number; Steps: number } => {
        let descendants = 0;
        let steps = stepsByGroup.get(rootId)?.length ?? 0;
        const stack: number[] = [rootId];
        while (stack.length > 0) {
            const id = stack.pop() as number;
            const kids = byParent.get(id) ?? [];
            for (const k of kids) {
                descendants += 1;
                steps += stepsByGroup.get(k.StepGroupId)?.length ?? 0;
                stack.push(k.StepGroupId);
            }
        }
        return { Descendants: descendants, Steps: steps };
    };

    const rows: BatchDeleteRow[] = [];
    for (const id of selectedIds) {
        const g = byId.get(id);
        if (g === undefined) continue;
        if (!isRoot(g)) continue;
        const { Descendants, Steps } = countSubtree(g.StepGroupId);
        rows.push({ Group: g, DescendantCount: Descendants, StepCount: Steps });
    }
    // Stable, predictable ordering (alphabetical) so the dialog
    // doesn't shuffle as the selection set changes.
    rows.sort((a, b) => a.Group.Name.localeCompare(b.Group.Name));
    return rows;
}

/* ------------------------------------------------------------------ */
/*  Rename application + undo                                          */
/* ------------------------------------------------------------------ */

export interface BatchRenameOutcome {
    /** Number of names actually changed (some may have failed mid-way). */
    readonly Applied: number;
    /** First error encountered, or `null` when the whole batch succeeded. */
    readonly Error: string | null;
    /**
     * Reverts every successfully-applied rename back to its original
     * name. Returns the same shape so the UI can confirm the undo
     * (or surface a partial-undo error). Safe to call exactly once.
     */
    readonly undo: () => BatchRenameOutcome;
}

export function useStepGroupBatchActions(lib: UseStepLibraryApi) {
    /**
     * Applies a batch of {Id, OldName, NewName} changes sequentially.
     * On success, the returned `undo()` reverts every Old→New back to
     * Old. We snapshot the *applied* list rather than the requested
     * one so a partial failure produces a partial undo that exactly
     * matches the on-disk state.
     */
    const applyBatchRename = useCallback(
        (changes: ReadonlyArray<BatchRenameChange>): BatchRenameOutcome => {
            const applied: BatchRenameChange[] = [];
            let firstError: string | null = null;
            for (const c of changes) {
                try {
                    lib.renameGroup(c.Id, c.NewName);
                    applied.push(c);
                } catch (err) {
                    firstError = err instanceof Error ? err.message : String(err);
                    break;
                }
            }
            const undo = (): BatchRenameOutcome => {
                const undone: BatchRenameChange[] = [];
                let undoError: string | null = null;
                for (const c of applied) {
                    try {
                        lib.renameGroup(c.Id, c.OldName);
                        undone.push({ Id: c.Id, OldName: c.NewName, NewName: c.OldName });
                    } catch (err) {
                        undoError = err instanceof Error ? err.message : String(err);
                        break;
                    }
                }
                return {
                    Applied: undone.length,
                    Error: undoError,
                    undo: () => ({ Applied: 0, Error: "Already undone", undo: () => undone[0] as never }),
                };
            };
            return { Applied: applied.length, Error: firstError, undo };
        },
        [lib],
    );

    return { applyBatchRename };
}

/**
 * Marco Extension — useStepGroupExport
 *
 * Reusable export pipeline shared by every panel that wants to ship a
 * "download selected groups as a ZIP" button.
 *
 * The hook owns:
 *
 *   1. Preview state — `previewStepGroupExport()` is run synchronously
 *      so we can surface counts + RunGroup-ref warnings before the user
 *      commits to the download.
 *   2. Confirm + download — packages the selected `StepGroupId`s via
 *      `runStepGroupExport()`, materialises the ZIP into a Blob, and
 *      pushes a synthetic <a download> click.
 *   3. Structured-error state — failures from either preview or the
 *      actual export are mapped via `explainExportFailure()` so the
 *      caller can render the shared `ExportErrorDialog`.
 *   4. Last-export summary — small object the caller can show in a
 *      "Last export" status line.
 *
 * The hook returns plain state + handlers (no JSX) so each panel keeps
 * full control over where the dialogs render. Both panels render the
 * same `ExportPreviewDialog` + `ExportErrorDialog` from this module's
 * exposed state, which guarantees identical UX.
 *
 * @see ./use-step-library — provides the SQL.js handle + project ctx.
 * @see @/background/recorder/step-library/export-bundle — packager.
 */

import { useCallback, useState } from "react";
import JSZip from "jszip";
import { toast } from "sonner";

import {
    previewStepGroupExport,
    runStepGroupExport,
    type StepGroupExportPreview,
} from "@/background/recorder/step-library/export-bundle";
import {
    explainExportFailure,
    type ExportErrorExplanation,
} from "@/background/recorder/step-library/export-error-explainer";
import type { LastExportSummary } from "@/components/options/BundleExchangePanel";
import type { useStepLibrary } from "@/hooks/use-step-library";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

/**
 * The pieces of `useStepLibrary()` we actually need. We accept just
 * this slim slice (instead of the full hook return) so unit tests can
 * pass a minimal stub without recreating the entire library state.
 */
export interface StepLibrarySliceForExport {
    readonly Lib: ReturnType<typeof useStepLibrary>["Lib"];
    readonly Project: ReturnType<typeof useStepLibrary>["Project"];
    readonly SqlJs: ReturnType<typeof useStepLibrary>["SqlJs"];
}

interface ExportPreviewState {
    readonly Open: boolean;
    readonly Preview: StepGroupExportPreview | null;
    readonly Pending: { readonly Ids: ReadonlyArray<number>; readonly IncludeDescendants: boolean } | null;
}

interface ExportErrorState {
    readonly Open: boolean;
    readonly Explanation: ExportErrorExplanation | null;
}

export interface UseStepGroupExportApi {
    /**
     * Validate the selection, run a dry-run preview, and open the
     * preview dialog. Surfaces any failure via the structured error
     * dialog instead of a toast-only path.
     */
    readonly requestExport: (
        ids: ReadonlyArray<number>,
        includeDescendants?: boolean,
    ) => void;

    /**
     * Commit the previewed export — packages the bundle and triggers
     * the browser download. Called by `ExportPreviewDialog`'s confirm.
     */
    readonly confirmExport: () => Promise<void>;

    /** Last successfully-exported bundle (or `null` before any). */
    readonly lastExport: LastExportSummary | null;

    /* --- Dialog-binding state (caller renders the actual dialogs) --- */

    readonly previewState: ExportPreviewState;
    readonly setPreviewOpen: (open: boolean) => void;
    readonly errorState: ExportErrorState;
    readonly setErrorOpen: (open: boolean) => void;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

const INITIAL_PREVIEW: ExportPreviewState = { Open: false, Preview: null, Pending: null };
const INITIAL_ERROR: ExportErrorState = { Open: false, Explanation: null };

export function useStepGroupExport(lib: StepLibrarySliceForExport): UseStepGroupExportApi {
    const [previewState, setPreviewState] = useState<ExportPreviewState>(INITIAL_PREVIEW);
    const [errorState, setErrorState] = useState<ExportErrorState>(INITIAL_ERROR);
    const [lastExport, setLastExport] = useState<LastExportSummary | null>(null);

    const showError = useCallback((explanation: ExportErrorExplanation) => {
        setErrorState({ Open: true, Explanation: explanation });
        toast.error(explanation.Title, { description: "See dialog for details" });
    }, []);

    const requestExport = useCallback(
        (ids: ReadonlyArray<number>, includeDescendants: boolean = true) => {
            if (lib.Lib === null || lib.Project === null || lib.SqlJs === null) {
                toast.error("Library not ready");
                return;
            }
            if (ids.length === 0) {
                toast.error("Select at least one group to export");
                return;
            }
            const preview = previewStepGroupExport({
                Source: lib.Lib,
                ProjectId: lib.Project.ProjectId,
                SelectedStepGroupIds: ids,
                IncludeDescendants: includeDescendants,
            });
            if (preview.Reason !== "Ok") {
                showError(explainExportFailure(preview));
                return;
            }
            setPreviewState({
                Open: true,
                Preview: preview,
                Pending: { Ids: ids, IncludeDescendants: includeDescendants },
            });
        },
        [lib.Lib, lib.Project, lib.SqlJs, showError],
    );

    const confirmExport = useCallback(async () => {
        const pending = previewState.Pending;
        setPreviewState(INITIAL_PREVIEW);
        if (pending === null) return;
        if (lib.Lib === null || lib.Project === null || lib.SqlJs === null) {
            toast.error("Library not ready");
            return;
        }
        const result = await runStepGroupExport({
            Source: lib.Lib,
            ProjectId: lib.Project.ProjectId,
            SelectedStepGroupIds: pending.Ids,
            IncludeDescendants: pending.IncludeDescendants,
            BundleName: `${lib.Project.Name} — ${pending.Ids.length} group(s)`,
            SqlJs: lib.SqlJs,
            JsZip: JSZip,
        });
        if (result.Reason !== "Ok") {
            showError(explainExportFailure(result));
            return;
        }
        // Materialise + push the download via a synthetic <a> click.
        const blob = new Blob([result.ZipBytes as BlobPart], { type: "application/zip" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = result.ZipFileName;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        setLastExport({
            FileName: result.ZipFileName,
            GroupCount: result.Manifest.Counts.StepGroups,
            StepCount: result.Manifest.Counts.Steps,
            At: new Date().toISOString(),
        });
        toast.success(
            `Exported ${result.Manifest.Counts.StepGroups} group(s)`,
            { description: `${result.Manifest.Counts.Steps} steps · ${result.ZipFileName}` },
        );
    }, [previewState.Pending, lib.Lib, lib.Project, lib.SqlJs, showError]);

    const setPreviewOpen = useCallback((open: boolean) => {
        setPreviewState((p) => (open ? { ...p, Open: true } : INITIAL_PREVIEW));
    }, []);

    const setErrorOpen = useCallback((open: boolean) => {
        setErrorState((p) => (open ? { ...p, Open: true } : INITIAL_ERROR));
    }, []);

    return {
        requestExport,
        confirmExport,
        lastExport,
        previewState,
        setPreviewOpen,
        errorState,
        setErrorOpen,
    };
}

/**
 * Marco Extension — useStepGroupImport
 *
 * Reusable import pipeline shared by every panel that lets the user
 * drop a `.zip` step-group bundle into the current project.
 *
 * Mirrors `useStepGroupExport` so both directions of the bundle
 * exchange feel identical from a caller's perspective:
 *
 *   - `importFile(file)` reads the ZIP, calls `runStepGroupImport()`,
 *     and routes the outcome to either `summaryState` (success) or
 *     `errorState` (structured failure via `explainImportFailure`).
 *   - `lastImport` is the small status-line summary the BundleExchange
 *     panel already consumes.
 *   - `summaryState` / `errorState` drive the two dialogs (the caller
 *     mounts `ImportSummaryDialog` + `ImportErrorDialog`).
 *
 * Conflict policy is fixed to `"Rename"` here — the only mode that
 * lets the import succeed when an incoming root name collides with an
 * existing one. The renamed pairs are surfaced verbatim in the summary
 * dialog so the user can locate the freshly-imported copy.
 *
 * After a successful import the hook calls `onAfterImport()` so the
 * caller can refresh the underlying library view (`useStepLibrary`).
 *
 * @see ./use-step-group-export — sibling hook for the outbound flow.
 * @see @/background/recorder/step-library/import-bundle — runner.
 */

import { useCallback, useState } from "react";
import JSZip from "jszip";
import { toast } from "sonner";

import {
    runStepGroupImport,
    type ImportSummary,
} from "@/background/recorder/step-library/import-bundle";
import {
    explainImportFailure,
    type ImportErrorExplanation,
} from "@/background/recorder/step-library/import-error-explainer";
import type { LastImportSummary } from "@/components/options/BundleExchangePanel";
import type { useStepLibrary } from "@/hooks/use-step-library";

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface StepLibrarySliceForImport {
    readonly Lib: ReturnType<typeof useStepLibrary>["Lib"];
    readonly Project: ReturnType<typeof useStepLibrary>["Project"];
    readonly SqlJs: ReturnType<typeof useStepLibrary>["SqlJs"];
}

interface ImportSummaryState {
    readonly Open: boolean;
    readonly Summary: ImportSummary | null;
    readonly FileName: string | null;
}

interface ImportErrorState {
    readonly Open: boolean;
    readonly Explanation: ImportErrorExplanation | null;
    readonly FileName: string | null;
}

export interface UseStepGroupImportApi {
    /** Read + import a user-uploaded ZIP, then open the relevant dialog. */
    readonly importFile: (file: File) => Promise<void>;

    readonly lastImport: LastImportSummary | null;

    readonly summaryState: ImportSummaryState;
    readonly setSummaryOpen: (open: boolean) => void;

    readonly errorState: ImportErrorState;
    readonly setErrorOpen: (open: boolean) => void;
}

interface UseStepGroupImportOptions {
    readonly lib: StepLibrarySliceForImport;
    /**
     * Invoked once after a successful import commits — callers wire
     * this to `useStepLibrary().refresh` so the tree / list views
     * pick up the new groups without a manual reload.
     */
    readonly onAfterImport?: () => void;
}

/* ------------------------------------------------------------------ */
/*  Hook                                                               */
/* ------------------------------------------------------------------ */

const INITIAL_SUMMARY: ImportSummaryState = { Open: false, Summary: null, FileName: null };
const INITIAL_ERROR: ImportErrorState = { Open: false, Explanation: null, FileName: null };

export function useStepGroupImport(opts: UseStepGroupImportOptions): UseStepGroupImportApi {
    const { lib, onAfterImport } = opts;
    const [summaryState, setSummaryState] = useState<ImportSummaryState>(INITIAL_SUMMARY);
    const [errorState, setErrorState] = useState<ImportErrorState>(INITIAL_ERROR);
    const [lastImport, setLastImport] = useState<LastImportSummary | null>(null);

    const importFile = useCallback(
        async (file: File) => {
            if (lib.Lib === null || lib.Project === null || lib.SqlJs === null) {
                toast.error("Library not ready");
                return;
            }
            let bytes: Uint8Array;
            try {
                const ab = await file.arrayBuffer();
                bytes = new Uint8Array(ab);
            } catch (err) {
                const detail = err instanceof Error ? err.message : "Could not read file bytes";
                toast.error("Failed to read ZIP", { description: detail });
                return;
            }
            const result = await runStepGroupImport({
                ZipBytes: bytes,
                Destination: lib.Lib,
                DestinationProjectId: lib.Project.ProjectId,
                OnNameConflict: "Rename",
                SqlJs: lib.SqlJs,
                JsZip: JSZip,
            });
            if (result.Reason !== "Ok") {
                const explanation = explainImportFailure(result);
                setErrorState({ Open: true, Explanation: explanation, FileName: file.name });
                toast.error(explanation.Title, { description: "See dialog for details" });
                return;
            }
            // Success — let the caller refresh first, then open the
            // summary dialog so the underlying list reflects the new
            // groups by the time the user clicks "Close".
            onAfterImport?.();
            const renames = result.RenamedRoots.length;
            setLastImport({
                GroupCount: result.Counts.StepGroups,
                StepCount: result.Counts.Steps,
                RenameCount: renames,
                At: new Date().toISOString(),
            });
            setSummaryState({ Open: true, Summary: result, FileName: file.name });
            toast.success(
                `Imported ${result.Counts.StepGroups} group(s)`,
                {
                    description:
                        `${result.Counts.Steps} steps` +
                        (renames > 0 ? ` · ${renames} renamed to avoid conflicts` : ""),
                },
            );
        },
        [lib.Lib, lib.Project, lib.SqlJs, onAfterImport],
    );

    const setSummaryOpen = useCallback((open: boolean) => {
        setSummaryState((p) => (open ? { ...p, Open: true } : INITIAL_SUMMARY));
    }, []);

    const setErrorOpen = useCallback((open: boolean) => {
        setErrorState((p) => (open ? { ...p, Open: true } : INITIAL_ERROR));
    }, []);

    return {
        importFile,
        lastImport,
        summaryState,
        setSummaryOpen,
        errorState,
        setErrorOpen,
    };
}

/**
 * Marco Extension — useStepLibrary
 *
 * React hook that owns an in-memory `StepLibraryDb` (sql.js) and
 * persists the raw DB bytes to `localStorage` on every mutation.
 *
 * This is the "preview-friendly" data layer that the new
 * `StepGroupLibraryPanel` uses. It deliberately does NOT touch OPFS,
 * chrome.storage, or the background message bus — those are wired
 * separately when the panel ships inside the extension. Keeping the
 * hook self-contained makes the panel runnable in the Lovable preview
 * and unit-testable without WASM mocking gymnastics.
 *
 * Storage key: `marco.step-library.v1` (versioned so a future schema
 * bump can invalidate cleanly).
 *
 * @see src/background/recorder/step-library/db.ts
 */

import { useCallback, useEffect, useMemo, useState } from "react";
import { logError } from "./hook-logger";
import { useCrossTabSync } from "./use-cross-tab-sync";
import { WorkspaceStorage } from "@/lib/workspace-storage";
import { StateReconciler } from "@/lib/state-reconciler";

import initSqlJs, { type Database, type SqlJsStatic } from "sql.js";

import {
    StepLibraryDb,
    type ProjectRow,
    type StepGroupRow,
    type StepRow,
} from "@/background/recorder/step-library/db";
import {
    clearGroupInput as clearGroupInputStorage,
    readAllGroupInputs,
    writeGroupInput,
    type GroupInputBag,
    type GroupInputsMap,
} from "@/background/recorder/step-library/group-inputs";
import { StepKindId } from "@/background/recorder/step-library/schema";

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const STORAGE_KEY = "marco.step-library.v1";
const WASM_CDN_URL = "https://sql.js.org/dist/sql-wasm.wasm";
const DEFAULT_PROJECT_NAME = "My Project";
const DEFAULT_PROJECT_EXTERNAL_ID = "00000000-0000-0000-0000-000000000001";

/* ------------------------------------------------------------------ */
/*  Structured load failure                                            */
/* ------------------------------------------------------------------ */

/**
 * Discriminated load-failure shape so the panel can render an
 * actionable error UI (icon + title + hint + recovery action) instead
 * of a single opaque string. Each kind maps to a distinct user-facing
 * recovery path:
 *
 *  - `SqlJsLoad` — sql.js WASM never resolved (CDN blocked, offline,
 *    CSP, slow network). User can retry once connectivity is back.
 *  - `StorageRead` — `localStorage` read or JSON parse failed
 *    (corrupt payload, quota inaccessible). User can reset to clear
 *    the bad blob and start fresh.
 *  - `StorageWrite` — initial seed write failed (quota, private
 *    mode). The library still works in-memory but won't persist;
 *    user should free space or exit private browsing.
 *  - `Unknown` — anything not classified above. Shown as-is with a
 *    generic retry.
 */
export type StepLibraryLoadError =
    | { Kind: "SqlJsLoad"; Message: string; Hint: string; Recoverable: true }
    | { Kind: "StorageRead"; Message: string; Hint: string; Recoverable: true }
    | { Kind: "StorageWrite"; Message: string; Hint: string; Recoverable: true }
    | { Kind: "Unknown"; Message: string; Hint: string; Recoverable: true };

function classifyLoadError(err: unknown, stage: "sqljs" | "storage-read" | "storage-write" | "other"): StepLibraryLoadError {
    const message = err instanceof Error ? err.message : String(err ?? "Unknown error");
    if (stage === "sqljs") {
        return {
            Kind: "SqlJsLoad",
            Message: message,
            Hint: "Could not download the SQL engine (sql.js WASM) from the CDN. Check your internet connection, then click Retry.",
            Recoverable: true,
        };
    }
    if (stage === "storage-read") {
        return {
            Kind: "StorageRead",
            Message: message,
            Hint: "Your saved step-library data appears to be corrupted or unreadable. Click Reset to clear it and start with an empty library.",
            Recoverable: true,
        };
    }
    if (stage === "storage-write") {
        return {
            Kind: "StorageWrite",
            Message: message,
            Hint: "Browser storage is full or unavailable (private/incognito mode often blocks writes). Free up space or use a normal window, then Retry.",
            Recoverable: true,
        };
    }
    return {
        Kind: "Unknown",
        Message: message,
        Hint: "Something went wrong while opening the step library. Try retrying — if the problem persists, reset to clear local state.",
        Recoverable: true,
    };
}

/* ------------------------------------------------------------------ */
/*  sql.js singleton (lazy, browser-only)                              */
/* ------------------------------------------------------------------ */

let sqlPromise: Promise<SqlJsStatic> | null = null;
function loadSql(): Promise<SqlJsStatic> {
    if (sqlPromise === null) {
        sqlPromise = initSqlJs({ locateFile: () => WASM_CDN_URL });
    }
    return sqlPromise;
}

/**
 * Read result is tri-state:
 *   - `{ Kind: "Empty" }`  — nothing stored yet, fresh start
 *   - `{ Kind: "Bytes" }`  — stored DB found and decoded
 *   - `{ Kind: "Error" }`  — storage was present but unreadable
 *                            (corrupt JSON, blocked access). Caller
 *                            propagates to the load-error UI rather
 *                            than silently wiping the user's data.
 */
type StorageReadResult =
    | { Kind: "Empty" }
    | { Kind: "Bytes"; Bytes: Uint8Array }
    | { Kind: "Error"; Error: unknown };

async function readBytesFromStorage(): Promise<StorageReadResult> {
    try {
        const bytes = await WorkspaceStorage.get<Uint8Array>(STORAGE_KEY);
        if (!bytes) return { Kind: "Empty" };
        return { Kind: "Bytes", Bytes: bytes };
    } catch (err) {
        return { Kind: "Error", Error: err };
    }
}

/**
 * Write result mirrors the read shape so the bootstrap path can
 * distinguish "saved fine" from "stayed in memory only".
 */
async function writeBytesToStorage(bytes: Uint8Array): Promise<{ Ok: true } | { Ok: false; Error: unknown }> {
    try {
        await WorkspaceStorage.set(STORAGE_KEY, bytes);
        return { Ok: true };
    } catch (err) {
        console.warn("useStepLibrary: WorkspaceStorage write failed", err);
        return { Ok: false, Error: err };
    }
}


/* ------------------------------------------------------------------ */
/*  Public hook surface                                                */
/* ------------------------------------------------------------------ */

export interface UseStepLibraryState {
    readonly Loading: boolean;
    /**
     * Legacy string error — kept for back-compat with any consumer
     * that just needs a message. New UI should read `LoadError` for
     * the structured kind + hint.
     */
    readonly Error: string | null;
    /** Structured load failure for the actionable error UI. */
    readonly LoadError: StepLibraryLoadError | null;
    readonly SqlJs: SqlJsStatic | null;
    readonly Lib: StepLibraryDb | null;
    readonly Project: ProjectRow | null;
    readonly Groups: ReadonlyArray<StepGroupRow>;
    readonly StepsByGroup: ReadonlyMap<number, ReadonlyArray<StepRow>>;
    /**
     * Per-StepGroup input variable bags. Empty Map until a user
     * applies one via the GroupInputsDialog. Persisted to a sibling
     * `localStorage` key — see `group-inputs.ts`.
     */
    readonly GroupInputs: GroupInputsMap;
}

export interface UseStepLibraryApi extends UseStepLibraryState {
    /** Force a re-read from the DB — call after a mutation outside CRUD helpers (e.g. import). */
    readonly refresh: () => void;
    readonly createGroup: (input: { Name: string; ParentStepGroupId: number | null; Description?: string | null }) => number;
    readonly renameGroup: (stepGroupId: number, newName: string) => void;
    readonly deleteGroup: (stepGroupId: number) => void;
    /**
     * Move a group up or down among its current siblings (same parent).
     * No-op when the move would push past either edge — the panel can
     * still call it on every arrow-button click without checking.
     */
    readonly moveGroupWithinParent: (stepGroupId: number, direction: "up" | "down") => void;
    /**
     * Reorder all sibling groups under a parent in one shot. Used by
     * the drag-and-drop handler — caller passes the COMPLETE new order.
     */
    readonly reorderSiblings: (parentStepGroupId: number | null, orderedIds: readonly number[]) => void;
    readonly setGroupArchived: (stepGroupId: number, archived: boolean) => void;
    /**
     * Flip the `IsDisabled` flag on a single step. Disabled steps are
     * dropped by the runner's expansion phase (`skipDisabled` defaults
     * to true), so this is the supported way to temporarily exclude
     * a step from a run while keeping its config intact.
     */
    readonly setStepDisabled: (stepId: number, disabled: boolean) => void;
    /**
     * Append a new step to the end of a StepGroup. Returns the new
     * StepId. Validation rules from the DB layer apply: RunGroup
     * steps require a TargetStepGroupId; every other kind forbids it.
     */
    readonly appendStep: (input: {
        StepGroupId: number;
        StepKindId: StepKindId;
        Label?: string | null;
        PayloadJson?: string | null;
        TargetStepGroupId?: number | null;
    }) => number;
    /** Edit a single step in place (preserves OrderIndex). */
    readonly updateStep: (input: {
        StepId: number;
        StepKindId: StepKindId;
        Label?: string | null;
        PayloadJson?: string | null;
        TargetStepGroupId?: number | null;
    }) => void;
    /** Delete a single step. */
    readonly deleteStep: (stepId: number) => void;
    /**
     * Move a step up or down among its sibling steps in the same
     * StepGroup. No-op when already at the edge — safe to call from
     * an always-rendered button.
     */
    readonly moveStepWithinGroup: (stepId: number, direction: "up" | "down") => void;
    /**
     * Reorder all sibling steps under a StepGroup in one shot. Caller
     * passes the COMPLETE new order (every existing StepId in the
     * group). Used by the drag-and-drop handler.
     */
    readonly reorderSteps: (stepGroupId: number, orderedStepIds: readonly number[]) => void;
    /**
     * Replace the input variable bag for one StepGroup. The bag must
     * be a plain JSON object — see `parseGroupInputJson` in
     * `group-inputs.ts`. Persisted immediately to localStorage.
     */
    readonly setGroupInput: (stepGroupId: number, bag: GroupInputBag) => void;
    /** Remove the input bag for one StepGroup. No-op when absent. */
    readonly clearGroupInput: (stepGroupId: number) => void;
    readonly resetAll: () => void;
    /**
     * Retry the bootstrap after a load failure. Resets the load
     * promise so a previously-failed sql.js fetch is attempted again
     * (the cached rejection would otherwise resolve instantly).
     */
    readonly retryLoad: () => void;
}

export function useStepLibrary(): UseStepLibraryApi {
    const [sql, setSql] = useState<SqlJsStatic | null>(null);
    const [lib, setLib] = useState<StepLibraryDb | null>(null);
    const [project, setProject] = useState<ProjectRow | null>(null);
    const [groups, setGroups] = useState<ReadonlyArray<StepGroupRow>>([]);
    const [stepsByGroup, setStepsByGroup] = useState<ReadonlyMap<number, ReadonlyArray<StepRow>>>(new Map());
    const [error, setError] = useState<string | null>(null);
    const [loadError, setLoadError] = useState<StepLibraryLoadError | null>(null);
    const [groupInputs, setGroupInputs] = useState<GroupInputsMap>(() => new Map());
    const [loading, setLoading] = useState(true);
    const [dbBytes, setDbBytes] = useState<Uint8Array | null>(null);
    /** Bumping this triggers the bootstrap effect to re-run. */
    const [bootstrapNonce, setBootstrapNonce] = useState(0);

    // Sync library state across tabs
    const onRemoteBytes = useCallback((remoteBytes: Uint8Array | null) => {
        if (!remoteBytes || !lib || !project) return;
        // Re-open DB with remote bytes
        const sqljs = sql;
        if (!sqljs) return;

        try {
            const db = new sqljs.Database(remoteBytes);
            const wrapper = new StepLibraryDb(db);
            setLib(wrapper);
            refreshFromDb(wrapper, project.ProjectId, setGroups, setStepsByGroup);
            setDbBytes(remoteBytes);
            // Also notify UI that we synced
            new BroadcastChannel("marco-sync-activity").postMessage("synced");
        } catch (err) {
            logError("use-step-library::onRemoteBytes", "Failed to sync remote library state", err);
        }
    }, [lib, project, sql]);

    useCrossTabSync<Uint8Array | null>("marco-step-library-sync", dbBytes, onRemoteBytes);


    /* ------------------------ bootstrap --------------------------- */

    useEffect(() => {
        let cancelled = false;
        setLoading(true);
        setError(null);
        setLoadError(null);
        (async () => {
            // ---- 1. Load sql.js (network / WASM) -----------------
            let sqljs: SqlJsStatic;
            try {
                sqljs = await loadSql();
            } catch (err) {
                if (cancelled) return;
                // Reset the cached promise so the next retry actually
                // re-fetches instead of resolving the stale rejection.
                sqlPromise = null;
                const classified = classifyLoadError(err, "sqljs");
                setLoadError(classified);
                setError(classified.Message);
                setLoading(false);
                return;
            }
            if (cancelled) return;

            // ---- 2. Read persisted DB bytes (WorkspaceStorage) -------
            const readResult = await readBytesFromStorage();
            if (readResult.Kind === "Error") {
                const classified = classifyLoadError(readResult.Error, "storage-read");
                setLoadError(classified);
                setError(classified.Message);
                setLoading(false);
                return;
            }

            // ---- 3. Open the database & seed if empty ------------
            try {
                const db: Database = readResult.Kind === "Empty"
                    ? new sqljs.Database()
                    : new sqljs.Database(readResult.Bytes);
                const wrapper = new StepLibraryDb(db);
                let projectId: number;
                const existing = wrapper.listProjects();
                if (existing.length === 0) {
                    projectId = wrapper.upsertProject({
                        ExternalId: DEFAULT_PROJECT_EXTERNAL_ID,
                        Name: DEFAULT_PROJECT_NAME,
                    });
                    seedExampleData(wrapper, projectId);
                    const writeResult = await writeBytesToStorage(wrapper.exportDbBytes());
                    if (!writeResult.Ok) {
                        // Hard-fail on the FIRST write only — the user
                        // hasn't done any work yet, so surfacing this
                        // up front is friendlier than silently losing
                        // data later. Subsequent mutation writes only
                        // warn (see `persist`).
                        const classified = classifyLoadError(writeResult.Error, "storage-write");
                        setLoadError(classified);
                        setError(classified.Message);
                        setLoading(false);
                        return;
                    }
                } else {

                    projectId = existing[0].ProjectId;
                }
                if (cancelled) return;
                const bytes = wrapper.exportDbBytes();
                setDbBytes(bytes);
                setSql(sqljs);


                setLib(wrapper);

                setProject(wrapper.listProjects().find((p) => p.ProjectId === projectId) ?? null);
                refreshFromDb(wrapper, projectId, setGroups, setStepsByGroup);
                setGroupInputs(readAllGroupInputs());
                setLoading(false);
            } catch (err) {
                if (cancelled) return;
                const classified = classifyLoadError(err, "other");
                setLoadError(classified);
                setError(classified.Message);
                setLoading(false);
            }
        })();
        return () => { cancelled = true; };
    }, [bootstrapNonce]);

    const persist = useCallback(() => {
        if (lib === null) return;
        const bytes = lib.exportDbBytes();
        setDbBytes(bytes);
        void writeBytesToStorage(bytes);


    }, [lib]);


    const refresh = useCallback(() => {
        if (lib === null || project === null) return;
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
    }, [lib, project]);

    const createGroup = useCallback<UseStepLibraryApi["createGroup"]>((input) => {
        if (lib === null || project === null) {
            throw new Error("createGroup: library not initialised");
        }
        const id = lib.createGroup({
            ProjectId: project.ProjectId,
            ParentStepGroupId: input.ParentStepGroupId,
            Name: input.Name,
            Description: input.Description ?? null,
        });
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
        return id;
    }, [lib, project, persist]);

    const renameGroup = useCallback<UseStepLibraryApi["renameGroup"]>((id, name) => {
        if (lib === null || project === null) return;
        lib.renameGroup(id, name);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const deleteGroup = useCallback<UseStepLibraryApi["deleteGroup"]>((id) => {
        if (lib === null || project === null) return;
        lib.deleteGroup(id);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const moveGroupWithinParent = useCallback<UseStepLibraryApi["moveGroupWithinParent"]>((id, direction) => {
        if (lib === null || project === null) return;
        const all = lib.listGroups(project.ProjectId);
        const target = all.find((g) => g.StepGroupId === id);
        if (target === undefined) return;
        const parent = target.ParentStepGroupId ?? null;
        const siblings = all
            .filter((g) => (g.ParentStepGroupId ?? null) === parent)
            .sort((a, b) => a.OrderIndex - b.OrderIndex || a.Name.localeCompare(b.Name))
            .map((g) => g.StepGroupId);
        const idx = siblings.indexOf(id);
        if (idx === -1) return;
        const swapWith = direction === "up" ? idx - 1 : idx + 1;
        if (swapWith < 0 || swapWith >= siblings.length) return; // already at edge
        const next = siblings.slice();
        [next[idx], next[swapWith]] = [next[swapWith], next[idx]];
        lib.reorderGroups(project.ProjectId, parent, next);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const reorderSiblings = useCallback<UseStepLibraryApi["reorderSiblings"]>((parent, orderedIds) => {
        if (lib === null || project === null) return;
        lib.reorderGroups(project.ProjectId, parent, orderedIds);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const setGroupArchived = useCallback<UseStepLibraryApi["setGroupArchived"]>((id, archived) => {
        if (lib === null || project === null) return;
        lib.setGroupArchived(id, archived);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const setStepDisabled = useCallback<UseStepLibraryApi["setStepDisabled"]>((stepId, disabled) => {
        if (lib === null || project === null) return;
        lib.setStepDisabled(stepId, disabled);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const setGroupInput = useCallback<UseStepLibraryApi["setGroupInput"]>((id, bag) => {
        writeGroupInput(id, bag);
        // Snapshot the bag with a defensive copy so a consumer who
        // mutates the value after the call cannot rewrite our state.
        setGroupInputs((prev) => {
            const next = new Map(prev);
            next.set(id, bag);
            return next;
        });
    }, []);

    const clearGroupInput = useCallback<UseStepLibraryApi["clearGroupInput"]>((id) => {
        clearGroupInputStorage(id);
        setGroupInputs((prev) => {
            if (!prev.has(id)) return prev;
            const next = new Map(prev);
            next.delete(id);
            return next;
        });
    }, []);

    const appendStep = useCallback<UseStepLibraryApi["appendStep"]>((input) => {
        if (lib === null || project === null) {
            throw new Error("appendStep: library not initialised");
        }
        const id = lib.appendStep(input);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
        return id;
    }, [lib, project, persist]);

    const updateStep = useCallback<UseStepLibraryApi["updateStep"]>((input) => {
        if (lib === null || project === null) return;
        lib.updateStep(input);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const deleteStep = useCallback<UseStepLibraryApi["deleteStep"]>((stepId) => {
        if (lib === null || project === null) return;
        lib.deleteStep(stepId);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const moveStepWithinGroup = useCallback<UseStepLibraryApi["moveStepWithinGroup"]>((stepId, direction) => {
        if (lib === null || project === null) return;
        // Locate the step's group from the current snapshot — avoids
        // a redundant DB scan and keeps the move atomic with what the
        // user sees on screen.
        let owningGroupId: number | null = null;
        for (const [gid, steps] of stepsByGroup) {
            if (steps.some((s) => s.StepId === stepId)) {
                owningGroupId = gid;
                break;
            }
        }
        if (owningGroupId === null) return;
        const ordered = (stepsByGroup.get(owningGroupId) ?? []).map((s) => s.StepId);
        const idx = ordered.indexOf(stepId);
        if (idx === -1) return;
        const swapWith = direction === "up" ? idx - 1 : idx + 1;
        if (swapWith < 0 || swapWith >= ordered.length) return; // already at edge
        const next = ordered.slice();
        [next[idx], next[swapWith]] = [next[swapWith], next[idx]];
        lib.reorderSteps(owningGroupId, next);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, stepsByGroup, persist]);

    const reorderSteps = useCallback<UseStepLibraryApi["reorderSteps"]>((stepGroupId, orderedStepIds) => {
        if (lib === null || project === null) return;
        lib.reorderSteps(stepGroupId, orderedStepIds);
        refreshFromDb(lib, project.ProjectId, setGroups, setStepsByGroup);
        persist();
    }, [lib, project, persist]);

    const resetAll = useCallback(() => {
        try {
            localStorage.removeItem(STORAGE_KEY);
        } catch (caught) {
            logError("useStepLibrary.resetAll", `localStorage.removeItem("${STORAGE_KEY}") failed — bootstrap nonce will still trigger reload`, caught);
        }
        // Force a hard reload of the in-memory DB by re-running bootstrap.
        // Easiest path: reload the page fragment owning the hook.
        window.location.reload();
    }, []);

    /**
     * Re-run the bootstrap effect without a full page reload. Used by
     * the load-error UI's Retry button. Resets the cached sql.js
     * promise so the next attempt actually re-fetches the WASM.
     */
    const retryLoad = useCallback(() => {
        sqlPromise = null;
        setBootstrapNonce((n) => n + 1);
    }, []);

    return useMemo<UseStepLibraryApi>(() => ({
        Loading: loading,
        Error: error,
        LoadError: loadError,
        SqlJs: sql,
        Lib: lib,
        Project: project,
        Groups: groups,
        StepsByGroup: stepsByGroup,
        GroupInputs: groupInputs,
        refresh,
        createGroup,
        renameGroup,
        deleteGroup,
        moveGroupWithinParent,
        reorderSiblings,
        setGroupArchived,
        setStepDisabled,
        appendStep,
        updateStep,
        deleteStep,
        moveStepWithinGroup,
        reorderSteps,
        setGroupInput,
        clearGroupInput,
        resetAll,
        retryLoad,
    }), [loading, error, loadError, sql, lib, project, groups, stepsByGroup, groupInputs, refresh, createGroup, renameGroup, deleteGroup, moveGroupWithinParent, reorderSiblings, setGroupArchived, setStepDisabled, appendStep, updateStep, deleteStep, moveStepWithinGroup, reorderSteps, setGroupInput, clearGroupInput, resetAll, retryLoad]);
}

