/**
 * useVisibilityPausedInterval
 *
 * `setInterval` that pauses while `document.hidden === true` and resumes
 * (with an immediate catch-up tick) when the page becomes visible again.
 *
 * Background — Idle/Background Loop Audit, 2026-04-25 (PERF-10..12):
 *   Naked `setInterval`s in React hooks keep firing while a tab is in a
 *   background window. For MV3 extensions this also wakes the service
 *   worker on every tick (each `sendMessage` revives the SW), defeating
 *   Chrome's idle-suspension heuristic. The pattern was first proven on
 *   `useErrorCount`; this hook generalises it so the rest of the codebase
 *   can adopt it with one line.
 *
 * Contract:
 *   - `tickFn` is invoked once on mount if the page is currently visible.
 *   - While visible: invoked every `intervalMs` until unmount.
 *   - On `visibilitychange → hidden`: timer cleared.
 *   - On `visibilitychange → visible`: `tickFn()` runs once immediately,
 *     then the timer is re-armed.
 *   - Setting `enabled = false` tears the timer down without unmounting.
 *
 * The hook deliberately tolerates SSR (`typeof document === "undefined"`)
 * and an extension-context-invalidated environment (no document at all).
 *
 * @see spec/22-app-issues/109-react-hooks-visibility-pause.md
 */

import { useEffect, useRef } from "react";

export function useVisibilityPausedInterval(
    tickFn: () => void,
    intervalMs: number,
    enabled = true,
): void {
    const tickRef = useRef(tickFn);
    tickRef.current = tickFn;

    useEffect(() => {
        if (!enabled) { return; }
        if (typeof document === "undefined") {
            const id = setInterval(() => tickRef.current(), intervalMs);
            return () => clearInterval(id);
        }

        let timerId: ReturnType<typeof setInterval> | null = null;

        const start = (): void => {
            if (timerId !== null) { return; }
            timerId = setInterval(() => tickRef.current(), intervalMs);
        };

        const stop = (): void => {
            if (timerId !== null) {
                clearInterval(timerId);
                timerId = null;
            }
        };

        const handleVisibility = (): void => {
            if (document.hidden) {
                stop();
            } else {
                tickRef.current();
                start();
            }
        };

        document.addEventListener("visibilitychange", handleVisibility);

        if (!document.hidden) {
            tickRef.current();
            start();
        }

        return () => {
            document.removeEventListener("visibilitychange", handleVisibility);
            stop();
        };
    }, [intervalMs, enabled]);
}

/**
 * Marco Extension — Keyword Event Bulk Actions
 *
 * Pure helpers backing the right-click context menu on the keyword events
 * list. Kept framework-free so they're trivially testable and reusable from
 * other surfaces (Steps, Sessions, Scripts/Projects) when those wire in.
 *
 *   • formatSequenceNumber  — zero-padded "01"/"001" rendering.
 *   • renderSequenceName    — "Login {n}" / "Login - 02" templating.
 *   • mergeTags             — flat-tag set add (de-duped, trimmed, sorted).
 *   • removeTags            — flat-tag set subtract.
 *   • buildExportPayload    — JSON snapshot of the selected events for ZIP.
 *
 * The full SQLite-in-ZIP exporter is a separate roadmap item; this module
 * intentionally produces JSON so the context menu can ship today.
 */

import type { KeywordEvent } from "@/hooks/use-keyword-events";

export interface SequenceRenameInput {
    readonly Base: string;
    readonly Start: number;
    readonly Padding: number;   // clamped to [1, 6]
    readonly Separator: string; // used only when {n} is absent
}

export const DEFAULT_SEQUENCE_RENAME: SequenceRenameInput = {
    Base: "Event {n}",
    Start: 1,
    Padding: 2,
    Separator: " ",
};

export function formatSequenceNumber(n: number, padding: number): string {
    const pad = Math.max(1, Math.min(6, Math.floor(padding)));
    const safe = Math.max(0, Math.floor(n));
    return safe.toString().padStart(pad, "0");
}

export function renderSequenceName(input: SequenceRenameInput, index: number): string {
    const count = formatSequenceNumber(input.Start + index, input.Padding);
    if (input.Base.includes("{n}")) {
        return input.Base.split("{n}").join(count);
    }
    const base = input.Base.trim();
    return base.length === 0 ? count : `${base}${input.Separator}${count}`;
}

/* ------------------------------------------------------------------ */
/*  Sequence rename validation                                         */
/* ------------------------------------------------------------------ */

export type SequencePreviewIssue =
    | "empty"           // resolved name is empty / whitespace
    | "too-long"        // > 200 chars; matches Keyword column soft limit
    | "duplicate"       // collides with another row inside this rename batch
    | "collision";      // collides with an existing event NOT in the selection

export interface SequencePreviewRow {
    readonly Id: string;
    readonly Old: string;
    readonly Next: string;
    readonly Issues: readonly SequencePreviewIssue[];
    /** Original-cased keywords from `outsideKeywords` whose normalised form
     *  matches `Next`. Empty when there is no `collision` issue. Surfaced by
     *  the rename dialog's "details" expander so the user can see which
     *  existing event each proposed name would clash with. */
    readonly CollidesWith: readonly string[];
}

export interface SequencePreviewSummary {
    readonly Rows: readonly SequencePreviewRow[];
    readonly DuplicateCount: number;
    readonly CollisionCount: number;
    readonly EmptyCount: number;
    readonly TooLongCount: number;
    /** True iff every row is issue-free. */
    readonly IsValid: boolean;
}

const SEQUENCE_NAME_MAX_LENGTH = 200;

/**
 * Computes the new name for every selected event AND flags duplicates,
 * collisions with non-selected events, and invalid (empty/over-long) names.
 *
 *   • `outsideKeywords` are the keywords of events NOT in `selectedEvents`
 *     (i.e. the rest of the list). Pass `[]` if collision detection is
 *     not desired. Comparison is case-insensitive + trimmed to mirror how
 *     users perceive duplicates.
 */
export function computeSequencePreview(
    selectedEvents: ReadonlyArray<{ readonly Id: string; readonly Keyword: string }>,
    input: SequenceRenameInput,
    outsideKeywords: ReadonlyArray<string>,
): SequencePreviewSummary {
    const norm = (s: string): string => s.trim().toLowerCase();
    // Build a map: normalised key → list of original-cased outside keywords
    // sharing that key. Lets the UI surface "Login 01 collides with Login 01,
    // login 01" when casing differs in the existing list.
    const outsideByKey = new Map<string, string[]>();
    for (const raw of outsideKeywords) {
        const key = norm(raw);
        if (key.length === 0) continue;
        const bucket = outsideByKey.get(key);
        if (bucket) bucket.push(raw);
        else outsideByKey.set(key, [raw]);
    }

    const proposed = selectedEvents.map((ev, i) => ({
        Id: ev.Id,
        Old: ev.Keyword,
        Next: renderSequenceName(input, i),
    }));

    // Count occurrences of each normalised proposed name to find within-batch
    // duplicates. >1 occurrence ⇒ every occurrence is a duplicate.
    const counts = new Map<string, number>();
    for (const p of proposed) {
        const key = norm(p.Next);
        if (key.length === 0) continue;
        counts.set(key, (counts.get(key) ?? 0) + 1);
    }

    let duplicateCount = 0;
    let collisionCount = 0;
    let emptyCount = 0;
    let tooLongCount = 0;

    const rows: SequencePreviewRow[] = proposed.map(p => {
        const issues: SequencePreviewIssue[] = [];
        const key = norm(p.Next);
        if (key.length === 0) {
            issues.push("empty");
            emptyCount += 1;
        }
        if (p.Next.length > SEQUENCE_NAME_MAX_LENGTH) {
            issues.push("too-long");
            tooLongCount += 1;
        }
        if (key.length > 0 && (counts.get(key) ?? 0) > 1) {
            issues.push("duplicate");
            duplicateCount += 1;
        }
        const collidesWith = key.length > 0 ? (outsideByKey.get(key) ?? []) : [];
        if (collidesWith.length > 0) {
            issues.push("collision");
            collisionCount += 1;
        }
        return {
            Id: p.Id,
            Old: p.Old,
            Next: p.Next,
            Issues: issues,
            CollidesWith: collidesWith,
        };
    });

    return {
        Rows: rows,
        DuplicateCount: duplicateCount,
        CollisionCount: collisionCount,
        EmptyCount: emptyCount,
        TooLongCount: tooLongCount,
        IsValid: duplicateCount === 0 && collisionCount === 0 && emptyCount === 0 && tooLongCount === 0,
    };
}

/** Returns a fresh, sorted, de-duplicated tag list (case-insensitive). */
export function mergeTags(
    current: readonly string[] | undefined,
    toAdd: readonly string[],
): string[] {
    const seen = new Map<string, string>();
    const consume = (raw: string): void => {
        const trimmed = raw.trim();
        if (trimmed.length === 0) return;
        const key = trimmed.toLowerCase();
        if (!seen.has(key)) seen.set(key, trimmed);
    };
    (current ?? []).forEach(consume);
    toAdd.forEach(consume);
    return Array.from(seen.values()).sort((a, b) => a.localeCompare(b));
}

export function removeTags(
    current: readonly string[] | undefined,
    toRemove: readonly string[],
): string[] {
    const drop = new Set(toRemove.map(t => t.trim().toLowerCase()).filter(Boolean));
    return (current ?? [])
        .filter(t => !drop.has(t.trim().toLowerCase()))
        .slice()
        .sort((a, b) => a.localeCompare(b));
}

/**
 * Parses comma/space/newline separated tag input into a clean list.
 * "  foo, bar  baz\nqux " → ["foo", "bar", "baz", "qux"]
 */
export function parseTagInput(raw: string): string[] {
    return raw
        .split(/[\s,]+/)
        .map(t => t.trim())
        .filter(t => t.length > 0);
}

/**
 * Normalises a category string for storage. Trims whitespace and collapses
 * inner runs; empty input returns `undefined` so the field round-trips as
 * "uncategorised" through the persistence layer (matching the
 * `Category?: string` shape on `KeywordEvent`).
 */
export function normaliseCategory(raw: string | undefined): string | undefined {
    if (raw === undefined) return undefined;
    const trimmed = raw.replace(/\s+/g, " ").trim();
    return trimmed.length === 0 ? undefined : trimmed;
}

/** Returns the unique, non-empty categories currently in use across the
 *  given events — sorted case-insensitively for stable suggestion lists. */
export function collectCategories(
    events: ReadonlyArray<{ readonly Category?: string }>,
): string[] {
    const seen = new Map<string, string>();
    for (const ev of events) {
        const c = normaliseCategory(ev.Category);
        if (c === undefined) continue;
        const key = c.toLowerCase();
        if (!seen.has(key)) seen.set(key, c);
    }
    return Array.from(seen.values()).sort((a, b) => a.localeCompare(b));
}

export interface ExportPayload {
    readonly Format: "marco.keyword-events.v1";
    readonly ExportedAt: string;
    readonly Events: readonly KeywordEvent[];
}

export function buildExportPayload(events: readonly KeywordEvent[]): ExportPayload {
    return {
        Format: "marco.keyword-events.v1",
        ExportedAt: new Date().toISOString(),
        Events: events,
    };
}

/** Slug for the .zip filename — "marco-keyword-events-2026-04-27T...". */
export function buildExportFilename(now: Date = new Date()): string {
    const stamp = now.toISOString().replace(/[:.]/g, "-");
    return `marco-keyword-events-${stamp}.zip`;
}

/**
 * prompt-history-import-roundtrip.spec.ts
 *
 * Browser regression for the Prompt History import round-trip (v4.184.0+).
 *
 * Covers:
 *   1. Initial panel open renders exactly the native revision rows with zero
 *      `imported` provenance badges.
 *   2. After a valid JSON import completes, reopening the panel shows the
 *      combined row count (native + imported) and one `imported` badge for
 *      each row whose `PromptId` is the `0` sentinel written by
 *      `insertImportedRevisions`.
 *   3. The import success toast reports the exact number of rows written.
 *
 * The DB layer is faked at the `chrome.runtime.sendMessage` boundary: SELECT
 * MAX(Id) returns a stable snapshot, INSERT / DELETE calls always succeed,
 * and `listPromptRevisions` is stubbed through `HistoryPanelDeps` so the
 * before/after state is fully controlled in-test.
 */

import { test, expect, chromium, type Browser, type Page } from '@playwright/test';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';
import { bundleBrowserIife } from './utils/esbuild-loader';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const REPO_ROOT = path.resolve(__dirname, '../..');
const HISTORY_PANEL_ENTRY = path.join(
    REPO_ROOT,
    'standalone-scripts/macro-controller/src/ui/prompt-history-panel.ts',
);

const SLUG = 'plan-default';
const ROLE = 'plan';

let bundleSource = '';
let browser: Browser | undefined;

function resolveChromiumExecutable(): string | undefined {
    const candidates = ['/usr/bin/chromium', '/bin/chromium', '/usr/bin/chromium-browser', '/usr/bin/google-chrome'];
    for (const candidate of candidates) if (fs.existsSync(candidate)) return candidate;
    return undefined;
}

test.beforeAll(async () => {
    bundleSource = await bundleBrowserIife(REPO_ROOT, {
        entryPoint: HISTORY_PANEL_ENTRY,
        globalName: 'PromptHistoryPanelBundle',
        footerJs: 'window.__promptHistoryPanel = PromptHistoryPanelBundle;',
    });
    browser = await chromium.launch({
        headless: true,
        executablePath: resolveChromiumExecutable(),
    });
});

test.afterAll(async () => {
    if (browser) await browser.close();
});

async function newHarnessPage(): Promise<Page> {
    if (!browser) throw new Error('browser not initialized');
    const context = await browser.newContext();
    const page = await context.newPage();

    await page.addInitScript(() => {
        interface RuntimeMessage {
            type?: string;
            method?: string;
            params?: { sql?: string };
        }
        interface RuntimeResponse {
            isOk: boolean;
            rows?: Array<Record<string, unknown>>;
            lastInsertId?: number;
        }
        const calls: Array<{ type: string; method?: string; sql?: string }> = [];
        (globalThis as typeof globalThis & { __calls: typeof calls }).__calls = calls;
        (globalThis as typeof globalThis & { chrome: unknown }).chrome = {
            runtime: {
                lastError: null,
                sendMessage: (message: RuntimeMessage, callback: (response: RuntimeResponse) => void) => {
                    const sql = message.params?.sql ?? '';
                    calls.push({ type: String(message.type ?? ''), method: message.method, sql });
                    let rows: Array<Record<string, unknown>> = [];
                    if (/SELECT\s+MAX\(Id\)/i.test(sql)) rows = [{ MaxId: 100 }];
                    setTimeout(() => callback({ isOk: true, rows, lastInsertId: 101 }), 0);
                },
            },
        };
    });

    await page.route('**/*', (route) => {
        route.fulfill({ status: 200, contentType: 'text/html', body: '<!doctype html><html><body></body></html>' });
    });
    await page.goto('https://prompt-history-import-harness.test/');
    await page.addScriptTag({ content: bundleSource });
    return page;
}

test.describe('prompt history import round-trip', () => {
    test('imported rows show the provenance badge and grow the row count', async () => {
        const page = await newHarnessPage();

        // ---- Stage 1: initial open with 2 native revisions ----
        await page.evaluate(async ({ slug, role }) => {
            interface RevRow {
                Id: number; PromptId: number; Slug: string; Name: string; Body: string;
                Role: string; ReplaceKey: string; ReplaceValues: string; CreatedAt: number; Reason: string;
            }
            const nativeRows: RevRow[] = [
                { Id: 91, PromptId: 7, Slug: slug, Name: 'Plan default', Body: 'v1 body', Role: role, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_000_000, Reason: 'upsert' },
                { Id: 92, PromptId: 7, Slug: slug, Name: 'Plan default', Body: 'v2 body', Role: role, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_100_000, Reason: 'upsert' },
            ];
            const importedRows: RevRow[] = [
                { Id: 101, PromptId: 0, Slug: slug, Name: 'Plan default', Body: 'imported A', Role: role, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_200_000, Reason: 'import' },
                { Id: 102, PromptId: 0, Slug: slug, Name: 'Plan default', Body: 'imported B', Role: role, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_300_000, Reason: 'import' },
                { Id: 103, PromptId: 0, Slug: slug, Name: 'Plan default', Body: 'imported C', Role: role, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_400_000, Reason: 'import' },
            ];
            const state = { openCount: 0, toasts: [] as Array<{ msg: string; kind?: string }> };
            (window as unknown as { __state: typeof state }).__state = state;

            interface DbOk<T> { ok: boolean; value?: T; error?: string }
            const listRevisions = async (): Promise<DbOk<RevRow[]>> => {
                state.openCount += 1;
                if (state.openCount === 1) return { ok: true, value: nativeRows.slice() };
                return { ok: true, value: [...nativeRows, ...importedRows] };
            };
            const toast = (msg: string, kind?: string) => { state.toasts.push({ msg, kind }); };
            (window as unknown as { __deps: unknown }).__deps = { listRevisions, toast, undoToast: toast };

            interface HistoryApi {
                openPromptHistoryPanel: (
                    input: { role: string; slug: string },
                    deps: unknown,
                ) => Promise<void>;
            }
            const api = (window as unknown as { __promptHistoryPanel: HistoryApi }).__promptHistoryPanel;
            await api.openPromptHistoryPanel({ role, slug }, (window as unknown as { __deps: unknown }).__deps);
        }, { slug: SLUG, role: ROLE });

        // Assert: 2 rows, 0 imported badges.
        await expect(page.locator('#marco-prompt-history-panel [data-role="revision-row"]')).toHaveCount(2);
        await expect(page.locator('#marco-prompt-history-panel [data-role="imported-badge"]')).toHaveCount(0);

        // ---- Stage 2: trigger import via the hidden file input ----
        const payload = JSON.stringify({
            schemaVersion: 1,
            slug: SLUG,
            role: ROLE,
            exportedAt: 1_700_000_500_000,
            revisionCount: 3,
            revisions: [
                { Slug: SLUG, Name: 'Plan default', Body: 'imported A', Role: ROLE, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_200_000, Reason: 'import' },
                { Slug: SLUG, Name: 'Plan default', Body: 'imported B', Role: ROLE, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_300_000, Reason: 'import' },
                { Slug: SLUG, Name: 'Plan default', Body: 'imported C', Role: ROLE, ReplaceKey: 'n', ReplaceValues: '["1","2","3"]', CreatedAt: 1_700_000_400_000, Reason: 'import' },
            ],
        });

        await page.locator('input[data-testid="history-import-input"]').setInputFiles({
            name: 'history-plan-default.json',
            mimeType: 'application/json',
            buffer: Buffer.from(payload, 'utf8'),
        });

        // Wait for the DB write path to record the INSERTs.
        await expect.poll(async () =>
            page.evaluate(() => (globalThis as unknown as {
                __calls: Array<{ sql?: string }>;
            }).__calls.filter((c) => /INSERT\s+INTO\s+PromptRevision/i.test(c.sql ?? '')).length),
        ).toBe(3);

        // Success toast reports the exact count written.
        const importToasts = await page.evaluate(() =>
            (window as unknown as { __state: { toasts: Array<{ msg: string }> } })
                .__state.toasts.map((t) => t.msg));
        expect(importToasts.some((m) => m.includes('Imported 3 revision(s)'))).toBe(true);

        // ---- Stage 3: reopen and assert combined count + badges ----
        await page.evaluate(async ({ slug, role }) => {
            interface HistoryApi {
                openPromptHistoryPanel: (input: { role: string; slug: string }, deps: unknown) => Promise<void>;
            }
            const api = (window as unknown as { __promptHistoryPanel: HistoryApi }).__promptHistoryPanel;
            await api.openPromptHistoryPanel({ role, slug }, (window as unknown as { __deps: unknown }).__deps);
        }, { slug: SLUG, role: ROLE });

        const panel = page.locator('#marco-prompt-history-panel');
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(5);
        await expect(panel.locator('[data-role="imported-badge"]')).toHaveCount(3);

        // Every badge must sit inside a row whose data-revision-id matches a
        // sentinel (PromptId=0) source row. The stub returns Ids 101..103 for
        // those, so assert the badge parent rows are exactly that set.
        const badgeRowIds = await panel
            .locator('[data-role="revision-row"]:has([data-role="imported-badge"])')
            .evaluateAll((els) => els.map((el) => el.getAttribute('data-revision-id')));
        expect(badgeRowIds.sort()).toEqual(['101', '102', '103']);

        await page.context().close();
    });
});

/**
 * prompt-history-sort-filter.spec.ts
 *
 * Playwright E2E regression for the Prompt History panel toolbar
 * (v4.192.0+): sortable Date/Reason columns, reason filter chips, and
 * the tri-state imported chip. Asserts the visible row count and order
 * update after each toolbar interaction.
 *
 * DB access is faked at `chrome.runtime.sendMessage`; the revision list
 * is delivered via `HistoryPanelDeps.listRevisions` so the fixture is
 * fully controlled in-test.
 */

import { test, expect, chromium, type Browser, type Page } from '@playwright/test';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';
import { bundleBrowserIife } from './utils/esbuild-loader';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const REPO_ROOT = path.resolve(__dirname, '../..');
const HISTORY_PANEL_ENTRY = path.join(
    REPO_ROOT,
    'standalone-scripts/macro-controller/src/ui/prompt-history-panel.ts',
);

const SLUG = 'plan-default';
const ROLE = 'plan';

let bundleSource = '';
let browser: Browser | undefined;

function resolveChromiumExecutable(): string | undefined {
    const candidates = ['/usr/bin/chromium', '/bin/chromium', '/usr/bin/chromium-browser', '/usr/bin/google-chrome'];
    for (const candidate of candidates) if (fs.existsSync(candidate)) return candidate;
    return undefined;
}

test.beforeAll(async () => {
    bundleSource = await bundleBrowserIife(REPO_ROOT, {
        entryPoint: HISTORY_PANEL_ENTRY,
        globalName: 'PromptHistoryPanelBundle',
        footerJs: 'window.__promptHistoryPanel = PromptHistoryPanelBundle;',
    });
    browser = await chromium.launch({
        headless: true,
        executablePath: resolveChromiumExecutable(),
    });
});

test.afterAll(async () => {
    if (browser) await browser.close();
});

async function newHarnessPage(): Promise<Page> {
    if (!browser) throw new Error('browser not initialized');
    const context = await browser.newContext();
    const page = await context.newPage();

    await page.addInitScript(() => {
        interface RuntimeResponse {
            isOk: boolean;
            rows?: Array<Record<string, unknown>>;
            lastInsertId?: number;
        }
        (globalThis as typeof globalThis & { chrome: unknown }).chrome = {
            runtime: {
                lastError: null,
                sendMessage: (_msg: unknown, callback: (r: RuntimeResponse) => void) => {
                    setTimeout(() => callback({ isOk: true, rows: [], lastInsertId: 0 }), 0);
                },
            },
        };
    });

    await page.route('**/*', (route) => {
        route.fulfill({ status: 200, contentType: 'text/html', body: '<!doctype html><html><body></body></html>' });
    });
    await page.goto('https://prompt-history-sort-filter-harness.test/');
    await page.addScriptTag({ content: bundleSource });
    return page;
}

async function openPanel(page: Page): Promise<void> {
    await page.evaluate(async ({ slug, role }) => {
        interface RevRow {
            Id: number; PromptId: number; Slug: string; Name: string; Body: string;
            Role: string; ReplaceKey: string; ReplaceValues: string; CreatedAt: number; Reason: string;
        }
        // Deterministic mixed fixture: 2 upsert (native), 1 restore
        // (native), 1 import (imported sentinel PromptId=0).
        const rows: RevRow[] = [
            { Id: 11, PromptId: 7, Slug: slug, Name: 'Plan default', Body: 'earliest',
              Role: role, ReplaceKey: 'n', ReplaceValues: '["1"]',
              CreatedAt: 1_700_000_100_000, Reason: 'upsert' },
            { Id: 12, PromptId: 7, Slug: slug, Name: 'Plan default', Body: 'middle-a',
              Role: role, ReplaceKey: 'n', ReplaceValues: '["1"]',
              CreatedAt: 1_700_000_200_000, Reason: 'restore' },
            { Id: 13, PromptId: 7, Slug: slug, Name: 'Plan default', Body: 'middle-b',
              Role: role, ReplaceKey: 'n', ReplaceValues: '["1"]',
              CreatedAt: 1_700_000_300_000, Reason: 'upsert' },
            { Id: 14, PromptId: 0, Slug: slug, Name: 'Plan default', Body: 'imported-latest',
              Role: role, ReplaceKey: 'n', ReplaceValues: '["1"]',
              CreatedAt: 1_700_000_400_000, Reason: 'import' },
        ];
        interface DbOk<T> { ok: boolean; value?: T; error?: string }
        const listRevisions = async (): Promise<DbOk<RevRow[]>> => ({ ok: true, value: rows.slice() });
        const toast = () => { /* noop */ };
        (window as unknown as { __deps: unknown }).__deps = { listRevisions, toast, undoToast: toast };

        interface HistoryApi {
            openPromptHistoryPanel: (input: { role: string; slug: string }, deps: unknown) => Promise<void>;
        }
        const api = (window as unknown as { __promptHistoryPanel: HistoryApi }).__promptHistoryPanel;
        await api.openPromptHistoryPanel({ role, slug }, (window as unknown as { __deps: unknown }).__deps);
    }, { slug: SLUG, role: ROLE });
}

async function rowIds(page: Page): Promise<string[]> {
    return page
        .locator('#marco-prompt-history-panel [data-role="revision-row"]')
        .evaluateAll((els) => els.map((el) => el.getAttribute('data-revision-id') ?? ''));
}

test.describe('prompt history sort + filter toolbar', () => {
    test('sort by Date/Reason and reason/imported chips update the visible row set', async () => {
        const page = await newHarnessPage();
        await openPanel(page);

        const panel = page.locator('#marco-prompt-history-panel');

        // Default: 4 rows, sorted by Date desc (newest first).
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(4);
        expect(await rowIds(page)).toEqual(['14', '13', '12', '11']);

        // Click Date sort again -> flips to ascending.
        await panel.locator('[data-role="sort-button"][data-sort-key="date"]').click();
        expect(await rowIds(page)).toEqual(['11', '12', '13', '14']);

        // Click Reason -> switches key, resets to desc. Reasons: import,
        // restore, upsert, upsert -> desc localeCompare -> u,u,r,i.
        await panel.locator('[data-role="sort-button"][data-sort-key="reason"]').click();
        const orderReasonDesc = await rowIds(page);
        // First two must be the two `upsert` rows (Ids 11 & 13),
        // followed by `restore` (12), then `import` (14).
        expect(orderReasonDesc.slice(0, 2).sort()).toEqual(['11', '13']);
        expect(orderReasonDesc[2]).toBe('12');
        expect(orderReasonDesc[3]).toBe('14');

        // Filter by reason chip 'upsert' -> only 2 rows survive.
        await panel.locator('[data-role="reason-chip"][data-reason="upsert"]').click();
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(2);
        expect((await rowIds(page)).sort()).toEqual(['11', '13']);
        await expect(panel.locator('[data-role="reason-chip"][data-reason="upsert"]'))
            .toHaveAttribute('aria-pressed', 'true');

        // Clear filters returns all 4.
        await panel.locator('button[data-action="clear-filters"]').click();
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(4);

        // Imported chip cycles all -> only -> hide.
        const importedChip = panel.locator('[data-role="imported-chip"]');
        await importedChip.click(); // -> only
        await expect(importedChip).toHaveAttribute('data-imported-filter', 'only');
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(1);
        expect(await rowIds(page)).toEqual(['14']);
        await expect(panel.locator('[data-role="imported-badge"]')).toHaveCount(1);

        await panel.locator('[data-role="imported-chip"]').click(); // -> hide
        await expect(panel.locator('[data-role="imported-chip"]'))
            .toHaveAttribute('data-imported-filter', 'exclude');
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(3);
        expect((await rowIds(page)).sort()).toEqual(['11', '12', '13']);
        await expect(panel.locator('[data-role="imported-badge"]')).toHaveCount(0);

        // Combine imported=hide with reason=restore -> only Id 12.
        await panel.locator('[data-role="reason-chip"][data-reason="restore"]').click();
        await expect(panel.locator('[data-role="revision-row"]')).toHaveCount(1);
        expect(await rowIds(page)).toEqual(['12']);

        await page.context().close();
    });
});
